	private sealed class ChatFileUndoScope : IDisposable
	{
		private readonly LmVsProxy _owner;
		private readonly ChatFileUndoTransaction _previous;
		private bool _disposed;

		public ChatFileUndoTransaction Transaction { get; }

		public ChatFileUndoScope(LmVsProxy owner, string ownerKey, string sessionId, string toolName)
		{
			_owner = owner;
			_previous = owner._activeChatFileUndoTransaction.Value;
			Transaction = new ChatFileUndoTransaction
			{
				Token = "undo_" + Guid.NewGuid().ToString("N"),
				OwnerKey = ownerKey ?? "",
				SessionId = owner.EnsureChatUiSessionId(sessionId),
				ToolName = toolName ?? "",
				CreatedUtc = DateTimeOffset.UtcNow
			};
			_owner._activeChatFileUndoTransaction.Value = Transaction;
		}

		public void Dispose()
		{
			if (_disposed)
			{
				return;
			}
			_disposed = true;
			_owner._activeChatFileUndoTransaction.Value = _previous;
		}
	}

