	private sealed class ChatBrowserClientSession : IDisposable
	{
		public string Key { get; }

		public CookieContainer Cookies { get; }

		public System.Net.Http.HttpClient ProxyClient { get; }

		public System.Net.Http.HttpClient ReadClient { get; }

		public DateTimeOffset LastUsedUtc { get; set; } = DateTimeOffset.UtcNow;

		public ChatBrowserClientSession(string key, TimeSpan timeout)
		{
			Key = key ?? "";
			Cookies = new CookieContainer();
			ProxyClient = new System.Net.Http.HttpClient(new HttpClientHandler
			{
				AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate,
				AllowAutoRedirect = false,
				UseCookies = true,
				CookieContainer = Cookies
			})
			{
				Timeout = timeout
			};
			ReadClient = new System.Net.Http.HttpClient(new HttpClientHandler
			{
				AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate,
				AllowAutoRedirect = false,
				UseCookies = true,
				CookieContainer = Cookies
			})
			{
				Timeout = timeout
			};
		}

		public void Dispose()
		{
			ProxyClient.Dispose();
			ReadClient.Dispose();
		}
	}

