	public TimeSpan PromptTimeout
	{
		get
		{
			return _promptTimeout;
		}
		set
		{
			if (value <= TimeSpan.Zero)
			{
				throw new ArgumentOutOfRangeException("value", "Prompt timeout must be greater than zero.");
			}
			_promptTimeout = value;
			if (_httpClient != null)
			{
				_httpClient.Timeout = value;
			}
			if (_chatBrowserProxyHttpClient != null)
			{
				_chatBrowserProxyHttpClient.Timeout = value;
			}
			if (_browserSkillHttpClient != null)
			{
				_browserSkillHttpClient.Timeout = value;
			}
			lock (_chatBrowserClientSessionsLock)
			{
				foreach (ChatBrowserClientSession session in _chatBrowserClientSessions.Values)
				{
					session.ProxyClient.Timeout = value;
					session.ReadClient.Timeout = value;
				}
			}
		}
	}

