	public void ConfigureChatStorageCosts(string storageType, double costFactor)
	{
		ChatCostSettings settings = GetChatCostSettings();
		string normalizedStorageType = NormalizeStorageType(storageType);
		double normalizedCostFactor = ClampStorageCostFactor(costFactor);
		if (string.Equals(settings.storageType, normalizedStorageType, StringComparison.OrdinalIgnoreCase) &&
			Math.Abs(settings.storageCostFactor - normalizedCostFactor) < 0.000001)
		{
			return;
		}
		settings.storageType = normalizedStorageType;
		settings.storageCostFactor = normalizedCostFactor;
		SaveChatCostSettings(settings);
	}

	public GpuTdpDetectionSnapshot DetectAndApplyNvidiaGpuTdpWatts()
	{
		return ApplyGpuTdpDetectionSnapshot(DetectNvidiaGpuTdp());
	}

	public GpuTdpDetectionSnapshot DetectAndApplyNvidiaGpuTdpWattsFromNvidiaSmiOutput(string output, string source)
	{
		GpuTdpCandidate candidate = SelectBestNvidiaGpuTdpCandidate(output);
		if (candidate == null)
		{
			return ApplyGpuTdpDetectionSnapshot(new GpuTdpDetectionSnapshot
			{
				GpuName = "",
				TdpWatts = 0.0,
				Source = string.IsNullOrWhiteSpace(source) ? "nvidia-smi" : source.Trim(),
				Detail = "No NVIDIA GPU TDP was detected from nvidia-smi output.",
				IsNvidia = false
			});
		}

		return ApplyGpuTdpDetectionSnapshot(BuildGpuTdpDetectionSnapshot(candidate, source));
	}

	private GpuTdpDetectionSnapshot ApplyGpuTdpDetectionSnapshot(GpuTdpDetectionSnapshot snapshot)
	{
		snapshot ??= new GpuTdpDetectionSnapshot();
		lock (_chatCostLock)
		{
			_detectedGpuTdpWatts = ((snapshot.TdpWatts > 0.0) ? snapshot.TdpWatts : 0.0);
		}
		if (snapshot.TdpWatts > 0.0)
		{
			lock (_chatSessionLock)
			{
				Table table = GetChatCostsTable();
				UpsertChatCostSetting(table, "gpuTdpWatts", snapshot.TdpWatts);
				SaveChatSessionDataAndInvalidateCaches();
			}
		}
		return snapshot;
	}

	public TokenRateRequestPolicySnapshot GetTokenRateRequestPolicy()
	{
		return TokenRateRequestPolicySnapshotFromSettings(GetChatCostSettings(), GetEffectiveAdvertisedTokenRate());
	}

	public TokenRateRequestPolicySnapshot ConfigureTokenRateRequestPolicy(bool enabled, long minTokenRate, long maxTokenRate, long advertisedTokenRate)
	{
		ChatCostSettings settings = GetChatCostSettings();
		long normalizedMinTokenRate = Math.Max(0L, minTokenRate);
		long normalizedMaxTokenRate = Math.Max(normalizedMinTokenRate, Math.Max(0L, maxTokenRate));
		long normalizedAdvertisedTokenRate = Math.Max(0L, advertisedTokenRate);
		if (settings.tokenRateRequestsEnabled == enabled &&
			settings.tokenRateRequestMin == normalizedMinTokenRate &&
			settings.tokenRateRequestMax == normalizedMaxTokenRate &&
			settings.advertisedTokenRate == normalizedAdvertisedTokenRate)
		{
			return TokenRateRequestPolicySnapshotFromSettings(settings, GetEffectiveAdvertisedTokenRate());
		}
		settings.tokenRateRequestsEnabled = enabled;
		settings.tokenRateRequestMin = normalizedMinTokenRate;
		settings.tokenRateRequestMax = normalizedMaxTokenRate;
		settings.advertisedTokenRate = normalizedAdvertisedTokenRate;
		SaveChatCostSettings(settings);
		return TokenRateRequestPolicySnapshotFromSettings(settings, GetEffectiveAdvertisedTokenRate());
	}

	public TokenRateRequestPolicySnapshot SetAdvertisedTokenRate(long advertisedTokenRate)
	{
		ChatCostSettings settings = GetChatCostSettings();
		long normalizedAdvertisedTokenRate = Math.Max(0L, advertisedTokenRate);
		if (settings.advertisedTokenRate == normalizedAdvertisedTokenRate)
		{
			return TokenRateRequestPolicySnapshotFromSettings(settings, GetEffectiveAdvertisedTokenRate());
		}
		settings.advertisedTokenRate = normalizedAdvertisedTokenRate;
		SaveChatCostSettings(settings);
		return TokenRateRequestPolicySnapshotFromSettings(settings, GetEffectiveAdvertisedTokenRate());
	}

	public int ConfigureChatThroughputTokensPerSecond(int tokensPerSecond)
	{
		ChatCostSettings settings = GetChatCostSettings();
		int normalizedTokensPerSecond = NormalizeChatThroughputTokensPerSecond(tokensPerSecond);
		if (settings.throughputTokensPerSecond == normalizedTokensPerSecond)
		{
			return settings.throughputTokensPerSecond;
		}
		settings.throughputTokensPerSecond = normalizedTokensPerSecond;
		SaveChatCostSettings(settings);
		return settings.throughputTokensPerSecond;
	}

	public void ConfigureServerBrowserProfile(LmVsProxyServerProfile profile)
	{
		LmVsProxyServerProfile next = (profile ?? new LmVsProxyServerProfile()).Clone();
		next.Normalize(Environment.MachineName + " LmVsProxy");
		string normalizedBenchmarks = NormalizeChatUiModelBenchmarksJson(next.ModelBenchmarksJson);
		lock (_serverBrowserProfileLock)
		{
			if (!string.IsNullOrWhiteSpace(normalizedBenchmarks))
			{
				_latestModelBenchmarksJson = normalizedBenchmarks;
				next.ModelBenchmarksJson = normalizedBenchmarks;
			}
			else if (!string.IsNullOrWhiteSpace(_latestModelBenchmarksJson))
			{
				next.ModelBenchmarksJson = _latestModelBenchmarksJson;
			}
			_serverBrowserProfile = next;
		}
	}

	public LmVsProxyServerProfile GetServerBrowserProfile()
	{
		lock (_serverBrowserProfileLock)
		{
			LmVsProxyServerProfile profile = (_serverBrowserProfile ?? new LmVsProxyServerProfile()).Clone();
			profile.Normalize(Environment.MachineName + " LmVsProxy");
			string normalizedBenchmarks = NormalizeChatUiModelBenchmarksJson(profile.ModelBenchmarksJson);
			if (!string.IsNullOrWhiteSpace(normalizedBenchmarks))
			{
				_latestModelBenchmarksJson = normalizedBenchmarks;
				profile.ModelBenchmarksJson = normalizedBenchmarks;
			}
			else if (!string.IsNullOrWhiteSpace(_latestModelBenchmarksJson))
			{
				profile.ModelBenchmarksJson = _latestModelBenchmarksJson;
			}
			return profile;
		}
	}

