	public IReadOnlyList<RemoteSessionFileCloneSnapshot> GetRemoteSessionFileClones()
	{
		lock (_remoteSessionFileCloneLock)
		{
			return _remoteSessionFileClones.Values.OrderByDescending((RemoteSessionFileCloneRecord item) => item.UpdatedUtc).Select(CloneRemoteSessionFileRecord).ToList();
		}
	}

	public bool CancelRemoteSessionFileClone(string id)
	{
		if (string.IsNullOrWhiteSpace(id))
		{
			return false;
		}
		CancellationTokenSource cancellation = null;
		RemoteSessionFileCloneRecord record = null;
		lock (_remoteSessionFileCloneLock)
		{
			if (!_remoteSessionFileClones.TryGetValue(id, out record))
			{
				return false;
			}
			_remoteSessionFileCloneCancellations.TryGetValue(id, out cancellation);
			if (IsRemoteSessionCloneTerminal(record.Status))
			{
				return false;
			}
			record.Status = "Canceling";
			record.UpdatedUtc = DateTimeOffset.UtcNow;
			record.Canceled = true;
		}
		try
		{
			cancellation?.Cancel();
		}
		catch
		{
		}
		NotifyRemoteSessionFileCloneChanged(record);
		return true;
	}

	public void CancelAllRemoteSessionFileClones()
	{
		List<string> ids;
		lock (_remoteSessionFileCloneLock)
		{
			ids = (from item in _remoteSessionFileClones.Values
				where !IsRemoteSessionCloneTerminal(item.Status)
				select item.Id).ToList();
		}
		foreach (string id in ids)
		{
			CancelRemoteSessionFileClone(id);
		}
	}

	public void ClearCompletedRemoteSessionFileClones()
	{
		lock (_remoteSessionFileCloneLock)
		{
			foreach (string id in (from item in _remoteSessionFileClones.Values
				where IsRemoteSessionCloneTerminal(item.Status)
				select item.Id).ToList())
			{
				_remoteSessionFileClones.Remove(id);
				_remoteSessionFileCloneCancellations.Remove(id);
			}
		}
	}

	public IReadOnlyList<ChatSessionDiagnosticsSnapshot> GetChatSessionDiagnostics()
	{
		List<ChatSessionDiagnosticsSnapshot> sessions = new List<ChatSessionDiagnosticsSnapshot>();
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				sessions.Add(new ChatSessionDiagnosticsSnapshot
				{
					Id = GetRowValue(row, 0),
					Title = GetRowValue(row, 1),
					CreatedUtc = GetRowValue(row, 2),
					UpdatedUtc = GetRowValue(row, 3),
					Model = GetRowValue(row, 4),
					Runtime = GetRowValue(row, 18),
					OwnerKey = GetRowValue(row, 7),
					MessageCount = CountJsonArrayItems(GetChatSessionPrivateValue(row, 5, "messages", "[]")),
					FileCount = CountJsonArrayItems(GetChatSessionPrivateValue(row, 6, "files", "[]")),
					TitleLocked = ParseStoredBool(GetRowValue(row, 11), fallback: false),
					SavedUtc = GetRowValue(row, 12),
					Locked = ParseStoredBool(GetRowValue(row, 13), fallback: false),
					LockedUtc = GetRowValue(row, 14),
					ClonedFromSessionId = GetRowValue(row, 15),
					PromptTokenCount = ParseStoredLong(GetRowValue(row, 16), 0L),
					PromptTokenBudget = ParseStoredLong(GetRowValue(row, 17), 8192L)
				});
			}
		}
		sessions.Sort((ChatSessionDiagnosticsSnapshot a, ChatSessionDiagnosticsSnapshot b) => string.CompareOrdinal(b.UpdatedUtc, a.UpdatedUtc));
		return sessions;
	}

	public IReadOnlyList<ActivePromptSessionDiagnosticsSnapshot> GetActivePromptSessionDiagnostics()
	{
		List<ActivePromptSessionDiagnosticsSnapshot> sessions = new List<ActivePromptSessionDiagnosticsSnapshot>();
		lock (_activePromptSessionLock)
		{
			PruneInactivePromptSessionsLocked();
			foreach (ActivePromptSessionState state in _activePromptSessions.Values)
			{
				sessions.Add(new ActivePromptSessionDiagnosticsSnapshot
				{
					Id = state.Id,
					SessionId = state.SessionId,
					Source = state.Source,
					Title = state.Title,
					OwnerKey = state.OwnerKey,
					StreamId = state.StreamId ?? "",
					Model = state.Model,
					Runtime = state.Runtime,
					Status = state.Status,
					Phase = state.Phase,
					StartedUtc = state.StartedUtc.ToString("O"),
					UpdatedUtc = state.UpdatedUtc.ToString("O"),
					CompletedUtc = (state.CompletedUtc.HasValue ? state.CompletedUtc.Value.ToString("O") : ""),
					ElapsedSeconds = Math.Max(0, (int)Math.Round(((state.CompletedUtc ?? DateTimeOffset.UtcNow) - state.StartedUtc).TotalSeconds)),
					PromptTokenCount = state.PromptTokenCount,
					PromptTokenBudget = state.PromptTokenBudget,
					PromptText = (state.PromptText ?? ""),
					ReferencesText = (state.ReferencesText ?? ""),
					AnswerContent = (state.AnswerContent ?? ""),
					ReasoningContent = (state.ReasoningContent ?? "")
				});
			}
		}
		sessions.Sort((ActivePromptSessionDiagnosticsSnapshot a, ActivePromptSessionDiagnosticsSnapshot b) => string.CompareOrdinal(b.UpdatedUtc, a.UpdatedUtc));
		return sessions;
	}

	public ChatSessionDiagnosticsSnapshot SaveChatSessionCheckpointDiagnostics(string sessionId, string ownerKey)
	{
		return MutateChatSessionDiagnostics(sessionId, ownerKey, delegate(object[] row)
