	public ChatSessionDiagnosticsSnapshot SetChatSessionLockedDiagnostics(string sessionId, string ownerKey, bool locked)
	{
		return MutateChatSessionDiagnostics(sessionId, ownerKey, delegate(object[] row)
		{
			row[13] = (locked ? "true" : "false");
			row[14] = (locked ? DateTimeOffset.UtcNow.ToString("O") : "");
			RefreshChatSessionPromptMetrics(row);
		});
	}

	public ChatSessionDiagnosticsSnapshot CloneChatSessionDiagnostics(string sessionId, string ownerKey, string title = null)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : sessionId.Trim());
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			throw new InvalidOperationException("Session id is required.");
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			object[] source = null;
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
				{
					source = row;
					break;
				}
			}
			if (source == null || !ChatOwnerKeysMatch(ownerKey, GetRowValue(source, 7)))
			{
				throw new InvalidOperationException("Session not found.");
			}
			string now = DateTimeOffset.UtcNow.ToString("O");
			string cloneId = "sess_" + Guid.NewGuid().ToString("N");
			string cloneTitle = NormalizeChatSessionTitleInput(title);
			if (string.IsNullOrWhiteSpace(cloneTitle))
			{
				cloneTitle = "Copy of " + NormalizeChatSessionTitleInput(GetRowValue(source, 1));
			}
			if (string.IsNullOrWhiteSpace(cloneTitle))
			{
				cloneTitle = "Copy of New chat";
			}
			object[] clone = CreateChatSessionRow(cloneId, cloneTitle, now, now, GetRowValue(source, 4), GetRowValue(source, 5), GetRowValue(source, 6), ownerKey, GetRowValue(source, 8), "", shareEnabled: false, titleLocked: true, now, locked: false, "", GetRowValue(source, 0), ParseStoredLong(GetRowValue(source, 17), 8192L), GetRowValue(source, 18));
			if (!EnsureChatStorageCanAdd(ownerKey, cloneId, EstimateChatSessionRowStorageBytes(clone), out var _, out var storageError))
			{
				throw new InvalidOperationException(storageError);
			}
			table.Rows.Add(clone);
			SaveChatSessionDataAndInvalidateCaches();
			return BuildChatSessionDiagnosticsSnapshot(clone);
		}
	}

