	public IReadOnlyList<ServerUserUsageDiagnosticsSnapshot> GetServerUserUsageDiagnostics()
	{
		Dictionary<string, ServerUserUsageDiagnosticsSnapshot> users = new Dictionary<string, ServerUserUsageDiagnosticsSnapshot>(StringComparer.OrdinalIgnoreCase);
		AddOwner(GetDefaultLocalChatOwnerKey(), "Localhost", "local", accountManaged: false);
		lock (_chatSessionLock)
		{
			if (StoreLocalWebAuthAccounts)
			{
				Table webAuthTable = GetWebAuthTable();
				foreach (object[] sourceRow in webAuthTable.Rows)
				{
					WebAuthRecord record = WebAuthRecordFromRow(sourceRow);
					if (record != null && !string.IsNullOrWhiteSpace(record.userName))
					{
						string ownerKey = "webauth:" + record.userName.Trim().ToLowerInvariant();
						AddOwner(ownerKey, record.userName, "webauth", accountManaged: true, record);
					}
				}
			}
			Table costsTable = GetChatUserCostsTable();
			foreach (object[] sourceRow2 in costsTable.Rows)
			{
				object[] row = NormalizeChatUserCostRow(sourceRow2);
				string ownerKey2 = GetRowValue(row, 0);
				if (!string.IsNullOrWhiteSpace(ownerKey2))
				{
					AddOwner(ownerKey2, "", GetServerUsageUserType(ownerKey2), accountManaged: false);
				}
			}
			Table sessionsTable = GetChatSessionsTable();
			foreach (object[] sourceRow3 in sessionsTable.Rows)
			{
				object[] row2 = NormalizeChatSessionRow(sourceRow3);
				string ownerKey3 = GetRowValue(row2, 7);
				if (!string.IsNullOrWhiteSpace(ownerKey3))
				{
					ServerUserUsageDiagnosticsSnapshot user = AddOwner(ownerKey3, "", GetServerUsageUserType(ownerKey3), accountManaged: false);
					user.SessionCount++;
					string updatedUtc = GetRowValue(row2, 3);
					if (IsLaterIsoUtc(updatedUtc, user.LastSessionUtc))
					{
						user.LastSessionUtc = updatedUtc;
					}
				}
			}
		}
		lock (_activePromptSessionLock)
		{
			PruneInactivePromptSessionsLocked();
			foreach (ActivePromptSessionState state in _activePromptSessions.Values)
			{
				string ownerKey4 = NormalizeChatFilesystemOwnerKey(state.OwnerKey);
				ServerUserUsageDiagnosticsSnapshot user2 = AddOwner(ownerKey4, "", GetServerUsageUserType(ownerKey4), accountManaged: false);
				user2.ActiveSessionCount++;
				string updatedUtc2 = state.UpdatedUtc.ToString("O");
				if (IsLaterIsoUtc(updatedUtc2, user2.LastSessionUtc))
				{
					user2.LastSessionUtc = updatedUtc2;
				}
			}
		}
		foreach (ServerUserUsageDiagnosticsSnapshot user3 in users.Values)
		{
			ChatPermissionState permissions = (string.Equals(user3.OwnerKey, "global", StringComparison.OrdinalIgnoreCase) ? GetChatPermissions() : GetChatPermissions(user3.OwnerKey));
			user3.MutedUntilUtc = permissions.mutedUntilUtc ?? "";
			user3.BannedUntilUtc = permissions.bannedUntilUtc ?? "";
			user3.MuteUntilEnabled = permissions.muteUntilEnabled;
			user3.BanUntilEnabled = permissions.banUntilEnabled;
			user3.IsMuted = IsChatMuted(permissions);
			user3.IsBanned = IsChatBanned(permissions);
			ChatUsageDiagnosticsSnapshot usage = (user3.Usage = BuildChatUsageDiagnosticsSnapshot(string.Equals(user3.OwnerKey, "global", StringComparison.OrdinalIgnoreCase) ? BuildAnonymousChatUsageSnapshot() : GetChatUsageSnapshot(user3.OwnerKey)));
			user3.TokensUsed = Math.Max(user3.TokensUsed, usage.TokensUsed);
			user3.TokenLimit = Math.Max(user3.TokenLimit, usage.TokenLimit);
			user3.TokensRemaining = (usage.Unlimited ? 0 : Math.Max(0L, user3.TokenLimit - user3.TokensUsed));
			user3.Unlimited = user3.Unlimited || usage.Unlimited;
		}
		return (from serverUserUsageDiagnosticsSnapshot in users.Values
			where !string.Equals(serverUserUsageDiagnosticsSnapshot.OwnerKey, "global", StringComparison.OrdinalIgnoreCase)
			orderby serverUserUsageDiagnosticsSnapshot.ActiveSessionCount > 0 descending, serverUserUsageDiagnosticsSnapshot.TokensUsed descending
			select serverUserUsageDiagnosticsSnapshot).ThenBy<ServerUserUsageDiagnosticsSnapshot, string>((ServerUserUsageDiagnosticsSnapshot serverUserUsageDiagnosticsSnapshot) => serverUserUsageDiagnosticsSnapshot.UserName, StringComparer.OrdinalIgnoreCase).ToList();
		ServerUserUsageDiagnosticsSnapshot AddOwner(string text, string userName, string userType, bool accountManaged, WebAuthRecord webAuthRecord = null)
		{
			text = NormalizeChatFilesystemOwnerKey(text);
			if (string.Equals(text, "global", StringComparison.OrdinalIgnoreCase))
			{
				text = "global";
			}
			if (!users.TryGetValue(text, out var snapshot))
			{
				snapshot = new ServerUserUsageDiagnosticsSnapshot
				{
					OwnerKey = text,
					UserName = FirstNonEmpty(userName, GetServerUsageDisplayName(text)),
					UserType = (string.IsNullOrWhiteSpace(userType) ? GetServerUsageUserType(text) : userType),
					AccountManaged = accountManaged,
					Enabled = true
				};
				users[text] = snapshot;
			}
			if (!string.IsNullOrWhiteSpace(userName))
			{
				snapshot.UserName = userName.Trim();
			}
			if (!string.IsNullOrWhiteSpace(userType))
			{
				snapshot.UserType = userType.Trim();
			}
			snapshot.AccountManaged |= accountManaged;
			if (webAuthRecord != null)
			{
				snapshot.UserName = FirstNonEmpty(webAuthRecord.userName, snapshot.UserName);
				snapshot.Enabled = webAuthRecord.enabled;
				snapshot.IsAdministrator = webAuthRecord.isAdministrator;
				snapshot.LastClientIp = webAuthRecord.lastClientIp ?? "";
				snapshot.CreatedUtc = webAuthRecord.createdUtc ?? "";
				snapshot.UpdatedUtc = webAuthRecord.updatedUtc ?? "";
				snapshot.LastLoginUtc = webAuthRecord.lastLoginUtc ?? "";
				snapshot.TokenLimit = Math.Max(0L, webAuthRecord.tokenLimit);
				snapshot.TokensUsed = Math.Max(snapshot.TokensUsed, Math.Max(0L, webAuthRecord.tokensUsed));
				snapshot.TokensRemaining = ((snapshot.TokenLimit <= 0) ? 0 : Math.Max(0L, snapshot.TokenLimit - snapshot.TokensUsed));
				snapshot.Unlimited = snapshot.TokenLimit <= 0;
			}
			return snapshot;
		}
	}

	public ChatSessionRenderDiagnosticsSnapshot GetChatSessionRenderDiagnostics(string sessionId, string ownerKey)
	{
		sessionId = (sessionId ?? "").Trim();
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		ChatSessionRenderDiagnosticsSnapshot snapshot = new ChatSessionRenderDiagnosticsSnapshot
		{
			Id = sessionId,
			OwnerKey = ownerKey,
			Usage = BuildChatUsageDiagnosticsSnapshot(GetChatUsageSnapshot(ownerKey, sessionId))
		};
		ActivePromptSessionState activeState = null;
		lock (_activePromptSessionLock)
		{
			PruneInactivePromptSessionsLocked();
			foreach (ActivePromptSessionState state in _activePromptSessions.Values)
			{
				if (string.Equals(state.Id, sessionId, StringComparison.Ordinal) || (!string.IsNullOrWhiteSpace(state.SessionId) && string.Equals(state.SessionId, sessionId, StringComparison.Ordinal)))
				{
					activeState = state;
					break;
				}
			}
		}
		if (activeState != null)
		{
			snapshot.Found = true;
			snapshot.IsActive = true;
			snapshot.ActivePromptId = activeState.Id;
			snapshot.Id = (string.IsNullOrWhiteSpace(activeState.SessionId) ? activeState.Id : activeState.SessionId);
			snapshot.OwnerKey = NormalizeChatFilesystemOwnerKey(activeState.OwnerKey);
			snapshot.Title = activeState.Title ?? "";
			snapshot.StartedUtc = activeState.StartedUtc.ToString("O");
			snapshot.UpdatedUtc = activeState.UpdatedUtc.ToString("O");
			snapshot.CompletedUtc = (activeState.CompletedUtc.HasValue ? activeState.CompletedUtc.Value.ToString("O") : "");
			snapshot.Model = activeState.Model ?? "";
			snapshot.Runtime = activeState.Runtime ?? "";
			snapshot.Status = activeState.Status ?? "";
			snapshot.Phase = activeState.Phase ?? "";
			snapshot.ElapsedSeconds = Math.Max(0, (int)Math.Round(((activeState.CompletedUtc ?? DateTimeOffset.UtcNow) - activeState.StartedUtc).TotalSeconds));
			snapshot.PromptTokenCount = activeState.PromptTokenCount;
			snapshot.PromptTokenBudget = activeState.PromptTokenBudget;
			snapshot.TokensPerSecond = ((snapshot.ElapsedSeconds <= 0) ? 0.0 : NormalizeCostNumber((double)snapshot.PromptTokenCount / Math.Max(1.0, snapshot.ElapsedSeconds)));
			if (HasChatOwnerEncryptionSecret(snapshot.OwnerKey))
			{
				snapshot.PromptText = activeState.PromptText ?? "";
				snapshot.ReferencesText = activeState.ReferencesText ?? "";
			}
			else
			{
				snapshot.PromptText = "";
				snapshot.ReferencesText = "";
				snapshot.Status = "Encrypted session content unavailable without the user's session secret.";
			}
			snapshot.Usage = BuildChatUsageDiagnosticsSnapshot(GetChatUsageSnapshot(snapshot.OwnerKey, snapshot.Id));
		}
		string storedSessionId = ((!string.IsNullOrWhiteSpace(snapshot.Id) && !snapshot.Id.StartsWith("prompt_", StringComparison.OrdinalIgnoreCase)) ? snapshot.Id : sessionId);
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (string.Equals(GetRowValue(row, 0), storedSessionId, StringComparison.Ordinal))
				{
					string rowOwnerKey = NormalizeChatFilesystemOwnerKey(GetRowValue(row, 7));
					if (ChatOwnerKeysMatch(ownerKey, rowOwnerKey) || ChatOwnerKeysMatch(rowOwnerKey, ownerKey))
					{
						bool canReadPrivate = CanReadChatSessionPrivateValues(row, rowOwnerKey);
						object[] readableRow = canReadPrivate ? DecryptChatSessionRowForOwner(row, rowOwnerKey) : row;
						snapshot.Found = true;
						snapshot.Id = GetRowValue(readableRow, 0);
						snapshot.OwnerKey = rowOwnerKey;
						snapshot.Title = FirstNonEmpty(snapshot.Title, GetRowValue(readableRow, 1));
						snapshot.CreatedUtc = GetRowValue(readableRow, 2);
						snapshot.UpdatedUtc = (IsLaterIsoUtc(snapshot.UpdatedUtc, GetRowValue(readableRow, 3)) ? snapshot.UpdatedUtc : GetRowValue(readableRow, 3));
						snapshot.Model = FirstNonEmpty(snapshot.Model, GetRowValue(readableRow, 4));
						snapshot.Runtime = FirstNonEmpty(snapshot.Runtime, GetRowValue(readableRow, 18));
						snapshot.MessagesJson = canReadPrivate ? NormalizeJsonArrayRawText(GetRowValue(readableRow, 5)) : "[]";
						snapshot.FilesJson = canReadPrivate ? NormalizeJsonArrayRawText(GetRowValue(readableRow, 6)) : "[]";
						snapshot.DraftPrompt = canReadPrivate ? GetRowValue(readableRow, 8) : "";
						snapshot.MessageCount = CountJsonArrayItems(snapshot.MessagesJson);
						snapshot.FileCount = CountJsonArrayItems(snapshot.FilesJson);
						snapshot.PromptTokenCount = Math.Max(snapshot.PromptTokenCount, ParseStoredLong(GetRowValue(readableRow, 16), 0L));
						snapshot.PromptTokenBudget = Math.Max(snapshot.PromptTokenBudget, ParseStoredLong(GetRowValue(readableRow, 17), 8192L));
						snapshot.Usage = BuildChatUsageDiagnosticsSnapshot(GetChatUsageSnapshot(rowOwnerKey, snapshot.Id));
						if (!canReadPrivate)
						{
							snapshot.Status = "Encrypted session content unavailable without the user's session secret.";
						}
						break;
					}
				}
			}
		}
		return snapshot;
	}

	public WebAuthUserDiagnosticsSnapshot SetWebAuthUserAdministrator(string username, bool isAdministrator)
	{
		WebAuthRecord record = UpdateWebAuthUserRecord(username, delegate(WebAuthRecord existing)
		{
			existing.isAdministrator = isAdministrator;
			existing.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
			return existing;
		});
		LogMessage("[WebAuth] " + (isAdministrator ? "Granted administrator to " : "Revoked administrator from ") + record.userName + ".");
		return WebAuthUserDiagnosticsSnapshotFromRecord(record);
	}

	public WebAuthUserDiagnosticsSnapshot RestrictWebAuthUser(string username, string restriction, TimeSpan? duration)
	{
		WebAuthRecord record = GetWebAuthRecordRequired(username);
		string ownerKey = "webauth:" + record.userName.Trim().ToLowerInvariant();
		RestrictChatClient(ownerKey, restriction, duration);
		LogMessage("[WebAuth] " + ((restriction ?? "").Equals("ban", StringComparison.OrdinalIgnoreCase) ? "Banned " : "Muted ") + record.userName + ".");
		return WebAuthUserDiagnosticsSnapshotFromRecord(GetWebAuthRecord(record.userName) ?? record);
	}

	public WebAuthUserDiagnosticsSnapshot EnableWebAuthUser(string username)
	{
		WebAuthRecord record = UpdateWebAuthUserRecord(username, delegate(WebAuthRecord existing)
		{
			existing.enabled = true;
			existing.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
			return existing;
		});
		EnableChatClient("webauth:" + record.userName.Trim().ToLowerInvariant());
		LogMessage("[WebAuth] Enabled " + record.userName + " and cleared mute/ban restrictions.");
		return WebAuthUserDiagnosticsSnapshotFromRecord(GetWebAuthRecord(record.userName) ?? record);
	}

	public ChatPerformanceDiagnosticsSnapshot GetChatPerformanceDiagnostics()
	{
		ChatPerformanceDiagnosticsSnapshot snapshot = new ChatPerformanceDiagnosticsSnapshot
		{
			UpdatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
		lock (_chatSessionLock)
		{
			Table table = GetChatUserCostsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatUserCostRow(sourceRow);
				string ownerKey = GetRowValue(row, 0);
				if (!string.IsNullOrWhiteSpace(ownerKey))
				{
					long tokensUsed = Math.Max(0L, ParseStoredLong(GetRowValue(row, 6), 0L));
					snapshot.OwnerCount++;
					if (snapshot.TotalTokensUsed > long.MaxValue - tokensUsed)
					{
						snapshot.TotalTokensUsed = long.MaxValue;
					}
					else
					{
						snapshot.TotalTokensUsed += tokensUsed;
					}
				}
			}
		}
		return snapshot;
	}

	public ObservabilitySnapshot GetObservabilityDiagnostics()
	{
		DateTimeOffset now = DateTimeOffset.UtcNow;
		ChatPerformanceDiagnosticsSnapshot performance = GetChatPerformanceDiagnostics();
		IReadOnlyList<ActivePromptSessionDiagnosticsSnapshot> activePrompts = GetActivePromptSessionDiagnostics();
		IReadOnlyList<ChatSessionDiagnosticsSnapshot> chatSessions = GetChatSessionDiagnostics();
		int pendingFilesystemRequests = GetPendingFilesystemPermissionRequestCount();
		int pendingTerminalRequests = GetPendingTerminalPermissionRequestCount();
		int pendingTokenRateRequests = SafeDiagnosticCount(() => GetPendingTokenRateRequests());
		int pendingRegistrationRequests = SafeDiagnosticCount(() => GetPendingWebAuthRegistrationRequests());
		int webAuthUsers = SafeDiagnosticCount(() => GetWebAuthUserDiagnostics());
		int trustOpenCases = SafeTrustOpenCaseCount();
		int masterServers = GetObservedMasterServerCount();
		object hardware = BuildObservabilityHardwarePayload(now);
		object services = BuildObservabilityServicesPayload();
		object pending = new
		{
			filesystem = pendingFilesystemRequests,
			terminal = pendingTerminalRequests,
			tokenRate = pendingTokenRateRequests,
			registrations = pendingRegistrationRequests,
			total = pendingFilesystemRequests + pendingTerminalRequests + pendingTokenRateRequests + pendingRegistrationRequests
		};
		int financePayments;
		object database = BuildObservabilityDatabasePayload(out financePayments);
		object security = BuildSecurityPermissionMonitoringPayload(GetDefaultLocalChatOwnerKey(), GetChatPermissions());
		object marketplace = BuildMarketplaceMonitoringPayload(masterServers);
		object developerWorkflow = BuildDeveloperProjectWorkflowFleetMonitoringPayload();
		List<ObservabilityRouteSnapshot> routes = new List<ObservabilityRouteSnapshot>();
		List<ObservabilityRecentEventSnapshot> events = new List<ObservabilityRecentEventSnapshot>();
		DateTimeOffset startedUtc;
		long totalRequests;
		long failedRequests;
		long totalTokens;
		long totalPromptSessions;
		long completedPromptSessions;
		long failedPromptSessions;
		long highWatermark;
		double totalLatencyMs;
		lock (_observabilityLock)
		{
			startedUtc = _observabilityStartedUtc;
			totalRequests = _observabilityTotalRequests;
			failedRequests = _observabilityFailedRequests;
			totalTokens = Math.Max(_observabilityTotalTokens, performance.TotalTokensUsed);
			totalPromptSessions = _observabilityTotalPromptSessions;
			completedPromptSessions = _observabilityCompletedPromptSessions;
			failedPromptSessions = _observabilityFailedPromptSessions;
			highWatermark = Math.Max(_observabilityActivePromptHighWatermark, activePrompts.Count);
			totalLatencyMs = _observabilityTotalLatencyMs;
			foreach (ObservabilityRouteAccumulator route in _observabilityRoutes.Values)
			{
				routes.Add(route.ToSnapshot());
			}
			events.AddRange(_observabilityEvents.Reverse());
		}
		routes.Sort(delegate(ObservabilityRouteSnapshot a, ObservabilityRouteSnapshot b)
		{
			int num = b.Failures.CompareTo(a.Failures);
			if (num != 0)
			{
				return num;
			}
			int num2 = b.AverageLatencyMs.CompareTo(a.AverageLatencyMs);
			return (num2 != 0) ? num2 : b.Count.CompareTo(a.Count);
		});
		ObservabilitySnapshot snapshot = new ObservabilitySnapshot
		{
			Ok = true,
			GeneratedUtc = now.ToString("O"),
			StartedUtc = startedUtc.ToString("O"),
			UptimeSeconds = Math.Max(0.0, (now - startedUtc).TotalSeconds),
			TotalRequests = totalRequests,
			FailedRequests = failedRequests,
			FailureRate = ((totalRequests <= 0) ? 0.0 : Math.Round((double)failedRequests / (double)totalRequests, 4)),
			AverageLatencyMs = ((totalRequests <= 0) ? 0.0 : Math.Round(totalLatencyMs / (double)totalRequests, 2)),
			TotalTokens = totalTokens,
			TotalPromptSessions = totalPromptSessions,
			CompletedPromptSessions = completedPromptSessions,
			FailedPromptSessions = failedPromptSessions,
			ActivePromptSessions = activePrompts.Count,
			ActivePromptHighWatermark = highWatermark,
			ChatSessions = chatSessions.Count,
			OwnerCount = performance.OwnerCount,
			WebAuthUsers = webAuthUsers,
			MasterServers = masterServers,
			TrustOpenCases = trustOpenCases,
			PendingFilesystemRequests = pendingFilesystemRequests,
			PendingTerminalRequests = pendingTerminalRequests,
			PendingTokenRateRequests = pendingTokenRateRequests,
			PendingRegistrationRequests = pendingRegistrationRequests,
			FinancePayments = financePayments,
			Hardware = hardware,
			Services = services,
			Security = security,
			Marketplace = marketplace,
			DeveloperWorkflow = developerWorkflow,
			Pending = pending,
			Database = database
		};
		snapshot.Routes.AddRange(routes);
		snapshot.RecentEvents.AddRange(events);
		snapshot.HealthScore = CalculateObservabilityHealthScore(snapshot, services, hardware);
		snapshot.HealthTier = BuildObservabilityHealthTier(snapshot.HealthScore);
		return snapshot;
	}

	public IReadOnlyList<TerminalPermissionRuleSnapshot> GetTerminalPermissionRulesDiagnostics(string ownerKey)
	{
		return GetTerminalPermissionRules(ownerKey);
	}

	public void RemoveTerminalPermissionRule(string ownerKey, string commandHash)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		commandHash = (commandHash ?? "").Trim();
		if (string.IsNullOrWhiteSpace(commandHash))
		{
			return;
		}
		List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
		lock (_chatSessionLock)
		{
			Table table = GetTerminalPermissionRulesTable();
			for (int i = table.Rows.Count - 1; i >= 0; i--)
			{
				object[] row = NormalizeTerminalPermissionRuleRow(table.Rows[i]);
				if (OwnerKeyListContains(ownerKeys, GetRowValue(row, 0)) && string.Equals(GetRowValue(row, 1), commandHash, StringComparison.OrdinalIgnoreCase))
				{
					table.Rows.RemoveAt(i);
				}
			}
			SaveChatSessionDataAndInvalidateCaches();
		}
	}

	public ChatClientPermissionSnapshot GetChatClientPermissionsDiagnostics(string ownerKey)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
	}

	public ChatClientPermissionSnapshot SaveChatClientPermissionsDiagnostics(ChatClientPermissionSnapshot snapshot)
	{
		if (snapshot == null)
		{
			throw new ArgumentNullException("snapshot");
		}
		string ownerKey = NormalizeChatFilesystemOwnerKey(snapshot.OwnerKey);
		ChatPermissionState permissions = ChatPermissionStateFromSnapshot(snapshot, GetChatPermissions(ownerKey));
		SaveChatPermissions(ownerKey, permissions);
		ApplyRuntimeChatPermissions(GetChatPermissions());
		return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
	}

	public ChatClientPermissionSnapshot RestrictChatClient(string ownerKey, string restriction, TimeSpan? duration)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		ChatPermissionState permissions = GetChatPermissions(ownerKey);
		DateTimeOffset now = DateTimeOffset.UtcNow;
		bool untilEnabled = !duration.HasValue || duration.Value <= TimeSpan.Zero;
		string until = (untilEnabled ? "" : now.Add(duration.Value).ToString("O"));
		if (string.Equals(restriction, "ban", StringComparison.OrdinalIgnoreCase))
		{
			permissions.bannedUntilUtc = until;
			permissions.banUntilEnabled = untilEnabled;
		}
		else
		{
			permissions.mutedUntilUtc = until;
			permissions.muteUntilEnabled = untilEnabled;
		}
		SaveChatPermissions(ownerKey, permissions);
		return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
	}

	public ChatClientPermissionSnapshot EnableChatClient(string ownerKey)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		ChatPermissionState permissions = GetChatPermissions(ownerKey);
		permissions.mutedUntilUtc = "";
		permissions.bannedUntilUtc = "";
		permissions.muteUntilEnabled = false;
		permissions.banUntilEnabled = false;
		SaveChatPermissions(ownerKey, permissions);
		return BuildChatClientPermissionSnapshot(ownerKey, GetChatPermissions(ownerKey));
	}

	private string NormalizeChatFilesystemOwnerKey(string ownerKey)
	{
		return string.IsNullOrWhiteSpace(ownerKey) ? GetDefaultLocalChatOwnerKey() : ownerKey.Trim();
	}

	private string BeginActivePromptSession(string source, string ownerKey, string requestBody, string sessionId = null, string participantKey = null)
	{
		string id = "prompt_" + Guid.NewGuid().ToString("N");
		DateTimeOffset now = DateTimeOffset.UtcNow;
		string model = ExtractJsonStringProperty(requestBody, "model") ?? ChatModel ?? "lm-studio";
		string promptText = ExtractChatUiLastUserPromptText(requestBody);
		string streamId = ExtractChatUiStreamId(requestBody);
		ActivePromptSessionState state = new ActivePromptSessionState
		{
			Id = id,
			SessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : SanitizeFileName(sessionId.Trim())),
			Source = (string.IsNullOrWhiteSpace(source) ? "LLM Prompt" : source.Trim()),
			Title = InferPromptSessionTitle(requestBody),
			OwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey),
			ParticipantKey = (string.IsNullOrWhiteSpace(participantKey) ? "" : participantKey.Trim()),
			StreamId = (string.IsNullOrWhiteSpace(streamId) ? "" : SanitizeFileName(streamId.Trim())),
			Model = model,
			Runtime = InferChatSessionRuntime(model),
			Status = "Running",
			Phase = "Processing prompt",
			StartedUtc = now,
			UpdatedUtc = now,
			PromptTokenCount = EstimatePromptTokensFromRequestBody(requestBody),
			PromptTokenBudget = ExtractPromptTokenBudgetFromRequestBody(requestBody, model),
			PromptText = promptText,
			ReferencesText = BuildActivePromptReferenceText(requestBody, sessionId, model),
			AnswerContent = "",
			ReasoningContent = ""
		};
		lock (_activePromptSessionLock)
		{
			PruneInactivePromptSessionsLocked();
			_activePromptSessions[id] = state;
			RecordObservabilityPromptStarted(state, _activePromptSessions.Count);
		}
		return id;
	}

	private void UpdateActivePromptSessionPhase(string id, string phase)
	{
		if (string.IsNullOrWhiteSpace(id))
		{
			return;
		}
		lock (_activePromptSessionLock)
		{
			if (_activePromptSessions.TryGetValue(id, out var state))
			{
				state.Phase = (string.IsNullOrWhiteSpace(phase) ? state.Phase : phase.Trim());
				state.UpdatedUtc = DateTimeOffset.UtcNow;
			}
		}
	}

	private void AppendActivePromptSessionOutput(string id, string content, string reasoning)
	{
		if (string.IsNullOrWhiteSpace(id) || (string.IsNullOrEmpty(content) && string.IsNullOrEmpty(reasoning)))
		{
			return;
		}
		lock (_activePromptSessionLock)
		{
			if (_activePromptSessions.TryGetValue(id, out var state) && state != null && !state.CompletedUtc.HasValue)
			{
				state.AnswerContent = AppendBoundedActivePromptText(state.AnswerContent, content);
				state.ReasoningContent = AppendBoundedActivePromptText(state.ReasoningContent, reasoning);
				state.UpdatedUtc = DateTimeOffset.UtcNow;
			}
		}
	}

	private static string AppendBoundedActivePromptText(string existing, string delta)
	{
		if (string.IsNullOrEmpty(delta))
		{
			return existing ?? "";
		}
		string combined = existing + delta;
		if (combined.Length <= 524288)
		{
			return combined;
		}
		string marker = "\n\n... earlier streaming output truncated ...\n\n";
		int keep = Math.Max(0, 524288 - marker.Length);
		if (keep <= 0)
		{
			return combined.Substring(combined.Length - 524288);
		}
		return marker + combined.Substring(combined.Length - keep);
	}

	private void CompleteActivePromptSession(string id, string status)
	{
		if (string.IsNullOrWhiteSpace(id))
		{
			return;
		}
		ActivePromptSessionState completed = null;
		lock (_activePromptSessionLock)
		{
			if (_activePromptSessions.TryGetValue(id, out var state))
			{
				DateTimeOffset now = DateTimeOffset.UtcNow;
				state.Status = (string.IsNullOrWhiteSpace(status) ? "Completed" : status.Trim());
				state.Phase = state.Status;
				state.UpdatedUtc = now;
				state.CompletedUtc = now;
				completed = state;
			}
		}
		if (completed != null)
		{
			RecordObservabilityPromptCompleted(completed);
		}
	}

	private void PruneInactivePromptSessionsLocked()
	{
		DateTimeOffset cutoff = DateTimeOffset.UtcNow - TimeSpan.FromMinutes(5.0);
		List<string> remove = new List<string>();
		foreach (KeyValuePair<string, ActivePromptSessionState> pair in _activePromptSessions)
		{
			if (pair.Value.CompletedUtc.HasValue && pair.Value.CompletedUtc.Value < cutoff)
			{
				remove.Add(pair.Key);
			}
		}
		foreach (string id in remove)
		{
			_activePromptSessions.Remove(id);
		}
	}

	private void RecordObservabilityPromptStarted(ActivePromptSessionState state, int activePromptCount)
	{
		if (state == null)
		{
			return;
		}
		lock (_observabilityLock)
		{
			_observabilityTotalPromptSessions++;
			if (activePromptCount > _observabilityActivePromptHighWatermark)
			{
				_observabilityActivePromptHighWatermark = activePromptCount;
			}
		}
		RecordObservabilityEvent("prompt", state.Source, "running", state.Title, state.OwnerKey, "", 0L);
	}

	private void RecordObservabilityPromptCompleted(ActivePromptSessionState state)
	{
		if (state == null)
		{
			return;
		}
		bool failed = IsObservabilityFailureStatus(state.Status);
		double latencyMs = Math.Max(0.0, ((state.CompletedUtc ?? DateTimeOffset.UtcNow) - state.StartedUtc).TotalMilliseconds);
		lock (_observabilityLock)
		{
			if (failed)
			{
				_observabilityFailedPromptSessions++;
			}
			else
			{
				_observabilityCompletedPromptSessions++;
			}
		}
		RecordObservabilityEvent("prompt", state.Source, failed ? "failed" : "completed", state.Status + ": " + state.Title, state.OwnerKey, "", 0L, latencyMs);
	}

	private void RecordObservabilityTokenCharge(string ownerKey, long tokens)
	{
		if (tokens <= 0)
		{
			return;
		}
		lock (_observabilityLock)
		{
			if (_observabilityTotalTokens > long.MaxValue - tokens)
			{
				_observabilityTotalTokens = long.MaxValue;
			}
			else
			{
				_observabilityTotalTokens += tokens;
			}
		}
	}

	private string ObserveChatRoute(string method, string route, string category, Func<string> handler, Func<string> ownerKey = null)
	{
		Stopwatch stopwatch = Stopwatch.StartNew();
		bool success = false;
		string detail = "";
		try
		{
			string result = handler();
			success = JsonResponseLooksSuccessful(result);
			if (!success)
			{
				detail = ExtractObservabilityJsonError(result);
			}
			return result;
		}
		catch (Exception ex)
		{
			detail = ex.Message;
			throw;
		}
		finally
		{
			stopwatch.Stop();
			RecordObservabilityRequest(method, route, category, success, stopwatch.Elapsed.TotalMilliseconds, 0L, SafeOwnerKey(ownerKey), detail);
		}
	}

	private async Task ObserveChatStreamRouteAsync(string method, string route, string category, Func<Task> handler, Func<string> ownerKey = null)
	{
		Stopwatch stopwatch = Stopwatch.StartNew();
		bool success = false;
		string detail = "";
		try
		{
			await handler().ConfigureAwait(continueOnCapturedContext: false);
			success = true;
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			detail = ex2.Message;
			throw;
		}
		finally
		{
			stopwatch.Stop();
			RecordObservabilityRequest(method, route, category, success, stopwatch.Elapsed.TotalMilliseconds, 0L, SafeOwnerKey(ownerKey), detail);
		}
	}

	private void RecordObservabilityRequest(string method, string route, string category, bool success, double latencyMs, long tokens, string ownerKey = "", string detail = "")
	{
		DateTimeOffset now = DateTimeOffset.UtcNow;
		method = (string.IsNullOrWhiteSpace(method) ? "HTTP" : method.Trim().ToUpperInvariant());
		route = (string.IsNullOrWhiteSpace(route) ? "/" : route.Trim());
		category = (string.IsNullOrWhiteSpace(category) ? "http" : category.Trim());
		latencyMs = Math.Max(0.0, latencyMs);
		tokens = Math.Max(0L, tokens);
		lock (_observabilityLock)
		{
			_observabilityTotalRequests++;
			_observabilityTotalLatencyMs += latencyMs;
			if (!success)
			{
				_observabilityFailedRequests++;
			}
			if (tokens > 0)
			{
				if (_observabilityTotalTokens > long.MaxValue - tokens)
				{
					_observabilityTotalTokens = long.MaxValue;
				}
				else
				{
					_observabilityTotalTokens += tokens;
				}
			}
			string key = method + " " + route;
			if (!_observabilityRoutes.TryGetValue(key, out var accumulator))
			{
				accumulator = new ObservabilityRouteAccumulator
				{
					Method = method,
					Route = route,
					Category = category,
					FirstSeenUtc = now
				};
				_observabilityRoutes[key] = accumulator;
			}
			accumulator.Category = (string.IsNullOrWhiteSpace(category) ? accumulator.Category : category);
			accumulator.Count++;
			if (!success)
			{
				accumulator.Failures++;
			}
			accumulator.TotalLatencyMs += latencyMs;
			accumulator.MaxLatencyMs = Math.Max(accumulator.MaxLatencyMs, latencyMs);
			if (tokens > 0)
			{
				accumulator.TotalTokens += tokens;
			}
			accumulator.LastSeenUtc = now;
		}
		if (!success || latencyMs >= 3000.0)
		{
			RecordObservabilityEvent(category, method + " " + route, success ? "slow" : "failed", detail, ownerKey, route, tokens, latencyMs);
		}
	}

	private void RecordObservabilityEvent(string category, string name, string status, string detail = "", string ownerKey = "", string route = "", long tokens = 0L, double latencyMs = 0.0)
	{
		ObservabilityRecentEventSnapshot snapshot = new ObservabilityRecentEventSnapshot
		{
			Id = "obs_" + Guid.NewGuid().ToString("N"),
			Category = (string.IsNullOrWhiteSpace(category) ? "event" : category.Trim()),
			Name = (string.IsNullOrWhiteSpace(name) ? "event" : name.Trim()),
			Status = (string.IsNullOrWhiteSpace(status) ? "info" : status.Trim()),
			Detail = TruncateForLog(detail ?? "", 500),
			OwnerKey = (string.IsNullOrWhiteSpace(ownerKey) ? "" : ownerKey.Trim()),
			Route = (string.IsNullOrWhiteSpace(route) ? "" : route.Trim()),
			Tokens = Math.Max(0L, tokens),
			LatencyMs = Math.Round(Math.Max(0.0, latencyMs), 2),
			CreatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
		lock (_observabilityLock)
		{
			_observabilityEvents.Enqueue(snapshot);
			while (_observabilityEvents.Count > 250)
			{
				_observabilityEvents.Dequeue();
			}
		}
		if (IsObservabilityFailureStatus(snapshot.Status))
		{
			RecordLmVsProxyError(snapshot.Status, snapshot.Category, snapshot.Name, snapshot.Route, snapshot.OwnerKey, snapshot.Detail, "");
		}
	}

	private void RecordLmVsProxyError(string severity, string category, string source, string route, string ownerKey, string message, string detail, Exception exception = null)
	{
		if (_chatSessionData == null)
		{
			return;
		}
		message = (string.IsNullOrWhiteSpace(message) ? detail : message);
		if (string.IsNullOrWhiteSpace(message))
		{
			return;
		}
		try
		{
			string now = DateTimeOffset.UtcNow.ToString("O");
			string exceptionType = ((exception == null) ? "" : (exception.GetType().FullName ?? exception.GetType().Name));
			string stackTrace = ((exception == null) ? "" : exception.ToString());
			string fingerprint = ComputeErrorDiagnosticsFingerprint(severity, category, source, route, message, exceptionType);
			object[] row = NormalizeErrorDiagnosticsRow(new object[14]
			{
				"err_" + Guid.NewGuid().ToString("N"),
				now,
				now,
				string.IsNullOrWhiteSpace(severity) ? "error" : severity.Trim(),
				string.IsNullOrWhiteSpace(category) ? "lmvsproxy" : category.Trim(),
				string.IsNullOrWhiteSpace(source) ? "LmVsProxy" : source.Trim(),
				string.IsNullOrWhiteSpace(route) ? "" : route.Trim(),
				string.IsNullOrWhiteSpace(ownerKey) ? "" : ownerKey.Trim(),
				TruncateForLog(message, 4000),
				TruncateForLog(detail ?? "", 8000),
				exceptionType,
				TruncateForLog(stackTrace, 12000),
				fingerprint,
				"1"
			});
			lock (_chatSessionLock)
			{
				Table table = GetErrorDiagnosticsTable();
				for (int i = table.Rows.Count - 1; i >= 0; i--)
				{
					object[] existing = NormalizeErrorDiagnosticsRow(table.Rows[i]);
					if (string.Equals(GetRowValue(existing, 12), fingerprint, StringComparison.Ordinal))
					{
						existing[2] = now;
						existing[8] = row[8];
						existing[9] = row[9];
						existing[11] = row[11];
						if (!int.TryParse(GetRowValue(existing, 13), NumberStyles.Integer, CultureInfo.InvariantCulture, out var count))
						{
							count = 1;
						}
						existing[13] = Math.Max(1, count + 1).ToString(CultureInfo.InvariantCulture);
						table.Rows[i] = existing;
						_chatSessionData.ScheduleSave();
						return;
					}
				}
				table.Rows.Add(row);
				while (table.Rows.Count > 2000)
				{
					table.Rows.RemoveAt(0);
				}
				_chatSessionData.ScheduleSave();
			}
		}
		catch
		{
		}
	}

	private static string ComputeErrorDiagnosticsFingerprint(string severity, string category, string source, string route, string message, string exceptionType)
	{
		string basis = string.Join("|", (severity ?? "").Trim().ToLowerInvariant(), (category ?? "").Trim().ToLowerInvariant(), (source ?? "").Trim().ToLowerInvariant(), (route ?? "").Trim().ToLowerInvariant(), NormalizeErrorFingerprintText(message), (exceptionType ?? "").Trim().ToLowerInvariant());
		using SHA256 sha = SHA256.Create();
		byte[] bytes = sha.ComputeHash(Encoding.UTF8.GetBytes(basis));
		return BitConverter.ToString(bytes).Replace("-", "").ToLowerInvariant();
	}

	private static string NormalizeErrorFingerprintText(string text)
	{
		text = (text ?? "").Trim().ToLowerInvariant();
		if (text.Length > 1000)
		{
			text = text.Substring(0, 1000);
		}
		return text;
	}

