	private object BuildSecurityPermissionMonitoringPayload(string ownerKey, ChatPermissionState permissions = null)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		permissions = permissions ?? GetChatPermissions(ownerKey);
		int pendingFilesystem = GetPendingFilesystemPermissionRequestCount();
		int pendingTerminal = GetPendingTerminalPermissionRequestCount();
		int allowedRoots = SafeDiagnosticCount(() => GetChatFilesystemAccessDiagnostics(ownerKey));
		int deniedRoots = 0;
		int temporaryRoots = 0;
		int terminalRules = 0;
		try
		{
			deniedRoots = GetChatFilesystemDeniedDirectories(ownerKey).Count;
		}
		catch
		{
		}
		try
		{
			temporaryRoots = GetTemporaryFilesystemAccess(ownerKey).Count;
		}
		catch
		{
		}
		try
		{
			terminalRules = GetTerminalPermissionRules(ownerKey).Count;
		}
		catch
		{
		}
		TrustAbuseSummarySnapshot trust = BuildTrustAbuseSummary(ownerKey, "", "", "");
		int score = CalculateSecurityPermissionScore(permissions, trust, pendingFilesystem, pendingTerminal, allowedRoots, deniedRoots, temporaryRoots, terminalRules);
		return new
		{
			ownerKey = ownerKey,
			securityScore = score,
			securityTier = BuildSecurityPermissionTier(score, trust),
			pendingFilesystemRequests = pendingFilesystem,
			pendingTerminalRequests = pendingTerminal,
			allowedRoots = allowedRoots,
			deniedRoots = deniedRoots,
			temporaryRoots = temporaryRoots,
			terminalRules = terminalRules,
			trustOpenCases = trust.OpenCases,
			criticalOpenCases = trust.CriticalOpenCases,
			highOpenCases = trust.HighOpenCases,
			commandsBlocked = trust.CommandsBlocked,
			hostSuspended = trust.HostSuspended,
			muted = IsChatMuted(permissions),
			banned = IsChatBanned(permissions),
			activeSensitivePermissions = CountSensitivePermissions(permissions),
			marketplacePolicy = BuildPeerRentalMarketplacePolicyPayload(ownerKey, GetRemoteModelServerSelection()),
			generatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
	}

	private int CalculateSecurityPermissionScore(ChatPermissionState permissions, TrustAbuseSummarySnapshot trust, int pendingFilesystem, int pendingTerminal, int allowedRoots, int deniedRoots, int temporaryRoots, int terminalRules)
	{
		permissions = permissions ?? new ChatPermissionState();
		trust = trust ?? new TrustAbuseSummarySnapshot();
		if (trust.HostSuspended || IsChatBanned(permissions))
		{
			return 0;
		}
		int score = 100;
		if (permissions.terminalCommands)
		{
			score -= (permissions.terminalForeverApproved ? 12 : 6);
		}
		if (permissions.sqlAdmin)
		{
			score -= 10;
		}
		if (permissions.ftpServer)
		{
			score -= 7;
		}
		if (permissions.vsCopilotTools)
		{
			score -= 4;
		}
		if (permissions.internetSearch)
		{
			score -= 4;
		}
		if (permissions.fileDownloads)
		{
			score -= 3;
		}
		if (IsChatMuted(permissions))
		{
			score -= 8;
		}
		score -= Math.Min(18, (pendingFilesystem + pendingTerminal) * 4);
		score -= Math.Min(10, Math.Max(0, allowedRoots - 3) * 2);
		score -= Math.Min(8, temporaryRoots * 2);
		score -= Math.Min(8, deniedRoots * 2);
		score -= Math.Min(8, Math.Max(0, terminalRules - 3));
		score -= Math.Min(30, trust.OpenCases * 5);
		score -= Math.Min(30, trust.HighOpenCases * 8 + trust.CriticalOpenCases * 12);
		if (trust.CommandsBlocked)
		{
			score -= 20;
		}
		if (trust.NeedsAdminIntervention)
		{
			score -= 8;
		}
		return Math.Max(0, Math.Min(100, score));
	}

	private static string BuildSecurityPermissionTier(int score, TrustAbuseSummarySnapshot trust)
	{
		if (trust != null && trust.HostSuspended)
		{
			return "Blocked";
		}
		if (score < 45)
		{
			return "Restricted";
		}
		if (score < 75)
		{
			return "Watch";
		}
		return "Healthy";
	}

	private static int CountSensitivePermissions(ChatPermissionState permissions)
	{
		if (permissions == null)
		{
			return 0;
		}
		int count = 0;
		if (permissions.internetSearch)
		{
			count++;
		}
		if (permissions.vsCopilotTools)
		{
			count++;
		}
		if (permissions.fileDownloads)
		{
			count++;
		}
		if (permissions.ftpServer)
		{
			count++;
		}
		if (permissions.sqlAdmin)
		{
			count++;
		}
		if (permissions.terminalCommands)
		{
			count++;
		}
		if (permissions.terminalForeverApproved)
		{
			count++;
		}
		return count;
	}

	private object BuildMarketplaceMonitoringPayload(int observedServers)
	{
		int remoteEntries = 0;
		int suspended = 0;
		int verified = 0;
		int review = 0;
		lock (_masterServerListLock)
		{
			remoteEntries = _masterServerEntries.Count;
			foreach (JsonElement entry in _masterServerEntries)
			{
				TrustAbuseSummarySnapshot trust = BuildMasterServerEntryTrustSummary(entry);
				if (trust.HostSuspended)
				{
					suspended++;
				}
				if (trust.HostVerified)
				{
					verified++;
				}
				if (trust.OpenCases > 0 || trust.RiskScore >= 40)
				{
					review++;
				}
			}
		}
		LmVsProxyServerProfile localProfile = GetServerBrowserProfile();
		TrustAbuseSummarySnapshot localTrust = BuildTrustAbuseSummary(NormalizeTrustOwnerKey("", localProfile.OwnerUserName), localProfile.ServerId, localProfile.ServerName, localProfile.PublicHost);
		if (localTrust.HostSuspended)
		{
			suspended++;
		}
		if (localTrust.HostVerified)
		{
			verified++;
		}
		if (localTrust.OpenCases > 0 || localTrust.RiskScore >= 40)
		{
			review++;
		}
		int listed = Math.Max(0, observedServers - suspended);
		int healthScore = ((observedServers <= 0) ? 90 : Math.Max(0, Math.Min(100, 100 - suspended * 25 - review * 8)));
		object copilotLease = BuildCopilotDuplicatorLeasePayload(GetRemoteModelServerSelection());
		object computeMetering = BuildMarketplaceComputeMeteringPayload();
		object leaseBroker = BuildMarketplaceLeaseBrokerMonitoringPayload();
		return new
		{
			observedServers = observedServers,
			remoteEntries = remoteEntries,
			listedServers = listed,
			suspendedServers = suspended,
			verifiedHosts = verified,
			reviewServers = review,
			copilotLease = copilotLease,
			computeMetering = computeMetering,
			leaseBroker = leaseBroker,
			marketplaceScore = healthScore,
			marketplaceTier = ((healthScore >= 90) ? "Healthy" : ((healthScore >= 70) ? "Watch" : ((healthScore >= 45) ? "At Risk" : "Blocked"))),
			generatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
	}

	private object BuildMarketplaceComputeMeteringPayload()
	{
		int operationCount = 0;
		int computeLinkedOperations = 0;
		long tokens = 0L;
		double gpuSeconds = 0.0;
		double cpuComputeSeconds = 0.0;
		double ramGbSeconds = 0.0;
		double systemSeconds = 0.0;
		long ioBytes = 0L;
		lock (_chatSessionLock)
		{
			Table table = GetFinanceTokenOperationsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				FinanceTokenOperationRecord record = FinanceTokenOperationFromRow(sourceRow);
				operationCount++;
				tokens = AddLongSaturating(tokens, Math.Max(0L, record.TokensDelta));
				gpuSeconds = NormalizeCostNumber(gpuSeconds + Math.Max(0.0, record.GpuSecondsDelta));
				cpuComputeSeconds = NormalizeCostNumber(cpuComputeSeconds + Math.Max(0.0, record.CpuComputeSecondsDelta));
				ramGbSeconds = NormalizeCostNumber(ramGbSeconds + Math.Max(0.0, record.RamGbSecondsDelta));
				systemSeconds = NormalizeCostNumber(systemSeconds + Math.Max(0.0, record.SystemSecondsDelta));
				ioBytes = AddUsageByteCount(ioBytes, record.IoBytesDelta);
				if (record.TokensDelta > 0 && (record.GpuSecondsDelta > 0.0 || record.CpuComputeSecondsDelta > 0.0))
				{
					computeLinkedOperations++;
				}
			}
		}
		double perThousand = ((tokens <= 0) ? 0.0 : (1000.0 / (double)tokens));
		return new
		{
			operationCount = operationCount,
			computeLinkedOperations = computeLinkedOperations,
			tokens = tokens,
			gpuSeconds = NormalizeCostNumber(gpuSeconds),
			cpuComputeSeconds = NormalizeCostNumber(cpuComputeSeconds),
			ramGbSeconds = NormalizeCostNumber(ramGbSeconds),
			systemSeconds = NormalizeCostNumber(systemSeconds),
			ioBytes = ioBytes,
			gpuSecondsPerThousandTokens = NormalizeCostNumber(gpuSeconds * perThousand),
			cpuComputeSecondsPerThousandTokens = NormalizeCostNumber(cpuComputeSeconds * perThousand),
			tokenComputeAccuracy = "gpu_cpu_resource_deltas_linked_to_token_operations"
		};
	}

	private int CountDataServerTableRowsLocked(string databaseName, string tableName)
	{
		if (string.IsNullOrWhiteSpace(databaseName) || string.IsNullOrWhiteSpace(tableName))
		{
			return 0;
		}
		try
		{
			if (_chatSessionData.Databases.TryGetValue(databaseName, out var database) && database != null && database.Tables != null && database.Tables.TryGetValue(tableName, out var table) && table != null && table.Rows != null)
			{
				return table.Rows.Count;
			}
		}
		catch
		{
		}
		return 0;
	}

	private double CalculateObservabilityHealthScore(ObservabilitySnapshot snapshot, object services, object hardware)
	{
		double score = 100.0;
		score -= Math.Min(45.0, snapshot.FailureRate * 120.0);
		score -= (double)Math.Min(20, snapshot.TrustOpenCases * 4);
		int pendingTotal = snapshot.PendingFilesystemRequests + snapshot.PendingTerminalRequests + snapshot.PendingTokenRateRequests + snapshot.PendingRegistrationRequests;
		score -= (double)Math.Min(12, pendingTotal * 2);
		object lmStudio = GetObjectProperty(services, "lmStudio");
		if (!ReadObjectBool(lmStudio, "connected", fallback: true))
		{
			score -= 10.0;
		}
		if (CopilotDuplicatorEnabled && !IsCopilotDuplicatorListening)
		{
			score -= 5.0;
		}
		double securityScore = ReadObjectDouble(snapshot.Security, "securityScore", 100.0);
		double marketplaceScore = ReadObjectDouble(snapshot.Marketplace, "marketplaceScore", 100.0);
		double workflowScore = ReadObjectDouble(snapshot.DeveloperWorkflow, "workflowScore", 100.0);
		if (securityScore < 75.0)
		{
			score -= Math.Min(10.0, (75.0 - securityScore) / 3.0);
		}
		if (marketplaceScore < 75.0)
		{
			score -= Math.Min(8.0, (75.0 - marketplaceScore) / 4.0);
		}
		if (workflowScore < 75.0)
		{
			score -= Math.Min(6.0, (75.0 - workflowScore) / 5.0);
		}
		double cpuPercent = ReadNestedMetricPercent(hardware, "cpu");
		double ramPercent = ReadNestedMetricPercent(hardware, "ram");
		double gpuPercent = ReadNestedMetricPercent(hardware, "gpu");
		if (cpuPercent >= 95.0)
		{
			score -= 5.0;
		}
		if (ramPercent >= 95.0)
		{
			score -= 5.0;
		}
		if (gpuPercent >= 98.0)
		{
			score -= 4.0;
		}
		if (score < 0.0)
		{
			return 0.0;
		}
		if (score > 100.0)
		{
			return 100.0;
		}
		return Math.Round(score, 1);
	}

	private static string BuildObservabilityHealthTier(double healthScore)
	{
		if (healthScore >= 90.0)
		{
			return "Healthy";
		}
		if (healthScore >= 75.0)
		{
			return "Watch";
		}
		if (healthScore >= 55.0)
		{
			return "Degraded";
		}
		return "Critical";
	}

	private static object GetObjectProperty(object source, string propertyName)
	{
		if (source == null || string.IsNullOrWhiteSpace(propertyName))
		{
			return null;
		}
		PropertyInfo property = source.GetType().GetProperties().FirstOrDefault((PropertyInfo item) => string.Equals(item.Name, propertyName, StringComparison.OrdinalIgnoreCase));
		return (property == null) ? null : property.GetValue(source);
	}

	private static bool ReadObjectBool(object source, string propertyName, bool fallback)
	{
		object value = GetObjectProperty(source, propertyName);
		if (value is bool boolValue)
		{
			return boolValue;
		}
		if (value != null && bool.TryParse(Convert.ToString(value, CultureInfo.InvariantCulture), out var parsed))
		{
			return parsed;
		}
		return fallback;
	}

	private static double ReadObjectDouble(object source, string propertyName, double fallback)
	{
		object value = GetObjectProperty(source, propertyName);
		if (value == null)
		{
			return fallback;
		}
		try
		{
			return Convert.ToDouble(value, CultureInfo.InvariantCulture);
		}
		catch
		{
			return fallback;
		}
	}

	private static double ReadNestedMetricPercent(object source, string propertyName)
	{
		object metric = GetObjectProperty(source, propertyName);
		object value = GetObjectProperty(metric, "percent");
		if (value == null)
		{
			return 0.0;
		}
		try
		{
			return Convert.ToDouble(value, CultureInfo.InvariantCulture);
		}
		catch
		{
			return 0.0;
		}
	}

	private static bool IsObservabilityFailureStatus(string status)
	{
		status = (status ?? "").Trim();
		return status.IndexOf("fail", StringComparison.OrdinalIgnoreCase) >= 0 || status.IndexOf("error", StringComparison.OrdinalIgnoreCase) >= 0 || status.IndexOf("cancel", StringComparison.OrdinalIgnoreCase) >= 0 || status.IndexOf("timeout", StringComparison.OrdinalIgnoreCase) >= 0;
	}

	private static string ExtractObservabilityLogName(string message)
	{
		message = (message ?? "").Trim();
		if (message.Length == 0)
		{
			return "Log";
		}
		if (message.StartsWith("[", StringComparison.Ordinal))
		{
			int end = message.IndexOf(']');
			if (end > 1)
			{
				return message.Substring(1, end - 1);
			}
		}
		int colon = message.IndexOf(':');
		if (colon > 0 && colon < 64)
		{
			return message.Substring(0, colon).Trim();
		}
		return (message.Length > 80) ? message.Substring(0, 80) : message;
	}

	private static string SafeOwnerKey(Func<string> ownerKey)
	{
		if (ownerKey == null)
		{
			return "";
