	private static bool JsonResponseLooksSuccessful(string json)
	{
		if (string.IsNullOrWhiteSpace(json))
		{
			return true;
		}
		string trimmed = json.TrimStart();
		if (trimmed.Length == 0 || (trimmed[0] != '{' && trimmed[0] != '['))
		{
			return true;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			if (document.RootElement.ValueKind != JsonValueKind.Object)
			{
				return true;
			}
			JsonElement value = document.RootElement;
			if (value.TryGetProperty("ok", out var okElement) && okElement.ValueKind == JsonValueKind.False)
			{
				return false;
			}
			if (!document.RootElement.TryGetProperty("ok", out value) && (document.RootElement.TryGetProperty("error", out value) || document.RootElement.TryGetProperty("Error", out value)))
			{
				return false;
			}
		}
		catch
		{
			return true;
		}
		return true;
	}

	private static string ExtractObservabilityJsonError(string json)
	{
		if (string.IsNullOrWhiteSpace(json))
		{
			return "";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			if (document.RootElement.ValueKind == JsonValueKind.Object)
			{
				if (document.RootElement.TryGetProperty("error", out var error) && error.ValueKind == JsonValueKind.String)
				{
					return error.GetString() ?? "";
				}
				if (document.RootElement.TryGetProperty("detail", out var detail) && detail.ValueKind == JsonValueKind.String)
				{
					return detail.GetString() ?? "";
				}
			}
		}
		catch
		{
		}
		return "";
	}

	private SemaphoreSlim GetSharedPromptQueue(string sessionId)
	{
		sessionId = EnsureChatUiSessionId(sessionId);
		lock (_sharedPromptQueueLock)
		{
			if (!_sharedPromptQueues.TryGetValue(sessionId, out var queue))
			{
				queue = new SemaphoreSlim(1, 1);
				_sharedPromptQueues[sessionId] = queue;
			}
			return queue;
		}
	}

	private string InferPromptSessionTitle(string requestBody)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(requestBody) ? "{}" : requestBody);
			JsonElement root = document.RootElement;
			if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty("messages", out var messages) && messages.ValueKind == JsonValueKind.Array)
			{
				List<JsonElement> messageList = new List<JsonElement>();
				foreach (JsonElement message in messages.EnumerateArray())
				{
					messageList.Add(message);
				}
				for (int i = messageList.Count - 1; i >= 0; i--)
				{
					JsonElement message2 = messageList[i];
					string role = ExtractStringProperty(message2, "role") ?? "";
					if (role.Equals("user", StringComparison.OrdinalIgnoreCase))
					{
						string text = ExtractMessageTextForTitle(message2);
						if (!string.IsNullOrWhiteSpace(text))
						{
							return TruncateForLog(text.Replace("\r", " ").Replace("\n", " "), 72);
						}
					}
				}
			}
			if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty("input", out var input))
			{
				string text2 = ((input.ValueKind == JsonValueKind.String) ? input.GetString() : ExtractResponsesContentText(input));
				if (!string.IsNullOrWhiteSpace(text2))
				{
					return TruncateForLog(text2.Replace("\r", " ").Replace("\n", " "), 72);
				}
			}
		}
		catch
		{
		}
		return "LLM prompt " + DateTime.Now.ToString("h:mm:ss tt");
	}

	private string GetHttpPromptOwnerKey(HttpListenerRequest request)
	{
		try
