			string ip = request?.RemoteEndPoint?.Address?.ToString();
			if (!string.IsNullOrWhiteSpace(ip))
			{
				return "ip:" + NormalizeClientIp(ip);
			}
		}
		catch
		{
		}
		return GetDefaultLocalChatOwnerKey();
	}

	public LmVsProxy(string lmStudioHost, int lmStudioPort, int proxyPort, int chatServerPort = 0)
		: this(lmStudioHost, lmStudioPort, proxyPort, chatServerPort, null)
	{
	}

	public LmVsProxy(string lmStudioHost, int lmStudioPort, int proxyPort, int chatServerPort, string dataRoot)
	{
		if (string.IsNullOrWhiteSpace(lmStudioHost))
		{
			throw new ArgumentException("LM Studio host is required.", "lmStudioHost");
		}
		if (lmStudioPort <= 0 || lmStudioPort > 65535)
		{
			throw new ArgumentException("LM Studio port must be between 1 and 65535.", "lmStudioPort");
		}
		if (proxyPort <= 0 || proxyPort > 65535)
		{
			throw new ArgumentException("Proxy port must be between 1 and 65535.", "proxyPort");
		}
		if (chatServerPort < 0 || chatServerPort > 65535)
		{
			throw new ArgumentException("Chat server port must be between 1 and 65535, or 0 for automatic selection.", "chatServerPort");
		}
		_lmStudioHost = lmStudioHost;
		_lmStudioPort = lmStudioPort;
		LocalModelRuntime = new HttpLmVsProxyModelRuntime("LM Studio", "http://" + lmStudioHost + ":" + lmStudioPort.ToString(CultureInfo.InvariantCulture), () => (EnsureLmStudioStartedAsync == null) ? Task.CompletedTask : EnsureLmStudioStartedAsync());
		_proxyPort = proxyPort;
		_chatServerPort = ((chatServerPort == 0) ? ChooseDefaultChatServerPort(lmStudioPort, proxyPort) : chatServerPort);
		_httpClient = new System.Net.Http.HttpClient(new HttpClientHandler
		{
			AutomaticDecompression = (DecompressionMethods.GZip | DecompressionMethods.Deflate)
		});
		_httpClient.Timeout = _promptTimeout;
		_chatBrowserProxyCookieContainer = new CookieContainer();
		_chatBrowserProxyHttpClient = new System.Net.Http.HttpClient(new HttpClientHandler
		{
			AutomaticDecompression = (DecompressionMethods.GZip | DecompressionMethods.Deflate),
			AllowAutoRedirect = false,
			UseCookies = true,
			CookieContainer = _chatBrowserProxyCookieContainer
		});
		_chatBrowserProxyHttpClient.Timeout = _promptTimeout;
		_browserSkillHttpClient = new System.Net.Http.HttpClient(new HttpClientHandler
		{
			AutomaticDecompression = (DecompressionMethods.GZip | DecompressionMethods.Deflate),
			AllowAutoRedirect = false
		});
		_browserSkillHttpClient.Timeout = _promptTimeout;
		_upstreamAdapter = new UpstreamAdapter(ChatModel);
		string sessionBaseDirectory = GetSessionBaseDirectory(dataRoot);
		_chatSessionRoot = GetDefaultChatSessionRoot(sessionBaseDirectory);
		_chatSessionFilesRoot = Path.Combine(_chatSessionRoot, "SessionFiles");
		_remoteSessionCloneRoot = GetDefaultRemoteSessionCloneRoot(sessionBaseDirectory);
		_sockJackDml = new SockJackDmlService(_chatSessionRoot);
		_sockJackDmlWorkflows = new SockJackDmlWorkflowService(_chatSessionRoot);
		StartRemoteSessionFileCloneWatcher();
		_chatSessionData = new DataServer("JackLLMChat", hosted: true)
		{
			DataPath = Path.Combine(_chatSessionRoot, "SocketJackDatabase.json"),
			DefaultDatabase = "SocketJack",
			ServerName = "JackLLMChat",
			AutoSave = true,
			AutoSaveDebounceMs = 250
		};
		_chatSessionData.LogOutput += RelaySocketJackLogOutput;
		_chatSessionData.OnError += RelaySocketJackError;
		_chatSessionData.Load();
		EnsureChatSessionTables();
		TryRegisterWpfRemoteControlProvider();
	}

