	private SandboxSession GetOrCreateChatSessionSandbox(string sessionId, string ownerKey)
	{
		sessionId = EnsureChatUiSessionId(sessionId);
		lock (_chatSessionSandboxLock)
		{
			if (_chatSessionSandboxes.TryGetValue(sessionId, out var existing) && existing != null && existing.State != SandboxSessionState.Disposed && existing.State != SandboxSessionState.Discarded)
			{
				return existing;
			}
			SandboxOptions options = CreateChatSessionSandboxOptions(sessionId, ownerKey);
			SandboxSession sandbox = SandboxSession.Create(options);
			sandbox.Audit.EventRecorded += OnChatSessionSandboxAuditEvent;
			_chatSessionSandboxes[sessionId] = sandbox;
			return sandbox;
		}
	}

	private SandboxOptions CreateChatSessionSandboxOptions(string sessionId, string ownerKey)
	{
		SandboxOptions options = SandboxOptions.CreateMemoryOverlay("jackllm-session-files");
		options.SessionId = BuildChatSessionSandboxSessionId(sessionId);
		options.TenantId = NormalizeChatFilesystemOwnerKey(ownerKey);
		options.Registry.Mode = SandboxRegistryMode.DenyAll;
		options.Registry.ReadPolicy = SandboxRegistryReadPolicy.DenyByDefault;
		options.Registry.WritePolicy = SandboxRegistryWritePolicy.Deny;
		options.Persistence.Mode = SandboxPersistenceMode.Discard;
		options.Persistence.SnapshotDirectory = "";
		options.Limits.MaxFileBytes = Math.Max(options.Limits.MaxFileBytes, 104857600L);
		options.Limits.MaxMemoryBytes = Math.Max(options.Limits.MaxMemoryBytes, 1610612736L);
		return options;
	}

	private static string BuildChatSessionSandboxSessionId(string sessionId)
	{
		string safe = (string.IsNullOrWhiteSpace(sessionId) ? "default-session" : sessionId.Trim());
		StringBuilder sb = new StringBuilder("jackllm_session_");
		string text = safe;
		foreach (char ch in text)
		{
			if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') || (ch >= '0' && ch <= '9') || ch == '_' || ch == '-')
			{
				sb.Append(ch);
			}
			else
			{
				sb.Append('_');
			}
		}
		return sb.ToString();
	}

	private void OnChatSessionSandboxAuditEvent(object sender, SandboxAuditEventArgs e)
	{
		try
		{
			SandboxAuditEvent auditEvent = e?.Event;
			if (auditEvent != null && (auditEvent.Mutation || !auditEvent.Allowed))
			{
				LogMessage("[SocketJack Sandbox] " + (auditEvent.Allowed ? "allowed " : "blocked ") + (auditEvent.Category ?? "sandbox") + " " + auditEvent.Operation + " " + auditEvent.Target + (string.IsNullOrWhiteSpace(auditEvent.Reason) ? "" : (" - " + auditEvent.Reason)));
			}
		}
		catch
		{
		}
	}

	private string GetRemoteSessionCloneDirectory(string sessionId)
	{
		string sessionFolder = SanitizeFileName(string.IsNullOrWhiteSpace(sessionId) ? "default-session" : sessionId.Trim());
		return Path.GetFullPath(Path.Combine(_remoteSessionCloneRoot, sessionFolder));
	}

	private string GetRemoteSessionCloneSessionIdFromPath(string fullPath)
	{
		try
		{
			string relative = Path.GetRelativePath(_remoteSessionCloneRoot, Path.GetFullPath(fullPath));
			string first = relative.Split(new char[2]
			{
				Path.DirectorySeparatorChar,
				Path.AltDirectorySeparatorChar
			}, StringSplitOptions.RemoveEmptyEntries).FirstOrDefault();
			return string.IsNullOrWhiteSpace(first) ? "" : first.Trim();
		}
		catch
		{
			return "";
		}
	}

	private SandboxFileEntry WriteChatSessionFileBytesToSandbox(string sessionId, string ownerKey, string fullPath, byte[] bytes, string kind, out string sandboxSessionId)
	{
		sandboxSessionId = "";
		if (string.IsNullOrWhiteSpace(fullPath))
		{
			throw new ArgumentException("Session file path is required.", "fullPath");
		}
		sessionId = EnsureChatUiSessionId(sessionId);
		string sandboxPath = BuildChatSessionSandboxPath(sessionId, fullPath);
		SandboxSession sandbox = GetOrCreateChatSessionSandbox(sessionId, ownerKey);
		SandboxFileEntry entry = sandbox.FileSystem.WriteAllBytes(sandboxPath, bytes ?? Array.Empty<byte>(), new SandboxFileWriteOptions
		{
			Overwrite = true,
			Kind = (string.IsNullOrWhiteSpace(kind) ? "session-file" : kind.Trim()),
			SourcePath = Path.GetFullPath(fullPath)
		});
		sandboxSessionId = sandbox.Id;
		return entry;
	}

	private SandboxFileEntry ImportChatSessionFileToSandbox(string sessionId, string ownerKey, string fullPath, string kind, out string sandboxSessionId)
	{
		string normalized = Path.GetFullPath(fullPath);
		return WriteChatSessionFileBytesToSandbox(sessionId, ownerKey, normalized, File.ReadAllBytes(normalized), kind, out sandboxSessionId);
	}

	private string BuildChatSessionSandboxPath(string sessionId, string fullPath)
	{
		string normalized = Path.GetFullPath(fullPath);
		string sessionRoot = GetChatSessionFilesDirectory(sessionId);
		if (!string.IsNullOrWhiteSpace(sessionRoot) && IsPathInsideRoot(normalized, sessionRoot))
		{
			return CombineSandboxPath("/session", SafeRelativePath(sessionRoot, normalized));
		}
		string remoteRoot = GetRemoteSessionCloneDirectory(sessionId);
		if (!string.IsNullOrWhiteSpace(remoteRoot) && IsPathInsideRoot(normalized, remoteRoot))
		{
			return CombineSandboxPath("/remote-session", SafeRelativePath(remoteRoot, normalized));
		}
		throw new SandboxPolicyException("write", normalized, "JackLLM session files must stay inside the current SocketJack Sandbox mounts.");
	}

	private bool TryGetChatSessionSandboxFileEntry(string sessionId, string ownerKey, string fullPath, out SandboxFileEntry entry)
	{
		entry = null;
		if (!IsJackLlmSessionManagedPath(fullPath))
		{
			return false;
		}
		try
		{
			string sandboxPath = BuildChatSessionSandboxPath(sessionId, fullPath);
			SandboxSession sandbox = GetOrCreateChatSessionSandbox(sessionId, ownerKey);
			if (!sandbox.FileSystem.FileExists(sandboxPath))
			{
				return TryHydrateChatSessionSandboxFileFromDatabase(sessionId, ownerKey, fullPath, out entry);
			}
			entry = sandbox.FileSystem.GetFile(sandboxPath);
			return entry != null;
		}
		catch
		{
			return false;
		}
	}

	private void HydrateChatSessionSandboxFilesFromSessionMetadata(string sessionId, string ownerKey, string rootPath = null)
	{
		sessionId = EnsureChatUiSessionId(sessionId);
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return;
		}
		string normalizedRoot = null;
		try
		{
			if (!string.IsNullOrWhiteSpace(rootPath))
			{
				normalizedRoot = Path.GetFullPath(rootPath);
			}
		}
		catch
		{
			normalizedRoot = null;
		}
		List<ChatSessionFile> files = new List<ChatSessionFile>();
		string normalizedOwner = NormalizeChatFilesystemOwnerKey(ownerKey);
		try
		{
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] row = NormalizeChatSessionRow(table.Rows[i]);
					if (!string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
					{
						continue;
					}
					if (!string.IsNullOrWhiteSpace(normalizedOwner) && !ChatOwnerKeysMatch(normalizedOwner, GetRowValue(row, 7)))
					{
						continue;
					}
					AddChatSessionFilesFromJson(files, new HashSet<string>(StringComparer.OrdinalIgnoreCase), GetChatSessionPrivateValue(row, 6, "files", "[]", normalizedOwner));
					break;
				}
			}
			if (files.Count == 0)
			{
				return;
			}
			SandboxSession sandbox = GetOrCreateChatSessionSandbox(sessionId, normalizedOwner);
			foreach (ChatSessionFile file in files)
			{
				if (file == null || string.IsNullOrWhiteSpace(file.path) || string.IsNullOrWhiteSpace(file.contentBase64))
				{
					continue;
				}
				string fullPath;
				try
				{
					fullPath = Path.GetFullPath(file.path);
				}
				catch
				{
					continue;
				}
				if (!IsJackLlmSessionManagedPath(fullPath))
				{
					continue;
				}
				if (!string.IsNullOrWhiteSpace(normalizedRoot) && !IsPathInsideRoot(fullPath, normalizedRoot))
				{
					continue;
				}
				string sandboxPath = BuildChatSessionSandboxPath(sessionId, fullPath);
				if (sandbox.FileSystem.FileExists(sandboxPath))
				{
					continue;
				}
				byte[] bytes;
				try
				{
					bytes = Convert.FromBase64String(file.contentBase64);
				}
				catch
				{
					continue;
				}
				sandbox.FileSystem.WriteAllBytes(sandboxPath, bytes ?? Array.Empty<byte>(), new SandboxFileWriteOptions
				{
					Overwrite = true,
					Kind = "metadata-hydrated-session-file",
					SourcePath = fullPath
				});
			}
		}
		catch
		{
		}
	}

	private bool TryHydrateChatSessionSandboxFileFromDatabase(string sessionId, string ownerKey, string fullPath, out SandboxFileEntry entry)
	{
		entry = null;
		if (string.IsNullOrWhiteSpace(sessionId) || string.IsNullOrWhiteSpace(fullPath) || !IsJackLlmSessionManagedPath(fullPath))
		{
			return false;
		}
		try
		{
			string normalizedPath = Path.GetFullPath(fullPath);
			string normalizedOwner = NormalizeChatFilesystemOwnerKey(ownerKey);
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] row = NormalizeChatSessionRow(table.Rows[i]);
					if (!string.Equals(GetRowValue(row, 0), EnsureChatUiSessionId(sessionId), StringComparison.Ordinal))
					{
						continue;
					}
					if (!string.IsNullOrWhiteSpace(normalizedOwner) && !ChatOwnerKeysMatch(normalizedOwner, GetRowValue(row, 7)))
					{
						continue;
					}
					List<ChatSessionFile> files = new List<ChatSessionFile>();
					AddChatSessionFilesFromJson(files, new HashSet<string>(StringComparer.OrdinalIgnoreCase), GetChatSessionPrivateValue(row, 6, "files", "[]", normalizedOwner));
					foreach (ChatSessionFile file in files)
					{
						if (file == null || string.IsNullOrWhiteSpace(file.path) || !PathsEqual(file.path, normalizedPath) || string.IsNullOrWhiteSpace(file.contentBase64))
						{
							continue;
						}
						byte[] bytes = Convert.FromBase64String(file.contentBase64);
						string sandboxSessionId;
						entry = WriteChatSessionFileBytesToSandbox(sessionId, normalizedOwner, normalizedPath, bytes, "database-hydrated-session-file", out sandboxSessionId);
						return entry != null;
					}
				}
			}
		}
		catch
		{
			entry = null;
		}
		return false;
	}

	private bool TryReadChatSessionSandboxTextFile(string sessionId, string ownerKey, string fullPath, out string text)
	{
		text = null;
		if (!IsJackLlmSessionManagedPath(fullPath))
		{
			return false;
		}
		try
		{
			string sandboxPath = BuildChatSessionSandboxPath(sessionId, fullPath);
			SandboxSession sandbox = GetOrCreateChatSessionSandbox(sessionId, ownerKey);
			if (!sandbox.FileSystem.FileExists(sandboxPath))
			{
				if (!TryHydrateChatSessionSandboxFileFromDatabase(sessionId, ownerKey, fullPath, out var _))
				{
					return false;
				}
			}
			text = sandbox.FileSystem.ReadAllText(sandboxPath, Encoding.UTF8);
			return true;
		}
		catch
		{
			return false;
		}
	}

