	}

	private static string CombineSandboxPath(string root, string relativePath)
	{
		List<string> parts = new List<string>();
		string[] array = (relativePath ?? "").Replace('\\', '/').Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries);
		foreach (string raw in array)
		{
			string part = raw.Trim();
			if (part.Length != 0 && !(part == ".") && !(part == ".."))
			{
				parts.Add(part);
			}
		}
		string prefix = (string.IsNullOrWhiteSpace(root) ? "/" : root.TrimEnd('/'));
		return (parts.Count == 0) ? (prefix + "/file") : (prefix + "/" + string.Join("/", parts));
	}

	private bool IsJackLlmSessionManagedPath(string fullPath)
	{
		if (string.IsNullOrWhiteSpace(fullPath))
		{
			return false;
		}
		return IsPathInsideRoot(fullPath, _chatSessionFilesRoot) || IsPathInsideRoot(fullPath, _remoteSessionCloneRoot);
	}

	private string ToChatSessionVirtualPath(string sessionId, string fullPath)
	{
		if (string.IsNullOrWhiteSpace(fullPath))
		{
			return fullPath ?? "";
		}
		try
		{
			string normalized = Path.GetFullPath(fullPath);
			string sessionRoot = GetChatSessionFilesDirectory(sessionId);
			if (!string.IsNullOrWhiteSpace(sessionRoot) && IsPathInsideRoot(normalized, sessionRoot))
			{
				return BuildChatSessionVirtualPath(SafeRelativePath(sessionRoot, normalized));
			}
			string remoteRoot = GetRemoteSessionCloneDirectory(sessionId);
			if (!string.IsNullOrWhiteSpace(remoteRoot) && IsPathInsideRoot(normalized, remoteRoot))
			{
				return BuildChatSessionVirtualPath(Path.Combine("RemoteSession", SafeRelativePath(remoteRoot, normalized)));
			}
		}
		catch
		{
		}
		return fullPath;
	}

	private string BuildChatSessionVirtualPath(string relativePath)
	{
		List<string> parts = new List<string>();
		string normalized = (relativePath ?? "").Replace('\\', '/');
		foreach (string rawPart in normalized.Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries))
		{
			string part = rawPart.Trim();
			if (part.Length != 0 && part != "." && part != "..")
			{
				parts.Add(part);
			}
		}
		return parts.Count == 0 ? "\\" : ("\\" + string.Join("\\", parts));
	}

	private string FormatChatAgentPathForOutput(string fullPath, string sessionId)
	{
		return IsJackLlmSessionManagedPath(fullPath) ? ToChatSessionVirtualPath(sessionId, fullPath) : (fullPath ?? "");
	}

	private bool TryResolveChatSessionRequestPath(string sessionId, string requestedPath, out string fullPath, out string error)
	{
		fullPath = null;
		error = null;
		string sessionRoot = GetChatSessionFilesDirectory(sessionId);
		if (string.IsNullOrWhiteSpace(sessionRoot))
		{
			error = "Session file directory is unavailable.";
			return false;
		}
		string cleaned = NormalizeLoosePathEscapes(requestedPath ?? "").Trim().Trim('"', '\'', ',', ' ');
		if (string.IsNullOrWhiteSpace(cleaned) || cleaned == "\\" || cleaned == "/")
		{
			fullPath = sessionRoot;
			return true;
		}
		try
		{
			string candidate = Path.GetFullPath(cleaned);
			if (IsPathInsideRoot(candidate, sessionRoot))
			{
				fullPath = candidate;
				return true;
			}
		}
		catch
		{
		}
		string relative = cleaned.Replace('\\', '/').TrimStart('/');
		if (relative.Length == 0)
		{
			fullPath = sessionRoot;
			return true;
		}
		string[] parts = relative.Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries);
		List<string> safeParts = new List<string>();
		foreach (string rawPart in parts)
		{
			string part = rawPart.Trim();
			if (part.Length == 0 || part == ".")
			{
				continue;
			}
			if (part == "..")
			{
				error = "Session paths cannot contain parent traversal.";
				return false;
			}
			safeParts.Add(part);
		}
		try
		{
			string candidate = sessionRoot;
			foreach (string part in safeParts)
			{
				candidate = Path.Combine(candidate, part);
			}
			candidate = Path.GetFullPath(candidate);
			if (!IsPathInsideRoot(candidate, sessionRoot))
			{
				error = "path is outside the current session files.";
				return false;
			}
			fullPath = candidate;
			return true;
		}
		catch (Exception ex)
		{
			error = ex.Message;
			return false;
		}
	}

	private void AttachSandboxMetadata(string sessionId, string ownerKey, ChatSessionFile file, string kind)
	{
		if (file != null && !string.IsNullOrWhiteSpace(file.path))
		{
			string fullPath = Path.GetFullPath(file.path);
			if (File.Exists(fullPath) && IsJackLlmSessionManagedPath(fullPath))
			{
				string sandboxSessionId;
				SandboxFileEntry entry = ImportChatSessionFileToSandbox(sessionId, ownerKey, fullPath, kind, out sandboxSessionId);
				file.sandboxed = true;
				file.sandboxSessionId = sandboxSessionId;
				file.sandboxFileId = entry.Id;
				file.sandboxPath = entry.Path;
				file.sandboxSha256 = entry.Sha256;
			}
		}
	}

	private void AttachSandboxMetadata(string sessionId, string ownerKey, ChatSessionFile file, SandboxFileEntry entry, string sandboxSessionId)
	{
		if (file != null && entry != null)
		{
			file.sandboxed = true;
			file.sandboxSessionId = sandboxSessionId ?? "";
			file.sandboxFileId = entry.Id ?? "";
			file.sandboxPath = entry.Path ?? "";
			file.sandboxSha256 = entry.Sha256 ?? "";
			if (string.IsNullOrWhiteSpace(file.contentBase64) &&
				!string.IsNullOrWhiteSpace(file.path) &&
				TryReadChatSessionSandboxFileBytes(sessionId, ownerKey, file.path, out var bytes))
			{
				file.contentBase64 = Convert.ToBase64String(bytes ?? Array.Empty<byte>());
			}
		}
	}

	private SandboxFileManifest GetChatSessionSandboxManifest(string sessionId, string ownerKey)
	{
		try
		{
			return GetOrCreateChatSessionSandbox(sessionId, ownerKey).FileSystem.GetManifest();
		}
		catch (Exception ex)
		{
			LogMessage("[SocketJack Sandbox] Session manifest failed for " + sessionId + ": " + ex.Message);
			return null;
		}
	}

	private void DiscardChatSessionSandbox(string sessionId)
	{
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return;
		}
		SandboxSession sandbox = null;
		lock (_chatSessionSandboxLock)
		{
			if (_chatSessionSandboxes.TryGetValue(sessionId, out sandbox))
			{
				_chatSessionSandboxes.Remove(sessionId);
			}
		}
		if (sandbox == null)
		{
			return;
		}
		try
		{
			sandbox.Audit.EventRecorded -= OnChatSessionSandboxAuditEvent;
		}
		catch
		{
		}
		try
		{
			sandbox.Discard();
		}
		catch
		{
		}
		try
		{
			sandbox.DisposeAsync().GetAwaiter().GetResult();
		}
		catch
		{
		}
	}

	private void DisposeChatSessionSandboxes()
	{
		List<SandboxSession> sandboxes;
		lock (_chatSessionSandboxLock)
		{
			sandboxes = _chatSessionSandboxes.Values.Where((SandboxSession item) => item != null).ToList();
			_chatSessionSandboxes.Clear();
		}
		foreach (SandboxSession sandbox in sandboxes)
		{
			try
			{
				sandbox.Audit.EventRecorded -= OnChatSessionSandboxAuditEvent;
			}
			catch
			{
			}
			try
			{
				sandbox.DisposeAsync().GetAwaiter().GetResult();
			}
			catch
			{
			}
		}
	}

	private static string GetSessionBaseDirectory(string dataRoot)
	{
		if (!string.IsNullOrWhiteSpace(dataRoot))
		{
			return PrepareSessionBaseDirectory(dataRoot);
		}
		return GetExecutableDirectoryForSessions();
	}

	private static string GetExecutableDirectoryForSessions()
	{
		string dataRoot = Environment.GetEnvironmentVariable("JACKLLM_DATA_ROOT") ?? "";
		if (!string.IsNullOrWhiteSpace(dataRoot))
		{
			try
			{
				return PrepareSessionBaseDirectory(dataRoot);
			}
			catch
			{
			}
		}

		string baseDirectory = AppContext.BaseDirectory;
		if (string.IsNullOrWhiteSpace(baseDirectory))
		{
			baseDirectory = Directory.GetCurrentDirectory();
		}
		return baseDirectory;
	}

	private static string PrepareSessionBaseDirectory(string dataRoot)
	{
		string fullDataRoot = Path.GetFullPath(Environment.ExpandEnvironmentVariables(dataRoot.Trim()));
		Directory.CreateDirectory(fullDataRoot);
		return fullDataRoot;
	}

	private async Task EnsureLmStudioForPromptAsync()
	{
		ILmVsProxyModelRuntime runtime = GetEffectiveLocalModelRuntime();
		if (runtime == null)
		{
			return;
		}
		try
		{
			Task launchTask = runtime.EnsureStartedAsync();
			if (launchTask != null)
			{
				await launchTask.ConfigureAwait(continueOnCapturedContext: false);
			}
		}
		catch (Exception ex)
		{
			if (await TryActivateEmergencyFallbackAsync(runtime, "ensure-start", ex.Message, ex).ConfigureAwait(continueOnCapturedContext: false))
			{
				return;
			}
			LogMessage("[" + GetModelRuntimeDisplayName(runtime) + "] Deferred launch hook failed: " + ex.Message);
		}
	}

	public async Task<bool> TryActivateEmergencyModelRuntimeFallbackAsync(string operation, string reason, Exception exception = null)
	{
		return await TryActivateEmergencyFallbackAsync(GetPrimaryLocalModelRuntime(), operation, reason, exception).ConfigureAwait(continueOnCapturedContext: false);
	}

	private ILmVsProxyModelRuntime GetPrimaryLocalModelRuntime()
	{
		lock (_modelRuntimeLock)
		{
			return _localModelRuntime;
		}
	}

	private ILmVsProxyModelRuntime GetEffectiveLocalModelRuntime()
	{
		lock (_modelRuntimeLock)
		{
			return _emergencyFallbackActiveRuntime ?? _localModelRuntime;
		}
	}

	private bool IsEmergencyFallbackActive()
	{
		lock (_modelRuntimeLock)
		{
			return _emergencyFallbackActiveRuntime != null;
		}
	}

	private async Task<bool> TryActivateEmergencyFallbackAsync(ILmVsProxyModelRuntime failedRuntime, string operation, string reason, Exception exception)
	{
		if (!EmergencyModelRuntimeFallbackEnabled)
		{
			return false;
		}
		ILmVsProxyModelRuntime fallback = EmergencyFallbackModelRuntime;
		if (fallback == null)
		{
			return false;
		}
		string primaryName = GetModelRuntimeDisplayName(failedRuntime);
		string fallbackName = GetModelRuntimeDisplayName(fallback);
		if (string.IsNullOrWhiteSpace(primaryName) || string.Equals(primaryName, fallbackName, StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		lock (_modelRuntimeLock)
		{
			if (_emergencyFallbackActiveRuntime != null)
			{
				return true;
			}
		}
		LogMessage("[Model Runtime] Critical " + primaryName + " failure during " + (operation ?? "prompt") + ": " + (reason ?? exception?.Message ?? "unknown error") + ". Checking " + fallbackName + " emergency fallback.");
		try
		{
			Task launchTask = fallback.EnsureStartedAsync();
			if (launchTask != null)
			{
				await launchTask.ConfigureAwait(continueOnCapturedContext: false);
			}
			if (!(await IsModelRuntimeEndpointAvailableAsync(fallback).ConfigureAwait(continueOnCapturedContext: false)))
			{
				LogMessage("[Model Runtime] Emergency fallback was not activated because " + fallbackName + " did not answer /v1/models.");
				await ReportModelRuntimeFallbackAsync(primaryName, fallbackName, operation, reason, exception, activated: false).ConfigureAwait(continueOnCapturedContext: false);
				return false;
			}
			lock (_modelRuntimeLock)
			{
				_emergencyFallbackActiveRuntime = fallback;
			}
			LogMessage("[Model Runtime] Emergency fallback activated: " + fallbackName + " is now handling prompts because " + primaryName + " critically failed.");
			await ReportModelRuntimeFallbackAsync(primaryName, fallbackName, operation, reason, exception, activated: true).ConfigureAwait(continueOnCapturedContext: false);
			return true;
		}
		catch (Exception ex)
		{
			LogMessage("[Model Runtime] Emergency fallback failed: " + fallbackName + " could not start or respond. " + ex.Message);
			await ReportModelRuntimeFallbackAsync(primaryName, fallbackName, operation, reason + " | fallback failed: " + ex.Message, exception ?? ex, activated: false).ConfigureAwait(continueOnCapturedContext: false);
			return false;
		}
	}

	private async Task<bool> IsModelRuntimeEndpointAvailableAsync(ILmVsProxyModelRuntime runtime)
	{
		string baseUrl = ((runtime == null) ? "" : runtime.OpenAiBaseUrl);
		baseUrl = LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(baseUrl);
		if (string.IsNullOrWhiteSpace(baseUrl))
		{
			return false;
		}
		try
		{
			using CancellationTokenSource timeout = new CancellationTokenSource(TimeSpan.FromSeconds(4.0));
			using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, baseUrl.TrimEnd('/') + "/v1/models");
			using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, timeout.Token).ConfigureAwait(continueOnCapturedContext: false);
			return response.IsSuccessStatusCode;
		}
		catch
		{
			return false;
		}
	}

	private async Task ReportModelRuntimeFallbackAsync(string primaryName, string fallbackName, string operation, string reason, Exception exception, bool activated)
	{
		Func<LmVsProxyModelRuntimeFallbackReport, Task> reporter = ModelRuntimeFallbackReporterAsync;
		if (reporter == null)
		{
			return;
		}
		lock (_modelRuntimeLock)
		{
			if (_emergencyFallbackReportSent && activated)
			{
				return;
			}
			if (activated)
			{
				_emergencyFallbackReportSent = true;
			}
		}
		LmVsProxyServerProfile profile = GetServerBrowserProfile();
		LmVsProxyModelRuntimeFallbackReport report = new LmVsProxyModelRuntimeFallbackReport
		{
			Id = "runtime_" + Guid.NewGuid().ToString("N"),
			CreatedUtc = DateTimeOffset.UtcNow.ToString("O", CultureInfo.InvariantCulture),
			Severity = (activated ? "critical" : "warning"),
			Category = (activated ? "model-runtime-fallback-activated" : "model-runtime-fallback-unavailable"),
			PrimaryProvider = (primaryName ?? ""),
			FallbackProvider = (fallbackName ?? ""),
			Operation = (operation ?? ""),
			Reason = (reason ?? exception?.Message ?? ""),
			Detail = ((exception == null) ? "" : exception.ToString()),
			MachineName = Environment.MachineName,
			ServerId = (profile?.ServerId ?? ""),
			ServerName = (profile?.ServerName ?? ""),
			OwnerUserName = (profile?.OwnerUserName ?? ""),
			PublicHost = (profile?.PublicHost ?? "")
		};
		try
		{
			Task task = reporter(report);
			if (task != null)
			{
				await task.ConfigureAwait(continueOnCapturedContext: false);
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Model Runtime] SocketJack.com fallback report failed: " + ex.Message);
		}
	}

	public bool Start()
	{
		if (_isDisposed)
		{
			throw new ObjectDisposedException("LmVsProxy is disposed.");
		}
		if (_isRunning)
		{
			return false;
		}
		try
		{
			_httpListener = new HttpListener();
			_httpListener.Prefixes.Add($"http://localhost:{_proxyPort}/");
			_httpListener.Start();
			_cts = new CancellationTokenSource();
			_isRunning = true;
			_listenerTask = Task.Run(() => ListenerLoop(_cts.Token), _cts.Token);
			StartCopilotDuplicatorListener();
			return true;
		}
		catch (Exception innerException)
		{
			throw new InvalidOperationException($"Failed to start LmVsProxy on port {_proxyPort}.", innerException);
		}
	}

	public void Stop()
	{
		StopCopilotDuplicatorListener();
		StopChatServer();
		if (!_isRunning)
		{
			return;
		}
		_isRunning = false;
		_cts?.Cancel();
		try
		{
			_httpListener?.Stop();
			_listenerTask?.Wait(TimeSpan.FromSeconds(5.0));
		}
		catch
		{
		}
	}

	private void LogMessage(string message)
	{
		string safeMessage = RedactSensitiveLogText(message ?? "");
		RecordObservabilityEvent("log", ExtractObservabilityLogName(safeMessage), IsObservabilityFailureStatus(safeMessage) ? "error" : "info", safeMessage, "", "", 0L);
		string formatted = "[LmVsProxy] " + safeMessage;
		if (!formatted.EndsWith(Environment.NewLine, StringComparison.Ordinal))
		{
			formatted += Environment.NewLine;
		}
		this.OutputLog?.Invoke(this, new OutputLogEventArgs(formatted));
	}

	private string RedactSensitiveLogText(string text)
	{
		if (string.IsNullOrEmpty(text))
		{
			return "";
		}
		string redacted = text;
		redacted = Regex.Replace(redacted, "(?i)\"(authorization|bearer|password|passwd|api[_-]?key|access[_-]?token|refresh[_-]?token|secret|client[_-]?secret)\"\\s*:\\s*\"[^\"]*\"", "\"$1\":\"<redacted>\"");
		redacted = Regex.Replace(redacted, "(?i)\\b(authorization|password|passwd|api[-_ ]?key|access[-_ ]?token|refresh[-_ ]?token|secret|client[-_ ]?secret)\\b\\s*[:=]\\s*\"?[^\"\\s,;]+\"?", "$1=<redacted>");
		redacted = Regex.Replace(redacted, "(?i)\\bBearer\\s+[A-Za-z0-9._~+/=-]{12,}", "Bearer <redacted>");
		return TruncateForLog(redacted, 4000);
	}

	private void RelaySocketJackLogOutput(string text)
	{
		if (!string.IsNullOrWhiteSpace(text))
		{
			string formatted = text;
			if (!formatted.EndsWith(Environment.NewLine, StringComparison.Ordinal))
			{
				formatted += Environment.NewLine;
			}
			this.OutputLog?.Invoke(this, new OutputLogEventArgs(formatted));
		}
	}

	private void RelaySocketJackError(ErrorEventArgs e)
	{
		if (e != null && e.Exception != null)
		{
			RelaySocketJackLogOutput("[SocketJack] ERROR: " + e.Exception.Message);
			RecordObservabilityEvent("socketjack", "SocketJack error", "error", e.Exception.Message, "", "", 0L);
		}
	}

	private static int ChooseDefaultChatServerPort(int lmStudioPort, int proxyPort)
	{
		int[] candidates = new int[4]
		{
			proxyPort + 1,
			proxyPort + 2,
			lmStudioPort + 1,
			11436
		};
		int[] array = candidates;
		foreach (int candidate in array)
		{
			if (candidate > 0 && candidate <= 65535 && candidate != proxyPort && candidate != lmStudioPort)
			{
				return candidate;
			}
		}
		for (int j = 49152; j <= 65535; j++)
		{
			if (j != proxyPort && j != lmStudioPort)
			{
				return j;
			}
		}
		throw new InvalidOperationException("Unable to choose a chat server port.");
	}

