	private string RenderChatServerHtml(string template, IEnumerable<string[]> templateVars, HttpRequest request)
	{
		if (request?.Context?.Response != null)
		{
			request.Context.Response.ContentType = "text/html; charset=utf-8";
			request.Context.Response.Headers["Cache-Control"] = "no-store, no-cache, must-revalidate";
		}
		List<string[]> merged = new List<string[]>();
		if (templateVars != null)
		{
			merged.AddRange(templateVars.Where((string[] pair) => pair != null && pair.Length >= 2));
		}
		merged.AddRange(BuildWorkstationMetadataTemplateVars(request));
		return ApplyTemplateVars(template, merged);
	}

	private IEnumerable<string[]> BuildWorkstationMetadataTemplateVars(HttpRequest request)
	{
		string title = BuildWorkstationMetadataTitle();
		string description = "Share a JackLLM Workstation local LLM and media generation server with live GPU, CPU, RAM, model, and tool metadata.";
		string url = BuildWorkstationMetadataUrl(request);
		return new string[5][]
		{
			new string[2]
			{
				"META_TITLE",
				WebUtility.HtmlEncode(title)
			},
			new string[2]
			{
				"META_DESCRIPTION",
				WebUtility.HtmlEncode(description)
			},
			new string[2]
			{
				"META_URL",
				WebUtility.HtmlEncode(url)
			},
			new string[2]
			{
				"META_IMAGE",
				WebUtility.HtmlEncode("https://socketjack.com/assets/jackllm-workstation-metadata.png")
			},
			new string[2]
			{
				"META_IMAGE_ALT",
				WebUtility.HtmlEncode("JackLLM Workstation metadata preview image")
			}
		};
	}

	private string BuildWorkstationMetadataTitle()
	{
		LmVsProxyServerProfile profile = GetServerBrowserProfile();
		string serverName = CompactMetadataName(FirstNonEmpty(profile.ServerName, Environment.MachineName, "JackLLM Workstation"), 34);
		string gpuName = BuildWorkstationMetadataGpuText(profile);
		string cpuName = CompactMetadataName(FirstNonEmpty(profile.CpuName, "CPU"), 42);
		string ram = BuildWorkstationMetadataRamText(profile);
		return serverName + " - " + gpuName + ", " + cpuName + ", ram (" + ram + ")";
	}

	private string BuildWorkstationMetadataGpuText(LmVsProxyServerProfile profile)
	{
		try
		{
			ServerHardwareGpuMetric metric = BuildServerHardwareGpuMetric(DateTimeOffset.UtcNow);
			if (metric != null && metric.available)
			{
				string name = CompactMetadataGpuModelName(metric.name, metric.deviceCount);
				if (metric.vramTotalBytes > 0)
				{
					return CompactMetadataName(name + " " + FormatMetadataGpuGigabytes(metric.vramUsedBytes, compactTotal: false) + "/" + FormatMetadataGpuGigabytes(metric.vramTotalBytes, compactTotal: true), 42);
				}
				return CompactMetadataName(name, 42);
			}
		}
		catch
		{
		}
		return CompactMetadataName(FirstNonEmpty(profile.GpuName, "Graphics Card"), 42);
	}

	private string BuildWorkstationMetadataRamText(LmVsProxyServerProfile profile)
	{
		try
		{
			ServerHardwareRamMetric metric = BuildServerHardwareRamMetric();
			if (metric != null && metric.available && metric.totalBytes != 0)
			{
				return FormatMetadataGigabytes(metric.usedBytes) + "/" + FormatMetadataGigabytes(metric.totalBytes);
			}
		}
		catch
		{
		}
		string advertised = ((profile == null) ? "" : profile.RamAvailable);
		if (!string.IsNullOrWhiteSpace(advertised))
		{
			MatchCollection matches = Regex.Matches(advertised, "(?i)(\\d+(?:\\.\\d+)?)\\s*(?:gib|gb|g)");
			if (matches.Count >= 2)
			{
				return FormatMetadataGigabytesText(matches[0].Groups[1].Value) + "/" + FormatMetadataGigabytesText(matches[1].Groups[1].Value);
			}
			if (matches.Count == 1)
			{
				return "?GB/" + FormatMetadataGigabytesText(matches[0].Groups[1].Value);
			}
		}
		return "?GB/?GB";
	}

	private static string FormatMetadataGigabytes(ulong bytes)
	{
		double gb = (double)bytes / 1073741824.0;
		return Math.Max(0, (int)Math.Round(gb)).ToString(CultureInfo.InvariantCulture) + "GB";
	}

	private static string FormatMetadataGpuGigabytes(ulong bytes, bool compactTotal)
	{
		double gb = Math.Max(0.0, (double)bytes / 1073741824.0);
		double rounded = Math.Round(gb);
		if (compactTotal && Math.Abs(gb - rounded) < 0.05)
		{
			return rounded.ToString("0", CultureInfo.InvariantCulture) + "GB";
		}
		return gb.ToString(gb >= 10.0 ? "0.#" : "0.0", CultureInfo.InvariantCulture) + "GB";
	}

	private static string FormatMetadataGigabytesText(string value)
	{
		if (double.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out var parsed))
		{
			return Math.Max(0, (int)Math.Round(parsed)).ToString(CultureInfo.InvariantCulture) + "GB";
		}
		return "?GB";
	}

	private static string CompactMetadataGpuModelName(string name, int deviceCount)
	{
		string text = (name ?? "").Trim();
		if (string.IsNullOrWhiteSpace(text))
		{
			text = "NVIDIA GPU";
		}
		text = Regex.Replace(text, "\\s+x\\d+\\s*$", "", RegexOptions.IgnoreCase).Trim();
		if (text.IndexOf("tesla", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			text = "NVIDIA Tesla";
		}
		else if (!text.StartsWith("NVIDIA ", StringComparison.OrdinalIgnoreCase))
		{
			text = "NVIDIA " + text;
		}
		if (deviceCount > 1 && text.IndexOf("(x", StringComparison.OrdinalIgnoreCase) < 0)
		{
			text += " (x" + deviceCount.ToString(CultureInfo.InvariantCulture) + ")";
		}
		return text;
	}

	private static string CompactMetadataName(string value, int maxLength)
	{
		value = (value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(value))
		{
			return "";
		}
		value = value.Replace("(R)", "", StringComparison.OrdinalIgnoreCase).Replace("(TM)", "", StringComparison.OrdinalIgnoreCase).Replace(" CPU ", " ", StringComparison.OrdinalIgnoreCase)
			.Replace(" Processor", "", StringComparison.OrdinalIgnoreCase)
			.Replace("NVIDIA GeForce ", "GeForce ", StringComparison.OrdinalIgnoreCase)
			.Replace("AMD Radeon ", "Radeon ", StringComparison.OrdinalIgnoreCase)
			.Replace("Intel(R)", "Intel", StringComparison.OrdinalIgnoreCase);
		while (value.Contains("  ", StringComparison.Ordinal))
		{
			value = value.Replace("  ", " ", StringComparison.Ordinal);
		}
		value = value.Trim();
		if (maxLength <= 4 || value.Length <= maxLength)
		{
			return value;
		}
		int cut = value.LastIndexOf(' ', Math.Min(value.Length - 1, maxLength - 4));
		if (cut < maxLength / 2)
		{
			cut = maxLength - 3;
		}
		return value.Substring(0, Math.Max(1, cut)).TrimEnd(',', '-', ' ') + "...";
	}

	private static string ApplyTemplateVars(string template, IEnumerable<string[]> vars)
	{
		string html = template ?? "";
		if (vars == null)
		{
			return html;
		}
		foreach (string[] pair in vars)
		{
			if (pair != null && pair.Length >= 2 && !string.IsNullOrWhiteSpace(pair[0]))
			{
				html = html.Replace("$" + pair[0], pair[1] ?? "", StringComparison.Ordinal);
			}
		}
		return html;
	}

	private string BuildWorkstationMetadataUrl(HttpRequest request)
	{
		string baseUrl = BuildRequestPublicBaseUrl(request);
		string prefix = GetRequestHeader(request, "X-Forwarded-Prefix");
		string path = (string.IsNullOrWhiteSpace(request?.Path) ? "/" : request.Path);
		if (!path.StartsWith("/", StringComparison.Ordinal))
		{
			path = "/" + path;
		}
		if (!string.IsNullOrWhiteSpace(prefix))
		{
			prefix = "/" + prefix.Trim('/');
			if (prefix == "/")
			{
				prefix = "";
			}
		}
		return baseUrl.TrimEnd('/') + prefix + path;
	}

	private string BuildRequestPublicBaseUrl(HttpRequest request)
	{
		string host = FirstNonEmpty(GetRequestHeader(request, "X-Forwarded-Host"), request?.Host, "localhost:" + _chatServerPort.ToString(CultureInfo.InvariantCulture));
		string scheme = FirstNonEmpty(GetRequestHeader(request, "X-Forwarded-Proto"), InferRequestScheme(request), "http");
		host = SanitizeMetadataHeaderValue(host).Trim('/');
		scheme = SanitizeMetadataHeaderValue(scheme).TrimEnd(':', '/');
		return scheme + "://" + host;
	}

	private static string InferRequestScheme(HttpRequest request)
	{
		try
		{
			return (request != null && request.Context?.Connection?.Parent?.Options?.UseSsl == true) ? "https" : "http";
		}
		catch
		{
			return "http";
		}
	}

	private static string GetRequestHeader(HttpRequest request, string name)
	{
		if (request?.Headers != null && request.Headers.TryGetValue(name, out var value) && !string.IsNullOrWhiteSpace(value))
		{
			return value;
		}
		return "";
	}

	private static string SanitizeMetadataHeaderValue(string value)
	{
		return (value ?? "").Replace("\r", "", StringComparison.Ordinal).Replace("\n", "", StringComparison.Ordinal).Trim();
	}

	private object BuildWorkstationMetadataImageResponse(HttpRequest request)
	{
		byte[] bytes = HtmlPageResources.GetBytes("JackLLMWorkstationMetadata.png");
		if (bytes == null || bytes.Length == 0)
		{
			request.Context.StatusCodeNumber = 404;
			request.Context.ReasonPhrase = "Not Found";
			request.Context.Response.ContentType = "text/plain; charset=utf-8";
			return "JackLLM Workstation metadata image not found.";
		}
		request.Context.Response.Headers["Cache-Control"] = "public, max-age=86400";
		return new FileResponse(bytes, "image/png", "JackLLMWorkstationMetadata.png");
	}

