		string BuildChatHealthPayload(NetworkConnection connection, HttpRequest request)
		{
			ChatPermissionState permissions = GetChatPermissions(GetChatSessionOwnerKey(connection, request));
			return JsonSerializer.Serialize(new
			{
				ok = true,
				proxyPort = _proxyPort,
				copilotDuplicatorPort = CopilotDuplicatorPort,
				copilotDuplicatorEndpoint = "http://localhost:" + CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture) + "/v1/chat/completions",
				copilotDuplicator = BuildCopilotDuplicatorPayload(),
				lmStudioEndpoint = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/v1/chat/completions",
				modelRuntimeEndpoint = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/v1/chat/completions",
				modelRuntimeProvider = GetLocalModelRuntimeDisplayName(),
				chatModel = ChatModel,
				database = new
				{
					name = _chatSessionData.Name,
					hosted = true,
					sharedChatServerPort = _chatServerPort,
					defaultDatabase = _chatSessionData.DefaultDatabase,
					sqlAdminEnabled = permissions.sqlAdmin,
					sqlAdminUrl = ChatServerUrl.TrimEnd('/') + "/sql"
				},
				ftp = GetChatFtpServerStatus()
			});
		}
	}

	private static void DisableDefaultSocketJackSecurity(HttpServer server)
	{
		server.RequestGate = null;
		server.Options.EndpointSecurity.Enabled = false;
		server.Options.EndpointSecurity.BlockKnownBadPaths = false;
		server.Options.EndpointSecurity.TreatSuspiciousUserAgentsAsBad = false;
	}

	private void RegisterSockJackDmlRoutes(HttpServer server)
	{
		string pageHtml = HtmlPageResources.GetHtml("SockJackDml.html");
		string[] array = new string[10] { "/SockJackDml", "/sockjackdml", "/sockjackdml/missions", "/sockjackdml/packs", "/sockjackdml/operator", "/sockjackdml/assist", "/sockjackdml/capabilities", "/sockjackdml/evidence", "/sockjackdml/accessibility", "/sockjackdml/workflow" };
		foreach (string path in array)
		{
			server.RouteString("GET", path, pageHtml, null, "SockJackDml:" + path, 0);
		}
		string[] apiRoutes = new string[20]
		{
