	private string HandleMagicToolRequest(NetworkConnection connection, HttpRequest request, string toolName)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string body = (string.IsNullOrWhiteSpace(request?.Body) ? "{}" : request.Body);
			if (!IsJsonObjectBody(body, out var bodyError))
			{
				return BuildJsonError(request, 400, "Bad Request", bodyError);
			}
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			if (permissions == null || !permissions.agentAccess)
			{
				return BuildJsonError(request, 403, "Forbidden", "Agent access is required for SockJackDml workflow tools.");
			}
			string sessionId = ExtractChatUiSessionId(body);
			if (string.IsNullOrWhiteSpace(sessionId))
			{
				sessionId = GetQueryParameter(request, "sessionId");
			}
			sessionId = EnsureChatUiSessionId(sessionId);
			string result = ExecuteSockJackDmlToolAsync(toolName, body, ownerKey, sessionId).GetAwaiter().GetResult();
			return string.IsNullOrWhiteSpace(result) ? JsonSerializer.Serialize(new
			{
				ok = false,
				error = "SockJackDml tool returned no result."
			}) : result;
		}
		catch (Exception ex)
		{
			LogMessage("[SockJackDml Tools] " + toolName + " endpoint failed: " + ex);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleMagicWorkflowStatusRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			if (permissions == null || !permissions.agentAccess)
			{
				return BuildJsonError(request, 403, "Forbidden", "Agent access is required for SockJackDml workflow tools.");
			}
			string sessionId = EnsureChatUiSessionId(GetQueryParameter(request, "sessionId"));
			MagicWorkflowStatusRequest workflowRequest = new MagicWorkflowStatusRequest
			{
				PlanId = (GetQueryParameter(request, "planId") ?? ""),
				ProgressId = (GetQueryParameter(request, "progressId") ?? ""),
				ExecutionId = (GetQueryParameter(request, "executionId") ?? ""),
				ProjectOrSessionName = (GetQueryParameter(request, "projectOrSessionName") ?? GetQueryParameter(request, "projectName") ?? ""),
				FeatureName = (GetQueryParameter(request, "featureName") ?? GetQueryParameter(request, "feature") ?? ""),
				ProgressPath = (GetQueryParameter(request, "progressPath") ?? GetQueryParameter(request, "path") ?? ""),
				IncludeAllSessions = ReadQueryBool(request, "includeAllSessions", fallback: false),
				Take = ReadQueryInt(request, "take", 50)
			};
			MagicWorkflowStatusResult result = _sockJackDmlWorkflows.GetWorkflowStatus(ownerKey, sessionId, workflowRequest);
			RecordObservabilityEvent("sockjack-dml", "workflow status", result.LatestStatus, result.NextAction, ownerKey, "/api/sockjackdml/tools/workflow/status", 0L);
			return _sockJackDmlWorkflows.Serialize(result);
		}
		catch (Exception ex)
		{
			LogMessage("[SockJackDml Tools] workflow status endpoint failed: " + ex);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private bool ReadQueryBool(HttpRequest request, string name, bool fallback)
	{
		string value = (GetQueryParameter(request, name) ?? "").Trim();
		if (string.IsNullOrWhiteSpace(value))
		{
			return fallback;
		}
		if (bool.TryParse(value, out var parsed))
		{
			return parsed;
		}
		return value == "1" || value.Equals("yes", StringComparison.OrdinalIgnoreCase) || value.Equals("on", StringComparison.OrdinalIgnoreCase);
	}

	private int ReadQueryInt(HttpRequest request, string name, int fallback)
	{
		string value = (GetQueryParameter(request, name) ?? "").Trim();
		int parsed;
		return int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : fallback;
	}

	private static bool IsJsonObjectBody(string body, out string error)
	{
		error = null;
		try
		{
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				if (document.RootElement.ValueKind == JsonValueKind.Object)
				{
					return true;
				}
			}
			error = "SockJackDml tool payload must be a JSON object.";
			return false;
		}
		catch (JsonException ex)
		{
			error = "Invalid JSON: " + ex.Message;
			return false;
		}
	}

	private string HandleChatUiModelsRequest(CancellationToken cancellationToken)
	{
		try
		{
			string configuredModel = GetConfiguredChatModelOrPlaceholder();
			if (TryLoadChatUiRuntimeModelInfos(cancellationToken, out var models, out var warning))
			{
				return JsonSerializer.Serialize(BuildChatUiModelInventorySnapshot(models, ChooseChatUiSelectedModel(models, configuredModel), modelListAvailable: true, warning));
			}
			List<ChatUiModelInfo> fallbackModels = GetCachedOrConfiguredChatModelInfos(configuredModel);
			MergeChatModelInfos(fallbackModels, BuildEnabledWebChatModelInfos());
			DecorateChatUiModelsWithPolicy(fallbackModels);
			return JsonSerializer.Serialize(BuildChatUiModelInventorySnapshot(fallbackModels, ChooseChatUiSelectedModel(fallbackModels, configuredModel), modelListAvailable: false, string.IsNullOrWhiteSpace(warning) ? (GetLocalModelRuntimeDisplayName() + " model list is unavailable.") : warning));
		}
		catch (OperationCanceledException)
		{
			LogMessage("[Chat UI] Models request timed out after " + ChatModelListTimeout.TotalSeconds.ToString("0", CultureInfo.InvariantCulture) + "s; using configured model.");
			string configuredModel2 = GetConfiguredChatModelOrPlaceholder();
			List<ChatUiModelInfo> fallbackModels2 = GetCachedOrConfiguredChatModelInfos(configuredModel2);
			MergeChatModelInfos(fallbackModels2, BuildEnabledWebChatModelInfos());
			DecorateChatUiModelsWithPolicy(fallbackModels2);
			return JsonSerializer.Serialize(BuildChatUiModelInventorySnapshot(fallbackModels2, ChooseChatUiSelectedModel(fallbackModels2, configuredModel2), modelListAvailable: false, GetLocalModelRuntimeDisplayName() + " model list timed out; using cached/configured models."));
		}
		catch (Exception ex2)
		{
			LogMessage("[Chat UI] Models request failed: " + ex2.Message);
			List<ChatUiModelInfo> models2 = BuildChatModelInfos(new List<string> { GetConfiguredChatModelOrPlaceholder() });
			MergeChatModelInfos(models2, BuildEnabledWebChatModelInfos());
			DecorateChatUiModelsWithPolicy(models2);
			ChatUiModelInventorySnapshot snapshot = BuildChatUiModelInventorySnapshot(models2, ChooseChatUiSelectedModel(models2, GetConfiguredChatModelOrPlaceholder()), modelListAvailable: false);
			snapshot.ok = false;
			snapshot.error = ex2.Message;
			return JsonSerializer.Serialize(snapshot);
		}
	}

	private bool TryLoadChatUiRuntimeModelInfos(CancellationToken cancellationToken, out List<ChatUiModelInfo> models, out string warning)
	{
		models = new List<ChatUiModelInfo>();
		warning = "";
		string runtimeName = GetLocalModelRuntimeDisplayName();
		foreach (string url in GetLmStudioModelListUrls())
		{
			using CancellationTokenSource timeoutCts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
			timeoutCts.CancelAfter(ChatModelListTimeout);
			using HttpResponseMessage response = _httpClient.GetAsync(url, timeoutCts.Token).GetAwaiter().GetResult();
			string responseBody = ((response.Content == null) ? "" : response.Content.ReadAsStringAsync().GetAwaiter().GetResult());
			if (!response.IsSuccessStatusCode)
			{
				warning = runtimeName + " is reachable, but " + url + " returned HTTP " + (int)response.StatusCode + " " + response.ReasonPhrase + ".";
				LogMessage($"[Chat UI] {runtimeName} models request returned {(int)response.StatusCode} {response.ReasonPhrase} from {url}: {TruncateForLog(responseBody, 1000)}");
				continue;
			}
			models = ExtractModelInfos(responseBody);
			if (models.Count == 0)
			{
				warning = runtimeName + " returned no model ids from " + url + ".";
				LogMessage("[Chat UI] " + runtimeName + " model list was empty from " + url + ".");
				continue;
			}
			foreach (ChatUiModelInfo model in models)
			{
				if (model != null)
				{
					model.isAvailable = true;
				}
			}
			MergeChatModelInfos(models, BuildEnabledWebChatModelInfos());
			DecorateChatUiModelsWithPolicy(models);
			CacheChatModelInfos(models);
			return true;
		}
		MergeChatModelInfos(models, BuildEnabledWebChatModelInfos());
		DecorateChatUiModelsWithPolicy(models);
		return false;
	}

	private static bool IsModelRuntimeCompatibilityStatusRequest(string method, string pathAndQuery)
	{
		if (!string.Equals(method, "GET", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		string path = (pathAndQuery ?? "").Split('?', 2)[0].Trim().TrimEnd('/').ToLowerInvariant();
		return string.Equals(path, "/api/v1/runtime/compatibility", StringComparison.OrdinalIgnoreCase);
	}

	private static bool IsModelRuntimeCompatibilityMutationRequest(string method, string pathAndQuery)
	{
		if (string.Equals(method, "GET", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		string path = (pathAndQuery ?? "").Split('?', 2)[0].Trim().TrimEnd('/').ToLowerInvariant();
		return path.StartsWith("/api/v1/runtime/compatibility", StringComparison.OrdinalIgnoreCase);
	}

	private static string BuildModelRuntimeCompatibilityCacheKey(string runtimeBaseUrl, string pathAndQuery)
	{
		return (runtimeBaseUrl ?? "").TrimEnd('/') + "|" + (pathAndQuery ?? "").Trim();
	}

	private bool TryGetCachedModelRuntimeCompatibility(string cacheKey, out string body)
	{
		body = "";
		if (string.IsNullOrWhiteSpace(cacheKey))
		{
			return false;
		}
		lock (_modelRuntimeCompatibilityCacheLock)
		{
			if (string.Equals(_cachedModelRuntimeCompatibilityKey, cacheKey, StringComparison.OrdinalIgnoreCase) &&
				!string.IsNullOrWhiteSpace(_cachedModelRuntimeCompatibilityBody) &&
				DateTimeOffset.UtcNow - _cachedModelRuntimeCompatibilityUtc < ModelRuntimeCompatibilityCacheDuration)
			{
				body = _cachedModelRuntimeCompatibilityBody;
				return true;
			}
		}
		return false;
	}

	private void CacheModelRuntimeCompatibility(string cacheKey, string body)
	{
		if (string.IsNullOrWhiteSpace(cacheKey) || string.IsNullOrWhiteSpace(body))
		{
			return;
		}
		lock (_modelRuntimeCompatibilityCacheLock)
		{
			_cachedModelRuntimeCompatibilityKey = cacheKey;
			_cachedModelRuntimeCompatibilityBody = body;
			_cachedModelRuntimeCompatibilityUtc = DateTimeOffset.UtcNow;
		}
	}

	private void InvalidateModelRuntimeCompatibilityCache()
	{
		lock (_modelRuntimeCompatibilityCacheLock)
		{
			_cachedModelRuntimeCompatibilityKey = "";
			_cachedModelRuntimeCompatibilityBody = "";
			_cachedModelRuntimeCompatibilityUtc = DateTimeOffset.MinValue;
		}
	}

	private string ForwardLocalModelRuntimeRequest(string method, string pathAndQuery, string body, CancellationToken cancellationToken)
	{
		string normalizedMethod = string.IsNullOrWhiteSpace(method) ? "GET" : method.Trim().ToUpperInvariant();
		bool logRuntimeMutation = IsHighSignalModelRuntimePath(pathAndQuery);
		bool suppressPollingNoise = IsModelRuntimePollingPath(pathAndQuery);
		bool compatibilityStatusRequest = IsModelRuntimeCompatibilityStatusRequest(normalizedMethod, pathAndQuery);
		bool compatibilityMutationRequest = IsModelRuntimeCompatibilityMutationRequest(normalizedMethod, pathAndQuery);
		string routeLabel = normalizedMethod + " " + TruncateForLog(pathAndQuery ?? "", 160);
		try
		{
			if (IsModelLoadPath(pathAndQuery) && !CanForwardWebChatModelLoad(body, out var blockedModel, out var blockedReason))
			{
				if (logRuntimeMutation)
				{
					LogMessage("[Model Runtime] " + routeLabel + " blocked by web chat model-load policy for " + (string.IsNullOrWhiteSpace(blockedModel) ? "unknown model" : blockedModel) + ".");
				}
				return JsonSerializer.Serialize(new
				{
					error = new
					{
						message = blockedReason,
						type = "model_runtime_policy_error",
						code = "model_dynamic_load_not_enabled"
					},
					model = blockedModel,
					web_chat_model_load_api_enabled = WebChatModelLoadApiEnabled
				});
			}
			if (compatibilityMutationRequest)
			{
				InvalidateModelRuntimeCompatibilityCache();
			}
			string runtimeBaseUrl = BuildLocalModelRuntimeBaseUrl();
			string compatibilityCacheKey = compatibilityStatusRequest ? BuildModelRuntimeCompatibilityCacheKey(runtimeBaseUrl, pathAndQuery) : "";
			if (compatibilityStatusRequest && TryGetCachedModelRuntimeCompatibility(compatibilityCacheKey, out var cachedCompatibilityBody))
			{
				return cachedCompatibilityBody;
			}
			EnsureLmStudioForPromptAsync().GetAwaiter().GetResult();
			ILmVsProxyModelRuntime runtime = GetEffectiveLocalModelRuntime();
			string runtimeDisplayName = GetModelRuntimeDisplayName(runtime);
			runtimeBaseUrl = BuildLocalModelRuntimeBaseUrl();
			if (compatibilityStatusRequest)
			{
				compatibilityCacheKey = BuildModelRuntimeCompatibilityCacheKey(runtimeBaseUrl, pathAndQuery);
				if (TryGetCachedModelRuntimeCompatibility(compatibilityCacheKey, out cachedCompatibilityBody))
				{
					return cachedCompatibilityBody;
				}
			}
			string url = CombineOpenAiUpstreamUrl(runtimeBaseUrl, pathAndQuery);
			string enrichedBody = ((IsModelLoadPath(pathAndQuery) && !IsLmStudioRuntimeDisplayName(runtimeDisplayName)) ? BuildWebChatModelLoadRequestBody(body) : body);
			string requestBody = PrepareModelRuntimeForwardBody(pathAndQuery, enrichedBody, runtimeDisplayName);
			string requestedLoadModel = (IsModelLoadPath(pathAndQuery) ? (ExtractModelIdentifierFromBody(requestBody) ?? "") : "");
			if (logRuntimeMutation)
			{
				LogMessage("[Model Runtime] " + runtimeDisplayName + " " + routeLabel + " requested.");
			}
			using HttpRequestMessage request = new HttpRequestMessage(new HttpMethod(string.IsNullOrWhiteSpace(method) ? "GET" : method), url);
			if (!string.Equals(method, "GET", StringComparison.OrdinalIgnoreCase))
			{
				request.Content = new StringContent(requestBody, Encoding.UTF8, "application/json");
			}
			using CancellationTokenSource timeout = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
			timeout.CancelAfter(GetModelRuntimeForwardTimeout(pathAndQuery));
			using HttpResponseMessage response = _httpClient.SendAsync(request, timeout.Token).GetAwaiter().GetResult();
			string responseBody = ((response.Content == null) ? "" : response.Content.ReadAsStringAsync().GetAwaiter().GetResult());
			if (IsModelRuntimeModelsListPath(pathAndQuery) && !response.IsSuccessStatusCode)
			{
				string fallbackBody = BuildEnabledWebChatRuntimeModelsListResponse(runtimeDisplayName + " returned HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + ".");
				if (!string.IsNullOrWhiteSpace(fallbackBody))
				{
					return fallbackBody;
				}
			}
			if (!response.IsSuccessStatusCode && string.IsNullOrWhiteSpace(responseBody))
			{
				if (!suppressPollingNoise)
				{
					LogMessage("[Model Runtime] " + runtimeDisplayName + " " + routeLabel + " returned HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + ".");
				}
				return JsonSerializer.Serialize(new
				{
					error = new
					{
						message = runtimeDisplayName + " returned HTTP " + (int)response.StatusCode,
						type = "model_runtime_error",
						code = "model_runtime_http_error"
					}
				});
			}
			responseBody = PrepareModelRuntimeForwardResponseBody(pathAndQuery, responseBody);
			if (compatibilityStatusRequest && response.IsSuccessStatusCode && !ResponseBodyContainsJsonError(responseBody))
			{
				CacheModelRuntimeCompatibility(compatibilityCacheKey, responseBody);
			}
			if (logRuntimeMutation)
			{
				LogMessage("[Model Runtime] " + runtimeDisplayName + " " + routeLabel + " completed with HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + ".");
			}
			if (IsModelLoadPath(pathAndQuery) && response.IsSuccessStatusCode && !ResponseBodyContainsJsonError(responseBody) && !string.IsNullOrWhiteSpace(requestedLoadModel))
			{
				NoteWebChatRuntimeModelUsed(requestedLoadModel);
			}
			return string.IsNullOrWhiteSpace(responseBody) ? "{}" : responseBody;
		}
		catch (Exception ex)
		{
			if (!suppressPollingNoise)
			{
				LogMessage("[Model Runtime] " + routeLabel + " failed: " + ex.Message);
			}
			if (IsModelRuntimeModelsListPath(pathAndQuery))
			{
				string fallbackBody2 = BuildEnabledWebChatRuntimeModelsListResponse(ex.Message);
				if (!string.IsNullOrWhiteSpace(fallbackBody2))
				{
					return fallbackBody2;
				}
			}
			return JsonSerializer.Serialize(new
			{
				error = new
				{
					message = ex.Message,
					type = "model_runtime_error",
					code = "model_runtime_unavailable"
				}
			});
		}
	}

	private async Task ForwardLocalModelRuntimeStreamRequestAsync(string method, string pathAndQuery, HttpRequest originalRequest, ChunkedStream output, CancellationToken cancellationToken)
	{
		string normalizedMethod = string.IsNullOrWhiteSpace(method) ? "GET" : method.Trim().ToUpperInvariant();
		string routeLabel = normalizedMethod + " " + TruncateForLog(pathAndQuery ?? "", 160);
		output.ContentType = "text/event-stream; charset=utf-8";
		output.LowLatencyMode = true;
		output.SetHeader("Cache-Control", "no-cache, no-store, no-transform");
		output.SetHeader("X-Accel-Buffering", "no");
		try
		{
			EnsureLmStudioForPromptAsync().GetAwaiter().GetResult();
			ILmVsProxyModelRuntime runtime = GetEffectiveLocalModelRuntime();
			string runtimeDisplayName = GetModelRuntimeDisplayName(runtime);
			string runtimeBaseUrl = BuildLocalModelRuntimeBaseUrl();
			string url = CombineOpenAiUpstreamUrl(runtimeBaseUrl, pathAndQuery);
			string requestBody = PrepareModelRuntimeForwardBody(pathAndQuery, originalRequest?.Body ?? "", runtimeDisplayName);
			LogMessage("[Model Runtime] " + runtimeDisplayName + " streaming " + routeLabel + " requested.");
			using HttpRequestMessage request = new HttpRequestMessage(new HttpMethod(normalizedMethod), url);
			if (!string.Equals(normalizedMethod, "GET", StringComparison.OrdinalIgnoreCase))
			{
				request.Content = new StringContent(requestBody, Encoding.UTF8, "application/json");
			}
			using CancellationTokenSource timeout = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
			timeout.CancelAfter(GetModelRuntimeStreamForwardTimeout(pathAndQuery));
			using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, timeout.Token).ConfigureAwait(false);
			string contentType = response.Content?.Headers?.ContentType?.ToString() ?? "";
			if (!string.IsNullOrWhiteSpace(contentType))
			{
				output.ContentType = contentType;
			}
			if (!response.IsSuccessStatusCode)
			{
				string responseBody = response.Content == null ? "" : await response.Content.ReadAsStringAsync().ConfigureAwait(false);
				LogMessage("[Model Runtime] " + runtimeDisplayName + " streaming " + routeLabel + " returned HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TruncateForLog(responseBody, 500));
				output.ContentType = "text/event-stream; charset=utf-8";
				output.Write("data: " + JsonSerializer.Serialize(new
				{
					error = new
					{
						message = string.IsNullOrWhiteSpace(responseBody) ? runtimeDisplayName + " returned HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) : responseBody,
						type = "model_runtime_error",
						code = "model_runtime_http_error"
					}
				}) + "\n\n");
				return;
			}
			if (response.Content == null)
			{
				output.Write("data: [DONE]\n\n");
				return;
			}
			using Stream responseStream = await response.Content.ReadAsStreamAsync().ConfigureAwait(false);
			byte[] buffer = new byte[8192];
			while (true)
			{
				int read = await responseStream.ReadAsync(buffer, 0, buffer.Length, timeout.Token).ConfigureAwait(false);
				if (read <= 0)
				{
					break;
				}
				output.Write(buffer, 0, read);
			}
			LogMessage("[Model Runtime] " + runtimeDisplayName + " streaming " + routeLabel + " completed.");
		}
		catch (Exception ex)
		{
			LogMessage("[Model Runtime] streaming " + routeLabel + " failed: " + ex.Message);
			output.ContentType = "text/event-stream; charset=utf-8";
			output.Write("data: " + JsonSerializer.Serialize(new
			{
				error = new
				{
					message = ex.Message,
					type = "model_runtime_error",
					code = "model_runtime_unavailable"
				}
			}) + "\n\n");
		}
	}

	private TimeSpan GetModelRuntimeStreamForwardTimeout(string pathAndQuery)
	{
		string path = (pathAndQuery ?? "").ToLowerInvariant();
		if (path.Contains("/chat/completions") || path.Contains("/responses"))
		{
			return _promptTimeout;
		}
		return GetModelRuntimeForwardTimeout(pathAndQuery);
	}

	private string HandleWorkstationStateRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!IsLoopbackWorkstationClient(connection))
		{
			return BuildJsonError(request, 403, "Forbidden", "Workstation remote control is available only to loopback clients.");
		}
		return JsonSerializer.Serialize(new
		{
			ok = true,
			capturedUtc = DateTimeOffset.UtcNow,
			source = "JackLLM native remote-control provider",
			desktopAvailable = LmVsProxyRemoteControl.HasScreenCaptureProvider,
			remoteControl = new
			{
				provider = LmVsProxyRemoteControl.ProviderName,
				screenCapture = LmVsProxyRemoteControl.HasScreenCaptureProvider,
				input = LmVsProxyRemoteControl.HasInputProvider
			},
			permissions = new
			{
				liveInput = _workstationLiveInputEnabled
			},
			transports = new[]
			{
				new
				{
					id = "polling",
					label = "Polling",
					url = "/api/workstation/screen.json?format=adaptive",
					requiresLiveInput = false
				}
			}
		});
	}

	private string HandleWorkstationScreenJsonRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!IsLoopbackWorkstationClient(connection))
		{
			return BuildJsonError(request, 403, "Forbidden", "Workstation remote control is available only to loopback clients.");
		}
		try
		{
			LmVsProxyScreenCaptureOptions options = ReadScreenCaptureOptions(request);
			LmVsProxyScreenCaptureResult capture = CaptureScreenForRemoteControl(options);
			string imageBase64 = Convert.ToBase64String(capture.Bytes);
			string mimeType = (string.IsNullOrWhiteSpace(capture.MimeType) ? "image/jpeg" : capture.MimeType);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				capturedUtc = DateTimeOffset.UtcNow,
				source = "JackLLM native remote-control provider",
				provider = LmVsProxyRemoteControl.ProviderName,
				backend = capture.Backend,
				mimeType = mimeType,
				encoding = WorkstationEncodingFromMimeType(mimeType),
				byteLength = capture.Bytes.Length,
				width = capture.Width,
				height = capture.Height,
				left = capture.Left,
				top = capture.Top,
				imageBase64 = imageBase64,
				dataUrl = "data:" + mimeType + ";base64," + imageBase64,
				cursor = new
				{
					visible = false,
					x = 0,
					y = 0,
					normalizedX = 0,
					normalizedY = 0
				}
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Workstation] Screen capture failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

