	private string HandleWorkstationInputRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!IsLoopbackWorkstationClient(connection))
		{
			return BuildJsonError(request, 403, "Forbidden", "Workstation remote control is available only to loopback clients.");
		}
		if (!_workstationLiveInputEnabled)
		{
			return BuildJsonError(request, 423, "Locked", "Live Input is disabled for the Workstation page.");
		}
		try
		{
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			LmVsProxyRemoteInputResult result = ExecuteRemoteInput(document.RootElement);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				result = new
				{
					action = result.Action,
					x = result.X,
					y = result.Y,
					message = result.Message
				}
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Workstation] Remote input failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleWorkstationPermissionsRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!IsLoopbackWorkstationClient(connection))
		{
			return BuildJsonError(request, 403, "Forbidden", "Workstation remote control is available only to loopback clients.");
		}
		try
		{
			bool liveInput = _workstationLiveInputEnabled;
			string body = request?.Body ?? "";
			if (!string.IsNullOrWhiteSpace(body))
			{
				using JsonDocument document = JsonDocument.Parse(body);
				JsonElement root = document.RootElement;
				if (root.ValueKind == JsonValueKind.Object)
				{
					JsonElement enabledElement;
					if (root.TryGetProperty("liveInput", out var liveInputElement))
					{
						liveInput = ReadJsonBool(liveInputElement, liveInput);
					}
					else if (root.TryGetProperty("enabled", out enabledElement))
					{
						liveInput = ReadJsonBool(enabledElement, liveInput);
					}
				}
			}
			_workstationLiveInputEnabled = liveInput;
			return JsonSerializer.Serialize(new
			{
				ok = true,
				permissions = new
				{
					liveInput = _workstationLiveInputEnabled
				}
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Workstation] Permission update failed: " + ex.Message);
			return BuildJsonError(request, 400, "Bad Request", ex.Message);
		}
	}

	private string HandleWorkstationEmergencyStopRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!IsLoopbackWorkstationClient(connection))
		{
			return BuildJsonError(request, 403, "Forbidden", "Workstation remote control is available only to loopback clients.");
		}
		_workstationLiveInputEnabled = false;
		return JsonSerializer.Serialize(new
		{
			ok = true,
			message = "Workstation Live Input disabled.",
			permissions = new
			{
				liveInput = false
			}
		});
	}

	private bool IsLoopbackWorkstationClient(NetworkConnection connection)
	{
		try
		{
			IPAddress address = connection?.EndPoint?.Address;
			if (address == null && connection?.Socket?.RemoteEndPoint is IPEndPoint socketEndPoint)
			{
				address = socketEndPoint.Address;
			}
			return IsLocalAddress(address);
		}
		catch
		{
			return false;
		}
	}

	private static string WorkstationEncodingFromMimeType(string mimeType)
	{
		mimeType = (mimeType ?? "").Trim().ToLowerInvariant();
		if (mimeType.Contains("png"))
		{
			return "png";
		}
		if (mimeType.Contains("jpeg") || mimeType.Contains("jpg"))
		{
			return "jpeg";
		}
		return "binary";
	}

	private bool CanForwardWebChatModelLoad(string body, out string model, out string reason)
	{
		model = ExtractModelIdentifierFromBody(body) ?? "";
		if ((WebChatModelLoadApiEnabled || (!string.IsNullOrWhiteSpace(model) && IsModelEnabledForWebChatDynamicLoad(model))) &&
			!IsVerifiedRuntimeLoadableModel(model, out reason))
		{
			return false;
		}
		if (WebChatModelLoadApiEnabled)
		{
			reason = "";
			return true;
		}
		if (!string.IsNullOrWhiteSpace(model) && IsModelEnabledForWebChatDynamicLoad(model))
		{
			reason = "";
			return true;
		}
		reason = "Dynamic web chat model loading is disabled for " + (string.IsNullOrWhiteSpace(model) ? "this model" : ("'" + model + "'")) + ". Enable the model in Workstation's Models tab, or enable the global web chat model-load API in Diagnostics.";
		return false;
	}

	private string BuildWebChatModelLoadRequestBody(string body)
	{
		string model = ExtractModelIdentifierFromBody(body) ?? "";
		if (string.IsNullOrWhiteSpace(model))
		{
			return string.IsNullOrWhiteSpace(body) ? "{}" : body;
		}
		if (!TryGetModelManagerLoadSettings(model, out var settings))
		{
			return string.IsNullOrWhiteSpace(body) ? JsonSerializer.Serialize(new { model }) : body;
		}
		using MemoryStream stream = new MemoryStream();
		using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
		{
			writer.WriteStartObject();
			writer.WriteString("model", model.Trim());
			if (!string.IsNullOrWhiteSpace(settings.Backend))
			{
				writer.WriteString("backend", settings.Backend);
			}
			if (settings.ContextLength > 0)
			{
				writer.WriteNumber("context_length", settings.ContextLength);
			}
			if (settings.EvalBatchSize > 0)
			{
				writer.WriteNumber("eval_batch_size", settings.EvalBatchSize);
			}
			string parallelismMode = settings.ParallelismMode;
			bool parallelTensor = settings.ParallelTensor || string.Equals(parallelismMode, "tensor_parallel", StringComparison.OrdinalIgnoreCase);
			if (parallelTensor && (settings.TargetDeviceIds?.Length ?? 0) > 1)
			{
				parallelismMode = "tensor_parallel";
			}
			else if ((settings.TargetDeviceIds?.Length ?? 0) > 1 && string.Equals(parallelismMode, "single", StringComparison.OrdinalIgnoreCase))
			{
				parallelismMode = "data_parallel";
			}
			writer.WriteNumber("gpu_layer_count", settings.GpuLayerCount);
			writer.WriteBoolean("flash_attention", settings.FlashAttention);
			writer.WriteBoolean("offload_kv_cache_to_gpu", settings.OffloadKvCacheToGpu);
			writer.WriteBoolean("allow_backend_fallback", settings.AllowBackendFallback);
			writer.WriteString("parallelism_mode", parallelismMode);
			writer.WriteString("parallelism_placement", settings.ParallelismPlacement);
			writer.WriteBoolean("parallel_tensor", parallelTensor && (settings.TargetDeviceIds?.Length ?? 0) > 1);
			writer.WriteNumber("tensor_parallel_size", parallelTensor ? Math.Max(1, settings.TargetDeviceIds?.Length ?? 0) : 1);
			if (settings.TargetDeviceIds != null && settings.TargetDeviceIds.Length > 0)
			{
				writer.WritePropertyName("target_device_ids");
				JsonSerializer.Serialize(writer, settings.TargetDeviceIds);
				writer.WritePropertyName("gpu_device_ids");
				JsonSerializer.Serialize(writer, settings.TargetDeviceIds);
			}
			if (settings.NetworkNodeIds != null && settings.NetworkNodeIds.Length > 0)
			{
				writer.WritePropertyName("network_node_ids");
				JsonSerializer.Serialize(writer, settings.NetworkNodeIds);
			}
			writer.WriteNumber("gpu_load_threshold_percent", Math.Max(0, Math.Min(100, settings.MaxGpuLoadPercent)));
			writer.WriteNumber("max_gpu_load_percent", Math.Max(0, Math.Min(100, settings.MaxGpuLoadPercent)));
			writer.WriteNumber("max_vram_usage_percent", Math.Max(0, Math.Min(100, settings.MaxVramUsagePercent)));
			writer.WriteNumber("pipeline_stage_count", Math.Max(1, settings.PipelineStageCount));
			writer.WriteNumber("data_parallel_replicas", Math.Max(1, Math.Max(settings.DataParallelReplicaCount, (settings.TargetDeviceIds?.Length ?? 0) > 1 && string.Equals(parallelismMode, "data_parallel", StringComparison.OrdinalIgnoreCase) ? settings.TargetDeviceIds.Length : 1)));
			writer.WriteString("video_device_map", settings.VideoDeviceMap ?? "");
			writer.WriteBoolean("video_allow_cpu_offload", settings.VideoAllowCpuOffload);
			writer.WriteString("video_offload_folder", settings.VideoOffloadFolder ?? "");
			writer.WriteBoolean("video_disable_cuda_memory_guard", settings.VideoDisableCudaMemoryGuard);
			writer.WriteNumber("video_cuda_memory_reserve_mb", Math.Max(0, settings.VideoCudaMemoryReserveMb));
			writer.WriteString("video_cpu_max_memory", settings.VideoCpuMaxMemory ?? "");
			writer.WriteBoolean("video_memory_saving", settings.VideoMemorySaving);
			writer.WriteBoolean("echo_load_config", value: true);
			writer.WriteEndObject();
		}
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private string PrepareModelRuntimeForwardResponseBody(string pathAndQuery, string responseBody)
	{
		if (!IsModelRuntimeModelsListPath(pathAndQuery) || string.IsNullOrWhiteSpace(responseBody))
		{
			return responseBody;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(responseBody);
			if (document.RootElement.ValueKind != JsonValueKind.Object || !document.RootElement.TryGetProperty("models", out var models) || models.ValueKind != JsonValueKind.Array)
			{
				return responseBody;
			}
			using MemoryStream stream = new MemoryStream();
			using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
			{
				HashSet<string> seenModelIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
				writer.WriteStartObject();
				foreach (JsonProperty property in document.RootElement.EnumerateObject())
				{
					if (string.Equals(property.Name, "models", StringComparison.OrdinalIgnoreCase))
					{
						writer.WritePropertyName(property.Name);
						writer.WriteStartArray();
						foreach (JsonElement model in models.EnumerateArray())
						{
							if (!IsRuntimeModelApiLoadable(model))
							{
								continue;
							}
							AddModelIdentifierCandidate(seenModelIds, ExtractModelIdentifier(model));
							WriteRuntimeModelWithWebChatLoadPolicy(writer, model);
						}
						foreach (WebChatModelManagerLoadSettings settings in GetAdvertisableWebChatModelSettings())
						{
							if (!ModelIdentifierMatchesAny(seenModelIds, settings.Key))
							{
								WriteEnabledWebChatRuntimeModel(writer, settings);
							}
						}
						writer.WriteEndArray();
					}
					else if (!string.Equals(property.Name, "web_chat_model_load_api_enabled", StringComparison.OrdinalIgnoreCase))
					{
						property.WriteTo(writer);
					}
				}
				writer.WriteBoolean("web_chat_model_load_api_enabled", WebChatModelLoadApiEnabled);
				writer.WriteEndObject();
			}
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (JsonException)
		{
			return responseBody;
		}
	}

	private string BuildEnabledWebChatRuntimeModelsListResponse(string warning)
	{
		List<WebChatModelManagerLoadSettings> enabledModels = GetAdvertisableWebChatModelSettings();
		if (enabledModels.Count == 0)
		{
			return "";
		}
		using MemoryStream stream = new MemoryStream();
		using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
		{
			writer.WriteStartObject();
			writer.WriteBoolean("ok", value: true);
			if (!string.IsNullOrWhiteSpace(warning))
			{
				writer.WriteString("warning", warning.Trim());
			}
			writer.WriteBoolean("web_chat_model_load_api_enabled", WebChatModelLoadApiEnabled);
			writer.WritePropertyName("models");
			writer.WriteStartArray();
			foreach (WebChatModelManagerLoadSettings settings in enabledModels)
			{
				WriteEnabledWebChatRuntimeModel(writer, settings);
			}
			writer.WriteEndArray();
			writer.WriteEndObject();
		}
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private void WriteEnabledWebChatRuntimeModel(Utf8JsonWriter writer, WebChatModelManagerLoadSettings settings)
	{
		if (settings == null || string.IsNullOrWhiteSpace(settings.Key))
		{
			return;
		}
		string modelId = settings.Key.Trim();
		EnabledWebChatRuntimeModelDescriptor descriptor = ResolveEnabledWebChatRuntimeModelDescriptor(modelId);
		string displayName = FirstNonEmpty(descriptor.DisplayName, BuildWebChatModelDisplayName(modelId));
		string modelType = FirstNonEmpty(descriptor.Type, "llm");
		string format = FirstNonEmpty(descriptor.Format, GuessWebChatModelFormat(modelId));
		string service = descriptor.Service ?? "";
		bool mediaService = IsWebChatMediaGenerationService(service);
		writer.WriteStartObject();
		writer.WriteString("key", modelId);
		writer.WriteString("id", modelId);
		writer.WriteString("name", displayName);
		writer.WriteString("display_name", displayName);
		writer.WriteString("source", "Workstation");
		writer.WriteString("publisher", "workstation");
		writer.WriteString("type", modelType);
		writer.WriteString("format", format);
		if (mediaService)
		{
			writer.WriteString("service", service);
			writer.WriteString("chat_service", service);
		}
		writer.WriteStartArray("loaded_instances");
		writer.WriteEndArray();
		if (descriptor.Tags.Count > 0)
		{
			writer.WritePropertyName("tags");
			writer.WriteStartArray();
			foreach (string tag in descriptor.Tags)
			{
				writer.WriteStringValue(tag);
			}
			writer.WriteEndArray();
		}
		writer.WriteString("description", descriptor.Description ?? "Enabled in JackLLM Workstation; web chat can load this model on first use.");
		writer.WriteBoolean("isAvailable", value: true);
		writer.WriteBoolean("isLoaded", value: false);
		writer.WriteBoolean("enabled", value: true);
		writer.WriteBoolean("isEnabled", value: true);
		writer.WriteBoolean("disabled", value: false);
		writer.WriteString("status", "enabled");
		writer.WriteBoolean("dynamicLoadEnabled", value: true);
		writer.WriteBoolean("serverDynamicLoadingEnabled", WebChatModelLoadApiEnabled);
		writer.WritePropertyName("capabilities");
		writer.WriteStartObject();
		writer.WriteBoolean("chat_completion", !mediaService);
		writer.WriteBoolean("runtime_load", value: true);
		if (mediaService)
		{
			writer.WriteBoolean("generation", value: true);
			writer.WriteString("chat_service", service);
			if (string.Equals(service, "image_generation", StringComparison.OrdinalIgnoreCase))
			{
				writer.WriteBoolean("image_generation", value: true);
			}
			else if (string.Equals(service, "audio_generation", StringComparison.OrdinalIgnoreCase))
			{
				writer.WriteBoolean("audio_generation", value: true);
			}
			else if (string.Equals(service, "video_generation", StringComparison.OrdinalIgnoreCase))
			{
				writer.WriteBoolean("video_generation", value: true);
			}
		}
		writer.WriteBoolean("web_chat_dynamic_load", value: true);
		writer.WriteEndObject();
		writer.WriteBoolean("web_chat_dynamic_load_enabled", value: true);
		writer.WriteBoolean("web_chat_model_load_api_enabled", WebChatModelLoadApiEnabled);
		writer.WriteBoolean("web_chat_model_enabled", value: true);
		writer.WriteNumber("web_chat_idle_unload_minutes", Math.Max(0, settings.IdleUnloadMinutes));
		writer.WriteEndObject();
	}

	private EnabledWebChatRuntimeModelDescriptor ResolveEnabledWebChatRuntimeModelDescriptor(string modelId)
	{
		EnabledWebChatRuntimeModelDescriptor descriptor = new EnabledWebChatRuntimeModelDescriptor
		{
			Id = (modelId ?? ""),
			DisplayName = BuildWebChatModelDisplayName(modelId),
			Type = "llm",
			Format = GuessWebChatModelFormat(modelId),
			Description = "Enabled in JackLLM Workstation; web chat can load this model on first use."
		};
		if (TryReadCompleteModelManifestDescriptor(modelId, descriptor))
		{
			return descriptor;
		}
		string guessedService = GuessWebChatMediaService(modelId, "");
		if (!string.IsNullOrWhiteSpace(guessedService))
		{
			ApplyWebChatMediaServiceDescriptor(descriptor, guessedService, "");
		}
		return descriptor;
	}

	private bool TryReadCompleteModelManifestDescriptor(string modelId, EnabledWebChatRuntimeModelDescriptor descriptor)
	{
		if (string.IsNullOrWhiteSpace(modelId) || descriptor == null)
		{
			return false;
		}
		HashSet<string> candidates = BuildModelIdentifierCandidates(modelId);
		foreach (string root in GetCompleteModelRoots())
		{
			if (string.IsNullOrWhiteSpace(root) || !Directory.Exists(root))
			{
				continue;
			}
			IEnumerable<string> manifests;
			try
			{
				manifests = Directory.EnumerateFiles(root, "manifest.json", SearchOption.AllDirectories);
			}
			catch
			{
				continue;
			}
			foreach (string manifestPath in manifests)
			{
				try
				{
					using JsonDocument document = JsonDocument.Parse(File.ReadAllText(manifestPath));
					JsonElement manifest = document.RootElement;
					if (manifest.ValueKind != JsonValueKind.Object)
					{
						continue;
					}
					string manifestId = ExtractStringProperty(manifest, "id") ?? "";
					string manifestName = ExtractStringProperty(manifest, "name") ?? "";
					string manifestType = ExtractStringProperty(manifest, "type") ?? "";
					string baseModelFor = "";
					if (TryGetObjectPropertyIgnoreCase(manifest, out var metadata, "metadata") && metadata.ValueKind == JsonValueKind.Object)
					{
						baseModelFor = FirstNonEmpty(ExtractStringProperty(metadata, "baseModelFor"), ExtractStringProperty(metadata, "base_model_for"));
					}
					if (!ModelIdentifierMatches(candidates, manifestId) && !ModelIdentifierMatches(candidates, manifestName) && !ModelIdentifierMatches(candidates, baseModelFor))
					{
						continue;
					}
					descriptor.DisplayName = FirstNonEmpty(manifestName, descriptor.DisplayName, manifestId);
					descriptor.Format = FirstNonEmpty(ExtractStringProperty(manifest, "format"), descriptor.Format);
					descriptor.ManifestType = manifestType;
					descriptor.Description = "Enabled CompleteModels generator in JackLLM Workstation; web chat can load it on first use.";
					string service = GuessWebChatMediaService(modelId, manifestType);
					if (!string.IsNullOrWhiteSpace(service))
					{
						ApplyWebChatMediaServiceDescriptor(descriptor, service, descriptor.Format);
					}
					return true;
				}
				catch
				{
				}
			}
		}
		return false;
	}

	private static IEnumerable<string> GetCompleteModelRoots()
	{
		HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		string[] array = new string[2]
		{
			AppContext.BaseDirectory,
			Directory.GetCurrentDirectory()
		};
		foreach (string basePath in array)
		{
			if (!string.IsNullOrWhiteSpace(basePath))
			{
				string root = Path.GetFullPath(Path.Combine(basePath, "CompleteModels"));
				if (seen.Add(root))
				{
					yield return root;
				}
			}
		}
	}

	private static void ApplyWebChatMediaServiceDescriptor(EnabledWebChatRuntimeModelDescriptor descriptor, string service, string format)
	{
		if (descriptor != null && IsWebChatMediaGenerationService(service))
		{
			descriptor.Service = service;
			string mediaType = (descriptor.Type = service.Replace("_generation", ""));
			if (!string.IsNullOrWhiteSpace(format))
			{
				descriptor.Format = format;
			}
			AddDescriptorTag(descriptor, mediaType);
			AddDescriptorTag(descriptor, mediaType + "-generation");
			AddDescriptorTag(descriptor, "complete-model");
		}
	}

	private static void AddDescriptorTag(EnabledWebChatRuntimeModelDescriptor descriptor, string tag)
	{
		if (descriptor != null && !string.IsNullOrWhiteSpace(tag) && !descriptor.Tags.Any((string existing) => string.Equals(existing, tag, StringComparison.OrdinalIgnoreCase)))
		{
			descriptor.Tags.Add(tag);
		}
	}

	private static bool IsWebChatMediaGenerationService(string service)
	{
		return string.Equals(service, "image_generation", StringComparison.OrdinalIgnoreCase) || string.Equals(service, "audio_generation", StringComparison.OrdinalIgnoreCase) || string.Equals(service, "video_generation", StringComparison.OrdinalIgnoreCase);
	}

	private static string GuessWebChatMediaService(string modelId, string manifestType)
	{
		string text = (modelId + " " + manifestType).ToLowerInvariant();
		if (text.Contains("video") || text.Contains("text-to-video") || text.Contains("image-to-video") || text.Contains("video-to-video") || text.Contains("ltx"))
		{
			return "video_generation";
		}
		if (text.Contains("audio") || text.Contains("speech") || text.Contains("text-to-speech") || text.Contains("tts"))
		{
			return "audio_generation";
		}
		if (text.Contains("image") || text.Contains("stable-diffusion") || text.Contains("diffusion") || text.Contains("text-to-image") || text.Contains("tiny-sd"))
		{
			return "image_generation";
		}
		return "";
	}

	private static string BuildWebChatModelDisplayName(string modelId)
	{
		string text = (modelId ?? "").Trim();
		if (string.IsNullOrWhiteSpace(text))
		{
			return "";
		}
		try
		{
			string fileName = Path.GetFileNameWithoutExtension(text);
			if (!string.IsNullOrWhiteSpace(fileName))
			{
				return fileName;
			}
		}
		catch
		{
		}
		return text;
	}

	private static string GuessWebChatModelFormat(string modelId)
	{
		string extension = "";
		try
		{
			extension = Path.GetExtension((modelId ?? "").Trim());
		}
		catch
		{
		}
		extension = (extension ?? "").TrimStart('.').Trim();
		return string.IsNullOrWhiteSpace(extension) ? "gguf" : extension.ToLowerInvariant();
	}

	private void WriteRuntimeModelWithWebChatLoadPolicy(Utf8JsonWriter writer, JsonElement model)
	{
		if (model.ValueKind != JsonValueKind.Object)
		{
			model.WriteTo(writer);
			return;
		}
		string modelId = ExtractModelIdentifier(model) ?? "";
		WebChatModelManagerLoadSettings settings = null;
		bool modelEnabled = !string.IsNullOrWhiteSpace(modelId) && TryGetModelManagerLoadSettings(modelId, out settings) && settings.Enabled;
		int idleUnloadMinutes = settings?.IdleUnloadMinutes ?? DefaultWebChatRuntimeModelIdleUnloadMinutes;
		bool loaded = RuntimeModelHasLoadedInstances(model);
		bool dynamicLoadEnabled = WebChatModelLoadApiEnabled || modelEnabled;
		bool usable = loaded || dynamicLoadEnabled;
		string policyReason = (usable ? "" : "Enable this model in Workstation's Models tab, or enable the global web chat model-load API in Diagnostics.");
		bool wroteCapabilities = false;
		bool hasLoadDisabledReason = false;
		writer.WriteStartObject();
		foreach (JsonProperty property in model.EnumerateObject())
		{
			if (string.Equals(property.Name, "web_chat_dynamic_load_enabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "webChatDynamicLoadEnabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "web_chat_model_load_api_enabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "web_chat_model_enabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "web_chat_idle_unload_minutes", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "web_chat_load_disabled_reason", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "isAvailable", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "isLoaded", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "enabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "isEnabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "disabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "status", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "dynamicLoadEnabled", StringComparison.OrdinalIgnoreCase) || string.Equals(property.Name, "serverDynamicLoadingEnabled", StringComparison.OrdinalIgnoreCase))
			{
				continue;
			}
			if (string.Equals(property.Name, "load_disabled_reason", StringComparison.OrdinalIgnoreCase))
			{
				hasLoadDisabledReason = !string.IsNullOrWhiteSpace(ReadJsonString(property.Value));
				if (!loaded && (dynamicLoadEnabled || hasLoadDisabledReason))
				{
					property.WriteTo(writer);
				}
			}
			else if (string.Equals(property.Name, "capabilities", StringComparison.OrdinalIgnoreCase) && property.Value.ValueKind == JsonValueKind.Object)
			{
				writer.WritePropertyName(property.Name);
				WriteRuntimeModelCapabilitiesWithPolicy(writer, property.Value, dynamicLoadEnabled);
				wroteCapabilities = true;
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteCapabilities)
		{
			writer.WritePropertyName("capabilities");
			writer.WriteStartObject();
			writer.WriteBoolean("web_chat_dynamic_load", dynamicLoadEnabled);
			writer.WriteEndObject();
		}
		writer.WriteBoolean("web_chat_dynamic_load_enabled", dynamicLoadEnabled);
		writer.WriteBoolean("web_chat_model_load_api_enabled", WebChatModelLoadApiEnabled);
		writer.WriteBoolean("web_chat_model_enabled", modelEnabled);
		writer.WriteNumber("web_chat_idle_unload_minutes", idleUnloadMinutes);
		writer.WriteBoolean("isAvailable", value: true);
		writer.WriteBoolean("isLoaded", loaded);
		writer.WriteBoolean("enabled", usable);
		writer.WriteBoolean("isEnabled", usable);
		writer.WriteBoolean("disabled", !usable);
		writer.WriteBoolean("dynamicLoadEnabled", dynamicLoadEnabled);
		writer.WriteBoolean("serverDynamicLoadingEnabled", WebChatModelLoadApiEnabled);
		writer.WriteString("status", BuildRuntimeModelPolicyStatus(loaded, modelEnabled, dynamicLoadEnabled, usable));
		if (!usable)
		{
			writer.WriteString("web_chat_load_disabled_reason", policyReason);
			if (!hasLoadDisabledReason)
			{
				writer.WriteString("load_disabled_reason", policyReason);
			}
		}
		writer.WriteEndObject();
	}

	private static string BuildRuntimeModelPolicyStatus(bool loaded, bool modelEnabled, bool dynamicLoadEnabled, bool usable)
	{
		if (loaded && modelEnabled)
		{
			return "loaded-enabled";
		}
		if (loaded && dynamicLoadEnabled)
		{
			return "loaded-dynamic";
		}
		if (loaded)
		{
			return "loaded";
		}
		if (modelEnabled)
		{
			return "enabled";
		}
		if (dynamicLoadEnabled)
		{
			return "dynamic-load-available";
		}
		return usable ? "available" : "disabled";
	}

	private static void WriteRuntimeModelCapabilitiesWithPolicy(Utf8JsonWriter writer, JsonElement capabilities, bool dynamicLoadEnabled)
	{
		writer.WriteStartObject();
		foreach (JsonProperty property in capabilities.EnumerateObject())
		{
			if (!string.Equals(property.Name, "web_chat_dynamic_load", StringComparison.OrdinalIgnoreCase) && !string.Equals(property.Name, "webChatDynamicLoad", StringComparison.OrdinalIgnoreCase))
			{
				property.WriteTo(writer);
			}
		}
		writer.WriteBoolean("web_chat_dynamic_load", dynamicLoadEnabled);
		writer.WriteEndObject();
	}

	private bool IsModelEnabledForWebChatDynamicLoad(string model)
	{
		WebChatModelManagerLoadSettings settings;
		return TryGetModelManagerLoadSettings(model, out settings) && settings.Enabled;
	}

	private bool TryGetModelManagerLoadSettings(string model, out WebChatModelManagerLoadSettings settings)
	{
		settings = null;
		if (string.IsNullOrWhiteSpace(model))
		{
			return false;
		}
		HashSet<string> candidates = BuildModelIdentifierCandidates(model);
		try
		{
			string path = GetModelManagerSettingsPath();
			if (!File.Exists(path))
			{
				return false;
			}
			using JsonDocument document = JsonDocument.Parse(File.ReadAllText(path));
			if (document.RootElement.ValueKind != JsonValueKind.Object)
			{
				return false;
			}
			foreach (JsonProperty property in document.RootElement.EnumerateObject())
			{
				if (!ModelIdentifierMatches(candidates, property.Name) || property.Value.ValueKind != JsonValueKind.Object)
				{
					continue;
				}
				settings = ReadModelManagerLoadSettings(property.Name, property.Value);
				return true;
			}
		}
		catch
		{
		}
		return false;
	}

	private WebChatModelManagerLoadSettings ReadModelManagerLoadSettings(string key, JsonElement root)
	{
		WebChatModelManagerLoadSettings webChatModelManagerLoadSettings = new WebChatModelManagerLoadSettings();
		webChatModelManagerLoadSettings.Key = (string.IsNullOrWhiteSpace(key) ? "" : key.Trim());
		webChatModelManagerLoadSettings.Backend = ReadModelManagerString(root, "backend") ?? "auto";
		webChatModelManagerLoadSettings.ParallelismMode = NormalizeWebChatParallelismMode(ReadModelManagerString(root, "parallelism_mode", "parallelismMode") ?? "single");
		webChatModelManagerLoadSettings.ParallelismPlacement = NormalizeWebChatParallelismPlacement(ReadModelManagerString(root, "parallelism_placement", "parallelismPlacement") ?? "local");
		webChatModelManagerLoadSettings.ParallelTensor = ReadModelManagerBool(root, false, "parallel_tensor", "parallelTensor") || string.Equals(webChatModelManagerLoadSettings.ParallelismMode, "tensor_parallel", StringComparison.OrdinalIgnoreCase);
		if (webChatModelManagerLoadSettings.ParallelTensor)
		{
			webChatModelManagerLoadSettings.ParallelismMode = "tensor_parallel";
		}
		webChatModelManagerLoadSettings.ContextLength = Math.Max(1, ReadModelManagerInt(root, 8192, "context_length", "contextLength"));
		webChatModelManagerLoadSettings.EvalBatchSize = Math.Max(1, ReadModelManagerInt(root, 512, "eval_batch_size", "evalBatchSize"));
		webChatModelManagerLoadSettings.GpuLayerCount = ReadModelManagerInt(root, -1, "gpu_layer_count", "gpuLayerCount");
		webChatModelManagerLoadSettings.TargetDeviceIds = ReadModelManagerStringArray(root, "target_device_ids", "targetDeviceIds", "gpu_device_ids", "gpuDeviceIds");
		webChatModelManagerLoadSettings.NetworkNodeIds = ReadModelManagerStringArray(root, "network_node_ids", "networkNodeIds");
		webChatModelManagerLoadSettings.MaxGpuLoadPercent = Math.Max(0, Math.Min(100, ReadModelManagerInt(root, 100, "gpu_load_threshold_percent", "gpuLoadThresholdPercent", "max_gpu_load_percent", "maxGpuLoadPercent")));
		webChatModelManagerLoadSettings.MaxVramUsagePercent = Math.Max(0, Math.Min(100, ReadModelManagerInt(root, 100, "max_vram_usage_percent", "maxVramUsagePercent")));
		webChatModelManagerLoadSettings.PipelineStageCount = Math.Max(1, ReadModelManagerInt(root, 1, "pipeline_stage_count", "pipelineStageCount"));
		webChatModelManagerLoadSettings.DataParallelReplicaCount = Math.Max(1, ReadModelManagerInt(root, 1, "data_parallel_replicas", "dataParallelReplicas", "replica_count", "replicaCount"));
		webChatModelManagerLoadSettings.IdleUnloadMinutes = Math.Max(0, ReadModelManagerInt(root, 15, "idle_unload_minutes", "idleUnloadMinutes"));
		webChatModelManagerLoadSettings.Enabled = ReadModelManagerBool(root, false, "enabled");
		webChatModelManagerLoadSettings.FlashAttention = ReadModelManagerBool(root, false, "flash_attention", "flashAttention");
		webChatModelManagerLoadSettings.OffloadKvCacheToGpu = ReadModelManagerBool(root, false, "offload_kv_cache_to_gpu", "offloadKvCacheToGpu");
		webChatModelManagerLoadSettings.AllowBackendFallback = ReadModelManagerBool(root, true, "allow_backend_fallback", "allowBackendFallback");
		webChatModelManagerLoadSettings.VideoDeviceMap = FirstNonEmpty(ReadModelManagerString(root, "video_device_map", "videoDeviceMap", "device_map", "deviceMap"), webChatModelManagerLoadSettings.VideoDeviceMap);
		webChatModelManagerLoadSettings.VideoAllowCpuOffload = ReadModelManagerBool(root, webChatModelManagerLoadSettings.VideoAllowCpuOffload, "video_allow_cpu_offload", "videoAllowCpuOffload", "allow_cpu_offload", "allowCpuOffload");
		webChatModelManagerLoadSettings.VideoOffloadFolder = ReadModelManagerString(root, "video_offload_folder", "videoOffloadFolder", "offload_folder", "offloadFolder") ?? "";
		webChatModelManagerLoadSettings.VideoDisableCudaMemoryGuard = ReadModelManagerBool(root, false, "video_disable_cuda_memory_guard", "videoDisableCudaMemoryGuard");
		webChatModelManagerLoadSettings.VideoCudaMemoryReserveMb = Math.Max(0, ReadModelManagerInt(root, 1024, "video_cuda_memory_reserve_mb", "videoCudaMemoryReserveMb", "cuda_memory_reserve_mb", "cudaMemoryReserveMb"));
		webChatModelManagerLoadSettings.VideoCpuMaxMemory = ReadModelManagerString(root, "video_cpu_max_memory", "videoCpuMaxMemory", "cpu_max_memory", "cpuMaxMemory") ?? "";
		webChatModelManagerLoadSettings.VideoMemorySaving = ReadModelManagerBool(root, webChatModelManagerLoadSettings.VideoMemorySaving, "video_memory_saving", "videoMemorySaving", "memory_saving", "memorySaving");
		return webChatModelManagerLoadSettings;
	}

	private static string NormalizeWebChatParallelismMode(string value)
	{
		string normalized = (value ?? "").Trim().Replace("-", "_").ToLowerInvariant();
		if (normalized == "data_parallel" || normalized == "model_offload" || normalized == "pipeline_parallel" || normalized == "tensor_parallel")
		{
			return normalized;
		}
		return "single";
	}

	private static string NormalizeWebChatParallelismPlacement(string value)
	{
		string normalized = (value ?? "").Trim().Replace("-", "_").ToLowerInvariant();
		if (normalized == "network" || normalized == "hybrid")
		{
			return normalized;
		}
		return "local";
	}

	private string ReadModelManagerString(JsonElement root, params string[] names)
	{
		JsonElement value;
		return TryGetObjectPropertyIgnoreCase(root, out value, names) ? ReadJsonString(value) : "";
	}

	private bool ReadModelManagerBool(JsonElement root, bool fallback, params string[] names)
	{
		JsonElement value;
		return TryGetObjectPropertyIgnoreCase(root, out value, names) ? ReadJsonBool(value, fallback) : fallback;
	}

	private int ReadModelManagerInt(JsonElement root, int fallback, params string[] names)
	{
		JsonElement value;
		return TryGetObjectPropertyIgnoreCase(root, out value, names) ? ReadJsonInt(value, fallback) : fallback;
	}

	private string[] ReadModelManagerStringArray(JsonElement root, params string[] names)
	{
		JsonElement value;
		if (!TryGetObjectPropertyIgnoreCase(root, out value, names))
		{
			return Array.Empty<string>();
		}
		if (value.ValueKind == JsonValueKind.Array)
		{
			return value.EnumerateArray()
				.Select(item => ReadJsonString(item))
				.Where(text => !string.IsNullOrWhiteSpace(text))
				.Select(text => text.Trim())
				.Distinct(StringComparer.OrdinalIgnoreCase)
				.ToArray();
		}
		string joined = ReadJsonString(value);
		if (string.IsNullOrWhiteSpace(joined))
		{
			return Array.Empty<string>();
		}
		return joined.Split(new char[4] { ',', ';', '\n', '\r' }, StringSplitOptions.RemoveEmptyEntries)
			.Select(text => text.Trim())
			.Where(text => !string.IsNullOrWhiteSpace(text))
			.Distinct(StringComparer.OrdinalIgnoreCase)
			.ToArray();
	}

	private static bool TryGetObjectPropertyIgnoreCase(JsonElement root, out JsonElement value, params string[] names)
	{
		if (root.ValueKind == JsonValueKind.Object)
		{
			foreach (JsonProperty property in root.EnumerateObject())
			{
				string[] array = names ?? Array.Empty<string>();
				foreach (string name in array)
				{
					if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase))
					{
						value = property.Value;
						return true;
					}
				}
			}
		}
		value = default(JsonElement);
		return false;
	}

	private async Task<string> EnsureWebChatRuntimeModelReadyAsync(string requestBody, CancellationToken cancellationToken, Action<string, double?> progress = null)
	{
		if (!IsEffectiveLocalRuntimeLlmRuntime())
		{
			return "";
		}
		string requestedModel = ExtractChatUiStringProperty(requestBody, "model") ?? "";
		string model = (IsChatModelPlaceholder(requestedModel) ? ResolveChatUiRequestModel(requestedModel) : requestedModel.Trim());
		if (IsChatModelPlaceholder(model))
		{
			return "";
		}
		progress?.Invoke("Checking LlmRuntime model " + model + "...", null);
		if (await IsWebChatRuntimeModelLoadedAsync(model, cancellationToken).ConfigureAwait(continueOnCapturedContext: false))
		{
			progress?.Invoke("LlmRuntime model " + model + " is loaded. Opening chat stream...", null);
			return model;
		}
		progress?.Invoke("Loading LlmRuntime model " + model + " for chat...", null);
		if (!CanForwardWebChatModelLoad(JsonSerializer.Serialize(new { model }), out var _, out var reason))
		{
			throw new InvalidOperationException(reason);
		}
		await LoadWebChatRuntimeModelAsync(model, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		progress?.Invoke("LlmRuntime model " + model + " loaded. Opening chat stream...", null);
		return model;
	}

	private bool IsEffectiveLocalRuntimeLlmRuntime()
	{
		return string.Equals(GetModelRuntimeProviderKind(GetLocalModelRuntimeDisplayName()), "llmruntime", StringComparison.OrdinalIgnoreCase);
	}

	private async Task<bool> IsWebChatRuntimeModelLoadedAsync(string model, CancellationToken cancellationToken)
	{
		if (string.IsNullOrWhiteSpace(model))
		{
			return false;
		}
		await EnsureLmStudioForPromptAsync().ConfigureAwait(continueOnCapturedContext: false);
		using (HttpRequestMessage request = new HttpRequestMessage(requestUri: BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/models", method: HttpMethod.Get))
		{
			using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseContentRead, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false)) : "");
			string body = text;
			if (!response.IsSuccessStatusCode || string.IsNullOrWhiteSpace(body))
			{
				return false;
			}
			try
			{
				using JsonDocument document = JsonDocument.Parse(body);
				if (document.RootElement.ValueKind != JsonValueKind.Object || !document.RootElement.TryGetProperty("models", out var models) || models.ValueKind != JsonValueKind.Array)
				{
					return false;
				}
				foreach (JsonElement item in models.EnumerateArray())
				{
					if (item.ValueKind == JsonValueKind.Object)
					{
						string id = ExtractRuntimeModelId(item);
						if (RuntimeModelIdMatches(id, model) && RuntimeModelHasLoadedInstances(item))
						{
							return true;
						}
					}
				}
			}
			catch (JsonException)
			{
			}
		}
		return false;
	}

	private async Task LoadWebChatRuntimeModelAsync(string model, CancellationToken cancellationToken)
	{
		await EnsureLmStudioForPromptAsync().ConfigureAwait(continueOnCapturedContext: false);
		string url = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/models/load";
		string body = BuildWebChatModelLoadRequestBody(JsonSerializer.Serialize(new { model }));
		using (CancellationTokenSource timeout = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken))
		{
			timeout.CancelAfter(ModelRuntimeLoadTimeout);
			using StringContent content = new StringContent(body, Encoding.UTF8, "application/json");
			using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Post, url);
			request.Content = content;
			using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseContentRead, timeout.Token).ConfigureAwait(continueOnCapturedContext: false);
			string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false)) : "");
			string responseBody = text;
			if (!response.IsSuccessStatusCode)
			{
				throw new InvalidOperationException(GetLocalModelRuntimeDisplayName() + " could not load '" + model + "': HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TruncateForLog(responseBody, 500));
			}
			if (ResponseBodyContainsJsonError(responseBody))
			{
				try
				{
					using JsonDocument document = JsonDocument.Parse(responseBody);
					throw new InvalidOperationException(ReadModelRuntimeErrorMessage(document.RootElement.GetProperty("error")));
				}
				catch (JsonException)
				{
					throw new InvalidOperationException(GetLocalModelRuntimeDisplayName() + " could not load '" + model + "'.");
				}
			}
		}
		LogMessage("[Chat UI] Loaded LlmRuntime model for web chat: " + model);
		NoteWebChatRuntimeModelUsed(model);
	}

	private string ReadModelRuntimeErrorMessage(JsonElement error)
	{
		if (error.ValueKind == JsonValueKind.String)
		{
			return error.GetString() ?? "Model runtime request failed.";
		}
		if (error.ValueKind == JsonValueKind.Object)
		{
			string message = ExtractStringProperty(error, "message") ?? ExtractStringProperty(error, "code") ?? ExtractStringProperty(error, "type");
			if (!string.IsNullOrWhiteSpace(message))
			{
				return message;
			}
		}
		return string.IsNullOrWhiteSpace(error.GetRawText()) ? "Model runtime request failed." : error.GetRawText();
	}

	private IDisposable BeginWebChatRuntimeModelUse(string model)
	{
		if (string.IsNullOrWhiteSpace(model))
		{
			return null;
		}
		string key = model.Trim();
		lock (_webChatRuntimeModelIdleLock)
		{
			CancelWebChatRuntimeModelIdleUnloadLocked(key);
			_webChatRuntimeModelLastUsedUtc[key] = DateTimeOffset.UtcNow;
			_webChatRuntimeModelActiveUses[key] = ((!_webChatRuntimeModelActiveUses.TryGetValue(key, out var count)) ? 1 : (count + 1));
		}
		return new ActionDisposable(delegate
		{
			EndWebChatRuntimeModelUse(key);
		});
	}

	private void EndWebChatRuntimeModelUse(string model)
	{
		if (string.IsNullOrWhiteSpace(model))
		{
			return;
		}
		lock (_webChatRuntimeModelIdleLock)
		{
			int active;
			int count = (_webChatRuntimeModelActiveUses.TryGetValue(model, out active) ? (active - 1) : 0);
			if (count > 0)
			{
				_webChatRuntimeModelActiveUses[model] = count;
				return;
			}
			_webChatRuntimeModelActiveUses.Remove(model);
			_webChatRuntimeModelLastUsedUtc[model] = DateTimeOffset.UtcNow;
			ScheduleWebChatRuntimeModelIdleUnloadLocked(model);
		}
	}

	private void NoteWebChatRuntimeModelUsed(string model)
	{
		if (string.IsNullOrWhiteSpace(model))
		{
			return;
		}
		model = model.Trim();
		lock (_webChatRuntimeModelIdleLock)
		{
			_webChatRuntimeModelLastUsedUtc[model] = DateTimeOffset.UtcNow;
			if (!_webChatRuntimeModelActiveUses.TryGetValue(model, out var active) || active <= 0)
			{
				ScheduleWebChatRuntimeModelIdleUnloadLocked(model);
			}
		}
	}

	private void ScheduleWebChatRuntimeModelIdleUnloadLocked(string model)
	{
		CancelWebChatRuntimeModelIdleUnloadLocked(model);
		int idleMinutes = GetWebChatRuntimeModelIdleUnloadMinutes(model);
		if (idleMinutes > 0)
		{
			CancellationTokenSource cancellation = new CancellationTokenSource();
			CancellationToken token = cancellation.Token;
			_webChatRuntimeModelIdleUnloadCancellations[model] = cancellation;
			TimeSpan delay = TimeSpan.FromMinutes(idleMinutes);
			Task.Run(async delegate
			{
				await UnloadWebChatRuntimeModelAfterIdleAsync(model, delay, token).ConfigureAwait(continueOnCapturedContext: false);
			});
		}
	}

	private async Task UnloadWebChatRuntimeModelAfterIdleAsync(string model, TimeSpan delay, CancellationToken cancellationToken)
	{
		try
		{
			await Task.Delay(delay, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		}
		catch (OperationCanceledException)
		{
			return;
		}
		bool shouldUnload = false;
		lock (_webChatRuntimeModelIdleLock)
		{
			if (cancellationToken.IsCancellationRequested)
			{
				return;
			}
			int idleMinutes = GetWebChatRuntimeModelIdleUnloadMinutes(model);
			if (idleMinutes <= 0)
			{
				CancelWebChatRuntimeModelIdleUnloadLocked(model);
				return;
			}
			if (_webChatRuntimeModelActiveUses.TryGetValue(model, out var active) && active > 0)
			{
				return;
			}
			DateTimeOffset last;
			DateTimeOffset lastUsed = (_webChatRuntimeModelLastUsedUtc.TryGetValue(model, out last) ? last : DateTimeOffset.UtcNow);
			if (DateTimeOffset.UtcNow - lastUsed < TimeSpan.FromMinutes(idleMinutes))
			{
				ScheduleWebChatRuntimeModelIdleUnloadLocked(model);
				return;
			}
			_webChatRuntimeModelIdleUnloadCancellations.Remove(model);
			shouldUnload = true;
		}
		if (shouldUnload)
		{
			await UnloadWebChatRuntimeModelAsync(model).ConfigureAwait(continueOnCapturedContext: false);
		}
	}

	private async Task UnloadWebChatRuntimeModelAsync(string model)
	{
		if (string.IsNullOrWhiteSpace(model) || !IsEffectiveLocalRuntimeLlmRuntime())
		{
			return;
		}
		try
		{
			string url = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/models/unload";
			string body = JsonSerializer.Serialize(new { model });
			using CancellationTokenSource timeout = new CancellationTokenSource(ModelRuntimeUnloadTimeout);
			using StringContent content = new StringContent(body, Encoding.UTF8, "application/json");
			using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Post, url);
			request.Content = content;
			using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseContentRead, timeout.Token).ConfigureAwait(continueOnCapturedContext: false);
			string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false)) : "");
			string responseBody = text;
			if (response.IsSuccessStatusCode && !ResponseBodyContainsJsonError(responseBody))
			{
				LogMessage("[Chat UI] Idle-unloaded LlmRuntime model: " + model);
				return;
			}
			LogMessage("[Chat UI] Idle unload failed for LlmRuntime model " + model + ": HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TruncateForLog(responseBody, 500));
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Idle unload failed for LlmRuntime model " + model + ": " + ex.Message);
		}
	}

	private async Task UnloadLoadedWebChatRuntimeModelsForPersonaPlexAsync()
	{
		if (!IsEffectiveLocalRuntimeLlmRuntime())
		{
			return;
		}
		List<string> loadedModels = new List<string>();
		try
		{
			foreach (ChatUiModelInfo model in BuildServerBrowserModelCapabilities(GetServerBrowserProfile()))
			{
				if (model == null || string.IsNullOrWhiteSpace(model.id) || !model.isLoaded)
				{
					continue;
				}
				if (!loadedModels.Any(existing => string.Equals(existing, model.id, StringComparison.OrdinalIgnoreCase)))
				{
					loadedModels.Add(model.id);
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[PersonaPlex] Could not inspect loaded runtime models before Voice Mode start: " + ex.Message);
			return;
		}
		foreach (string model in loadedModels)
		{
			try
			{
				LogMessage("[PersonaPlex] Unloading LlmRuntime model before Voice Mode start: " + model);
				await UnloadWebChatRuntimeModelAsync(model).ConfigureAwait(false);
			}
			catch (Exception ex)
			{
				LogMessage("[PersonaPlex] Could not unload LlmRuntime model before Voice Mode start: " + model + ": " + ex.Message);
			}
		}
	}

	private int GetWebChatRuntimeModelIdleUnloadMinutes(string model)
	{
		WebChatModelManagerLoadSettings settings;
		return TryGetModelManagerLoadSettings(model, out settings) ? Math.Max(0, settings.IdleUnloadMinutes) : (WebChatModelLoadApiEnabled ? DefaultWebChatRuntimeModelIdleUnloadMinutes : 0);
	}

	private void CancelWebChatRuntimeModelIdleUnloadLocked(string model)
	{
		if (!_webChatRuntimeModelIdleUnloadCancellations.TryGetValue(model, out var cancellation))
		{
			return;
		}
		_webChatRuntimeModelIdleUnloadCancellations.Remove(model);
		try
		{
			cancellation.Cancel();
		}
		catch
		{
		}
		try
		{
			cancellation.Dispose();
		}
		catch
		{
		}
	}

	private void CancelAllWebChatRuntimeModelIdleUnloads()
	{
		List<CancellationTokenSource> cancellations;
		lock (_webChatRuntimeModelIdleLock)
		{
			cancellations = _webChatRuntimeModelIdleUnloadCancellations.Values.ToList();
			_webChatRuntimeModelIdleUnloadCancellations.Clear();
			_webChatRuntimeModelActiveUses.Clear();
			_webChatRuntimeModelLastUsedUtc.Clear();
		}
		foreach (CancellationTokenSource cancellation in cancellations)
		{
			try
			{
				cancellation.Cancel();
			}
			catch
			{
			}
			try
			{
				cancellation.Dispose();
			}
			catch
			{
			}
		}
	}

