	private static HashSet<string> BuildModelIdentifierCandidates(string model)
	{
		HashSet<string> candidates = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		AddModelIdentifierCandidate(candidates, model);
		return candidates;
	}

	private static void AddModelIdentifierCandidate(HashSet<string> candidates, string value)
	{
		value = (value ?? "").Trim();
		if (value.Length == 0)
		{
			return;
		}
		AddModelIdentifierCandidateAlias(candidates, value);
		try
		{
			string fileName = Path.GetFileName(value);
			if (!string.IsNullOrWhiteSpace(fileName))
			{
				AddModelIdentifierCandidateAlias(candidates, fileName);
				string withoutExtension = Path.GetFileNameWithoutExtension(fileName);
				if (!string.IsNullOrWhiteSpace(withoutExtension))
				{
					AddModelIdentifierCandidateAlias(candidates, withoutExtension);
				}
			}
		}
		catch
		{
		}
	}

	private static void AddModelIdentifierCandidateAlias(HashSet<string> candidates, string value)
	{
		value = (value ?? "").Trim();
		if (candidates == null || string.IsNullOrWhiteSpace(value))
		{
			return;
		}
		candidates.Add(value);
		string stripped = StripRuntimeModelPackagingSuffix(value);
		if (!string.IsNullOrWhiteSpace(stripped))
		{
			candidates.Add(stripped);
		}
	}

	private static string StripRuntimeModelPackagingSuffix(string value)
	{
		string text = (value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(text))
		{
			return "";
		}
		text = Regex.Replace(text, @"(?:[\s._-]+(?:pytorch|diffusers|onnx|cuda|cpu|safetensors|checkpoint|weights))+$", "", RegexOptions.IgnoreCase);
		return text.Trim('.', '/', '\\', '-', '_', ' ');
	}

	private static bool ModelIdentifierMatches(HashSet<string> candidates, string configuredModel)
	{
		if (candidates == null || candidates.Count == 0 || string.IsNullOrWhiteSpace(configuredModel))
		{
			return false;
		}
		foreach (string candidate in BuildModelIdentifierCandidates(configuredModel))
		{
			if (candidates.Contains(candidate))
			{
				return true;
			}
		}
		return false;
	}

	private static bool IsTruthyString(string value)
	{
		string normalized = (value ?? "").Trim();
		return normalized.Equals("true", StringComparison.OrdinalIgnoreCase) || normalized.Equals("1", StringComparison.OrdinalIgnoreCase) || normalized.Equals("yes", StringComparison.OrdinalIgnoreCase) || normalized.Equals("on", StringComparison.OrdinalIgnoreCase) || normalized.Equals("enabled", StringComparison.OrdinalIgnoreCase);
	}

	private static string ExtractModelIdentifierFromBody(string body)
	{
		if (string.IsNullOrWhiteSpace(body))
		{
			return null;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(body);
			return ExtractModelIdentifier(document.RootElement);
		}
		catch (JsonException)
		{
			return null;
		}
	}

	internal static string PrepareModelRuntimeForwardBody(string pathAndQuery, string body, string runtimeDisplayName)
	{
		string normalizedBody = (string.IsNullOrWhiteSpace(body) ? "{}" : body);
		if (!IsModelLoadOrUnloadPath(pathAndQuery))
		{
			return normalizedBody;
		}
		string[] propertyNames = ((!IsLmStudioRuntimeDisplayName(runtimeDisplayName)) ? Array.Empty<string>() : new string[3] { "backend", "gpu_layer_count", "allow_backend_fallback" });
		return RemoveJsonObjectProperties(normalizedBody, normalizeModelProperty: true, propertyNames);
	}

