	private static string RemoveJsonObjectProperties(string body, bool normalizeModelProperty, params string[] propertyNames)
	{
		if (string.IsNullOrWhiteSpace(body))
		{
			return string.IsNullOrWhiteSpace(body) ? "{}" : body;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(body);
			if (document.RootElement.ValueKind != JsonValueKind.Object)
			{
				return body;
			}
			if (propertyNames == null)
			{
				propertyNames = Array.Empty<string>();
			}
			HashSet<string> excluded = new HashSet<string>(propertyNames, StringComparer.OrdinalIgnoreCase);
			string model = (normalizeModelProperty ? ExtractModelIdentifier(document.RootElement) : null);
			bool hasModel = HasModelProperty(document.RootElement);
			using MemoryStream stream = new MemoryStream();
			using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
			{
				writer.WriteStartObject();
				foreach (JsonProperty property in document.RootElement.EnumerateObject())
				{
					if (!excluded.Contains(property.Name))
					{
						if (normalizeModelProperty && string.Equals(property.Name, "model", StringComparison.OrdinalIgnoreCase) && string.IsNullOrWhiteSpace(ReadJsonString(property.Value)))
						{
							hasModel = false;
						}
						else
						{
							property.WriteTo(writer);
						}
					}
				}
				if (normalizeModelProperty && !hasModel && !string.IsNullOrWhiteSpace(model))
				{
					writer.WriteString("model", model);
				}
				writer.WriteEndObject();
			}
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (JsonException)
		{
			return body;
		}
	}

	private static bool HasModelProperty(JsonElement root)
	{
		if (root.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		return root.EnumerateObject().Any((JsonProperty property) => string.Equals(property.Name, "model", StringComparison.OrdinalIgnoreCase) && !string.IsNullOrWhiteSpace(ReadJsonString(property.Value)));
	}

	private static string ExtractModelIdentifier(JsonElement root)
	{
		if (root.ValueKind != JsonValueKind.Object)
		{
			return null;
		}
		return FirstNonEmpty(ReadJsonString(GetPropertyOrNull(root, "model")), ReadJsonString(GetPropertyOrNull(root, "model_id")), ReadJsonString(GetPropertyOrNull(root, "key")), ReadJsonString(GetPropertyOrNull(root, "id")), ReadJsonString(GetPropertyOrNull(root, "name")), ReadJsonString(GetPropertyOrNull(root, "display_name")), ReadJsonString(GetPropertyOrNull(root, "displayName")), ReadJsonString(GetPropertyOrNull(root, "path")), ReadJsonString(GetPropertyOrNull(root, "file_path")), ReadJsonString(GetPropertyOrNull(root, "filePath")));
	}

	private static JsonElement? GetPropertyOrNull(JsonElement root, string propertyName)
	{
		if (root.ValueKind != JsonValueKind.Object)
		{
			return null;
		}
		foreach (JsonProperty property in root.EnumerateObject())
		{
			if (string.Equals(property.Name, propertyName, StringComparison.OrdinalIgnoreCase))
			{
				return property.Value;
			}
		}
		return null;
	}

	private static string ReadJsonString(JsonElement? element)
	{
		if (!element.HasValue)
		{
			return "";
		}
		JsonElement value = element.Value;
		JsonValueKind valueKind = value.ValueKind;
		if (1 == 0)
		{
		}
		string result = valueKind switch
		{
			JsonValueKind.String => value.GetString() ?? "", 
			JsonValueKind.Number => value.GetRawText(), 
			JsonValueKind.True => "true", 
			JsonValueKind.False => "false", 
			_ => "", 
		};
		if (1 == 0)
		{
		}
		return result;
	}

	private static bool ResponseBodyContainsJsonError(string responseBody)
	{
		if (string.IsNullOrWhiteSpace(responseBody))
		{
			return false;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(responseBody);
			JsonElement error;
			return document.RootElement.ValueKind == JsonValueKind.Object && document.RootElement.TryGetProperty("error", out error) && error.ValueKind != JsonValueKind.Null && error.ValueKind != JsonValueKind.Undefined && !string.IsNullOrWhiteSpace(error.GetRawText());
		}
		catch (JsonException)
		{
			return false;
		}
	}

	private static TimeSpan GetModelRuntimeForwardTimeout(string pathAndQuery)
	{
		string path = (pathAndQuery ?? "").ToLowerInvariant();
		if (path.Contains("/runtime/compatibility/repair-pytorch"))
		{
			return ModelRuntimeLoadTimeout;
		}
		if (path.Contains("/runtime/compatibility"))
		{
			return ModelRuntimeListTimeout;
		}
		if (path.Contains("/models/load"))
		{
			return ModelRuntimeLoadTimeout;
		}
		if (path.Contains("/models/unload"))
		{
			return ModelRuntimeUnloadTimeout;
		}
		if (path.Contains("/models"))
		{
			return ModelRuntimeListTimeout;
		}
		return ChatModelListTimeout;
	}

	private string GetConfiguredChatModelOrPlaceholder()
	{
		return string.IsNullOrWhiteSpace(ChatModel) ? "lm-studio" : ChatModel.Trim();
	}

	private List<ChatUiModelInfo> GetCachedOrConfiguredChatModelInfos(string configuredModel)
	{
		List<ChatUiModelInfo> models = new List<ChatUiModelInfo>();
		lock (_chatModelCacheLock)
		{
			MergeChatModelInfos(models, _lastChatUiModelInfos);
		}
		if (models.Count == 0)
		{
			models = BuildChatModelInfos(new List<string> { configuredModel });
		}
		return models;
	}

	private IEnumerable<string> GetLmStudioModelListUrls()
	{
		string baseUrl = BuildLocalModelRuntimeBaseUrl().TrimEnd('/');
		if (IsEffectiveLocalRuntimeLlmRuntime())
		{
			yield return baseUrl + "/api/v1/models";
			yield return baseUrl + "/v1/models";
			yield return baseUrl + "/api/v0/models";
			yield break;
		}
		yield return baseUrl + "/v1/models";
		yield return baseUrl + "/api/v1/models";
		yield return baseUrl + "/api/v0/models";
	}

	private string ResolveChatUiRequestModel(string requestedModel)
	{
		if (!IsChatModelPlaceholder(requestedModel) && !IsLikelyModelArtifactId(requestedModel) && !IsLikelyNonChatModelId(requestedModel))
		{
			return requestedModel.Trim();
		}
		string configuredModel = GetConfiguredChatModelOrPlaceholder();
		if (!IsChatModelPlaceholder(configuredModel) && !IsLikelyModelArtifactId(configuredModel) && !IsLikelyNonChatModelId(configuredModel))
		{
			return configuredModel;
		}
		lock (_chatModelCacheLock)
		{
			ChatUiModelInfo cached = _lastChatUiModelInfos.FirstOrDefault((ChatUiModelInfo model) => model != null && model.isLoaded && !IsChatModelPlaceholder(model.id));
			if (cached != null && !string.IsNullOrWhiteSpace(cached.id))
			{
				return cached.id;
			}
		}
		string discoveredModel = TryRefreshAndGetFirstLoadedChatModel();
		if (!IsChatModelPlaceholder(discoveredModel))
		{
			return discoveredModel;
		}
		return "lm-studio";
	}

	private string ChooseChatUiSelectedModel(List<ChatUiModelInfo> models, string configuredModel)
	{
		configuredModel = (string.IsNullOrWhiteSpace(configuredModel) ? "lm-studio" : configuredModel.Trim());
		bool configuredUsable = !IsChatModelPlaceholder(configuredModel) && !IsLikelyModelArtifactId(configuredModel) && !IsLikelyNonChatModelId(configuredModel);
		if (models == null || models.Count == 0)
		{
			return configuredUsable ? configuredModel : "lm-studio";
		}
		if (configuredUsable && models.Any((ChatUiModelInfo model) => model != null && string.Equals(model.id, configuredModel, StringComparison.OrdinalIgnoreCase)))
		{
			return configuredModel;
		}
		ChatUiModelInfo firstLoadedModel = models.FirstOrDefault((ChatUiModelInfo model) => model != null && model.isLoaded && !IsChatModelPlaceholder(model.id));
		return (firstLoadedModel != null && !string.IsNullOrWhiteSpace(firstLoadedModel.id)) ? firstLoadedModel.id : (configuredUsable ? configuredModel : "lm-studio");
	}

	private void CacheChatModelInfos(List<ChatUiModelInfo> models)
	{
		lock (_chatModelCacheLock)
		{
			_lastChatUiModelInfos = ((models == null) ? new List<ChatUiModelInfo>() : models.Where(IsAdvertisableChatUiModelInfo).ToList());
		}
	}

	private ChatUiModelInventorySnapshot BuildChatUiModelInventorySnapshot(List<ChatUiModelInfo> models, string selected, bool modelListAvailable, string warning = "")
	{
		models = ((models == null) ? new List<ChatUiModelInfo>() : (from @group in models.Where((ChatUiModelInfo model) => model != null && !string.IsNullOrWhiteSpace(model.id)).GroupBy<ChatUiModelInfo, string>((ChatUiModelInfo model) => model.id.Trim(), StringComparer.OrdinalIgnoreCase)
			select @group.First() into model
			orderby model.isLoaded descending, model.enabled descending
			select model).ThenBy<ChatUiModelInfo, string>((ChatUiModelInfo model) => model.id, StringComparer.OrdinalIgnoreCase).ToList());
		DecorateChatUiModelsWithPolicy(models);
		models = models.Where(IsAdvertisableChatUiModelInfo).ToList();
		if (!string.IsNullOrWhiteSpace(selected) && !models.Any((ChatUiModelInfo model) => string.Equals(model.id, selected, StringComparison.OrdinalIgnoreCase)))
		{
			selected = ChooseChatUiSelectedModel(models, selected);
		}
		string modelBenchmarksJson = GetCurrentModelBenchmarksJson();
		int benchmarkedModelCount = ApplyChatUiModelBenchmarks(models, modelBenchmarksJson);
		ApplyServerBrowserPaymentDefaults(models, GetServerBrowserProfile());
		return new ChatUiModelInventorySnapshot
		{
			ok = true,
			selected = (selected ?? ""),
			modelListAvailable = modelListAvailable,
			warning = (warning ?? ""),
			dynamicLoadingEnabled = (WebChatModelLoadApiEnabled || models.Any((ChatUiModelInfo model) => model.dynamicLoadEnabled)),
			serverDynamicLoadingEnabled = WebChatModelLoadApiEnabled,
			web_chat_model_load_api_enabled = WebChatModelLoadApiEnabled,
			modelCount = models.Count,
			availableModelCount = models.Count((ChatUiModelInfo model) => model.isAvailable),
			loadedModelCount = models.Count((ChatUiModelInfo model) => model.isLoaded),
			enabledModelCount = models.Count((ChatUiModelInfo model) => model.enabled),
			disabledModelCount = models.Count((ChatUiModelInfo model) => model.disabled),
			availableModels = JoinChatUiModelIds(models.Where((ChatUiModelInfo model) => model.isAvailable)),
			loadedModels = JoinChatUiModelIds(models.Where((ChatUiModelInfo model) => model.isLoaded)),
			enabledModels = JoinChatUiModelIds(models.Where((ChatUiModelInfo model) => model.enabled)),
			disabledModels = JoinChatUiModelIds(models.Where((ChatUiModelInfo model) => model.disabled)),
			modelBenchmarksJson = modelBenchmarksJson,
			benchmarkedModelCount = benchmarkedModelCount,
			models = models
		};
	}

	private string GetCurrentModelBenchmarksJson()
	{
		try
		{
			return NormalizeChatUiModelBenchmarksJson(GetServerBrowserProfile()?.ModelBenchmarksJson);
		}
		catch
		{
			return "";
		}
	}

	private int ApplyChatUiModelBenchmarks(List<ChatUiModelInfo> models, string modelBenchmarksJson)
	{
		if (models == null || models.Count == 0)
		{
			return 0;
		}
		Dictionary<string, ChatUiModelBenchmarkSummary> benchmarks = ReadChatUiModelBenchmarks(modelBenchmarksJson);
		if (benchmarks.Count == 0)
		{
			return 0;
		}
		foreach (ChatUiModelInfo model in models)
		{
			if (model != null && !string.IsNullOrWhiteSpace(model.id) && benchmarks.TryGetValue(model.id.Trim(), out var benchmark))
			{
				model.supportsImages = model.supportsImages || benchmark.SupportsImages;
				model.supportsTools = model.supportsTools || benchmark.SupportsTools;
				model.supportsImageGeneration = model.supportsImageGeneration || benchmark.SupportsImageGeneration;
				model.supportsAudioGeneration = model.supportsAudioGeneration || benchmark.SupportsAudioGeneration;
				model.supportsVideoGeneration = model.supportsVideoGeneration || benchmark.SupportsVideoGeneration;
				model.tokensPerSecond = benchmark.TokensPerSecond;
				model.tokensPerHour = benchmark.TokensPerHour;
				model.outputTokens = benchmark.OutputTokens;
				model.benchmarkDurationMs = benchmark.DurationMs;
				model.benchmarkRating = benchmark.Rating;
				model.rating = benchmark.Rating;
				model.score = benchmark.Rating;
				model.benchmarkedUtc = benchmark.BenchmarkedUtc ?? "";
				model.benchmarkStatus = FirstNonEmpty(benchmark.Status, (benchmark.TokensPerSecond > 0.0) ? ("Done: " + benchmark.TokensPerSecond.ToString("0.0", CultureInfo.InvariantCulture) + " tok/s, score " + benchmark.Rating.ToString(CultureInfo.InvariantCulture) + "/100") : "");
				model.benchmarked = benchmark.TokensPerSecond > 0.0 || benchmark.Rating > 0 || !string.IsNullOrWhiteSpace(model.benchmarkedUtc);
				ApplyChatUiModelPaymentInfo(model, benchmark.RequiresPayment, benchmark.StripePriceId, benchmark.StripeAccount, benchmark.StripeUnitAmountCents, benchmark.StripeCurrency, benchmark.PaymentStatus);
			}
		}
		return benchmarks.Count;
	}

	private Dictionary<string, ChatUiModelBenchmarkSummary> ReadChatUiModelBenchmarks(string modelBenchmarksJson)
	{
		Dictionary<string, ChatUiModelBenchmarkSummary> benchmarks = new Dictionary<string, ChatUiModelBenchmarkSummary>(StringComparer.OrdinalIgnoreCase);
		modelBenchmarksJson = NormalizeChatUiModelBenchmarksJson(modelBenchmarksJson);
		if (string.IsNullOrWhiteSpace(modelBenchmarksJson))
		{
			return benchmarks;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(modelBenchmarksJson);
			if (document.RootElement.ValueKind != JsonValueKind.Array)
			{
				return benchmarks;
			}
			foreach (JsonElement item in document.RootElement.EnumerateArray())
			{
				if (item.ValueKind != JsonValueKind.Object)
				{
					continue;
				}
				string modelId = ReadBenchmarkString(item, "modelId", "ModelId", "id", "model", "name");
				if (!string.IsNullOrWhiteSpace(modelId))
				{
					ChatUiModelBenchmarkSummary chatUiModelBenchmarkSummary = new ChatUiModelBenchmarkSummary();
					chatUiModelBenchmarkSummary.ModelId = modelId.Trim();
					chatUiModelBenchmarkSummary.SupportsImages = ReadBenchmarkBool(item, false, "supportsImages", "SupportsImages", "supportsVision", "SupportsVision");
					chatUiModelBenchmarkSummary.SupportsTools = ReadBenchmarkBool(item, false, "supportsTools", "SupportsTools");
					chatUiModelBenchmarkSummary.SupportsImageGeneration = ReadBenchmarkBool(item, false, "supportsImageGeneration", "SupportsImageGeneration", "imageGeneration", "ImageGeneration");
					chatUiModelBenchmarkSummary.SupportsAudioGeneration = ReadBenchmarkBool(item, false, "supportsAudioGeneration", "SupportsAudioGeneration", "audioGeneration", "AudioGeneration");
					chatUiModelBenchmarkSummary.SupportsVideoGeneration = ReadBenchmarkBool(item, false, "supportsVideoGeneration", "SupportsVideoGeneration", "videoGeneration", "VideoGeneration");
					chatUiModelBenchmarkSummary.TokensPerSecond = ReadBenchmarkDouble(item, 0.0, "tokensPerSecond", "TokensPerSecond", "tokPerSecond", "tok_s");
					chatUiModelBenchmarkSummary.TokensPerHour = ReadBenchmarkDouble(item, 0.0, "tokensPerHour", "TokensPerHour");
					chatUiModelBenchmarkSummary.OutputTokens = ReadBenchmarkInt(item, 0, "outputTokens", "OutputTokens");
					chatUiModelBenchmarkSummary.DurationMs = ReadBenchmarkDouble(item, 0.0, "durationMs", "DurationMs", "benchmarkDurationMs");
					chatUiModelBenchmarkSummary.Rating = ReadBenchmarkInt(item, 0, "rating", "Rating", "benchmarkRating", "score", "Score");
					chatUiModelBenchmarkSummary.BenchmarkedUtc = ReadBenchmarkString(item, "benchmarkedUtc", "BenchmarkedUtc", "updatedUtc", "createdUtc");
					chatUiModelBenchmarkSummary.Status = ReadBenchmarkString(item, "status", "Status", "benchmarkStatus");
					ReadModelPaymentInfo(item, out bool requiresPayment, out string stripePriceId, out string stripeAccount, out long unitAmountCents, out string stripeCurrency, out string paymentStatus);
					chatUiModelBenchmarkSummary.RequiresPayment = requiresPayment;
					chatUiModelBenchmarkSummary.StripePriceId = stripePriceId;
					chatUiModelBenchmarkSummary.StripeAccount = stripeAccount;
					chatUiModelBenchmarkSummary.StripeUnitAmountCents = unitAmountCents;
					chatUiModelBenchmarkSummary.StripeCurrency = stripeCurrency;
					chatUiModelBenchmarkSummary.PaymentStatus = paymentStatus;
					ChatUiModelBenchmarkSummary benchmark = chatUiModelBenchmarkSummary;
					if (benchmark.Rating <= 0 && benchmark.TokensPerSecond > 0.0)
					{
						benchmark.Rating = (int)Math.Round(Math.Max(0.0, Math.Min(100.0, benchmark.TokensPerSecond / 120.0 * 100.0)));
					}
					benchmarks[benchmark.ModelId] = benchmark;
				}
			}
		}
		catch
		{
		}
		return benchmarks;
	}

	private string ReadBenchmarkString(JsonElement element, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(element, name, out var value))
			{
				return ExtractJsonString(value) ?? "";
			}
		}
		return "";
	}

	private bool ReadBenchmarkBool(JsonElement element, bool fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(element, name, out var value))
			{
				return ReadJsonBool(value, fallback);
			}
		}
		return fallback;
	}

	private int ReadBenchmarkInt(JsonElement element, int fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(element, name, out var value))
			{
				return ReadJsonInt(value, fallback);
			}
		}
		return fallback;
	}

	private double ReadBenchmarkDouble(JsonElement element, double fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(element, name, out var value))
			{
				return ReadJsonDouble(value, fallback);
			}
		}
		return fallback;
	}

	private static string NormalizeChatUiModelBenchmarksJson(string json)
	{
		//IL_0103: Unknown result type (might be due to invalid IL or missing references)
		//IL_010a: Expected O, but got Unknown
		if (string.IsNullOrWhiteSpace(json))
		{
			return "";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			JsonElement root = document.RootElement;
			if (root.ValueKind == JsonValueKind.Array)
			{
				return (root.GetArrayLength() == 0 || !JsonElementArrayHasBenchmarkSignal(root)) ? "" : root.GetRawText();
			}
			if (root.ValueKind != JsonValueKind.Object)
			{
				return "";
			}
			if (TryGetJsonArrayProperty(root, "modelBenchmarks", out var modelBenchmarks))
			{
				return (modelBenchmarks.GetArrayLength() == 0 || !JsonElementArrayHasBenchmarkSignal(modelBenchmarks)) ? "" : modelBenchmarks.GetRawText();
			}
			if (TryGetJsonArrayProperty(root, "benchmarks", out var benchmarks))
			{
				return (benchmarks.GetArrayLength() == 0 || !JsonElementArrayHasBenchmarkSignal(benchmarks)) ? "" : benchmarks.GetRawText();
			}
			JsonArray keyedBenchmarks = new JsonArray((JsonNodeOptions?)null);
			foreach (JsonProperty property in root.EnumerateObject())
			{
				if (property.Value.ValueKind != JsonValueKind.Object || !JsonElementLooksLikeBenchmark(property.Value, requireId: false))
				{
					continue;
				}
				JsonNode node = JsonNode.Parse(property.Value.GetRawText(), (JsonNodeOptions?)null, default(JsonDocumentOptions));
				JsonObject item = (JsonObject)(object)((node is JsonObject) ? node : null);
				if (item != null)
				{
					if (!item.ContainsKey("modelId") && !item.ContainsKey("ModelId") && !item.ContainsKey("id"))
					{
						item["modelId"] = property.Name;
					}
					keyedBenchmarks.Add<JsonObject>(item);
				}
			}
			return (keyedBenchmarks.Count == 0) ? "" : ((JsonNode)keyedBenchmarks).ToJsonString((JsonSerializerOptions)null);
		}
		catch
		{
			return "";
		}
	}

	private static bool JsonElementArrayHasBenchmarkSignal(JsonElement array)
	{
		if (array.ValueKind != JsonValueKind.Array)
		{
			return false;
		}
		foreach (JsonElement item in array.EnumerateArray())
		{
			if (JsonElementLooksLikeBenchmark(item))
			{
				return true;
			}
		}
		return false;
	}

	private static bool JsonElementLooksLikeBenchmark(JsonElement item, bool requireId = true)
	{
		if (item.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		bool hasId = !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "modelId")) || !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "ModelId")) || !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "id")) || !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "model")) || !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "name"));
		return (ReadJsonElementDouble(item, "tokensPerSecond") > 0.0 || ReadJsonElementDouble(item, "TokensPerSecond") > 0.0 || ReadJsonElementDouble(item, "tokensPerHour") > 0.0 || ReadJsonElementDouble(item, "TokensPerHour") > 0.0 || ReadJsonElementInt(item, "outputTokens") > 0 || ReadJsonElementInt(item, "OutputTokens") > 0 || ReadJsonElementDouble(item, "durationMs") > 0.0 || ReadJsonElementDouble(item, "DurationMs") > 0.0 || ReadJsonElementDouble(item, "benchmarkDurationMs") > 0.0 || ReadJsonElementDouble(item, "BenchmarkDurationMs") > 0.0 || ReadJsonElementInt(item, "rating") > 0 || ReadJsonElementInt(item, "Rating") > 0 || ReadJsonElementInt(item, "benchmarkRating") > 0 || ReadJsonElementInt(item, "BenchmarkRating") > 0 || ReadJsonElementInt(item, "score") > 0 || ReadJsonElementInt(item, "Score") > 0 || !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "benchmarkedUtc")) || !string.IsNullOrWhiteSpace(ReadJsonElementString(item, "BenchmarkedUtc"))) && (!requireId || hasId);
	}

	private static string ReadJsonElementString(JsonElement item, string name)
	{
		if (!TryGetMasterJsonProperty(item, name, out var value))
		{
			return "";
		}
		if (value.ValueKind == JsonValueKind.String)
		{
			return value.GetString() ?? "";
		}
		if (value.ValueKind == JsonValueKind.Number || value.ValueKind == JsonValueKind.True || value.ValueKind == JsonValueKind.False)
		{
			return value.ToString();
		}
		return "";
	}

	private static int ReadJsonElementInt(JsonElement item, string name)
	{
		if (!TryGetMasterJsonProperty(item, name, out var value))
		{
			return 0;
		}
		if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out var integer))
		{
			return integer;
		}
		return (value.ValueKind == JsonValueKind.String && int.TryParse(value.GetString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out integer)) ? integer : 0;
	}

	private static double ReadJsonElementDouble(JsonElement item, string name)
	{
		if (!TryGetMasterJsonProperty(item, name, out var value))
		{
			return 0.0;
		}
		if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out var number))
		{
			return number;
		}
		return (value.ValueKind == JsonValueKind.String && double.TryParse(value.GetString(), NumberStyles.Float, CultureInfo.InvariantCulture, out number)) ? number : 0.0;
	}

	private static bool TryGetJsonArrayProperty(JsonElement element, string name, out JsonElement value)
	{
		value = default(JsonElement);
		if (element.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		foreach (JsonProperty property in element.EnumerateObject())
		{
			if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase) && property.Value.ValueKind == JsonValueKind.Array)
			{
				value = property.Value;
				return true;
			}
		}
		return false;
	}

	private static string JoinChatUiModelIds(IEnumerable<ChatUiModelInfo> models)
	{
		return string.Join(", ", (from model in models ?? Enumerable.Empty<ChatUiModelInfo>()
			where model != null && !string.IsNullOrWhiteSpace(model.id)
			select model.id.Trim()).Distinct<string>(StringComparer.OrdinalIgnoreCase));
	}

	private List<ChatUiModelInfo> BuildEnabledWebChatModelInfos()
	{
		List<ChatUiModelInfo> models = new List<ChatUiModelInfo>();
		foreach (WebChatModelManagerLoadSettings settings in GetAdvertisableWebChatModelSettings())
		{
			if (settings != null && !string.IsNullOrWhiteSpace(settings.Key))
			{
				string modelId = settings.Key.Trim();
				EnabledWebChatRuntimeModelDescriptor descriptor = ResolveEnabledWebChatRuntimeModelDescriptor(modelId);
				ChatUiModelInfo info = BuildChatModelInfo(modelId);
				info.isAvailable = true;
				info.enabled = settings.Enabled;
				info.supportsImages = info.supportsImages || descriptor.Tags.Any((string tag) => string.Equals(tag, "vision", StringComparison.OrdinalIgnoreCase));
				info.supportsTools = info.supportsTools;
				info.supportsImageGeneration = info.supportsImageGeneration || string.Equals(descriptor.Service, "image_generation", StringComparison.OrdinalIgnoreCase);
				info.supportsAudioGeneration = info.supportsAudioGeneration || string.Equals(descriptor.Service, "audio_generation", StringComparison.OrdinalIgnoreCase);
				info.supportsVideoGeneration = info.supportsVideoGeneration || string.Equals(descriptor.Service, "video_generation", StringComparison.OrdinalIgnoreCase);
				models.Add(info);
			}
		}
		DecorateChatUiModelsWithPolicy(models);
		return models;
	}

	private void DecorateChatUiModelsWithPolicy(List<ChatUiModelInfo> models)
	{
		if (models == null)
		{
			return;
		}
		foreach (ChatUiModelInfo model in models)
		{
			if (model != null && !string.IsNullOrWhiteSpace(model.id))
			{
				WebChatModelManagerLoadSettings settings = null;
				bool settingsEnabled = TryGetModelManagerLoadSettings(model.id, out settings) && settings != null && settings.Enabled;
				bool modelEnabled = settingsEnabled || model.web_chat_model_enabled || ChatUiModelStatusImpliesModelEnabled(model) || (model.enabled && !ChatUiModelPolicyLooksApplied(model));
				bool dynamicLoadEnabled = WebChatModelLoadApiEnabled || modelEnabled;
				bool usable = model.isLoaded || dynamicLoadEnabled;
				string disabledReason = (usable ? "" : "Enable this model in Workstation's Models tab, or enable the global web chat model-load API in Diagnostics.");
				model.isAvailable = model.isAvailable || model.isLoaded || modelEnabled || WebChatModelLoadApiEnabled;
				model.enabled = usable;
				model.isEnabled = usable;
				model.disabled = !usable;
				model.dynamicLoadEnabled = dynamicLoadEnabled;
				model.serverDynamicLoadingEnabled = WebChatModelLoadApiEnabled;
				model.web_chat_dynamic_load_enabled = dynamicLoadEnabled;
				model.web_chat_model_load_api_enabled = WebChatModelLoadApiEnabled;
				model.web_chat_model_enabled = modelEnabled;
				model.web_chat_idle_unload_minutes = ((settings == null) ? DefaultWebChatRuntimeModelIdleUnloadMinutes : Math.Max(0, settings.IdleUnloadMinutes));
				model.web_chat_load_disabled_reason = disabledReason;
				model.loadDisabledReason = disabledReason;
				model.status = BuildChatUiModelPolicyStatus(model);
			}
		}
	}

	private static bool ChatUiModelPolicyLooksApplied(ChatUiModelInfo model)
	{
		if (model == null)
		{
			return false;
		}
		string status = model.status ?? "";
		return model.web_chat_model_enabled ||
			model.web_chat_dynamic_load_enabled ||
			model.web_chat_model_load_api_enabled ||
			model.serverDynamicLoadingEnabled ||
			!string.IsNullOrWhiteSpace(model.web_chat_load_disabled_reason) ||
			!string.IsNullOrWhiteSpace(model.loadDisabledReason) ||
			string.Equals(status, "loaded", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(status, "loaded-dynamic", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(status, "dynamic-load-available", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(status, "available", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(status, "disabled", StringComparison.OrdinalIgnoreCase);
	}

	private static bool ChatUiModelStatusImpliesModelEnabled(ChatUiModelInfo model)
	{
		string status = model?.status ?? "";
		return string.Equals(status, "enabled", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(status, "loaded-enabled", StringComparison.OrdinalIgnoreCase);
	}

	private static string BuildChatUiModelPolicyStatus(ChatUiModelInfo model)
	{
		if (model == null)
		{
			return "unknown";
		}
		if (model.isLoaded && model.web_chat_model_enabled)
		{
			return "loaded-enabled";
		}
		if (model.isLoaded && model.dynamicLoadEnabled)
		{
			return "loaded-dynamic";
		}
		if (model.isLoaded)
		{
			return "loaded";
		}
		if (model.web_chat_model_enabled)
		{
			return "enabled";
		}
		if (model.dynamicLoadEnabled || model.serverDynamicLoadingEnabled)
		{
			return "dynamic-load-available";
		}
		if (model.enabled)
		{
			return "available";
		}
		return "disabled";
	}

	private static bool IsChatModelPlaceholder(string model)
	{
		return string.IsNullOrWhiteSpace(model) || string.Equals(model.Trim(), "lm-studio", StringComparison.OrdinalIgnoreCase);
	}

	private bool IsAdvertisableChatUiModelInfo(ChatUiModelInfo model)
	{
		if (model == null || string.IsNullOrWhiteSpace(model.id) || IsChatModelPlaceholder(model.id) || IsLikelyModelArtifactId(model.id))
		{
			return false;
		}
		if (model.supportsImageGeneration || model.supportsAudioGeneration || model.supportsVideoGeneration)
		{
			return true;
		}
		if (!IsEffectiveLocalRuntimeLlmRuntime())
		{
			return !IsLikelyNonChatModelId(model.id);
		}
		if (IsLikelyNonChatModelId(model.id))
		{
			return false;
		}
		if (model.isLoaded || model.enabled || model.dynamicLoadEnabled || model.serverDynamicLoadingEnabled || model.web_chat_dynamic_load_enabled || model.web_chat_model_enabled || model.isAvailable)
		{
			return IsPlausibleLoadableModelIdentifier(model.id);
		}
		return false;
	}

	private static bool IsLikelyModelArtifactId(string modelId)
	{
		if (string.IsNullOrWhiteSpace(modelId))
		{
			return true;
		}
		string id = modelId.Trim().Replace('\\', '/').ToLowerInvariant();
		if (id.EndsWith("/manifest", StringComparison.OrdinalIgnoreCase) || id.EndsWith("/manifest.json", StringComparison.OrdinalIgnoreCase) || id.EndsWith("/config.json", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		switch (id)
		{
		case "api":
		case "auth":
		case "chat":
		case "complete-model":
		case "complete-models":
		case "config":
		case "convert":
		case "data":
		case "download":
		case "load":
		case "manifest":
		case "model":
		case "models":
		case "repository":
		case "runtime":
		case "search":
		case "status":
		case "unload":
			return true;
		default:
			return false;
		}
	}

	private static bool IsPlausibleLoadableModelIdentifier(string modelId)
	{
		if (IsLikelyModelArtifactId(modelId))
		{
			return false;
		}
		string id = modelId.Trim().Replace('\\', '/').ToLowerInvariant();
		if (id.EndsWith(".gguf", StringComparison.OrdinalIgnoreCase) || id.EndsWith(".onnx", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		string[] knownModelTokens = new string[]
		{
			"llama", "qwen", "mistral", "mixtral", "gemma", "phi", "deepseek", "claude", "opus", "gpt", "hermes", "command-r", "glm", "kimi",
			"wan", "ltx", "fastvideo", "lightricks", "hunyuan", "mochi", "stable-diffusion", "sdxl", "flux", "diffusion", "pytorch"
		};
		if (knownModelTokens.Any(token => id.Contains(token)))
		{
			return true;
		}
		if (id.Contains("/") && !id.Contains("/api/") && !id.EndsWith(".json", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		return Regex.IsMatch(id, @"(^|[^a-z0-9])(?:a?\d+(?:\.\d+)?b|[0-9]+x[0-9]+b)([^a-z0-9]|$)", RegexOptions.CultureInvariant);
	}

	private static bool IsLikelyNonChatModelId(string modelId)
	{
		if (string.IsNullOrWhiteSpace(modelId))
		{
			return false;
		}
		string id = modelId.Replace('\\', '/').ToLowerInvariant();
		return id.Contains("text-to-video") || id.Contains("image-to-video") || id.Contains("t2v") || id.Contains("i2v") || id.Contains("v2v") || id.Contains("wan2") || id.Contains("wan-") || id.Contains("hunyuanvideo") || id.Contains("ltx-video") || id.Contains("ltxv") || id.Contains("mochi") || id.Contains("motifv") || id.Contains("highnoise") || id.Contains("lownoise") || id.Contains("text-to-image") || id.Contains("t2i") || id.Contains("stable-diffusion") || id.Contains("sdxl") || id.Contains("flux") || id.Contains("qwen-image") || id.Contains("imagegen") || id.Contains("diffusion") || id.Contains("unet") || id.Contains("nomic-embed") || id.Contains("bge-") || id.Contains("gte-") || id.Contains("e5-") || id.Contains("embed") || id.Contains("whisper") || id.Contains("wav2vec") || id.Contains("musicgen");
	}

	private string TryRefreshAndGetFirstLoadedChatModel()
	{
		try
		{
			foreach (string url in GetLmStudioModelListUrls())
			{
				using CancellationTokenSource timeoutCts = new CancellationTokenSource(ChatModelListTimeout);
				using HttpResponseMessage response = _httpClient.GetAsync(url, timeoutCts.Token).GetAwaiter().GetResult();
				if (!response.IsSuccessStatusCode)
				{
					continue;
				}
				string responseBody = ((response.Content == null) ? "" : response.Content.ReadAsStringAsync().GetAwaiter().GetResult());
				List<ChatUiModelInfo> models = ExtractModelInfos(responseBody);
				if (models.Count != 0)
				{
					CacheChatModelInfos(models);
					ChatUiModelInfo firstLoadedModel = models.FirstOrDefault((ChatUiModelInfo model) => model != null && model.isLoaded && !IsChatModelPlaceholder(model.id));
					if (firstLoadedModel != null && !string.IsNullOrWhiteSpace(firstLoadedModel.id))
					{
						return firstLoadedModel.id;
					}
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Could not auto-resolve default model: " + ex.Message);
		}
		return null;
	}

	private string HandleChatServicesRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				canEdit = IsDatabaseAdministrator(connection, request),
				services = BuildChatServiceCatalog(permissions)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Service catalog load failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleMagicMissionsGetRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string missionId = (GetQueryParameter(request, "missionId") ?? GetQueryParameter(request, "id") ?? "").Trim();
			if (!string.IsNullOrWhiteSpace(missionId))
			{
				MagicMissionRecord mission = _sockJackDml.FindMission(ownerKey, missionId);
				if (mission == null)
				{
					return BuildJsonError(request, 404, "Not Found", "Mission not found: " + missionId);
				}
				return JsonSerializer.Serialize(new
				{
					ok = true,
					ownerKey = ownerKey,
					mission = mission,
