	private string FirstMagicString(JsonElement root, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			string value = ExtractStringProperty(root, name);
			if (!string.IsNullOrWhiteSpace(value))
			{
				return value;
			}
		}
		return "";
	}

	private List<string> ReadMagicStringList(JsonElement root, params string[] names)
	{
		List<string> values = new List<string>();
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (root.ValueKind != JsonValueKind.Object || !root.TryGetProperty(name, out var element))
			{
				continue;
			}
			if (element.ValueKind == JsonValueKind.Array)
			{
				foreach (JsonElement item in element.EnumerateArray())
				{
					string text = ExtractJsonString(item);
					if (!string.IsNullOrWhiteSpace(text))
					{
						values.Add(text.Trim());
					}
				}
				continue;
			}
			string text2 = ExtractJsonString(element);
			if (string.IsNullOrWhiteSpace(text2))
			{
				continue;
			}
			string[] array2 = text2.Split(new char[4] { ',', ';', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
			foreach (string part in array2)
			{
				if (!string.IsNullOrWhiteSpace(part))
				{
					values.Add(part.Trim());
				}
			}
		}
		return values.Distinct<string>(StringComparer.OrdinalIgnoreCase).Take(64).ToList();
	}

	private bool ReadMagicBool(JsonElement root, bool fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty(name, out var element))
			{
				return ReadJsonBool(element, fallback);
			}
		}
		return fallback;
	}

	private int ReadMagicInt(JsonElement root, int fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty(name, out var element))
			{
				return ReadJsonInt(element, fallback);
			}
		}
		return fallback;
	}

