	private object BuildHardwareAttestationPayload(NetworkConnection connection, HttpRequest request)
	{
		LmVsProxyServerProfile profile = GetServerBrowserProfile();
		string connectHost = ResolveServerBrowserConnectHost(profile, request);
	string publicUrl = BuildServerBrowserPublicUrl(connectHost, _chatServerPort);
	List<ChatUiModelInfo> modelCapabilities = BuildServerBrowserModelCapabilities(profile);
	string advertisedModels = JoinChatUiModelIds(modelCapabilities);
	TrustAbuseSummarySnapshot trust = BuildTrustAbuseSummary(NormalizeTrustOwnerKey("", profile.OwnerUserName), profile.ServerId, profile.ServerName, connectHost);
		DateTimeOffset now = DateTimeOffset.UtcNow;
		object runtimeHardware;
		lock (_serverHardwareMetricsLock)
		{
			runtimeHardware = new
			{
				cpu = BuildServerHardwareCpuMetric(now),
				ram = BuildServerHardwareRamMetric(),
				gpu = BuildServerHardwareGpuMetric(now),
				network = BuildServerHardwareNetworkMetric(now),
				io = BuildServerHardwareIoMetric(now)
			};
		}
		Dictionary<string, object> claims = new Dictionary<string, object>(StringComparer.Ordinal)
		{
			["version"] = "socketjack.hardware.attestation.v1",
			["serverId"] = profile.ServerId ?? "",
			["ownerUserName"] = profile.OwnerUserName ?? "",
			["serverName"] = profile.ServerName ?? "",
			["publicHost"] = profile.PublicHost ?? "",
			["connectHost"] = connectHost ?? "",
			["publicUrl"] = publicUrl ?? "",
			["natMode"] = (string.IsNullOrWhiteSpace(profile.PublicHost) ? "local_or_reverse_proxy" : "public_host"),
			["gpuName"] = profile.GpuName ?? "",
			["availableVram"] = profile.AvailableVram ?? "",
			["gpuAvailable"] = profile.GpuAvailable ?? "",
			["cpuName"] = profile.CpuName ?? "",
			["cpuAvailable"] = profile.CpuAvailable ?? "",
			["ramAvailable"] = profile.RamAvailable ?? "",
			["storageAvailable"] = profile.StorageAvailable ?? "",
			["availableModels"] = advertisedModels,
			["modelCount"] = modelCapabilities?.Count ?? 0,
			["modelBenchmarksJson"] = NormalizeChatUiModelBenchmarksJson(profile.ModelBenchmarksJson),
			["uptimeSeconds"] = Math.Max(0L, profile.UptimeSeconds),
			["runtimeHardware"] = runtimeHardware,
			["trustScore"] = trust.ReputationScore,
			["trustTier"] = trust.ReputationTier ?? "",
			["hostVerificationStatus"] = trust.HostVerificationStatus ?? "",
			["hostVerified"] = trust.HostVerified,
			["generatedUtc"] = now.ToString("O")
		};
		string claimsJson = JsonSerializer.Serialize(claims);
		string fingerprint = ComputeSha256Hex(claimsJson);
		string signatureTrust;
		string signature = ComputeHardwareAttestationSignature(claimsJson, profile, out signatureTrust);
		return new
		{
			algorithm = "HMAC-SHA256",
			fingerprint = fingerprint,
			signature = signature,
			signatureTrust = signatureTrust,
			signed = !string.IsNullOrWhiteSpace(signature),
			claims = DeserializeJsonElement(claimsJson, "{}")
		};
	}

	private string ComputeHardwareAttestationSignature(string claimsJson, LmVsProxyServerProfile profile, out string trust)
	{
		string secret = Environment.GetEnvironmentVariable("SOCKETJACK_ATTESTATION_SECRET") ?? Environment.GetEnvironmentVariable("SOCKETJACK_HOST_ATTESTATION_SECRET") ?? "";
		trust = (string.IsNullOrWhiteSpace(secret) ? "local_ephemeral" : "configured_secret");
		if (string.IsNullOrWhiteSpace(secret))
		{
			string seed = Environment.MachineName + "|" + Environment.UserName + "|" + profile?.ServerId + "|" + profile?.OwnerUserName;
			secret = ComputeSha256Hex(seed);
		}
		using HMACSHA256 hmac = new HMACSHA256(Encoding.UTF8.GetBytes(secret));
		byte[] signature = hmac.ComputeHash(Encoding.UTF8.GetBytes(claimsJson ?? ""));
		return Convert.ToBase64String(signature);
	}

	private static string ComputeSha256Hex(string value)
	{
		using SHA256 sha = SHA256.Create();
		byte[] bytes = sha.ComputeHash(Encoding.UTF8.GetBytes(value ?? ""));
		StringBuilder builder = new StringBuilder(bytes.Length * 2);
		byte[] array = bytes;
		foreach (byte b in array)
		{
			builder.Append(b.ToString("x2", CultureInfo.InvariantCulture));
		}
		return builder.ToString();
	}

