	private string BuildObservabilityPrometheusText(ObservabilitySnapshot snapshot)
	{
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("# HELP socketjack_uptime_seconds LmVsProxy observability uptime in seconds.");
		sb.AppendLine("# TYPE socketjack_uptime_seconds gauge");
		sb.Append("socketjack_uptime_seconds ").AppendLine(FormatPrometheusNumber(snapshot.UptimeSeconds));
		sb.AppendLine("# HELP socketjack_health_score SocketJack operational health score from 0 to 100.");
		sb.AppendLine("# TYPE socketjack_health_score gauge");
		sb.Append("socketjack_health_score ").AppendLine(FormatPrometheusNumber(snapshot.HealthScore));
		sb.AppendLine("# TYPE socketjack_requests_total counter");
		sb.Append("socketjack_requests_total ").AppendLine(snapshot.TotalRequests.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_request_failures_total counter");
		sb.Append("socketjack_request_failures_total ").AppendLine(snapshot.FailedRequests.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_request_latency_ms_average gauge");
		sb.Append("socketjack_request_latency_ms_average ").AppendLine(FormatPrometheusNumber(snapshot.AverageLatencyMs));
		sb.AppendLine("# TYPE socketjack_tokens_total counter");
		sb.Append("socketjack_tokens_total ").AppendLine(snapshot.TotalTokens.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_active_prompts gauge");
		sb.Append("socketjack_active_prompts ").AppendLine(snapshot.ActivePromptSessions.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_prompt_sessions_total counter");
		sb.Append("socketjack_prompt_sessions_total ").AppendLine(snapshot.TotalPromptSessions.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_chat_sessions gauge");
		sb.Append("socketjack_chat_sessions ").AppendLine(snapshot.ChatSessions.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_trust_open_cases gauge");
		sb.Append("socketjack_trust_open_cases ").AppendLine(snapshot.TrustOpenCases.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_pending_admin_requests gauge");
		int pending = snapshot.PendingFilesystemRequests + snapshot.PendingTerminalRequests + snapshot.PendingTokenRateRequests + snapshot.PendingRegistrationRequests;
		sb.Append("socketjack_pending_admin_requests ").AppendLine(pending.ToString(CultureInfo.InvariantCulture));
		sb.AppendLine("# TYPE socketjack_security_score gauge");
		sb.Append("socketjack_security_score ").AppendLine(FormatPrometheusNumber(ReadObjectDouble(snapshot.Security, "securityScore", 0.0)));
		sb.AppendLine("# TYPE socketjack_marketplace_score gauge");
		sb.Append("socketjack_marketplace_score ").AppendLine(FormatPrometheusNumber(ReadObjectDouble(snapshot.Marketplace, "marketplaceScore", 0.0)));
		sb.AppendLine("# TYPE socketjack_developer_workflow_score gauge");
		sb.Append("socketjack_developer_workflow_score ").AppendLine(FormatPrometheusNumber(ReadObjectDouble(snapshot.DeveloperWorkflow, "workflowScore", 0.0)));
		sb.AppendLine("# TYPE socketjack_route_requests_total counter");
		sb.AppendLine("# TYPE socketjack_route_failures_total counter");
		sb.AppendLine("# TYPE socketjack_route_latency_ms_average gauge");
		foreach (ObservabilityRouteSnapshot route in snapshot.Routes)
		{
			string labels = "{method=\"" + EscapePrometheusLabel(route.Method) + "\",route=\"" + EscapePrometheusLabel(route.Route) + "\",category=\"" + EscapePrometheusLabel(route.Category) + "\"}";
			sb.Append("socketjack_route_requests_total").Append(labels).Append(' ')
				.AppendLine(route.Count.ToString(CultureInfo.InvariantCulture));
			sb.Append("socketjack_route_failures_total").Append(labels).Append(' ')
				.AppendLine(route.Failures.ToString(CultureInfo.InvariantCulture));
			sb.Append("socketjack_route_latency_ms_average").Append(labels).Append(' ')
				.AppendLine(FormatPrometheusNumber(route.AverageLatencyMs));
		}
		return sb.ToString();
	}

	private static string FormatPrometheusNumber(double value)
	{
		if (double.IsNaN(value) || double.IsInfinity(value))
		{
			return "0";
		}
		return value.ToString("0.###", CultureInfo.InvariantCulture);
	}

	private static string EscapePrometheusLabel(string value)
	{
		return (value ?? "").Replace("\\", "\\\\").Replace("\"", "\\\"").Replace("\r", "\\r")
			.Replace("\n", "\\n");
	}

