	private string HandleServerLocationLookupRequest(HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string target = (GetQueryParameter(request, "target") ?? GetQueryParameter(request, "host") ?? GetQueryParameter(request, "ip") ?? "").Trim();
			if (string.IsNullOrWhiteSpace(target))
			{
				return BuildJsonError(request, 400, "Bad Request", "A target, host, or ip query value is required.");
			}
			ServerLocationLookupResult location = LookupServerLocation(target);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				location = location
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Server Location] Lookup failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private ServerLocationLookupResult LookupServerLocation(string rawTarget)
	{
		if (!TryNormalizeServerLocationTarget(rawTarget, out var cacheKey, out var lookupIp, out var normalizedHost, out var privateAddress, out var error))
		{
			return new ServerLocationLookupResult
			{
				found = false,
				input = (rawTarget ?? ""),
				target = (normalizedHost ?? ""),
				ip = (lookupIp ?? ""),
				privateAddress = privateAddress,
				error = (error ?? "Location lookup is not available for this target."),
				source = "local",
				updatedUtc = DateTimeOffset.UtcNow.ToString("O")
			};
		}
		DateTimeOffset now = DateTimeOffset.UtcNow;
		lock (_serverLocationLookupLock)
		{
			if (_serverLocationLookupCache.TryGetValue(cacheKey, out var cached) && cached.ExpiresUtc > now && cached.Result != null)
			{
				ServerLocationLookupResult result = CopyServerLocationLookupResult(cached.Result);
				result.cached = true;
				return result;
			}
			TimeSpan wait = TimeSpan.FromMilliseconds(1100.0) - (now - _lastServerLocationLookupUtc);
			if (wait > TimeSpan.Zero)
			{
				Thread.Sleep(wait);
			}
			ServerLocationLookupResult lookedUp = QueryServerLocationApi(rawTarget, normalizedHost, lookupIp);
			_lastServerLocationLookupUtc = DateTimeOffset.UtcNow;
			_serverLocationLookupCache[cacheKey] = new ServerLocationLookupCacheEntry
			{
				ExpiresUtc = (lookedUp.found ? _lastServerLocationLookupUtc.AddHours(12.0) : _lastServerLocationLookupUtc.AddMinutes(15.0)),
				Result = CopyServerLocationLookupResult(lookedUp)
			};
			return lookedUp;
		}
	}

	private ServerLocationLookupResult QueryServerLocationApi(string rawTarget, string normalizedHost, string lookupIp)
	{
		ServerLocationLookupResult result = new ServerLocationLookupResult
		{
			found = false,
			input = (rawTarget ?? ""),
			target = (normalizedHost ?? ""),
			ip = (lookupIp ?? ""),
			source = "ipwho.is",
			updatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
		try
		{
			using CancellationTokenSource timeout = new CancellationTokenSource(TimeSpan.FromSeconds(6.0));
			using HttpRequestMessage lookupRequest = new HttpRequestMessage(HttpMethod.Get, "https://ipwho.is/" + Uri.EscapeDataString(lookupIp ?? ""));
			lookupRequest.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-LmVsProxy/1.0");
			using HttpResponseMessage response = _httpClient.SendAsync(lookupRequest, HttpCompletionOption.ResponseHeadersRead, timeout.Token).GetAwaiter().GetResult();
			string body = response.Content.ReadAsStringAsync().GetAwaiter().GetResult();
			if (!response.IsSuccessStatusCode || string.IsNullOrWhiteSpace(body))
			{
				result.error = "The location API did not return a usable response.";
				return result;
			}
			using JsonDocument document = JsonDocument.Parse(body);
			JsonElement root = document.RootElement;
			if (root.TryGetProperty("success", out var successElement) && successElement.ValueKind != JsonValueKind.True && (successElement.ValueKind != JsonValueKind.String || !string.Equals(successElement.GetString(), "true", StringComparison.OrdinalIgnoreCase)))
			{
				result.error = ExtractStringProperty(root, "message") ?? ExtractStringProperty(root, "error") ?? "The location API could not resolve this server.";
				return result;
			}
			string city = ExtractStringProperty(root, "city") ?? "";
			string region = ExtractStringProperty(root, "region") ?? "";
			string country = ExtractStringProperty(root, "country") ?? "";
			string countryCode = ExtractStringProperty(root, "country_code") ?? "";
			string timezone = "";
			if (root.TryGetProperty("timezone", out var timezoneElement))
			{
				timezone = ((timezoneElement.ValueKind == JsonValueKind.String) ? timezoneElement.GetString() : (ExtractStringProperty(timezoneElement, "id") ?? ""));
			}
			result.found = true;
			result.ip = ExtractStringProperty(root, "ip") ?? lookupIp ?? "";
			result.city = city;
			result.region = region;
			result.country = country;
			result.countryCode = countryCode;
			result.timezone = timezone;
			result.isp = ExtractStringProperty(root, "connection") ?? "";
			if (root.TryGetProperty("connection", out var connection) && connection.ValueKind == JsonValueKind.Object)
			{
				result.isp = ExtractStringProperty(connection, "isp") ?? ExtractStringProperty(connection, "org") ?? result.isp;
			}
			if (root.TryGetProperty("latitude", out var latitude) && latitude.TryGetDouble(out var lat))
			{
				result.latitude = lat;
			}
			if (root.TryGetProperty("longitude", out var longitude) && longitude.TryGetDouble(out var lon))
			{
				result.longitude = lon;
			}
			result.label = BuildServerLocationLabel(city, region, country);
			return result;
		}
		catch (Exception ex)
		{
			result.error = ex.Message;
			return result;
		}
	}

	private static string BuildServerLocationLabel(string city, string region, string country)
	{
		List<string> parts = new List<string>();
		if (!string.IsNullOrWhiteSpace(city))
		{
			parts.Add(city.Trim());
		}
		if (!string.IsNullOrWhiteSpace(region) && !parts.Any((string part) => string.Equals(part, region.Trim(), StringComparison.OrdinalIgnoreCase)))
		{
			parts.Add(region.Trim());
		}
		if (!string.IsNullOrWhiteSpace(country) && !parts.Any((string part) => string.Equals(part, country.Trim(), StringComparison.OrdinalIgnoreCase)))
		{
			parts.Add(country.Trim());
		}
		return (parts.Count == 0) ? "" : string.Join(", ", parts);
	}

	private static ServerLocationLookupResult CopyServerLocationLookupResult(ServerLocationLookupResult source)
	{
		if (source == null)
		{
			return null;
		}
		return new ServerLocationLookupResult
		{
			found = source.found,
			cached = source.cached,
			privateAddress = source.privateAddress,
			input = source.input,
			target = source.target,
			ip = source.ip,
			city = source.city,
			region = source.region,
			country = source.country,
			countryCode = source.countryCode,
			timezone = source.timezone,
			isp = source.isp,
			label = source.label,
			source = source.source,
			error = source.error,
			updatedUtc = source.updatedUtc,
			latitude = source.latitude,
			longitude = source.longitude
		};
	}

	private static bool TryNormalizeServerLocationTarget(string rawTarget, out string cacheKey, out string lookupIp, out string normalizedHost, out bool privateAddress, out string error)
	{
		cacheKey = "";
		lookupIp = "";
		normalizedHost = "";
		privateAddress = false;
		error = "";
		string host = (normalizedHost = ExtractServerLocationHost(rawTarget));
		if (string.IsNullOrWhiteSpace(host))
		{
			error = "The target does not contain a usable host.";
			return false;
		}
		if (host.Equals("localhost", StringComparison.OrdinalIgnoreCase))
		{
			privateAddress = true;
			error = "Localhost does not have a public location.";
			return false;
		}
		if (IPAddress.TryParse(host, out var address))
		{
			if (IsPrivateOrReservedIpAddress(address))
			{
				privateAddress = true;
				lookupIp = address.ToString();
				error = "Private or local addresses do not have a public location.";
				return false;
			}
			lookupIp = address.ToString();
			cacheKey = lookupIp;
			return true;
		}
		if (host.Length > 253 || host.Any(char.IsWhiteSpace))
		{
			error = "The host name is not valid for location lookup.";
			return false;
		}
		try
		{
			IPAddress[] addresses = Dns.GetHostAddresses(host);
			IPAddress[] array = addresses;
			foreach (IPAddress candidate in array)
			{
				if (!IsPrivateOrReservedIpAddress(candidate))
				{
					lookupIp = candidate.ToString();
					cacheKey = host.ToLowerInvariant() + "|" + lookupIp;
					return true;
				}
			}
			privateAddress = addresses.Length != 0;
			error = (privateAddress ? "The host resolves only to private or local addresses." : "The host did not resolve to an IP address.");
			return false;
		}
		catch (Exception ex)
		{
			error = "DNS resolution failed: " + ex.Message;
			return false;
		}
	}

	private static string ExtractServerLocationHost(string rawTarget)
	{
		string target = (rawTarget ?? "").Trim();
		if (string.IsNullOrWhiteSpace(target))
		{
			return "";
		}
		if (Uri.TryCreate(target, UriKind.Absolute, out Uri absolute) && (absolute.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) || absolute.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)))
		{
			return (absolute.Host ?? "").Trim().Trim('[', ']');
		}
		target = target.Trim();
		int slashIndex = target.IndexOfAny(new char[4] { '/', '\\', '?', '#' });
		if (slashIndex >= 0)
		{
			target = target.Substring(0, slashIndex);
		}
		int atIndex = target.LastIndexOf('@');
		if (atIndex >= 0)
		{
			target = target.Substring(atIndex + 1);
		}
		if (target.StartsWith("[", StringComparison.Ordinal) && target.Contains("]"))
		{
			int end = target.IndexOf(']');
			return target.Substring(1, Math.Max(0, end - 1)).Trim();
		}
		int colonIndex = target.LastIndexOf(':');
		if (colonIndex > 0 && target.IndexOf(':') == colonIndex)
		{
			target = target.Substring(0, colonIndex);
		}
		return target.Trim().Trim('[', ']');
	}

	private static bool IsPrivateOrReservedIpAddress(IPAddress address)
	{
		if (address == null)
		{
			return true;
		}
		if (IPAddress.IsLoopback(address))
		{
			return true;
		}
		if (address.IsIPv4MappedToIPv6)
		{
			address = address.MapToIPv4();
		}
		if (address.AddressFamily == AddressFamily.InterNetwork)
		{
			byte[] bytes = address.GetAddressBytes();
			if (bytes[0] == 0 || bytes[0] == 10 || bytes[0] == 127)
			{
				return true;
			}
			if (bytes[0] == 100 && bytes[1] >= 64 && bytes[1] <= 127)
			{
				return true;
			}
			if (bytes[0] == 169 && bytes[1] == 254)
			{
				return true;
			}
			if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31)
			{
				return true;
			}
			if (bytes[0] == 192 && bytes[1] == 168)
			{
				return true;
			}
			if (bytes[0] == 198 && (bytes[1] == 18 || bytes[1] == 19))
			{
				return true;
			}
			if (bytes[0] >= 224)
			{
				return true;
			}
		}
		else if (address.AddressFamily == AddressFamily.InterNetworkV6)
		{
			byte[] bytes2 = address.GetAddressBytes();
			if (address.Equals(IPAddress.IPv6None) || address.Equals(IPAddress.IPv6Any) || address.IsIPv6LinkLocal || address.IsIPv6Multicast || address.IsIPv6SiteLocal)
			{
				return true;
			}
			if ((bytes2[0] & 0xFE) == 252)
			{
				return true;
			}
		}
		return false;
	}

	private string HandleMasterServerRegistrationRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string body = request?.Body ?? "{}";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				if (document.RootElement.ValueKind != JsonValueKind.Object)
				{
					return BuildJsonError(request, 400, "Bad Request", "Server registration payload must be a JSON object.");
				}
				string ownerKeyHash = BuildMasterServerOwnerKeyHash(ExtractMasterServerOwnerKey(request, document.RootElement));
				JsonElement entry = AttachMasterServerOwnerKeyHash(document.RootElement, ownerKeyHash);
				string key = BuildMasterServerEntryKey(entry);
				bool removeEntry = IsMasterServerOfflineRegistration(entry);
				bool exactDuplicateIgnored = false;
				lock (_masterServerListLock)
				{
					if (!removeEntry && IsExactDuplicateMasterServerEntry(entry))
					{
						exactDuplicateIgnored = true;
					}
					if (!string.IsNullOrWhiteSpace(key) || !string.IsNullOrWhiteSpace(ownerKeyHash))
					{
						int i = _masterServerEntries.Count - 1;
						while (i >= 0 && !exactDuplicateIgnored)
						{
							if (MasterServerEntryMatchesPublishedSlot(_masterServerEntries[i], entry, key, ownerKeyHash))
							{
								_masterServerEntries.RemoveAt(i);
							}
							i--;
						}
					}
					if (!removeEntry && !exactDuplicateIgnored)
					{
						_masterServerEntries.Insert(0, entry);
					}
				}
				if (exactDuplicateIgnored)
				{
					LogMessage("[Master List] Ignored exact duplicate server registration.");
				}
				else
				{
					RecordObservabilityEvent("marketplace", "server registration", removeEntry ? "offline" : "published", key, GetChatSessionOwnerKey(connection, request), "/api/lmvsproxy/servers", 0L);
				}
			}
			return HandleMasterServerListRequest(connection, request);
		}
		catch (Exception ex)
		{
			LogMessage("[Master List] Registration failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

