	private string HandleCopilotDuplicatorSaveRequest(HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string body = request?.Body ?? "{}";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				if (root.ValueKind != JsonValueKind.Object)
				{
					return BuildJsonError(request, 400, "Bad Request", "Copilot duplicator payload must be a JSON object.");
				}
				string action = ExtractStringProperty(root, "action") ?? "";
				if (action.Equals("clear", StringComparison.OrdinalIgnoreCase) || action.Equals("local", StringComparison.OrdinalIgnoreCase))
				{
					ClearRemoteModelServerSelection();
					LogMessage("[Copilot Duplicator] Cleared remote model selection; localhost:" + CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture) + " will use " + GetLocalModelRuntimeDisplayName() + ".");
					return JsonSerializer.Serialize(BuildCopilotDuplicatorPayload());
				}
				LmVsProxyRemoteModelServerSelection lmVsProxyRemoteModelServerSelection = new LmVsProxyRemoteModelServerSelection();
				lmVsProxyRemoteModelServerSelection.Enabled = true;
				lmVsProxyRemoteModelServerSelection.ServerId = ReadCopilotJsonString(root, "serverId", "id");
				lmVsProxyRemoteModelServerSelection.ServerName = ReadCopilotJsonString(root, "serverName", "title", "displayName", "name");
				lmVsProxyRemoteModelServerSelection.OwnerUserName = ReadCopilotJsonString(root, "ownerUserName", "ownerUsername", "serverOwnerUserName", "serverOwnerUsername");
				lmVsProxyRemoteModelServerSelection.ExternalIp = ReadCopilotJsonString(root, "externalIp", "connectHost", "publicHost", "host");
				lmVsProxyRemoteModelServerSelection.HardwareSummary = ReadCopilotJsonString(root, "hardwareSummary", "hardware");
				lmVsProxyRemoteModelServerSelection.Endpoint = ReadCopilotJsonString(root, "endpoint", "serverEndpoint", "effectiveEndpoint", "publicEndpoint", "proxyEndpoint");
				lmVsProxyRemoteModelServerSelection.OpenAiBaseUrl = ReadCopilotJsonString(root, "openAiBaseUrl", "openAiEndpoint", "baseUrl", "modelAccessUrl", "modelApiBaseUrl", "customUrl", "customURL", "vsProxyEndpoint", "proxyEndpoint");
				lmVsProxyRemoteModelServerSelection.SelectedModel = ReadCopilotJsonString(root, "model", "selectedModel", "modelId", "selectedModelId", "modelName", "modelDisplayName");
				lmVsProxyRemoteModelServerSelection.AuthorizationBearerToken = FirstNonEmpty(ReadCopilotJsonString(root, "authorizationBearerToken", "accessToken", "access_token", "socketJackAuthToken"), ExtractBearerToken(request));
				lmVsProxyRemoteModelServerSelection.SourceJson = root.GetRawText();
				lmVsProxyRemoteModelServerSelection.LeaseId = ReadCopilotJsonString(root, "leaseId");
				lmVsProxyRemoteModelServerSelection.LeaseRequired = ReadCopilotJsonBool(root, false, "leaseRequired", "requiresPayment", "paymentRequired");
				lmVsProxyRemoteModelServerSelection.LeaseStatus = ReadCopilotJsonString(root, "leaseStatus");
				lmVsProxyRemoteModelServerSelection.LeasePaymentStatus = ReadCopilotJsonString(root, "leasePaymentStatus", "paymentStatus");
				lmVsProxyRemoteModelServerSelection.LeaseStartedUtc = ReadCopilotJsonString(root, "leaseStartedUtc", "startedUtc");
				lmVsProxyRemoteModelServerSelection.LeaseRenewedUtc = ReadCopilotJsonString(root, "leaseRenewedUtc", "renewedUtc");
				lmVsProxyRemoteModelServerSelection.LeaseExpiresUtc = ReadCopilotJsonString(root, "leaseExpiresUtc", "expiresUtc");
				lmVsProxyRemoteModelServerSelection.LeaseSource = ReadCopilotJsonString(root, "leaseSource");
				lmVsProxyRemoteModelServerSelection.LeaseMode = ReadCopilotJsonString(root, "leaseMode");
				lmVsProxyRemoteModelServerSelection.SelectedUtc = DateTimeOffset.UtcNow.ToString("O");
				LmVsProxyRemoteModelServerSelection selection = lmVsProxyRemoteModelServerSelection;
				selection.Normalize();
				ApplyCopilotLeaseDefaults(selection);
				if (!selection.Enabled)
				{
					return BuildJsonError(request, 400, "Bad Request", "A valid http/https OpenAI-compatible base URL is required.");
				}
				ConfigureRemoteModelServerSelection(selection);
				LogMessage("[Copilot Duplicator] Selected " + ((selection.ServerName.Length == 0) ? selection.OpenAiBaseUrl : selection.ServerName) + " -> " + selection.OpenAiBaseUrl + "; lease=" + selection.LeaseStatus + ".");
			}
			return JsonSerializer.Serialize(BuildCopilotDuplicatorPayload());
		}
		catch (JsonException ex)
		{
			return BuildJsonError(request, 400, "Bad Request", "Invalid JSON: " + ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[Copilot Duplicator] Selection update failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private string HandleCopilotDuplicatorLeaseRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!IsLocalAdmin(connection, request))
		{
			return BuildLocalAdminOnlyJsonError(request, "Lease state changes are local-admin only.");
		}
		try
		{
			string body = request?.Body ?? "{}";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				if (root.ValueKind != JsonValueKind.Object)
				{
					return BuildJsonError(request, 400, "Bad Request", "Lease payload must be a JSON object.");
				}
				LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
				if (selection == null || !selection.Enabled)
				{
					return BuildJsonError(request, 409, "Conflict", "Select a remote Copilot server before updating lease state.");
				}
				string action = ReadCopilotJsonString(root, "action");
				if (string.IsNullOrWhiteSpace(action))
				{
					action = "renew";
				}
				action = action.Trim().ToLowerInvariant().Replace(' ', '_')
					.Replace('-', '_');
				DateTimeOffset now = DateTimeOffset.UtcNow;
				long minutes = Math.Max(1L, ReadCopilotJsonLong(root, 60L, "minutes", "leaseMinutes", "durationMinutes"));
				string suppliedLeaseId = ReadCopilotJsonString(root, "leaseId", "id");
				if (!string.IsNullOrWhiteSpace(suppliedLeaseId))
				{
					selection.LeaseId = suppliedLeaseId;
				}
				if (string.IsNullOrWhiteSpace(selection.LeaseId))
				{
					selection.LeaseId = BuildCopilotLeaseId(selection);
				}
				if (ReadCopilotJsonBool(root, selection.LeaseRequired, "leaseRequired", "requiresPayment", "paymentRequired"))
				{
					selection.LeaseRequired = true;
				}
				switch (action)
				{
				default:
					if (!(action == "expired"))
					{
						if (action == "clear")
						{
							selection.LeaseId = "";
							selection.LeaseStatus = (selection.LeaseRequired ? "pending_payment" : "active");
							selection.LeasePaymentStatus = (selection.LeaseRequired ? "payment_required" : "not_required");
							selection.LeaseStartedUtc = "";
							selection.LeaseRenewedUtc = "";
							selection.LeaseExpiresUtc = "";
							break;
						}
						selection.LeaseStatus = "active";
						selection.LeasePaymentStatus = (selection.LeaseRequired ? FirstNonEmpty(ReadCopilotJsonString(root, "leasePaymentStatus", "paymentStatus"), "paid") : "not_required");
						if (string.IsNullOrWhiteSpace(selection.LeaseStartedUtc))
						{
							selection.LeaseStartedUtc = now.ToString("O");
						}
						selection.LeaseRenewedUtc = now.ToString("O");
						selection.LeaseExpiresUtc = now.AddMinutes(minutes).ToString("O");
						break;
					}
					goto case "cancel";
				case "cancel":
				case "end":
				case "expire":
					selection.LeaseStatus = ((action == "cancel") ? "canceled" : "expired");
					selection.LeaseExpiresUtc = now.ToString("O");
					selection.LeaseRenewedUtc = now.ToString("O");
					break;
				}
				selection.LeaseSource = FirstNonEmpty(ReadCopilotJsonString(root, "leaseSource"), selection.LeaseSource, "local-admin");
				selection.LeaseMode = "local-model-illusion";
				ApplyCopilotLeaseDefaults(selection);
				ConfigureRemoteModelServerSelection(selection);
				RecordObservabilityEvent("marketplace", "copilot lease", selection.LeaseStatus, selection.LeaseId, GetChatSessionOwnerKey(connection, request), "/api/copilot-duplicator/lease", 0L);
			}
			return JsonSerializer.Serialize(BuildCopilotDuplicatorPayload());
		}
		catch (JsonException ex)
		{
			return BuildJsonError(request, 400, "Bad Request", "Invalid JSON: " + ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[Copilot Duplicator] Lease update failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private object BuildCopilotDuplicatorPayload()
	{
		LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
		string localBaseUrl = BuildLocalLmStudioBaseUrl();
		object leaseState = BuildCopilotDuplicatorLeasePayload(selection);
		string leaseBlockReason;
		bool routeRemote = ShouldRouteCopilotToRemote(selection, out leaseBlockReason);
		string activeBaseUrl = (routeRemote ? selection.OpenAiBaseUrl : localBaseUrl);
		string localEndpoint = "http://localhost:" + CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture) + "/v1/chat/completions";
		return new
		{
			ok = true,
			enabled = CopilotDuplicatorEnabled,
			listening = IsCopilotDuplicatorListening,
			port = CopilotDuplicatorPort,
			localEndpoint = localEndpoint,
			activeUpstream = activeBaseUrl,
			usingRemoteServer = routeRemote,
			remoteServerSelected = selection.Enabled,
			routingMode = (routeRemote ? "remote-lease" : "local-lm-studio"),
			leaseAware = true,
			leaseBlockReason = leaseBlockReason,
			lease = leaseState,
			localModelIllusion = new
			{
				enabled = true,
				localEndpoint = localEndpoint,
				visibleBaseUrl = "http://localhost:" + CopilotDuplicatorPort.ToString(CultureInfo.InvariantCulture),
				visibleModel = FirstNonEmpty(selection.SelectedModel, "lm-studio"),
				remoteBaseUrl = selection.OpenAiBaseUrl,
				remoteRoutingActive = routeRemote,
				leaseAware = true,
				leaseStatus = selection.LeaseStatus,
				blockReason = leaseBlockReason
			},
			selection = new
			{
				enabled = selection.Enabled,
				serverId = selection.ServerId,
				serverName = selection.ServerName,
				ownerUserName = selection.OwnerUserName,
				externalIp = selection.ExternalIp,
				hardwareSummary = selection.HardwareSummary,
				endpoint = selection.Endpoint,
				openAiBaseUrl = selection.OpenAiBaseUrl,
				selectedModel = selection.SelectedModel,
				selectedUtc = selection.SelectedUtc,
				leaseId = selection.LeaseId,
				leaseRequired = selection.LeaseRequired,
				leaseStatus = selection.LeaseStatus,
				leasePaymentStatus = selection.LeasePaymentStatus,
				leaseStartedUtc = selection.LeaseStartedUtc,
				leaseRenewedUtc = selection.LeaseRenewedUtc,
				leaseExpiresUtc = selection.LeaseExpiresUtc,
				leaseSource = selection.LeaseSource,
				leaseMode = selection.LeaseMode
			},
			localLmStudio = new
			{
				baseUrl = localBaseUrl,
				chatCompletions = localBaseUrl.TrimEnd('/') + "/v1/chat/completions",
				models = localBaseUrl.TrimEnd('/') + "/v1/models"
			}
		};
	}

	private object BuildCopilotDuplicatorLeasePayload(LmVsProxyRemoteModelServerSelection selection)
	{
		selection = ((selection == null) ? new LmVsProxyRemoteModelServerSelection() : selection.Clone());
		ApplyCopilotLeaseDefaults(selection);
		string blockReason;
		bool active = ShouldRouteCopilotToRemote(selection, out blockReason);
		string effectiveStatus = GetEffectiveCopilotLeaseStatus(selection);
		return new
		{
			id = selection.LeaseId,
			required = selection.LeaseRequired,
			active = active,
			status = effectiveStatus,
			paymentStatus = selection.LeasePaymentStatus,
			startedUtc = selection.LeaseStartedUtc,
			renewedUtc = selection.LeaseRenewedUtc,
			expiresUtc = selection.LeaseExpiresUtc,
			source = selection.LeaseSource,
			mode = selection.LeaseMode,
			blockReason = blockReason,
			serverId = selection.ServerId,
			serverName = selection.ServerName,
			remoteBaseUrl = selection.OpenAiBaseUrl,
			meteringRequired = selection.Enabled,
			reconnectBehavior = (active ? "route_remote" : "use_local_until_active")
		};
	}

	private bool ShouldRouteCopilotToRemote(LmVsProxyRemoteModelServerSelection selection, out string reason)
	{
		reason = "";
		if (selection == null || !selection.Enabled || string.IsNullOrWhiteSpace(selection.OpenAiBaseUrl))
		{
			reason = "No remote Copilot server is selected.";
			return false;
		}
		string status = GetEffectiveCopilotLeaseStatus(selection);
		if (!string.IsNullOrWhiteSpace(selection.LeaseId))
		{
			MarketplaceLeaseRecord brokerLease = FindMarketplaceLeaseById(selection.LeaseId);
			if (brokerLease != null)
			{
				string brokerStatus = GetEffectiveMarketplaceLeaseStatus(brokerLease);
				if (IsMarketplaceLeaseActiveStatus(brokerStatus))
				{
					return true;
				}
				reason = "Marketplace lease broker status is " + brokerStatus + ".";
				return false;
			}
		}
		if (IsCopilotLeaseActiveStatus(status))
		{
			return true;
		}
		if (1 == 0)
		{
		}
		string text = status switch
		{
			"pending_payment" => "Paid lease is pending payment.", 
			"payment_required" => "Payment is required before remote routing.", 
			"expired" => "Lease has expired.", 
			"canceled" => "Lease was canceled.", 
			"suspended" => "Lease is suspended.", 
			_ => "Lease is not active.", 
		};
		if (1 == 0)
		{
		}
		reason = text;
		return false;
	}

	private void ApplyCopilotLeaseDefaults(LmVsProxyRemoteModelServerSelection selection)
	{
		if (selection == null)
		{
			return;
		}
		selection.Normalize();
		if (!selection.Enabled)
		{
			return;
		}
		if (string.IsNullOrWhiteSpace(selection.LeaseId))
		{
			selection.LeaseId = BuildCopilotLeaseId(selection);
		}
		if (string.IsNullOrWhiteSpace(selection.LeaseSource))
		{
			selection.LeaseSource = "selection";
		}
		if (string.IsNullOrWhiteSpace(selection.LeaseMode))
		{
			selection.LeaseMode = "local-model-illusion";
		}
		if (!selection.LeaseRequired)
		{
			if (string.IsNullOrWhiteSpace(selection.LeaseStatus))
			{
				selection.LeaseStatus = "active";
			}
			if (string.IsNullOrWhiteSpace(selection.LeasePaymentStatus))
			{
				selection.LeasePaymentStatus = "not_required";
			}
			if (string.IsNullOrWhiteSpace(selection.LeaseStartedUtc))
			{
				selection.LeaseStartedUtc = DateTimeOffset.UtcNow.ToString("O");
			}
			if (string.IsNullOrWhiteSpace(selection.LeaseExpiresUtc))
			{
				selection.LeaseExpiresUtc = DateTimeOffset.UtcNow.AddHours(12.0).ToString("O");
			}
		}
		else
		{
			if (string.IsNullOrWhiteSpace(selection.LeaseStatus))
			{
				selection.LeaseStatus = "pending_payment";
			}
			if (string.IsNullOrWhiteSpace(selection.LeasePaymentStatus))
			{
				selection.LeasePaymentStatus = "payment_required";
			}
		}
		selection.Normalize();
	}

	private string GetEffectiveCopilotLeaseStatus(LmVsProxyRemoteModelServerSelection selection)
	{
		if (selection == null || !selection.Enabled)
		{
			return "none";
		}
		string status = ((!string.IsNullOrWhiteSpace(selection.LeaseStatus)) ? selection.LeaseStatus.Trim().ToLowerInvariant().Replace(' ', '_')
			.Replace('-', '_') : (selection.LeaseRequired ? "pending_payment" : "active"));
		if (IsCopilotLeaseActiveStatus(status) && TryParseUtc(selection.LeaseExpiresUtc, out var expiresUtc) && expiresUtc <= DateTimeOffset.UtcNow)
		{
			return "expired";
		}
		return status;
	}

	private static bool IsCopilotLeaseActiveStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant().Replace(' ', '_')
			.Replace('-', '_');
		int result;
		switch (status)
		{
		default:
			result = ((status == "grace") ? 1 : 0);
			break;
		case "active":
		case "free":
		case "trial":
		case "comped":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private string BuildCopilotLeaseId(LmVsProxyRemoteModelServerSelection selection)
	{
		string seed = string.Join("|", new string[5]
		{
			selection?.ServerId,
			selection?.OwnerUserName,
			selection?.ServerName,
			selection?.OpenAiBaseUrl,
			selection?.SelectedUtc
		}.Where((string value) => !string.IsNullOrWhiteSpace(value)));
		if (string.IsNullOrWhiteSpace(seed))
		{
			seed = Guid.NewGuid().ToString("N");
		}
		return "lease_" + ComputeStableShortHash(seed);
	}

	private string ReadCopilotJsonString(JsonElement root, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(root, name, out var value))
			{
				string text = ExtractJsonString(value);
				if (!string.IsNullOrWhiteSpace(text))
				{
					return text;
				}
			}
		}
		return "";
	}

	private bool ReadCopilotJsonBool(JsonElement root, bool fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(root, name, out var value))
			{
				return ReadJsonBool(value, fallback);
			}
		}
		return fallback;
	}

	private long ReadCopilotJsonLong(JsonElement root, long fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(root, name, out var value))
			{
				return ReadJsonLong(value, fallback);
			}
		}
		return fallback;
	}

	private static bool TryParseUtc(string value, out DateTimeOffset parsed)
	{
		return DateTimeOffset.TryParse(value, CultureInfo.InvariantCulture, DateTimeStyles.AdjustToUniversal | DateTimeStyles.AssumeUniversal, out parsed);
	}

	private string HandleMarketplaceLeasesGetRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			bool isAdmin = IsDatabaseAdministrator(connection, request);
			string leaseId = (GetQueryParameter(request, "leaseId") ?? GetQueryParameter(request, "id") ?? "").Trim();
			List<MarketplaceLeaseRecord> leases = ListMarketplaceLeases(ownerKey, isAdmin);
			MarketplaceLeaseRecord selected = (string.IsNullOrWhiteSpace(leaseId) ? null : leases.FirstOrDefault((MarketplaceLeaseRecord lease) => string.Equals(lease.Id, leaseId, StringComparison.OrdinalIgnoreCase)));
			return JsonSerializer.Serialize(new
			{
				ok = true,
				ownerKey = ownerKey,
				canEdit = isAdmin,
				table = "Finance.MarketplaceLeases",
				policy = BuildPeerRentalMarketplacePolicyPayload(ownerKey, GetRemoteModelServerSelection()),
				summary = BuildMarketplaceLeaseBrokerMonitoringPayload(),
				activeLease = BuildMarketplaceLeasePayload(FindActiveMarketplaceLease(ownerKey)),
				selectedLease = BuildMarketplaceLeasePayload(selected),
				leases = leases.Take(100).Select(BuildMarketplaceLeasePayload).ToList(),
				copilotDuplicator = BuildCopilotDuplicatorPayload()
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Marketplace Lease] Load failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleMarketplaceLeaseMutationRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			bool localAdmin = IsLocalAdmin(connection, request);
			bool databaseAdmin = IsDatabaseAdministrator(connection, request);
			if (!identity.Authenticated && !identity.IsAdmin && !localAdmin)
			{
				return BuildJsonError(request, 401, "Unauthorized", "Sign in before reserving peer hardware.");
			}
			string ownerKey = NormalizeCostOwnerKey(string.IsNullOrWhiteSpace(identity.OwnerKey) ? GetChatSessionOwnerKey(connection, request) : identity.OwnerKey);
			string userName = (string.IsNullOrWhiteSpace(identity.UserName) ? GetUserNameFromOwnerKey(ownerKey) : identity.UserName);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			if (root.ValueKind != JsonValueKind.Object)
			{
				return BuildJsonError(request, 400, "Bad Request", "Marketplace lease payload must be a JSON object.");
			}
			string action = NormalizeMarketplaceLeaseAction(ReadCopilotJsonString(root, "action"));
			MarketplaceLeaseRecord requested = BuildMarketplaceLeaseRecordFromRequest(root, ownerKey, userName);
			MarketplaceLeaseRecord existing = ((!string.IsNullOrWhiteSpace(requested.Id)) ? FindMarketplaceLeaseById(requested.Id) : null);
			if (existing != null && !CanAccessMarketplaceLease(existing, ownerKey, databaseAdmin || localAdmin))
			{
				return BuildJsonError(request, 403, "Forbidden", "You cannot modify this marketplace lease.");
			}
			if (action == "quote")
			{
				return JsonSerializer.Serialize(new
				{
					ok = true,
					action = action,
					quote = BuildMarketplaceLeaseQuotePayload(requested),
					policy = BuildPeerRentalMarketplacePolicyPayload(ownerKey, GetRemoteModelServerSelection()),
					lease = BuildMarketplaceLeasePayload(requested)
				});
			}
			MarketplaceLeaseRecord lease = ((existing == null) ? requested : MergeMarketplaceLease(existing, requested));
			DateTimeOffset now = DateTimeOffset.UtcNow;
			lease.OwnerKey = ownerKey;
			lease.UserName = userName;
			lease.UpdatedUtc = now.ToString("O");
			if (string.IsNullOrWhiteSpace(lease.CreatedUtc))
			{
				lease.CreatedUtc = lease.UpdatedUtc;
			}
			if (action == "queue" || action == "schedule" || action == "reserve_slot")
			{
				lease.QuoteUsd = CalculateMarketplaceLeaseQuoteUsd(lease);
				lease.Status = ((action == "schedule") ? "scheduled" : "queued");
				lease.PaymentStatus = (lease.LeaseRequired ? "payment_required" : "not_required");
				Dictionary<string, string> metadata = ReadFinancePaymentMetadata(lease.MetadataJson);
				string scheduledStartUtc = ReadCopilotJsonString(root, "scheduledStartUtc", "startUtc", "notBeforeUtc");
				if (!string.IsNullOrWhiteSpace(scheduledStartUtc))
				{
					metadata["scheduledStartUtc"] = scheduledStartUtc;
				}
				double maxSpendUsd = ReadMarketplaceJsonDouble(root, 0.0, "maxSpendUsd", "maxBudgetUsd", "spendLimitUsd");
				if (maxSpendUsd > 0.0)
				{
					metadata["maxSpendUsd"] = NormalizeCostNumber(maxSpendUsd).ToString("0.########", CultureInfo.InvariantCulture);
				}
				long autoStopMinutes = ReadCopilotJsonLong(root, 0L, "autoStopMinutes", "timeoutMinutes", "maxRuntimeMinutes");
				if (autoStopMinutes > 0)
				{
					metadata["autoStopMinutes"] = autoStopMinutes.ToString(CultureInfo.InvariantCulture);
				}
				metadata["queuePosition"] = CalculateMarketplaceQueuePosition(lease).ToString(CultureInfo.InvariantCulture);
				metadata["reservationPolicy"] = "max_spend_auto_stop_timeout";
				lease.MetadataJson = WriteFinancePaymentMetadata(metadata);
			}
			else if (action == "reserve" || action == "create" || action == "start")
			{
				lease.QuoteUsd = CalculateMarketplaceLeaseQuoteUsd(lease);
				lease.Status = (lease.LeaseRequired ? "reserved" : "active");
				lease.PaymentStatus = (lease.LeaseRequired ? "payment_required" : "not_required");
				if (!lease.LeaseRequired)
				{
					lease.Status = "active";
					if (string.IsNullOrWhiteSpace(lease.StartedUtc))
					{
						lease.StartedUtc = now.ToString("O");
					}
					lease.RenewedUtc = now.ToString("O");
					lease.ExpiresUtc = now.AddMinutes(Math.Max(1L, lease.LeaseMinutes)).ToString("O");
				}
			}
			else if (action == "activate" || action == "paid")
			{
				lease.Status = "active";
				lease.PaymentStatus = (lease.LeaseRequired ? "paid" : "not_required");
				if (string.IsNullOrWhiteSpace(lease.StartedUtc))
				{
					lease.StartedUtc = now.ToString("O");
				}
				lease.RenewedUtc = now.ToString("O");
				lease.ExpiresUtc = now.AddMinutes(Math.Max(1L, lease.LeaseMinutes)).ToString("O");
			}
			else if (action == "heartbeat" || action == "renew")
			{
				if (!IsMarketplaceLeaseActive(lease))
				{
					return BuildJsonError(request, 409, "Conflict", "Only active leases can be renewed or heartbeated.");
				}
				long minutes = (lease.LeaseMinutes = Math.Max(1L, ReadCopilotJsonLong(root, (lease.LeaseMinutes <= 0) ? 60 : lease.LeaseMinutes, "minutes", "leaseMinutes", "durationMinutes")));
				lease.LastHeartbeatUtc = now.ToString("O");
				lease.RenewedUtc = now.ToString("O");
				lease.ExpiresUtc = now.AddMinutes(minutes).ToString("O");
			}
			else if (action == "cancel" || action == "end" || action == "expire")
			{
				lease.Status = ((action == "expire") ? "expired" : ((action == "cancel") ? "canceled" : "ended"));
				lease.EndedUtc = now.ToString("O");
				lease.ExpiresUtc = (string.IsNullOrWhiteSpace(lease.ExpiresUtc) ? lease.EndedUtc : lease.ExpiresUtc);
			}
			else
			{
				if (!(action == "apply_copilot") && !(action == "select") && !(action == "use"))
				{
					return BuildJsonError(request, 400, "Bad Request", "Unknown marketplace lease action.");
				}
				if (!IsMarketplaceLeaseActive(lease))
				{
					return BuildJsonError(request, 409, "Conflict", "Only active marketplace leases can be selected for the Copilot duplicator.");
				}
				ConfigureRemoteModelServerSelection(BuildRemoteModelSelectionFromMarketplaceLease(lease));
			}
			lease.PolicyJson = NormalizeJsonObjectRawText(JsonSerializer.Serialize(BuildPeerRentalMarketplacePolicyPayload(ownerKey, BuildRemoteModelSelectionFromMarketplaceLease(lease))));
			lease = UpsertMarketplaceLease(lease);
			switch (action)
			{
			default:
				if (!(action == "use"))
				{
					break;
				}
				goto case "activate";
			case "activate":
			case "paid":
			case "apply_copilot":
			case "select":
				ConfigureRemoteModelServerSelection(BuildRemoteModelSelectionFromMarketplaceLease(lease));
				break;
			}
			RecordObservabilityEvent("marketplace", "lease " + action, lease.Status, lease.Id, ownerKey, "/api/marketplace/leases", 0L);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				action = action,
				lease = BuildMarketplaceLeasePayload(lease),
				summary = BuildMarketplaceLeaseBrokerMonitoringPayload(),
				copilotDuplicator = BuildCopilotDuplicatorPayload()
			});
		}
		catch (JsonException ex)
		{
			return BuildJsonError(request, 400, "Bad Request", "Invalid JSON: " + ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[Marketplace Lease] Mutation failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private MarketplaceLeaseRecord BuildMarketplaceLeaseRecordFromRequest(JsonElement root, string ownerKey, string userName)
	{
		LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
		DateTimeOffset now = DateTimeOffset.UtcNow;
		string id = ReadCopilotJsonString(root, "leaseId", "id");
		string serverId = FirstNonEmpty(ReadCopilotJsonString(root, "serverId"), selection.ServerId);
		string serverName = FirstNonEmpty(ReadCopilotJsonString(root, "serverName", "title"), selection.ServerName);
		string hostUser = FirstNonEmpty(ReadCopilotJsonString(root, "hostUserName", "ownerUserName", "host"), selection.OwnerUserName);
		string hostOwner = NormalizeTrustOwnerKey(ReadCopilotJsonString(root, "hostOwnerKey"), hostUser);
		string endpoint = FirstNonEmpty(ReadCopilotJsonString(root, "endpoint", "remoteEndpoint"), selection.Endpoint, selection.OpenAiBaseUrl);
		string openAiBaseUrl = LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(FirstNonEmpty(ReadCopilotJsonString(root, "openAiBaseUrl", "baseUrl"), selection.OpenAiBaseUrl, endpoint));
		bool leaseRequired = ReadCopilotJsonBool(root, selection.LeaseRequired, "leaseRequired", "requiresPayment", "paymentRequired");
		double quoteUsd = ReadMarketplaceJsonDouble(root, 0.0, "quoteUsd", "priceUsd", "amountUsd");
		long tokenRate = Math.Max(0L, ReadCopilotJsonLong(root, 0L, "tokenRate", "tokensPerHour", "advertisedTokenRate"));
		if (tokenRate <= 0)
		{
			tokenRate = Math.Max(1L, GetPricingTokensPerHour(GetChatCostSettings()));
		}
		long minutes = Math.Max(1L, ReadCopilotJsonLong(root, Math.Max(1, selection.LeaseRequired ? 60 : 720), "minutes", "leaseMinutes", "durationMinutes"));
		TrustAbuseSummarySnapshot trust = BuildTrustAbuseSummary(hostOwner, serverId, serverName, ReadCopilotJsonString(root, "externalIp", "ip"));
		MarketplaceLeaseRecord marketplaceLeaseRecord = new MarketplaceLeaseRecord();
		marketplaceLeaseRecord.Id = (string.IsNullOrWhiteSpace(id) ? BuildMarketplaceLeaseId(ownerKey, serverId, serverName, openAiBaseUrl) : id.Trim());
		marketplaceLeaseRecord.OwnerKey = ownerKey;
		marketplaceLeaseRecord.UserName = userName ?? "";
		marketplaceLeaseRecord.ServerId = serverId;
		marketplaceLeaseRecord.ServerName = serverName;
		marketplaceLeaseRecord.HostOwnerKey = hostOwner;
		marketplaceLeaseRecord.HostUserName = hostUser;
		marketplaceLeaseRecord.RemoteEndpoint = endpoint;
		marketplaceLeaseRecord.OpenAiBaseUrl = openAiBaseUrl;
		marketplaceLeaseRecord.SelectedModel = FirstNonEmpty(ReadCopilotJsonString(root, "model", "selectedModel"), selection.SelectedModel);
		marketplaceLeaseRecord.HardwareSummary = FirstNonEmpty(ReadCopilotJsonString(root, "hardwareSummary", "hardware"), selection.HardwareSummary);
		marketplaceLeaseRecord.LeaseRequired = leaseRequired || quoteUsd > 0.0;
		marketplaceLeaseRecord.QuoteUsd = quoteUsd;
		marketplaceLeaseRecord.TokenRate = tokenRate;
		marketplaceLeaseRecord.LeaseMinutes = minutes;
		marketplaceLeaseRecord.Status = "reserved";
		marketplaceLeaseRecord.PaymentStatus = ((leaseRequired || quoteUsd > 0.0) ? "payment_required" : "not_required");
		marketplaceLeaseRecord.TrustRiskTier = trust.RiskTier;
		marketplaceLeaseRecord.CreatedUtc = now.ToString("O");
		marketplaceLeaseRecord.UpdatedUtc = now.ToString("O");
		marketplaceLeaseRecord.PolicyJson = NormalizeJsonObjectRawText(JsonSerializer.Serialize(BuildPeerRentalMarketplacePolicyPayload(ownerKey, selection)));
		marketplaceLeaseRecord.MetadataJson = NormalizeJsonObjectRawText(JsonSerializer.Serialize(new
		{
			source = "marketplace_lease_broker",
			requestedUtc = now.ToString("O"),
			trustRiskScore = trust.RiskScore,
			trustRiskTier = trust.RiskTier,
			hostVerificationStatus = trust.HostVerificationStatus,
			renterIdentityStatus = trust.RenterIdentityStatus
		}));
		MarketplaceLeaseRecord record = marketplaceLeaseRecord;
		record.QuoteUsd = CalculateMarketplaceLeaseQuoteUsd(record);
		return record;
	}

	private MarketplaceLeaseRecord MergeMarketplaceLease(MarketplaceLeaseRecord existing, MarketplaceLeaseRecord incoming)
	{
		existing = existing ?? new MarketplaceLeaseRecord();
		incoming = incoming ?? new MarketplaceLeaseRecord();
		existing.ServerId = FirstNonEmpty(incoming.ServerId, existing.ServerId);
		existing.ServerName = FirstNonEmpty(incoming.ServerName, existing.ServerName);
		existing.HostOwnerKey = FirstNonEmpty(incoming.HostOwnerKey, existing.HostOwnerKey);
		existing.HostUserName = FirstNonEmpty(incoming.HostUserName, existing.HostUserName);
		existing.RemoteEndpoint = FirstNonEmpty(incoming.RemoteEndpoint, existing.RemoteEndpoint);
		existing.OpenAiBaseUrl = FirstNonEmpty(incoming.OpenAiBaseUrl, existing.OpenAiBaseUrl);
		existing.SelectedModel = FirstNonEmpty(incoming.SelectedModel, existing.SelectedModel);
		existing.HardwareSummary = FirstNonEmpty(incoming.HardwareSummary, existing.HardwareSummary);
		existing.LeaseRequired = incoming.LeaseRequired || existing.LeaseRequired;
		existing.QuoteUsd = ((incoming.QuoteUsd > 0.0) ? incoming.QuoteUsd : existing.QuoteUsd);
		existing.TokenRate = ((incoming.TokenRate > 0) ? incoming.TokenRate : existing.TokenRate);
		existing.LeaseMinutes = ((incoming.LeaseMinutes > 0) ? incoming.LeaseMinutes : existing.LeaseMinutes);
		existing.TrustRiskTier = FirstNonEmpty(incoming.TrustRiskTier, existing.TrustRiskTier);
		existing.PolicyJson = NormalizeJsonObjectRawText(FirstNonEmpty(incoming.PolicyJson, existing.PolicyJson));
		existing.MetadataJson = NormalizeJsonObjectRawText(FirstNonEmpty(incoming.MetadataJson, existing.MetadataJson));
		return existing;
	}

	private object BuildPeerRentalMarketplacePolicyPayload(string ownerKey, LmVsProxyRemoteModelServerSelection selection)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		ChatPermissionState permissions = GetChatPermissions(ownerKey);
		TrustAbuseSummarySnapshot renterTrust = BuildTrustAbuseSummary(ownerKey, "", "", "");
		selection = selection ?? new LmVsProxyRemoteModelServerSelection();
		TrustAbuseSummarySnapshot hostTrust = BuildTrustAbuseSummary(NormalizeTrustOwnerKey("", selection.OwnerUserName), selection.ServerId, selection.ServerName, selection.ExternalIp);
		bool blocked = renterTrust.HostSuspended || hostTrust.HostSuspended || renterTrust.CommandsBlocked || hostTrust.CommandsBlocked || IsChatBanned(permissions);
		return new
		{
			leaseBrokerEnabled = true,
			requireAuthenticatedRenters = true,
			requireActiveLeaseForRemoteCopilot = true,
			requireVerifiedHostsForPreferredListing = true,
			requireRenterIdentityForPaidLeases = true,
			blockSuspendedHosts = true,
			blockCommandAbuse = true,
			sandboxProjectWorkspaces = true,
			filesystemContextLeaseScoped = true,
			sqlAdminReadOnlyByDefaultForLeases = true,
			blocked = blocked,
			renter = new
			{
				ownerKey = ownerKey,
				reputationScore = renterTrust.ReputationScore,
				riskTier = renterTrust.RiskTier,
				identityStatus = renterTrust.RenterIdentityStatus,
				commandsBlocked = renterTrust.CommandsBlocked,
				hostSuspended = renterTrust.HostSuspended
			},
			host = new
			{
				ownerUserName = (selection.OwnerUserName ?? ""),
				serverId = (selection.ServerId ?? ""),
				reputationScore = hostTrust.ReputationScore,
				riskTier = hostTrust.RiskTier,
				verificationStatus = hostTrust.HostVerificationStatus,
				commandsBlocked = hostTrust.CommandsBlocked,
				hostSuspended = hostTrust.HostSuspended
			}
		};
	}

	private object BuildMarketplaceLeaseQuotePayload(MarketplaceLeaseRecord lease)
	{
		lease = lease ?? new MarketplaceLeaseRecord();
		long tokenRate = ((lease.TokenRate > 0) ? lease.TokenRate : Math.Max(1L, GetPricingTokensPerHour(GetChatCostSettings())));
		long minutes = Math.Max(1L, lease.LeaseMinutes);
		long estimatedTokens = Math.Max(1L, (long)Math.Ceiling((double)tokenRate * ((double)minutes / 60.0)));
		double quoteUsd = CalculateMarketplaceLeaseQuoteUsd(lease);
		double socketJackFeeUsd = NormalizeCostNumber(quoteUsd * 0.015);
		return new
		{
			leaseId = lease.Id,
			currency = "usd",
			quoteUsd = quoteUsd,
			socketJackFeeUsd = socketJackFeeUsd,
			hostGrossUsd = NormalizeCostNumber(Math.Max(0.0, quoteUsd - socketJackFeeUsd)),
			tokenRate = tokenRate,
			leaseMinutes = minutes,
			estimatedTokens = estimatedTokens,
			tokenUsdPerToken = GetEffectiveTokenUsdPerToken(GetChatCostSettings()),
			paymentRequired = (lease.LeaseRequired || quoteUsd > 0.0),
			expiresInMinutes = 15
		};
	}

	private double CalculateMarketplaceLeaseQuoteUsd(MarketplaceLeaseRecord lease)
	{
		lease = lease ?? new MarketplaceLeaseRecord();
		if (lease.QuoteUsd > 0.0)
		{
			return NormalizeCostNumber(lease.QuoteUsd);
		}
		if (!lease.LeaseRequired)
		{
			return 0.0;
		}
		long tokenRate = ((lease.TokenRate > 0) ? lease.TokenRate : Math.Max(1L, GetPricingTokensPerHour(GetChatCostSettings())));
		long minutes = Math.Max(1L, lease.LeaseMinutes);
		long estimatedTokens = Math.Max(1L, (long)Math.Ceiling((double)tokenRate * ((double)minutes / 60.0)));
		return NormalizeCostNumber(Math.Max(5E-05, GetEffectiveTokenUsdPerToken(GetChatCostSettings())) * (double)estimatedTokens);
	}

	private object BuildMarketplaceLeasePayload(MarketplaceLeaseRecord record)
	{
		if (record == null)
		{
			return null;
		}
		string effectiveStatus = GetEffectiveMarketplaceLeaseStatus(record);
		return new
		{
			id = record.Id,
			ownerKey = record.OwnerKey,
			username = record.UserName,
			serverId = record.ServerId,
			serverName = record.ServerName,
			hostOwnerKey = record.HostOwnerKey,
			hostUserName = record.HostUserName,
			remoteEndpoint = record.RemoteEndpoint,
			openAiBaseUrl = record.OpenAiBaseUrl,
			selectedModel = record.SelectedModel,
			hardwareSummary = record.HardwareSummary,
			status = effectiveStatus,
			storedStatus = record.Status,
			active = IsMarketplaceLeaseActive(record),
			paymentStatus = record.PaymentStatus,
			leaseRequired = record.LeaseRequired,
			checkoutSessionId = record.CheckoutSessionId,
			paymentId = record.PaymentId,
			quoteUsd = record.QuoteUsd,
			tokenRate = record.TokenRate,
			leaseMinutes = record.LeaseMinutes,
			startedUtc = record.StartedUtc,
			renewedUtc = record.RenewedUtc,
			expiresUtc = record.ExpiresUtc,
			endedUtc = record.EndedUtc,
			lastHeartbeatUtc = record.LastHeartbeatUtc,
			createdUtc = record.CreatedUtc,
			updatedUtc = record.UpdatedUtc,
			trustRiskTier = record.TrustRiskTier,
			quote = BuildMarketplaceLeaseQuotePayload(record),
			policy = DeserializeJsonElement(record.PolicyJson, "{}"),
			metadata = DeserializeJsonElement(record.MetadataJson, "{}")
		};
	}

	private object BuildMarketplaceLeaseBrokerMonitoringPayload()
	{
		int total = 0;
		int active = 0;
		int queued = 0;
		int scheduled = 0;
		int reserved = 0;
		int pendingPayment = 0;
		int expired = 0;
		int ended = 0;
		int paid = 0;
		DateTimeOffset now = DateTimeOffset.UtcNow;
		lock (_chatSessionLock)
		{
			Table table = GetMarketplaceLeasesTable();
			foreach (object[] row in table.Rows)
			{
				MarketplaceLeaseRecord lease = MarketplaceLeaseFromRow(row);
				total++;
				string status = GetEffectiveMarketplaceLeaseStatus(lease);
				if (IsMarketplaceLeaseActiveStatus(status))
				{
					active++;
				}
				else
				{
					switch (status)
					{
					case "queued":
						queued++;
						break;
					case "scheduled":
						scheduled++;
						break;
					case "reserved":
						reserved++;
						break;
					case "expired":
						expired++;
						break;
					default:
						if (!(status == "canceled"))
						{
							break;
						}
						goto case "ended";
					case "ended":
						ended++;
						break;
					}
				}
				if (lease.LeaseRequired && lease.PaymentStatus == "payment_required")
				{
					pendingPayment++;
				}
				if (lease.PaymentStatus == "paid")
				{
					paid++;
				}
			}
		}
		int score = ((total <= 0) ? 90 : Math.Max(0, Math.Min(100, 100 - pendingPayment * 4 - expired * 3)));
		return new
		{
			table = "Finance.MarketplaceLeases",
			totalLeases = total,
			activeLeases = active,
			queuedLeases = queued,
			scheduledLeases = scheduled,
			reservedLeases = reserved,
			pendingPaymentLeases = pendingPayment,
			paidLeases = paid,
			expiredLeases = expired,
			endedLeases = ended,
			leaseBrokerScore = score,
			leaseBrokerTier = ((score >= 90) ? "Ready" : ((score >= 75) ? "Watch" : ((score >= 55) ? "Needs Review" : "Blocked"))),
			generatedUtc = now.ToString("O")
		};
	}

	private int CalculateMarketplaceQueuePosition(MarketplaceLeaseRecord requested)
	{
		int ahead = 0;
		lock (_chatSessionLock)
		{
			Table table = GetMarketplaceLeasesTable();
			foreach (object[] row in table.Rows)
			{
				MarketplaceLeaseRecord lease = MarketplaceLeaseFromRow(row);
				string status = GetEffectiveMarketplaceLeaseStatus(lease);
				if ((!(status != "queued") || !(status != "scheduled") || !(status != "reserved") || !(status != "pending_payment")) && (string.IsNullOrWhiteSpace(requested?.ServerId) || string.Equals(lease.ServerId, requested.ServerId, StringComparison.OrdinalIgnoreCase)))
				{
					ahead++;
				}
			}
		}
		return ahead + 1;
	}

	private MarketplaceLeaseRecord UpsertMarketplaceLease(MarketplaceLeaseRecord record)
	{
		if (record == null)
		{
			throw new ArgumentNullException("record");
		}
		record.Id = (string.IsNullOrWhiteSpace(record.Id) ? ("lease_" + Guid.NewGuid().ToString("N")) : record.Id.Trim());
		record.OwnerKey = NormalizeCostOwnerKey(record.OwnerKey);
		if (string.IsNullOrWhiteSpace(record.UserName))
		{
			record.UserName = GetUserNameFromOwnerKey(record.OwnerKey);
		}
		string now = DateTimeOffset.UtcNow.ToString("O");
		if (string.IsNullOrWhiteSpace(record.CreatedUtc))
		{
			record.CreatedUtc = now;
		}
		record.UpdatedUtc = now;
		lock (_chatSessionLock)
		{
			Table table = GetMarketplaceLeasesTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				MarketplaceLeaseRecord existing = MarketplaceLeaseFromRow(table.Rows[i]);
				if (string.Equals(existing.Id, record.Id, StringComparison.OrdinalIgnoreCase))
				{
					table.Rows[i] = MarketplaceLeaseToRow(record);
					SaveChatSessionDataAndInvalidateCaches();
					return record;
				}
			}
			table.Rows.Add(MarketplaceLeaseToRow(record));
			SaveChatSessionDataAndInvalidateCaches();
		}
		return record;
	}

	private MarketplaceLeaseRecord FindMarketplaceLeaseById(string leaseId)
	{
		if (string.IsNullOrWhiteSpace(leaseId))
		{
			return null;
		}
		lock (_chatSessionLock)
		{
			Table table = GetMarketplaceLeasesTable();
			foreach (object[] row in table.Rows)
			{
				MarketplaceLeaseRecord record = MarketplaceLeaseFromRow(row);
				if (string.Equals(record.Id, leaseId.Trim(), StringComparison.OrdinalIgnoreCase))
				{
					return record;
				}
			}
		}
		return null;
	}

	private MarketplaceLeaseRecord FindActiveMarketplaceLease(string ownerKey)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		lock (_chatSessionLock)
		{
			Table table = GetMarketplaceLeasesTable();
			return (from lease in table.Rows.Select(MarketplaceLeaseFromRow)
				where string.Equals(lease.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) && IsMarketplaceLeaseActive(lease)
				orderby lease.UpdatedUtc ?? "" descending
				select lease).FirstOrDefault();
		}
	}

	private List<MarketplaceLeaseRecord> ListMarketplaceLeases(string ownerKey, bool includeAll)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		lock (_chatSessionLock)
		{
			Table table = GetMarketplaceLeasesTable();
			return (from lease in table.Rows.Select(MarketplaceLeaseFromRow)
				where includeAll || string.Equals(lease.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase)
				orderby lease.UpdatedUtc ?? "" descending
				select lease).ToList();
		}
	}

	private bool CanAccessMarketplaceLease(MarketplaceLeaseRecord lease, string ownerKey, bool admin)
	{
		if (lease == null)
		{
			return false;
		}
		if (admin)
		{
			return true;
		}
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		return string.Equals(lease.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase);
	}

	private LmVsProxyRemoteModelServerSelection BuildRemoteModelSelectionFromMarketplaceLease(MarketplaceLeaseRecord lease)
	{
		lease = lease ?? new MarketplaceLeaseRecord();
		LmVsProxyRemoteModelServerSelection selection = new LmVsProxyRemoteModelServerSelection
		{
			Enabled = !string.IsNullOrWhiteSpace(lease.OpenAiBaseUrl),
			ServerId = lease.ServerId,
			ServerName = lease.ServerName,
			OwnerUserName = lease.HostUserName,
			HardwareSummary = lease.HardwareSummary,
			Endpoint = lease.RemoteEndpoint,
			OpenAiBaseUrl = lease.OpenAiBaseUrl,
			SelectedModel = lease.SelectedModel,
			LeaseId = lease.Id,
			LeaseRequired = lease.LeaseRequired,
			LeaseStatus = GetEffectiveMarketplaceLeaseStatus(lease),
			LeasePaymentStatus = lease.PaymentStatus,
			LeaseStartedUtc = lease.StartedUtc,
			LeaseRenewedUtc = lease.RenewedUtc,
			LeaseExpiresUtc = lease.ExpiresUtc,
			LeaseSource = "marketplace-lease-broker",
			LeaseMode = "local-model-illusion",
			SelectedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
		selection.Normalize();
		return selection;
	}

	private string BuildMarketplaceLeaseId(string ownerKey, string serverId, string serverName, string openAiBaseUrl)
	{
		string seed = string.Join("|", new string[5]
		{
			ownerKey,
			serverId,
			serverName,
			openAiBaseUrl,
			DateTimeOffset.UtcNow.ToUnixTimeMilliseconds().ToString(CultureInfo.InvariantCulture)
		}.Where((string value) => !string.IsNullOrWhiteSpace(value)));
		return "lease_" + ComputeStableShortHash(string.IsNullOrWhiteSpace(seed) ? Guid.NewGuid().ToString("N") : seed);
	}

	private string NormalizeMarketplaceLeaseAction(string action)
	{
		action = (action ?? "").Trim().ToLowerInvariant().Replace("-", "_")
			.Replace(" ", "_");
		if (string.IsNullOrWhiteSpace(action))
		{
			return "reserve";
		}
		if (action == "request" || action == "book")
		{
			return "reserve";
		}
		if (action == "enqueue" || action == "queued")
		{
			return "queue";
		}
		if (action == "reservation" || action == "reserve_slot")
		{
			return "reserve_slot";
		}
		if (action == "pay" || action == "payment_paid")
		{
			return "paid";
		}
		if (action == "select_copilot" || action == "use_for_copilot")
		{
			return "apply_copilot";
		}
		return action;
	}

	private string NormalizeMarketplaceLeaseStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant().Replace("-", "_")
			.Replace(" ", "_");
		switch (status)
		{
		case "active":
		case "queued":
		case "scheduled":
		case "reserved":
		case "pending_payment":
		case "expired":
		case "ended":
		case "canceled":
		case "suspended":
			return status;
		case "cancelled":
			return "canceled";
		default:
			return "reserved";
		}
	}

	private string NormalizeMarketplaceLeasePaymentStatus(string status, bool required)
	{
		status = (status ?? "").Trim().ToLowerInvariant().Replace("-", "_")
			.Replace(" ", "_");
		switch (status)
		{
		case "paid":
		case "payment_required":
		case "pending":
		case "failed":
		case "refunded":
		case "disputed":
		case "not_required":
			return status;
		default:
			return required ? "payment_required" : "not_required";
		}
	}

	private string GetEffectiveMarketplaceLeaseStatus(MarketplaceLeaseRecord lease)
	{
		if (lease == null)
		{
			return "none";
		}
		string status = NormalizeMarketplaceLeaseStatus(lease.Status);
		if (IsMarketplaceLeaseActiveStatus(status) && TryParseUtc(lease.ExpiresUtc, out var expiresUtc) && expiresUtc <= DateTimeOffset.UtcNow)
		{
			return "expired";
		}
		if (lease.LeaseRequired && lease.PaymentStatus == "payment_required" && status == "reserved")
		{
			return "pending_payment";
		}
		return status;
	}

	private static bool IsMarketplaceLeaseActiveStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant().Replace("-", "_")
			.Replace(" ", "_");
		int result;
		switch (status)
		{
		default:
			result = ((status == "grace") ? 1 : 0);
			break;
		case "active":
		case "free":
		case "trial":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private bool IsMarketplaceLeaseActive(MarketplaceLeaseRecord lease)
	{
		return IsMarketplaceLeaseActiveStatus(GetEffectiveMarketplaceLeaseStatus(lease));
	}

	private double ReadMarketplaceJsonDouble(JsonElement root, double fallback, params string[] names)
	{
		string[] array = names ?? Array.Empty<string>();
		foreach (string name in array)
		{
			if (TryGetMasterJsonProperty(root, name, out var value))
			{
				return ReadJsonDouble(value, fallback);
			}
		}
		return fallback;
	}

	private string HandleDeveloperProjectWorkflowGetRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string sessionId = NormalizeOptionalDeveloperProjectSessionId(GetQueryParameter(request, "sessionId"));
			string projectId = (GetQueryParameter(request, "projectId") ?? "").Trim();
			bool canLinkArbitraryRoot = IsDatabaseAdministrator(connection, request);
			return JsonSerializer.Serialize(BuildDeveloperProjectWorkflowPayload(ownerKey, sessionId, projectId, canLinkArbitraryRoot));
		}
		catch (Exception ex)
		{
			LogMessage("[Project Workflow] Load failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleDeveloperProjectWorkflowMutationRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			bool canLinkArbitraryRoot = IsDatabaseAdministrator(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			if (root.ValueKind != JsonValueKind.Object)
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Project workflow payload must be a JSON object."
				});
			}
			string action = (ExtractStringProperty(root, "action") ?? "upsert").Trim();
			string projectId = (ExtractStringProperty(root, "projectId") ?? ExtractStringProperty(root, "id") ?? "").Trim();
			string sessionId = NormalizeOptionalDeveloperProjectSessionId(ExtractStringProperty(root, "sessionId") ?? GetQueryParameter(request, "sessionId"));
			if (action.Equals("archive", StringComparison.OrdinalIgnoreCase))
			{
				if (string.IsNullOrWhiteSpace(projectId))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						error = "Project id is required."
					});
				}
				bool archived = false;
				lock (_chatSessionLock)
				{
					Table table = GetDeveloperProjectWorkspacesTable();
					for (int i = 0; i < table.Rows.Count; i++)
					{
						DeveloperProjectWorkspaceRecord record = DeveloperProjectWorkspaceRecordFromRow(table.Rows[i]);
						if (string.Equals(record.Id, projectId, StringComparison.OrdinalIgnoreCase) && string.Equals(record.OwnerKey, NormalizeChatFilesystemOwnerKey(ownerKey), StringComparison.OrdinalIgnoreCase))
						{
							record.Status = "archived";
							record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
							table.Rows[i] = DeveloperProjectWorkspaceRecordToRow(record);
							SaveChatSessionDataAndInvalidateCaches();
							archived = true;
							break;
						}
					}
				}
				if (!archived)
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						error = "Project workspace was not found."
					});
				}
				return JsonSerializer.Serialize(BuildDeveloperProjectWorkflowPayload(ownerKey, sessionId, "", canLinkArbitraryRoot));
			}
			bool useMirrorRoot = action.Equals("useMirrorRoot", StringComparison.OrdinalIgnoreCase);
			string requestedRoot = ExtractStringProperty(root, "workspaceRoot") ?? "";
			if (useMirrorRoot || string.IsNullOrWhiteSpace(requestedRoot))
			{
				requestedRoot = BuildDeveloperProjectMirrorRoot(sessionId);
			}
			if (!TryPrepareDeveloperProjectWorkspaceRoot(requestedRoot, sessionId, useMirrorRoot || string.IsNullOrWhiteSpace(ExtractStringProperty(root, "workspaceRoot")), out var workspaceRoot, out var rootError))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = rootError
				});
			}
			bool isMirrorRoot = IsDeveloperProjectMirrorRoot(workspaceRoot);
			bool alreadyAccessible = IsDeveloperProjectWorkspaceRootAccessible(ownerKey, workspaceRoot);
			if (!isMirrorRoot && !alreadyAccessible && !canLinkArbitraryRoot)
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Only an administrator can link a new local project root. Use the session mirror root or ask for filesystem access first."
				});
			}
			JsonElement makeAccessibleElement;
			bool makeAccessible = !root.TryGetProperty("makeAccessible", out makeAccessibleElement) || ReadJsonBool(makeAccessibleElement, fallback: true);
			DeveloperProjectWorkspaceRecord saved = SaveDeveloperProjectWorkspaceFromPayload(ownerKey, root, action, projectId, sessionId, workspaceRoot);
			if (makeAccessible && (isMirrorRoot || canLinkArbitraryRoot) && Directory.Exists(workspaceRoot))
			{
				SaveChatFilesystemAccess(ownerKey, workspaceRoot);
			}
			LogMessage("[Project Workflow] " + (string.IsNullOrWhiteSpace(projectId) ? "Saved" : "Updated") + " project workspace " + saved.Id + " at " + workspaceRoot + ".");
			return JsonSerializer.Serialize(BuildDeveloperProjectWorkflowPayload(ownerKey, saved.SessionId, saved.Id, canLinkArbitraryRoot));
		}
		catch (Exception ex)
		{
			LogMessage("[Project Workflow] Update failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleDeveloperSdkGetRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string sessionId = NormalizeOptionalDeveloperProjectSessionId(GetQueryParameter(request, "sessionId"));
			bool canLinkArbitraryRoot = IsDatabaseAdministrator(connection, request);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				surface = "SocketJack.DeveloperSdk",
				actions = new string[6] { "rent", "queue", "schedule", "run", "sync", "stop" },
				endpoints = new
				{
					sdk = "/api/developer-sdk",
					leases = "/api/marketplace/leases",
					workflow = "/api/developer-project-workflow",
					copilot = "/api/copilot-duplicator",
					attestation = "/api/hardware-attestation"
				},
				workflow = BuildDeveloperProjectWorkflowPayload(ownerKey, sessionId, "", canLinkArbitraryRoot),
				activeLease = BuildMarketplaceLeasePayload(FindActiveMarketplaceLease(ownerKey)),
				copilotDuplicator = BuildCopilotDuplicatorPayload()
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Developer SDK] Load failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleDeveloperSdkMutationRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			if (!identity.Authenticated && !identity.IsAdmin && !IsLocalAdmin(connection, request))
			{
				return BuildJsonError(request, 401, "Unauthorized", "Sign in before using the developer SDK workflow.");
			}
			string ownerKey = NormalizeCostOwnerKey(string.IsNullOrWhiteSpace(identity.OwnerKey) ? GetChatSessionOwnerKey(connection, request) : identity.OwnerKey);
			string userName = (string.IsNullOrWhiteSpace(identity.UserName) ? GetUserNameFromOwnerKey(ownerKey) : identity.UserName);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			if (root.ValueKind != JsonValueKind.Object)
			{
				return BuildJsonError(request, 400, "Bad Request", "Developer SDK payload must be a JSON object.");
			}
			string action = (ExtractStringProperty(root, "action") ?? "sync").Trim().ToLowerInvariant().Replace("-", "_")
				.Replace(" ", "_");
			string sessionId = NormalizeOptionalDeveloperProjectSessionId(ExtractStringProperty(root, "sessionId"));
			bool canLinkArbitraryRoot = IsDatabaseAdministrator(connection, request);
			switch (action)
			{
			default:
				if (!(action == "schedule"))
				{
					if (action == "run" || action == "use" || action == "select")
					{
						string leaseId = ExtractStringProperty(root, "leaseId") ?? "";
						MarketplaceLeaseRecord lease = (string.IsNullOrWhiteSpace(leaseId) ? FindActiveMarketplaceLease(ownerKey) : FindMarketplaceLeaseById(leaseId));
						if (lease == null || !CanAccessMarketplaceLease(lease, ownerKey, identity.IsAdmin))
						{
							return BuildJsonError(request, 404, "Not Found", "No accessible marketplace lease is available.");
						}
						if (!IsMarketplaceLeaseActive(lease))
						{
							return BuildJsonError(request, 409, "Conflict", "Only active marketplace leases can be used for run.");
						}
						ConfigureRemoteModelServerSelection(BuildRemoteModelSelectionFromMarketplaceLease(lease));
						RecordObservabilityEvent("project-workflow", "sdk run", "active", lease.Id, ownerKey, "/api/developer-sdk", 0L);
						return JsonSerializer.Serialize(new
						{
							ok = true,
							action = action,
							lease = BuildMarketplaceLeasePayload(lease),
							copilotDuplicator = BuildCopilotDuplicatorPayload()
						});
					}
					if (action == "sync" || action == "mirror")
					{
						string requestedRoot = ExtractStringProperty(root, "workspaceRoot") ?? BuildDeveloperProjectMirrorRoot(sessionId);
						bool useMirrorRoot = string.IsNullOrWhiteSpace(ExtractStringProperty(root, "workspaceRoot")) || ReadCopilotJsonBool(root, true, "useMirrorRoot");
						if (!TryPrepareDeveloperProjectWorkspaceRoot(requestedRoot, sessionId, useMirrorRoot, out var workspaceRoot, out var rootError))
						{
							return JsonSerializer.Serialize(new
							{
								ok = false,
								error = rootError
							});
						}
						DeveloperProjectWorkspaceRecord saved = SaveDeveloperProjectWorkspaceFromPayload(ownerKey, root, "activate", ExtractStringProperty(root, "projectId") ?? "", sessionId, workspaceRoot);
						if (Directory.Exists(workspaceRoot))
						{
							SaveChatFilesystemAccess(ownerKey, workspaceRoot);
						}
						RecordObservabilityEvent("project-workflow", "sdk sync", "linked", saved.Id, ownerKey, "/api/developer-sdk", 0L);
						return JsonSerializer.Serialize(BuildDeveloperProjectWorkflowPayload(ownerKey, saved.SessionId, saved.Id, canLinkArbitraryRoot));
					}
					if (action == "stop" || action == "end")
					{
						string leaseId2 = ExtractStringProperty(root, "leaseId") ?? "";
						MarketplaceLeaseRecord lease2 = (string.IsNullOrWhiteSpace(leaseId2) ? FindActiveMarketplaceLease(ownerKey) : FindMarketplaceLeaseById(leaseId2));
						if (lease2 == null || !CanAccessMarketplaceLease(lease2, ownerKey, identity.IsAdmin))
						{
							return BuildJsonError(request, 404, "Not Found", "No accessible marketplace lease is available.");
						}
						lease2.Status = "ended";
						lease2.EndedUtc = DateTimeOffset.UtcNow.ToString("O");
						lease2 = UpsertMarketplaceLease(lease2);
						int cleanedWorkspaces = CleanupDeveloperProjectWorkspacesForLease(ownerKey, lease2.Id);
						RecordObservabilityEvent("project-workflow", "sdk stop", "ended", lease2.Id, ownerKey, "/api/developer-sdk", 0L);
						return JsonSerializer.Serialize(new
						{
							ok = true,
							action = action,
							lease = BuildMarketplaceLeasePayload(lease2),
							cleanedWorkspaces = cleanedWorkspaces
						});
					}
					return BuildJsonError(request, 400, "Bad Request", "Unknown developer SDK action.");
				}
				goto case "rent";
			case "rent":
			case "reserve":
			case "queue":
			{
				MarketplaceLeaseRecord lease3 = BuildMarketplaceLeaseRecordFromRequest(root, ownerKey, userName);
				DateTimeOffset now = DateTimeOffset.UtcNow;
				lease3.OwnerKey = ownerKey;
				lease3.UserName = userName;
				lease3.QuoteUsd = CalculateMarketplaceLeaseQuoteUsd(lease3);
				lease3.Status = ((action == "queue") ? "queued" : ((action == "schedule") ? "scheduled" : (lease3.LeaseRequired ? "reserved" : "active")));
				lease3.PaymentStatus = (lease3.LeaseRequired ? "payment_required" : "not_required");
				if (!lease3.LeaseRequired && lease3.Status == "active")
				{
					lease3.StartedUtc = (string.IsNullOrWhiteSpace(lease3.StartedUtc) ? now.ToString("O") : lease3.StartedUtc);
					lease3.ExpiresUtc = now.AddMinutes(Math.Max(1L, lease3.LeaseMinutes)).ToString("O");
				}
				lease3.PolicyJson = NormalizeJsonObjectRawText(JsonSerializer.Serialize(BuildPeerRentalMarketplacePolicyPayload(ownerKey, BuildRemoteModelSelectionFromMarketplaceLease(lease3))));
				lease3 = UpsertMarketplaceLease(lease3);
				RecordObservabilityEvent("project-workflow", "sdk " + action, lease3.Status, lease3.Id, ownerKey, "/api/developer-sdk", 0L);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					action = action,
					lease = BuildMarketplaceLeasePayload(lease3),
					checkoutRequired = (lease3.LeaseRequired && lease3.PaymentStatus != "paid"),
					checkoutEndpoint = "/api/payments/checkout"
				});
			}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Developer SDK] Mutation failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private DeveloperProjectWorkspaceRecord SaveDeveloperProjectWorkspaceFromPayload(string ownerKey, JsonElement root, string action, string projectId, string sessionId, string workspaceRoot)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = NormalizeOptionalDeveloperProjectSessionId(sessionId);
		string now = DateTimeOffset.UtcNow.ToString("O");
		LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
		DeveloperProjectWorkspaceRecord saved = null;
		lock (_chatSessionLock)
		{
			Table table = GetDeveloperProjectWorkspacesTable();
			int existingIndex = -1;
			for (int i = 0; i < table.Rows.Count; i++)
			{
				DeveloperProjectWorkspaceRecord candidate = DeveloperProjectWorkspaceRecordFromRow(table.Rows[i]);
				if (!string.IsNullOrWhiteSpace(projectId) && string.Equals(candidate.Id, projectId, StringComparison.OrdinalIgnoreCase) && string.Equals(candidate.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
				{
					existingIndex = i;
					saved = candidate;
					break;
				}
			}
			if (saved == null && !string.IsNullOrWhiteSpace(sessionId))
			{
				for (int j = 0; j < table.Rows.Count; j++)
				{
					DeveloperProjectWorkspaceRecord candidate2 = DeveloperProjectWorkspaceRecordFromRow(table.Rows[j]);
					if (string.Equals(candidate2.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) && string.Equals(candidate2.SessionId, sessionId, StringComparison.Ordinal) && !string.Equals(NormalizeDeveloperProjectStatus(candidate2.Status), "archived", StringComparison.OrdinalIgnoreCase))
					{
						existingIndex = j;
						saved = candidate2;
						break;
					}
				}
			}
			if (saved == null)
			{
				saved = new DeveloperProjectWorkspaceRecord
				{
					Id = (string.IsNullOrWhiteSpace(projectId) ? ("project_" + Guid.NewGuid().ToString("N")) : projectId.Trim()),
					OwnerKey = ownerKey,
					CreatedUtc = now
				};
			}
			saved.OwnerKey = ownerKey;
			saved.SessionId = sessionId;
			saved.WorkspaceRoot = workspaceRoot ?? "";
			saved.Name = ExtractStringProperty(root, "name") ?? saved.Name;
			if (string.IsNullOrWhiteSpace(saved.Name) || saved.Name.Equals("Project Workspace", StringComparison.OrdinalIgnoreCase))
			{
				saved.Name = BuildDeveloperProjectDefaultName(ownerKey, sessionId);
			}
			saved.LeaseId = ExtractStringProperty(root, "leaseId") ?? saved.LeaseId ?? "";
			saved.Status = NormalizeDeveloperProjectStatus(ExtractStringProperty(root, "status") ?? (action.Equals("activate", StringComparison.OrdinalIgnoreCase) ? "active" : saved.Status));
			saved.Notes = ExtractStringProperty(root, "notes") ?? saved.Notes ?? "";
			saved.RemoteServerId = (selection.Enabled ? (selection.ServerId ?? "") : "");
			saved.RemoteServerName = (selection.Enabled ? (selection.ServerName ?? "") : "");
			saved.RemoteOwnerUserName = (selection.Enabled ? (selection.OwnerUserName ?? "") : "");
			saved.RemoteEndpoint = (selection.Enabled ? (selection.Endpoint ?? "") : "");
			saved.RemoteOpenAiBaseUrl = (selection.Enabled ? (selection.OpenAiBaseUrl ?? "") : "");
			if (TryReadDeveloperProjectFilesystemContext(root, out var contextMode, out var contextRootsJson))
			{
				saved.FilesystemContextMode = contextMode;
				saved.FilesystemContextRootsJson = contextRootsJson;
			}
			saved.FileQuotaBytes = Math.Max(0L, ReadCopilotJsonLong(root, (saved.FileQuotaBytes <= 0) ? 2147483648u : saved.FileQuotaBytes, "fileQuotaBytes", "quotaBytes", "storageQuotaBytes"));
			saved.CommandPolicy = NormalizeDeveloperProjectCommandPolicy(ExtractStringProperty(root, "commandPolicy") ?? saved.CommandPolicy);
			saved.NetworkPolicy = NormalizeDeveloperProjectNetworkPolicy(ExtractStringProperty(root, "networkPolicy") ?? saved.NetworkPolicy);
			saved.SecretsVaultEnabled = ReadCopilotJsonBool(root, saved.SecretsVaultEnabled, "secretsVaultEnabled", "secretsVault", "secretVault");
			saved.CleanupOnLeaseEnd = ReadCopilotJsonBool(root, saved.CleanupOnLeaseEnd, "cleanupOnLeaseEnd", "cleanupOnEnd", "deleteOnLeaseEnd");
			saved.MetadataJson = BuildDeveloperProjectMetadataJson(selection);
			saved.UpdatedUtc = now;
			if (existingIndex >= 0)
			{
				table.Rows[existingIndex] = DeveloperProjectWorkspaceRecordToRow(saved);
			}
			else
			{
				table.Rows.Add(DeveloperProjectWorkspaceRecordToRow(saved));
			}
			SaveChatSessionDataAndInvalidateCaches();
		}
		return saved;
	}

	private int CleanupDeveloperProjectWorkspacesForLease(string ownerKey, string leaseId)
	{
		if (string.IsNullOrWhiteSpace(leaseId))
		{
			return 0;
		}
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		int cleaned = 0;
		lock (_chatSessionLock)
		{
			Table table = GetDeveloperProjectWorkspacesTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				DeveloperProjectWorkspaceRecord record = DeveloperProjectWorkspaceRecordFromRow(table.Rows[i]);
				if (!string.Equals(record.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) || !string.Equals(record.LeaseId, leaseId, StringComparison.OrdinalIgnoreCase) || !record.CleanupOnLeaseEnd)
				{
					continue;
				}
				record.Status = "archived";
				record.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
				record.Notes = AppendDeveloperProjectNote(record.Notes, "Archived automatically after lease end.");
				if (IsDeveloperProjectMirrorRoot(record.WorkspaceRoot))
				{
					try
					{
						if (Directory.Exists(record.WorkspaceRoot))
						{
							Directory.Delete(record.WorkspaceRoot, recursive: true);
						}
						record.Notes = AppendDeveloperProjectNote(record.Notes, "Session mirror root deleted.");
					}
					catch (Exception ex)
					{
						record.Notes = AppendDeveloperProjectNote(record.Notes, "Session mirror cleanup failed: " + ex.Message);
					}
				}
				table.Rows[i] = DeveloperProjectWorkspaceRecordToRow(record);
				cleaned++;
			}
			if (cleaned > 0)
			{
				SaveChatSessionDataAndInvalidateCaches();
			}
		}
		return cleaned;
	}

	private string AppendDeveloperProjectNote(string existing, string note)
	{
		note = (note ?? "").Trim();
		if (string.IsNullOrWhiteSpace(note))
		{
			return existing ?? "";
		}
		if (string.IsNullOrWhiteSpace(existing))
		{
			return note;
		}
		return existing.Trim() + " " + note;
	}

	private object BuildDeveloperProjectWorkflowPayload(string ownerKey, string sessionId, string projectId, bool canLinkArbitraryRoot)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = NormalizeOptionalDeveloperProjectSessionId(sessionId);
		projectId = (projectId ?? "").Trim();
		List<DeveloperProjectWorkspaceRecord> projects;
		lock (_chatSessionLock)
		{
			projects = new List<DeveloperProjectWorkspaceRecord>();
			Table table = GetDeveloperProjectWorkspacesTable();
			foreach (object[] row in table.Rows)
			{
				DeveloperProjectWorkspaceRecord record = DeveloperProjectWorkspaceRecordFromRow(row);
				if (string.Equals(record.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) && !string.Equals(NormalizeDeveloperProjectStatus(record.Status), "archived", StringComparison.OrdinalIgnoreCase))
				{
					projects.Add(record);
				}
			}
		}
		projects.Sort((DeveloperProjectWorkspaceRecord a, DeveloperProjectWorkspaceRecord b) => string.CompareOrdinal(b.UpdatedUtc ?? "", a.UpdatedUtc ?? ""));
		DeveloperProjectWorkspaceRecord active = projects.FirstOrDefault((DeveloperProjectWorkspaceRecord project) => !string.IsNullOrWhiteSpace(projectId) && string.Equals(project.Id, projectId, StringComparison.OrdinalIgnoreCase));
		if (active == null && !string.IsNullOrWhiteSpace(sessionId))
		{
			active = projects.FirstOrDefault((DeveloperProjectWorkspaceRecord project) => string.Equals(project.SessionId, sessionId, StringComparison.Ordinal));
		}
		if (active == null)
		{
			active = projects.FirstOrDefault((DeveloperProjectWorkspaceRecord project) => string.Equals(NormalizeDeveloperProjectStatus(project.Status), "active", StringComparison.OrdinalIgnoreCase));
		}
		DeveloperProjectWorkspaceRecord suggested = BuildSuggestedDeveloperProjectWorkspace(ownerKey, sessionId);
		string effectiveSessionId = ((!string.IsNullOrWhiteSpace(sessionId)) ? sessionId : (active?.SessionId ?? ""));
		object cloneSummary = BuildDeveloperProjectCloneSummary(ownerKey, effectiveSessionId);
		object monitoring = BuildDeveloperProjectWorkflowMonitoringPayload(ownerKey, effectiveSessionId, active);
		return new
		{
			ok = true,
			ownerKey = ownerKey,
			sessionId = effectiveSessionId,
			table = "SocketJack.LmVsProxyProjectWorkspaces",
			canUseMirrorRoot = true,
			canLinkArbitraryRoot = canLinkArbitraryRoot,
			mirrorRoot = BuildDeveloperProjectMirrorRoot(effectiveSessionId),
			activeProject = ((active == null) ? null : BuildDeveloperProjectWorkspacePayload(active)),
			suggestedProject = BuildDeveloperProjectWorkspacePayload(suggested),
			projects = projects.Select(BuildDeveloperProjectWorkspacePayload).ToList(),
			rootSuggestions = BuildDeveloperProjectRootSuggestions(ownerKey, effectiveSessionId, active),
			filesystemContext = BuildDeveloperProjectFilesystemContextPayload(ownerKey, effectiveSessionId, active),
			cloneSummary = cloneSummary,
			monitoring = monitoring,
			marketplaceLease = BuildMarketplaceLeasePayload(FindActiveMarketplaceLease(ownerKey)),
			copilotDuplicator = BuildCopilotDuplicatorPayload()
		};
	}

	private DeveloperProjectWorkspaceRecord DeveloperProjectWorkspaceRecordFromRow(object[] row)
	{
		row = NormalizeDeveloperProjectWorkspaceRow(row);
		return new DeveloperProjectWorkspaceRecord
		{
			Id = GetRowValue(row, 0),
			OwnerKey = GetRowValue(row, 1),
			Name = GetRowValue(row, 2),
			WorkspaceRoot = GetRowValue(row, 3),
			SessionId = GetRowValue(row, 4),
			RemoteServerId = GetRowValue(row, 5),
			RemoteServerName = GetRowValue(row, 6),
			RemoteOwnerUserName = GetRowValue(row, 7),
			RemoteEndpoint = GetRowValue(row, 8),
			RemoteOpenAiBaseUrl = GetRowValue(row, 9),
			LeaseId = GetRowValue(row, 10),
			Status = NormalizeDeveloperProjectStatus(GetRowValue(row, 11)),
			CreatedUtc = GetRowValue(row, 12),
			UpdatedUtc = GetRowValue(row, 13),
			Notes = GetRowValue(row, 14),
			MetadataJson = GetRowValue(row, 15),
			FilesystemContextMode = NormalizeDeveloperProjectFilesystemContextMode(GetRowValue(row, 16)),
			FilesystemContextRootsJson = NormalizeJsonArrayRawText(GetRowValue(row, 17)),
			FileQuotaBytes = ReadLongInvariant(GetRowValue(row, 18), 2147483648L),
			CommandPolicy = NormalizeDeveloperProjectCommandPolicy(GetRowValue(row, 19)),
			NetworkPolicy = NormalizeDeveloperProjectNetworkPolicy(GetRowValue(row, 20)),
			SecretsVaultEnabled = ParseBoolString(GetRowValue(row, 21), fallback: true),
			CleanupOnLeaseEnd = ParseBoolString(GetRowValue(row, 22), fallback: true)
		};
	}

	private object[] DeveloperProjectWorkspaceRecordToRow(DeveloperProjectWorkspaceRecord record)
	{
		record = record ?? new DeveloperProjectWorkspaceRecord();
		return NormalizeDeveloperProjectWorkspaceRow(new object[23]
		{
			record.Id ?? "",
			NormalizeChatFilesystemOwnerKey(record.OwnerKey),
			string.IsNullOrWhiteSpace(record.Name) ? "Project Workspace" : record.Name.Trim(),
			record.WorkspaceRoot ?? "",
			NormalizeOptionalDeveloperProjectSessionId(record.SessionId),
			record.RemoteServerId ?? "",
			record.RemoteServerName ?? "",
			record.RemoteOwnerUserName ?? "",
			record.RemoteEndpoint ?? "",
			record.RemoteOpenAiBaseUrl ?? "",
			record.LeaseId ?? "",
			NormalizeDeveloperProjectStatus(record.Status),
			record.CreatedUtc ?? "",
			record.UpdatedUtc ?? "",
			record.Notes ?? "",
			string.IsNullOrWhiteSpace(record.MetadataJson) ? "{}" : record.MetadataJson,
			NormalizeDeveloperProjectFilesystemContextMode(record.FilesystemContextMode),
			NormalizeJsonArrayRawText(record.FilesystemContextRootsJson),
			Math.Max(0L, record.FileQuotaBytes).ToString(CultureInfo.InvariantCulture),
			NormalizeDeveloperProjectCommandPolicy(record.CommandPolicy),
			NormalizeDeveloperProjectNetworkPolicy(record.NetworkPolicy),
			record.SecretsVaultEnabled ? "true" : "false",
			record.CleanupOnLeaseEnd ? "true" : "false"
		});
	}

	private object BuildDeveloperProjectWorkspacePayload(DeveloperProjectWorkspaceRecord record)
	{
		if (record == null)
		{
			return null;
		}
		string root = record.WorkspaceRoot ?? "";
		bool rootExists = false;
		try
		{
			rootExists = !string.IsNullOrWhiteSpace(root) && Directory.Exists(root);
		}
		catch
		{
		}
		return new
		{
			id = (record.Id ?? ""),
			ownerKey = (record.OwnerKey ?? ""),
			name = (record.Name ?? "Project Workspace"),
			workspaceRoot = root,
			rootExists = rootExists,
			sessionId = (record.SessionId ?? ""),
			leaseId = (record.LeaseId ?? ""),
			status = NormalizeDeveloperProjectStatus(record.Status),
			remoteServerId = (record.RemoteServerId ?? ""),
			remoteServerName = (record.RemoteServerName ?? ""),
			remoteOwnerUserName = (record.RemoteOwnerUserName ?? ""),
			remoteEndpoint = (record.RemoteEndpoint ?? ""),
			remoteOpenAiBaseUrl = (record.RemoteOpenAiBaseUrl ?? ""),
			createdUtc = (record.CreatedUtc ?? ""),
			updatedUtc = (record.UpdatedUtc ?? ""),
			notes = (record.Notes ?? ""),
			filesystemContextMode = NormalizeDeveloperProjectFilesystemContextMode(record.FilesystemContextMode),
			filesystemContextRoots = DeserializeJsonElement(NormalizeJsonArrayRawText(record.FilesystemContextRootsJson), "[]"),
			sandbox = new
			{
				isolated = true,
				fileQuotaBytes = Math.Max(0L, record.FileQuotaBytes),
				commandPolicy = NormalizeDeveloperProjectCommandPolicy(record.CommandPolicy),
				networkPolicy = NormalizeDeveloperProjectNetworkPolicy(record.NetworkPolicy),
				secretsVaultEnabled = record.SecretsVaultEnabled,
				cleanupOnLeaseEnd = record.CleanupOnLeaseEnd
			},
			metadata = DeserializeJsonElement(record.MetadataJson, "{}")
		};
	}

	private DeveloperProjectWorkspaceRecord BuildSuggestedDeveloperProjectWorkspace(string ownerKey, string sessionId)
	{
		sessionId = NormalizeOptionalDeveloperProjectSessionId(sessionId);
		return new DeveloperProjectWorkspaceRecord
		{
			Id = "",
			OwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey),
			Name = BuildDeveloperProjectDefaultName(ownerKey, sessionId),
			WorkspaceRoot = BuildDeveloperProjectMirrorRoot(sessionId),
			SessionId = sessionId,
			Status = "suggested",
			FilesystemContextMode = "none",
			FilesystemContextRootsJson = "[]",
			FileQuotaBytes = 2147483648L,
			CommandPolicy = "restricted",
			NetworkPolicy = "deny-private",
			SecretsVaultEnabled = true,
			CleanupOnLeaseEnd = true,
			CreatedUtc = "",
			UpdatedUtc = ""
		};
	}

	private List<object> BuildDeveloperProjectRootSuggestions(string ownerKey, string sessionId, DeveloperProjectWorkspaceRecord active)
	{
		List<object> suggestions = new List<object>();
		List<string> seen = new List<string>();
		AddDeveloperProjectRootSuggestion(suggestions, seen, "Session mirror", BuildDeveloperProjectMirrorRoot(sessionId), "mirror", createable: true);
		if (active != null)
		{
			AddDeveloperProjectRootSuggestion(suggestions, seen, "Active project", active.WorkspaceRoot, "project", createable: false);
		}
		try
		{
			AddDeveloperProjectRootSuggestion(suggestions, seen, "Current directory", Directory.GetCurrentDirectory(), "cwd", createable: false);
		}
		catch
		{
		}
		foreach (string root in GetActiveSolutionRoots())
		{
			AddDeveloperProjectRootSuggestion(suggestions, seen, "Solution root", root, "solution", createable: false);
		}
		foreach (ChatFilesystemAccessEntry item in GetChatFilesystemAccess(ownerKey))
		{
			AddDeveloperProjectRootSuggestion(suggestions, seen, "Approved root", item?.path, "approved", createable: false);
		}
		return suggestions;
	}

	private void AddDeveloperProjectRootSuggestion(List<object> suggestions, List<string> seen, string label, string path, string source, bool createable)
	{
		if (suggestions == null || seen == null || string.IsNullOrWhiteSpace(path))
		{
			return;
		}
		string full;
		try
		{
			full = Path.GetFullPath(Environment.ExpandEnvironmentVariables(path.Trim().Trim('"')));
		}
		catch
		{
			return;
		}
		foreach (string existing in seen)
		{
			if (PathsEqual(existing, full))
			{
				return;
			}
		}
		seen.Add(full);
		bool exists = false;
		try
		{
			exists = Directory.Exists(full);
		}
		catch
		{
		}
		suggestions.Add(new
		{
			label = label,
			source = source,
			path = full,
			exists = exists,
			createable = createable
		});
	}

	private object BuildDeveloperProjectCloneSummary(string ownerKey, string sessionId)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = NormalizeOptionalDeveloperProjectSessionId(sessionId);
		List<RemoteSessionFileCloneSnapshot> clones = (from remoteSessionFileCloneSnapshot in GetRemoteSessionFileClones()
			where remoteSessionFileCloneSnapshot != null && (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(remoteSessionFileCloneSnapshot.OwnerKey) || string.Equals(remoteSessionFileCloneSnapshot.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase)) && (string.IsNullOrWhiteSpace(sessionId) || string.Equals(remoteSessionFileCloneSnapshot.SessionId ?? "", sessionId, StringComparison.Ordinal))
			select remoteSessionFileCloneSnapshot).ToList();
		int downloading = 0;
		int completed = 0;
		int failed = 0;
		int canceled = 0;
		int changed = 0;
		long bytes = 0L;
		string latest = "";
		foreach (RemoteSessionFileCloneSnapshot clone in clones)
		{
			string status = clone.Status ?? "";
			if (status.Equals("Downloading", StringComparison.OrdinalIgnoreCase) || status.Equals("Canceling", StringComparison.OrdinalIgnoreCase))
			{
				downloading++;
			}
			else if (status.Equals("Completed", StringComparison.OrdinalIgnoreCase))
			{
				completed++;
			}
			else if (status.Equals("Failed", StringComparison.OrdinalIgnoreCase) || status.Equals("Missing", StringComparison.OrdinalIgnoreCase))
			{
				failed++;
			}
			if (clone.Canceled || status.Equals("Canceled", StringComparison.OrdinalIgnoreCase))
			{
				canceled++;
			}
			if (clone.ChangedLocally)
			{
				changed++;
			}
			bytes += Math.Max(0L, clone.Bytes);
			if (string.CompareOrdinal(clone.UpdatedUtc ?? "", latest) > 0)
			{
				latest = clone.UpdatedUtc ?? "";
			}
		}
		return new
		{
			total = clones.Count,
			downloading = downloading,
			completed = completed,
			failed = failed,
			canceled = canceled,
			changed = changed,
			bytes = bytes,
			latestUpdatedUtc = latest,
			clones = (from remoteSessionFileCloneSnapshot in clones.Take(20)
				select new
				{
					id = remoteSessionFileCloneSnapshot.Id,
					fileName = remoteSessionFileCloneSnapshot.FileName,
					remotePath = remoteSessionFileCloneSnapshot.RemotePath,
					localPath = remoteSessionFileCloneSnapshot.LocalPath,
					sandboxSessionId = remoteSessionFileCloneSnapshot.SandboxSessionId,
					sandboxFileId = remoteSessionFileCloneSnapshot.SandboxFileId,
					sandboxPath = remoteSessionFileCloneSnapshot.SandboxPath,
					status = remoteSessionFileCloneSnapshot.Status,
					bytes = remoteSessionFileCloneSnapshot.Bytes,
					sha256 = remoteSessionFileCloneSnapshot.Sha256,
					changedLocally = remoteSessionFileCloneSnapshot.ChangedLocally,
					updatedUtc = remoteSessionFileCloneSnapshot.UpdatedUtc
				}).ToList()
		};
	}

	private object BuildDeveloperProjectWorkflowMonitoringPayload(string ownerKey, string sessionId, DeveloperProjectWorkspaceRecord active)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = NormalizeOptionalDeveloperProjectSessionId(sessionId);
		string root = ((active != null && !string.IsNullOrWhiteSpace(active.WorkspaceRoot)) ? active.WorkspaceRoot : BuildDeveloperProjectMirrorRoot(sessionId));
		bool workspaceExists = false;
		try
		{
			workspaceExists = !string.IsNullOrWhiteSpace(root) && Directory.Exists(root);
		}
		catch
		{
		}
		bool workspaceAccessible = workspaceExists && IsDeveloperProjectWorkspaceRootAccessible(ownerKey, root);
		LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
		MarketplaceLeaseRecord activeLease = FindActiveMarketplaceLease(ownerKey);
		string contextMode = ((active == null) ? "none" : NormalizeDeveloperProjectFilesystemContextMode(active.FilesystemContextMode));
		int contextRootCount = CountDeveloperProjectFilesystemContextRoots(active);
		List<RemoteSessionFileCloneSnapshot> clones = (from clone in GetRemoteSessionFileClones()
			where clone != null && (string.IsNullOrWhiteSpace(ownerKey) || string.IsNullOrWhiteSpace(clone.OwnerKey) || string.Equals(clone.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase)) && (string.IsNullOrWhiteSpace(sessionId) || string.Equals(clone.SessionId ?? "", sessionId, StringComparison.Ordinal))
			select clone).ToList();
		int totalClones = clones.Count;
		int incompleteClones = clones.Count((RemoteSessionFileCloneSnapshot clone) => clone != null && !string.Equals(clone.Status ?? "", "Completed", StringComparison.OrdinalIgnoreCase) && !string.Equals(clone.Status ?? "", "Canceled", StringComparison.OrdinalIgnoreCase));
		int changedClones = clones.Count((RemoteSessionFileCloneSnapshot clone) => clone?.ChangedLocally ?? false);
		int score = 100;
		if (active == null)
		{
			score -= 12;
		}
		if (!workspaceExists)
		{
			score -= 22;
		}
		if (workspaceExists && !workspaceAccessible)
		{
			score -= 18;
		}
		if ((selection == null || !selection.Enabled) && activeLease == null)
		{
			score -= 6;
		}
		if (contextMode == "none")
		{
			score -= 6;
		}
		if (incompleteClones > 0)
		{
			score -= Math.Min(16, incompleteClones * 4);
		}
		if (changedClones > 0)
		{
			score -= Math.Min(10, changedClones * 2);
		}
		if (active != null && (active.FileQuotaBytes <= 0 || NormalizeDeveloperProjectCommandPolicy(active.CommandPolicy) == "none" || NormalizeDeveloperProjectNetworkPolicy(active.NetworkPolicy) == "none"))
		{
			score -= 10;
		}
		score = Math.Max(0, Math.Min(100, score));
		return new
		{
			ownerKey = ownerKey,
			sessionId = sessionId,
			workspaceRoot = root,
			workspaceExists = workspaceExists,
			workspaceAccessible = workspaceAccessible,
			activeProjectId = (active?.Id ?? ""),
			activeProjectStatus = ((active == null) ? "suggested" : NormalizeDeveloperProjectStatus(active.Status)),
			usingRemoteServer = (selection?.Enabled ?? false),
			activeLeaseId = (activeLease?.Id ?? ""),
			activeLeaseStatus = ((activeLease == null) ? "none" : GetEffectiveMarketplaceLeaseStatus(activeLease)),
			remoteServerName = ((selection != null) ? (selection.ServerName ?? "") : ""),
			remoteOwnerUserName = ((selection != null) ? (selection.OwnerUserName ?? "") : ""),
			filesystemContextMode = contextMode,
			filesystemContextRootCount = contextRootCount,
			mirroredFiles = totalClones,
			incompleteMirrors = incompleteClones,
			changedMirrors = changedClones,
			sandbox = new
			{
				isolated = true,
				fileQuotaBytes = (active?.FileQuotaBytes ?? 2147483648u),
				commandPolicy = NormalizeDeveloperProjectCommandPolicy(active?.CommandPolicy),
				networkPolicy = NormalizeDeveloperProjectNetworkPolicy(active?.NetworkPolicy),
				secretsVaultEnabled = (active?.SecretsVaultEnabled ?? true),
				cleanupOnLeaseEnd = (active?.CleanupOnLeaseEnd ?? true)
			},
			readinessScore = score,
			readinessTier = BuildDeveloperProjectReadinessTier(score),
			generatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
	}

	private object BuildDeveloperProjectWorkflowFleetMonitoringPayload()
	{
		int total = 0;
		int active = 0;
		int missingRoots = 0;
		int remoteLinked = 0;
		int contextEnabled = 0;
		int leaseLinked = 0;
		lock (_chatSessionLock)
		{
			Table table = GetDeveloperProjectWorkspacesTable();
			foreach (object[] row in table.Rows)
			{
				DeveloperProjectWorkspaceRecord record = DeveloperProjectWorkspaceRecordFromRow(row);
				if (string.Equals(NormalizeDeveloperProjectStatus(record.Status), "archived", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				total++;
				if (string.Equals(NormalizeDeveloperProjectStatus(record.Status), "active", StringComparison.OrdinalIgnoreCase))
				{
					active++;
				}
				try
				{
					if (string.IsNullOrWhiteSpace(record.WorkspaceRoot) || !Directory.Exists(record.WorkspaceRoot))
					{
						missingRoots++;
					}
				}
				catch
				{
					missingRoots++;
				}
				if (!string.IsNullOrWhiteSpace(record.RemoteOpenAiBaseUrl) || !string.IsNullOrWhiteSpace(record.RemoteServerId))
				{
					remoteLinked++;
				}
				if (!string.IsNullOrWhiteSpace(record.LeaseId))
				{
					leaseLinked++;
				}
				if (NormalizeDeveloperProjectFilesystemContextMode(record.FilesystemContextMode) != "none")
				{
					contextEnabled++;
				}
			}
		}
		int score = ((total <= 0) ? 90 : Math.Max(0, Math.Min(100, 100 - missingRoots * 18)));
		return new
		{
			totalProjects = total,
			activeProjects = active,
			missingRoots = missingRoots,
			remoteLinkedProjects = remoteLinked,
			leaseLinkedProjects = leaseLinked,
			filesystemContextEnabledProjects = contextEnabled,
			workflowScore = score,
			workflowTier = BuildDeveloperProjectReadinessTier(score),
			generatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
	}

	private static string BuildDeveloperProjectReadinessTier(int score)
	{
		if (score >= 90)
		{
			return "Ready";
		}
		if (score >= 75)
		{
			return "Watch";
		}
		if (score >= 55)
		{
			return "Needs Setup";
		}
		return "Blocked";
	}

	private int CountDeveloperProjectFilesystemContextRoots(DeveloperProjectWorkspaceRecord active)
	{
		if (active == null)
		{
			return 0;
		}
		if (NormalizeDeveloperProjectFilesystemContextMode(active.FilesystemContextMode) == "all")
		{
			return -1;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(NormalizeJsonArrayRawText(active.FilesystemContextRootsJson));
			return (document.RootElement.ValueKind == JsonValueKind.Array) ? document.RootElement.GetArrayLength() : 0;
		}
		catch
		{
			return 0;
		}
	}

	private string BuildDeveloperProjectMirrorRoot(string sessionId)
	{
		return GetRemoteSessionCloneDirectory(sessionId);
	}

	private bool TryPrepareDeveloperProjectWorkspaceRoot(string requestedRoot, string sessionId, bool createIfMissing, out string workspaceRoot, out string error)
	{
		workspaceRoot = null;
		error = null;
		try
		{
			workspaceRoot = Path.GetFullPath(Environment.ExpandEnvironmentVariables((requestedRoot ?? "").Trim().Trim('"')));
			if (string.IsNullOrWhiteSpace(workspaceRoot))
			{
				error = "Workspace root is required.";
				return false;
			}
			if (createIfMissing)
			{
				if (!IsDeveloperProjectMirrorRoot(workspaceRoot))
				{
					error = "Only session mirror roots can be created automatically.";
					return false;
				}
				Directory.CreateDirectory(workspaceRoot);
				return true;
			}
			if (!Directory.Exists(workspaceRoot))
			{
				error = "Workspace root does not exist: " + workspaceRoot;
				return false;
			}
			return true;
		}
		catch (Exception ex)
		{
			error = "Invalid workspace root: " + ex.Message;
			return false;
		}
	}

	private bool IsDeveloperProjectMirrorRoot(string path)
	{
		if (string.IsNullOrWhiteSpace(path) || string.IsNullOrWhiteSpace(_remoteSessionCloneRoot))
		{
			return false;
		}
		try
		{
			return IsPathInsideRoot(path, _remoteSessionCloneRoot);
		}
		catch
		{
			return false;
		}
	}

	private bool IsDeveloperProjectWorkspaceRootAccessible(string ownerKey, string workspaceRoot)
	{
		if (string.IsNullOrWhiteSpace(workspaceRoot))
		{
			return false;
		}
		if (IsDeveloperProjectMirrorRoot(workspaceRoot))
		{
			return true;
		}
		foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(ownerKey))
		{
			if (entry != null && !string.IsNullOrWhiteSpace(entry.path) && IsPathInsideRoot(workspaceRoot, entry.path))
			{
				return true;
			}
		}
		return false;
	}

	private string BuildDeveloperProjectDefaultName(string ownerKey, string sessionId)
	{
		string title = GetChatSessionTitleForOwner(ownerKey, sessionId);
		if (!string.IsNullOrWhiteSpace(title))
		{
			return title;
		}
		if (!string.IsNullOrWhiteSpace(sessionId))
		{
			return "Project " + sessionId.Trim();
		}
		return "Project Workspace";
	}

	private string GetChatSessionTitleForOwner(string ownerKey, string sessionId)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = NormalizeOptionalDeveloperProjectSessionId(sessionId);
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return "";
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal) && ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
				{
					return GetRowValue(row, 1);
				}
			}
		}
		return "";
	}

	private string NormalizeOptionalDeveloperProjectSessionId(string sessionId)
	{
		return string.IsNullOrWhiteSpace(sessionId) ? "" : SanitizeFileName(sessionId.Trim());
	}

	private string NormalizeDeveloperProjectStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant();
		if (status == "paused" || status == "archived" || status == "suggested")
		{
			return status;
		}
		return "active";
	}

	private string NormalizeDeveloperProjectFilesystemContextMode(string mode)
	{
		mode = (mode ?? "").Trim().ToLowerInvariant();
		return (mode == "all" || mode == "selected") ? mode : "none";
	}

	private string NormalizeDeveloperProjectCommandPolicy(string policy)
	{
		policy = (policy ?? "").Trim().ToLowerInvariant().Replace("_", "-");
		switch (policy)
		{
		default:
			if (!(policy == "approved-only"))
			{
				return "restricted";
			}
			goto case "none";
		case "none":
		case "read-only":
		case "restricted":
			return policy;
		}
	}

	private string NormalizeDeveloperProjectNetworkPolicy(string policy)
	{
		policy = (policy ?? "").Trim().ToLowerInvariant().Replace("_", "-");
		switch (policy)
		{
		default:
			if (!(policy == "approved-only"))
			{
				return "deny-private";
			}
			goto case "none";
		case "none":
		case "offline":
		case "deny-private":
			return policy;
		}
	}

	private static long ReadLongInvariant(string value, long fallback)
	{
		long parsed;
		return long.TryParse((value ?? "").Trim(), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : fallback;
	}

	private static bool ParseBoolString(string value, bool fallback)
	{
		if (bool.TryParse((value ?? "").Trim(), out var parsed))
		{
			return parsed;
		}
		if (string.Equals(value, "1", StringComparison.OrdinalIgnoreCase) || string.Equals(value, "yes", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		if (string.Equals(value, "0", StringComparison.OrdinalIgnoreCase) || string.Equals(value, "no", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		return fallback;
	}

	private bool TryReadDeveloperProjectFilesystemContext(JsonElement root, out string mode, out string rootsJson)
	{
		mode = "none";
		rootsJson = "[]";
		if (root.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		if (!root.TryGetProperty("filesystemContext", out var _) && !root.TryGetProperty("filesystemContextMode", out var value) && !root.TryGetProperty("filesystemContextRoots", out value) && !root.TryGetProperty("selectedFilesystemContextRoots", out value))
		{
			return false;
		}
		mode = NormalizeDeveloperProjectFilesystemContextMode(ReadAgentFilesystemContextMode(root));
		rootsJson = JsonSerializer.Serialize(ReadAgentFilesystemContextRootSelection(root));
		return true;
	}

	private object BuildDeveloperProjectFilesystemContextPayload(string ownerKey, string sessionId, DeveloperProjectWorkspaceRecord active)
	{
		string mode = ((active == null) ? "none" : NormalizeDeveloperProjectFilesystemContextMode(active.FilesystemContextMode));
		string rootsJson = ((active == null) ? "[]" : NormalizeJsonArrayRawText(active.FilesystemContextRootsJson));
		return new
		{
			mode = mode,
			roots = DeserializeJsonElement(rootsJson, "[]"),
			availableRoots = BuildAgentFilesystemContextRootOptions(ownerKey, sessionId)
		};
	}

