	private string HandleServerBrowserCheckoutRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			LmVsProxyServerProfile profile = GetServerBrowserProfile();
			string customerEmail = "";
			string clientReferenceId = "";
			string successUrl = "";
			string cancelUrl = "";
			string modelId = "";
			if (!string.IsNullOrWhiteSpace(request?.Body))
			{
				using JsonDocument document = JsonDocument.Parse(request.Body);
				JsonElement root = document.RootElement;
				if (root.ValueKind == JsonValueKind.Object)
				{
					customerEmail = ExtractStringProperty(root, "customerEmail") ?? "";
					clientReferenceId = ExtractStringProperty(root, "clientReferenceId") ?? "";
					successUrl = ExtractStringProperty(root, "successUrl") ?? "";
					cancelUrl = ExtractStringProperty(root, "cancelUrl") ?? "";
					modelId = FirstNonEmpty(ExtractStringProperty(root, "modelId"), ExtractStringProperty(root, "model"), ExtractStringProperty(root, "selectedModel"));
				}
			}
			List<ChatUiModelInfo> checkoutModels = BuildServerBrowserModelCapabilities(profile);
			ChatUiModelInfo checkoutModel = FindServerBrowserCheckoutModel(checkoutModels, modelId);
			bool modelRequiresPayment = checkoutModel != null &&
				(checkoutModel.requiresPayment || !string.IsNullOrWhiteSpace(checkoutModel.stripePriceId) || checkoutModel.stripeUnitAmountCents > 0);
			bool paymentRequired = profile.RequiresPayment || modelRequiresPayment;
			if (!paymentRequired)
			{
				return JsonSerializer.Serialize(new
				{
					ok = true,
					paymentRequired = false,
					message = "This LmVsProxy host does not require Stripe checkout."
				});
			}
			string checkoutStripePriceId = FirstNonEmpty(checkoutModel?.stripePriceId, profile.StripePriceId);
			string checkoutStripeAccount = FirstNonEmpty(checkoutModel?.stripeAccount, profile.StripeAccount);
			long checkoutUnitAmountCents = checkoutModel != null && checkoutModel.stripeUnitAmountCents > 0 ? checkoutModel.stripeUnitAmountCents : profile.StripeUnitAmountCents;
			string checkoutCurrency = FirstNonEmpty(checkoutModel?.stripeCurrency, profile.StripeCurrency, "usd");
			if (string.IsNullOrWhiteSpace(checkoutStripePriceId) && checkoutUnitAmountCents <= 0)
			{
				return BuildJsonError(request, 503, "Service Unavailable", "This server requires payment, but no Stripe price or unit amount is configured for the selected model.");
			}
			string connectHost = ResolveServerBrowserConnectHost(profile, request);
			string publicUrl = BuildServerBrowserPublicUrl(connectHost, _chatServerPort);
			if (string.IsNullOrWhiteSpace(successUrl))
			{
				successUrl = publicUrl.TrimEnd('/') + "/?checkout=success";
			}
			if (string.IsNullOrWhiteSpace(cancelUrl))
			{
				cancelUrl = publicUrl.TrimEnd('/') + "/?checkout=cancel";
			}
			if (string.IsNullOrWhiteSpace(clientReferenceId))
			{
				clientReferenceId = "lmvsproxy-shell-" + Guid.NewGuid().ToString("N");
			}
			JackLLMPaymentCheckoutSessionRequest checkoutRequest = new JackLLMPaymentCheckoutSessionRequest
			{
				SuccessUrl = successUrl,
				CancelUrl = cancelUrl,
				CustomerEmail = (customerEmail ?? ""),
				ClientReferenceId = clientReferenceId,
				ConnectedAccountId = (checkoutStripeAccount ?? ""),
				IdempotencyKey = "lmvsproxy-shell-" + Guid.NewGuid().ToString("N")
			};
			checkoutRequest.Metadata["lmvsproxy_server"] = profile.ServerName ?? "";
			checkoutRequest.Metadata["lmvsproxy_host"] = connectHost ?? "";
			checkoutRequest.Metadata["lmvsproxy_client"] = clientReferenceId ?? "";
			checkoutRequest.Metadata["lmvsproxy_cost_factor"] = profile.CostFactor.ToString("0.###", CultureInfo.InvariantCulture);
			checkoutRequest.Metadata["lmvsproxy_model"] = checkoutModel?.id ?? modelId ?? "";
			checkoutRequest.LineItems.Add(new JackLLMPaymentCheckoutLineItem
			{
				PriceId = (checkoutStripePriceId ?? ""),
				ProductName = BuildServerBrowserCheckoutProductName(profile, checkoutModel),
				Description = "Remote JackLLM/API relay access",
				Currency = (string.IsNullOrWhiteSpace(checkoutCurrency) ? "usd" : checkoutCurrency),
				UnitAmount = ((checkoutUnitAmountCents > 0) ? new long?(checkoutUnitAmountCents) : ((long?)null)),
				Quantity = 1L
			});
			JackLLMPaymentCheckoutSessionResult result = RequirePaymentProcessor("server browser checkout").CreateCheckoutSessionAsync(checkoutRequest, cancellationToken).GetAwaiter().GetResult();
			return JsonSerializer.Serialize(new
			{
				ok = true,
				paymentRequired = true,
				checkout = result,
				profile = BuildServerBrowserProfilePayload(connection, request)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Server Browser] Stripe checkout failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private object BuildServerBrowserProfilePayload(NetworkConnection connection, HttpRequest request)
	{
		LmVsProxyServerProfile profile = GetServerBrowserProfile();
		string connectHost = ResolveServerBrowserConnectHost(profile, request);
		string publicUrl = BuildServerBrowserPublicUrl(connectHost, _chatServerPort);
		object ftpStatus = GetChatFtpServerStatus();
		ModelRuntimeStatusSnapshot runtimeStatus = ProbeLocalModelRuntimeStatus();
		object modelRuntimeStatus = BuildModelRuntimeStatusPayload(runtimeStatus);
	object lmStudioStatus = BuildLmStudioStatusPayload(runtimeStatus);
	object llmRuntimeStatus = BuildLlmRuntimeStatusPayload(runtimeStatus);
	List<ChatUiModelInfo> modelCapabilities = BuildServerBrowserModelCapabilities(profile);
	string advertisedModels = JoinChatUiModelIds(modelCapabilities);
	bool supportsImages = modelCapabilities.Any((ChatUiModelInfo model) => model?.supportsImages ?? false);
		bool supportsTools = modelCapabilities.Any((ChatUiModelInfo model) => model?.supportsTools ?? false) || !string.IsNullOrWhiteSpace(profile.ToolsAllowed);
		bool supportsImageGeneration = modelCapabilities.Any((ChatUiModelInfo model) => model?.supportsImageGeneration ?? false);
		bool supportsAudioGeneration = modelCapabilities.Any((ChatUiModelInfo model) => model?.supportsAudioGeneration ?? false);
		bool supportsVideoGeneration = modelCapabilities.Any((ChatUiModelInfo model) => model?.supportsVideoGeneration ?? false);
		TrustAbuseSummarySnapshot trust = BuildTrustAbuseSummary(NormalizeTrustOwnerKey("", profile.OwnerUserName), profile.ServerId, profile.ServerName, connectHost);
		bool online = _chatServer != null && _chatServer.IsListening;
		string status = (trust.HostSuspended ? "Suspended" : (online ? "Online" : "Offline"));
		DateTimeOffset now = DateTimeOffset.UtcNow;
		object hardware;
		lock (_serverHardwareMetricsLock)
		{
			hardware = new
			{
				capturedUtc = now.ToString("O"),
				cpu = BuildServerHardwareCpuMetric(now),
				ram = BuildServerHardwareRamMetric(),
				gpu = BuildServerHardwareGpuMetric(now),
				network = BuildServerHardwareNetworkMetric(now),
				io = BuildServerHardwareIoMetric(now)
			};
		}
		object monitoring = BuildServerBrowserMonitoringPayload(profile, trust, online, modelCapabilities);
		object attestation = BuildHardwareAttestationPayload(connection, request);
		return new
		{
			ok = true,
			serverId = profile.ServerId,
			ownerUserName = profile.OwnerUserName,
			serverName = profile.ServerName,
			displayName = profile.ServerName,
			title = profile.ServerName,
			name = profile.ServerName,
			endpoint = publicUrl,
			connectHost = connectHost,
			online = online,
			offline = !online,
			status = status,
			lastStatus = status,
			visibleOnWebsite = (online && !trust.HostSuspended),
			trust = trust,
			monitoring = monitoring,
			attestation = attestation,
			availableModels = advertisedModels,
			models = modelCapabilities,
			modelCapabilities = modelCapabilities,
			capabilities = new
			{
				vision = supportsImages,
				images = supportsImages,
				tools = supportsTools,
				imageGeneration = supportsImageGeneration,
				audioGeneration = supportsAudioGeneration,
				videoGeneration = supportsVideoGeneration
			},
			supportsVision = supportsImages,
			supportsImages = supportsImages,
			supportsTools = supportsTools,
			supportsImageGeneration = supportsImageGeneration,
			supportsAudioGeneration = supportsAudioGeneration,
			supportsVideoGeneration = supportsVideoGeneration,
			profile = new
			{
				serverId = profile.ServerId,
				ownerUserName = profile.OwnerUserName,
				serverName = profile.ServerName,
				publicHost = profile.PublicHost,
				connectHost = connectHost,
				publicUrl = publicUrl,
				online = online,
				offline = !online,
				status = status,
				lastStatus = status,
				updatedUtc = profile.UpdatedUtc,
				costFactor = profile.CostFactor,
				gpuName = profile.GpuName,
				gpuAvailable = profile.GpuAvailable,
				cpuName = profile.CpuName,
				cpuAvailable = profile.CpuAvailable,
				ramAvailable = profile.RamAvailable,
				storageAvailable = profile.StorageAvailable,
				storageLimitMegabytes = profile.StorageLimitMegabytes,
				storageLimitBytes = GetEffectiveTotalStorageLimitBytes(GetChatCostSettings()),
				availableResources = profile.AvailableResources,
				availableModels = advertisedModels,
				toolsAllowed = profile.ToolsAllowed,
				models = modelCapabilities,
				modelCapabilities = modelCapabilities,
				capabilities = new
				{
					vision = supportsImages,
					images = supportsImages,
					tools = supportsTools,
					imageGeneration = supportsImageGeneration,
					audioGeneration = supportsAudioGeneration,
					videoGeneration = supportsVideoGeneration
				},
				supportsVision = supportsImages,
				supportsImages = supportsImages,
				supportsTools = supportsTools,
				supportsImageGeneration = supportsImageGeneration,
				supportsAudioGeneration = supportsAudioGeneration,
				supportsVideoGeneration = supportsVideoGeneration,
				availableVram = profile.AvailableVram,
				maxTokens = profile.MaxTokens,
				advertisedTokenRate = GetEffectiveAdvertisedTokenRate(),
				modelCapabilitiesJson = profile.ModelCapabilitiesJson,
				modelBenchmarksJson = NormalizeChatUiModelBenchmarksJson(profile.ModelBenchmarksJson),
				requiresPayment = profile.RequiresPayment,
				trust = trust,
				monitoring = monitoring,
				attestation = attestation,
				modelRuntime = modelRuntimeStatus,
				lmStudio = lmStudioStatus,
				llmRuntime = llmRuntimeStatus
			},
			ports = new
			{
				vsProxy = _proxyPort,
				chat = _chatServerPort,
				lmStudio = _lmStudioPort,
				ftp = ExtractFtpPort(ftpStatus)
			},
			modelRuntime = modelRuntimeStatus,
			lmStudio = lmStudioStatus,
			llmRuntime = llmRuntimeStatus,
			payment = new
			{
				requiresPayment = profile.RequiresPayment,
				checkoutEndpoint = publicUrl.TrimEnd('/') + "/api/server-browser/checkout",
				stripePriceId = profile.StripePriceId,
				stripeAccount = profile.StripeAccount,
				unitAmountCents = profile.StripeUnitAmountCents,
				currency = (string.IsNullOrWhiteSpace(profile.StripeCurrency) ? "usd" : profile.StripeCurrency),
				checkoutConfigured = (!string.IsNullOrWhiteSpace(profile.StripePriceId) || profile.StripeUnitAmountCents > 0)
			},
			hardware = hardware,
			ftp = ftpStatus
		};
	}

	private object BuildServerBrowserMonitoringPayload(LmVsProxyServerProfile profile, TrustAbuseSummarySnapshot trust, bool online, List<ChatUiModelInfo> modelCapabilities)
	{
		profile = profile ?? new LmVsProxyServerProfile();
		trust = trust ?? new TrustAbuseSummarySnapshot();
		int modelCount = modelCapabilities?.Count ?? 0;
		bool hardwareAdvertised = !string.IsNullOrWhiteSpace(profile.GpuName) || !string.IsNullOrWhiteSpace(profile.GpuAvailable) || !string.IsNullOrWhiteSpace(profile.CpuName) || !string.IsNullOrWhiteSpace(profile.CpuAvailable);
		int score = 100;
		if (!online)
		{
			score -= 45;
		}
		if (trust.HostSuspended)
		{
			score = 0;
		}
		if (!trust.HostVerified)
		{
			score -= 8;
		}
		score -= Math.Min(30, trust.OpenCases * 5);
		score -= Math.Min(30, trust.HighOpenCases * 8 + trust.CriticalOpenCases * 12);
		if (trust.CommandsBlocked)
		{
			score -= 12;
		}
		if (modelCount <= 0)
		{
			score -= 8;
		}
		if (!hardwareAdvertised)
		{
			score -= 8;
		}
		score = Math.Max(0, Math.Min(100, score));
		return new
		{
			monitoredUtc = DateTimeOffset.UtcNow.ToString("O"),
			lastSeenUtc = (string.IsNullOrWhiteSpace(profile.UpdatedUtc) ? DateTimeOffset.UtcNow.ToString("O") : profile.UpdatedUtc),
			online = online,
			status = (trust.HostSuspended ? "Suspended" : (online ? "Online" : "Offline")),
			healthScore = score,
			healthTier = BuildServerBrowserHealthTier(score, online, trust.HostSuspended),
			openTrustCases = trust.OpenCases,
			criticalOpenCases = trust.CriticalOpenCases,
			highOpenCases = trust.HighOpenCases,
			reputationScore = trust.ReputationScore,
			reputationTier = trust.ReputationTier,
			hostVerificationStatus = trust.HostVerificationStatus,
			commandsBlocked = trust.CommandsBlocked,
			hostSuspended = trust.HostSuspended,
			modelsAdvertised = modelCount,
			hardwareAdvertised = hardwareAdvertised,
			paymentRequired = profile.RequiresPayment
		};
	}

	private object BuildMasterServerEntryMonitoringPayload(JsonElement entry)
	{
		JsonElement profile = entry;
		if (TryGetMasterJsonProperty(entry, "profile", out var profileElement) && profileElement.ValueKind == JsonValueKind.Object)
		{
			profile = profileElement;
		}
		TrustAbuseSummarySnapshot trust = BuildMasterServerEntryTrustSummary(entry);
		string status = FirstMasterNonEmpty(ReadMasterJsonString(entry, "status"), ReadMasterJsonString(entry, "lastStatus"), ReadMasterJsonString(profile, "status"), ReadMasterJsonString(profile, "lastStatus"));
		bool online = !trust.HostSuspended && !status.Equals("offline", StringComparison.OrdinalIgnoreCase) && !status.Equals("stopped", StringComparison.OrdinalIgnoreCase) && !status.Equals("disabled", StringComparison.OrdinalIgnoreCase);
		string models = FirstMasterNonEmpty(ReadMasterJsonString(entry, "availableModels"), ReadMasterJsonString(profile, "availableModels"), ReadMasterJsonString(entry, "models"), ReadMasterJsonString(profile, "models"));
		int modelCount = CountAdvertisedModelHints(models);
		bool hardwareAdvertised = !string.IsNullOrWhiteSpace(FirstMasterNonEmpty(ReadMasterJsonString(entry, "gpuName"), ReadMasterJsonString(profile, "gpuName"), ReadMasterJsonString(entry, "gpuAvailable"), ReadMasterJsonString(profile, "gpuAvailable"), ReadMasterJsonString(entry, "cpuName"), ReadMasterJsonString(profile, "cpuName")));
		bool attestationSigned = HasSignedMasterServerAttestation(entry) || HasSignedMasterServerAttestation(profile);
		int score = 100;
		if (!online)
		{
			score -= 45;
		}
		if (trust.HostSuspended)
		{
			score = 0;
		}
		if (!trust.HostVerified)
		{
			score -= 8;
		}
		score -= Math.Min(30, trust.OpenCases * 5);
		score -= Math.Min(30, trust.HighOpenCases * 8 + trust.CriticalOpenCases * 12);
		if (trust.CommandsBlocked)
		{
			score -= 12;
		}
		if (modelCount <= 0)
		{
			score -= 8;
		}
		if (!hardwareAdvertised)
		{
			score -= 8;
		}
		if (!attestationSigned)
		{
			score -= 6;
		}
		score = Math.Max(0, Math.Min(100, score));
		string lastSeen = FirstMasterNonEmpty(ReadMasterJsonString(entry, "updatedUtc"), ReadMasterJsonString(profile, "updatedUtc"), ReadMasterJsonString(entry, "capturedUtc"), ReadMasterJsonString(profile, "capturedUtc"), ReadMasterJsonString(entry, "registeredUtc"), ReadMasterJsonString(profile, "registeredUtc"));
		return new
		{
			monitoredUtc = DateTimeOffset.UtcNow.ToString("O"),
			lastSeenUtc = (string.IsNullOrWhiteSpace(lastSeen) ? DateTimeOffset.UtcNow.ToString("O") : lastSeen),
			online = online,
			status = (trust.HostSuspended ? "Suspended" : (online ? "Online" : "Offline")),
			healthScore = score,
			healthTier = BuildServerBrowserHealthTier(score, online, trust.HostSuspended),
			openTrustCases = trust.OpenCases,
			criticalOpenCases = trust.CriticalOpenCases,
			highOpenCases = trust.HighOpenCases,
			reputationScore = trust.ReputationScore,
			reputationTier = trust.ReputationTier,
			hostVerificationStatus = trust.HostVerificationStatus,
			commandsBlocked = trust.CommandsBlocked,
			hostSuspended = trust.HostSuspended,
			modelsAdvertised = modelCount,
			hardwareAdvertised = hardwareAdvertised,
			attestationSigned = attestationSigned,
			paymentRequired = (ReadMasterJsonBool(entry, "requiresPayment", fallback: false) || ReadMasterJsonBool(profile, "requiresPayment", fallback: false))
		};
	}

	private static bool HasSignedMasterServerAttestation(JsonElement element)
	{
		if (element.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		if (!TryGetMasterJsonProperty(element, "attestation", out var attestation) || attestation.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		string signature = ExtractStringProperty(attestation, "signature") ?? "";
		string fingerprint = ExtractStringProperty(attestation, "fingerprint") ?? "";
		return !string.IsNullOrWhiteSpace(signature) && !string.IsNullOrWhiteSpace(fingerprint);
	}

	private static string BuildServerBrowserHealthTier(int score, bool online, bool suspended)
	{
		if (suspended)
		{
			return "Suspended";
		}
		if (!online)
		{
			return "Offline";
		}
		if (score >= 90)
		{
			return "Healthy";
		}
		if (score >= 70)
		{
			return "Watch";
		}
		if (score >= 45)
		{
			return "At Risk";
		}
		return "Blocked";
	}

	private static int CountAdvertisedModelHints(string models)
	{
		if (string.IsNullOrWhiteSpace(models))
		{
			return 0;
		}
		return (from part in models.Replace("\r\n", "\n").Replace('\r', '\n').Split(new char[4] { '\n', ',', ';', '\t' }, StringSplitOptions.RemoveEmptyEntries)
			select part.Trim()).Count((string part) => !string.IsNullOrWhiteSpace(part));
	}

	private List<ChatUiModelInfo> BuildServerBrowserModelCapabilities(LmVsProxyServerProfile profile)
	{
		List<ChatUiModelInfo> models = new List<ChatUiModelInfo>();
		if (profile == null)
		{
			profile = new LmVsProxyServerProfile();
		}
		List<string> enabledModelIds = GetEnabledWebChatModelIds();
		HashSet<string> enabledCandidates = BuildModelIdentifierCandidateSet(enabledModelIds);
		string capabilitiesJson = profile.ModelCapabilitiesJson;
		if (!string.IsNullOrWhiteSpace(capabilitiesJson))
		{
			MergeChatModelInfos(models, from info in ExtractModelInfos(capabilitiesJson)
				where info != null && (ModelIdentifierMatchesAny(enabledCandidates, info.id) || IsAdvertisableWebChatModelInfo(info))
				select info);
		}
		foreach (string id in enabledModelIds)
		{
			MergeChatModelInfo(models, BuildChatModelInfo(id));
		}
		lock (_chatModelCacheLock)
		{
			MergeChatModelInfos(models, _lastChatUiModelInfos.Where((ChatUiModelInfo info) => info != null && (ModelIdentifierMatchesAny(enabledCandidates, info.id) || IsAdvertisableWebChatModelInfo(info))));
		}
		if (TryLoadChatUiRuntimeModelInfos(CancellationToken.None, out var runtimeModels, out _))
		{
			MergeChatModelInfos(models, runtimeModels.Where(IsAdvertisableWebChatModelInfo));
		}
		DecorateChatUiModelsWithPolicy(models);
		ApplyServerBrowserPaymentDefaults(models, profile);
		return models.Where(IsAdvertisableWebChatModelInfo).ToList();
	}

	private string GetAdvertisedEnabledModelsText(LmVsProxyServerProfile profile)
	{
		return JoinChatUiModelIds(BuildServerBrowserModelCapabilities(profile));
	}

	private static bool IsAdvertisableWebChatModelInfo(ChatUiModelInfo model)
	{
		if (model == null || string.IsNullOrWhiteSpace(model.id))
		{
			return false;
		}
		if (model.disabled && !model.isLoaded && !model.enabled && !model.isEnabled && !model.dynamicLoadEnabled && !model.web_chat_dynamic_load_enabled && !model.web_chat_model_enabled)
		{
			return false;
		}
		return model.enabled ||
		       model.isEnabled ||
		       model.web_chat_model_enabled ||
		       model.isLoaded ||
		       model.dynamicLoadEnabled ||
		       model.web_chat_dynamic_load_enabled ||
		       model.serverDynamicLoadingEnabled;
	}

	private List<string> GetEnabledWebChatModelIds()
	{
		return (from settings in GetAdvertisableWebChatModelSettings()
			select settings.Key into key
			where !string.IsNullOrWhiteSpace(key)
			select key).Distinct<string>(StringComparer.OrdinalIgnoreCase).ToList();
	}

	private List<WebChatModelManagerLoadSettings> GetEnabledWebChatModelSettings()
	{
		List<WebChatModelManagerLoadSettings> settingsList = new List<WebChatModelManagerLoadSettings>();
		try
		{
			string path = GetModelManagerSettingsPath();
			if (!File.Exists(path))
			{
				return settingsList;
			}
			using JsonDocument document = JsonDocument.Parse(File.ReadAllText(path));
			if (document.RootElement.ValueKind != JsonValueKind.Object)
			{
				return settingsList;
			}
			foreach (JsonProperty property in document.RootElement.EnumerateObject())
			{
				if (property.Value.ValueKind == JsonValueKind.Object)
				{
					WebChatModelManagerLoadSettings settings = ReadModelManagerLoadSettings(property.Name, property.Value);
					if (settings.Enabled && !string.IsNullOrWhiteSpace(settings.Key) && !settingsList.Any((WebChatModelManagerLoadSettings existing) => string.Equals(existing.Key, settings.Key, StringComparison.OrdinalIgnoreCase)))
					{
						settingsList.Add(settings);
					}
				}
			}
		}
		catch
		{
		}
		return settingsList;
	}

	private List<WebChatModelManagerLoadSettings> GetAdvertisableWebChatModelSettings()
	{
		List<WebChatModelManagerLoadSettings> settingsList = GetEnabledWebChatModelSettings();
		if (!IsEffectiveLocalRuntimeLlmRuntime())
		{
			return settingsList;
		}

		if (!TryReadRuntimeLoadableModelIds(out HashSet<string> loadableModelIds, out _))
		{
			return new List<WebChatModelManagerLoadSettings>();
		}

		return settingsList
			.Where(settings => settings != null &&
				!string.IsNullOrWhiteSpace(settings.Key) &&
				RuntimeLoadableModelIdMatches(loadableModelIds, settings.Key))
			.ToList();
	}

	private bool TryReadRuntimeLoadableModelIds(out HashSet<string> modelIds, out string error)
	{
		modelIds = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		error = "";
		try
		{
			string url = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/models";
			using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, url);
			using CancellationTokenSource timeout = new CancellationTokenSource(TimeSpan.FromSeconds(6));
			using HttpResponseMessage response = _httpClient.SendAsync(request, timeout.Token).GetAwaiter().GetResult();
			string responseBody = response.Content == null ? "" : response.Content.ReadAsStringAsync().GetAwaiter().GetResult();
			if (!response.IsSuccessStatusCode)
			{
				error = GetLocalModelRuntimeDisplayName() + " returned HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " while verifying loadable models.";
				return false;
			}
			using JsonDocument document = JsonDocument.Parse(responseBody);
			AddRuntimeLoadableModelIds(document.RootElement, modelIds);
			return modelIds.Count > 0;
		}
		catch (Exception ex)
		{
			error = ex.Message;
			return false;
		}
	}

	private void AddRuntimeLoadableModelIds(JsonElement element, HashSet<string> modelIds)
	{
		if (modelIds == null)
		{
			return;
		}
		if (element.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement child in element.EnumerateArray())
			{
				AddRuntimeLoadableModelIds(child, modelIds);
			}
			return;
		}
		if (element.ValueKind != JsonValueKind.Object)
		{
			return;
		}
		if (element.TryGetProperty("models", out JsonElement models))
		{
			AddRuntimeLoadableModelIds(models, modelIds);
		}
		if (element.TryGetProperty("data", out JsonElement data))
		{
			AddRuntimeLoadableModelIds(data, modelIds);
		}
		if (!IsRuntimeModelApiLoadable(element))
		{
			return;
		}
		AddRuntimeLoadableModelId(modelIds, ExtractModelIdentifier(element));
	}

	private static void AddRuntimeLoadableModelId(HashSet<string> modelIds, string model)
	{
		if (modelIds == null || string.IsNullOrWhiteSpace(model) || IsLikelyModelArtifactId(model))
		{
			return;
		}
		string normalized = NormalizeRuntimeLoadableModelId(model);
		if (string.IsNullOrWhiteSpace(normalized))
		{
			return;
		}
		modelIds.Add(normalized);
		string stripped = StripRuntimeModelPackagingSuffix(normalized);
		if (!string.IsNullOrWhiteSpace(stripped))
		{
			modelIds.Add(stripped);
		}
		try
		{
			string fileName = Path.GetFileName(normalized);
			if (!string.IsNullOrWhiteSpace(fileName) && (fileName.EndsWith(".gguf", StringComparison.OrdinalIgnoreCase) || fileName.EndsWith(".onnx", StringComparison.OrdinalIgnoreCase)))
			{
				modelIds.Add(fileName);
				string strippedFileName = StripRuntimeModelPackagingSuffix(fileName);
				if (!string.IsNullOrWhiteSpace(strippedFileName))
				{
					modelIds.Add(strippedFileName);
				}
				string withoutExtension = Path.GetFileNameWithoutExtension(fileName);
				if (!string.IsNullOrWhiteSpace(withoutExtension))
				{
					modelIds.Add(withoutExtension);
					string strippedWithoutExtension = StripRuntimeModelPackagingSuffix(withoutExtension);
					if (!string.IsNullOrWhiteSpace(strippedWithoutExtension))
					{
						modelIds.Add(strippedWithoutExtension);
					}
				}
			}
		}
		catch
		{
		}
	}

	private bool IsVerifiedRuntimeLoadableModel(string model, out string reason)
	{
		reason = "";
		if (string.IsNullOrWhiteSpace(model) || !IsEffectiveLocalRuntimeLlmRuntime())
		{
			return true;
		}
		if (!TryReadRuntimeLoadableModelIds(out HashSet<string> loadableModelIds, out string error))
		{
			reason = "Could not verify that '" + model + "' is a loadable LlmRuntime model: " + (string.IsNullOrWhiteSpace(error) ? "runtime model list unavailable." : error);
			return false;
		}
		if (RuntimeLoadableModelIdMatches(loadableModelIds, model))
		{
			return true;
		}
		reason = "'" + model + "' is not reported as a loadable LlmRuntime model. Download or enable a complete model bundle that appears in /api/v1/models with runtime_load=true.";
		return false;
	}

	private IEnumerable<string> EnumerateCompleteModelManifestModelIds()
	{
		HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		foreach (string root in GetCompleteModelRoots())
		{
			if (string.IsNullOrWhiteSpace(root) || !Directory.Exists(root))
			{
				continue;
			}
			IEnumerable<string> manifests;
			try
			{
				manifests = Directory.EnumerateFiles(root, "manifest.json", SearchOption.AllDirectories);
			}
			catch
			{
				continue;
			}
			foreach (string manifestPath in manifests)
			{
				string modelId = "";
				try
				{
					using JsonDocument document = JsonDocument.Parse(File.ReadAllText(manifestPath));
					JsonElement manifest = document.RootElement;
					if (manifest.ValueKind == JsonValueKind.Object)
					{
						string manifestType = ExtractStringProperty(manifest, "type") ?? "";
						modelId = FirstNonEmpty(ExtractStringProperty(manifest, "id"), ExtractStringProperty(manifest, "name"));
						if (!string.IsNullOrWhiteSpace(modelId) && !string.IsNullOrWhiteSpace(GuessWebChatMediaService(modelId, manifestType)))
						{
							goto IL_01f9;
						}
					}
				}
				catch
				{
				}
				continue;
				IL_01f9:
				if (seen.Add(modelId))
				{
					yield return modelId;
				}
			}
		}
	}

	private static HashSet<string> BuildModelIdentifierCandidateSet(IEnumerable<string> modelIds)
	{
		HashSet<string> candidates = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		if (modelIds == null)
		{
			return candidates;
		}
		foreach (string id in modelIds)
		{
			AddModelIdentifierCandidate(candidates, id);
		}
		return candidates;
	}

	private static bool ModelIdentifierMatchesAny(HashSet<string> candidates, string modelId)
	{
		if (candidates == null || candidates.Count == 0 || string.IsNullOrWhiteSpace(modelId))
		{
			return false;
		}
		foreach (string candidate in BuildModelIdentifierCandidates(modelId))
		{
			if (candidates.Contains(candidate))
			{
				return true;
			}
		}
		return false;
	}

	private static bool RuntimeLoadableModelIdMatches(HashSet<string> loadableModelIds, string modelId)
	{
		if (loadableModelIds == null || loadableModelIds.Count == 0 || string.IsNullOrWhiteSpace(modelId) || IsLikelyModelArtifactId(modelId))
		{
			return false;
		}
		string normalized = NormalizeRuntimeLoadableModelId(modelId);
		if (string.IsNullOrWhiteSpace(normalized))
		{
			return false;
		}
		if (loadableModelIds.Contains(normalized))
		{
			return true;
		}
		try
		{
			string fileName = Path.GetFileName(normalized);
			if (!string.IsNullOrWhiteSpace(fileName) && loadableModelIds.Contains(fileName))
			{
				return true;
			}
			string withoutExtension = Path.GetFileNameWithoutExtension(fileName);
			return !string.IsNullOrWhiteSpace(withoutExtension) && loadableModelIds.Contains(withoutExtension);
		}
		catch
		{
			return false;
		}
	}

	private static string NormalizeRuntimeLoadableModelId(string modelId)
	{
		return (modelId ?? "").Trim().Replace('\\', '/');
	}

	private void MergeChatModelInfos(List<ChatUiModelInfo> target, IEnumerable<ChatUiModelInfo> source)
	{
		if (source == null)
		{
			return;
		}
		foreach (ChatUiModelInfo info in source)
		{
			MergeChatModelInfo(target, info);
		}
	}

	private void MergeChatModelInfo(List<ChatUiModelInfo> target, ChatUiModelInfo info)
	{
		if (target != null && info != null && !string.IsNullOrWhiteSpace(info.id))
		{
			ChatUiModelInfo existing = target.Find((ChatUiModelInfo model) => string.Equals(model.id, info.id, StringComparison.OrdinalIgnoreCase));
			if (existing == null)
			{
				target.Add(new ChatUiModelInfo
				{
					id = info.id.Trim(),
					supportsImages = info.supportsImages,
					supportsTools = info.supportsTools,
					isLoaded = info.isLoaded,
					isAvailable = info.isAvailable,
					enabled = info.enabled,
					disabled = info.disabled,
					status = info.status,
					dynamicLoadEnabled = info.dynamicLoadEnabled,
					serverDynamicLoadingEnabled = info.serverDynamicLoadingEnabled,
					web_chat_dynamic_load_enabled = info.web_chat_dynamic_load_enabled,
					web_chat_model_load_api_enabled = info.web_chat_model_load_api_enabled,
					web_chat_model_enabled = info.web_chat_model_enabled,
					web_chat_idle_unload_minutes = info.web_chat_idle_unload_minutes,
					web_chat_load_disabled_reason = info.web_chat_load_disabled_reason,
					loadDisabledReason = info.loadDisabledReason,
					supportsImageGeneration = info.supportsImageGeneration,
					supportsAudioGeneration = info.supportsAudioGeneration,
					supportsVideoGeneration = info.supportsVideoGeneration,
					requiresPayment = info.requiresPayment,
					stripePriceId = info.stripePriceId ?? "",
					stripeAccount = info.stripeAccount ?? "",
					stripeUnitAmountCents = Math.Max(0L, info.stripeUnitAmountCents),
					stripeCurrency = FirstNonEmpty(info.stripeCurrency, "usd").ToLowerInvariant(),
					paymentStatus = info.paymentStatus ?? "",
					checkoutConfigured = info.checkoutConfigured || !string.IsNullOrWhiteSpace(info.stripePriceId) || info.stripeUnitAmountCents > 0
				});
			}
			else
			{
				existing.supportsImages = existing.supportsImages || info.supportsImages;
				existing.supportsTools = existing.supportsTools || info.supportsTools;
				existing.isLoaded = existing.isLoaded || info.isLoaded;
				existing.isAvailable = existing.isAvailable || info.isAvailable;
				existing.enabled = existing.enabled || info.enabled;
				existing.disabled = existing.disabled && info.disabled;
				existing.dynamicLoadEnabled = existing.dynamicLoadEnabled || info.dynamicLoadEnabled;
				existing.serverDynamicLoadingEnabled = existing.serverDynamicLoadingEnabled || info.serverDynamicLoadingEnabled;
				existing.web_chat_dynamic_load_enabled = existing.web_chat_dynamic_load_enabled || info.web_chat_dynamic_load_enabled;
				existing.web_chat_model_load_api_enabled = existing.web_chat_model_load_api_enabled || info.web_chat_model_load_api_enabled;
				existing.web_chat_model_enabled = existing.web_chat_model_enabled || info.web_chat_model_enabled;
				existing.web_chat_idle_unload_minutes = Math.Max(existing.web_chat_idle_unload_minutes, info.web_chat_idle_unload_minutes);
				existing.web_chat_load_disabled_reason = FirstNonEmpty(existing.web_chat_load_disabled_reason, info.web_chat_load_disabled_reason);
				existing.loadDisabledReason = FirstNonEmpty(existing.loadDisabledReason, info.loadDisabledReason);
				existing.status = FirstNonEmpty(existing.status, info.status);
				existing.supportsImageGeneration = existing.supportsImageGeneration || info.supportsImageGeneration;
				existing.supportsAudioGeneration = existing.supportsAudioGeneration || info.supportsAudioGeneration;
				existing.supportsVideoGeneration = existing.supportsVideoGeneration || info.supportsVideoGeneration;
				ApplyChatUiModelPaymentInfo(existing, info.requiresPayment, info.stripePriceId, info.stripeAccount, info.stripeUnitAmountCents, info.stripeCurrency, info.paymentStatus);
			}
		}
	}

	private static void ApplyChatUiModelPaymentInfo(ChatUiModelInfo model, bool requiresPayment, string stripePriceId, string stripeAccount, long unitAmountCents, string stripeCurrency, string paymentStatus)
	{
		if (model == null)
		{
			return;
		}

		model.requiresPayment = model.requiresPayment || requiresPayment;
		model.stripePriceId = FirstNonEmpty(model.stripePriceId, stripePriceId);
		model.stripeAccount = FirstNonEmpty(model.stripeAccount, stripeAccount);
		model.stripeUnitAmountCents = Math.Max(model.stripeUnitAmountCents, Math.Max(0L, unitAmountCents));
		model.stripeCurrency = FirstNonEmpty(model.stripeCurrency, stripeCurrency, "usd").ToLowerInvariant();
		model.paymentStatus = FirstNonEmpty(model.paymentStatus, paymentStatus);
		model.checkoutConfigured = model.checkoutConfigured || !string.IsNullOrWhiteSpace(model.stripePriceId) || model.stripeUnitAmountCents > 0;
	}

	private static void ApplyServerBrowserPaymentDefaults(List<ChatUiModelInfo> models, LmVsProxyServerProfile profile)
	{
		if (models == null || profile == null)
		{
			return;
		}
		bool hasServerCheckoutConfiguration = !string.IsNullOrWhiteSpace(profile.StripePriceId) || profile.StripeUnitAmountCents > 0;
		bool requiresPayment = profile.RequiresPayment || hasServerCheckoutConfiguration;
		if (!requiresPayment)
		{
			return;
		}
		foreach (ChatUiModelInfo model in models)
		{
			if (model == null)
			{
				continue;
			}
			bool hasModelCheckoutConfiguration = model.requiresPayment || !string.IsNullOrWhiteSpace(model.stripePriceId) || model.stripeUnitAmountCents > 0;
			if (!hasServerCheckoutConfiguration && !hasModelCheckoutConfiguration)
			{
				continue;
			}
			model.requiresPayment = true;
			if (hasServerCheckoutConfiguration && string.IsNullOrWhiteSpace(model.stripePriceId))
			{
				model.stripePriceId = profile.StripePriceId ?? "";
			}
			if (hasServerCheckoutConfiguration && string.IsNullOrWhiteSpace(model.stripeAccount))
			{
				model.stripeAccount = profile.StripeAccount ?? "";
			}
			if (hasServerCheckoutConfiguration && model.stripeUnitAmountCents <= 0)
			{
				model.stripeUnitAmountCents = Math.Max(0L, profile.StripeUnitAmountCents);
			}
			model.stripeCurrency = FirstNonEmpty(model.stripeCurrency, profile.StripeCurrency, "usd").ToLowerInvariant();
			model.paymentStatus = FirstNonEmpty(model.paymentStatus, "payment-required");
			model.checkoutConfigured = model.checkoutConfigured || !string.IsNullOrWhiteSpace(model.stripePriceId) || model.stripeUnitAmountCents > 0;
		}
	}

	private static ChatUiModelInfo FindServerBrowserCheckoutModel(IEnumerable<ChatUiModelInfo> models, string modelId)
	{
		if (models == null)
		{
			return null;
		}
		List<ChatUiModelInfo> candidates = models.Where((ChatUiModelInfo model) => model != null && !string.IsNullOrWhiteSpace(model.id)).ToList();
		if (!string.IsNullOrWhiteSpace(modelId))
		{
			foreach (ChatUiModelInfo model in candidates)
			{
				if (string.Equals(model.id, modelId.Trim(), StringComparison.OrdinalIgnoreCase))
				{
					return model;
				}
			}
			HashSet<string> requestedCandidates = BuildModelIdentifierCandidateSet(new[] { modelId });
			foreach (ChatUiModelInfo model in candidates)
			{
				if (ModelIdentifierMatchesAny(requestedCandidates, model.id))
				{
					return model;
				}
			}
		}
		return candidates.FirstOrDefault((ChatUiModelInfo model) => model.requiresPayment || !string.IsNullOrWhiteSpace(model.stripePriceId) || model.stripeUnitAmountCents > 0);
	}

	private static string BuildServerBrowserCheckoutProductName(LmVsProxyServerProfile profile, ChatUiModelInfo model)
	{
		string serverName = FirstNonEmpty(profile?.ServerName, "LmVsProxy");
		string modelId = model?.id ?? "";
		if (!string.IsNullOrWhiteSpace(modelId))
		{
			return serverName + " model access: " + modelId;
		}
		return serverName + " LmVsProxy shell access";
	}

	private IEnumerable<string> ExtractAdvertisedModelIds(string availableModels)
	{
		if (string.IsNullOrWhiteSpace(availableModels))
		{
			yield break;
		}
		string normalized = availableModels.Replace("\r\n", "\n").Replace('\r', '\n');
		char[] separators = new char[4] { '\n', ',', ';', '\t' };
		string[] array = normalized.Split(separators, StringSplitOptions.RemoveEmptyEntries);
		foreach (string part in array)
		{
			string id = part.Trim();
			if (!string.IsNullOrWhiteSpace(id))
			{
				if (id.StartsWith("Available Models:", StringComparison.OrdinalIgnoreCase))
				{
					id = id.Substring("Available Models:".Length).Trim();
				}
				int detailIndex = id.IndexOf(" - ", StringComparison.Ordinal);
				if (detailIndex > 0)
				{
					id = id.Substring(0, detailIndex).Trim();
				}
				if (!string.IsNullOrWhiteSpace(id))
				{
					yield return id;
				}
			}
		}
	}

	private string BuildLocalLmStudioBaseUrl()
	{
		return BuildLocalModelRuntimeBaseUrl();
