	{
		string displayName = ((runtime == null) ? "" : runtime.DisplayName);
		return string.IsNullOrWhiteSpace(displayName) ? "LM Studio" : displayName.Trim();
	}

	private bool IsCopilotDuplicatorRequest(HttpListenerRequest request)
	{
		try
		{
			if (request == null)
			{
				return false;
			}
			if (request.LocalEndPoint != null && request.LocalEndPoint.Port == CopilotDuplicatorPort)
			{
				return true;
			}
			string header = request.Headers["X-SocketJack-Copilot-Duplicator"];
			return !string.IsNullOrWhiteSpace(header) && (header.Equals("true", StringComparison.OrdinalIgnoreCase) || header.Equals("1", StringComparison.OrdinalIgnoreCase));
		}
		catch
		{
			return false;
		}
	}

	private string ResolveOpenAiUpstreamBaseUrl(HttpListenerRequest request)
	{
		if (IsCopilotDuplicatorRequest(request))
		{
			return GetEffectiveCopilotDuplicatorUpstreamBaseUrl();
		}
		return BuildLocalModelRuntimeBaseUrl();
	}

	private bool IsLocalLmStudioUpstream(string baseUrl)
	{
		return string.Equals(LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(baseUrl), LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(BuildLocalModelRuntimeBaseUrl()), StringComparison.OrdinalIgnoreCase);
	}

	private string CombineOpenAiUpstreamUrl(string baseUrl, string pathAndQuery)
	{
		baseUrl = LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(baseUrl);
		if (string.IsNullOrWhiteSpace(baseUrl))
		{
			baseUrl = BuildLocalModelRuntimeBaseUrl();
		}
		pathAndQuery = (string.IsNullOrWhiteSpace(pathAndQuery) ? "/v1/chat/completions" : pathAndQuery);
		if (!pathAndQuery.StartsWith("/", StringComparison.Ordinal))
		{
			pathAndQuery = "/" + pathAndQuery;
		}
		return baseUrl.TrimEnd('/') + pathAndQuery;
	}

