	private ChatUiModelInventorySnapshot BuildMasterListModelInventorySnapshot()
	{
		string configuredModel = GetConfiguredChatModelOrPlaceholder();
		try
		{
			if (TryLoadChatUiRuntimeModelInfos(CancellationToken.None, out var models, out var warning))
			{
				return BuildChatUiModelInventorySnapshot(models, ChooseChatUiSelectedModel(models, configuredModel), modelListAvailable: true, warning);
			}
			models = GetCachedOrConfiguredChatModelInfos(configuredModel);
			MergeChatModelInfos(models, BuildEnabledWebChatModelInfos());
			DecorateChatUiModelsWithPolicy(models);
			return BuildChatUiModelInventorySnapshot(models, ChooseChatUiSelectedModel(models, configuredModel), modelListAvailable: false, warning);
		}
		catch (Exception ex)
		{
			List<ChatUiModelInfo> models2 = GetCachedOrConfiguredChatModelInfos(configuredModel);
			MergeChatModelInfos(models2, BuildEnabledWebChatModelInfos());
			DecorateChatUiModelsWithPolicy(models2);
			ChatUiModelInventorySnapshot snapshot = BuildChatUiModelInventorySnapshot(models2, ChooseChatUiSelectedModel(models2, configuredModel), modelListAvailable: false, ex.Message);
			snapshot.ok = false;
			snapshot.error = ex.Message;
			return snapshot;
		}
	}

	private ModelRuntimeStatusSnapshot GetCachedModelRuntimeStatus(TimeSpan maxAge)
	{
		DateTimeOffset now = DateTimeOffset.UtcNow;
		lock (_modelRuntimeStatusCacheLock)
		{
			if (_cachedModelRuntimeStatus != null && now - _cachedModelRuntimeStatusUtc <= maxAge)
			{
				return _cachedModelRuntimeStatus;
			}
			ModelRuntimeStatusSnapshot snapshot = (_cachedModelRuntimeStatus = ProbeLocalModelRuntimeStatus());
			_cachedModelRuntimeStatusUtc = now;
			return snapshot;
		}
	}

