	private object BuildLlmRuntimeStatusPayload(ModelRuntimeStatusSnapshot runtime)
	{
		bool selected = string.Equals(runtime.ProviderKind, "llmruntime", StringComparison.OrdinalIgnoreCase);
		return new
		{
			provider = "LlmRuntime",
			runtimeProvider = runtime.Provider,
			runtimeDisplayName = runtime.Provider,
			providerKind = runtime.ProviderKind,
			selected = selected,
			runtimeEndpoint = (selected ? runtime.BaseUrl : ""),
			endpoint = (selected ? runtime.BaseUrl : ""),
			modelsEndpoint = (selected ? runtime.ModelsEndpoint : ""),
			emergencyFallbackActive = runtime.EmergencyFallbackActive,
			runtimeConnected = runtime.Connected,
			connected = (selected && runtime.Connected),
			status = ((!selected) ? "Not selected" : (runtime.Connected ? "Connected" : "Disconnected")),
			error = (selected ? runtime.Error : ""),
			checkedUtc = runtime.CheckedUtc
		};
	}

	private object BuildLmStudioStatusPayload()
	{
		return BuildLmStudioStatusPayload(ProbeLocalModelRuntimeStatus());
	}

	private ModelRuntimeStatusSnapshot ProbeLocalModelRuntimeStatus()
	{
		string runtimeBaseUrl = BuildLocalModelRuntimeBaseUrl();
		string runtimeDisplayName = GetLocalModelRuntimeDisplayName();
		string providerKind = GetModelRuntimeProviderKind(runtimeDisplayName);
		string modelsEndpoint = runtimeBaseUrl.TrimEnd('/') + "/v1/models";
		bool connected = false;
		string error = "";
		try
		{
			using CancellationTokenSource timeout = new CancellationTokenSource(TimeSpan.FromMilliseconds(900.0));
			using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, modelsEndpoint);
			using HttpResponseMessage response = _httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, timeout.Token).GetAwaiter().GetResult();
			connected = response.IsSuccessStatusCode;
			if (!connected)
			{
				error = "HTTP " + (int)response.StatusCode;
			}
		}
		catch (Exception ex)
		{
			error = ex.Message ?? "unreachable";
			if (error.Length > 120)
			{
				error = error.Substring(0, 120) + "...";
			}
		}
		return new ModelRuntimeStatusSnapshot
		{
			Provider = runtimeDisplayName,
			ProviderKind = providerKind,
			BaseUrl = runtimeBaseUrl,
			ModelsEndpoint = modelsEndpoint,
			Connected = connected,
			Error = error,
			EmergencyFallbackActive = IsEmergencyFallbackActive(),
			CheckedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
	}

	private static string GetModelRuntimeProviderKind(string provider)
	{
		string normalized = (provider ?? "").Trim().ToLowerInvariant();
		if (normalized.Contains("llmruntime", StringComparison.Ordinal) || normalized.Contains("llm runtime", StringComparison.Ordinal))
		{
			return "llmruntime";
		}
		if (normalized.Contains("lmstudio", StringComparison.Ordinal) || normalized.Contains("lm studio", StringComparison.Ordinal))
		{
			return "lmstudio";
		}
		return string.IsNullOrWhiteSpace(normalized) ? "unknown" : "model-runtime";
	}

	private string BuildMasterServerEntryKey(JsonElement entry)
	{
		JsonElement profile = entry;
		if (TryGetMasterJsonProperty(entry, "profile", out var profileElement) && profileElement.ValueKind == JsonValueKind.Object)
		{
			profile = profileElement;
		}
		if (TryBuildSocketJackProxyMasterEntryKey(entry, profile, out var socketJackKey))
		{
			return socketJackKey;
		}
		string id = ReadMasterJsonString(entry, "id");
		if (string.IsNullOrWhiteSpace(id))
		{
			id = ReadMasterJsonString(entry, "serverId");
		}
		if (string.IsNullOrWhiteSpace(id))
		{
			id = ReadMasterJsonString(profile, "id");
		} 
		if (string.IsNullOrWhiteSpace(id))
		{
			id = ReadMasterJsonString(profile, "serverId");
		}
		if (!string.IsNullOrWhiteSpace(id))
		{
			return "id|" + id.Trim().ToLowerInvariant();
		}
		string endpoint = ReadMasterJsonString(entry, "endpoint");
		string connectHost = ReadMasterJsonString(profile, "connectHost");
		if (string.IsNullOrWhiteSpace(connectHost))
		{
			connectHost = ReadMasterJsonString(entry, "connectHost");
		}
		if (string.IsNullOrWhiteSpace(connectHost))
		{
			connectHost = ReadMasterJsonString(profile, "publicHost");
		}
		if (string.IsNullOrWhiteSpace(connectHost))
		{
			connectHost = ReadMasterJsonString(entry, "publicHost");
		}
		if (string.IsNullOrWhiteSpace(connectHost))
		{
			connectHost = NormalizeServerBrowserHost(endpoint);
		}
		string serverName = ReadMasterJsonString(profile, "serverName");
		if (string.IsNullOrWhiteSpace(serverName))
		{
			serverName = ReadMasterJsonString(entry, "serverName");
		}
		string hostKey = NormalizeServerBrowserHost(connectHost);
		if (string.IsNullOrWhiteSpace(hostKey))
		{
			hostKey = NormalizeServerBrowserHost(endpoint);
		}
		if (string.IsNullOrWhiteSpace(hostKey))
		{
			return serverName ?? "";
		}
		return hostKey + "|" + serverName;
	}

	private bool TryBuildSocketJackProxyMasterEntryKey(JsonElement entry, JsonElement profile, out string key)
	{
		key = "";
		Uri proxyUri = TryCreateSocketJackProxyMasterUri(ReadMasterJsonString(entry, "endpoint"));
		if (proxyUri == null)
		{
			proxyUri = TryCreateSocketJackProxyMasterUri(ReadMasterJsonString(profile, "endpoint"));
		}
		if (proxyUri == null)
		{
			proxyUri = TryCreateSocketJackProxyMasterUri(ReadMasterJsonString(entry, "publicUrl"));
		}
		if (proxyUri == null)
		{
			proxyUri = TryCreateSocketJackProxyMasterUri(ReadMasterJsonString(profile, "publicUrl"));
		}
		if (proxyUri == null)
		{
			proxyUri = TryCreateSocketJackProxyMasterUri(ReadMasterJsonString(entry, "connectHost"));
		}
		if (proxyUri == null)
		{
			proxyUri = TryCreateSocketJackProxyMasterUri(ReadMasterJsonString(profile, "connectHost"));
		}
		if (proxyUri == null)
		{
			return false;
		}
		string route = NormalizeSocketJackProxyMasterRoute(proxyUri);
		string ownerUserName = NormalizeMasterServerKeyComponent(ReadMasterServerOwnerUserName(entry, profile));
		string title = NormalizeMasterServerKeyComponent(ReadMasterServerTitle(entry, profile));
		string id = NormalizeMasterServerKeyComponent(FirstMasterNonEmpty(ReadMasterJsonString(entry, "serverId"), ReadMasterJsonString(profile, "serverId"), ReadMasterJsonString(entry, "id"), ReadMasterJsonString(profile, "id")));
		string host = NormalizeMasterServerKeyComponent(proxyUri.Host);
		string identity = FirstMasterNonEmpty(route, title, id);
		if (string.IsNullOrWhiteSpace(host) || string.IsNullOrWhiteSpace(identity))
		{
			return false;
		}
		key = "socketjack-proxy|" + host + "|" + identity + "|owner:" + ownerUserName;
		return true;
	}

	private static Uri TryCreateSocketJackProxyMasterUri(string value)
	{
		value = (value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(value))
		{
			return null;
		}
		if (!Uri.TryCreate(value, UriKind.Absolute, out Uri uri) || string.IsNullOrWhiteSpace(uri.Host))
		{
			return null;
		}
		return IsSocketJackProxyMasterUri(uri) ? uri : null;
	}

	private static bool IsSocketJackProxyMasterUri(Uri uri)
	{
		string path = uri.AbsolutePath ?? "";
		if (path.StartsWith("/proxy/", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		return uri.Host.IndexOf("socketjack", StringComparison.OrdinalIgnoreCase) >= 0 && path.IndexOf("/proxy/", StringComparison.OrdinalIgnoreCase) >= 0;
	}

	private static string NormalizeSocketJackProxyMasterRoute(Uri uri)
	{
		string path = uri.AbsolutePath ?? "";
		int proxy = path.IndexOf("/proxy/", StringComparison.OrdinalIgnoreCase);
		if (proxy >= 0)
		{
			path = path.Substring(proxy);
		}
		path = Uri.UnescapeDataString(path).Trim().Trim('/');
		return NormalizeMasterServerKeyComponent(path);
	}

	private static string ReadMasterServerOwnerUserName(JsonElement entry, JsonElement profile)
	{
		return FirstMasterNonEmpty(ReadMasterJsonString(entry, "ownerUserName"), ReadMasterJsonString(entry, "ownerUsername"), ReadMasterJsonString(entry, "serverOwnerUserName"), ReadMasterJsonString(entry, "serverOwnerUsername"), ReadMasterJsonString(profile, "ownerUserName"), ReadMasterJsonString(profile, "ownerUsername"), ReadMasterJsonString(profile, "serverOwnerUserName"), ReadMasterJsonString(profile, "serverOwnerUsername"));
	}

	private static string ReadMasterServerTitle(JsonElement entry, JsonElement profile)
	{
		return FirstMasterNonEmpty(ReadMasterJsonString(profile, "serverName"), ReadMasterJsonString(profile, "displayName"), ReadMasterJsonString(profile, "title"), ReadMasterJsonString(profile, "name"), ReadMasterJsonString(entry, "serverName"), ReadMasterJsonString(entry, "displayName"), ReadMasterJsonString(entry, "title"), ReadMasterJsonString(entry, "name"), ReadMasterJsonString(entry, "requestedPath"));
	}

	private static string FirstMasterNonEmpty(params string[] values)
	{
		foreach (string value in values)
		{
			if (!string.IsNullOrWhiteSpace(value))
			{
				return value.Trim();
			}
		}
		return "";
	}

	private static string NormalizeMasterServerKeyComponent(string value)
	{
		return (value ?? "").Trim().ToLowerInvariant();
	}

	private bool MasterServerEntryMatchesPublishedSlot(JsonElement existing, JsonElement incoming, string incomingKey, string incomingOwnerKeyHash)
	{
		if (!string.IsNullOrWhiteSpace(incomingOwnerKeyHash))
		{
			string existingOwnerKeyHash = ReadMasterServerOwnerKeyHash(existing);
			if (!string.IsNullOrWhiteSpace(existingOwnerKeyHash) && string.Equals(existingOwnerKeyHash, incomingOwnerKeyHash, StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
		}
		if (string.IsNullOrWhiteSpace(incomingKey))
		{
			return false;
		}
		return string.Equals(BuildMasterServerEntryKey(existing), incomingKey, StringComparison.OrdinalIgnoreCase);
	}

	private static string ExtractMasterServerOwnerKey(HttpRequest request, JsonElement entry)
	{
		string ownerKey = "";
		if (request?.Headers != null)
		{
			request.Headers.TryGetValue("X-LmVsProxy-Server-Owner", out ownerKey);
			if (string.IsNullOrWhiteSpace(ownerKey))
			{
				request.Headers.TryGetValue("X-SocketJack-Server-Owner", out ownerKey);
			}
		}
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			ownerKey = ReadMasterJsonString(entry, "serverOwner");
		}
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			ownerKey = ReadMasterJsonString(entry, "ownerToken");
		}
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			ownerKey = ReadMasterJsonString(entry, "ownerKey");
		}
		return ownerKey ?? "";
	}

	private static string BuildMasterServerOwnerKeyHash(string ownerKey)
	{
		ownerKey = (ownerKey ?? "").Trim();
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			return "";
		}
		byte[] bytes = Encoding.UTF8.GetBytes(ownerKey);
		using SHA256 sha256 = SHA256.Create();
		return Convert.ToBase64String(sha256.ComputeHash(bytes));
	}

	private static string ReadMasterServerOwnerKeyHash(JsonElement entry)
	{
		string ownerKeyHash = ReadMasterJsonString(entry, "ownerKeyHash");
		if (!string.IsNullOrWhiteSpace(ownerKeyHash))
		{
			return ownerKeyHash;
		}
		return BuildMasterServerOwnerKeyHash(ExtractMasterServerOwnerKey(null, entry));
	}

	private static JsonElement AttachMasterServerOwnerKeyHash(JsonElement entry, string ownerKeyHash)
	{
		if (entry.ValueKind != JsonValueKind.Object)
		{
			return entry.Clone();
		}
		using MemoryStream stream = new MemoryStream();
		using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
		{
			writer.WriteStartObject();
			foreach (JsonProperty property in entry.EnumerateObject())
			{
				if (!IsPrivateMasterServerProperty(property.Name))
				{
					property.WriteTo(writer);
				}
			}
			if (!string.IsNullOrWhiteSpace(ownerKeyHash))
			{
				writer.WriteString("ownerKeyHash", ownerKeyHash);
			}
			writer.WriteEndObject();
		}
		using JsonDocument document = JsonDocument.Parse(stream.ToArray());
		return document.RootElement.Clone();
	}

	private JsonElement BuildPublicMasterServerEntry(JsonElement entry)
	{
		if (entry.ValueKind != JsonValueKind.Object)
		{
			return entry.Clone();
		}
		using MemoryStream stream = new MemoryStream();
		using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
		{
			writer.WriteStartObject();
			foreach (JsonProperty property in entry.EnumerateObject())
			{
				if (!IsPrivateMasterServerProperty(property.Name) && !string.Equals(property.Name, "trust", StringComparison.OrdinalIgnoreCase) && !string.Equals(property.Name, "monitoring", StringComparison.OrdinalIgnoreCase))
				{
					property.WriteTo(writer);
				}
			}
			writer.WritePropertyName("trust");
			JsonSerializer.Serialize(writer, BuildMasterServerEntryTrustPayload(entry));
			writer.WritePropertyName("monitoring");
			JsonSerializer.Serialize(writer, BuildMasterServerEntryMonitoringPayload(entry));
			writer.WriteEndObject();
		}
		using JsonDocument document = JsonDocument.Parse(stream.ToArray());
		return document.RootElement.Clone();
	}

	private bool IsMasterServerEntrySuspended(JsonElement entry)
