			reputationTier = trust.ReputationTier,
			openCases = trust.OpenCases,
			hostVerificationStatus = trust.HostVerificationStatus,
			renterIdentityStatus = trust.RenterIdentityStatus,
			hostVerified = trust.HostVerified,
			renterIdentityVerified = trust.RenterIdentityVerified,
			commandsBlocked = trust.CommandsBlocked,
			hostSuspended = trust.HostSuspended,
			updatedUtc = trust.UpdatedUtc
		};
	}

	private TrustAbuseSummarySnapshot BuildMasterServerEntryTrustSummary(JsonElement entry)
	{
		JsonElement profile = entry;
		if (TryGetMasterJsonProperty(entry, "profile", out var profileElement) && profileElement.ValueKind == JsonValueKind.Object)
		{
			profile = profileElement;
		}
		string ownerUserName = ReadMasterServerOwnerUserName(entry, profile);
		string ownerKey = NormalizeTrustOwnerKey("", ownerUserName);
		string serverId = FirstMasterNonEmpty(ReadMasterJsonString(entry, "serverId"), ReadMasterJsonString(profile, "serverId"), ReadMasterJsonString(entry, "id"), ReadMasterJsonString(profile, "id"));
		string serverName = ReadMasterServerTitle(entry, profile);
		string externalIp = FirstMasterNonEmpty(ReadMasterJsonString(entry, "externalIp"), ReadMasterJsonString(profile, "externalIp"), ReadMasterJsonString(entry, "connectHost"), ReadMasterJsonString(profile, "connectHost"), NormalizeServerBrowserHost(ReadMasterJsonString(entry, "endpoint")), NormalizeServerBrowserHost(ReadMasterJsonString(profile, "endpoint")));
		return BuildTrustAbuseSummary(ownerKey, serverId, serverName, externalIp);
	}

	private bool IsExactDuplicateMasterServerEntry(JsonElement incoming)
	{
		string incomingText = BuildLowercaseMasterServerEntryText(incoming);
		if (string.IsNullOrWhiteSpace(incomingText))
		{
			return false;
		}
		foreach (JsonElement existing in _masterServerEntries)
		{
			if (string.Equals(BuildLowercaseMasterServerEntryText(existing), incomingText, StringComparison.Ordinal))
			{
				return true;
			}
		}
		return false;
	}

	private static string BuildLowercaseMasterServerEntryText(JsonElement entry)
	{
		if (entry.ValueKind == JsonValueKind.Undefined || entry.ValueKind == JsonValueKind.Null)
		{
			return "";
		}
		return JsonSerializer.Serialize(entry).Trim().ToLowerInvariant();
	}

	private static bool IsPrivateMasterServerProperty(string name)
	{
		return string.Equals(name, "ownerKeyHash", StringComparison.OrdinalIgnoreCase) || string.Equals(name, "ownerToken", StringComparison.OrdinalIgnoreCase) || string.Equals(name, "ownerKey", StringComparison.OrdinalIgnoreCase) || string.Equals(name, "serverOwner", StringComparison.OrdinalIgnoreCase) || string.Equals(name, "serverOwnerToken", StringComparison.OrdinalIgnoreCase);
	}

	private static bool IsMasterServerOfflineRegistration(JsonElement entry)
	{
		JsonElement profile = entry;
		if (TryGetMasterJsonProperty(entry, "profile", out var profileElement) && profileElement.ValueKind == JsonValueKind.Object)
		{
			profile = profileElement;
		}
		if (ReadMasterJsonBool(entry, "remove", fallback: false) || ReadMasterJsonBool(entry, "offline", fallback: false) || ReadMasterJsonBool(profile, "offline", fallback: false))
		{
			return true;
		}
		if (TryGetMasterJsonProperty(entry, "online", out var onlineElement) && onlineElement.ValueKind == JsonValueKind.False)
		{
			return true;
		}
		if (TryGetMasterJsonProperty(profile, "online", out var profileOnlineElement) && profileOnlineElement.ValueKind == JsonValueKind.False)
		{
			return true;
		}
		string action = ReadMasterJsonString(entry, "action");
		if (IsMasterServerOfflineText(action))
		{
			return true;
		}
		string status = ReadMasterJsonString(entry, "lastStatus");
		if (string.IsNullOrWhiteSpace(status))
		{
			status = ReadMasterJsonString(entry, "status");
		}
		if (string.IsNullOrWhiteSpace(status))
		{
			status = ReadMasterJsonString(entry, "state");
		}
		if (string.IsNullOrWhiteSpace(status))
		{
			status = ReadMasterJsonString(profile, "lastStatus");
		}
		if (string.IsNullOrWhiteSpace(status))
		{
			status = ReadMasterJsonString(profile, "status");
		}
		if (string.IsNullOrWhiteSpace(status))
		{
			status = ReadMasterJsonString(profile, "state");
		}
		return IsMasterServerOfflineText(status);
	}

	private static bool IsMasterServerOfflineText(string value)
	{
		value = (value ?? "").Trim();
		if (value.Length == 0)
		{
			return false;
		}
		return value.Equals("remove", StringComparison.OrdinalIgnoreCase) || value.Equals("offline", StringComparison.OrdinalIgnoreCase) || value.Equals("stop", StringComparison.OrdinalIgnoreCase) || value.Equals("stopped", StringComparison.OrdinalIgnoreCase) || value.IndexOf("offline", StringComparison.OrdinalIgnoreCase) >= 0 || value.IndexOf("stopped", StringComparison.OrdinalIgnoreCase) >= 0 || value.IndexOf("unavailable", StringComparison.OrdinalIgnoreCase) >= 0;
	}

	private static bool TryGetMasterJsonProperty(JsonElement element, string name, out JsonElement value)
	{
		value = default(JsonElement);
		if (element.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		if (element.TryGetProperty(name, out value))
		{
			return true;
		}
		foreach (JsonProperty property in element.EnumerateObject())
		{
			if (string.Equals(property.Name, name, StringComparison.OrdinalIgnoreCase))
			{
				value = property.Value;
				return true;
			}
		}
		return false;
	}

	private static string ReadMasterJsonString(JsonElement element, string name)
	{
		if (!TryGetMasterJsonProperty(element, name, out var value))
		{
			return "";
		}
		if (value.ValueKind == JsonValueKind.String)
		{
			return value.GetString() ?? "";
		}
		if (value.ValueKind == JsonValueKind.Number || value.ValueKind == JsonValueKind.True || value.ValueKind == JsonValueKind.False)
		{
			return value.ToString();
		}
		return "";
	}

	private static bool ReadMasterJsonBool(JsonElement element, string name, bool fallback)
	{
		if (!TryGetMasterJsonProperty(element, name, out var value))
		{
			return fallback;
		}
		if (value.ValueKind == JsonValueKind.True)
		{
			return true;
		}
		if (value.ValueKind == JsonValueKind.False)
		{
			return false;
		}
		if (value.ValueKind == JsonValueKind.String && bool.TryParse(value.GetString(), out var parsed))
		{
			return parsed;
		}
		return fallback;
	}

	private string ResolveServerBrowserConnectHost(LmVsProxyServerProfile profile, HttpRequest request)
	{
		string fromProfile = NormalizeServerBrowserHost(profile?.PublicHost);
		if (!string.IsNullOrWhiteSpace(fromProfile))
		{
			return fromProfile;
		}
		string hostHeader = ExtractHostHeader(request);
		string fromRequest = NormalizeServerBrowserHost(hostHeader);
		if (!string.IsNullOrWhiteSpace(fromRequest))
		{
			return fromRequest;
		}
		return Dns.GetHostName();
	}

	private string ExtractHostHeader(HttpRequest request)
	{
		if (request?.Headers == null)
		{
			return "";
		}
		string value;
		return request.Headers.TryGetValue("Host", out value) ? (value ?? "") : "";
	}

	private string NormalizeServerBrowserHost(string value)
	{
		value = (value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(value))
		{
			return "";
		}
		if (Uri.TryCreate(value, UriKind.Absolute, out Uri uri) && !string.IsNullOrWhiteSpace(uri.Host))
		{
			return uri.Host;
		}
		if (value.StartsWith("[", StringComparison.Ordinal))
		{
			int close = value.IndexOf(']');
			if (close > 1)
			{
				return value.Substring(1, close - 1).Trim();
			}
		}
		int slash = value.IndexOf('/');
		if (slash >= 0)
		{
			value = value.Substring(0, slash);
		}
		int colon = value.LastIndexOf(':');
		if (colon > 0 && value.IndexOf(':') == colon)
		{
			value = value.Substring(0, colon);
		}
		return value.Trim();
	}

	private string BuildServerBrowserPublicUrl(string host, int port)
	{
		host = (string.IsNullOrWhiteSpace(host) ? "localhost" : host.Trim());
		string bracketedHost = ((host.Contains(":") && !host.StartsWith("[", StringComparison.Ordinal)) ? ("[" + host + "]") : host);
		string portPart = ((port == 80 || port == 443) ? "" : (":" + port.ToString(CultureInfo.InvariantCulture)));
		return "https://" + bracketedHost + portPart + "/";
	}

	private int ExtractFtpPort(object ftpStatus)
	{
		try
		{
			if (ftpStatus == null)
			{
				return 0;
			}
			PropertyInfo property = ftpStatus.GetType().GetProperty("port");
			if (property != null && property.GetValue(ftpStatus) is int value)
			{
				return value;
			}
		}
		catch
		{
		}
		return 0;
	}

	private string HandleChatSqlAdminStatusRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			return JsonSerializer.Serialize(BuildChatSqlAdminStatus(connection, request));
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] SQL Admin status failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatSqlAdminControlRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthorizeDatabaseAdministrator(connection, request, out var _, out var authError))
			{
				return BuildDatabaseAdminOnlyJsonError(request, authError);
			}
			string action = "status";
			bool? useMutableServer = null;
			int? port = null;
			bool? sqlAdminEnabled = null;
			if (!string.IsNullOrWhiteSpace(request?.Body))
			{
				using JsonDocument document = JsonDocument.Parse(request.Body);
				JsonElement root = document.RootElement;
				if (root.ValueKind == JsonValueKind.Object)
				{
					action = ExtractStringProperty(root, "action") ?? action;
					if (root.TryGetProperty("useMutableServer", out var useMutable))
					{
						useMutableServer = ReadJsonBool(useMutable, _chatSqlUseMutableServer);
					}
					if (root.TryGetProperty("port", out var portElement) && TryReadJsonInt(portElement, out var parsedPort))
					{
						port = parsedPort;
					}
					if (root.TryGetProperty("sqlAdminEnabled", out var sqlAdminElement))
					{
						sqlAdminEnabled = ReadJsonBool(sqlAdminElement, GetChatPermissions(GetChatSessionOwnerKey(connection, request)).sqlAdmin);
					}
				}
			}
			if (port.HasValue)
			{
				SetStandaloneChatSqlPort(port.Value);
			}
			if (sqlAdminEnabled.HasValue)
			{
				SetChatSqlAdminPermission(sqlAdminEnabled.Value);
			}
			if (useMutableServer.HasValue)
			{
				SetChatSqlUseMutableServer(useMutableServer.Value);
			}
			action = (action ?? "status").Trim().ToLowerInvariant();
			switch (action)
			{
			case "start":
				StartChatSqlEndpoint();
				break;
			case "stop":
				StopChatSqlEndpoint();
				break;
			case "restart":
				StopChatSqlEndpoint();
				StartChatSqlEndpoint();
				break;
			default:
				if (!(action == "status"))
				{
					throw new InvalidOperationException("Unknown SQL Admin action: " + action);
				}
				goto case "config";
			case "config":
			case "configure":
				if (useMutableServer.HasValue && IsChatSqlEndpointRunning())
				{
					StartChatSqlEndpoint();
				}
				break;
			}
			return JsonSerializer.Serialize(BuildChatSqlAdminStatus(connection, request));
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] SQL Admin control failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private object BuildChatSqlAdminStatus(NetworkConnection connection, HttpRequest request)
	{
		bool isAdmin = IsDatabaseAdministrator(connection, request);
		string ownerKey = GetChatSessionOwnerKey(connection, request);
		ChatPermissionState permissions = GetChatPermissions(ownerKey);
		bool mutableListening = false;
		bool tdsRegistered = false;
		bool standaloneListening = false;
		lock (_chatSqlServerLock)
		{
			mutableListening = _chatServer is MutableTcpServer mutable && mutable.IsListening;
			tdsRegistered = _chatTdsProtocolRegistered;
			standaloneListening = _standaloneChatSqlServer != null && _standaloneChatSqlServer.IsListening;
		}
		bool running = (_chatSqlUseMutableServer ? (mutableListening && tdsRegistered) : standaloneListening);
		int tableCount = 0;
		foreach (SocketJack.Net.Database.Database database in _chatSessionData.Databases.Values)
		{
			tableCount += ((database != null && database.Tables != null) ? database.Tables.Count : 0);
		}
		return new
		{
			ok = true,
			canEdit = isAdmin,
			sqlAdminEnabled = permissions.sqlAdmin,
			sqlAdminUrl = ChatServerUrl.TrimEnd('/') + "/sql",
			database = new
			{
				name = _chatSessionData.Name,
				defaultDatabase = _chatSessionData.DefaultDatabase,
				dataPath = _chatSessionData.DataPath,
				databaseCount = _chatSessionData.Databases.Count,
				tableCount = tableCount,
				userCount = _chatSessionData.Users.Count,
				activeSessions = _chatSessionData.Sessions.Count
			},
			safety = new
			{
				marketplaceSafeMode = true,
				readOnlyByDefaultForLeases = true,
				requiresWebAuthAdminForMutableActions = true,
				localhostOnlySaBootstrap = true,
				destructiveQueryConfirmation = true,
				auditLedgerEnabled = true,
				dynamicApiPolicyRequired = true,
				reflectionEventsRequireAllowlist = true,
				tenantIsolationByOwnerUsername = true
			},
			server = new
			{
				running = running,
				useMutableServer = _chatSqlUseMutableServer,
				mutableServerListening = mutableListening,
				mutableServerPort = _chatServerPort,
				databaseProtocolEnabled = tdsRegistered,
				standaloneRunning = standaloneListening,
				standalonePort = _chatStandaloneSqlPort,
				activePort = (_chatSqlUseMutableServer ? _chatServerPort : _chatStandaloneSqlPort),
				connection = "localhost," + (_chatSqlUseMutableServer ? _chatServerPort : _chatStandaloneSqlPort)
			}
		};
	}

	private bool TryReadJsonInt(JsonElement element, out int value)
	{
		if (element.ValueKind == JsonValueKind.Number && element.TryGetInt32(out value))
		{
			return true;
		}
		if (element.ValueKind == JsonValueKind.String && int.TryParse(element.GetString(), out value))
		{
			return true;
		}
		value = 0;
		return false;
	}

	private void SetStandaloneChatSqlPort(int port)
	{
		if (port <= 0 || port > 65535)
		{
			throw new InvalidOperationException("Database port must be between 1 and 65535.");
		}
		if (port == _chatServerPort)
		{
			throw new InvalidOperationException("Standalone database port cannot match the mutable web server port.");
		}
		lock (_chatSqlServerLock)
		{
			if (_standaloneChatSqlServer != null && _standaloneChatSqlServer.IsListening && port != _chatStandaloneSqlPort)
			{
				throw new InvalidOperationException("Stop the standalone database server before changing its port.");
			}
			_chatStandaloneSqlPort = port;
		}
	}

	private void SetChatSqlAdminPermission(bool enabled)
	{
		ChatPermissionState permissions = GetChatPermissions();
		permissions.sqlAdmin = enabled;
		SaveChatPermissions(permissions);
		ApplyRuntimeChatPermissions(permissions);
	}

	private void SetChatSqlUseMutableServer(bool useMutableServer)
	{
		lock (_chatSqlServerLock)
		{
			if (_chatSqlUseMutableServer == useMutableServer)
			{
				return;
			}
		}
		bool wasRunning = IsChatSqlEndpointRunning();
		StopChatSqlEndpoint();
		lock (_chatSqlServerLock)
		{
			_chatSqlUseMutableServer = useMutableServer;
		}
		if (wasRunning)
		{
			StartChatSqlEndpoint();
		}
	}

	private bool IsChatSqlEndpointRunning()
	{
		lock (_chatSqlServerLock)
		{
			if (_chatSqlUseMutableServer)
			{
				return _chatServer is MutableTcpServer { IsListening: not false } && _chatTdsProtocolRegistered;
			}
			return _standaloneChatSqlServer != null && _standaloneChatSqlServer.IsListening;
		}
	}

	private void StartChatSqlEndpoint()
	{
		lock (_chatSqlServerLock)
		{
			if (_chatSqlUseMutableServer)
			{
				if (!(_chatServer is MutableTcpServer mutable))
				{
					throw new InvalidOperationException("Mutable chat server is not available.");
				}
				if (_chatTdsProtocolHandler == null)
				{
					_chatTdsProtocolHandler = new TdsProtocolHandler(_chatSessionData);
				}
				if (!_chatTdsProtocolRegistered)
				{
					mutable.RegisterProtocol(_chatTdsProtocolHandler);
					_chatTdsProtocolRegistered = true;
				}
				LogMessage("[Chat UI] SQL database endpoint enabled on mutable server port " + _chatServerPort + ".");
			}
			else if (_standaloneChatSqlServer == null || !_standaloneChatSqlServer.IsListening)
			{
				_standaloneChatSqlServer = CreateStandaloneChatSqlServer(_chatStandaloneSqlPort);
				if (!_standaloneChatSqlServer.Listen())
				{
					throw new InvalidOperationException("Unable to start standalone SQL database server on port " + _chatStandaloneSqlPort + ".");
				}
				LogMessage("[Chat UI] Standalone SQL database endpoint started on port " + _chatStandaloneSqlPort + ".");
			}
		}
	}

	private void StopChatSqlEndpoint()
	{
		lock (_chatSqlServerLock)
		{
			if (_chatSqlUseMutableServer)
			{
				if (_chatServer is MutableTcpServer mutable && _chatTdsProtocolHandler != null && _chatTdsProtocolRegistered)
				{
					mutable.RemoveProtocol(_chatTdsProtocolHandler);
				}
				_chatTdsProtocolRegistered = false;
				LogMessage("[Chat UI] SQL database endpoint disabled on mutable server.");
			}
			else
			{
				StopStandaloneChatSqlServerLocked();
			}
		}
	}

	private DataServer CreateStandaloneChatSqlServer(int port)
	{
		DataServer server = new DataServer(port, "LmVsProxy SQL Database");
		server.LogOutput += RelaySocketJackLogOutput;
		server.OnError += RelaySocketJackError;
		server.DataPath = _chatSessionData.DataPath;
		server.DefaultDatabase = _chatSessionData.DefaultDatabase;
		server.ServerName = _chatSessionData.ServerName;
		server.InstanceName = _chatSessionData.InstanceName;
		server.Username = _chatSessionData.Username;
		server.Password = _chatSessionData.Password;
		server.Users = _chatSessionData.Users;
		server.Databases = _chatSessionData.Databases;
		return server;
	}

	private void StopStandaloneChatSqlServerLocked()
	{
		if (_standaloneChatSqlServer == null)
		{
			return;
		}
		try
		{
			if (_standaloneChatSqlServer.IsListening)
			{
				_standaloneChatSqlServer.StopListening();
			}
			((IDisposable)_standaloneChatSqlServer)?.Dispose();
			LogMessage("[Chat UI] Standalone SQL database endpoint stopped.");
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Standalone SQL database stop failed: " + ex.Message);
		}
		finally
		{
			_standaloneChatSqlServer = null;
		}
	}

	private ServerHardwarePercentMetric BuildServerHardwareCpuMetric(DateTimeOffset now)
	{
		try
		{
			if (!GetSystemTimes(out var idleTime, out var kernelTime, out var userTime))
			{
				return ServerHardwarePercentMetric.Unavailable("Unavailable");
			}
			ulong idleTicks = idleTime.ToUInt64();
			ulong kernelTicks = kernelTime.ToUInt64();
			ulong userTicks = userTime.ToUInt64();
			double percent = 0.0;
			string text = "warming";
			if (_lastServerHardwareCpuSampleUtc != DateTimeOffset.MinValue && kernelTicks >= _lastServerHardwareCpuKernelTicks && userTicks >= _lastServerHardwareCpuUserTicks && idleTicks >= _lastServerHardwareCpuIdleTicks)
			{
				ulong kernelDelta = kernelTicks - _lastServerHardwareCpuKernelTicks;
				ulong userDelta = userTicks - _lastServerHardwareCpuUserTicks;
				ulong idleDelta = idleTicks - _lastServerHardwareCpuIdleTicks;
				ulong totalDelta = kernelDelta + userDelta;
				if (totalDelta != 0)
				{
					percent = ClampPercent((1.0 - (double)idleDelta / (double)totalDelta) * 100.0);
				}
				text = FormatMetricPercent(percent);
			}
			_lastServerHardwareCpuSampleUtc = now;
			_lastServerHardwareCpuIdleTicks = idleTicks;
			_lastServerHardwareCpuKernelTicks = kernelTicks;
			_lastServerHardwareCpuUserTicks = userTicks;
			return new ServerHardwarePercentMetric
			{
				available = true,
				percent = percent,
				text = text
			};
		}
		catch
		{
			return ServerHardwarePercentMetric.Unavailable("Unavailable");
		}
	}

	private ServerHardwareRamMetric BuildServerHardwareRamMetric()
	{
		try
		{
			MemoryStatusEx memory = MemoryStatusEx.Create();
			if (!GlobalMemoryStatusEx(ref memory) || memory.ullTotalPhys == 0)
			{
				return ServerHardwareRamMetric.Unavailable("Unavailable");
			}
			ulong usedBytes = ((memory.ullTotalPhys > memory.ullAvailPhys) ? (memory.ullTotalPhys - memory.ullAvailPhys) : 0);
			double percent = ClampPercent((double)usedBytes / (double)memory.ullTotalPhys * 100.0);
			return new ServerHardwareRamMetric
			{
				available = true,
				percent = percent,
				text = FormatMetricPercent(percent),
				usedBytes = usedBytes,
				totalBytes = memory.ullTotalPhys
			};
		}
		catch
		{
			return ServerHardwareRamMetric.Unavailable("Unavailable");
		}
	}

	private ServerHardwareGpuMetric BuildServerHardwareGpuMetric(DateTimeOffset now)
	{
		if (_lastServerHardwareGpuMetric != null && _lastServerHardwareGpuSampleUtc != DateTimeOffset.MinValue && now - _lastServerHardwareGpuSampleUtc < TimeSpan.FromSeconds(10.0))
		{
			return _lastServerHardwareGpuMetric;
		}
		_lastServerHardwareGpuSampleUtc = now;
		_lastServerHardwareGpuMetric = QueryServerHardwareGpuMetric();
		return _lastServerHardwareGpuMetric;
	}

	private ServerHardwareGpuMetric QueryServerHardwareGpuMetric()
	{
		string arguments = "--query-gpu=name,utilization.gpu,memory.used,memory.total --format=csv,noheader,nounits";
		if (IsWineEnvironment() && TryQueryForwardedServerHardwareGpuMetric(out var wineForwardedMetric))
		{
			return wineForwardedMetric;
		}
		if (RuntimeInformation.IsOSPlatform(OSPlatform.Linux) || IsWineEnvironment())
		{
			foreach (string executable in EnumerateLinuxNvidiaSmiExecutables())
			{
				try
				{
					string linuxOutput = RunLinuxGpuQuery(executable, arguments);
					if (TryCreateNvidiaSmiGpuMetric(linuxOutput, aggregateAllRows: true, out var linuxMetric))
					{
						return linuxMetric;
					}
				}
				catch
				{
				}
			}
		}
		string[] executables = RuntimeInformation.IsOSPlatform(OSPlatform.Linux) ? Array.Empty<string>() : new string[2] { "nvidia-smi.exe", "nvidia-smi" };
		string[] array = executables;
		foreach (string executable in array)
		{
			try
			{
				string output = RunGpuQuery(executable, arguments);
				if (TryCreateNvidiaSmiGpuMetric(output, aggregateAllRows: false, out var metric))
				{
					return metric;
				}
			}
			catch
			{
			}
		}
		if (TryQueryForwardedServerHardwareGpuMetric(out var forwardedMetric))
		{
			return forwardedMetric;
		}
		return ServerHardwareGpuMetric.Unavailable("No NVIDIA GPU");
	}

	private IEnumerable<string> EnumerateLinuxNvidiaSmiExecutables()
	{
		HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		string configured = Environment.GetEnvironmentVariable("NVIDIA_SMI_PATH") ?? Environment.GetEnvironmentVariable("JACKLLM_NVIDIA_SMI") ?? "";
		string[] candidates = new string[5] { configured, "/usr/bin/nvidia-smi", "/bin/nvidia-smi", "/usr/local/bin/nvidia-smi", "nvidia-smi" };
		foreach (string candidate in candidates)
		{
			string executable = (candidate ?? "").Trim();
			if (!string.IsNullOrWhiteSpace(executable) && seen.Add(executable))
			{
				if (executable.StartsWith("/", StringComparison.Ordinal) && !File.Exists(executable))
				{
					continue;
				}
				yield return executable;
			}
		}
	}

	private string RunLinuxGpuQuery(string executable, string arguments)
	{
		try
		{
			string output = RunGpuQuery(executable, arguments);
			if (!string.IsNullOrWhiteSpace(output))
			{
				return output;
			}
		}
		catch
		{
		}
		if (!IsWineEnvironment())
		{
			return "";
		}
		string command = executable + " " + (arguments ?? "");
		return RunGpuQueryWithArgumentList("/bin/sh", "-lc", command);
	}

	private sealed class NvidiaSmiGpuSample
	{
		public string Name { get; set; } = "";

		public double GpuPercent { get; set; }

		public double VramUsedMb { get; set; }

		public double VramTotalMb { get; set; }
	}

	private static bool TryCreateNvidiaSmiGpuMetric(string output, bool aggregateAllRows, out ServerHardwareGpuMetric metric)
	{
		metric = null;
		if (string.IsNullOrWhiteSpace(output))
		{
			return false;
		}
		List<NvidiaSmiGpuSample> samples = new List<NvidiaSmiGpuSample>();
		string[] lines = output.Split(new char[2] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
		foreach (string line in lines)
		{
			if (TryParseNvidiaSmiGpuSample(line, out NvidiaSmiGpuSample sample))
			{
				samples.Add(sample);
				if (!aggregateAllRows)
				{
					break;
				}
			}
		}
		if (samples.Count == 0)
		{
			return false;
		}
		double gpuPercent = ClampPercent(samples.Average(sample => sample.GpuPercent));
		double vramUsedMb = samples.Sum(sample => sample.VramUsedMb);
		double vramTotalMb = samples.Sum(sample => sample.VramTotalMb);
		double vramPercent = ((vramTotalMb > 0.0) ? ClampPercent(vramUsedMb / vramTotalMb * 100.0) : 0.0);
		string name = FormatNvidiaSmiGpuName(samples);
		metric = new ServerHardwareGpuMetric
		{
			available = true,
			name = name,
			source = aggregateAllRows ? "nvidia-smi-linux" : "nvidia-smi",
			deviceCount = samples.Count,
			percent = gpuPercent,
			text = (samples.Count > 1 ? "avg " : "") + FormatMetricPercent(gpuPercent),
			vramPercent = vramPercent,
			vramText = ((vramTotalMb > 0.0) ? (FormatMetricPercent(vramPercent) + " (" + FormatMetricMegabytes(vramUsedMb) + " / " + FormatMetricMegabytes(vramTotalMb) + ")") : "Unavailable"),
			vramUsedBytes = MegabytesToBytes(vramUsedMb),
			vramTotalBytes = MegabytesToBytes(vramTotalMb)
		};
		return true;
	}

	private static bool TryParseNvidiaSmiGpuSample(string line, out NvidiaSmiGpuSample sample)
	{
		sample = null;
		if (string.IsNullOrWhiteSpace(line))
		{
			return false;
		}
		string[] parts = line.Split(',');
		if (parts.Length < 4)
		{
			return false;
		}
		string name = parts[0].Trim();
		double gpuPercent = ParseMetricDouble(parts[1]);
		double vramUsedMb = ParseMetricDouble(parts[2]);
		double vramTotalMb = ParseMetricDouble(parts[3]);
		if (string.IsNullOrWhiteSpace(name) && vramTotalMb <= 0.0)
		{
			return false;
		}
		sample = new NvidiaSmiGpuSample
		{
			Name = name,
			GpuPercent = gpuPercent,
			VramUsedMb = vramUsedMb,
			VramTotalMb = vramTotalMb
		};
		return true;
	}

	private static string FormatNvidiaSmiGpuName(List<NvidiaSmiGpuSample> samples)
	{
		if (samples == null || samples.Count == 0)
		{
			return "";
		}
		if (samples.Count == 1)
		{
			return samples[0].Name;
		}
		string firstName = samples[0].Name ?? "";
		bool sameName = !string.IsNullOrWhiteSpace(firstName) && samples.All(sample => string.Equals(sample.Name, firstName, StringComparison.OrdinalIgnoreCase));
		if (sameName)
		{
			return firstName + " x" + samples.Count.ToString(CultureInfo.InvariantCulture);
		}
		return samples.Count.ToString(CultureInfo.InvariantCulture) + " NVIDIA GPUs";
	}

	private bool TryQueryForwardedServerHardwareGpuMetric(out ServerHardwareGpuMetric metric)
	{
		metric = null;
		if (!ShouldTryForwardedServerHardwareGpuMetric())
		{
			return false;
		}
		foreach (string url in EnumerateForwardedServerHardwareUrls())
		{
			try
			{
				HttpWebRequest request = (HttpWebRequest)WebRequest.Create(url);
				request.Method = "GET";
				request.Timeout = 1200;
				request.ReadWriteTimeout = 1200;
				using HttpWebResponse response = (HttpWebResponse)request.GetResponse();
				if (response.StatusCode != HttpStatusCode.OK)
				{
					continue;
				}
				using Stream stream = response.GetResponseStream();
				using StreamReader reader = new StreamReader(stream ?? Stream.Null, Encoding.UTF8);
				using JsonDocument document = JsonDocument.Parse(reader.ReadToEnd());
				if (document.RootElement.TryGetProperty("gpu", out var gpu))
				{
					ServerHardwareGpuMetric candidate = ReadForwardedServerHardwareGpuMetric(gpu);
					if (candidate != null && candidate.available)
					{
						metric = candidate;
						return true;
					}
				}
			}
			catch
			{
			}
		}
		return false;
	}

	private static ServerHardwareGpuMetric ReadForwardedServerHardwareGpuMetric(JsonElement gpu)
	{
		string name = ReadHardwareJsonString(gpu, "name");
		string source = ReadHardwareJsonString(gpu, "source");
		string text = ReadHardwareJsonString(gpu, "text");
		string vramText = ReadHardwareJsonString(gpu, "vramText");
		double? percent = ReadHardwareJsonNullableDouble(gpu, "percent");
		double? vramPercent = ReadHardwareJsonNullableDouble(gpu, "vramPercent");
		int deviceCount = (int)Math.Min(int.MaxValue, ReadHardwareJsonUInt64(gpu, "deviceCount"));
		ulong vramUsedBytes = ReadHardwareJsonUInt64(gpu, "vramUsedBytes");
		ulong vramTotalBytes = ReadHardwareJsonUInt64(gpu, "vramTotalBytes");
		if (!ReadHardwareJsonBool(gpu, "available") && string.IsNullOrWhiteSpace(name) && vramTotalBytes == 0)
		{
			return null;
		}
		return new ServerHardwareGpuMetric
		{
			available = true,
			name = name,
			source = source,
			deviceCount = deviceCount,
			percent = (percent.HasValue ? new double?(ClampPercent(percent.Value)) : ((double?)null)),
			text = (string.IsNullOrWhiteSpace(text) ? "Available" : text),
			vramPercent = (vramPercent.HasValue ? new double?(ClampPercent(vramPercent.Value)) : ((double?)null)),
			vramText = ((string.IsNullOrWhiteSpace(vramText) && vramTotalBytes != 0) ? (FormatMetricBytes(vramUsedBytes) + " / " + FormatMetricBytes(vramTotalBytes)) : (string.IsNullOrWhiteSpace(vramText) ? "Available" : vramText)),
			vramUsedBytes = vramUsedBytes,
			vramTotalBytes = vramTotalBytes
		};
	}

	private IEnumerable<string> EnumerateForwardedServerHardwareUrls()
	{
		HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		string[] array = new string[2] { "JACKLLM_SERVER_HARDWARE_URL", "JACKLLM_WORKSTATION_HARDWARE_URL" };
		foreach (string variable in array)
		{
			string configured = NormalizeServerHardwareMetricUrl(Environment.GetEnvironmentVariable(variable));
			if (!string.IsNullOrWhiteSpace(configured) && seen.Add(configured))
			{
				yield return configured;
			}
		}
		foreach (string inferred in EnumerateForwardedServerHardwareUrlsFromRuntime())
		{
			string normalized = NormalizeServerHardwareMetricUrl(inferred);
			if (!string.IsNullOrWhiteSpace(normalized) && seen.Add(normalized))
			{
				yield return normalized;
			}
		}
		if (_chatServerPort != 12437)
		{
			string defaultNativeWorkstation = "http://127.0.0.1:12437/api/server-hardware";
			if (seen.Add(defaultNativeWorkstation))
			{
				yield return defaultNativeWorkstation;
			}
		}
	}

	private IEnumerable<string> EnumerateForwardedServerHardwareUrlsFromRuntime()
	{
		ILmVsProxyModelRuntime runtime;
		try
		{
			runtime = GetEffectiveLocalModelRuntime();
		}
		catch
		{
			yield break;
		}
		if (runtime != null && !string.IsNullOrWhiteSpace(runtime.OpenAiBaseUrl) && Uri.TryCreate(runtime.OpenAiBaseUrl, UriKind.Absolute, out Uri runtimeUri) && runtimeUri.Port > 0)
		{
			int workstationPort = runtimeUri.Port + 2;
			if (workstationPort > 0 && workstationPort <= 65535 && workstationPort != _chatServerPort)
			{
				UriBuilder builder = new UriBuilder(runtimeUri.Scheme, runtimeUri.Host, workstationPort)
				{
					Path = "api/server-hardware",
					Query = ""
				};
				yield return builder.Uri.ToString();
			}
		}
	}

	private static bool ShouldTryForwardedServerHardwareGpuMetric()
	{
		if (!string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable("JACKLLM_SERVER_HARDWARE_URL")) || !string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable("JACKLLM_WORKSTATION_HARDWARE_URL")))
		{
			return true;
		}
		if (RuntimeInformation.IsOSPlatform(OSPlatform.Linux))
		{
			return true;
		}
		return IsWineEnvironment();
	}

	private static bool IsWineEnvironment()
	{
		string[] array = new string[4] { "WINEPREFIX", "WINELOADERNOEXEC", "WINEDLLPATH", "WINEDEBUG" };
		foreach (string variable in array)
		{
			if (!string.IsNullOrWhiteSpace(Environment.GetEnvironmentVariable(variable)))
			{
				return true;
			}
		}
		return false;
	}

	private static string NormalizeServerHardwareMetricUrl(string value)
	{
		value = (value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(value))
		{
			return "";
		}
		if (value.IndexOf("://", StringComparison.Ordinal) < 0)
		{
			value = "http://" + value.TrimStart('/');
		}
		if (!Uri.TryCreate(value, UriKind.Absolute, out Uri uri) || string.IsNullOrWhiteSpace(uri.Host))
		{
			return "";
		}
		UriBuilder builder = new UriBuilder(uri);
		string path = (builder.Path ?? "").TrimEnd('/');
		if (!path.EndsWith("/api/server-hardware", StringComparison.OrdinalIgnoreCase))
		{
			path += "/api/server-hardware";
		}
		builder.Path = path.TrimStart('/');
		builder.Query = "";
		return builder.Uri.ToString();
	}

	private static string ReadHardwareJsonString(JsonElement element, string name)
	{
		if (!element.TryGetProperty(name, out var value) || value.ValueKind == JsonValueKind.Null || value.ValueKind == JsonValueKind.Undefined)
		{
			return "";
		}
		if (value.ValueKind == JsonValueKind.String)
		{
			return value.GetString() ?? "";
		}
		return value.ToString();
	}

	private static bool ReadHardwareJsonBool(JsonElement element, string name)
	{
		if (!element.TryGetProperty(name, out var value))
		{
			return false;
		}
		if (value.ValueKind == JsonValueKind.True)
		{
			return true;
		}
		if (value.ValueKind == JsonValueKind.False)
		{
			return false;
		}
		bool parsed;
		return bool.TryParse(value.ToString(), out parsed) && parsed;
	}

	private static double? ReadHardwareJsonNullableDouble(JsonElement element, string name)
	{
		if (!element.TryGetProperty(name, out var value) || value.ValueKind == JsonValueKind.Null || value.ValueKind == JsonValueKind.Undefined)
		{
			return null;
		}
		if (value.ValueKind == JsonValueKind.Number && value.TryGetDouble(out var number))
		{
			return NormalizeMetricNumber(number);
		}
		if (double.TryParse(value.ToString(), NumberStyles.Float, CultureInfo.InvariantCulture, out var parsed))
		{
			return NormalizeMetricNumber(parsed);
		}
		return null;
	}

	private static ulong ReadHardwareJsonUInt64(JsonElement element, string name)
	{
		if (!element.TryGetProperty(name, out var value) || value.ValueKind == JsonValueKind.Null || value.ValueKind == JsonValueKind.Undefined)
		{
			return 0uL;
		}
		if (value.ValueKind == JsonValueKind.Number)
		{
			if (value.TryGetUInt64(out var unsigned))
			{
				return unsigned;
			}
			if (value.TryGetDouble(out var number))
			{
				return (number <= 0.0) ? 0 : ((ulong)Math.Round(Math.Min(number, 1.8446744073709552E+19)));
			}
		}
		ulong parsed;
		return ulong.TryParse(value.ToString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? parsed : 0;
	}

	private ServerHardwareNetworkMetric BuildServerHardwareNetworkMetric(DateTimeOffset now)
	{
		try
		{
			ulong receivedBytes = 0uL;
			ulong sentBytes = 0uL;
			NetworkInterface[] allNetworkInterfaces = NetworkInterface.GetAllNetworkInterfaces();
			foreach (NetworkInterface networkInterface in allNetworkInterfaces)
			{
				if (networkInterface != null && networkInterface.OperationalStatus == OperationalStatus.Up && networkInterface.NetworkInterfaceType != NetworkInterfaceType.Loopback && networkInterface.NetworkInterfaceType != NetworkInterfaceType.Tunnel)
				{
					IPv4InterfaceStatistics statistics = networkInterface.GetIPv4Statistics();
					if (statistics != null)
					{
						receivedBytes = SaturatingAdd(receivedBytes, (ulong)Math.Max(0L, statistics.BytesReceived));
						sentBytes = SaturatingAdd(sentBytes, (ulong)Math.Max(0L, statistics.BytesSent));
					}
				}
			}
			double downKbps = 0.0;
			double upKbps = 0.0;
			if (_lastServerHardwareNetworkSampleUtc != DateTimeOffset.MinValue && receivedBytes >= _lastServerHardwareNetworkReceivedBytes && sentBytes >= _lastServerHardwareNetworkSentBytes)
			{
				double seconds = Math.Max(0.001, (now - _lastServerHardwareNetworkSampleUtc).TotalSeconds);
				downKbps = (double)(receivedBytes - _lastServerHardwareNetworkReceivedBytes) * 8.0 / seconds / 1000.0;
				upKbps = (double)(sentBytes - _lastServerHardwareNetworkSentBytes) * 8.0 / seconds / 1000.0;
			}
			_lastServerHardwareNetworkSampleUtc = now;
			_lastServerHardwareNetworkReceivedBytes = receivedBytes;
			_lastServerHardwareNetworkSentBytes = sentBytes;
			return new ServerHardwareNetworkMetric
			{
				available = true,
				downKbps = NormalizeMetricNumber(downKbps),
				upKbps = NormalizeMetricNumber(upKbps),
				text = "Down " + FormatMetricKbps(downKbps) + " / Up " + FormatMetricKbps(upKbps)
			};
		}
		catch
		{
			return ServerHardwareNetworkMetric.Unavailable("Unavailable");
		}
	}

	private ServerHardwareIoMetric BuildServerHardwareIoMetric(DateTimeOffset now)
	{
		try
		{
			using Process process = Process.GetCurrentProcess();
			if (!TryGetCurrentProcessIoBytes(process.Handle, out var readBytes, out var writeBytes))
			{
				return ServerHardwareIoMetric.Unavailable("Unavailable");
			}
			double readBps = 0.0;
			double writeBps = 0.0;
			if (_lastServerHardwareIoSampleUtc != DateTimeOffset.MinValue && readBytes >= _lastServerHardwareIoReadBytes && writeBytes >= _lastServerHardwareIoWriteBytes)
			{
				double seconds = Math.Max(0.001, (now - _lastServerHardwareIoSampleUtc).TotalSeconds);
				readBps = (double)(readBytes - _lastServerHardwareIoReadBytes) / seconds;
				writeBps = (double)(writeBytes - _lastServerHardwareIoWriteBytes) / seconds;
			}
			_lastServerHardwareIoSampleUtc = now;
			_lastServerHardwareIoReadBytes = readBytes;
			_lastServerHardwareIoWriteBytes = writeBytes;
			return new ServerHardwareIoMetric
			{
				available = true,
				readBps = NormalizeMetricNumber(readBps),
				writeBps = NormalizeMetricNumber(writeBps),
				text = "Read " + FormatMetricBytesPerSecond(readBps) + " / Write " + FormatMetricBytesPerSecond(writeBps)
			};
		}
		catch
		{
			return ServerHardwareIoMetric.Unavailable("Unavailable");
		}
	}

	private static double ClampPercent(double value)
	{
		if (double.IsNaN(value) || double.IsInfinity(value))
		{
			return 0.0;
		}
		return Math.Max(0.0, Math.Min(100.0, value));
	}

	private static double NormalizeMetricNumber(double value)
	{
		if (double.IsNaN(value) || double.IsInfinity(value) || value < 0.0)
		{
			return 0.0;
		}
		return value;
	}

	private static double ParseMetricDouble(string value)
	{
		if (double.TryParse((value ?? "").Trim(), NumberStyles.Float, CultureInfo.InvariantCulture, out var result))
		{
			return NormalizeMetricNumber(result);
		}
		return 0.0;
	}

	private static ulong MegabytesToBytes(double megabytes)
	{
		double bytes = NormalizeMetricNumber(megabytes) * 1024.0 * 1024.0;
		return (bytes >= 1.8446744073709552E+19) ? ulong.MaxValue : ((ulong)Math.Round(bytes));
	}

	private static string FormatMetricPercent(double value)
	{
		return ClampPercent(value).ToString("0", CultureInfo.InvariantCulture) + "%";
	}

	private static string FormatMetricKbps(double value)
	{
		double kbps = NormalizeMetricNumber(value);
		if (kbps >= 1000.0)
		{
			return (kbps / 1000.0).ToString("0.0", CultureInfo.InvariantCulture) + " Mbps";
		}
		return kbps.ToString((kbps >= 10.0) ? "0" : "0.0", CultureInfo.InvariantCulture) + " Kbps";
	}

	private static string FormatMetricMegabytes(double value)
	{
		double megabytes = NormalizeMetricNumber(value);
		if (megabytes >= 1024.0)
		{
			return (megabytes / 1024.0).ToString("0.0", CultureInfo.InvariantCulture) + " GB";
		}
		return megabytes.ToString("0", CultureInfo.InvariantCulture) + " MB";
	}

	private static string FormatMetricBytes(ulong value)
	{
		double bytes = value;
		string[] units = new string[5] { "B", "KB", "MB", "GB", "TB" };
		int unit = 0;
		while (bytes >= 1024.0 && unit < units.Length - 1)
		{
			bytes /= 1024.0;
			unit++;
		}
		string format = ((unit == 0) ? "0" : ((bytes < 10.0) ? "0.0" : "0"));
		return bytes.ToString(format, CultureInfo.InvariantCulture) + " " + units[unit];
	}

	private static string FormatMetricBytesPerSecond(double value)
	{
		double bytes = NormalizeMetricNumber(value);
		string[] units = new string[4] { "B/s", "KB/s", "MB/s", "GB/s" };
		int unit = 0;
		while (bytes >= 1024.0 && unit < units.Length - 1)
		{
			bytes /= 1024.0;
			unit++;
		}
		string format = ((unit == 0) ? "0" : ((bytes < 10.0) ? "0.0" : "0"));
		return bytes.ToString(format, CultureInfo.InvariantCulture) + " " + units[unit];
	}

	private string HandleWebAuthCorsPreflight(HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		SetHttpStatus(request, 204, "No Content");
		return "";
	}

	private string BuildSocketJackManagedAccountsError(HttpRequest request)
	{
		string authority = NormalizeHttpsAuthority(SocketJackAuthServerUrl);
		if (string.IsNullOrWhiteSpace(authority))
		{
			authority = "https://socketjack.com";
		}
		return BuildJsonError(request, 410, "Gone", "JackLLM no longer stores accounts locally. Sign in and manage accounts on " + authority + ".");
	}

	private string HandleWebAuthRegisterRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!StoreLocalWebAuthAccounts)
		{
			return BuildSocketJackManagedAccountsError(request);
		}
		try
		{
			bool localAdmin = IsLocalAdmin(connection, request);
			bool openRegistration = AllowOpenRegistration;
			if (!localAdmin && !openRegistration)
			{
				return BuildJsonError(request, 403, "Forbidden", "Open registration is disabled. Send a registration request for administrator approval.");
			}
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string username = ExtractStringProperty(root, "username") ?? ExtractStringProperty(root, "user") ?? ExtractStringProperty(root, "login");
			string password = ExtractStringProperty(root, "password") ?? ExtractStringProperty(root, "pass");
			JsonElement overwriteElement;
			bool overwrite = localAdmin && root.TryGetProperty("overwrite", out overwriteElement) && ReadJsonBool(overwriteElement, fallback: false);
			if (!TryNormalizeWebAuthUserName(username, out var normalizedUserName, out var userError))
			{
				return BuildJsonError(request, 400, "Bad Request", userError);
			}
			if (!IsValidWebAuthPassword(password, out var passwordError))
			{
				return BuildJsonError(request, 400, "Bad Request", passwordError);
			}
			WebAuthRecord record = CreateWebAuthRecord(normalizedUserName, password);
			record.lastClientIp = ExtractClientIp(connection, request) ?? "";
			if (localAdmin && ((root.TryGetProperty("isAdministrator", out var isAdministratorElement) && ReadJsonBool(isAdministratorElement, fallback: false)) || (root.TryGetProperty("administrator", out var administratorElement) && ReadJsonBool(administratorElement, fallback: false)) || !HasAnyWebAuthAdministrator()))
			{
				record.isAdministrator = true;
			}
			bool created = SaveWebAuthRecord(record, overwrite);
			if (!created && !overwrite)
			{
				return BuildJsonError(request, 409, "Conflict", "A WebAuth user with that name already exists.");
			}
			string token = "";
			DateTimeOffset expires = DateTimeOffset.UtcNow.Add(WebAuthTokenLifetime);
			if (!localAdmin)
			{
				token = GenerateWebAuthToken();
				record.tokenHash = HashWebAuthToken(token);
				record.tokenExpiresUtc = expires.ToString("O");
				UpsertWebAuthRecord(record);
				SetWebAuthCookie(request, token, expires);
				LinkWebAuthUserToIp(record.userName, record.lastClientIp);
				RememberChatOwnerEncryptionSecret("webauth:" + record.userName.ToLowerInvariant(), password);
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				authenticated = !localAdmin,
				username = normalizedUserName,
				isAdministrator = record.isAdministrator,
				created = created,
				overwritten = (!created && overwrite),
				canRegisterRemotely = openRegistration,
				tokenType = (string.IsNullOrWhiteSpace(token) ? "" : "Bearer"),
				accessToken = token,
				expiresUtc = (string.IsNullOrWhiteSpace(token) ? "" : record.tokenExpiresUtc),
				usage = BuildChatUsageSnapshot("webauth:" + normalizedUserName.ToLowerInvariant(), record),
				table = "Auth.Users"
			});
		}
		catch (Exception ex)
		{
			LogMessage("[WebAuth] Register failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleWebAuthRegistrationRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!StoreLocalWebAuthAccounts)
		{
			return BuildSocketJackManagedAccountsError(request);
		}
		try
		{
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string username = ExtractStringProperty(root, "username") ?? ExtractStringProperty(root, "user") ?? ExtractStringProperty(root, "login");
			string password = ExtractStringProperty(root, "password") ?? ExtractStringProperty(root, "pass");
			if (!TryNormalizeWebAuthUserName(username, out var normalizedUserName, out var userError))
			{
				return BuildJsonError(request, 400, "Bad Request", userError);
			}
			if (!IsValidWebAuthPassword(password, out var passwordError))
			{
				return BuildJsonError(request, 400, "Bad Request", passwordError);
			}
			if (GetWebAuthRecord(normalizedUserName) != null)
			{
				return BuildJsonError(request, 409, "Conflict", "A WebAuth user with that name already exists.");
			}
			string clientIp = ExtractClientIp(connection, request) ?? "";
			if (AllowOpenRegistration || IsLocalAdmin(connection, request))
			{
				WebAuthRecord record = CreateWebAuthRecord(normalizedUserName, password);
				record.lastClientIp = clientIp;
				if (IsLocalAdmin(connection, request) && !HasAnyWebAuthAdministrator())
				{
					record.isAdministrator = true;
				}
				if (!SaveWebAuthRecord(record, overwrite: false))
				{
					return BuildJsonError(request, 409, "Conflict", "A WebAuth user with that name already exists.");
				}
				string token = GenerateWebAuthToken();
				DateTimeOffset expires = DateTimeOffset.UtcNow.Add(WebAuthTokenLifetime);
				record.tokenHash = HashWebAuthToken(token);
				record.tokenExpiresUtc = expires.ToString("O");
				UpsertWebAuthRecord(record);
				SetWebAuthCookie(request, token, expires);
				LinkWebAuthUserToIp(record.userName, clientIp);
				RememberChatOwnerEncryptionSecret("webauth:" + record.userName.ToLowerInvariant(), password);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					authenticated = true,
					registered = true,
					pending = false,
					username = record.userName,
					isAdministrator = record.isAdministrator,
					tokenType = "Bearer",
					accessToken = token,
					expiresUtc = record.tokenExpiresUtc,
					usage = BuildChatUsageSnapshot("webauth:" + record.userName.ToLowerInvariant(), record)
				});
			}
			WebAuthRegistrationRequestRecord registration = SaveWebAuthRegistrationRequest(normalizedUserName, password, clientIp);
			WebAuthRegistrationRequestSnapshot snapshot = WebAuthRegistrationRequestSnapshotFromRecord(registration);
			LogMessage("[WebAuth] Registration request from " + snapshot.ClientIp + " for " + snapshot.UserName + ".");
			this.WebAuthRegistrationRequested?.Invoke(this, new WebAuthRegistrationRequestEventArgs(snapshot));
			return JsonSerializer.Serialize(new
			{
				ok = true,
				authenticated = false,
				registered = false,
				pending = true,
				requestId = snapshot.Id,
				username = snapshot.UserName,
				message = "Registration request sent. An administrator must approve it before you can sign in."
			});
		}
		catch (Exception ex)
		{
			LogMessage("[WebAuth] Registration request failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleWebAuthLoginRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		if (!StoreLocalWebAuthAccounts)
		{
			return BuildSocketJackManagedAccountsError(request);
		}
		try
		{
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string username = ExtractStringProperty(root, "username") ?? ExtractStringProperty(root, "user") ?? ExtractStringProperty(root, "login");
			string password = ExtractStringProperty(root, "password") ?? ExtractStringProperty(root, "pass");
			if (!TryValidateWebAuthCredentials(username, password, out var record, out var error))
			{
				return BuildJsonError(request, 401, "Unauthorized", error);
			}
			string token = GenerateWebAuthToken();
			DateTimeOffset expires = DateTimeOffset.UtcNow.Add(WebAuthTokenLifetime);
			record.tokenHash = HashWebAuthToken(token);
			record.tokenExpiresUtc = expires.ToString("O");
			record.lastLoginUtc = DateTimeOffset.UtcNow.ToString("O");
			record.lastClientIp = ExtractClientIp(connection, request) ?? "";
			record.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
			UpsertWebAuthRecord(record);
			SetWebAuthCookie(request, token, expires);
			LinkWebAuthUserToIp(record.userName, record.lastClientIp);
			RememberChatOwnerEncryptionSecret("webauth:" + record.userName.ToLowerInvariant(), password);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				username = record.userName,
				isAdministrator = record.isAdministrator,
				tokenType = "Bearer",
				accessToken = token,
				expiresUtc = record.tokenExpiresUtc,
				usage = BuildChatUsageSnapshot("webauth:" + record.userName.ToLowerInvariant(), record)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[WebAuth] Login failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleWebAuthLogoutRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthenticateWebAuthRequest(request, out var principal, out var error))
			{
				return BuildJsonError(request, 401, "Unauthorized", error);
			}
			if (StoreLocalWebAuthAccounts)
			{
				ClearWebAuthToken(principal.UserName);
			}
			ClearWebAuthCookie(request);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				username = principal.UserName,
				loggedOut = true
			});
		}
		catch (Exception ex)
		{
			LogMessage("[WebAuth] Logout failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleWebAuthSessionRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string clientIp = ExtractClientIp(connection, request) ?? "";
			if (TryAuthenticateWebAuthRequest(request, out var principal, out var _))
			{
				string authOwnerKey = "webauth:" + principal.UserName.ToLowerInvariant();
				RememberSocketJackBearerToken(authOwnerKey, principal.AccessToken);
				RememberChatOwnerEncryptionSecret(authOwnerKey, ExtractChatSessionEncryptionSecret(request, principal));
				WebAuthRecord record = (StoreLocalWebAuthAccounts ? GetOrCreateWebAuthTokenAccount(principal.UserName, connection, request) : null);
				LinkWebAuthUserToIp(principal.UserName, clientIp);
				bool isServerOwner = IsServerOwnerPrincipal(principal);
				bool isAdministrator = principal.IsAdministrator || IsDefaultAdministratorUserName(principal.UserName) || isServerOwner || (record != null && record.enabled && record.isAdministrator) || IsWebAuthAdministrator(principal.UserName);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					authenticated = true,
					username = principal.UserName,
					authType = principal.AuthType,
					accountType = (principal.AccountType ?? ""),
					isPublicAccount = principal.IsPublicAccount,
					expiresUtc = principal.ExpiresUtc,
					ownerKey = authOwnerKey,
					clientIp = clientIp,
					isAdministrator = isAdministrator,
					isOwner = isServerOwner,
					isServerOwner = isServerOwner,
					serverOwnerUserName = (principal.ServerOwnerUserName ?? GetConfiguredServerOwnerUserName()),
					canRegisterOpen = (StoreLocalWebAuthAccounts && AllowOpenRegistration),
					usage = BuildChatUsageSnapshot(authOwnerKey, record),
					table = (StoreLocalWebAuthAccounts ? "Auth.Users" : "SocketJack.com")
				});
			}
			if (IsLocalAdmin(connection, request))
			{
				string ownerKey = GetChatSessionOwnerKey(connection, request);
				string localUserName = GetLocalChatPromptUserName();
				string serverOwnerUserName = GetConfiguredServerOwnerUserName();
				return JsonSerializer.Serialize(new
				{
					ok = true,
					authenticated = true,
					username = (string.IsNullOrWhiteSpace(localUserName) ? "local user" : localUserName),
					authType = "Localhost",
					accountType = "local",
					isPublicAccount = false,
					expiresUtc = "",
					ownerKey = ownerKey,
					clientIp = clientIp,
					isAdministrator = true,
					isOwner = true,
					isServerOwner = true,
					serverOwnerUserName = string.IsNullOrWhiteSpace(serverOwnerUserName) ? "localhost" : serverOwnerUserName,
					canRegisterOpen = AllowOpenRegistration,
					usage = GetChatUsageSnapshot(ownerKey),
					table = "Auth.Users"
				});
			}
			string guestOwnerKey = GetChatSessionOwnerKey(connection, request);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				authenticated = false,
				username = "guest",
				authType = "Ip",
				accountType = "guest",
				isPublicAccount = true,
				ownerKey = guestOwnerKey,
				clientIp = clientIp,
				isAdministrator = false,
				isOwner = false,
				isServerOwner = false,
				serverOwnerUserName = GetConfiguredServerOwnerUserName(),
				canRegisterOpen = AllowOpenRegistration,
				usage = GetChatUsageSnapshot(guestOwnerKey),
				table = "Auth.Users"
			});
		}
		catch (Exception ex)
		{
			LogMessage("[WebAuth] Session check failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private double GetEffectiveTokenUsdPerToken(ChatCostSettings settings)
	{
		double value = NormalizeCostNumber(settings?.tokenUsdPerToken ?? 0.0);
		return (value > 0.0) ? value : 5E-05;
	}

	private double GetEffectiveServiceTaxRate(ChatCostSettings settings)
	{
		return Math.Max(0.015, NormalizeCostNumber(settings?.serviceTaxRate ?? 0.0));
	}

	private long GetPricingTokensPerHour(ChatCostSettings settings)
	{
		long advertised = GetEffectiveAdvertisedTokenRate(settings);
		if (advertised > 0)
		{
			return advertised;
		}
		long min = Math.Max(0L, settings?.tokenRateRequestMin ?? 0);
		long max = Math.Max(min, settings?.tokenRateRequestMax ?? 0);
		if (max > 0)
		{
			return Math.Max(min, Math.Min(max, 10000L));
		}
		return 10000L;
	}

	private double CalculateEstimatedHardwareUsdPerToken(ChatCostSettings settings)
	{
		settings = settings ?? GetChatCostSettings();
		long tokensPerHour = Math.Max(1L, GetPricingTokensPerHour(settings));
		double ramGb = Math.Max(1.0, GetCurrentProcessRamGbEstimate());
		double gpuHourly = CalculateElectricityCostUsd(settings.gpuTdpWatts, 3600.0, settings);
		double cpuHourly = CalculateElectricityCostUsd(settings.cpuTdpWatts, 3600.0, settings);
		double ramHourly = CalculateElectricityCostUsd(settings.ramWattsPerGb * ramGb, 3600.0, settings);
		double systemHourly = CalculateElectricityCostUsd(settings.systemWatts, 3600.0, settings);
		double hourlyHardwareUsd = NormalizeCostNumber(gpuHourly + cpuHourly + ramHourly + systemHourly);
		return NormalizeCostNumber(hourlyHardwareUsd / (double)tokensPerHour);
	}

	private WebAuthRecord GetOrCreateWebAuthTokenAccount(string username, NetworkConnection connection, HttpRequest request)
	{
		if (!TryNormalizeWebAuthUserName(username, out var normalizedUserName, out var _))
		{
			normalizedUserName = (username ?? "").Trim();
		}
		WebAuthRecord record = GetWebAuthRecord(normalizedUserName);
		if (record != null)
		{
			return record;
		}
		string now = DateTimeOffset.UtcNow.ToString("O");
		record = new WebAuthRecord
		{
			userName = normalizedUserName,
			createdUtc = now,
			updatedUtc = now,
			enabled = true,
			isAdministrator = IsDefaultAdministratorUserName(normalizedUserName),
			lastClientIp = (ExtractClientIp(connection, request) ?? "")
		};
		if (!StoreLocalWebAuthAccounts)
		{
			return record;
		}
		UpsertWebAuthRecord(record);
		return record;
	}

	private string HandleChatCostsGetRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				canEdit = IsDatabaseAdministrator(connection, request),
				settings = GetChatCostSettings(),
				usage = GetChatUsageSnapshot(ownerKey)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat Costs] Load failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleChatCostsSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!IsDatabaseAdministrator(connection, request))
			{
				return BuildDatabaseAdminOnlyJsonError(request, "");
			}
			ChatCostSettings settings = GetChatCostSettings();
			string body = request?.Body ?? "{}";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				if (root.TryGetProperty("tokenUsdPerToken", out var tokenUsdPerToken))
				{
					settings.tokenUsdPerToken = Math.Max(0.0, ReadJsonDouble(tokenUsdPerToken, settings.tokenUsdPerToken));
				}
				if (root.TryGetProperty("tokenUsdPerThousand", out var tokenUsdPerThousand))
				{
					settings.tokenUsdPerToken = Math.Max(0.0, ReadJsonDouble(tokenUsdPerThousand, settings.tokenUsdPerToken * 1000.0) / 1000.0);
				}
				if (root.TryGetProperty("electricityCentsPerKwh", out var electricityCents))
				{
					settings.electricityCentsPerKwh = Math.Max(0.0, ReadJsonDouble(electricityCents, settings.electricityCentsPerKwh));
				}
				if (root.TryGetProperty("electricityMultiplier", out var electricityMultiplier))
				{
					settings.electricityMultiplier = Math.Max(0.0, ReadJsonDouble(electricityMultiplier, settings.electricityMultiplier));
				}
				if (root.TryGetProperty("gpuTdpWatts", out var gpuTdpWatts))
				{
					settings.gpuTdpWatts = Math.Max(0.0, ReadJsonDouble(gpuTdpWatts, settings.gpuTdpWatts));
				}
				if (root.TryGetProperty("cpuTdpWatts", out var cpuTdpWatts))
				{
					settings.cpuTdpWatts = Math.Max(0.0, ReadJsonDouble(cpuTdpWatts, settings.cpuTdpWatts));
				}
				if (root.TryGetProperty("ramWattsPerGb", out var ramWattsPerGb))
				{
					settings.ramWattsPerGb = Math.Max(0.0, ReadJsonDouble(ramWattsPerGb, settings.ramWattsPerGb));
				}
				if (root.TryGetProperty("systemWatts", out var systemWatts))
				{
					settings.systemWatts = Math.Max(0.0, ReadJsonDouble(systemWatts, settings.systemWatts));
				}
				if (root.TryGetProperty("ioWattsPerGbps", out var ioWattsPerGbps))
				{
					settings.ioWattsPerGbps = Math.Max(0.0, ReadJsonDouble(ioWattsPerGbps, settings.ioWattsPerGbps));
				}
				if (root.TryGetProperty("serviceTaxRate", out var serviceTaxRate))
				{
					settings.serviceTaxRate = Math.Max(0.0, ReadJsonDouble(serviceTaxRate, settings.serviceTaxRate));
				}
				if (root.TryGetProperty("serviceTaxPercent", out var serviceTaxPercent))
				{
					settings.serviceTaxRate = Math.Max(0.0, ReadJsonDouble(serviceTaxPercent, settings.serviceTaxRate * 100.0) / 100.0);
				}
				if (root.TryGetProperty("storageType", out var storageType))
				{
					settings.storageType = NormalizeStorageType(ExtractJsonString(storageType));
				}
				if (root.TryGetProperty("storageCostFactor", out var storageCostFactor))
				{
					settings.storageCostFactor = ClampStorageCostFactor(ReadJsonDouble(storageCostFactor, settings.storageCostFactor));
				}
				if (root.TryGetProperty("storageLimitBytes", out var storageLimitBytes))
				{
					settings.storageLimitBytes = Math.Max(0L, ReadJsonLong(storageLimitBytes, settings.storageLimitBytes));
				}
				if (root.TryGetProperty("allowOpenRegistration", out var allowOpenRegistration))
				{
					settings.allowOpenRegistration = ReadJsonBool(allowOpenRegistration, settings.allowOpenRegistration);
				}
				if (root.TryGetProperty("tokenRateRequestsEnabled", out var tokenRateRequestsEnabled))
				{
					settings.tokenRateRequestsEnabled = ReadJsonBool(tokenRateRequestsEnabled, settings.tokenRateRequestsEnabled);
				}
				if (root.TryGetProperty("tokenRateRequestMin", out var tokenRateRequestMin))
				{
					settings.tokenRateRequestMin = Math.Max(0L, ReadJsonLong(tokenRateRequestMin, settings.tokenRateRequestMin));
				}
				if (root.TryGetProperty("tokenRateRequestMax", out var tokenRateRequestMax))
				{
					settings.tokenRateRequestMax = Math.Max(0L, ReadJsonLong(tokenRateRequestMax, settings.tokenRateRequestMax));
				}
				if (root.TryGetProperty("advertisedTokenRate", out var advertisedTokenRate))
				{
					settings.advertisedTokenRate = Math.Max(0L, ReadJsonLong(advertisedTokenRate, settings.advertisedTokenRate));
				}
				JsonElement tokensPerSecond;
				JsonElement maxTokensPerSecond;
				if (root.TryGetProperty("throughputTokensPerSecond", out var throughputTokensPerSecond))
				{
					settings.throughputTokensPerSecond = NormalizeChatThroughputTokensPerSecond(ReadJsonLong(throughputTokensPerSecond, settings.throughputTokensPerSecond));
				}
				else if (root.TryGetProperty("tokensPerSecond", out tokensPerSecond))
				{
					settings.throughputTokensPerSecond = NormalizeChatThroughputTokensPerSecond(ReadJsonLong(tokensPerSecond, settings.throughputTokensPerSecond));
				}
				else if (root.TryGetProperty("maxTokensPerSecond", out maxTokensPerSecond))
				{
					settings.throughputTokensPerSecond = NormalizeChatThroughputTokensPerSecond(ReadJsonLong(maxTokensPerSecond, settings.throughputTokensPerSecond));
				}
				NormalizeTokenRateRequestSettings(settings);
				SaveChatCostSettings(settings);
			}
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				settings = GetChatCostSettings(),
				usage = GetChatUsageSnapshot(ownerKey)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat Costs] Save failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

