	private string HandleFinanceAccountSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			if (!identity.Authenticated && !identity.IsAdmin)
			{
				return BuildJsonError(request, 401, "Unauthorized", "Sign in before updating account finance settings.");
			}
			FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(identity.OwnerKey, identity.UserName);
			string body = request?.Body ?? "{}";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				profile.UserName = identity.UserName;
				profile.BillingEmail = ExtractStringProperty(root, "billingEmail") ?? profile.BillingEmail;
				profile.StripeCustomerId = ExtractStringProperty(root, "stripeCustomerId") ?? profile.StripeCustomerId;
				profile.StripeConnectedAccountId = ExtractStringProperty(root, "stripeConnectedAccountId") ?? profile.StripeConnectedAccountId;
				profile.TaxCountry = (ExtractStringProperty(root, "taxCountry") ?? profile.TaxCountry ?? "US").Trim().ToUpperInvariant();
				profile.TaxClassification = ExtractStringProperty(root, "taxClassification") ?? profile.TaxClassification;
				profile.TaxpayerName = ExtractStringProperty(root, "taxpayerName") ?? profile.TaxpayerName;
				profile.PayoutSchedule = NormalizeFinancePayoutSchedule(ExtractStringProperty(root, "payoutSchedule") ?? profile.PayoutSchedule);
				profile.PayoutDay = NormalizeFinanceWeeklyPayoutDay(ExtractStringProperty(root, "payoutDay") ?? ExtractStringProperty(root, "weeklyPayoutDay") ?? profile.PayoutDay);
				profile.PayoutMethod = NormalizeFinancePayoutMethod(ExtractStringProperty(root, "payoutMethod") ?? profile.PayoutMethod);
				profile.InstantPayoutDestinationId = ExtractStringProperty(root, "instantPayoutDestinationId") ?? ExtractStringProperty(root, "instantDestinationId") ?? profile.InstantPayoutDestinationId;
				string taxIdentifier = ExtractStringProperty(root, "taxIdentifier");
				if (!string.IsNullOrWhiteSpace(taxIdentifier))
				{
					profile.TaxIdentifierMasked = MaskTaxIdentifier(taxIdentifier);
				}
				if (root.TryGetProperty("taxFormConsent", out var taxFormConsent))
				{
					profile.TaxFormConsent = ReadJsonBool(taxFormConsent, profile.TaxFormConsent);
				}
			}
			profile.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
			UpsertFinanceAccountProfile(profile);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				account = FinanceAccountProfileToPayload(profile),
				payoutPolicy = BuildFinancePayoutPolicyPayload(profile),
				tax1099 = BuildFinanceTax1099Payload(identity.OwnerKey, ReadFinancePeriod(request))
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Account save failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

