	private string HandleFinancePayoutsMutationRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			if (!identity.Authenticated && !identity.IsAdmin)
			{
				return BuildJsonError(request, 401, "Unauthorized", "Sign in before managing payouts.");
			}
			string action = "";
			string payoutId = "";
			string note = "";
			string method = "";
			string destinationId = "";
			string weeklyDay = "";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(request?.Body) ? "{}" : request.Body))
			{
				JsonElement root = document.RootElement;
				action = (ExtractStringProperty(root, "action") ?? "request").Trim().ToLowerInvariant();
				payoutId = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "payoutId") ?? "";
				note = ExtractStringProperty(root, "note") ?? "";
				method = ExtractStringProperty(root, "method") ?? ExtractStringProperty(root, "payoutMethod") ?? "";
				destinationId = ExtractStringProperty(root, "destinationId") ?? ExtractStringProperty(root, "instantPayoutDestinationId") ?? ExtractStringProperty(root, "externalAccountId") ?? "";
				weeklyDay = ExtractStringProperty(root, "weeklyPayoutDay") ?? ExtractStringProperty(root, "payoutDay") ?? "";
			}
			FinancePeriod period = ReadFinancePeriod(request);
			FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(identity.OwnerKey, identity.UserName);
			if (action == "instant")
			{
				method = "instant";
			}
			else if (action == "direct-deposit" || action == "direct_deposit")
			{
				method = "direct_deposit";
			}
			else if (action == "weekly")
			{
				method = "weekly";
			}
			if (action == "configure-weekly" || action == "weekly-schedule")
			{
				ConfigureFinanceWeeklyPayoutSchedule(profile, weeklyDay, note);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					account = FinanceAccountProfileToPayload(profile),
					payoutPolicy = BuildFinancePayoutPolicyPayload(profile),
					dashboard = BuildFinanceDashboard(identity, period, "date", descending: true)
				});
			}
			if (action == "run-weekly" || action == "create-weekly-payouts")
			{
				if (!identity.IsAdmin)
				{
					return BuildDatabaseAdminOnlyJsonError(request, "");
				}
				List<FinancePayoutRecord> records = CreateWeeklyFinancePayouts(identity, weeklyDay, note);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					payouts = records.Select(FinancePayoutToPayload).ToList(),
					dashboard = BuildFinanceDashboard(identity, period, "date", descending: true)
				});
			}
			if (action == "request" || action == "create" || action == "weekly")
			{
				string payoutMethod = NormalizeFinancePayoutMethod(method);
				FinancePeriod payoutPeriod = ((payoutMethod == "weekly") ? BuildFinanceWeeklyPayoutPeriod(profile.PayoutDay) : period);
				FinancePayoutRecord record = CreateFinancePayout(identity.OwnerKey, identity.UserName, payoutPeriod, note, payoutMethod, destinationId, (payoutMethod == "weekly") ? "weekly" : "manual");
				record = TrySettleFinancePayoutWithPaymentProcessor(record, profile, note);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					payout = FinancePayoutToPayload(record),
					dashboard = BuildFinanceDashboard(identity, period, "date", descending: true)
				});
			}
			if (action == "settle")
			{
				if (!identity.IsAdmin)
				{
					return BuildDatabaseAdminOnlyJsonError(request, "");
				}
				FinancePayoutRecord existing = FindFinancePayoutById(payoutId);
				if (existing == null)
				{
					return BuildJsonError(request, 404, "Not Found", "Payout was not found.");
				}
				FinanceAccountProfile payoutProfile = GetOrCreateFinanceAccountProfile(existing.OwnerKey, existing.UserName);
				FinancePayoutRecord record2 = TrySettleFinancePayoutWithPaymentProcessor(existing, payoutProfile, note);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					payout = FinancePayoutToPayload(record2),
					dashboard = BuildFinanceDashboard(identity, period, "date", descending: true)
				});
			}
			if (action == "paid" || action == "mark-paid")
			{
				if (!identity.IsAdmin)
				{
					return BuildDatabaseAdminOnlyJsonError(request, "");
				}
				FinancePayoutRecord record3 = UpdateFinancePayoutStatus(payoutId, "paid", note);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					payout = FinancePayoutToPayload(record3),
					dashboard = BuildFinanceDashboard(identity, period, "date", descending: true)
				});
			}
			if (action == "cancel" || action == "void")
			{
				FinancePayoutRecord record4 = UpdateFinancePayoutStatus(payoutId, "cancelled", note);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					payout = FinancePayoutToPayload(record4),
					dashboard = BuildFinanceDashboard(identity, period, "date", descending: true)
				});
			}
			return BuildJsonError(request, 400, "Bad Request", "Unknown payout action.");
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Payout mutation failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleFinancePaymentsGetRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			FinancePeriod period = ReadFinancePeriod(request);
			List<FinancePaymentRecord> payments = (from payment in ListFinancePayments(identity, period)
				orderby payment.CreatedUtc descending
				select payment).ToList();
			long paidCents = payments.Where((FinancePaymentRecord payment) => string.Equals(payment.Status, "paid", StringComparison.OrdinalIgnoreCase)).Sum((FinancePaymentRecord payment) => payment.AmountCents);
			long pendingCents = payments.Where((FinancePaymentRecord payment) => string.Equals(payment.Status, "created", StringComparison.OrdinalIgnoreCase) || string.Equals(payment.Status, "pending", StringComparison.OrdinalIgnoreCase)).Sum((FinancePaymentRecord payment) => payment.AmountCents);
			long disputedCents = payments.Where((FinancePaymentRecord payment) => string.Equals(payment.Status, "disputed", StringComparison.OrdinalIgnoreCase) || string.Equals(payment.Status, "refunded", StringComparison.OrdinalIgnoreCase)).Sum((FinancePaymentRecord payment) => payment.AmountCents);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				isAdmin = identity.IsAdmin,
				ownerKey = identity.OwnerKey,
				username = identity.UserName,
				period = new
				{
					startUtc = period.StartUtc.ToString("O"),
					endUtc = period.EndUtc.ToString("O"),
					key = period.Key
				},
				summary = new
				{
					count = payments.Count,
					paidCents = paidCents,
					pendingCents = pendingCents,
					disputedCents = disputedCents,
					paidUsd = NormalizeCostNumber((double)paidCents / 100.0),
					pendingUsd = NormalizeCostNumber((double)pendingCents / 100.0),
					disputedUsd = NormalizeCostNumber((double)disputedCents / 100.0)
				},
				payments = payments.Take(250).Select(FinancePaymentToPayload).ToList(),
				products = BuildFinancePaymentProductPayloads()
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Payment ledger load failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

