	private string HandleFinancePaymentCheckoutRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			if (!identity.Authenticated && !identity.IsAdmin)
			{
				return BuildJsonError(request, 401, "Unauthorized", "Sign in before buying SocketJack tokens.");
			}
			string body = request?.Body ?? "{}";
			string kind = "token_purchase";
			string productId = "";
			string customerEmail = "";
			string successUrl = "";
			string cancelUrl = "";
			string leaseId = "";
			long requestedLeaseMinutes = 0L;
			bool allowPromotionCodes = true;
			long requestedTokens = 0L;
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				if (root.ValueKind == JsonValueKind.Object)
				{
					kind = (ExtractStringProperty(root, "kind") ?? kind).Trim().ToLowerInvariant();
					productId = ExtractStringProperty(root, "productId") ?? ExtractStringProperty(root, "priceId") ?? "";
					customerEmail = ExtractStringProperty(root, "customerEmail") ?? "";
					successUrl = ExtractStringProperty(root, "successUrl") ?? "";
					cancelUrl = ExtractStringProperty(root, "cancelUrl") ?? "";
					leaseId = ExtractStringProperty(root, "leaseId") ?? ExtractStringProperty(root, "id") ?? "";
					if (root.TryGetProperty("leaseMinutes", out var leaseMinutesElement))
					{
						requestedLeaseMinutes = Math.Max(0L, ReadJsonLong(leaseMinutesElement, 0L));
					}
					if (root.TryGetProperty("minutes", out var minutesElement))
					{
						requestedLeaseMinutes = Math.Max(requestedLeaseMinutes, ReadJsonLong(minutesElement, 0L));
					}
					if (root.TryGetProperty("tokenAmount", out var tokenAmountElement))
					{
						requestedTokens = Math.Max(0L, ReadJsonLong(tokenAmountElement, 0L));
					}
					if (root.TryGetProperty("tokens", out var tokensElement))
					{
						requestedTokens = Math.Max(requestedTokens, ReadJsonLong(tokensElement, 0L));
					}
					if (root.TryGetProperty("allowPromotionCodes", out var allowPromotionCodesElement))
					{
						allowPromotionCodes = ReadJsonBool(allowPromotionCodesElement, allowPromotionCodes);
					}
				}
			}
			if (kind == "marketplace_lease" || kind == "server_lease")
			{
				return CreateMarketplaceLeaseCheckout(identity, leaseId, requestedLeaseMinutes, customerEmail, successUrl, cancelUrl, allowPromotionCodes, cancellationToken, request);
			}
			if (kind != "token_purchase" && kind != "tokens")
			{
				return BuildJsonError(request, 400, "Bad Request", "This checkout endpoint currently accepts token_purchase payments.");
			}
			IJackLLMPaymentProcessor paymentProcessor = RequirePaymentProcessor("token checkout");
			JackLLMPaymentTokenProductConfig product = ResolveFinanceTokenProduct(productId, requestedTokens);
			if (product == null || !product.Enabled || product.TokenAmount <= 0 || product.UnitAmountCents <= 0)
			{
				return BuildJsonError(request, 400, "Bad Request", "Choose an enabled paid token product.");
			}
			FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(identity.OwnerKey, identity.UserName);
			if (string.IsNullOrWhiteSpace(customerEmail))
			{
				customerEmail = profile.BillingEmail ?? "";
			}
			string publicUrl = GetFinancePublicBaseUrl();
			if (string.IsNullOrWhiteSpace(successUrl))
			{
				successUrl = publicUrl.TrimEnd('/') + "/?checkout=success";
			}
			if (string.IsNullOrWhiteSpace(cancelUrl))
			{
				cancelUrl = publicUrl.TrimEnd('/') + "/?checkout=cancel";
			}
			successUrl = EnsureCheckoutSessionSuccessUrl(successUrl);
			long amountCents = Math.Max(0L, product.UnitAmountCents);
			FinancePaymentRecord payment = new FinancePaymentRecord
			{
				Id = "pay_" + Guid.NewGuid().ToString("N"),
				Kind = "token_purchase",
				Status = "created",
				OwnerKey = identity.OwnerKey,
				UserName = identity.UserName,
				Currency = (string.IsNullOrWhiteSpace(product.Currency) ? "usd" : product.Currency.ToLowerInvariant()),
				AmountCents = amountCents,
				SocketJackFeeCents = amountCents,
				HostAmountCents = 0L,
				TokenAmount = product.TokenAmount,
				LeaseMinutes = 0L,
				StripeCustomerId = (profile.StripeCustomerId ?? ""),
				CreatedUtc = DateTimeOffset.UtcNow.ToString("O"),
				MetadataJson = WriteFinancePaymentMetadata(new Dictionary<string, string>(StringComparer.Ordinal)
				{
					["kind"] = "socketjack.token_purchase",
					["socketjack_payment_id"] = "",
					["socketjack_payment_kind"] = "token_purchase",
					["socketjack_owner_key"] = identity.OwnerKey,
					["socketjack_user_name"] = identity.UserName,
					["socketjack_tokens"] = product.TokenAmount.ToString(CultureInfo.InvariantCulture),
					["socketjack_product_id"] = product.ProductId ?? "",
					["socketjack_price_id"] = product.PriceId ?? ""
				})
			};
			Dictionary<string, string> metadata = ReadFinancePaymentMetadata(payment.MetadataJson);
			metadata["socketjack_payment_id"] = payment.Id;
			payment.MetadataJson = WriteFinancePaymentMetadata(metadata);
			UpsertFinancePayment(payment);
			JackLLMPaymentCheckoutSessionRequest checkoutRequest = new JackLLMPaymentCheckoutSessionRequest
			{
				SuccessUrl = successUrl,
				CancelUrl = cancelUrl,
				CustomerId = (profile.StripeCustomerId ?? ""),
				CustomerEmail = (customerEmail ?? ""),
				ClientReferenceId = identity.OwnerKey,
				IdempotencyKey = payment.Id,
				AllowPromotionCodes = allowPromotionCodes
			};
			foreach (KeyValuePair<string, string> pair in metadata)
			{
				checkoutRequest.Metadata[pair.Key] = pair.Value;
			}
			checkoutRequest.LineItems.Add(new JackLLMPaymentCheckoutLineItem
			{
				PriceId = (product.PriceId ?? ""),
				ProductId = (product.ProductId ?? ""),
				ProductName = (string.IsNullOrWhiteSpace(product.Name) ? "SocketJack Tokens" : product.Name),
				Description = (string.IsNullOrWhiteSpace(product.Description) ? (product.TokenAmount.ToString(CultureInfo.InvariantCulture) + " SocketJack tokens") : product.Description),
				Currency = payment.Currency,
				UnitAmount = amountCents,
				Quantity = 1L
			});
			JackLLMPaymentCheckoutSessionResult result = paymentProcessor.CreateCheckoutSessionAsync(checkoutRequest, cancellationToken).GetAwaiter().GetResult();
			payment.StripeCheckoutSessionId = result.Id;
			payment.StripePaymentIntentId = result.PaymentIntentId;
			payment.StripeCustomerId = (string.IsNullOrWhiteSpace(result.CustomerId) ? payment.StripeCustomerId : result.CustomerId);
			payment.CheckoutUrl = result.Url;
			payment.Status = (string.Equals(result.Status, "complete", StringComparison.OrdinalIgnoreCase) ? "paid" : "pending");
			payment.AmountCents = ((result.AmountTotal.HasValue && result.AmountTotal.Value > 0) ? result.AmountTotal.Value : payment.AmountCents);
			UpsertFinancePayment(payment);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				checkout = result,
				payment = FinancePaymentToPayload(payment),
				products = BuildFinancePaymentProductPayloads()
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Payment checkout failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleFinancePaymentCheckoutSessionRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string sessionId = GetQueryParameter(request, "session_id") ?? GetQueryParameter(request, "sessionId") ?? GetQueryParameter(request, "checkoutSessionId") ?? "";
			if (string.IsNullOrWhiteSpace(sessionId))
			{
				return BuildJsonError(request, 400, "Bad Request", "Stripe Checkout Session id is required.");
			}
			string stripeAccount = FindFinancePaymentByCheckoutSessionId(sessionId.Trim())?.StripeAccountId ?? "";
			JackLLMPaymentCheckoutSessionResult result = RequirePaymentProcessor("checkout session retrieval").RetrieveCheckoutSessionAsync(sessionId.Trim(), stripeAccount, cancellationToken).GetAwaiter().GetResult();
			FinancePaymentRecord updated = ApplyStripeCheckoutSessionToPayment(result, "Checkout session retrieved by client redirect.");
			FinanceIdentity identity = GetFinanceIdentity(connection, request);
			if (updated != null && !identity.IsAdmin && !string.Equals(updated.OwnerKey, identity.OwnerKey, StringComparison.OrdinalIgnoreCase))
			{
				return BuildJsonError(request, 403, "Forbidden", "You cannot view this payment session.");
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				checkout = result,
				payment = FinancePaymentToPayload(updated)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Payment checkout session sync failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string CreateMarketplaceLeaseCheckout(FinanceIdentity identity, string leaseId, long requestedLeaseMinutes, string customerEmail, string successUrl, string cancelUrl, bool allowPromotionCodes, CancellationToken cancellationToken, HttpRequest request)
	{
		if (identity == null || (!identity.Authenticated && !identity.IsAdmin))
		{
			return BuildJsonError(request, 401, "Unauthorized", "Sign in before paying for a marketplace lease.");
		}
		if (string.IsNullOrWhiteSpace(leaseId))
		{
			return BuildJsonError(request, 400, "Bad Request", "leaseId is required for marketplace lease checkout.");
		}
		IJackLLMPaymentProcessor paymentProcessor = RequirePaymentProcessor("marketplace lease checkout");
		MarketplaceLeaseRecord lease = FindMarketplaceLeaseById(leaseId.Trim());
		if (lease == null)
		{
			return BuildJsonError(request, 404, "Not Found", "Marketplace lease was not found.");
		}
		if (!CanAccessMarketplaceLease(lease, identity.OwnerKey, identity.IsAdmin))
		{
			return BuildJsonError(request, 403, "Forbidden", "You cannot pay for this marketplace lease.");
		}
		if (requestedLeaseMinutes > 0)
		{
			lease.LeaseMinutes = requestedLeaseMinutes;
		}
		lease.LeaseRequired = true;
		lease.QuoteUsd = CalculateMarketplaceLeaseQuoteUsd(lease);
		long amountCents = UsdToMinorUnits(lease.QuoteUsd);
		if (amountCents <= 0)
		{
			return BuildJsonError(request, 400, "Bad Request", "Marketplace lease checkout requires a positive quote.");
		}
		FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(identity.OwnerKey, identity.UserName);
		if (string.IsNullOrWhiteSpace(customerEmail))
		{
			customerEmail = profile.BillingEmail ?? "";
		}
		string publicUrl = GetFinancePublicBaseUrl();
		if (string.IsNullOrWhiteSpace(successUrl))
		{
			successUrl = publicUrl.TrimEnd('/') + "/?checkout=success";
		}
		if (string.IsNullOrWhiteSpace(cancelUrl))
		{
			cancelUrl = publicUrl.TrimEnd('/') + "/?checkout=cancel";
		}
		successUrl = EnsureCheckoutSessionSuccessUrl(successUrl);
		long feeCents = Math.Max(0L, (long)Math.Round((double)amountCents * 0.015, MidpointRounding.AwayFromZero));
		long hostAmountCents = Math.Max(0L, amountCents - feeCents);
		long tokenAmount = Math.Max(1L, (long)Math.Ceiling((double)Math.Max(1L, lease.TokenRate) * ((double)Math.Max(1L, lease.LeaseMinutes) / 60.0)));
		FinancePaymentRecord payment = new FinancePaymentRecord
		{
			Id = "pay_" + Guid.NewGuid().ToString("N"),
			Kind = "marketplace_lease",
			Status = "created",
			OwnerKey = identity.OwnerKey,
			UserName = identity.UserName,
			ServerId = lease.ServerId,
			ServerName = lease.ServerName,
			SessionId = lease.Id,
			LeaseId = lease.Id,
			Currency = "usd",
			AmountCents = amountCents,
			SocketJackFeeCents = feeCents,
			HostAmountCents = hostAmountCents,
			TokenAmount = tokenAmount,
			LeaseMinutes = Math.Max(1L, lease.LeaseMinutes),
			StripeCustomerId = (profile.StripeCustomerId ?? ""),
			CreatedUtc = DateTimeOffset.UtcNow.ToString("O"),
			MetadataJson = WriteFinancePaymentMetadata(new Dictionary<string, string>(StringComparer.Ordinal)
			{
				["kind"] = "socketjack.marketplace_lease",
				["socketjack_payment_id"] = "",
				["socketjack_payment_kind"] = "marketplace_lease",
				["socketjack_owner_key"] = identity.OwnerKey,
				["socketjack_user_name"] = identity.UserName,
				["socketjack_server_id"] = lease.ServerId ?? "",
				["socketjack_server_name"] = lease.ServerName ?? "",
				["socketjack_host_owner_key"] = lease.HostOwnerKey ?? "",
				["socketjack_host_user_name"] = lease.HostUserName ?? "",
				["socketjack_lease_id"] = lease.Id,
				["socketjack_lease_minutes"] = Math.Max(1L, lease.LeaseMinutes).ToString(CultureInfo.InvariantCulture),
				["socketjack_tokens"] = tokenAmount.ToString(CultureInfo.InvariantCulture),
				["socketjack_fee_cents"] = feeCents.ToString(CultureInfo.InvariantCulture),
				["socketjack_host_amount_cents"] = hostAmountCents.ToString(CultureInfo.InvariantCulture)
			})
		};
		Dictionary<string, string> metadata = ReadFinancePaymentMetadata(payment.MetadataJson);
		metadata["socketjack_payment_id"] = payment.Id;
		payment.MetadataJson = WriteFinancePaymentMetadata(metadata);
		UpsertFinancePayment(payment);
		JackLLMPaymentCheckoutSessionRequest checkoutRequest = new JackLLMPaymentCheckoutSessionRequest
		{
			SuccessUrl = successUrl,
			CancelUrl = cancelUrl,
			CustomerId = (profile.StripeCustomerId ?? ""),
			CustomerEmail = (customerEmail ?? ""),
			ClientReferenceId = identity.OwnerKey,
			IdempotencyKey = payment.Id,
			AllowPromotionCodes = allowPromotionCodes
		};
		foreach (KeyValuePair<string, string> pair in metadata)
		{
			checkoutRequest.Metadata[pair.Key] = pair.Value;
		}
		checkoutRequest.LineItems.Add(new JackLLMPaymentCheckoutLineItem
		{
			ProductName = (string.IsNullOrWhiteSpace(lease.ServerName) ? "SocketJack peer compute lease" : (lease.ServerName + " peer compute lease")),
			Description = Math.Max(1L, lease.LeaseMinutes).ToString(CultureInfo.InvariantCulture) + " minutes of peer-rented AI inference hardware",
			Currency = payment.Currency,
			UnitAmount = amountCents,
			Quantity = 1L
		});
		JackLLMPaymentCheckoutSessionResult result = paymentProcessor.CreateCheckoutSessionAsync(checkoutRequest, cancellationToken).GetAwaiter().GetResult();
		payment.StripeCheckoutSessionId = result.Id;
		payment.StripePaymentIntentId = result.PaymentIntentId;
		payment.StripeCustomerId = (string.IsNullOrWhiteSpace(result.CustomerId) ? payment.StripeCustomerId : result.CustomerId);
		payment.CheckoutUrl = result.Url;
		payment.Status = (string.Equals(result.Status, "complete", StringComparison.OrdinalIgnoreCase) ? "paid" : "pending");
		payment.AmountCents = ((result.AmountTotal.HasValue && result.AmountTotal.Value > 0) ? result.AmountTotal.Value : payment.AmountCents);
		UpsertFinancePayment(payment);
		lease.PaymentId = payment.Id;
		lease.CheckoutSessionId = result.Id;
		lease.PaymentStatus = ((payment.Status == "paid") ? "paid" : "pending");
		lease.Status = ((payment.Status == "paid") ? "active" : "pending_payment");
		UpsertMarketplaceLease(lease);
		return JsonSerializer.Serialize(new
		{
			ok = true,
			checkout = result,
			payment = FinancePaymentToPayload(payment),
			lease = BuildMarketplaceLeasePayload(lease)
		});
	}

	private string HandleFinanceStripeWebhookRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		string json = request?.Body ?? "";
		try
		{
			string signature = "";
			if (request?.Headers != null)
			{
				request.Headers.TryGetValue("Stripe-Signature", out signature);
				if (string.IsNullOrWhiteSpace(signature))
				{
					request.Headers.TryGetValue("stripe-signature", out signature);
				}
			}
			JackLLMVerifiedPaymentWebhookEvent paymentEvent = RequirePaymentProcessor("payment webhook verification").VerifyWebhookEvent(json, signature);
			FinancePaymentRecord payment = ApplyVerifiedStripeWebhookPayload(json, paymentEvent?.Type ?? "");
			return JsonSerializer.Serialize(new
			{
				ok = true,
				received = true,
				eventId = (paymentEvent?.Id ?? ""),
				eventType = (paymentEvent?.Type ?? ""),
				payment = ((payment == null) ? null : FinancePaymentToPayload(payment))
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Stripe webhook rejected: " + ex.Message);
			return BuildJsonError(request, 400, "Bad Request", "Stripe webhook signature or payload was invalid.");
		}
	}

