	private string HandleTokenRateRequestConfigSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthorizeDatabaseAdministrator(connection, request, out var _, out var authError))
			{
				return BuildDatabaseAdminOnlyJsonError(request, authError);
			}
			ChatCostSettings settings = GetChatCostSettings();
			string body = request?.Body ?? "{}";
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				if (root.TryGetProperty("enabled", out var enabled))
				{
					settings.tokenRateRequestsEnabled = ReadJsonBool(enabled, settings.tokenRateRequestsEnabled);
				}
				if (root.TryGetProperty("tokenRateRequestsEnabled", out var tokenRateRequestsEnabled))
				{
					settings.tokenRateRequestsEnabled = ReadJsonBool(tokenRateRequestsEnabled, settings.tokenRateRequestsEnabled);
				}
				if (root.TryGetProperty("minTokenRate", out var minTokenRate))
				{
					settings.tokenRateRequestMin = Math.Max(0L, ReadJsonLong(minTokenRate, settings.tokenRateRequestMin));
				}
				if (root.TryGetProperty("tokenRateRequestMin", out var tokenRateRequestMin))
				{
					settings.tokenRateRequestMin = Math.Max(0L, ReadJsonLong(tokenRateRequestMin, settings.tokenRateRequestMin));
				}
				if (root.TryGetProperty("maxTokenRate", out var maxTokenRate))
				{
					settings.tokenRateRequestMax = Math.Max(0L, ReadJsonLong(maxTokenRate, settings.tokenRateRequestMax));
				}
				if (root.TryGetProperty("tokenRateRequestMax", out var tokenRateRequestMax))
				{
					settings.tokenRateRequestMax = Math.Max(0L, ReadJsonLong(tokenRateRequestMax, settings.tokenRateRequestMax));
				}
				if (root.TryGetProperty("advertisedTokenRate", out var advertisedTokenRate))
				{
					settings.advertisedTokenRate = Math.Max(0L, ReadJsonLong(advertisedTokenRate, settings.advertisedTokenRate));
				}
			}
			NormalizeTokenRateRequestSettings(settings);
			SaveChatCostSettings(settings);
			LogMessage("[Token Rate] Request policy saved. Enabled=" + settings.tokenRateRequestsEnabled + ", range=" + settings.tokenRateRequestMin + "-" + settings.tokenRateRequestMax + ".");
			return JsonSerializer.Serialize(BuildTokenRateRequestConfigPayload(connection, request));
		}
		catch (Exception ex)
		{
			LogMessage("[Token Rate] Policy save failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleTokenRateRequestSubmitRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			ChatCostSettings settings = GetChatCostSettings();
			NormalizeTokenRateRequestSettings(settings);
			if (!settings.tokenRateRequestsEnabled)
			{
				return BuildJsonError(request, 403, "Forbidden", "Token-rate requests are disabled by this server.");
			}
			if (!TryAuthenticateWebAuthRequest(request, out var principal, out var authError) || principal == null || string.IsNullOrWhiteSpace(principal.UserName))
			{
				return BuildJsonError(request, 401, "Unauthorized", authError);
			}
			WebAuthRecord user = (StoreLocalWebAuthAccounts ? GetWebAuthRecord(principal.UserName) : null);
			if (StoreLocalWebAuthAccounts && (user == null || !user.enabled))
			{
				return BuildJsonError(request, 401, "Unauthorized", "WebAuth user is not enabled.");
			}
			string body = request?.Body ?? "{}";
			long requestedRate = 0L;
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				JsonElement root = document.RootElement;
				JsonElement tokenRate;
				JsonElement tokensPerHour;
				if (root.TryGetProperty("requestedTokenRate", out var requestedTokenRate))
				{
					requestedRate = ReadJsonLong(requestedTokenRate, 0L);
				}
				else if (root.TryGetProperty("tokenRate", out tokenRate))
				{
					requestedRate = ReadJsonLong(tokenRate, 0L);
				}
				else if (root.TryGetProperty("tokensPerHour", out tokensPerHour))
				{
					requestedRate = ReadJsonLong(tokensPerHour, 0L);
				}
			}
			if (requestedRate < settings.tokenRateRequestMin || requestedRate > settings.tokenRateRequestMax)
			{
				return BuildJsonError(request, 400, "Bad Request", "Requested token rate must be between " + settings.tokenRateRequestMin.ToString("N0", CultureInfo.InvariantCulture) + " and " + settings.tokenRateRequestMax.ToString("N0", CultureInfo.InvariantCulture) + " tokens/hour.");
			}
			string requestUserName = (StoreLocalWebAuthAccounts ? user.userName : principal.UserName.Trim());
			string ownerKey = "webauth:" + requestUserName.ToLowerInvariant();
			TokenRateRequestRecord record = SaveTokenRateRequest(requestUserName, ownerKey, ExtractClientIp(connection, request) ?? ((user == null) ? "" : user.lastClientIp) ?? "", requestedRate, GetEffectiveAdvertisedTokenRate(), settings.tokenRateRequestMin, settings.tokenRateRequestMax);
			TokenRateRequestSnapshot snapshot = TokenRateRequestSnapshotFromRecord(record);
			LogMessage("[Token Rate] " + snapshot.UserName + " requested " + snapshot.RequestedTokenRate.ToString("N0", CultureInfo.InvariantCulture) + " tokens/hour.");
			this.TokenRateRequestRequested?.Invoke(this, new TokenRateRequestEventArgs(snapshot));
			return JsonSerializer.Serialize(new
			{
				ok = true,
				pending = true,
				request = snapshot,
				policy = TokenRateRequestPolicySnapshotFromSettings(settings, GetEffectiveAdvertisedTokenRate())
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Token Rate] Request submit failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

