	private string HandleTokenRateRequestsAdminDecisionRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthorizeDatabaseAdministrator(connection, request, out var principal, out var authError))
			{
				return BuildDatabaseAdminOnlyJsonError(request, authError);
			}
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string requestId = ExtractStringProperty(root, "requestId") ?? ExtractStringProperty(root, "id") ?? "";
			string action = (ExtractStringProperty(root, "action") ?? "").Trim().ToLowerInvariant();
			string note = ExtractStringProperty(root, "note") ?? "";
			if (string.IsNullOrWhiteSpace(requestId))
			{
				return BuildJsonError(request, 400, "Bad Request", "Token-rate request id is required.");
			}
			string decidedBy = principal?.UserName ?? "admin";
			TokenRateRequestSnapshot snapshot;
			if (action == "approve" || action == "allow")
			{
				snapshot = ApproveTokenRateRequest(requestId, decidedBy, note);
			}
			else
			{
				if (!(action == "deny") && !(action == "block"))
				{
					return BuildJsonError(request, 400, "Bad Request", "Unknown token-rate request action.");
				}
				snapshot = DenyTokenRateRequest(requestId, decidedBy, note);
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				request = snapshot,
				requests = GetPendingTokenRateRequests(),
				policy = GetTokenRateRequestPolicy()
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Token Rate] Admin decision failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

