	private object BuildTokenRateRequestConfigPayload(NetworkConnection connection, HttpRequest request)
	{
		ChatCostSettings settings = GetChatCostSettings();
		NormalizeTokenRateRequestSettings(settings);
		long advertisedRate = GetEffectiveAdvertisedTokenRate(settings);
		bool canEdit = IsDatabaseAdministrator(connection, request);
		bool authenticated = false;
		string username = "";
		string authType = "";
		TokenRateRequestSnapshot pending = null;
		if (TryAuthenticateWebAuthRequest(request, out var principal, out var _) && principal != null && !string.IsNullOrWhiteSpace(principal.UserName))
		{
			authenticated = true;
			username = principal.UserName;
			authType = principal.AuthType ?? "";
			string ownerKey = "webauth:" + principal.UserName.Trim().ToLowerInvariant();
			TokenRateRequestRecord pendingRecord = FindPendingTokenRateRequestForOwner(ownerKey);
			if (pendingRecord != null)
			{
				pending = TokenRateRequestSnapshotFromRecord(pendingRecord);
			}
		}
		else if (IsLocalAdmin(connection, request))
		{
			authenticated = true;
			username = "localhost";
			authType = "Localhost";
		}
		return new
		{
			ok = true,
			canEdit = canEdit,
			authenticated = authenticated,
			username = username,
			authType = authType,
			enabled = settings.tokenRateRequestsEnabled,
			minTokenRate = settings.tokenRateRequestMin,
			maxTokenRate = settings.tokenRateRequestMax,
			advertisedTokenRate = advertisedRate,
			pendingRequest = pending,
			policy = TokenRateRequestPolicySnapshotFromSettings(settings, advertisedRate)
		};
	}

	private bool TryAuthorizeLlmClientRequest(NetworkConnection connection, HttpRequest request, out WebAuthPrincipal principal, out string error)
	{
		return TryAuthenticateWebAuthRequest(request, out principal, out error);
	}

	private string GetLlmClientOwnerKey(NetworkConnection connection, HttpRequest request, WebAuthPrincipal principal)
	{
		if (principal != null && !string.Equals(principal.AuthType, "Localhost", StringComparison.OrdinalIgnoreCase) && !string.IsNullOrWhiteSpace(principal.UserName))
		{
			return "webauth:" + principal.UserName.ToLowerInvariant();
		}
		return GetChatSessionOwnerKey(connection, request);
	}

	private string HandleLlmClientStatusRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthorizeDatabaseAdministrator(connection, request, out var principal, out var error))
			{
				return BuildJsonError(request, 403, "Forbidden", error);
			}
			string ownerKey = GetLlmClientOwnerKey(connection, request, principal);
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				authenticated = true,
				username = principal.UserName,
				authType = principal.AuthType,
				isAdministrator = principal.IsAdministrator,
				chatModel = ChatModel,
				proxyPort = _proxyPort,
				chatServerPort = _chatServerPort,
				lmStudioEndpoint = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/v1/chat/completions",
				modelRuntimeEndpoint = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/v1/chat/completions",
				modelRuntimeProvider = GetLocalModelRuntimeDisplayName(),
				database = new
				{
					defaultDatabase = _chatSessionData.DefaultDatabase,
					authTable = "WebAuth",
					dataPath = _chatSessionData.DataPath
				},
				remoteControl = new
				{
					provider = LmVsProxyRemoteControl.ProviderName,
					screenCapture = LmVsProxyRemoteControl.HasScreenCaptureProvider,
					input = LmVsProxyRemoteControl.HasInputProvider
				},
				permissions = permissions
			});
		}
		catch (Exception ex)
		{
			LogMessage("[LLM Client API] Status failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleLlmClientRemoteChatRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthenticateWebAuthRequest(request, out var principal, out var error))
			{
				return BuildJsonError(request, 401, "Unauthorized", error);
			}
			if (!TryRequireChatUiRequestBody(request, out var bodyError))
			{
				return BuildChatUiBadRequestJson(request, bodyError);
			}
			string ownerKey = "webauth:" + principal.UserName.ToLowerInvariant();
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			string restriction = BuildChatRestrictionMessage(permissions);
			if (!string.IsNullOrWhiteSpace(restriction))
			{
				return BuildJsonError(request, 403, "Forbidden", restriction);
			}
			bool agentMode = IsChatAgentServiceSelected(request?.Body);
			bool browserMode = IsChatBrowserSkillServiceSelected(request?.Body);
			bool terminalMode = IsChatTerminalServiceSelected(request?.Body);
			bool imageRequest = ChatUiRequestContainsImageContent(request?.Body);
			string sessionId = EnsureChatUiSessionId(ExtractChatUiSessionId(request?.Body));
			ProcessExplicitChatMemoryCommands(ownerKey, sessionId, request.Body);
			if (agentMode && !permissions.agentAccess)
			{
				return BuildJsonError(request, 403, "Forbidden", "Agent access is disabled for this session.");
			}
			if (browserMode && !permissions.agentAccess)
			{
				return BuildJsonError(request, 403, "Forbidden", "Agent access is required for Browser Skill mode.");
			}
			if (terminalMode && !permissions.terminalCommands)
			{
				return BuildJsonError(request, 403, "Forbidden", "Terminal Commands permission is disabled for this session.");
			}
			if (!EnsureChatUsageCanStart(request, ownerKey, request?.Body, out var usageSnapshot, out var usageError))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = usageError,
					usage = usageSnapshot
				});
			}
			string lmRequestJson = BuildChatUiCompletionRequestJson(request?.Body, streamResponses: false, permissions, principal.UserName, ownerKey);
			if (agentMode || browserMode || terminalMode)
			{
				lmRequestJson = AddProxyResearchTools(lmRequestJson, permissions, agentMode, agentMode || terminalMode, agentMode || browserMode, ownerKey);
			}
			ChatUsageMeter usageMeter = CreateChatUsageMeter();
			DateTimeOffset startedUtc = DateTimeOffset.UtcNow;
			ChatUiCompletion completion = ExecuteChatUiCompletionWithProxyToolsAsync(lmRequestJson, ownerKey, sessionId, cancellationToken).GetAwaiter().GetResult();
			completion = NormalizeChatUiCompletionForDisplay(completion, lmRequestJson);
			if (HasChatUiCompletionOutput(completion))
			{
				AppendChatUiFinishReasonNoticeIfNeeded(completion);
			}
			TimeSpan elapsed = DateTimeOffset.UtcNow - startedUtc;
			double gpuSeconds = Math.Max(0.0, elapsed.TotalSeconds);
			ChatResourceUsageDelta resourceDelta = ((gpuSeconds > 0.0) ? BuildChatResourceUsageDelta(gpuSeconds, usageMeter, elapsed) : new ChatResourceUsageDelta());
			int completionTokens = EstimateTokenCount(completion?.Content) + EstimateTokenCount(completion?.Reasoning);
			if (completionTokens > 0)
			{
				TryChargeChatUsageTokens(ownerKey, completionTokens, out var _, out usageSnapshot, resourceDelta, gpuSeconds);
			}
			else
			{
				if (gpuSeconds > 0.0)
				{
					ApplyChatUsageCosts(ownerKey, 0, gpuSeconds, resourceDelta);
				}
				usageSnapshot = GetChatUsageSnapshot(ownerKey);
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				username = principal.UserName,
				content = completion.Content,
				reasoning = completion.Reasoning,
				raw = completion.Raw,
				finishReason = completion.FinishReason,
				usage = usageSnapshot
			});
		}
		catch (OperationCanceledException)
		{
			return BuildJsonError(request, 408, "Request Timeout", "The " + GetLocalModelRuntimeDisplayName() + " request timed out or was cancelled.");
		}
		catch (Exception ex2)
		{
			if (IsChatUiRequestValidationException(ex2))
			{
				return BuildChatUiBadRequestJson(request, BuildChatUiRequestValidationError(ex2));
			}
			LogMessage("[LLM Client API] Chat failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

