	private string HandleLlmClientScreenCaptureRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthorizeDatabaseAdministrator(connection, request, out var principal, out var error))
			{
				return BuildJsonError(request, 403, "Forbidden", error);
			}
			LmVsProxyScreenCaptureOptions options = ReadScreenCaptureOptions(request);
			LmVsProxyScreenCaptureResult capture = CaptureScreenForRemoteControl(options);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				username = principal.UserName,
				mimeType = capture.MimeType,
				width = capture.Width,
				height = capture.Height,
				left = capture.Left,
				top = capture.Top,
				backend = capture.Backend,
				transport = "SocketJack HTTP JSON",
				imageBase64 = Convert.ToBase64String(capture.Bytes),
				dataUrl = "data:" + capture.MimeType + ";base64," + Convert.ToBase64String(capture.Bytes)
			});
		}
		catch (NotSupportedException ex)
		{
			LogMessage("[LLM Client API] Screen capture unavailable: " + ex.Message);
			return BuildJsonError(request, 501, "Not Implemented", ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[LLM Client API] Screen capture failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private object HandleLlmClientScreenCaptureFileRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
