			return BuildJsonError(request, 501, "Not Implemented", ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[LLM Client API] Screen capture file failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private string HandleLlmClientInputRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!TryAuthorizeDatabaseAdministrator(connection, request, out var principal, out var error))
			{
				return BuildJsonError(request, 403, "Forbidden", error);
			}
			string body = request?.Body ?? "{}";
			LmVsProxyRemoteInputResult result;
			using (JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body))
			{
				result = ExecuteRemoteInput(document.RootElement);
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				username = principal.UserName,
				action = result.Action,
				x = result.X,
				y = result.Y,
				message = result.Message
			});
		}
		catch (NotSupportedException ex)
		{
			LogMessage("[LLM Client API] Input unavailable: " + ex.Message);
			return BuildJsonError(request, 501, "Not Implemented", ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[LLM Client API] Input failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private LmVsProxyScreenCaptureOptions ReadScreenCaptureOptions(HttpRequest request)
	{
		LmVsProxyScreenCaptureOptions options = new LmVsProxyScreenCaptureOptions();
		if (request?.QueryParameters != null)
		{
			if (request.QueryParameters.TryGetValue("target", out var target))
			{
				options.Target = target;
			}
			if (request.QueryParameters.TryGetValue("quality", out var quality))
			{
				options.Quality = ParseStoredInt(quality, options.Quality);
			}
			if (request.QueryParameters.TryGetValue("maxWidth", out var maxWidth))
			{
				options.MaxWidth = ParseStoredInt(maxWidth, options.MaxWidth);
			}
			if (request.QueryParameters.TryGetValue("maxHeight", out var maxHeight))
			{
				options.MaxHeight = ParseStoredInt(maxHeight, options.MaxHeight);
			}
		}
		string body = request?.Body ?? "";
		if (!string.IsNullOrWhiteSpace(body))
		{
			using JsonDocument document = JsonDocument.Parse(body);
			JsonElement root = document.RootElement;
			if (root.ValueKind == JsonValueKind.Object)
			{
				if (root.TryGetProperty("target", out var target2))
				{
					options.Target = ExtractJsonString(target2) ?? options.Target;
				}
				if (root.TryGetProperty("quality", out var quality2))
				{
					options.Quality = ReadJsonInt(quality2, options.Quality);
				}
				if (root.TryGetProperty("maxWidth", out var maxWidth2))
				{
					options.MaxWidth = ReadJsonInt(maxWidth2, options.MaxWidth);
				}
				if (root.TryGetProperty("maxHeight", out var maxHeight2))
				{
					options.MaxHeight = ReadJsonInt(maxHeight2, options.MaxHeight);
				}
			}
		}
		options.Quality = Math.Max(1, Math.Min(100, options.Quality));
		options.MaxWidth = Math.Max(0, options.MaxWidth);
		options.MaxHeight = Math.Max(0, options.MaxHeight);
		if (string.IsNullOrWhiteSpace(options.Target))
		{
			options.Target = "admin";
		}
		return options;
	}

	private LmVsProxyScreenCaptureResult CaptureScreenForRemoteControl(LmVsProxyScreenCaptureOptions options)
	{
		Func<LmVsProxyScreenCaptureOptions, LmVsProxyScreenCaptureResult> captureProvider = LmVsProxyRemoteControl.CaptureScreen;
		if (captureProvider == null)
		{
			throw new NotSupportedException("No SocketJack remote screen capture provider is registered. Use SocketJack.WPF on Windows or the JackLLM Workstation Linux desktop provider.");
		}
		LmVsProxyScreenCaptureResult capture = captureProvider(options ?? new LmVsProxyScreenCaptureOptions());
		if (capture == null || capture.Bytes == null || capture.Bytes.Length == 0)
		{
			throw new InvalidOperationException("The SocketJack remote screen capture provider did not return a screen capture.");
		}
		if (string.IsNullOrWhiteSpace(capture.MimeType))
		{
			capture.MimeType = "image/jpeg";
		}
		return capture;
	}

	private LmVsProxyRemoteInputResult ExecuteRemoteInput(JsonElement root)
	{
		Func<LmVsProxyRemoteInputRequest, LmVsProxyRemoteInputResult> inputProvider = LmVsProxyRemoteControl.ExecuteInput;
		if (inputProvider == null)
		{
			throw new NotSupportedException("No SocketJack remote input provider is registered. Use SocketJack.WPF on Windows or the JackLLM Workstation Linux desktop provider.");
		}
		LmVsProxyRemoteInputRequest input = ReadRemoteInputRequest(root);
		return inputProvider(input);
	}

	private LmVsProxyRemoteInputRequest ReadRemoteInputRequest(JsonElement root)
	{
		LmVsProxyRemoteInputRequest request = new LmVsProxyRemoteInputRequest();
		if (root.ValueKind != JsonValueKind.Object)
		{
			return request;
		}
		if (root.TryGetProperty("action", out var action))
		{
			request.Action = ExtractJsonString(action) ?? request.Action;
		}
		if (root.TryGetProperty("button", out var button))
		{
			request.Button = ExtractJsonString(button) ?? request.Button;
		}
		if (root.TryGetProperty("text", out var text))
		{
			request.Text = ExtractJsonString(text) ?? request.Text;
		}
		if (root.TryGetProperty("key", out var key))
		{
			request.Key = ExtractJsonString(key) ?? request.Key;
		}
		if (root.TryGetProperty("normalized", out var normalized))
		{
			request.Normalized = ReadJsonBool(normalized, request.Normalized);
		}
		if (root.TryGetProperty("x", out var x))
		{
			request.X = ReadJsonDouble(x, request.X);
			request.HasPoint = true;
		}
		if (root.TryGetProperty("y", out var y))
		{
			request.Y = ReadJsonDouble(y, request.Y);
			request.HasPoint = true;
		}
		if (root.TryGetProperty("toX", out var toX) || root.TryGetProperty("endX", out toX))
		{
			request.ToX = ReadJsonDouble(toX, request.ToX);
			request.HasTargetPoint = true;
		}
		if (root.TryGetProperty("toY", out var toY) || root.TryGetProperty("endY", out toY))
		{
			request.ToY = ReadJsonDouble(toY, request.ToY);
			request.HasTargetPoint = true;
		}
		if (root.TryGetProperty("durationMs", out var durationMs))
		{
			request.DurationMs = ReadJsonInt(durationMs, request.DurationMs);
		}
		if (root.TryGetProperty("steps", out var steps))
		{
			request.Steps = ReadJsonInt(steps, request.Steps);
		}
		if (root.TryGetProperty("delta", out var delta))
		{
			request.Delta = ReadJsonInt(delta, request.Delta);
		}
		request.DurationMs = Math.Max(0, Math.Min(30000, request.DurationMs));
		request.Steps = Math.Max(1, Math.Min(240, request.Steps));
		if (string.IsNullOrWhiteSpace(request.Action))
		{
			request.Action = "move";
		}
		if (string.IsNullOrWhiteSpace(request.Button))
		{
			request.Button = "left";
		}
		return request;
	}

	private List<ChatUiModelInfo> BuildChatModelInfos(List<string> modelIds)
	{
		List<ChatUiModelInfo> result = new List<ChatUiModelInfo>();
		foreach (string id in modelIds ?? new List<string>())
		{
			if (!string.IsNullOrWhiteSpace(id) && !IsLikelyModelArtifactId(id) && !IsLikelyNonChatModelId(id))
			{
				result.Add(new ChatUiModelInfo
				{
					id = id,
					supportsImages = ModelLikelySupportsImages(id),
					supportsTools = ModelLikelySupportsTools(id),
					supportsImageGeneration = ModelLikelySupportsImageGeneration(id),
					supportsAudioGeneration = ModelLikelySupportsAudioGeneration(id),
					supportsVideoGeneration = ModelLikelySupportsVideoGeneration(id)
				});
			}
		}
		return result;
	}

	private ChatUiModelInfo BuildChatModelInfo(string modelId)
	{
		return new ChatUiModelInfo
		{
			id = modelId,
			supportsImages = ModelLikelySupportsImages(modelId),
			supportsTools = ModelLikelySupportsTools(modelId),
			supportsImageGeneration = ModelLikelySupportsImageGeneration(modelId),
			supportsAudioGeneration = ModelLikelySupportsAudioGeneration(modelId),
			supportsVideoGeneration = ModelLikelySupportsVideoGeneration(modelId)
		};
	}

