	private bool TryGetChatMediaGenerationService(string requestBody, out string serviceId, out string mediaKind)
	{
		serviceId = "";
		mediaKind = "";
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return false;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			serviceId = FirstNonEmpty(ExtractStringProperty(document.RootElement, "service"), ExtractStringProperty(document.RootElement, "serviceId"), ExtractStringProperty(document.RootElement, "chat_service"), ExtractStringProperty(document.RootElement, "chatService"), ExtractStringProperty(document.RootElement, "mode"));
			if (!IsWebChatMediaGenerationService(serviceId))
			{
				string modelId = FirstNonEmpty(ExtractStringProperty(document.RootElement, "model"), ExtractStringProperty(document.RootElement, "modelId"), ExtractStringProperty(document.RootElement, "selectedModel"));
				string inferredService = GuessWebChatMediaService(modelId, "");
				if (string.IsNullOrWhiteSpace(serviceId) || string.Equals(serviceId, "chat", StringComparison.OrdinalIgnoreCase))
				{
					serviceId = inferredService;
				}
			}
		}
		catch
		{
			return false;
		}
		if (string.Equals(serviceId, "image_generation", StringComparison.OrdinalIgnoreCase))
		{
			mediaKind = "image";
			return true;
		}
		if (string.Equals(serviceId, "audio_generation", StringComparison.OrdinalIgnoreCase))
		{
			mediaKind = "audio";
			return true;
		}
		if (string.Equals(serviceId, "video_generation", StringComparison.OrdinalIgnoreCase))
		{
			mediaKind = "video";
			return true;
		}
		return false;
	}

