	private ActiveChatStreamCancellation RegisterActiveChatStreamCancellation(string ownerKey, string streamId, string sessionId)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		streamId = NormalizeChatUiStreamId(streamId);
		sessionId = EnsureChatUiSessionId(sessionId);
		ActiveChatStreamCancellation active = new ActiveChatStreamCancellation
		{
			OwnerKey = ownerKey,
			StreamId = streamId,
			SessionId = sessionId,
			Cancellation = new CancellationTokenSource(),
			StartedUtc = DateTimeOffset.UtcNow
		};
		lock (_activeChatStreamCancellationLock)
		{
			PruneActiveChatStreamCancellationsLocked();
			string key = BuildActiveChatStreamCancellationKey(ownerKey, streamId);
			if (_activeChatStreamCancellations.TryGetValue(key, out var existing))
			{
				existing.Cancellation.Cancel();
			}
			_activeChatStreamCancellations[key] = active;
			if (_pendingChatStreamStops.Remove(key))
			{
				active.Cancellation.Cancel();
			}
			if (_pendingChatStreamSteering.TryGetValue(key, out var pendingSteering) &&
				(string.IsNullOrWhiteSpace(pendingSteering.SessionId) || string.Equals(pendingSteering.SessionId, sessionId, StringComparison.Ordinal)))
			{
				lock (active.SteeringMessages)
				{
					active.SteeringMessages.AddRange(pendingSteering.Messages);
				}
				_pendingChatStreamSteering.Remove(key);
			}
		}
		return active;
	}

	private bool TryFindActiveChatStreamCancellationLocked(string ownerKey, string streamId, string sessionId, out ActiveChatStreamCancellation active)
	{
		active = null;
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		streamId = NormalizeChatUiStreamId(streamId);
		sessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : EnsureChatUiSessionId(sessionId));
		string key = BuildActiveChatStreamCancellationKey(ownerKey, streamId);
		if (_activeChatStreamCancellations.TryGetValue(key, out active) && active != null)
		{
			return string.IsNullOrWhiteSpace(sessionId) || string.Equals(active.SessionId ?? "", sessionId, StringComparison.Ordinal);
		}
		ActiveChatStreamCancellation matched = null;
		foreach (ActiveChatStreamCancellation candidate in _activeChatStreamCancellations.Values)
		{
			if (candidate != null && string.Equals(candidate.StreamId ?? "", streamId, StringComparison.Ordinal) && (string.IsNullOrWhiteSpace(sessionId) || string.Equals(candidate.SessionId ?? "", sessionId, StringComparison.Ordinal)))
			{
				if (matched != null)
				{
					return false;
				}
				matched = candidate;
			}
		}
		active = matched;
		return active != null;
	}

	private bool CancelActiveChatStream(string ownerKey, string streamId, string sessionId)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		streamId = NormalizeChatUiStreamId(streamId);
		sessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : EnsureChatUiSessionId(sessionId));
		ActiveChatStreamCancellation activeToForceStop = null;
		lock (_activeChatStreamCancellationLock)
		{
			string key = BuildActiveChatStreamCancellationKey(ownerKey, streamId);
			if (!TryFindActiveChatStreamCancellationLocked(ownerKey, streamId, sessionId, out var active))
			{
				_pendingChatStreamStops[key] = DateTimeOffset.UtcNow;
				return true;
			}
			active.Cancellation.Cancel();
			activeToForceStop = active;
		}
		if (activeToForceStop != null)
		{
			_ = Task.Run(() => ForceCancelActiveChatGenerationAsync(activeToForceStop));
		}
		return true;
	}

	private async Task ForceCancelActiveChatGenerationAsync(ActiveChatStreamCancellation active)
	{
		if (active == null)
		{
			return;
		}
		try
		{
			string jobId = (active.MediaJobId ?? "").Trim();
			string toolCallId = (active.MediaToolCallId ?? "").Trim();
			if (string.IsNullOrWhiteSpace(jobId) && !string.IsNullOrWhiteSpace(toolCallId))
			{
				DateTimeOffset deadline = DateTimeOffset.UtcNow + TimeSpan.FromSeconds(5.0);
				while (string.IsNullOrWhiteSpace(jobId) && DateTimeOffset.UtcNow < deadline)
				{
					try
					{
						using CancellationTokenSource timeout = new CancellationTokenSource(TimeSpan.FromSeconds(2.0));
						ChatUiMediaGenerationProgressSnapshot snapshot = await FetchChatUiMediaGenerationProgressAsync(toolCallId, timeout.Token).ConfigureAwait(continueOnCapturedContext: false);
						jobId = (snapshot?.JobId ?? "").Trim();
					}
					catch (OperationCanceledException)
					{
					}
					if (string.IsNullOrWhiteSpace(jobId))
					{
						await Task.Delay(TimeSpan.FromMilliseconds(300.0)).ConfigureAwait(continueOnCapturedContext: false);
					}
				}
			}
			if (string.IsNullOrWhiteSpace(jobId))
			{
				return;
			}
			using CancellationTokenSource cancelTimeout = new CancellationTokenSource(TimeSpan.FromSeconds(6.0));
			await CancelChatUiMediaGenerationJobAsync(jobId, cancelTimeout.Token).ConfigureAwait(continueOnCapturedContext: false);
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Media generation force-stop failed: " + ex.Message);
		}
	}

	private async Task CancelChatUiMediaGenerationJobAsync(string jobId, CancellationToken cancellationToken)
	{
		jobId = (jobId ?? "").Trim();
		if (string.IsNullOrWhiteSpace(jobId))
		{
			return;
		}
		string url = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/tools/calls";
		string payload = JsonSerializer.Serialize(new
		{
			approved = true,
			tool_calls = new[]
			{
				new
				{
					id = "call_media_cancel_" + Guid.NewGuid().ToString("N").Substring(0, 12),
					name = "jackonnx_jobs_cancel",
					arguments = new { jobId }
				}
			}
		});
		using StringContent content = new StringContent(payload, Encoding.UTF8, "application/json");
		using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Post, url);
		request.Content = content;
		using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseContentRead, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		string body = response.Content == null ? "" : await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false);
		if (response.IsSuccessStatusCode)
		{
			LogMessage("[Chat UI] Requested JackONNX media job cancellation for " + jobId + ".");
			return;
		}
		LogMessage("[Chat UI] JackONNX media job cancellation returned " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + response.ReasonPhrase + ": " + TruncateForLog(body, 800));
	}

	private bool AddActiveChatStreamSteering(string ownerKey, string streamId, string sessionId, string steering)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		streamId = NormalizeChatUiStreamId(streamId);
		sessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : EnsureChatUiSessionId(sessionId));
		steering = NormalizeChatStreamSteeringText(steering);
		if (string.IsNullOrWhiteSpace(steering))
		{
			return false;
		}
		lock (_activeChatStreamCancellationLock)
		{
			if (!TryFindActiveChatStreamCancellationLocked(ownerKey, streamId, sessionId, out var active))
			{
				AddPendingChatStreamSteeringLocked(ownerKey, streamId, sessionId, steering);
				return true;
			}
			lock (active.SteeringMessages)
			{
				active.SteeringMessages.Add(steering);
			}
			return true;
		}
	}

	private void AddPendingChatStreamSteeringLocked(string ownerKey, string streamId, string sessionId, string steering)
	{
		string key = BuildActiveChatStreamCancellationKey(ownerKey, streamId);
		if (!_pendingChatStreamSteering.TryGetValue(key, out var pending) || pending == null)
		{
			pending = new PendingChatStreamSteering
			{
				OwnerKey = ownerKey,
				StreamId = streamId,
				SessionId = sessionId
			};
			_pendingChatStreamSteering[key] = pending;
		}
		if (string.IsNullOrWhiteSpace(pending.SessionId) && !string.IsNullOrWhiteSpace(sessionId))
		{
			pending.SessionId = sessionId;
		}
		pending.UpdatedUtc = DateTimeOffset.UtcNow;
		pending.Messages.Add(steering);
	}

	private string ConsumeActiveChatStreamSteering(ActiveChatStreamCancellation active)
	{
		if (active == null)
		{
			return "";
		}
		lock (active.SteeringMessages)
		{
			if (active.SteeringMessages.Count == 0)
			{
				return "";
			}
			string steering = active.SteeringMessages.Count == 1
				? active.SteeringMessages[0]
				: string.Join(Environment.NewLine + Environment.NewLine, active.SteeringMessages.Select((message, index) => "[Steering update " + (index + 1).ToString(CultureInfo.InvariantCulture) + "]" + Environment.NewLine + message));
			active.SteeringMessages.Clear();
			return steering;
		}
	}

	private string NormalizeChatStreamSteeringText(string steering)
	{
		steering = (steering ?? "").Trim();
		if (steering.Length <= 4000)
		{
			return steering;
		}
		return steering.Substring(0, 4000);
	}

	private void UnregisterActiveChatStreamCancellation(ActiveChatStreamCancellation active)
	{
		if (active == null)
		{
			return;
		}
		lock (_activeChatStreamCancellationLock)
		{
			string key = BuildActiveChatStreamCancellationKey(active.OwnerKey, active.StreamId);
			if (_activeChatStreamCancellations.TryGetValue(key, out var current) && current == active)
			{
				_activeChatStreamCancellations.Remove(key);
			}
		}
		active.Cancellation.Dispose();
	}

	private string BuildActiveChatStreamCancellationKey(string ownerKey, string streamId)
	{
		return NormalizeChatFilesystemOwnerKey(ownerKey) + "\u001f" + NormalizeChatUiStreamId(streamId);
	}

	private void PruneActiveChatStreamCancellationsLocked()
	{
		DateTimeOffset cutoff = DateTimeOffset.UtcNow - TimeSpan.FromHours(1.0);
		List<string> remove = new List<string>();
		foreach (KeyValuePair<string, ActiveChatStreamCancellation> pair in _activeChatStreamCancellations)
		{
			if (pair.Value == null || pair.Value.StartedUtc < cutoff)
			{
				remove.Add(pair.Key);
			}
		}
		foreach (string key in remove)
		{
			if (_activeChatStreamCancellations.TryGetValue(key, out var active))
			{
				active.Cancellation.Cancel();
			}
			_activeChatStreamCancellations.Remove(key);
		}
		DateTimeOffset pendingCutoff = DateTimeOffset.UtcNow - TimeSpan.FromSeconds(10.0);
		remove.Clear();
		foreach (KeyValuePair<string, DateTimeOffset> pair2 in _pendingChatStreamStops)
		{
			if (pair2.Value < pendingCutoff)
			{
				remove.Add(pair2.Key);
			}
		}
		foreach (string key2 in remove)
		{
			_pendingChatStreamStops.Remove(key2);
		}
		remove.Clear();
		foreach (KeyValuePair<string, PendingChatStreamSteering> pair3 in _pendingChatStreamSteering)
		{
			if (pair3.Value == null || pair3.Value.UpdatedUtc < pendingCutoff)
			{
				remove.Add(pair3.Key);
			}
		}
		foreach (string key3 in remove)
		{
			_pendingChatStreamSteering.Remove(key3);
		}
	}

	private string HandleChatUiStreamStopRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string sharedOwnerKey;
			string sessionId;
			string sharedError;
			bool sharedChat = TryResolveSharedChatRequest(request?.Body, out sharedOwnerKey, out sessionId, out sharedError);
			if (!string.IsNullOrWhiteSpace(ExtractChatUiShareKey(request?.Body)) && !sharedChat)
			{
				return BuildJsonError(request, 403, "Forbidden", sharedError);
			}
			if (sharedChat)
			{
				ownerKey = sharedOwnerKey;
			}
			string streamId = ExtractChatUiStreamId(request?.Body);
			if (string.IsNullOrWhiteSpace(streamId))
			{
				return BuildJsonError(request, 400, "Bad Request", "streamId is required.");
			}
			string sessionId2 = ExtractChatUiSessionId(request?.Body);
			bool cancelled = CancelActiveChatStream(ownerKey, streamId, sessionId2);
			if (cancelled)
			{
				LogMessage("[Chat UI] Stop requested for stream " + NormalizeChatUiStreamId(streamId) + " by " + ownerKey + ".");
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				cancelled = cancelled
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Stop request failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleChatUiStreamSteerRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string sharedOwnerKey;
			string sessionId;
			string sharedError;
			bool sharedChat = TryResolveSharedChatRequest(request?.Body, out sharedOwnerKey, out sessionId, out sharedError);
			if (!string.IsNullOrWhiteSpace(ExtractChatUiShareKey(request?.Body)) && !sharedChat)
			{
				return BuildJsonError(request, 403, "Forbidden", sharedError);
			}
			if (sharedChat)
			{
				ownerKey = sharedOwnerKey;
			}
			string streamId = ExtractChatUiStreamId(request?.Body);
			if (string.IsNullOrWhiteSpace(streamId))
			{
				return BuildJsonError(request, 400, "Bad Request", "streamId is required.");
			}
			string steering = ExtractChatUiSteeringText(request?.Body);
			if (string.IsNullOrWhiteSpace(steering))
			{
				return BuildJsonError(request, 400, "Bad Request", "steering text is required.");
			}
			string sessionId2 = ExtractChatUiSessionId(request?.Body);
			if (!AddActiveChatStreamSteering(ownerKey, streamId, sessionId2, steering))
			{
				return BuildJsonError(request, 404, "Not Found", "No active stream was found to steer.");
			}
			LogMessage("[Chat UI] Steering added for stream " + NormalizeChatUiStreamId(streamId) + " by " + ownerKey + ".");
			return JsonSerializer.Serialize(new
			{
				ok = true,
				accepted = true
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Steering request failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandlePromptIntellisenseRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string text = ExtractStringProperty(root, "text") ?? "";
			int caretIndex = (root.TryGetProperty("caretIndex", out var caretElement) ? ReadJsonInt(caretElement, text.Length) : text.Length);
			int take = (root.TryGetProperty("take", out var takeElement) ? ReadJsonInt(takeElement, 24) : 24);
			caretIndex = Math.Max(0, Math.Min(text.Length, caretIndex));
			take = Math.Max(1, Math.Min(80, take));
			List<object> completions = new List<object>();
			foreach (PromptIntellisense.CompletionItem item in _promptIntellisense.GetCompletions(text, caretIndex))
			{
				if (IsPromptIntellisenseCompletionAllowed(item, ownerKey))
				{
					(string, int) applied = _promptIntellisense.ApplyCompletion(text, caretIndex, item);
					completions.Add(new
					{
						displayText = (item.DisplayText ?? ""),
						insertText = (item.InsertText ?? ""),
						description = (item.Description ?? ""),
						category = (item.Category ?? ""),
						writeup = (item.Writeup ?? ""),
						isDirectory = item.IsDirectory,
						isExecutable = item.IsExecutable,
						hasBrowseButton = item.HasBrowseButton,
						browseTarget = item.BrowseTarget.ToString(),
						browseTitle = (item.BrowseTitle ?? ""),
						browseFilter = (item.BrowseFilter ?? ""),
						browseInsertPrefix = (item.BrowseInsertPrefix ?? ""),
						browseInitialDirectory = (item.BrowseInitialDirectory ?? ""),
						newText = (applied.Item1 ?? text),
						caretIndex = applied.Item2
					});
					if (completions.Count >= take)
					{
						break;
					}
				}
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				service = "prompt_intellisense",
				mode = (IsChatAgentServiceSelected(body) ? "agent" : "assistant"),
				completions = completions
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Prompt Intellisense] Failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private bool IsPromptIntellisenseCompletionAllowed(PromptIntellisense.CompletionItem item, string ownerKey)
	{
		if (item == null)
		{
			return false;
		}
		string insertText = item.InsertText ?? "";
		if (item.Category != null && item.Category.Equals("File", StringComparison.OrdinalIgnoreCase) && Path.IsPathRooted(insertText))
		{
			try
			{
				string candidate = Path.GetFullPath(insertText.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar));
				return IsPathUnderAnyRoot(candidate, GetChatAgentAllowedRoots(ownerKey));
			}
			catch
			{
				return false;
			}
		}
		return true;
	}

