	private List<ChatUiModelInfo> ExtractModelInfos(string responseBody)
	{
		List<ChatUiModelInfo> models = new List<ChatUiModelInfo>();
		if (string.IsNullOrWhiteSpace(responseBody))
		{
			return models;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(responseBody);
			if (document.RootElement.ValueKind == JsonValueKind.Object)
			{
				bool addedKnownContainer = false;
				if (TryGetObjectPropertyIgnoreCase(document.RootElement, out JsonElement data, "data"))
				{
					AddModelInfosFromElement(data, models);
					addedKnownContainer = true;
				}
				if (TryGetObjectPropertyIgnoreCase(document.RootElement, out JsonElement modelList, "models", "modelCapabilities", "model_capabilities"))
				{
					AddModelInfosFromElement(modelList, models);
					addedKnownContainer = true;
				}
				if (addedKnownContainer)
				{
					return models;
				}
			}
			AddModelInfosFromElement(document.RootElement, models);
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Could not parse model capabilities response: " + ex.Message);
		}
		return models;
	}

	private void AddModelInfosFromElement(JsonElement element, List<ChatUiModelInfo> models)
	{
		if (models == null)
		{
			return;
		}
		if (element.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement child in element.EnumerateArray())
			{
				AddModelInfosFromElement(child, models);
			}
			return;
		}
		ChatUiModelInfo info = null;
		if (element.ValueKind == JsonValueKind.Object)
		{
			string id = ExtractStringProperty(element, "id") ?? ExtractStringProperty(element, "key") ?? ExtractStringProperty(element, "model") ?? ExtractStringProperty(element, "model_id") ?? ExtractStringProperty(element, "modelId") ?? ExtractStringProperty(element, "name");
			if (string.IsNullOrWhiteSpace(id))
			{
				{
					foreach (JsonProperty property in element.EnumerateObject())
					{
						if (IsModelContainerMetadataPropertyName(property.Name))
						{
							continue;
						}
						if (property.Value.ValueKind == JsonValueKind.Object && !IsModelCapabilityContainerName(property.Name) && !ModelElementHasId(property.Value))
						{
							bool imageGeneration = ModelLikelySupportsImageGeneration(property.Name) || ElementIndicatesMediaGeneration(property.Value, "image");
							bool audioGeneration = ModelLikelySupportsAudioGeneration(property.Name) || ElementIndicatesMediaGeneration(property.Value, "audio");
							bool videoGeneration = ModelLikelySupportsVideoGeneration(property.Name) || ElementIndicatesMediaGeneration(property.Value, "video");
							if ((!ElementExplicitlyDisablesChatCompletion(property.Value) && IsPlausibleLoadableModelIdentifier(property.Name) && !IsLikelyNonChatModelId(property.Name)) || imageGeneration || audioGeneration || videoGeneration)
							{
								ChatUiModelInfo mapped = BuildChatModelInfo(property.Name);
								mapped.isLoaded = RuntimeModelHasLoadedInstances(property.Value);
								mapped.supportsImages = mapped.supportsImages || ElementIndicatesCapability(property.Value, "vision", "image", "images", "multimodal", "vlm");
								mapped.supportsTools = mapped.supportsTools || ElementIndicatesCapability(property.Value, "tool", "tools", "tool_call", "tool_calls", "tool_choice", "function", "functions", "function_calling", "tool_use", "native_tool");
								mapped.supportsImageGeneration |= imageGeneration;
								mapped.supportsAudioGeneration |= audioGeneration;
								mapped.supportsVideoGeneration |= videoGeneration;
								ReadModelPaymentInfo(property.Value, out bool mappedRequiresPayment, out string mappedStripePriceId, out string mappedStripeAccount, out long mappedUnitAmountCents, out string mappedStripeCurrency, out string mappedPaymentStatus);
								ApplyChatUiModelPaymentInfo(mapped, mappedRequiresPayment, mappedStripePriceId, mappedStripeAccount, mappedUnitAmountCents, mappedStripeCurrency, mappedPaymentStatus);
								MergeChatModelInfo(models, mapped);
							}
						}
						else
						{
							AddModelInfosFromElement(property.Value, models);
						}
					}
					return;
				}
			}
			bool imageGeneration2 = ModelLikelySupportsImageGeneration(id) || ElementIndicatesMediaGeneration(element, "image");
			bool audioGeneration2 = ModelLikelySupportsAudioGeneration(id) || ElementIndicatesMediaGeneration(element, "audio");
			bool videoGeneration2 = ModelLikelySupportsVideoGeneration(id) || ElementIndicatesMediaGeneration(element, "video");
			if (IsLikelyModelArtifactId(id))
			{
				return;
			}
			if (!IsRuntimeModelApiLoadable(element))
			{
				return;
			}
			if ((ElementExplicitlyDisablesChatCompletion(element) || IsLikelyNonChatModelId(id)) && !imageGeneration2 && !audioGeneration2 && !videoGeneration2)
			{
				return;
			}
			info = BuildChatModelInfo(id);
			info.isLoaded = RuntimeModelHasLoadedInstances(element);
			info.supportsImages = info.supportsImages || ElementIndicatesCapability(element, "vision", "image", "images", "multimodal", "vlm");
			info.supportsTools = info.supportsTools || ElementIndicatesCapability(element, "tool", "tools", "tool_call", "tool_calls", "tool_choice", "function", "functions", "function_calling", "tool_use", "native_tool");
			info.supportsImageGeneration = info.supportsImageGeneration || imageGeneration2;
			info.supportsAudioGeneration = info.supportsAudioGeneration || audioGeneration2;
			info.supportsVideoGeneration = info.supportsVideoGeneration || videoGeneration2;
			ReadModelPaymentInfo(element, out bool requiresPayment, out string stripePriceId, out string stripeAccount, out long unitAmountCents, out string stripeCurrency, out string paymentStatus);
			ApplyChatUiModelPaymentInfo(info, requiresPayment, stripePriceId, stripeAccount, unitAmountCents, stripeCurrency, paymentStatus);
		}
		else if (element.ValueKind == JsonValueKind.String)
		{
			string id2 = element.GetString();
			if (!string.IsNullOrWhiteSpace(id2) && !IsLikelyModelArtifactId(id2) && IsPlausibleLoadableModelIdentifier(id2) && (!IsLikelyNonChatModelId(id2) || ModelLikelySupportsAnyMediaGeneration(id2)))
			{
				info = BuildChatModelInfo(id2);
			}
		}
		if (info != null && !string.IsNullOrWhiteSpace(info.id))
		{
			ChatUiModelInfo existing = models.Find((ChatUiModelInfo model) => string.Equals(model.id, info.id, StringComparison.OrdinalIgnoreCase));
			if (existing == null)
			{
				models.Add(info);
				return;
			}
			existing.supportsImages = existing.supportsImages || info.supportsImages;
			existing.supportsTools = existing.supportsTools || info.supportsTools;
			existing.isLoaded = existing.isLoaded || info.isLoaded;
			existing.supportsImageGeneration = existing.supportsImageGeneration || info.supportsImageGeneration;
			existing.supportsAudioGeneration = existing.supportsAudioGeneration || info.supportsAudioGeneration;
			existing.supportsVideoGeneration = existing.supportsVideoGeneration || info.supportsVideoGeneration;
			ApplyChatUiModelPaymentInfo(existing, info.requiresPayment, info.stripePriceId, info.stripeAccount, info.stripeUnitAmountCents, info.stripeCurrency, info.paymentStatus);
		}
	}

	private bool IsRuntimeModelApiLoadable(JsonElement element)
	{
		if (element.ValueKind != JsonValueKind.Object)
		{
			return true;
		}

		bool loaded = RuntimeModelHasLoadedInstances(element);
		string disabledReason = FirstNonEmpty(
			ReadJsonPropertyString(element, "load_disabled_reason", "loadDisabledReason"),
			ReadJsonPropertyString(element, "web_chat_load_disabled_reason", "webChatLoadDisabledReason"));
		if (!string.IsNullOrWhiteSpace(disabledReason) && !loaded)
		{
			return false;
		}

		if (TryReadRuntimeModelCapabilityBool(element, out bool runtimeLoad, "runtime_load", "runtimeLoad", "load"))
		{
			return runtimeLoad || loaded;
		}

		if (TryReadRuntimeModelCapabilityBool(element, out bool chatCompletion, "chat_completion", "chatCompletion"))
		{
			return chatCompletion || loaded || RuntimeModelHasGenerationService(element);
		}

		return true;
	}

	private bool RuntimeModelHasGenerationService(JsonElement element)
	{
		string service = FirstNonEmpty(
			ReadJsonPropertyString(element, "service", "chat_service", "chatService"),
			ReadJsonPropertyString(GetObjectPropertyOrDefault(element, "capabilities"), "service", "chat_service", "chatService"));
		return IsWebChatMediaGenerationService(service);
	}

	private bool TryReadRuntimeModelCapabilityBool(JsonElement element, out bool value, params string[] names)
	{
		if (TryReadJsonBoolProperty(element, out value, names))
		{
			return true;
		}
		if (TryGetObjectPropertyIgnoreCase(element, out JsonElement capabilities, "capabilities") &&
			capabilities.ValueKind == JsonValueKind.Object &&
			TryReadJsonBoolProperty(capabilities, out value, names))
		{
			return true;
		}
		value = false;
		return false;
	}

	private bool TryReadJsonBoolProperty(JsonElement element, out bool value, params string[] names)
	{
		if (TryGetObjectPropertyIgnoreCase(element, out JsonElement property, names))
		{
			value = ReadJsonBool(property, fallback: false);
			return true;
		}
		value = false;
		return false;
	}

	private string ReadJsonPropertyString(JsonElement element, params string[] names)
	{
		return TryGetObjectPropertyIgnoreCase(element, out JsonElement value, names) ? ReadJsonString(value) : "";
	}

	private static JsonElement GetObjectPropertyOrDefault(JsonElement element, string name)
	{
		return element.ValueKind == JsonValueKind.Object && element.TryGetProperty(name, out JsonElement value)
			? value
			: default;
	}

	private bool ModelElementHasId(JsonElement element)
	{
		return element.ValueKind == JsonValueKind.Object && (!string.IsNullOrWhiteSpace(ExtractStringProperty(element, "id")) || !string.IsNullOrWhiteSpace(ExtractStringProperty(element, "key")) || !string.IsNullOrWhiteSpace(ExtractStringProperty(element, "name")) || !string.IsNullOrWhiteSpace(ExtractStringProperty(element, "model")) || !string.IsNullOrWhiteSpace(ExtractStringProperty(element, "model_id")) || !string.IsNullOrWhiteSpace(ExtractStringProperty(element, "modelId")));
	}

	private bool ElementIndicatesMediaGeneration(JsonElement element, string mediaKind)
	{
		if (element.ValueKind != JsonValueKind.Object || string.IsNullOrWhiteSpace(mediaKind))
		{
			return false;
		}
		string normalizedKind = mediaKind.Trim().ToLowerInvariant();
		string serviceId = normalizedKind + "_generation";
		if (RuntimeModelMatchesMediaService(element, serviceId))
		{
			return true;
		}
		string pascalKind = char.ToUpperInvariant(normalizedKind[0]) + normalizedKind.Substring(1);
		return ElementIndicatesCapability(element, serviceId, serviceId.Replace("_", "-"), serviceId.Replace("_", ""), "generates" + pascalKind, "jackonnx_" + normalizedKind, normalizedKind + "_generate", normalizedKind + ".generate");
	}

	private bool IsModelCapabilityContainerName(string name)
	{
		if (string.IsNullOrWhiteSpace(name))
		{
			return true;
		}
		string lower = name.Trim().ToLowerInvariant();
		int result;
		switch (lower)
		{
		default:
			result = ((lower == "features") ? 1 : 0);
			break;
		case "data":
		case "models":
		case "modelcapabilities":
		case "model_capabilities":
		case "capabilities":
		case "metadata":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private bool IsModelContainerMetadataPropertyName(string name)
	{
		if (string.IsNullOrWhiteSpace(name))
		{
			return true;
		}
		string lower = name.Trim().ToLowerInvariant();
		int result;
		switch (lower)
		{
		default:
			result = ((lower == "created_at") ? 1 : 0);
			break;
		case "object":
		case "ok":
		case "selected":
		case "model":
		case "modellistavailable":
		case "model_list_available":
		case "warning":
		case "error":
		case "source":
		case "created":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private bool ElementExplicitlyDisablesChatCompletion(JsonElement element)
	{
		if (element.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		string type = ExtractStringProperty(element, "type") ?? "";
		if (IsNonChatModelType(type))
		{
			return true;
		}
		if (TryGetMasterJsonProperty(element, "chat_completion", out var chatCompletion) || TryGetMasterJsonProperty(element, "chatCompletion", out chatCompletion))
		{
			return JsonValueIsExplicitFalse(chatCompletion);
		}
		if (TryGetMasterJsonProperty(element, "capabilities", out var capabilities) && capabilities.ValueKind == JsonValueKind.Object && (TryGetMasterJsonProperty(capabilities, "chat_completion", out chatCompletion) || TryGetMasterJsonProperty(capabilities, "chatCompletion", out chatCompletion)))
		{
			return JsonValueIsExplicitFalse(chatCompletion);
		}
		return false;
	}

	private static bool IsNonChatModelType(string type)
	{
		if (string.IsNullOrWhiteSpace(type))
		{
			return false;
		}
		string lower = type.Trim().ToLowerInvariant();
		return lower == "embedding" || lower.StartsWith("image", StringComparison.Ordinal) || lower.StartsWith("audio", StringComparison.Ordinal) || lower.StartsWith("video", StringComparison.Ordinal);
	}

	private static bool JsonValueIsExplicitFalse(JsonElement value)
	{
		if (value.ValueKind == JsonValueKind.False)
		{
			return true;
		}
		if (value.ValueKind == JsonValueKind.True)
		{
			return false;
		}
		if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out var number))
		{
			return number == 0;
		}
		if (value.ValueKind == JsonValueKind.String)
		{
			string text = value.GetString();
			return string.IsNullOrWhiteSpace(text) || text.Equals("false", StringComparison.OrdinalIgnoreCase) || text.Equals("no", StringComparison.OrdinalIgnoreCase) || text.Equals("none", StringComparison.OrdinalIgnoreCase) || text.Equals("0", StringComparison.OrdinalIgnoreCase);
		}
		return false;
	}

	private bool ElementIndicatesCapability(JsonElement element, params string[] tokens)
	{
		if (tokens == null || tokens.Length == 0)
		{
			return false;
		}
		if (element.ValueKind == JsonValueKind.Object)
		{
			foreach (JsonProperty property in element.EnumerateObject())
			{
				bool propertyMatches = ContainsAnyToken(property.Name, tokens);
				JsonElement value = property.Value;
				if (propertyMatches)
				{
					if (value.ValueKind == JsonValueKind.True)
					{
						return true;
					}
					if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out var number) && number != 0)
					{
						return true;
					}
					if (value.ValueKind == JsonValueKind.String)
					{
						string text = value.GetString();
						if (!string.IsNullOrWhiteSpace(text) && !text.Equals("false", StringComparison.OrdinalIgnoreCase) && !text.Equals("none", StringComparison.OrdinalIgnoreCase) && !text.Equals("0", StringComparison.OrdinalIgnoreCase))
						{
							return true;
						}
					}
					if (value.ValueKind == JsonValueKind.Array || value.ValueKind == JsonValueKind.Object)
					{
						return ElementIndicatesCapability(value, tokens);
					}
				}
				if (ElementIndicatesCapability(value, tokens))
				{
					return true;
				}
			}
		}
		else if (element.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement child in element.EnumerateArray())
			{
				if (ElementIndicatesCapability(child, tokens))
				{
					return true;
				}
			}
		}
		else if (element.ValueKind == JsonValueKind.String)
		{
			return ContainsAnyToken(element.GetString(), tokens);
		}
		return false;
	}

	private bool ContainsAnyToken(string text, string[] tokens)
	{
		if (string.IsNullOrWhiteSpace(text))
		{
			return false;
		}
		string lower = text.ToLowerInvariant();
		foreach (string token in tokens)
		{
			if (!string.IsNullOrWhiteSpace(token) && lower.Contains(token.ToLowerInvariant()))
			{
				return true;
			}
		}
		return false;
	}

	private List<string> ExtractModelIds(string responseBody)
	{
		List<string> models = new List<string>();
		if (string.IsNullOrWhiteSpace(responseBody))
		{
			return models;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(responseBody);
			AddModelIdsFromElement(document.RootElement, models);
			if (document.RootElement.ValueKind == JsonValueKind.Object)
			{
				if (document.RootElement.TryGetProperty("data", out var data))
				{
					AddModelIdsFromElement(data, models);
				}
				if (document.RootElement.TryGetProperty("models", out var modelList))
				{
					AddModelIdsFromElement(modelList, models);
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Could not parse models response: " + ex.Message);
		}
		return models;
	}

	private void AddModelIdsFromElement(JsonElement element, List<string> models)
	{
		if (models == null)
		{
			return;
		}
		if (element.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement child in element.EnumerateArray())
			{
				AddModelIdsFromElement(child, models);
			}
			return;
		}
		string id = null;
		if (element.ValueKind == JsonValueKind.Object)
		{
			id = ExtractStringProperty(element, "id") ?? ExtractStringProperty(element, "key") ?? ExtractStringProperty(element, "model") ?? ExtractStringProperty(element, "model_id") ?? ExtractStringProperty(element, "modelId") ?? ExtractStringProperty(element, "name");
		}
		else if (element.ValueKind == JsonValueKind.String)
		{
			id = element.GetString();
		}
		if (!string.IsNullOrWhiteSpace(id) && !models.Contains(id))
		{
			models.Add(id);
		}
	}

	private string HandleChatSessionOwnerRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			return JsonSerializer.Serialize(new
			{
				ok = true,
				ownerKey = GetChatSessionOwnerKey(connection, request)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session owner failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatPermissionsGetRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			bool isAdmin = IsDatabaseAdministrator(connection, request);
			if (!isAdmin)
			{
				return BuildDatabaseAdminOnlyJsonError(request, "");
			}
			string currentOwnerKey = GetChatSessionOwnerKey(connection, request);
			string requestedOwnerKey = GetQueryParameter(request, "ownerKey");
			string ownerKey = ((!string.IsNullOrWhiteSpace(requestedOwnerKey)) ? NormalizeChatOwnerKeyInput(requestedOwnerKey) : "global");
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				canEdit = isAdmin,
				isAdmin = isAdmin,
				ownerKey = ownerKey,
				currentOwnerKey = currentOwnerKey,
				permissions = permissions,
				clientPermissions = BuildChatClientPermissionSnapshot(ownerKey, permissions),
				monitoring = BuildSecurityPermissionMonitoringPayload(ownerKey, permissions)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Permission load failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatPermissionsSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			if (!IsDatabaseAdministrator(connection, request))
			{
				return BuildDatabaseAdminOnlyJsonError(request, "");
			}
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string ownerKey = NormalizeChatOwnerKeyInput(ExtractStringProperty(root, "ownerKey") ?? "global");
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			if (root.TryGetProperty("internetSearch", out var internetSearch))
			{
				permissions.internetSearch = ReadJsonBool(internetSearch, permissions.internetSearch);
			}
			if (root.TryGetProperty("vsCopilotTools", out var vsCopilotTools))
			{
				permissions.vsCopilotTools = ReadJsonBool(vsCopilotTools, permissions.vsCopilotTools);
			}
			if (root.TryGetProperty("fileDownloads", out var fileDownloads))
			{
				permissions.fileDownloads = ReadJsonBool(fileDownloads, permissions.fileDownloads);
			}
			if (root.TryGetProperty("ftpServer", out var ftpServer))
			{
				permissions.ftpServer = ReadJsonBool(ftpServer, permissions.ftpServer);
			}
			if (root.TryGetProperty("sqlAdmin", out var sqlAdmin))
			{
				permissions.sqlAdmin = ReadJsonBool(sqlAdmin, permissions.sqlAdmin);
			}
			if (root.TryGetProperty("agentAccess", out var agentAccess))
			{
				permissions.agentAccess = ReadJsonBool(agentAccess, permissions.agentAccess);
			}
			if (root.TryGetProperty("fileUploads", out var fileUploads))
			{
				permissions.fileUploads = ReadJsonBool(fileUploads, permissions.fileUploads);
			}
			if (root.TryGetProperty("imageUploads", out var imageUploads))
			{
				permissions.imageUploads = ReadJsonBool(imageUploads, permissions.imageUploads);
			}
			if (root.TryGetProperty("terminalCommands", out var terminalCommands))
			{
				permissions.terminalCommands = ReadJsonBool(terminalCommands, permissions.terminalCommands);
			}
			if (root.TryGetProperty("terminalForeverApproved", out var terminalForeverApproved))
			{
				permissions.terminalForeverApproved = ReadJsonBool(terminalForeverApproved, permissions.terminalForeverApproved);
			}
			if (root.TryGetProperty("muteUntilEnabled", out var muteUntilEnabled))
			{
				permissions.muteUntilEnabled = ReadJsonBool(muteUntilEnabled, permissions.muteUntilEnabled);
			}
			if (root.TryGetProperty("banUntilEnabled", out var banUntilEnabled))
			{
				permissions.banUntilEnabled = ReadJsonBool(banUntilEnabled, permissions.banUntilEnabled);
			}
			string mutedUntil = ExtractStringProperty(root, "mutedUntilUtc");
			if (mutedUntil != null)
			{
				permissions.mutedUntilUtc = mutedUntil;
			}
			string bannedUntil = ExtractStringProperty(root, "bannedUntilUtc");
			if (bannedUntil != null)
			{
				permissions.bannedUntilUtc = bannedUntil;
			}
			SaveChatPermissions(ownerKey, permissions);
			ApplyRuntimeChatPermissions(GetChatPermissions());
			RecordObservabilityEvent("security", "permissions saved", "updated", "Saved chat permissions.", ownerKey, "/api/chat-permissions", 0L);
			ChatPermissionState updated = GetChatPermissions(ownerKey);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				canEdit = true,
				ownerKey = ownerKey,
				permissions = updated,
				clientPermissions = BuildChatClientPermissionSnapshot(ownerKey, updated),
				monitoring = BuildSecurityPermissionMonitoringPayload(ownerKey, updated)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Permission save failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

