	private string HandleChatClientAdminRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string ownerKey = NormalizeChatOwnerKeyInput(ExtractStringProperty(root, "ownerKey"));
			string action = (ExtractStringProperty(root, "action") ?? "").Trim().ToLowerInvariant();
			if (string.IsNullOrWhiteSpace(ownerKey))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					canEdit = true,
					error = "ownerKey is required."
				});
			}
			bool databaseAdmin = IsDatabaseAdministrator(connection, request);
			bool sharedSessionOwner = !databaseAdmin && CanAdministerSharedSessionClient(connection, request, root, ownerKey);
			if (!databaseAdmin && !sharedSessionOwner)
			{
				return BuildDatabaseAdminOnlyJsonError(request, "Only administrators or the owner of this shared session can update this client.");
			}
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			if (action == "mute" || action == "ban")
			{
				JsonElement minutesElement;
				int minutes = (root.TryGetProperty("minutes", out minutesElement) ? ReadJsonInt(minutesElement, 0) : 0);
				bool untilEnabled = minutes <= 0;
				string until = (untilEnabled ? "" : DateTimeOffset.UtcNow.AddMinutes(minutes).ToString("O"));
				if (action == "ban")
				{
					permissions.bannedUntilUtc = until;
					permissions.banUntilEnabled = untilEnabled;
				}
				else
				{
					permissions.mutedUntilUtc = until;
					permissions.muteUntilEnabled = untilEnabled;
				}
			}
			else if (action == "enable")
			{
				permissions.mutedUntilUtc = "";
				permissions.bannedUntilUtc = "";
				permissions.muteUntilEnabled = false;
				permissions.banUntilEnabled = false;
			}
			else
			{
				if (!(action == "permissions"))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						canEdit = true,
						error = "Unknown client administration action."
					});
				}
				permissions = ((!root.TryGetProperty("permissions", out var permissionRoot) || permissionRoot.ValueKind != JsonValueKind.Object) ? ChatPermissionStateFromJson(root, permissions) : ChatPermissionStateFromJson(permissionRoot, permissions));
			}
			SaveChatPermissions(ownerKey, permissions);
			ApplyRuntimeChatPermissions(GetChatPermissions());
			ChatPermissionState updated = GetChatPermissions(ownerKey);
			RecordObservabilityEvent("security", "client administration", action, "Updated client security state.", ownerKey, "/api/chat-client-admin", 0L);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				canEdit = true,
				ownerKey = ownerKey,
				permissions = updated,
				clientPermissions = BuildChatClientPermissionSnapshot(ownerKey, updated),
				monitoring = BuildSecurityPermissionMonitoringPayload(ownerKey, updated)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Client admin update failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private bool CanAdministerSharedSessionClient(NetworkConnection connection, HttpRequest request, JsonElement root, string targetOwnerKey)
	{
		if (string.IsNullOrWhiteSpace(targetOwnerKey) || !targetOwnerKey.StartsWith("ip:", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		string sessionId = ExtractStringProperty(root, "sessionId") ?? ExtractStringProperty(root, "id");
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return false;
		}
		string currentOwnerKey = GetChatSessionOwnerKey(connection, request);
		sessionId = EnsureChatUiSessionId(sessionId);
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (!string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
				{
					continue;
				}
				return ParseStoredBool(GetRowValue(row, 10), fallback: false) && ChatOwnerKeysMatch(currentOwnerKey, GetRowValue(row, 7));
			}
		}
		return false;
	}

