	private string HandleTerminalApprovalDecisionRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			if (!IsDatabaseAdministrator(connection, request))
			{
				return BuildDatabaseAdminOnlyJsonError(request, "");
			}
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string requestId = ExtractStringProperty(root, "requestId") ?? ExtractStringProperty(root, "id") ?? "";
			string action = (ExtractStringProperty(root, "action") ?? "").Trim().ToLowerInvariant();
			JsonElement alwaysElement;
			bool always = root.TryGetProperty("always", out alwaysElement) && ReadJsonBool(alwaysElement, fallback: false);
			JsonElement foreverElement;
			bool forever = root.TryGetProperty("forever", out foreverElement) && ReadJsonBool(foreverElement, fallback: false);
			if (string.IsNullOrWhiteSpace(requestId))
			{
				return BuildJsonError(request, 400, "Bad Request", "Terminal approval request id is required.");
			}
			TerminalPermissionRequestSnapshot snapshot;
			if (action == "approve" || action == "allow")
			{
				snapshot = ApproveTerminalPermissionRequest(requestId, always || forever, forever);
			}
			else
			{
				if (!(action == "deny") && !(action == "block"))
				{
					return BuildJsonError(request, 400, "Bad Request", "Unknown terminal approval action.");
				}
				snapshot = DenyTerminalPermissionRequest(requestId, always);
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				request = snapshot,
				approvals = GetPendingTerminalPermissionRequests()
			});
		}
		catch (InvalidOperationException ex)
		{
			return BuildJsonError(request, 404, "Not Found", ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[Chat UI] Terminal approval decision failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

