	private string HandleChatFilesystemAccessMutationRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			if (!IsDatabaseAdministrator(connection, request))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					canEdit = false,
					error = "Filesystem access can only be changed by a WebAuth administrator or the configured server owner."
				});
			}
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string action = ExtractStringProperty(root, "action") ?? "";
			string path = ExtractStringProperty(root, "path") ?? "";
			if (action.Equals("add", StringComparison.OrdinalIgnoreCase))
			{
				if (!TryNormalizeAccessibleDirectory(path, requireExists: true, out var normalizedPath, out var error))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						canEdit = true,
						error = error
					});
				}
				SaveChatFilesystemAccess(ownerKey, normalizedPath);
				RecordObservabilityEvent("security", "filesystem access", "allowed", normalizedPath, ownerKey, "/api/chat-filesystem-access", 0L);
			}
			else
			{
				if (!action.Equals("remove", StringComparison.OrdinalIgnoreCase))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						canEdit = true,
						error = "Unknown filesystem access action."
					});
				}
				if (!TryNormalizeAccessibleDirectory(path, requireExists: false, out var normalizedPath2, out var error2, allowFilesystemRoot: true))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						canEdit = true,
						error = error2
					});
				}
				RemoveChatFilesystemAccess(ownerKey, normalizedPath2);
				StopChatFtpServerIfRootRemoved(ownerKey, normalizedPath2);
				RecordObservabilityEvent("security", "filesystem access", "removed", normalizedPath2, ownerKey, "/api/chat-filesystem-access", 0L);
			}
			string sessionId = NormalizeOptionalDeveloperProjectSessionId(ExtractStringProperty(root, "sessionId") ?? GetQueryParameter(request, "sessionId"));
			return JsonSerializer.Serialize(new
			{
				ok = true,
				canEdit = true,
				ownerKey = ownerKey,
				directories = GetChatFilesystemAccess(ownerKey),
				contextRoots = BuildAgentFilesystemContextRootOptions(ownerKey, sessionId),
				monitoring = BuildSecurityPermissionMonitoringPayload(ownerKey)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Filesystem access update failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

