	private string HandleChatSolutionExplorerRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string requestedPath = GetQueryParameter(request, "path");
			string kind = (GetQueryParameter(request, "kind") ?? "").Trim();
			string sessionId = EnsureChatUiSessionId(GetQueryParameter(request, "sessionId"));
			string search = (GetQueryParameter(request, "search") ?? "").Trim();
			string sort = (GetQueryParameter(request, "sort") ?? "").Trim();
			if (string.IsNullOrWhiteSpace(requestedPath))
			{
				if (!string.IsNullOrWhiteSpace(search))
				{
					return JsonSerializer.Serialize(new
					{
						ok = true,
						ownerKey = ownerKey,
						sessionId = sessionId,
						storage = BuildSolutionExplorerStorageMetrics(ownerKey, sessionId),
						results = SearchSolutionExplorerEntries(ownerKey, sessionId, search, sort)
					});
				}
				return JsonSerializer.Serialize(new
				{
					ok = true,
					ownerKey = ownerKey,
					sessionId = sessionId,
					storage = BuildSolutionExplorerStorageMetrics(ownerKey, sessionId),
					roots = BuildChatSolutionExplorerRoots(ownerKey, sessionId, includeAccessibleRoots: true)
				});
			}
			if (!TryResolveSolutionExplorerDirectory(ownerKey, sessionId, kind, requestedPath, out var fullPath, out var error))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					ownerKey = ownerKey,
					sessionId = sessionId,
					error = error
				});
			}
			List<SolutionExplorerEntry> children = BuildSolutionExplorerChildren(ownerKey, kind, fullPath, sessionId, sort);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				ownerKey = ownerKey,
				sessionId = sessionId,
				storage = BuildSolutionExplorerStorageMetrics(ownerKey, sessionId),
				current = BuildSolutionExplorerEntry(kind, fullPath, isDirectory: true, sessionId),
				children = children
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Solution explorer load failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

