				error = ex.Message
			});
		}
	}

	private string HandleChatFtpConfigSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			if (!IsDatabaseAdministrator(connection, request))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					canEdit = false,
					error = "FTP configuration can only be changed by a WebAuth administrator or the configured server owner."
				});
			}
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string action = (ExtractStringProperty(root, "action") ?? "save").Trim();
			if (string.IsNullOrWhiteSpace(action))
			{
				action = "save";
			}
			string requestedOwnerKey = ExtractStringProperty(root, "ownerKey") ?? ExtractStringProperty(root, "username") ?? ExtractStringProperty(root, "user");
			if (!string.IsNullOrWhiteSpace(requestedOwnerKey))
			{
				string normalizedOwnerKey = NormalizeChatOwnerKeyInput(requestedOwnerKey);
				if (!string.IsNullOrWhiteSpace(normalizedOwnerKey))
				{
					ownerKey = normalizedOwnerKey;
				}
			}
			permissions = GetChatPermissions(ownerKey);
			if (root.TryGetProperty("permissionEnabled", out var permissionEnabled))
			{
				permissions.ftpServer = ReadJsonBool(permissionEnabled, permissions.ftpServer);
				SaveChatPermissions(ownerKey, permissions);
				if (!permissions.ftpServer && IsChatFtpServerActiveForOwner(ownerKey))
				{
					StopChatFtpServer();
				}
				if (ownerKey.Equals("global", StringComparison.OrdinalIgnoreCase))
				{
					ApplyRuntimeChatPermissions(permissions);
				}
			}
			ChatFtpServerConfig existing = GetChatFtpConfig(ownerKey);
			if (action.Equals("permission", StringComparison.OrdinalIgnoreCase))
			{
				LogMessage("[Chat UI] FTP permission updated for " + ownerKey + "; enabled=" + permissions.ftpServer + ".");
				return BuildChatFtpConfigResponse(connection, request, ownerKey, permissions);
			}
			if (action.Equals("stop", StringComparison.OrdinalIgnoreCase))
			{
				existing.enabled = false;
				existing.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
				SaveChatFtpConfig(ownerKey, existing);
				if (IsChatFtpServerActiveForOwner(ownerKey))
				{
					StopChatFtpServer();
				}
				LogMessage("[Chat UI] FTP stop requested for " + ownerKey + ".");
				return BuildChatFtpConfigResponse(connection, request, ownerKey, permissions);
			}
			if (!permissions.ftpServer)
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					canEdit = true,
					error = "Ftp Server permission is disabled."
				});
			}
			ChatFtpServerConfig config = BuildChatFtpConfigFromJson(root, existing);
			string validationError = NormalizeAndValidateChatFtpUsers(ownerKey, config);
			if (!string.IsNullOrWhiteSpace(validationError))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					canEdit = true,
					error = validationError
				});
			}
			if (action.Equals("start", StringComparison.OrdinalIgnoreCase))
			{
				config.enabled = true;
				SaveChatFtpConfig(ownerKey, config);
				LogMessage("[Chat UI] FTP config saved for " + ownerKey + " before start; autostart=" + config.autoStart + ".");
				StartChatFtpServer(ownerKey, config);
			}
			else
			{
				if (!action.Equals("save", StringComparison.OrdinalIgnoreCase))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						canEdit = true,
						error = "Unknown FTP configuration action."
					});
				}
				config.enabled = existing.enabled;
				SaveChatFtpConfig(ownerKey, config);
				LogMessage("[Chat UI] FTP config saved for " + ownerKey + "; autostart=" + config.autoStart + ".");
				if (config.enabled && IsChatFtpServerActiveForOwner(ownerKey))
				{
					StartChatFtpServer(ownerKey, config);
				}
			}
			return BuildChatFtpConfigResponse(connection, request, ownerKey, permissions);
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] FTP config update failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string BuildChatFtpConfigResponse(NetworkConnection connection, HttpRequest request, string ownerKey, ChatPermissionState permissions)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		List<ChatFilesystemAccessEntry> directories = GetChatFilesystemAccess(ownerKey);
		ChatFtpServerConfig config = GetChatFtpConfig(ownerKey);
		ApplyDefaultChatFtpDirectory(config, directories);
		bool canEdit = IsDatabaseAdministrator(connection, request);
		string currentOwnerKey = GetChatSessionOwnerKey(connection, request);
		string userName = GetUserNameFromOwnerKey(ownerKey);
		return JsonSerializer.Serialize(new
		{
			ok = true,
			canEdit = canEdit,
			canManageOwners = canEdit,
			currentOwnerKey = currentOwnerKey,
			ownerKey = ownerKey,
			username = userName,
			permissionEnabled = (permissions?.ftpServer ?? false),
			config = config,
			directories = directories,
			status = GetChatFtpServerStatus()
		});
	}

	private string HandleChatSessionsListRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			bool isAdmin = IsDatabaseAdministrator(connection, request);
			int take = ReadChatSessionListTake(request);
			int skip = ReadChatSessionListSkip(request);
			if (TryGetChatSessionListCache(ownerKey, skip, take, out var cachedList))
			{
				int cachedCount = cachedList.Sessions?.Count ?? 0;
				return JsonSerializer.Serialize(new
				{
					ok = true,
					ownerKey = ownerKey,
					isAdmin = isAdmin,
					total = cachedList.Total,
					count = cachedCount,
					skip = skip,
					take = take,
					hasMore = take >= 0 && skip + cachedCount < cachedList.Total,
					cached = true,
					sessions = cachedList.Sessions ?? Array.Empty<ChatSessionSummary>()
				});
			}
			List<ChatSessionListRowSnapshot> candidates = new List<ChatSessionListRowSnapshot>();
			List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				foreach (object[] sourceRow in table.Rows)
				{
					object[] row = NormalizeChatSessionRow(sourceRow);
					string rowOwnerKey = GetRowValue(row, 7);
					if (OwnerKeyListContains(ownerKeys, rowOwnerKey))
					{
						candidates.Add(new ChatSessionListRowSnapshot
						{
							Row = (object[])row.Clone(),
							UpdatedUtc = GetRowValue(row, 3)
						});
					}
				}
			}
			candidates.Sort((ChatSessionListRowSnapshot a, ChatSessionListRowSnapshot b) => string.CompareOrdinal(b?.UpdatedUtc ?? "", a?.UpdatedUtc ?? ""));
			int totalCount = candidates.Count;
			IEnumerable<ChatSessionListRowSnapshot> page = candidates;
			if (skip > 0)
			{
				page = page.Skip(skip);
			}
			if (take >= 0)
			{
				page = page.Take(take);
			}
			List<ChatSessionListRowSnapshot> pageRows = page.Where((ChatSessionListRowSnapshot item) => item?.Row != null).ToList();
			Dictionary<string, int> commentCounts = CountChatSessionCommentsBySessionSnapshot(pageRows.Select((ChatSessionListRowSnapshot item) => GetRowValue(item.Row, 0)));
			Dictionary<string, ChatSessionComputeSummary> computeBySession = GetChatSessionComputeSummaries(ownerKeys, pageRows.Select((ChatSessionListRowSnapshot item) => GetRowValue(item.Row, 0)));
			List<ChatSessionSummary> sessions = new List<ChatSessionSummary>(pageRows.Count);
			foreach (ChatSessionListRowSnapshot snapshot in pageRows)
			{
				object[] row = snapshot.Row;
				string sessionId = GetRowValue(row, 0);
				int messageCount = CountChatSessionPrivateArrayItems(row, 5, "messages", "[]", ownerKey, allowDecrypt: true);
				int fileCount = CountChatSessionPrivateArrayItems(row, 6, "files", "[]", ownerKey, allowDecrypt: true);
				int commentCount = (commentCounts.TryGetValue(sessionId, out var comments) ? comments : 0);
				ChatSessionComputeSummary compute = (computeBySession.TryGetValue(sessionId, out var recordedCompute) ? recordedCompute : new ChatSessionComputeSummary());
				sessions.Add(new ChatSessionSummary
				{
					id = sessionId,
					title = GetRowValue(row, 1),
					createdUtc = GetRowValue(row, 2),
					updatedUtc = GetRowValue(row, 3),
					model = GetRowValue(row, 4),
					ownerKey = GetRowValue(row, 7),
					messageCount = messageCount,
					fileCount = fileCount,
					shareKey = GetRowValue(row, 9),
					shareEnabled = ParseStoredBool(GetRowValue(row, 10), fallback: false),
					titleLocked = ParseStoredBool(GetRowValue(row, 11), fallback: false),
					savedUtc = GetRowValue(row, 12),
					locked = ParseStoredBool(GetRowValue(row, 13), fallback: false),
					lockedUtc = GetRowValue(row, 14),
					clonedFromSessionId = GetRowValue(row, 15),
					promptTokenCount = ParseStoredLong(GetRowValue(row, 16), 0L),
					promptTokenBudget = ParseStoredLong(GetRowValue(row, 17), 8192L),
					runtime = GetRowValue(row, 18),
					commentCount = commentCount,
					tokensUsed = compute.TokensUsed,
					gpuSeconds = compute.GpuSeconds,
					cpuComputeSeconds = compute.CpuComputeSeconds,
					ramGbSeconds = compute.RamGbSeconds,
					ioBytes = compute.IoBytes,
					compatibility = BuildChatSessionCompatibilityPayload(row, null, null, -1L, 0L, messageCount, fileCount, commentCount)
				});
			}
			SetChatSessionListCache(ownerKey, skip, take, sessions, totalCount);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				ownerKey = ownerKey,
				isAdmin = isAdmin,
				total = totalCount,
				count = sessions.Count,
				skip = skip,
				take = take,
				hasMore = take >= 0 && skip + sessions.Count < totalCount,
				cached = false,
				sessions = sessions
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session list failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private Dictionary<string, ChatSessionComputeSummary> GetChatSessionComputeSummaries(List<string> ownerKeys, IEnumerable<string> sessionIds)
	{
		HashSet<string> wanted = new HashSet<string>((sessionIds ?? Array.Empty<string>()).Where(id => !string.IsNullOrWhiteSpace(id)), StringComparer.OrdinalIgnoreCase);
		Dictionary<string, ChatSessionComputeSummary> result = new Dictionary<string, ChatSessionComputeSummary>(StringComparer.OrdinalIgnoreCase);
		if (wanted.Count == 0)
		{
			return result;
		}
		lock (_chatSessionLock)
		{
			Table table = GetFinanceUsageLedgerTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeFinanceUsageLedgerRow(sourceRow);
				string sessionId = GetRowValue(row, 6);
				if (!wanted.Contains(sessionId) || !OwnerKeyListContains(ownerKeys, GetRowValue(row, 2)))
				{
					continue;
				}
				if (!result.TryGetValue(sessionId, out ChatSessionComputeSummary summary))
				{
					summary = new ChatSessionComputeSummary();
					result[sessionId] = summary;
				}
				summary.TokensUsed += Math.Max(0L, ParseStoredLong(GetRowValue(row, 8), 0L));
				summary.GpuSeconds += Math.Max(0.0, ParseStoredDouble(GetRowValue(row, 10), 0.0));
				summary.CpuComputeSeconds += Math.Max(0.0, ParseStoredDouble(GetRowValue(row, 11), 0.0));
				summary.RamGbSeconds += Math.Max(0.0, ParseStoredDouble(GetRowValue(row, 12), 0.0));
				summary.IoBytes += Math.Max(0L, ParseStoredLong(GetRowValue(row, 13), 0L));
			}
		}
		return result;
	}

	private int ReadChatSessionListTake(HttpRequest request)
	{
		string value = (GetQueryParameter(request, "take") ?? GetQueryParameter(request, "limit") ?? "").Trim();
		if (value.Equals("all", StringComparison.OrdinalIgnoreCase) || value.Equals("none", StringComparison.OrdinalIgnoreCase))
		{
			return -1;
		}
		if (!int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out var take))
		{
			return ChatSessionListDefaultTake;
		}
		if (take < 0)
		{
			return -1;
		}
		return Math.Min(ChatSessionListMaxTake, Math.Max(1, take));
	}

	private int ReadChatSessionListSkip(HttpRequest request)
	{
		string value = (GetQueryParameter(request, "skip") ?? GetQueryParameter(request, "offset") ?? "").Trim();
		if (!int.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out var skip))
		{
			return 0;
		}
		return Math.Max(0, skip);
	}

	private string BuildChatSessionListCacheKey(string ownerKey, int skip, int take)
	{
		return NormalizeChatFilesystemOwnerKey(ownerKey) + "|" + skip.ToString(CultureInfo.InvariantCulture) + "|" + take.ToString(CultureInfo.InvariantCulture);
	}

	private bool TryGetChatSessionListCache(string ownerKey, int skip, int take, out ChatSessionListCacheEntry entry)
	{
		entry = null;
		string key = BuildChatSessionListCacheKey(ownerKey, skip, take);
		lock (_chatSessionListCacheLock)
		{
			if (_chatSessionListCache.TryGetValue(key, out var cached) && cached != null)
			{
				entry = cached;
				return true;
			}
		}
		return false;
	}

	private void SetChatSessionListCache(string ownerKey, int skip, int take, IReadOnlyList<ChatSessionSummary> sessions, int total)
	{
		string key = BuildChatSessionListCacheKey(ownerKey, skip, take);
		lock (_chatSessionListCacheLock)
		{
			_chatSessionListCache[key] = new ChatSessionListCacheEntry
			{
				Sessions = (sessions ?? Array.Empty<ChatSessionSummary>()).ToArray(),
				Total = Math.Max(0, total),
				CreatedUtc = DateTimeOffset.UtcNow
			};
		}
	}

	private void InvalidateChatSessionDerivedCaches(string ownerKey = null, string sessionId = null)
	{
		Interlocked.Increment(ref _chatDataVersion);
		lock (_chatUsageSnapshotCacheLock)
		{
			_chatUsageSnapshotCache.Clear();
		}
		lock (_chatSessionLock)
		{
			_chatCostSettingsCache = null;
			_chatCostSettingsCacheVersion = -1;
		}
		lock (_chatSessionListCacheLock)
		{
			_chatSessionListCache.Clear();
		}
		lock (_solutionExplorerStorageCacheLock)
		{
			_solutionExplorerStorageCache.Clear();
		}
	}

	private void SaveChatSessionDataAndInvalidateCaches(string ownerKey = null, string sessionId = null)
	{
		_chatSessionData.Save();
		InvalidateChatSessionDerivedCaches(ownerKey, sessionId);
	}

	private Dictionary<string, int> CountChatSessionCommentsBySessionSnapshot(IEnumerable<string> sessionIds)
	{
		HashSet<string> requested = new HashSet<string>((sessionIds ?? Array.Empty<string>()).Where((string id) => !string.IsNullOrWhiteSpace(id)), StringComparer.Ordinal);
		Dictionary<string, int> counts = new Dictionary<string, int>(StringComparer.Ordinal);
		if (requested.Count == 0)
		{
			return counts;
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionCommentsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionCommentRow(sourceRow);
				string sessionId = GetRowValue(row, 1);
				if (!requested.Contains(sessionId))
				{
					continue;
				}
				counts.TryGetValue(sessionId, out var current);
				counts[sessionId] = current + 1;
			}
		}
		return counts;
	}

	private int CountChatSessionPrivateArrayItems(object[] row, int index, string purpose, string fallback, string ownerKey, bool allowDecrypt)
	{
		if (row == null || index < 0 || index >= row.Length)
		{
			return 0;
		}
		string value = GetRowValue(row, index);
		if (TryReadProtectedChatSessionPrivateArrayCount(value, purpose, out var protectedCount))
		{
			return protectedCount;
		}
		if (!IsProtectedChatSessionPrivateValue(value))
		{
			return CountJsonArrayItems(string.IsNullOrWhiteSpace(value) ? fallback : value);
		}
		return allowDecrypt ? CountJsonArrayItems(GetChatSessionPrivateValue(row, index, purpose, fallback, ownerKey)) : 0;
	}

	private bool TryReadProtectedChatSessionPrivateArrayCount(string protectedValue, string purpose, out int count)
	{
		count = 0;
		if (string.IsNullOrWhiteSpace(protectedValue) || !protectedValue.StartsWith(ChatPrivatePayloadPrefixV2, StringComparison.Ordinal))
		{
			return false;
		}
		string payloadText = protectedValue.Substring(ChatPrivatePayloadPrefixV2.Length);
		int first = payloadText.IndexOf(':');
		if (first <= 0)
		{
			return false;
		}
		int second = payloadText.IndexOf(':', first + 1);
		if (second <= first)
		{
			return false;
		}
		int third = payloadText.IndexOf(':', second + 1);
		if (third <= second)
		{
			return false;
		}
		string storedPurpose = payloadText.Substring(0, first);
		if (!string.Equals(storedPurpose, purpose, StringComparison.Ordinal))
		{
			return false;
		}
		string countText = payloadText.Substring(second + 1, third - second - 1);
		return int.TryParse(countText, NumberStyles.Integer, CultureInfo.InvariantCulture, out count) && count >= 0;
	}

	private string HandleChatActiveSessionsRequest(NetworkConnection connection, HttpRequest request)
	{
		AddWebAuthCorsHeaders(request);
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string filterSessionId = "";
			string shareKey = GetQueryParameter(request, "hashKey") ?? GetQueryParameter(request, "shareKey") ?? GetQueryParameter(request, "key");
			if (!string.IsNullOrWhiteSpace(shareKey) && TryResolveSharedSessionByKey(shareKey, out var sharedOwnerKey, out var sharedSessionId))
			{
				ownerKey = sharedOwnerKey;
				filterSessionId = sharedSessionId;
			}
			List<object> sessions = new List<object>();
			lock (_activePromptSessionLock)
			{
				PruneInactivePromptSessionsLocked();
				foreach (ActivePromptSessionState state in _activePromptSessions.Values)
				{
					if (state != null && !state.CompletedUtc.HasValue && string.Equals(state.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) && (string.IsNullOrWhiteSpace(filterSessionId) || string.Equals(state.SessionId, filterSessionId, StringComparison.Ordinal)))
					{
						sessions.Add(new
						{
							id = state.Id,
							sessionId = (state.SessionId ?? ""),
							source = (state.Source ?? ""),
							title = (state.Title ?? ""),
							ownerKey = (state.OwnerKey ?? ""),
							streamId = (state.StreamId ?? ""),
							participantKey = (state.ParticipantKey ?? ""),
							participantIp = DisplayIpFromOwnerKey(state.ParticipantKey),
							model = (state.Model ?? ""),
							runtime = (state.Runtime ?? ""),
							status = (state.Status ?? ""),
							phase = (state.Phase ?? ""),
							startedUtc = state.StartedUtc.ToString("O"),
							updatedUtc = state.UpdatedUtc.ToString("O"),
							elapsedSeconds = Math.Max(0, (int)Math.Round((DateTimeOffset.UtcNow - state.StartedUtc).TotalSeconds)),
							promptTokenCount = state.PromptTokenCount,
							promptTokenBudget = state.PromptTokenBudget,
							answerContent = (state.AnswerContent ?? ""),
							reasoningContent = (state.ReasoningContent ?? ""),
							compatibility = BuildChatSessionCompatibilityPayload(state.OwnerKey, state.SessionId, state.Model, state.Runtime, state.PromptTokenCount, state.PromptTokenBudget)
						});
					}
				}
			}
			sessions.Sort(delegate(object a, object b)
			{
				string strA = ((a == null) ? "" : (a.GetType().GetProperty("startedUtc")?.GetValue(a)?.ToString() ?? ""));
				string strB = ((b == null) ? "" : (b.GetType().GetProperty("startedUtc")?.GetValue(b)?.ToString() ?? ""));
				return string.CompareOrdinal(strA, strB);
			});
			return JsonSerializer.Serialize(new
			{
				ok = true,
				ownerKey = ownerKey,
				sessions = sessions
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Active session list failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

