	private string HandleChatSessionGetRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string queryId;
			string id = ((request != null && request.QueryParameters != null && request.QueryParameters.TryGetValue("id", out queryId)) ? queryId : null);
			if (string.IsNullOrWhiteSpace(id))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Session id is required."
				});
			}
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				foreach (object[] row in table.Rows)
				{
					if (!string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
					{
						continue;
					}
					if (!ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
					{
						return JsonSerializer.Serialize(new
						{
							ok = false,
							error = "Session not found."
						});
					}
					object[] readableRow = DecryptChatSessionRowForOwner(row, ownerKey);
					return JsonSerializer.Serialize(new
					{
						ok = true,
						session = new
						{
							id = GetRowValue(readableRow, 0),
							title = GetRowValue(readableRow, 1),
							createdUtc = GetRowValue(readableRow, 2),
							updatedUtc = GetRowValue(readableRow, 3),
							model = GetRowValue(readableRow, 4),
							messages = DeserializeJsonElement(GetRowValue(readableRow, 5), "[]"),
							files = DeserializePublicChatSessionFilesElement(GetRowValue(readableRow, 6), GetRowValue(readableRow, 0)),
							draftPrompt = GetRowValue(readableRow, 8),
							shareKey = GetRowValue(readableRow, 9),
							shareEnabled = ParseStoredBool(GetRowValue(readableRow, 10), fallback: false),
							titleLocked = ParseStoredBool(GetRowValue(readableRow, 11), fallback: false),
							savedUtc = GetRowValue(readableRow, 12),
							locked = ParseStoredBool(GetRowValue(readableRow, 13), fallback: false),
							lockedUtc = GetRowValue(readableRow, 14),
							clonedFromSessionId = GetRowValue(readableRow, 15),
							promptTokenCount = ParseStoredLong(GetRowValue(readableRow, 16), 0L),
							promptTokenBudget = ParseStoredLong(GetRowValue(readableRow, 17), 8192L),
							runtime = GetRowValue(readableRow, 18),
							commentCount = CountChatSessionComments(GetRowValue(readableRow, 0)),
							compatibility = BuildChatSessionCompatibilityPayload(readableRow, null, null, -1L, 0L)
						}
					});
				}
			}
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = "Session not found."
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session get failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatSessionSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string action = (ExtractStringProperty(root, "action") ?? "save").Trim();
			string id = ExtractStringProperty(root, "id");
			if (action.Equals("delete", StringComparison.OrdinalIgnoreCase))
			{
				if (string.IsNullOrWhiteSpace(id))
				{
					return JsonSerializer.Serialize(new
					{
						ok = false,
						error = "Session id is required."
					});
				}
				return DeleteChatSessionsBulk(request, ownerKey, new string[1] { id }, failOnLockedSingleDelete: true);
			}
			if (action.Equals("delete-bulk", StringComparison.OrdinalIgnoreCase) || action.Equals("bulk-delete", StringComparison.OrdinalIgnoreCase) || action.Equals("delete_selected", StringComparison.OrdinalIgnoreCase))
			{
				IReadOnlyList<string> ids = ExtractChatSessionDeleteIds(root);
				return DeleteChatSessionsBulk(request, ownerKey, ids);
			}
			if (string.IsNullOrWhiteSpace(id))
			{
				id = "sess_" + Guid.NewGuid().ToString("N");
			}
			string model = ExtractStringProperty(root, "model") ?? "";
			string title = ExtractStringProperty(root, "title");
			JsonElement messages;
			string messagesJson = (root.TryGetProperty("messages", out messages) ? messages.GetRawText() : "[]");
			JsonElement files;
			string filesJson = (root.TryGetProperty("files", out files) ? files.GetRawText() : "[]");
			filesJson = NormalizeChatSessionFilesJsonForStorage(filesJson, id);
			string draftPrompt = ExtractStringProperty(root, "draftPrompt") ?? "";
			JsonElement titleLockedElement;
			bool titleLockedSpecified = root.TryGetProperty("titleLocked", out titleLockedElement);
			bool titleLocked = titleLockedSpecified && ReadJsonBool(titleLockedElement, fallback: false);
			JsonElement promptTokenBudgetElement;
			long promptTokenBudget = (root.TryGetProperty("promptTokenBudget", out promptTokenBudgetElement) ? NormalizePromptTokenBudget(ReadJsonLong(promptTokenBudgetElement, 8192L)) : ExtractPromptTokenBudgetFromRequestBody(body, model));
			string runtime = ExtractStringProperty(root, "runtime") ?? InferChatSessionRuntime(model);
			title = NormalizeChatSessionTitleInput(title);
			if (string.IsNullOrWhiteSpace(title))
			{
				title = ((CountJsonArrayItems(messagesJson) > 0 || string.IsNullOrWhiteSpace(draftPrompt)) ? InferChatSessionTitle(messagesJson) : InferChatSessionTitleFromDraft(draftPrompt));
			}
			string now = DateTimeOffset.UtcNow.ToString("O");
			string savedTitle = title;
			bool savedTitleLocked = titleLocked;
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				int existingIndex = -1;
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] row = NormalizeChatSessionRow(table.Rows[i]);
					table.Rows[i] = row;
					if (string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
					{
						existingIndex = i;
						break;
					}
				}
				if (existingIndex < 0)
				{
					object[] next = CreateChatSessionRow(id, title, now, now, model, messagesJson, filesJson, ownerKey, draftPrompt, "", shareEnabled: false, titleLocked, now, locked: false, "", "", promptTokenBudget, runtime);
					if (!EnsureChatStorageCanAdd(ownerKey, id, EstimateChatSessionRowStorageBytes(next), out var usageSnapshot, out var storageError))
					{
						SetHttpStatus(request, 507, "Insufficient Storage");
						return JsonSerializer.Serialize(new
						{
							ok = false,
							error = storageError,
							usage = usageSnapshot
						});
					}
					table.Rows.Add(next);
					savedTitle = title;
					savedTitleLocked = titleLocked;
				}
				else
				{
					object[] existingStored = table.Rows[existingIndex];
					object[] existing = DecryptChatSessionRowForOwner(existingStored, ownerKey);
					if (!ChatOwnerKeysMatch(ownerKey, GetRowValue(existing, 7)))
					{
						return JsonSerializer.Serialize(new
						{
							ok = false,
							error = "Session belongs to another client."
						});
					}
					if (ParseStoredBool(GetRowValue(existing, 13), fallback: false))
					{
						return BuildJsonError(request, 423, "Locked", "Session is locked.");
					}
					object[] next2 = (object[])existing.Clone();
					bool existingTitleLocked = ParseStoredBool(GetRowValue(existing, 11), fallback: false);
					bool nextTitleLocked = (titleLockedSpecified ? titleLocked : existingTitleLocked);
					next2[1] = ((existingTitleLocked && !titleLockedSpecified) ? GetRowValue(existing, 1) : title);
					next2[3] = now;
					next2[4] = model;
					next2[5] = messagesJson;
					next2[6] = MergeChatSessionFilesJson(filesJson, GetRowValue(existing, 6));
					next2[7] = ownerKey;
					next2[8] = draftPrompt;
					next2[9] = GetRowValue(existing, 9);
					next2[10] = GetRowValue(existing, 10);
					next2[11] = (nextTitleLocked ? "true" : "false");
					next2[12] = now;
					next2[13] = GetRowValue(existing, 13);
					next2[14] = GetRowValue(existing, 14);
					next2[15] = GetRowValue(existing, 15);
					next2[16] = EstimateChatSessionPromptTokens(messagesJson, draftPrompt).ToString(CultureInfo.InvariantCulture);
					next2[17] = promptTokenBudget.ToString(CultureInfo.InvariantCulture);
					next2[18] = (string.IsNullOrWhiteSpace(runtime) ? GetRowValue(existing, 18) : runtime);
					long rowDelta = Math.Max(0L, EstimateChatSessionRowStorageBytes(next2) - EstimateChatSessionRowStorageBytes(existing));
					if (!EnsureChatStorageCanAdd(ownerKey, id, rowDelta, out var usageSnapshot2, out var storageError2))
					{
						SetHttpStatus(request, 507, "Insufficient Storage");
						return JsonSerializer.Serialize(new
						{
							ok = false,
							error = storageError2,
							usage = usageSnapshot2
						});
					}
					ProtectChatSessionRowSensitiveValues(next2);
					table.Rows[existingIndex] = next2;
					savedTitle = GetRowValue(next2, 1);
					savedTitleLocked = nextTitleLocked;
				}
				SaveChatSessionDataAndInvalidateCaches();
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				id = id,
				title = savedTitle,
				updatedUtc = now,
				savedUtc = now,
				ownerKey = ownerKey,
				titleLocked = savedTitleLocked,
				locked = false,
				promptTokenCount = EstimateChatSessionPromptTokens(messagesJson, draftPrompt),
				promptTokenBudget = promptTokenBudget,
				runtime = runtime
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session save failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string DeleteChatSessionsBulk(HttpRequest request, string ownerKey, IReadOnlyList<string> ids, bool failOnLockedSingleDelete = false)
	{
		string[] requestedIds = NormalizeChatSessionDeleteIds(ids);
		if (requestedIds.Length == 0)
		{
			return BuildJsonError(request, 400, "Bad Request", "At least one session id is required.");
		}
		HashSet<string> requestedSet = new HashSet<string>(requestedIds, StringComparer.Ordinal);
		List<string> deletedIds = new List<string>();
		List<string> lockedIds = new List<string>();
		int removedComments = 0;
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			for (int i = table.Rows.Count - 1; i >= 0; i--)
			{
				object[] row = NormalizeChatSessionRow(table.Rows[i]);
				table.Rows[i] = row;
				string rowId = GetRowValue(row, 0);
				if (requestedSet.Contains(rowId) && ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
				{
					if (ParseStoredBool(GetRowValue(row, 13), fallback: false))
					{
						lockedIds.Add(rowId);
					}
					else
					{
						table.Rows.RemoveAt(i);
						deletedIds.Add(rowId);
					}
				}
			}
			if (deletedIds.Count > 0)
			{
				removedComments = RemoveChatSessionCommentsForSessionsLocked(new HashSet<string>(deletedIds, StringComparer.Ordinal));
				SaveChatSessionDataAndInvalidateCaches();
			}
		}
		if (failOnLockedSingleDelete && lockedIds.Count > 0)
		{
			return BuildJsonError(request, 423, "Locked", "Session is locked.");
		}
		HashSet<string> deletedSet = new HashSet<string>(deletedIds, StringComparer.Ordinal);
		HashSet<string> lockedSet = new HashSet<string>(lockedIds, StringComparer.Ordinal);
		string[] missingIds = requestedIds.Where((string id) => !deletedSet.Contains(id) && !lockedSet.Contains(id)).ToArray();
		foreach (string deletedId in deletedIds)
		{
			DeleteChatSessionFilesDirectory(deletedId, ownerKey);
		}
		return JsonSerializer.Serialize(new
		{
			ok = true,
			ownerKey = ownerKey,
			requested = requestedIds.Length,
			deleted = (deletedIds.Count > 0),
			deletedCount = deletedIds.Count,
			missingCount = missingIds.Length,
			lockedCount = lockedIds.Count,
			removedComments = removedComments,
			deletedIds = deletedIds.OrderBy((string id) => Array.IndexOf(requestedIds, id)).ToArray(),
			missingIds = missingIds,
			lockedIds = lockedIds.OrderBy((string id) => Array.IndexOf(requestedIds, id)).ToArray(),
			error = ""
		});
	}

	private static IReadOnlyList<string> ExtractChatSessionDeleteIds(JsonElement root)
	{
		List<string> ids = new List<string>();
		AddJsonStringArray(root, "ids", ids);
		AddJsonStringArray(root, "sessionIds", ids);
		AddJsonStringArray(root, "sessions", ids);
		string id = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "sessionId");
		if (!string.IsNullOrWhiteSpace(id))
		{
			ids.Add(id);
		}
		return ids;
	}

	private static void AddJsonStringArray(JsonElement root, string propertyName, List<string> values)
	{
		if (values == null || root.ValueKind != JsonValueKind.Object || !root.TryGetProperty(propertyName, out var element) || element.ValueKind != JsonValueKind.Array)
		{
			return;
		}
		foreach (JsonElement item in element.EnumerateArray())
		{
			string value = ((item.ValueKind == JsonValueKind.String) ? item.GetString() : ((item.ValueKind == JsonValueKind.Object) ? (ExtractStringProperty(item, "id") ?? ExtractStringProperty(item, "sessionId")) : ""));
			if (!string.IsNullOrWhiteSpace(value))
			{
				values.Add(value);
			}
		}
	}

	private static string[] NormalizeChatSessionDeleteIds(IReadOnlyList<string> ids)
	{
		if (ids == null || ids.Count == 0)
		{
			return Array.Empty<string>();
		}
		return (from id in ids
			where !string.IsNullOrWhiteSpace(id)
			select id.Trim() into id
			where id.Length > 0
			select id).Distinct<string>(StringComparer.Ordinal).Take(1000).ToArray();
	}

	private int RemoveChatSessionCommentsForSessionsLocked(HashSet<string> deletedSessionIds)
	{
		if (deletedSessionIds == null || deletedSessionIds.Count == 0)
		{
			return 0;
		}
		int removed = 0;
		Table commentsTable = GetChatSessionCommentsTable();
		for (int i = commentsTable.Rows.Count - 1; i >= 0; i--)
		{
			object[] row = NormalizeChatSessionCommentRow(commentsTable.Rows[i]);
			commentsTable.Rows[i] = row;
			if (deletedSessionIds.Contains(GetRowValue(row, 1)))
			{
				commentsTable.Rows.RemoveAt(i);
				removed++;
			}
		}
		return removed;
	}

	private string HandleChatSessionRenameRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string id = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "sessionId");
			string title = NormalizeChatSessionTitleInput(ExtractStringProperty(root, "title") ?? ExtractStringProperty(root, "name"));
			if (string.IsNullOrWhiteSpace(id))
			{
				return BuildJsonError(request, 400, "Bad Request", "Session id is required.");
			}
			if (string.IsNullOrWhiteSpace(title))
			{
				return BuildJsonError(request, 400, "Bad Request", "Session title is required.");
			}
			string now = DateTimeOffset.UtcNow.ToString("O");
			int commentCount = 0;
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] row = NormalizeChatSessionRow(table.Rows[i]);
					table.Rows[i] = row;
					if (string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
					{
						if (!ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
						{
							return BuildJsonError(request, 404, "Not Found", "Session not found.");
						}
						row[1] = title;
						row[3] = now;
						row[11] = "true";
						ProtectChatSessionRowSensitiveValues(row);
						table.Rows[i] = row;
						SaveChatSessionDataAndInvalidateCaches();
						commentCount = CountChatSessionComments(id);
						return JsonSerializer.Serialize(new
						{
							ok = true,
							id = id,
							title = title,
							updatedUtc = now,
							ownerKey = ownerKey,
							titleLocked = true,
							savedUtc = GetRowValue(row, 12),
							locked = ParseStoredBool(GetRowValue(row, 13), fallback: false),
							lockedUtc = GetRowValue(row, 14),
							clonedFromSessionId = GetRowValue(row, 15),
							promptTokenCount = ParseStoredLong(GetRowValue(row, 16), 0L),
							promptTokenBudget = ParseStoredLong(GetRowValue(row, 17), 8192L),
							runtime = GetRowValue(row, 18),
							commentCount = commentCount
						});
					}
				}
			}
			return BuildJsonError(request, 404, "Not Found", "Session not found.");
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session rename failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleChatSessionActionRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string action = (ExtractStringProperty(root, "action") ?? "").Trim().ToLowerInvariant();
			string id = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "sessionId");
			if (string.IsNullOrWhiteSpace(action))
			{
				return BuildJsonError(request, 400, "Bad Request", "Session action is required.");
			}
			if (string.IsNullOrWhiteSpace(id))
			{
				return BuildJsonError(request, 400, "Bad Request", "Session id is required.");
			}
			string now = DateTimeOffset.UtcNow.ToString("O");
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				int index = -1;
				object[] row = null;
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] current = NormalizeChatSessionRow(table.Rows[i]);
					table.Rows[i] = current;
					if (string.Equals(GetRowValue(current, 0), id, StringComparison.Ordinal))
					{
						index = i;
						row = current;
						break;
					}
				}
				if (row == null || index < 0 || !ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
				{
					return BuildJsonError(request, 404, "Not Found", "Session not found.");
				}
				row = DecryptChatSessionRowForOwner(row, ownerKey);
				switch (action)
				{
				case "lock":
					row[13] = "true";
					row[14] = now;
					row[12] = (string.IsNullOrWhiteSpace(GetRowValue(row, 12)) ? now : GetRowValue(row, 12));
					RefreshChatSessionPromptMetrics(row);
					ProtectChatSessionRowSensitiveValues(row);
					table.Rows[index] = row;
					SaveChatSessionDataAndInvalidateCaches();
					return JsonSerializer.Serialize(new
					{
						ok = true,
						action = action,
						session = BuildChatSessionMetadataPayload(row)
					});
				case "unlock":
					row[13] = "false";
					row[14] = "";
					row[12] = (string.IsNullOrWhiteSpace(GetRowValue(row, 12)) ? now : GetRowValue(row, 12));
					RefreshChatSessionPromptMetrics(row);
					ProtectChatSessionRowSensitiveValues(row);
					table.Rows[index] = row;
					SaveChatSessionDataAndInvalidateCaches();
					return JsonSerializer.Serialize(new
					{
						ok = true,
						action = action,
						session = BuildChatSessionMetadataPayload(row)
					});
				default:
					if (!(action == "checkpoint"))
					{
						if (action == "clone" || action == "duplicate")
						{
							string cloneId = "sess_" + Guid.NewGuid().ToString("N");
							string requestedTitle = NormalizeChatSessionTitleInput(ExtractStringProperty(root, "title") ?? ExtractStringProperty(root, "name"));
							string sourceTitle = NormalizeChatSessionTitleInput(GetRowValue(row, 1));
							string cloneTitle = (string.IsNullOrWhiteSpace(requestedTitle) ? ("Copy of " + (string.IsNullOrWhiteSpace(sourceTitle) ? "New chat" : sourceTitle)) : requestedTitle);
							object[] clone = CreateChatSessionRow(cloneId, cloneTitle, now, now, GetRowValue(row, 4), GetRowValue(row, 5), GetRowValue(row, 6), ownerKey, GetRowValue(row, 8), "", shareEnabled: false, titleLocked: true, now, locked: false, "", GetRowValue(row, 0), ParseStoredLong(GetRowValue(row, 17), 8192L), GetRowValue(row, 18));
							if (!EnsureChatStorageCanAdd(ownerKey, cloneId, EstimateChatSessionRowStorageBytes(clone), out var usageSnapshot, out var storageError))
							{
								SetHttpStatus(request, 507, "Insufficient Storage");
								return JsonSerializer.Serialize(new
								{
									ok = false,
									error = storageError,
									usage = usageSnapshot
								});
							}
							table.Rows.Add(clone);
							SaveChatSessionDataAndInvalidateCaches();
							return JsonSerializer.Serialize(new
							{
								ok = true,
								action = "clone",
								sourceId = id,
								id = cloneId,
								session = BuildChatSessionMetadataPayload(clone)
							});
						}
						return BuildJsonError(request, 400, "Bad Request", "Unknown session action.");
					}
					goto case "save";
				case "save":
					row[12] = now;
					row[3] = now;
					RefreshChatSessionPromptMetrics(row);
					ProtectChatSessionRowSensitiveValues(row);
					table.Rows[index] = row;
					SaveChatSessionDataAndInvalidateCaches();
					return JsonSerializer.Serialize(new
					{
						ok = true,
						action = "save",
						session = BuildChatSessionMetadataPayload(row)
					});
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session action failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private object BuildChatSessionMetadataPayload(object[] row)
	{
		row = DecryptChatSessionRowForOwner(row);
		string sessionId = GetRowValue(row, 0);
		return new
		{
			id = sessionId,
			title = GetRowValue(row, 1),
			createdUtc = GetRowValue(row, 2),
			updatedUtc = GetRowValue(row, 3),
			model = GetRowValue(row, 4),
			messages = DeserializeJsonElement(GetRowValue(row, 5), "[]"),
			files = DeserializePublicChatSessionFilesElement(GetRowValue(row, 6), sessionId),
			ownerKey = GetRowValue(row, 7),
			draftPrompt = GetRowValue(row, 8),
			shareKey = GetRowValue(row, 9),
			shareEnabled = ParseStoredBool(GetRowValue(row, 10), fallback: false),
			titleLocked = ParseStoredBool(GetRowValue(row, 11), fallback: false),
			savedUtc = GetRowValue(row, 12),
			locked = ParseStoredBool(GetRowValue(row, 13), fallback: false),
			lockedUtc = GetRowValue(row, 14),
			clonedFromSessionId = GetRowValue(row, 15),
			promptTokenCount = ParseStoredLong(GetRowValue(row, 16), 0L),
			promptTokenBudget = ParseStoredLong(GetRowValue(row, 17), 8192L),
			runtime = GetRowValue(row, 18),
			commentCount = CountChatSessionComments(sessionId),
			compatibility = BuildChatSessionCompatibilityPayload(row, null, null, -1L, 0L)
		};
	}

	private void PersistChatUiAssistantCompletion(string ownerKey, string sessionId, string requestBody, string content, string reasoning)
	{
		content = content ?? "";
		reasoning = reasoning ?? "";
		ChatUiCompletion persistedCompletion = NormalizeChatUiCompletionForDisplay(new ChatUiCompletion
		{
			Content = content,
			Reasoning = reasoning
		}, requestBody);
		content = persistedCompletion?.Content ?? "";
		reasoning = ShouldSuppressChatUiReasoningForRequest(requestBody) ? "" : (persistedCompletion?.Reasoning ?? "");
		if (string.IsNullOrWhiteSpace(sessionId) || (string.IsNullOrEmpty(content) && string.IsNullOrEmpty(reasoning)))
		{
			return;
		}
		try
		{
			ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
			sessionId = EnsureChatUiSessionId(sessionId);
			string requestMessagesJson = ExtractChatUiJsonArrayProperty(requestBody, "messages", "[]");
			string requestFilesJson = ExtractChatUiJsonArrayProperty(requestBody, "files", "[]");
			requestFilesJson = NormalizeChatSessionFilesJsonForStorage(requestFilesJson, sessionId);
			string requestModel = ExtractChatUiStringProperty(requestBody, "model") ?? "";
			string now = DateTimeOffset.UtcNow.ToString("O");
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				int existingIndex = -1;
				object[] existing = null;
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] row = NormalizeChatSessionRow(table.Rows[i]);
					table.Rows[i] = row;
					if (string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
					{
						existingIndex = i;
						existing = row;
						break;
					}
				}
				if (existing != null && !ChatOwnerKeysMatch(ownerKey, GetRowValue(existing, 7)))
				{
					LogMessage("[Chat UI] Skipped background completion save for session " + sessionId + " because the owner changed.");
					return;
				}
				if (existing != null)
				{
					existing = DecryptChatSessionRowForOwner(existing, ownerKey);
				}
				if (existing != null && ParseStoredBool(GetRowValue(existing, 13), fallback: false))
				{
					LogMessage("[Chat UI] Skipped background completion save for locked session " + sessionId + ".");
					return;
				}
				string existingMessagesJson = ((existing == null) ? "[]" : GetRowValue(existing, 5));
				string baseMessagesJson = ((CountJsonArrayItems(existingMessagesJson) >= CountJsonArrayItems(requestMessagesJson)) ? existingMessagesJson : requestMessagesJson);
				string messagesJson = AppendAssistantCompletionMessageJson(baseMessagesJson, content, reasoning);
				if (existing != null && string.Equals(NormalizeJsonArrayRawText(existingMessagesJson), messagesJson, StringComparison.Ordinal))
				{
					return;
				}
				string title = ((existing != null && ParseStoredBool(GetRowValue(existing, 11), fallback: false)) ? GetRowValue(existing, 1) : InferChatSessionTitle(messagesJson));
				string model = ((string.IsNullOrWhiteSpace(requestModel) && existing != null) ? GetRowValue(existing, 4) : requestModel);
				long promptTokenBudget = ExtractPromptTokenBudgetFromRequestBody(requestBody, model);
				string runtime = InferChatSessionRuntime(model);
				ChatUsageSnapshot snapshot;
				if (existingIndex < 0)
				{
					object[] next = CreateChatSessionRow(sessionId, title, now, now, model, messagesJson, requestFilesJson, ownerKey, "", "", shareEnabled: false, titleLocked: false, now, locked: false, "", "", promptTokenBudget, runtime);
					if (!EnsureChatStorageCanAdd(ownerKey, sessionId, EstimateChatSessionRowStorageBytes(next), out snapshot, out var storageError))
					{
						LogMessage("[Chat UI] Background completion save skipped for session " + sessionId + ": " + storageError);
						return;
					}
					table.Rows.Add(next);
				}
				else
				{
					object[] next2 = (object[])existing.Clone();
					next2[1] = title;
					next2[3] = now;
					next2[4] = model;
					next2[5] = messagesJson;
					next2[6] = MergeChatSessionFilesJson(requestFilesJson, GetRowValue(existing, 6));
					next2[7] = ownerKey;
					next2[11] = GetRowValue(existing, 11);
					next2[12] = now;
					next2[13] = GetRowValue(existing, 13);
					next2[14] = GetRowValue(existing, 14);
					next2[15] = GetRowValue(existing, 15);
					next2[16] = EstimateChatSessionPromptTokens(messagesJson, GetRowValue(existing, 8)).ToString(CultureInfo.InvariantCulture);
					next2[17] = promptTokenBudget.ToString(CultureInfo.InvariantCulture);
					next2[18] = (string.IsNullOrWhiteSpace(runtime) ? GetRowValue(existing, 18) : runtime);
					long rowDelta = Math.Max(0L, EstimateChatSessionRowStorageBytes(next2) - EstimateChatSessionRowStorageBytes(existing));
					if (!EnsureChatStorageCanAdd(ownerKey, sessionId, rowDelta, out snapshot, out var storageError2))
					{
						LogMessage("[Chat UI] Background completion save skipped for session " + sessionId + ": " + storageError2);
						return;
					}
					ProtectChatSessionRowSensitiveValues(next2);
					table.Rows[existingIndex] = next2;
				}
				SaveChatSessionDataAndInvalidateCaches();
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Background completion save failed: " + ex.Message);
		}
	}

	private string AppendAssistantCompletionMessageJson(string messagesJson, string content, string reasoning)
	{
		messagesJson = NormalizeJsonArrayRawText(messagesJson);
		if (ChatMessagesEndWithAssistantCompletion(messagesJson, content, reasoning))
		{
			return messagesJson;
		}
		string assistantJson = JsonSerializer.Serialize(new
		{
			role = "assistant",
			content = (content ?? ""),
			reasoning = (reasoning ?? "")
		});
		if (messagesJson == "[]")
		{
			return "[" + assistantJson + "]";
		}
		return messagesJson.Substring(0, messagesJson.Length - 1) + "," + assistantJson + "]";
	}

	private bool ChatMessagesEndWithAssistantCompletion(string messagesJson, string content, string reasoning)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(NormalizeJsonArrayRawText(messagesJson));
			if (document.RootElement.ValueKind != JsonValueKind.Array || document.RootElement.GetArrayLength() == 0)
			{
				return false;
			}
			JsonElement last = document.RootElement[document.RootElement.GetArrayLength() - 1];
			if (last.ValueKind != JsonValueKind.Object)
			{
				return false;
			}
			string role = ExtractStringProperty(last, "role") ?? "";
			if (!role.Equals("assistant", StringComparison.OrdinalIgnoreCase))
			{
				return false;
			}
			string existingContent = ExtractStringProperty(last, "content") ?? "";
			string existingReasoning = ExtractStringProperty(last, "reasoning") ?? "";
			return string.Equals(existingContent, content ?? "", StringComparison.Ordinal) && string.Equals(existingReasoning, reasoning ?? "", StringComparison.Ordinal);
		}
		catch
		{
			return false;
		}
	}

	private string ExtractChatUiJsonArrayProperty(string requestBody, string propertyName, string fallback)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(requestBody) ? "{}" : requestBody);
			if (document.RootElement.ValueKind == JsonValueKind.Object && document.RootElement.TryGetProperty(propertyName, out var value) && value.ValueKind == JsonValueKind.Array)
			{
				return value.GetRawText();
			}
		}
		catch
		{
		}
		return NormalizeJsonArrayRawText(fallback);
	}

	private string ExtractChatUiStringProperty(string requestBody, string propertyName)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(requestBody) ? "{}" : requestBody);
			if (document.RootElement.ValueKind == JsonValueKind.Object)
			{
				return ExtractStringProperty(document.RootElement, propertyName);
			}
		}
		catch
		{
		}
		return null;
	}

	private string NormalizeJsonArrayRawText(string json)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "[]" : json);
			return (document.RootElement.ValueKind == JsonValueKind.Array) ? document.RootElement.GetRawText() : "[]";
		}
		catch
		{
			return "[]";
		}
	}

	private string NormalizeJsonObjectRawText(string json)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
			return (document.RootElement.ValueKind == JsonValueKind.Object) ? document.RootElement.GetRawText() : "{}";
		}
		catch
		{
			return "{}";
		}
	}

	private string HandleChatSessionShareGetRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string shareKey = (GetQueryParameter(request, "hashKey") ?? GetQueryParameter(request, "key") ?? GetQueryParameter(request, "shareKey") ?? "").Trim();
			if (string.IsNullOrWhiteSpace(shareKey))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Share key is required."
				});
			}
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				foreach (object[] sourceRow in table.Rows)
				{
					object[] row = NormalizeChatSessionRow(sourceRow);
					if (!ParseStoredBool(GetRowValue(row, 10), fallback: false) || !string.Equals(GetRowValue(row, 9), shareKey, StringComparison.Ordinal))
					{
						continue;
					}
					string sessionId = GetRowValue(row, 0);
					string ownerKey = GetRowValue(row, 7);
					bool canReadPrivate = CanReadChatSessionPrivateValues(row, ownerKey);
					object[] readableRow = canReadPrivate ? DecryptChatSessionRowForOwner(row, ownerKey) : row;
					ChatUsageSnapshot usage = GetChatUsageSnapshot(ownerKey, sessionId);
					string tokenWarning;
					bool canPrompt = CanStartSharedChatWithOwnerTokens(ownerKey, usage, out tokenWarning);
					return JsonSerializer.Serialize(new
					{
						ok = true,
						shared = true,
						session = new
						{
							id = sessionId,
							title = GetRowValue(readableRow, 1),
							createdUtc = GetRowValue(readableRow, 2),
							updatedUtc = GetRowValue(readableRow, 3),
							model = GetRowValue(readableRow, 4),
							messages = DeserializeJsonElement(canReadPrivate ? GetRowValue(readableRow, 5) : "[]", "[]"),
							files = DeserializeJsonElement("[]", "[]"),
							draftPrompt = "",
							shareKey = shareKey,
							hashKey = shareKey,
							shareEnabled = true,
							titleLocked = ParseStoredBool(GetRowValue(readableRow, 11), fallback: false),
							savedUtc = GetRowValue(readableRow, 12),
							locked = ParseStoredBool(GetRowValue(readableRow, 13), fallback: false),
							lockedUtc = GetRowValue(readableRow, 14),
							clonedFromSessionId = GetRowValue(readableRow, 15),
							promptTokenCount = ParseStoredLong(GetRowValue(readableRow, 16), 0L),
							promptTokenBudget = ParseStoredLong(GetRowValue(readableRow, 17), 8192L),
							runtime = GetRowValue(readableRow, 18),
							commentCount = CountChatSessionComments(sessionId),
							ownerKey = ownerKey,
							usage = usage,
							canPrompt = canPrompt,
							tokenWarning = tokenWarning
						}
					});
				}
			}
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = "Shared session not found or no longer public."
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Shared session load failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatSessionShareSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string id = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "sessionId");
			if (string.IsNullOrWhiteSpace(id))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Session id is required."
				});
			}
			JsonElement shareEnabledElement;
			JsonElement enabledElement;
			bool shareEnabled = (root.TryGetProperty("shareEnabled", out shareEnabledElement) ? ReadJsonBool(shareEnabledElement, fallback: false) : (root.TryGetProperty("enabled", out enabledElement) && ReadJsonBool(enabledElement, fallback: false)));
			JsonElement rotateElement;
			bool rotate = root.TryGetProperty("rotate", out rotateElement) && ReadJsonBool(rotateElement, fallback: false);
			if (!TryUpdateChatSessionShare(ownerKey, id, shareEnabled, rotate, out var shareKey, out var commentCount, out var updatedUtc, out var error))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = error
				});
			}
			ChatUsageSnapshot usage = GetChatUsageSnapshot(ownerKey, id);
			string tokenWarning;
			bool canPrompt = CanStartSharedChatWithOwnerTokens(ownerKey, usage, out tokenWarning);
			string shareUrl = BuildChatSessionShareUrl(request, root, shareKey);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				id = id,
				ownerKey = ownerKey,
				shareEnabled = shareEnabled,
				shareKey = shareKey,
				hashKey = shareKey,
				url = shareUrl,
				shareUrl = shareUrl,
				commentCount = commentCount,
				usage = usage,
				canPrompt = canPrompt,
				tokenWarning = tokenWarning,
				updatedUtc = updatedUtc
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session share update failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatSessionShareLinkCreateRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string id = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "sessionId");
			if (string.IsNullOrWhiteSpace(id))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Session id is required."
				});
			}
			JsonElement shareEnabledElement;
			JsonElement enabledElement;
			bool shareEnabled = (root.TryGetProperty("shareEnabled", out shareEnabledElement) ? ReadJsonBool(shareEnabledElement, fallback: true) : (!root.TryGetProperty("enabled", out enabledElement) || ReadJsonBool(enabledElement, fallback: true)));
			JsonElement rotateElement;
			bool rotate = root.TryGetProperty("rotate", out rotateElement) && ReadJsonBool(rotateElement, fallback: false);
			if (!TryUpdateChatSessionShare(ownerKey, id, shareEnabled, rotate, out var shareKey, out var commentCount, out var updatedUtc, out var error))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = error
				});
			}
			ChatUsageSnapshot usage = GetChatUsageSnapshot(ownerKey, id);
			string tokenWarning;
			bool canPrompt = CanStartSharedChatWithOwnerTokens(ownerKey, usage, out tokenWarning);
			string shareUrl = BuildChatSessionShareUrl(request, root, shareKey);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				id = id,
				ownerKey = ownerKey,
				shareEnabled = shareEnabled,
				shareKey = shareKey,
				hashKey = shareKey,
				url = shareUrl,
				shareUrl = shareUrl,
				commentCount = commentCount,
				usage = usage,
				canPrompt = canPrompt,
				tokenWarning = tokenWarning,
				updatedUtc = updatedUtc
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session share link create failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private bool TryUpdateChatSessionShare(string ownerKey, string id, bool shareEnabled, bool rotate, out string shareKey, out int commentCount, out string updatedUtc, out string error)
	{
		shareKey = "";
		commentCount = 0;
		updatedUtc = DateTimeOffset.UtcNow.ToString("O");
		error = "";
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				object[] row = NormalizeChatSessionRow(table.Rows[i]);
				table.Rows[i] = row;
				if (string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal))
				{
					if (!ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
					{
						error = "Session belongs to another client.";
						return false;
					}
					shareKey = GetRowValue(row, 9);
					if (shareEnabled && (rotate || string.IsNullOrWhiteSpace(shareKey)))
					{
						shareKey = GenerateChatShareKey();
					}
					row[3] = updatedUtc;
					row[9] = shareKey;
					row[10] = (shareEnabled ? "true" : "false");
					table.Rows[i] = row;
					SaveChatSessionDataAndInvalidateCaches();
					commentCount = CountChatSessionComments(id);
					return true;
				}
			}
		}
		error = "Session not found.";
		return false;
	}

	private string HandleChatSessionShareMessageSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string sessionId = ExtractStringProperty(root, "sessionId") ?? ExtractStringProperty(root, "id");
			string shareKey = ExtractStringProperty(root, "hashKey") ?? ExtractStringProperty(root, "shareKey") ?? ExtractStringProperty(root, "key");
			string model = ExtractStringProperty(root, "model") ?? "";
			if (string.IsNullOrWhiteSpace(sessionId))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Session id is required."
				});
			}
			if (string.IsNullOrWhiteSpace(shareKey))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Share key is required."
				});
			}
			if (!root.TryGetProperty("messages", out var incomingMessages) || incomingMessages.ValueKind != JsonValueKind.Array)
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Messages are required."
				});
			}
			sessionId = SanitizeFileName(sessionId.Trim());
			string now = DateTimeOffset.UtcNow.ToString("O");
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				for (int i = 0; i < table.Rows.Count; i++)
				{
					object[] row = NormalizeChatSessionRow(table.Rows[i]);
					table.Rows[i] = row;
					if (string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
					{
						if (!ParseStoredBool(GetRowValue(row, 10), fallback: false) || !string.Equals(GetRowValue(row, 9), shareKey.Trim(), StringComparison.Ordinal))
						{
							return JsonSerializer.Serialize(new
							{
								ok = false,
								error = "Shared session not found or no longer public."
							});
						}
						if (ParseStoredBool(GetRowValue(row, 13), fallback: false))
						{
							return BuildJsonError(request, 423, "Locked", "Session is locked.");
						}
						if (!CanReadChatSessionPrivateValues(row, GetRowValue(row, 7)))
						{
							return BuildJsonError(request, 423, "Locked", "Shared session content is encrypted and cannot be modified without the user's session secret.");
						}
						row = DecryptChatSessionRowForOwner(row, GetRowValue(row, 7));
						int appendedCount;
						string mergedMessagesJson = AppendPublicSharedChatMessagesJson(GetRowValue(row, 5), incomingMessages, out appendedCount);
						if (appendedCount == 0)
						{
							return JsonSerializer.Serialize(new
							{
								ok = false,
								error = "No valid public chat messages were provided."
							});
						}
						if (mergedMessagesJson.Length > 512000)
						{
							return JsonSerializer.Serialize(new
							{
								ok = false,
								error = "Shared session message history is too large."
							});
						}
						row[3] = now;
						if (!string.IsNullOrWhiteSpace(model))
						{
							row[4] = model;
						}
						row[5] = mergedMessagesJson;
						RefreshChatSessionPromptMetrics(row);
						ProtectChatSessionRowSensitiveValues(row);
						table.Rows[i] = row;
						SaveChatSessionDataAndInvalidateCaches();
						return JsonSerializer.Serialize(new
						{
							ok = true,
							id = sessionId,
							shareKey = shareKey,
							appendedCount = appendedCount,
							updatedUtc = now,
							session = new
							{
								id = sessionId,
								title = GetRowValue(row, 1),
								createdUtc = GetRowValue(row, 2),
								updatedUtc = GetRowValue(row, 3),
								model = GetRowValue(row, 4),
								messages = DeserializeJsonElement(DecryptChatSessionRowForOwner(row, GetRowValue(row, 7))[5]?.ToString() ?? "[]", "[]"),
								files = DeserializeJsonElement("[]", "[]"),
								draftPrompt = "",
								shareKey = GetRowValue(row, 9),
								shareEnabled = true,
								titleLocked = ParseStoredBool(GetRowValue(row, 11), fallback: false),
								savedUtc = GetRowValue(row, 12),
								locked = ParseStoredBool(GetRowValue(row, 13), fallback: false),
								lockedUtc = GetRowValue(row, 14),
								clonedFromSessionId = GetRowValue(row, 15),
								promptTokenCount = ParseStoredLong(GetRowValue(row, 16), 0L),
								promptTokenBudget = ParseStoredLong(GetRowValue(row, 17), 8192L),
								runtime = GetRowValue(row, 18),
								commentCount = CountChatSessionComments(sessionId)
							}
						});
					}
				}
			}
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = "Shared session not found or no longer public."
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Shared session message save failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatSessionCommentsGetRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string sessionId = GetQueryParameter(request, "sessionId") ?? GetQueryParameter(request, "id");
			string shareKey = GetQueryParameter(request, "hashKey") ?? GetQueryParameter(request, "shareKey") ?? GetQueryParameter(request, "key");
			if (string.IsNullOrWhiteSpace(sessionId))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Session id is required."
				});
			}
			if (!CanAccessChatSessionComments(ownerKey, sessionId, shareKey, out var ownerAccess, out var sharedAccess))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Comments are unavailable for this session."
				});
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				sessionId = sessionId,
				ownerAccess = ownerAccess,
				sharedAccess = sharedAccess,
				comments = GetChatSessionComments(sessionId)
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session comments load failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private string HandleChatSessionCommentSaveRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string body = request?.Body ?? "{}";
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
			JsonElement root = document.RootElement;
			string sessionId = ExtractStringProperty(root, "sessionId") ?? ExtractStringProperty(root, "id");
			string shareKey = ExtractStringProperty(root, "hashKey") ?? ExtractStringProperty(root, "shareKey") ?? ExtractStringProperty(root, "key");
			string text = (ExtractStringProperty(root, "body") ?? ExtractStringProperty(root, "comment") ?? "").Trim();
			if (string.IsNullOrWhiteSpace(sessionId))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Session id is required."
				});
			}
			if (string.IsNullOrWhiteSpace(text))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Comment text is required."
				});
			}
			if (text.Length > 4000)
			{
				text = text.Substring(0, 4000);
			}
			if (!CanAccessChatSessionComments(ownerKey, sessionId, shareKey, out var ownerAccess, out var sharedAccess))
			{
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = "Comments are unavailable for this session."
				});
			}
			if (!TryGetChatCommentIdentity(connection, request, out var authorKey, out var displayName, out var identityError))
			{
				SetHttpStatus(request, 403, "Forbidden");
				return JsonSerializer.Serialize(new
				{
					ok = false,
					error = identityError
				});
			}
			ChatSessionComment comment = new ChatSessionComment
			{
				id = "comment_" + Guid.NewGuid().ToString("N"),
				sessionId = SanitizeFileName(sessionId),
				ownerKey = GetChatSessionOwnerForComments(sessionId),
				authorKey = (authorKey ?? ""),
				authorName = displayName,
				body = text,
				createdUtc = DateTimeOffset.UtcNow.ToString("O")
			};
			lock (_chatSessionLock)
			{
				GetChatSessionCommentsTable().Rows.Add(ChatSessionCommentToRow(comment));
				SaveChatSessionDataAndInvalidateCaches();
			}
			return JsonSerializer.Serialize(new
			{
				ok = true,
				sessionId = sessionId,
				comment = comment,
				comments = GetChatSessionComments(sessionId),
				ownerAccess = ownerAccess,
				sharedAccess = sharedAccess
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Session comment save failed: " + ex.Message);
			return JsonSerializer.Serialize(new
			{
				ok = false,
				error = ex.Message
			});
		}
	}

	private object HandleChatBrowserProxyOptionsRequest(NetworkConnection connection, HttpRequest request)
	{
		if (!IsTrustedBrowserProxyOrigin(connection, request))
		{
			return BuildJsonError(request, 403, "Forbidden", "Browser proxy requests are only accepted from the JackLLM console origin.");
		}
		SetHttpStatus(request, 204, "No Content");
		AddChatBrowserProxyHeaders(request, "");
		if (request?.Context?.Response != null)
		{
			request.Context.Response.ContentType = "text/plain";
		}
		return "";
	}

	private object HandleChatBrowserProxyRequest(NetworkConnection connection, HttpRequest request, CancellationToken cancellationToken)
	{
		try
		{
			if (!IsTrustedBrowserProxyOrigin(connection, request))
			{
				return BuildJsonError(request, 403, "Forbidden", "Browser proxy requests are only accepted from the JackLLM console origin.");
			}
			AddChatBrowserProxyHeaders(request, "");
			string rawUrl = (GetQueryParameter(request, "url") ?? "").Trim();
			if (string.IsNullOrWhiteSpace(rawUrl))
			{
				return BuildJsonError(request, 400, "Bad Request", "Browser proxy requires a url query value.");
			}
			string browserCookie = GetQueryParameter(request, "__jack_browser_proxy_cookie");
			bool isCookieSyncRequest = !string.IsNullOrWhiteSpace(browserCookie);
			if (!isCookieSyncRequest)
			{
				rawUrl = MergeChatBrowserProxyOuterQueryIntoTarget(rawUrl, request);
			}
			rawUrl = SanitizeBrowserSkillUrlArgument(rawUrl);
			if (!Uri.TryCreate(rawUrl, UriKind.Absolute, out Uri targetUri) || (!targetUri.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) && !targetUri.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)))
			{
				return BuildJsonError(request, 400, "Bad Request", "Browser proxy can only open absolute HTTP or HTTPS URLs.");
			}
			if (IsChatBrowserProxyUrlBlocked(targetUri, out var blockedReason))
			{
				return BuildChatBrowserProxyBlockedResponse(request, targetUri, blockedReason);
			}
			if (!TryValidateBrowserDestination(targetUri, BrowserPrivateNetworkAccessEnabled, out var destinationReason))
			{
				return BuildChatBrowserProxyBlockedResponse(request, targetUri, destinationReason);
			}
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			string rawSessionId = GetChatBrowserProxySessionId(request);
			bool hasExplicitBrowserSession = !string.IsNullOrWhiteSpace(rawSessionId);
			ChatBrowserClientSession browserSession = hasExplicitBrowserSession
				? GetOrCreateChatBrowserClientSession(ownerKey, EnsureChatUiSessionId(rawSessionId))
				: CreateTransientChatBrowserClientSession();
			if (isCookieSyncRequest)
			{
				StoreChatBrowserProxyCookieString(browserSession.Cookies, targetUri, browserCookie);
				SetHttpStatus(request, 204, "No Content");
				AddChatBrowserProxyHeaders(request, targetUri.AbsoluteUri);
				if (!hasExplicitBrowserSession)
				{
					browserSession.Dispose();
				}
				return "";
			}
			try
			{
				ImportChatBrowserProxyClientCookies(browserSession.Cookies, request, targetUri);
				string publicProxyRoute = BuildChatBrowserProxyRouteForRequest(request);
				using HttpRequestMessage upstreamRequest = BuildChatBrowserProxyUpstreamRequest(request, targetUri);
				using HttpResponseMessage upstream = browserSession.ProxyClient.SendAsync(upstreamRequest, HttpCompletionOption.ResponseHeadersRead, cancellationToken).GetAwaiter().GetResult();
				Uri finalUri = upstream.RequestMessage?.RequestUri ?? targetUri;
				if (IsChatBrowserProxyRedirect(upstream.StatusCode) && upstream.Headers.Location != null)
				{
					return BuildChatBrowserProxyRedirectResponse(request, finalUri, upstream.Headers.Location, publicProxyRoute, upstream.StatusCode, upstream.ReasonPhrase);
				}
				string contentType = upstream.Content?.Headers?.ContentType?.ToString() ?? "application/octet-stream";
				byte[] bytes = ReadChatBrowserProxyContent(upstream, cancellationToken);
				SetHttpStatus(request, (int)upstream.StatusCode, string.IsNullOrWhiteSpace(upstream.ReasonPhrase) ? upstream.StatusCode.ToString() : upstream.ReasonPhrase);
				AddChatBrowserProxyHeaders(request, finalUri.AbsoluteUri);
				AddChatBrowserProxyRefreshHeader(request, upstream, finalUri, publicProxyRoute);
				if (IsChatBrowserProxyHtml(contentType, finalUri))
				{
					string html = DecodeChatBrowserProxyText(bytes, upstream.Content?.Headers?.ContentType?.CharSet);
					string rewritten = RewriteChatBrowserProxyHtml(html, finalUri, publicProxyRoute);
					bytes = Encoding.UTF8.GetBytes(rewritten);
					contentType = BuildChatBrowserProxyUtf8ContentType(contentType, "text/html");
				}
				else if (IsChatBrowserProxyCss(contentType, finalUri))
				{
					string css = DecodeChatBrowserProxyText(bytes, upstream.Content?.Headers?.ContentType?.CharSet);
					string rewritten2 = RewriteChatBrowserProxyCss(css, finalUri, publicProxyRoute);
					bytes = Encoding.UTF8.GetBytes(rewritten2);
					contentType = BuildChatBrowserProxyUtf8ContentType(contentType, "text/css");
				}
				else if (IsChatBrowserProxyJavaScript(contentType, finalUri))
				{
					contentType = string.IsNullOrWhiteSpace(contentType) ? "application/javascript" : contentType;
				}
				else if (IsChatBrowserProxySvg(contentType, finalUri))
				{
					string svg = DecodeChatBrowserProxyText(bytes, upstream.Content?.Headers?.ContentType?.CharSet);
					string rewritten4 = RewriteChatBrowserProxyHtml(svg, finalUri, publicProxyRoute);
					bytes = Encoding.UTF8.GetBytes(rewritten4);
					contentType = BuildChatBrowserProxyUtf8ContentType(contentType, "image/svg+xml");
				}
				return new FileResponse(bytes, contentType);
			}
			finally
			{
				if (!hasExplicitBrowserSession)
				{
					browserSession.Dispose();
				}
			}
		}
		catch (TaskCanceledException)
		{
			return BuildJsonError(request, 504, "Gateway Timeout", "Browser proxy request timed out.");
		}
		catch (Exception ex2)
		{
			LogMessage("[Browser Proxy] Request failed: " + ex2.Message);
			return BuildJsonError(request, 502, "Bad Gateway", ex2.Message);
		}
	}

	private object BuildChatBrowserProxyRedirectResponse(HttpRequest request, Uri currentUri, Uri location, string publicProxyRoute, HttpStatusCode statusCode, string reasonPhrase)
	{
		Uri redirectUri = ResolveChatBrowserProxyRedirectUri(currentUri, location);
		if (redirectUri == null)
		{
			return BuildJsonError(request, 502, "Bad Gateway", "Browser proxy received an invalid redirect location.");
		}
		if (IsChatBrowserProxyUrlBlocked(redirectUri, out var blockedReason))
		{
			return BuildChatBrowserProxyBlockedResponse(request, redirectUri, blockedReason);
		}
		if (!TryValidateBrowserDestination(redirectUri, BrowserPrivateNetworkAccessEnabled, out var destinationReason))
		{
			return BuildChatBrowserProxyBlockedResponse(request, redirectUri, destinationReason);
		}
		string proxiedLocation = BuildChatBrowserProxyClientUrl(redirectUri.AbsoluteUri, currentUri, publicProxyRoute);
		SetHttpStatus(request, (int)statusCode, string.IsNullOrWhiteSpace(reasonPhrase) ? statusCode.ToString() : reasonPhrase);
		AddChatBrowserProxyHeaders(request, redirectUri.AbsoluteUri);
		SetResponseHeader(request, "Location", proxiedLocation);
		string safeTarget = WebUtility.HtmlEncode(redirectUri.AbsoluteUri);
		string safeLocation = WebUtility.HtmlEncode(proxiedLocation);
		string html = "<!doctype html><html><head><meta charset=\"utf-8\"><meta http-equiv=\"refresh\" content=\"0;url=" + safeLocation + "\"><title>Redirecting</title></head><body><p>Redirecting through JackLLM Browser to <a href=\"" + safeLocation + "\">" + safeTarget + "</a>.</p></body></html>";
		return new FileResponse(Encoding.UTF8.GetBytes(html), "text/html; charset=utf-8");
	}

	private static Uri ResolveChatBrowserProxyRedirectUri(Uri currentUri, Uri location)
	{
		if (location == null)
		{
			return null;
		}
		if (location.IsAbsoluteUri)
		{
			return location;
		}
		if (currentUri == null)
		{
			return null;
		}
		try
		{
			return new Uri(currentUri, location);
		}
		catch
		{
			return null;
		}
	}

	private static bool IsChatBrowserProxyRedirect(HttpStatusCode statusCode)
	{
		return statusCode == HttpStatusCode.MovedPermanently || statusCode == HttpStatusCode.Found || statusCode == HttpStatusCode.SeeOther || statusCode == HttpStatusCode.TemporaryRedirect || statusCode == HttpStatusCode.PermanentRedirect;
	}

	private object BuildChatBrowserProxyBlockedResponse(HttpRequest request, Uri targetUri, string reason)
	{
		SetHttpStatus(request, 403, "Forbidden");
		AddChatBrowserProxyHeaders(request, targetUri?.AbsoluteUri ?? "");
		SetResponseHeader(request, "X-Jack-Browser-Proxy-Blocked", "true");
		string safeUrl = WebUtility.HtmlEncode(targetUri?.AbsoluteUri ?? "");
		string safeReason = WebUtility.HtmlEncode(string.IsNullOrWhiteSpace(reason) ? "This URL is blocked by the JackLLM Browser blacklist." : reason);
		string html = "<!doctype html><html><head><meta charset=\"utf-8\"><title>Blocked by JackLLM Browser</title><style>body{font-family:Segoe UI,Arial,sans-serif;margin:40px;background:#111827;color:#f9fafb;}main{max-width:760px;}code{word-break:break-all;color:#bfdbfe;}p{line-height:1.5;color:#d1d5db;}</style></head><body><main><h1>Blocked by JackLLM Browser</h1><p>" + safeReason + "</p><p><code>" + safeUrl + "</code></p></main></body></html>";
		return new FileResponse(Encoding.UTF8.GetBytes(html), "text/html; charset=utf-8");
	}

	private HttpRequestMessage BuildChatBrowserProxyUpstreamRequest(HttpRequest request, Uri targetUri)
	{
		string methodName = (string.IsNullOrWhiteSpace(request?.Method) ? "GET" : request.Method.Trim().ToUpperInvariant());
		HttpRequestMessage upstreamRequest = new HttpRequestMessage(new HttpMethod(methodName), targetUri);
		string accept = GetChatBrowserProxyRequestHeader(request, "Accept");
		upstreamRequest.Headers.TryAddWithoutValidation("Accept", string.IsNullOrWhiteSpace(accept) ? BrowserLikeAccept : accept);
		string acceptLanguage = GetChatBrowserProxyRequestHeader(request, "Accept-Language");
		upstreamRequest.Headers.TryAddWithoutValidation("Accept-Language", string.IsNullOrWhiteSpace(acceptLanguage) ? "en-US,en;q=0.9" : acceptLanguage);
		upstreamRequest.Headers.TryAddWithoutValidation("Accept-Encoding", "gzip, deflate");
		string range = GetChatBrowserProxyRequestHeader(request, "Range");
		if (!string.IsNullOrWhiteSpace(range))
		{
			upstreamRequest.Headers.TryAddWithoutValidation("Range", range);
		}
		string userAgent = GetChatBrowserProxyRequestHeader(request, "User-Agent");
		upstreamRequest.Headers.TryAddWithoutValidation("User-Agent", string.IsNullOrWhiteSpace(userAgent) ? BrowserLikeUserAgent : userAgent);
		upstreamRequest.Headers.TryAddWithoutValidation("Sec-CH-UA", "\"Chromium\";v=\"125\", \"Google Chrome\";v=\"125\", \"Not.A/Brand\";v=\"24\"");
		upstreamRequest.Headers.TryAddWithoutValidation("Sec-CH-UA-Mobile", "?0");
		upstreamRequest.Headers.TryAddWithoutValidation("Sec-CH-UA-Platform", "\"Windows\"");
		upstreamRequest.Headers.TryAddWithoutValidation("Referer", BuildChatBrowserProxyUpstreamReferer(request, targetUri));
		string origin = GetChatBrowserProxyRequestHeader(request, "Origin");
		if (!string.IsNullOrWhiteSpace(origin))
		{
			upstreamRequest.Headers.TryAddWithoutValidation("Origin", targetUri.GetLeftPart(UriPartial.Authority));
		}
		string[] array = new string[6] { "DNT", "Sec-Fetch-Dest", "Sec-Fetch-Mode", "Sec-Fetch-Site", "Sec-Fetch-User", "Upgrade-Insecure-Requests" };
		foreach (string headerName in array)
		{
			string headerValue = GetChatBrowserProxyRequestHeader(request, headerName);
			if (!string.IsNullOrWhiteSpace(headerValue))
			{
				upstreamRequest.Headers.TryAddWithoutValidation(headerName, headerValue);
			}
		}
		if (!methodName.Equals("GET", StringComparison.OrdinalIgnoreCase) && !methodName.Equals("HEAD", StringComparison.OrdinalIgnoreCase))
		{
			byte[] bodyBytes = request?.BodyBytes;
			if ((bodyBytes == null || bodyBytes.Length == 0) && !string.IsNullOrEmpty(request?.Body))
			{
				bodyBytes = Encoding.UTF8.GetBytes(request.Body);
			}
			upstreamRequest.Content = new ByteArrayContent(bodyBytes ?? Array.Empty<byte>());
			string contentType = GetChatBrowserProxyRequestHeader(request, "Content-Type");
			if (!string.IsNullOrWhiteSpace(contentType))
			{
				upstreamRequest.Content.Headers.TryAddWithoutValidation("Content-Type", contentType);
			}
		}
		return upstreamRequest;
	}

	private string BuildChatBrowserProxyUpstreamReferer(HttpRequest request, Uri targetUri)
	{
		string fallback = targetUri.GetLeftPart(UriPartial.Authority) + "/";
		string referer = GetChatBrowserProxyRequestHeader(request, "Referer");
		if (string.IsNullOrWhiteSpace(referer))
		{
			return fallback;
		}
		if (TryExtractChatBrowserProxyTarget(referer, BuildChatBrowserProxyRouteForRequest(request), out var proxiedTarget, out var _) && Uri.TryCreate(proxiedTarget, UriKind.Absolute, out Uri proxiedReferer) && (proxiedReferer.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) || proxiedReferer.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)))
		{
			return proxiedReferer.AbsoluteUri;
		}
		if (Uri.TryCreate(referer, UriKind.Absolute, out Uri directReferer) && (directReferer.Scheme.Equals(Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) || directReferer.Scheme.Equals(Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)) && !IsChatBrowserProxyLocalHost(directReferer.Host))
		{
			return directReferer.AbsoluteUri;
		}
		return fallback;
	}

	private string MergeChatBrowserProxyOuterQueryIntoTarget(string rawUrl, HttpRequest request)
	{
		if (string.IsNullOrWhiteSpace(rawUrl) || request == null || !string.Equals(request.Method, "GET", StringComparison.OrdinalIgnoreCase) || string.IsNullOrWhiteSpace(request.QueryString))
		{
			return rawUrl;
		}
		List<string> passthrough = new List<string>();
		string[] array = request.QueryString.Split('&');
		foreach (string part in array)
		{
			if (!string.IsNullOrWhiteSpace(part))
			{
				int equals = part.IndexOf('=');
				string key = ((equals >= 0) ? part.Substring(0, equals) : part);
				string decodedKey;
				try
				{
					decodedKey = WebUtility.UrlDecode(key.Replace("+", " "));
				}
				catch
				{
					decodedKey = key;
				}
				if (!decodedKey.Equals("url", StringComparison.OrdinalIgnoreCase) && !decodedKey.Equals("__jack_browser_proxy_cookie", StringComparison.OrdinalIgnoreCase) && !decodedKey.Equals("sessionId", StringComparison.OrdinalIgnoreCase))
				{
					passthrough.Add(part);
				}
			}
		}
		if (passthrough.Count == 0)
		{
			return rawUrl;
		}
		if (!Uri.TryCreate(rawUrl, UriKind.Absolute, out Uri uri))
		{
			return rawUrl;
		}
		UriBuilder builder = new UriBuilder(uri);
		string existing = builder.Query;
		if (!string.IsNullOrWhiteSpace(existing))
		{
			existing = existing.TrimStart('?') + "&";
		}
		builder.Query = existing + string.Join("&", passthrough);
		return builder.Uri.AbsoluteUri;
	}

	private string GetChatBrowserProxyRequestHeader(HttpRequest request, string name)
	{
		if (request?.Headers != null && request.Headers.TryGetValue(name, out var value) && !string.IsNullOrWhiteSpace(value))
		{
			return value;
		}
		return "";
	}

	private string GetChatBrowserProxySessionId(HttpRequest request)
	{
		string sessionId = (GetQueryParameter(request, "sessionId") ?? "").Trim();
		if (!string.IsNullOrWhiteSpace(sessionId))
		{
			return sessionId;
		}
		string[] headerNames = new string[2] { "Referer", "Origin" };
		foreach (string headerName in headerNames)
		{
			string header = GetChatBrowserProxyRequestHeader(request, headerName);
			if (string.IsNullOrWhiteSpace(header))
			{
				continue;
			}
			try
			{
				Uri uri = new Uri(header, UriKind.Absolute);
				string query = uri.Query.TrimStart('?');
				foreach (string part in query.Split('&'))
				{
					int equals = part.IndexOf('=');
					string key = equals >= 0 ? part.Substring(0, equals) : part;
					if (string.Equals(WebUtility.UrlDecode(key.Replace("+", " ")), "sessionId", StringComparison.OrdinalIgnoreCase))
					{
						string value = equals >= 0 ? part.Substring(equals + 1) : "";
						return WebUtility.UrlDecode(value.Replace("+", " ")).Trim();
					}
				}
			}
			catch
			{
			}
		}
		return "";
	}

	private byte[] ReadChatBrowserProxyContent(HttpResponseMessage upstream, CancellationToken cancellationToken)
	{
		long? length = upstream.Content?.Headers?.ContentLength;
		if (length.HasValue && length.Value > 52428800)
		{
			throw new InvalidOperationException("Browser proxy response exceeded the " + 50.ToString(CultureInfo.InvariantCulture) + " MB limit.");
		}
		byte[] bytes = ((upstream.Content == null) ? Array.Empty<byte>() : upstream.Content.ReadAsByteArrayAsync().GetAwaiter().GetResult());
		if (bytes.Length > 52428800)
		{
			throw new InvalidOperationException("Browser proxy response exceeded the " + 50.ToString(CultureInfo.InvariantCulture) + " MB limit.");
		}
		cancellationToken.ThrowIfCancellationRequested();
		return bytes;
	}

	private void AddChatBrowserProxyHeaders(HttpRequest request, string targetUrl)
	{
		SetResponseHeader(request, "Cache-Control", "no-store, max-age=0");
		SetResponseHeader(request, "Pragma", "no-cache");
		SetResponseHeader(request, "X-Content-Type-Options", "nosniff");
		string origin = GetChatBrowserProxyRequestHeader(request, "Origin");
		if (!string.IsNullOrWhiteSpace(origin))
		{
			SetResponseHeader(request, "Access-Control-Allow-Origin", origin);
			SetResponseHeader(request, "Vary", "Origin");
		}
		SetResponseHeader(request, "Access-Control-Allow-Methods", "GET, POST, PUT, PATCH, DELETE, HEAD, OPTIONS");
		SetResponseHeader(request, "Access-Control-Allow-Headers", "Content-Type, Accept, Range, X-Requested-With");
		if (!string.IsNullOrWhiteSpace(targetUrl))
		{
			SetResponseHeader(request, "X-Jack-Browser-Proxy-Url", targetUrl);
		}
	}

	private void AddChatBrowserProxyRefreshHeader(HttpRequest request, HttpResponseMessage upstream, Uri finalUri, string publicProxyRoute)
	{
		if (upstream?.Headers != null && upstream.Headers.TryGetValues("Refresh", out var values))
		{
			string refresh = values.FirstOrDefault();
			if (!string.IsNullOrWhiteSpace(refresh))
			{
				SetResponseHeader(request, "Refresh", RewriteChatBrowserProxyMetaRefresh(refresh, finalUri, publicProxyRoute));
			}
		}
	}

	private void ImportChatBrowserProxyClientCookies(CookieContainer cookieContainer, HttpRequest request, Uri targetUri)
	{
		string cookieHeader = GetChatBrowserProxyRequestHeader(request, "Cookie");
		if (string.IsNullOrWhiteSpace(cookieHeader) || targetUri == null || cookieContainer == null)
		{
			return;
		}
		string[] array = cookieHeader.Split(';');
		foreach (string part in array)
		{
			string cookie = part.Trim();
			if (string.IsNullOrWhiteSpace(cookie))
			{
				continue;
			}
			int equals = cookie.IndexOf('=');
			if (equals <= 0)
			{
				continue;
			}
			string name = cookie.Substring(0, equals).Trim();
			string value = cookie.Substring(equals + 1).Trim();
			if (ShouldSkipChatBrowserProxyClientCookie(name))
			{
				continue;
			}
			try
			{
				lock (cookieContainer)
				{
					cookieContainer.Add(targetUri, new Cookie(name, value, "/"));
				}
			}
			catch
			{
			}
		}
	}

	private void StoreChatBrowserProxyCookieString(CookieContainer cookieContainer, Uri targetUri, string cookieValue)
	{
		if (targetUri == null || string.IsNullOrWhiteSpace(cookieValue) || cookieContainer == null)
		{
			return;
		}
		try
		{
			lock (cookieContainer)
			{
				cookieContainer.SetCookies(targetUri, cookieValue);
			}
		}
		catch
		{
			int equals = cookieValue.IndexOf('=');
			if (equals <= 0)
			{
				return;
			}
			string name = cookieValue.Substring(0, equals).Trim();
			string value = cookieValue.Substring(equals + 1).Split(';')[0].Trim();
			if (ShouldSkipChatBrowserProxyClientCookie(name))
			{
				return;
			}
			try
			{
				lock (cookieContainer)
				{
					cookieContainer.Add(targetUri, new Cookie(name, value, "/"));
				}
			}
			catch
			{
			}
		}
	}

	private static bool ShouldSkipChatBrowserProxyClientCookie(string name)
	{
		if (string.IsNullOrWhiteSpace(name))
		{
			return true;
		}
		name = name.Trim();
		return name.Equals("LmVsProxyAuth", StringComparison.OrdinalIgnoreCase) || name.Equals("SocketJackAuth", StringComparison.OrdinalIgnoreCase) || name.IndexOfAny(new char[5] { '\r', '\n', ';', ',', ' ' }) >= 0;
	}

	private bool IsTrustedBrowserProxyOrigin(NetworkConnection connection, HttpRequest request)
	{
		string origin = GetChatBrowserProxyRequestHeader(request, "Origin").Trim();
		if (string.IsNullOrWhiteSpace(origin))
		{
			return true;
		}
		// A loopback Workstation proxy is the network stack for its embedded browser,
		// so remote pages must be able to issue their own same-site and cross-site
		// requests through it. Destination validation below remains the SSRF boundary.
		if (IsLocalAdmin(connection, request))
		{
			return true;
		}
		if (origin.Equals("null", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		if (!Uri.TryCreate(origin, UriKind.Absolute, out Uri originUri) ||
			(originUri.Scheme != Uri.UriSchemeHttp && originUri.Scheme != Uri.UriSchemeHttps))
		{
			return false;
		}
		string requestHost = (request?.Host ?? "").Trim();
		if (!string.IsNullOrWhiteSpace(requestHost) && originUri.Authority.Equals(requestHost, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		if (IsChatBrowserProxyLocalHost(originUri.Host))
		{
			return false;
		}
		return originUri.Scheme == Uri.UriSchemeHttps &&
			(originUri.Host.Equals("socketjack.com", StringComparison.OrdinalIgnoreCase) || originUri.Host.EndsWith(".socketjack.com", StringComparison.OrdinalIgnoreCase));
	}

	internal static bool TryValidateBrowserDestination(Uri uri, bool allowPrivateNetwork, out string reason)
	{
		reason = "";
		if (uri == null || !uri.IsAbsoluteUri || (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps) || string.IsNullOrWhiteSpace(uri.Host))
		{
			reason = "Only absolute HTTP and HTTPS destinations are allowed.";
			return false;
		}
		if (!string.IsNullOrEmpty(uri.UserInfo))
		{
			reason = "URLs containing embedded credentials are blocked.";
			return false;
		}
		if (allowPrivateNetwork)
		{
			return true;
		}
		try
		{
			IPAddress[] addresses = IPAddress.TryParse(uri.Host, out IPAddress literal)
				? new[] { literal }
				: Dns.GetHostAddresses(uri.IdnHost);
			if (addresses.Length == 0)
			{
				reason = "The destination host did not resolve to an address.";
				return false;
			}
			foreach (IPAddress address in addresses)
			{
				if (IsPrivateOrSpecialPurposeAddress(address))
				{
					reason = "Private, loopback, link-local, and special-purpose network destinations are blocked.";
					return false;
				}
			}
			return true;
		}
		catch
		{
			reason = "The destination host could not be resolved safely.";
			return false;
		}
	}

	private static bool IsPrivateOrSpecialPurposeAddress(IPAddress address)
	{
		if (address == null)
		{
			return true;
		}
		if (address.IsIPv4MappedToIPv6)
		{
			return IsPrivateOrSpecialPurposeAddress(address.MapToIPv4());
		}
		if (IPAddress.IsLoopback(address) || address.Equals(IPAddress.Any) || address.Equals(IPAddress.IPv6Any) || address.Equals(IPAddress.None) || address.Equals(IPAddress.IPv6None))
		{
			return true;
		}
		byte[] bytes = address.GetAddressBytes();
		if (address.AddressFamily == AddressFamily.InterNetwork)
		{
			return bytes[0] == 0 || bytes[0] == 10 || bytes[0] >= 224 ||
				(bytes[0] == 100 && bytes[1] >= 64 && bytes[1] <= 127) ||
				(bytes[0] == 127) ||
				(bytes[0] == 169 && bytes[1] == 254) ||
				(bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) ||
				(bytes[0] == 192 && bytes[1] == 168) ||
				(bytes[0] == 198 && (bytes[1] == 18 || bytes[1] == 19));
		}
		return address.AddressFamily != AddressFamily.InterNetworkV6 || address.IsIPv6LinkLocal || address.IsIPv6Multicast || address.IsIPv6SiteLocal || (bytes[0] & 0xFE) == 0xFC;
	}

	private static bool IsChatBrowserProxyUrlBlocked(Uri uri, out string reason)
	{
		reason = "";
		string host = (uri?.Host ?? "").Trim().Trim('.').ToLowerInvariant();
		if (string.IsNullOrWhiteSpace(host) || IsChatBrowserProxyLocalHost(host))
		{
			return false;
		}
		string[] labels = host.Split(new char[1] { '.' }, StringSplitOptions.RemoveEmptyEntries);
		string topLevelDomain = ((labels.Length == 0) ? "" : labels[^1]);
		string[] chatBrowserProxyBlockedTopLevelDomains = ChatBrowserProxyBlockedTopLevelDomains;
		foreach (string blockedTld in chatBrowserProxyBlockedTopLevelDomains)
		{
			if (topLevelDomain.Equals(blockedTld, StringComparison.OrdinalIgnoreCase))
			{
				reason = "This URL uses a blocked adult-content top-level domain.";
				return true;
			}
		}
		string[] chatBrowserProxyBlockedDomainSuffixes = ChatBrowserProxyBlockedDomainSuffixes;
		foreach (string suffix in chatBrowserProxyBlockedDomainSuffixes)
		{
			if (HostMatchesChatBrowserProxySuffix(host, suffix))
			{
				reason = "This domain is blocked by the JackLLM Browser blacklist.";
				return true;
			}
		}
		string[] array = labels;
		foreach (string label in array)
		{
			string[] chatBrowserProxyBlockedHostTokens = ChatBrowserProxyBlockedHostTokens;
			foreach (string token in chatBrowserProxyBlockedHostTokens)
			{
				if (label.Equals(token, StringComparison.OrdinalIgnoreCase) || label.IndexOf(token, StringComparison.OrdinalIgnoreCase) >= 0)
				{
					reason = "This domain matches a blocked browser category.";
					return true;
				}
			}
		}
		return false;
	}

	private static bool HostMatchesChatBrowserProxySuffix(string host, string suffix)
	{
		if (string.IsNullOrWhiteSpace(host) || string.IsNullOrWhiteSpace(suffix))
		{
			return false;
		}
		suffix = suffix.Trim().Trim('.').ToLowerInvariant();
		return host.Equals(suffix, StringComparison.OrdinalIgnoreCase) || host.EndsWith("." + suffix, StringComparison.OrdinalIgnoreCase);
	}

	private static bool IsChatBrowserProxyLocalHost(string host)
	{
		if (string.IsNullOrWhiteSpace(host))
		{
			return false;
		}
		host = host.Trim().Trim('[', ']').Trim('.')
			.ToLowerInvariant();
		return host.Equals("localhost", StringComparison.OrdinalIgnoreCase) || host.Equals("127.0.0.1", StringComparison.OrdinalIgnoreCase) || host.Equals("::1", StringComparison.OrdinalIgnoreCase) || host.StartsWith("127.", StringComparison.OrdinalIgnoreCase) || host.EndsWith(".localhost", StringComparison.OrdinalIgnoreCase);
	}

	private static string DecodeChatBrowserProxyText(byte[] bytes, string charset)
	{
		if (bytes == null || bytes.Length == 0)
		{
			return "";
		}
		Encoding encoding = Encoding.UTF8;
		if (!string.IsNullOrWhiteSpace(charset))
		{
			try
			{
				encoding = Encoding.GetEncoding(charset.Trim().Trim('"', '\''));
			}
			catch
			{
				encoding = Encoding.UTF8;
			}
		}
		return encoding.GetString(bytes);
	}

	private static string BuildChatBrowserProxyUtf8ContentType(string contentType, string fallbackMediaType)
	{
		string mediaType = "";
		if (!string.IsNullOrWhiteSpace(contentType))
		{
			mediaType = contentType.Split(';')[0].Trim();
		}
		if (string.IsNullOrWhiteSpace(mediaType))
		{
			mediaType = fallbackMediaType;
		}
		return mediaType + "; charset=utf-8";
	}

	private static bool IsChatBrowserProxyHtml(string contentType, Uri uri)
	{
		string type = (contentType ?? "").ToLowerInvariant();
		return type.Contains("text/html") || type.Contains("application/xhtml") || HasBrowserProxyPathExtension(uri, ".html", ".htm", ".xhtml");
	}

	private static bool IsChatBrowserProxyCss(string contentType, Uri uri)
	{
		string type = (contentType ?? "").ToLowerInvariant();
		return type.Contains("text/css") || HasBrowserProxyPathExtension(uri, ".css");
	}

	private static bool IsChatBrowserProxyJavaScript(string contentType, Uri uri)
	{
		string type = (contentType ?? "").ToLowerInvariant();
		return type.Contains("javascript") || type.Contains("ecmascript") || type.Contains("text/js") || HasBrowserProxyPathExtension(uri, ".js", ".mjs", ".cjs");
	}

	private static bool IsChatBrowserProxySvg(string contentType, Uri uri)
	{
		string type = (contentType ?? "").ToLowerInvariant();
		return type.Contains("image/svg") || HasBrowserProxyPathExtension(uri, ".svg");
	}

	private static bool HasBrowserProxyPathExtension(Uri uri, params string[] extensions)
	{
		string path = uri?.AbsolutePath ?? "";
		foreach (string extension in extensions)
		{
			if (path.EndsWith(extension, StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
		}
		return false;
	}

	private string BuildChatBrowserProxyRouteForRequest(HttpRequest request)
	{
		string prefix = NormalizeChatBrowserProxyPrefix(GetRequestHeader(request, "X-Forwarded-Prefix"));
		if (string.IsNullOrWhiteSpace(prefix))
		{
			prefix = ExtractChatBrowserProxyPrefixFromPath(request?.Path);
		}
		if (string.IsNullOrWhiteSpace(prefix))
		{
			prefix = ExtractChatBrowserProxyPrefixFromHeaderUrl(GetChatBrowserProxyRequestHeader(request, "Referer"));
		}
		if (string.IsNullOrWhiteSpace(prefix))
		{
			prefix = ExtractChatBrowserProxyPrefixFromHeaderUrl(GetChatBrowserProxyRequestHeader(request, "Origin"));
		}
		return (string.IsNullOrWhiteSpace(prefix) ? "" : prefix) + "/api/browser-proxy";
	}

	private static string NormalizeChatBrowserProxyPrefix(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return "";
		}
		string prefix = "/" + value.Trim().Trim('/');
		return (prefix == "/") ? "" : prefix;
	}

	private static string ExtractChatBrowserProxyPrefixFromHeaderUrl(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return "";
		}
		try
		{
			if (Uri.TryCreate(value.Trim(), UriKind.Absolute, out Uri uri))
			{
				return ExtractChatBrowserProxyPrefixFromPath(uri.AbsolutePath);
			}
		}
		catch
		{
		}
		return "";
	}

	private static string ExtractChatBrowserProxyPrefixFromPath(string path)
	{
		if (string.IsNullOrWhiteSpace(path))
		{
			return "";
		}
		path = path.Trim();
		if (!path.StartsWith("/", StringComparison.Ordinal))
		{
			path = "/" + path;
		}
		int proxyRouteIndex = path.IndexOf("/api/browser-proxy", StringComparison.OrdinalIgnoreCase);
		if (proxyRouteIndex > 0)
		{
			return path.Substring(0, proxyRouteIndex).TrimEnd('/');
		}
		string[] parts = path.Trim('/').Split('/');
		if (parts.Length >= 2 && parts[0].Equals("proxy", StringComparison.OrdinalIgnoreCase))
		{
			return "/proxy/" + Uri.EscapeDataString(Uri.UnescapeDataString(parts[1]));
		}
		return "";
	}

	private static string NormalizeChatBrowserProxyPublicRoute(string proxyRoute)
	{
		string route = (string.IsNullOrWhiteSpace(proxyRoute) ? "/api/browser-proxy" : proxyRoute.Trim());
		if (!route.StartsWith("/", StringComparison.Ordinal))
		{
			route = "/" + route;
		}
		return route;
	}

	private string RewriteChatBrowserProxyHtml(string html, Uri baseUri, string proxyRoute)
	{
		if (string.IsNullOrEmpty(html))
		{
			html = "";
		}
		html = Regex.Replace(html, "<meta\\b(?=[^>]*\\bhttp-equiv\\s*=\\s*[\"']?content-security-policy[\"']?)[^>]*>", "", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		html = Regex.Replace(html, "\\s+integrity\\s*=\\s*(?:\"[^\"]*\"|'[^']*'|[^\\s>]+)", "", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		html = Regex.Replace(html, "(?<name>\\b(?:href|src|action|poster|data|background|formaction|manifest|xlink:href)\\s*=\\s*)(?<quote>[\"']?)(?<url>[^\"'\\s>]+)(?<end>\\k<quote>)", (Match match) => RewriteChatBrowserProxyHtmlUrlAttribute(match, baseUri, proxyRoute), RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		html = Regex.Replace(html, "(?<name>\\b(?:srcset|imagesrcset)\\s*=\\s*)(?<quote>[\"'])(?<value>.*?)(?<end>\\k<quote>)", (Match match) => match.Groups["name"].Value + match.Groups["quote"].Value + WebUtility.HtmlEncode(RewriteChatBrowserProxySrcSet(WebUtility.HtmlDecode(match.Groups["value"].Value), baseUri, proxyRoute)) + match.Groups["end"].Value, RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		html = Regex.Replace(html, "(?<name>\\bstyle\\s*=\\s*)(?<quote>[\"'])(?<value>.*?)(?<end>\\k<quote>)", (Match match) => match.Groups["name"].Value + match.Groups["quote"].Value + WebUtility.HtmlEncode(RewriteChatBrowserProxyCss(WebUtility.HtmlDecode(match.Groups["value"].Value), baseUri, proxyRoute)) + match.Groups["end"].Value, RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		html = Regex.Replace(html, "(?<prefix><meta\\b(?=[^>]*\\bhttp-equiv\\s*=\\s*[\"']?refresh[\"']?)[^>]*\\bcontent\\s*=\\s*)(?<quote>[\"'])(?<value>.*?)(?<end>\\k<quote>)", (Match match) => match.Groups["prefix"].Value + match.Groups["quote"].Value + WebUtility.HtmlEncode(RewriteChatBrowserProxyMetaRefresh(WebUtility.HtmlDecode(match.Groups["value"].Value), baseUri, proxyRoute)) + match.Groups["end"].Value, RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		html = Regex.Replace(html, "(?<open><style\\b[^>]*>)(?<css>[\\s\\S]*?)(?<close></style>)", (Match match) => match.Groups["open"].Value + RewriteChatBrowserProxyCss(match.Groups["css"].Value, baseUri, proxyRoute) + match.Groups["close"].Value, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		string runtime = "<script>" + BuildChatBrowserProxyRuntimeScript(baseUri, proxyRoute) + "</script><script>" + BuildChatBrowserProxyNavigationFixScript(baseUri, proxyRoute) + "</script>";
		Match head = Regex.Match(html, "<head\\b[^>]*>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		if (head.Success)
		{
			return html.Insert(head.Index + head.Length, runtime);
		}
		return runtime + html;
	}

	private string RewriteChatBrowserProxyHtmlUrlAttribute(Match match, Uri baseUri, string proxyRoute)
	{
		string raw = WebUtility.HtmlDecode(match.Groups["url"].Value ?? "");
		string rewritten = BuildChatBrowserProxyClientUrl(raw, baseUri, proxyRoute);
		if (string.Equals(rewritten, raw, StringComparison.Ordinal))
		{
			return match.Value;
		}
		string quote = match.Groups["quote"].Value;
		return match.Groups["name"].Value + quote + WebUtility.HtmlEncode(rewritten) + match.Groups["end"].Value;
	}

	private string RewriteChatBrowserProxyCss(string css, Uri baseUri, string proxyRoute)
	{
		if (string.IsNullOrEmpty(css))
		{
			return css ?? "";
		}
		css = Regex.Replace(css, "url\\(\\s*(?<quote>[\"']?)(?<url>[^)'\"\\s]+)(?<endquote>[\"']?)\\s*\\)", delegate(Match match)
		{
			string value = match.Groups["url"].Value;
			string text = BuildChatBrowserProxyClientUrl(value, baseUri, proxyRoute);
			string text2 = (string.IsNullOrEmpty(match.Groups["quote"].Value) ? "" : match.Groups["quote"].Value);
			return "url(" + text2 + text + text2 + ")";
		}, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		css = Regex.Replace(css, "@import\\s+(?:url\\(\\s*)?(?<quote>[\"']?)(?<url>[^)'\";\\s]+)(?<endquote>[\"']?)(?:\\s*\\))?", delegate(Match match)
		{
			string value = match.Groups["url"].Value;
			string text = BuildChatBrowserProxyClientUrl(value, baseUri, proxyRoute);
			string text2 = (string.IsNullOrEmpty(match.Groups["quote"].Value) ? "\"" : match.Groups["quote"].Value);
			return "@import " + text2 + text + text2;
		}, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		return css;
	}

	private string RewriteChatBrowserProxyJavaScript(string script, Uri baseUri, string proxyRoute)
	{
		if (string.IsNullOrEmpty(script))
		{
			return script ?? "";
		}
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\bimport\\s*\\(\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\bfrom\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\b(?:new\\s+)?(?:Worker|SharedWorker|EventSource)\\s*\\(\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\b(?:fetch|importScripts)\\s*\\(\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\b(?:(?:window|document|top|parent|self)\\.)?location(?:\\.href)?\\s*=\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\b(?:(?:window|document|top|parent|self)\\.)?location\\.(?:assign|replace)\\s*\\(\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		script = RewriteChatBrowserProxyJavaScriptCall(script, baseUri, proxyRoute, "(?<prefix>\\b(?:window\\.)?open\\s*\\(\\s*)(?<quote>[\"'])(?<url>[^\"']+)(?<end>\\k<quote>)");
		return script;
	}

	private string RewriteChatBrowserProxyJavaScriptCall(string script, Uri baseUri, string proxyRoute, string pattern)
	{
		return Regex.Replace(script, pattern, delegate(Match match)
		{
			string value = match.Groups["url"].Value;
			string text = BuildChatBrowserProxyClientUrl(value, baseUri, proxyRoute);
			if (string.Equals(text, value, StringComparison.Ordinal))
			{
				return match.Value;
			}
			string value2 = match.Groups["quote"].Value;
			return match.Groups["prefix"].Value + value2 + EscapeChatBrowserProxyJavaScriptString(text, value2[0]) + match.Groups["end"].Value;
		}, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
	}

	private string RewriteChatBrowserProxySrcSet(string srcset, Uri baseUri, string proxyRoute)
	{
		if (string.IsNullOrWhiteSpace(srcset))
		{
			return srcset ?? "";
		}
		List<string> parts = new List<string>();
		string[] array = srcset.Split(',');
		foreach (string rawPart in array)
		{
			string part = rawPart.Trim();
			if (part.Length != 0)
			{
				Match match = Regex.Match(part, "^(?<url>\\S+)(?<descriptor>.*)$", RegexOptions.CultureInvariant);
				if (!match.Success)
				{
					parts.Add(part);
					continue;
				}
				string rewritten = BuildChatBrowserProxyClientUrl(match.Groups["url"].Value, baseUri, proxyRoute);
				parts.Add(rewritten + match.Groups["descriptor"].Value);
			}
		}
		return string.Join(", ", parts);
	}

	private string RewriteChatBrowserProxyMetaRefresh(string value, Uri baseUri, string proxyRoute)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return value ?? "";
		}
		return Regex.Replace(value, "(?<prefix>\\burl\\s*=\\s*)(?<url>[^;]+)$", delegate(Match match)
		{
			string rawValue = match.Groups["url"].Value.Trim().Trim('"', '\'');
			return match.Groups["prefix"].Value + BuildChatBrowserProxyClientUrl(rawValue, baseUri, proxyRoute);
		}, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
	}

	private string BuildChatBrowserProxyRuntimeScript(Uri baseUri, string proxyRoute)
	{
		string targetJson = JsonSerializer.Serialize(baseUri?.AbsoluteUri ?? "").Replace("</", "<\\/", StringComparison.Ordinal);
		string routeJson = JsonSerializer.Serialize(NormalizeChatBrowserProxyPublicRoute(proxyRoute)).Replace("</", "<\\/", StringComparison.Ordinal);
		string cookieQueryJson = JsonSerializer.Serialize("__jack_browser_proxy_cookie").Replace("</", "<\\/", StringComparison.Ordinal);
		return "\n(function() {\n  'use strict';\n  var targetUrl = " + targetJson + ";\n  var proxyRoute = " + routeJson + ";\n  var cookieQueryName = " + cookieQueryJson + ";\n  var nativeSendBeacon = navigator.sendBeacon ? navigator.sendBeacon.bind(navigator) : null;\n  var NativeXHR = window.XMLHttpRequest;\n  var nativeXhrOpen = NativeXHR && NativeXHR.prototype ? NativeXHR.prototype.open : null;\n  var nativeXhrSend = NativeXHR && NativeXHR.prototype ? NativeXHR.prototype.send : null;\n  try {\n    if (/(?:^|\\/)api\\/browser-proxy$/i.test(location.pathname || '')) proxyRoute = location.pathname;\n  } catch (_) { }\n  function proxyTargetFromProxyUrl(value) {\n    try {\n      var raw = String(value == null ? '' : value).trim();\n      if (!raw) return '';\n      var parsed = new URL(raw, location.href);\n      if (!/(?:^|\\/)api\\/browser-proxy$/i.test(parsed.pathname)) return '';\n      var target = parsed.searchParams.get('url') || '';\n      return target ? target + (parsed.hash || '') : '';\n    } catch (_) {\n      return '';\n    }\n  }\n  function skipUrl(value) {\n    var raw = String(value == null ? '' : value).trim();\n    return !raw || raw[0] === '#' || /^(?:data|blob|about|javascript|mailto|tel|sms|urn|chrome|edge|file|ws|wss):/i.test(raw);\n  }\n  function proxyUrlFor(value, base) {\n    try {\n      if (value && typeof Request !== 'undefined' && value instanceof Request) return value;\n      var raw = String(value == null ? '' : value).trim();\n      if (skipUrl(raw)) return value;\n      if (proxyTargetFromProxyUrl(raw)) return value;\n      var url = new URL(raw, base || targetUrl);\n      if (url.protocol !== 'http:' && url.protocol !== 'https:') return value;\n      var hash = url.hash || '';\n      url.hash = '';\n      return proxyRoute + '?url=' + encodeURIComponent(url.href) + hash;\n    } catch (_) {\n      return value;\n    }\n  }\n  function rewriteCss(css) {\n    return String(css || '')\n      .replace(/url\\(\\s*(['\"]?)([^)'\"\\s]+)\\1