	}

	private string BuildChatBrowserProxyNavigationFixScript(Uri baseUri, string proxyRoute)
	{
		string targetJson = JsonSerializer.Serialize(baseUri?.AbsoluteUri ?? "").Replace("</", "<\\/", StringComparison.Ordinal);
		string routeJson = JsonSerializer.Serialize(NormalizeChatBrowserProxyPublicRoute(proxyRoute)).Replace("</", "<\\/", StringComparison.Ordinal);
		return @"
(function() {
  'use strict';
  var targetUrl = " + targetJson + @";
  var configuredRoute = " + routeJson + @";
  function activeProxyRoute() {
    var route = configuredRoute || '/api/browser-proxy';
    try {
      var path = String(location.pathname || '').replace(/\/+$/, '');
      if (/(?:^|\/)api\/browser-proxy$/i.test(path)) route = path;
    } catch (_) { }
    route = String(route || '/api/browser-proxy').replace(/\/+$/, '');
    return route.charAt(0) === '/' ? route : '/' + route;
  }
  var proxyRoute = activeProxyRoute();
  function proxyTargetFromProxyUrl(value) {
    try {
      var parsed = new URL(String(value == null ? '' : value).trim(), location.href);
      if (!/(?:^|\/)api\/browser-proxy\/?$/i.test(parsed.pathname || '')) return '';
      var target = parsed.searchParams.get('url') || '';
      return target ? target + (parsed.hash || '') : '';
    } catch (_) {
      return '';
    }
  }
  function proxyUrlFromTarget(value) {
    var raw = String(value == null ? '' : value).trim();
    if (!raw) return '';
    try {
      var url = new URL(raw, targetUrl || location.href);
      var hash = url.hash || '';
      url.hash = '';
      return proxyRoute + '?url=' + encodeURIComponent(url.href) + hash;
    } catch (_) {
      var hashIndex = raw.indexOf('#');
      var hash = hashIndex >= 0 ? raw.slice(hashIndex) : '';
      var target = hashIndex >= 0 ? raw.slice(0, hashIndex) : raw;
      return proxyRoute + '?url=' + encodeURIComponent(target) + hash;
    }
  }
  function shouldSkipUrl(value) {
    var raw = String(value == null ? '' : value).trim();
    return !raw || raw.charAt(0) === '#' || /^(?:data|blob|about|javascript|mailto|tel|sms|urn|chrome|edge|file|ws|wss):/i.test(raw);
  }
  function proxyUrlFor(value, base) {
    var raw = String(value == null ? '' : value).trim();
    if (shouldSkipUrl(raw)) return value;
    var existingTarget = proxyTargetFromProxyUrl(raw);
    if (existingTarget) return proxyUrlFromTarget(existingTarget);
    try {
      var url = new URL(raw, base || targetUrl || location.href);
      if (url.protocol !== 'http:' && url.protocol !== 'https:') return value;
      var hash = url.hash || '';
      url.hash = '';
      return proxyUrlFromTarget(url.href + hash);
    } catch (_) {
      return value;
    }
  }
  function normalizeElement(el) {
    if (!el || !el.getAttribute || !el.setAttribute) return;
    ['href','src','action','poster','data','background','formaction','manifest','xlink:href'].forEach(function(name) {
      var value = el.getAttribute(name);
      if (!value) return;
      var next = proxyUrlFor(value);
      if (next && next !== value) el.setAttribute(name, next);
    });
  }
  function normalizeTree(root) {
    try {
      if (!root || !root.querySelectorAll) return;
      root.querySelectorAll('a[href],area[href],link[href],script[src],img[src],iframe[src],source[src],video[poster],audio[src],form[action],button[formaction],object[data],embed[src],[manifest]').forEach(normalizeElement);
    } catch (_) { }
  }
  document.addEventListener('click', function(event) {
    var link = event && event.target && event.target.closest ? event.target.closest('a[href], area[href]') : null;
    if (!link || event.defaultPrevented || event.button && event.button !== 0 || event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) return;
    var next = proxyUrlFor(link.getAttribute('href') || link.href);
    if (!next || next === link.getAttribute('href')) return;
    link.setAttribute('href', next);
    event.preventDefault();
    try { location.assign(next); } catch (_) { location.href = next; }
  }, true);
  document.addEventListener('submit', function(event) {
    if (event && event.target) normalizeElement(event.target);
  }, true);
  try {
    new MutationObserver(function(records) {
      records.forEach(function(record) {
        if (record.type === 'attributes') normalizeElement(record.target);
        if (record.addedNodes) record.addedNodes.forEach(function(node) {
          if (node && node.nodeType === 1) {
            normalizeElement(node);
            normalizeTree(node);
          }
        });
      });
    }).observe(document.documentElement || document, { childList: true, subtree: true, attributes: true, attributeFilter: ['href','src','action','poster','data','background','formaction','manifest','xlink:href'] });
  } catch (_) { }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', function() { normalizeTree(document); });
  normalizeTree(document);
  if (window.__jackBrowserProxy) {
    window.__jackBrowserProxy.route = proxyRoute;
    window.__jackBrowserProxy.rewriteUrl = proxyUrlFor;
  }
