		EnsureChatSessionColumns(table);
		if (table.Rows == null)
		{
			table.Rows = new List<object[]>();
		}
		for (int i = 0; i < table.Rows.Count; i++)
		{
			object[] row = NormalizeChatSessionRow(table.Rows[i]);
			if (IsProtectedChatSessionPrivateValue(GetRowValue(row, 5)) ||
				IsProtectedChatSessionPrivateValue(GetRowValue(row, 6)) ||
				IsProtectedChatSessionPrivateValue(GetRowValue(row, 8)) ||
				HasChatOwnerEncryptionSecret(GetRowValue(row, 7)))
			{
				ProtectChatSessionRowSensitiveValues(row);
			}
			table.Rows[i] = row;
		}
		return table;
	}

