	private void MigrateLegacyWebAuthRows(Table target)
	{
		if (target == null || (target.Rows != null && target.Rows.Count > 0))
		{
			return;
		}
		try
		{
			if (!_chatSessionData.Databases.TryGetValue("SocketJack", out var legacyDb) || legacyDb == null || !legacyDb.Tables.TryGetValue("WebAuth", out var legacyTable) || legacyTable?.Rows == null || legacyTable.Rows.Count == 0)
			{
				return;
			}
			if (target.Rows == null)
			{
				target.Rows = new List<object[]>();
			}
			foreach (object[] row in legacyTable.Rows)
			{
				target.Rows.Add(NormalizeWebAuthRow(row));
			}
			SaveChatSessionDataAndInvalidateCaches();
		}
		catch
		{
		}
	}

