	private void EnsureColumn(Table table, int index, string name, int maxLength)
	{
		while (table.Columns.Count <= index)
		{
			table.Columns.Add(new Column());
		}
		table.Columns[index] = new Column(name, typeof(string), maxLength);
	}

	private object[] CreateChatSessionRow(string id, string title, string createdUtc, string updatedUtc, string model, string messagesJson, string filesJson, string ownerKey, string draftPrompt, string shareKey, bool shareEnabled, bool titleLocked, string savedUtc, bool locked, string lockedUtc, string clonedFromSessionId, long promptTokenBudget, string runtime)
	{
		long promptTokens = EstimateChatSessionPromptTokens(messagesJson, draftPrompt);
		object[] row = NormalizeChatSessionRow(new object[19]
		{
			id ?? "",
			title ?? "",
			createdUtc ?? "",
			updatedUtc ?? "",
			model ?? "",
			NormalizeJsonArrayRawText(messagesJson),
			NormalizeJsonArrayRawText(filesJson),
			ownerKey ?? "",
			draftPrompt ?? "",
			shareKey ?? "",
			shareEnabled ? "true" : "false",
			titleLocked ? "true" : "false",
			savedUtc ?? "",
			locked ? "true" : "false",
			lockedUtc ?? "",
			clonedFromSessionId ?? "",
			promptTokens.ToString(CultureInfo.InvariantCulture),
			NormalizePromptTokenBudget(promptTokenBudget).ToString(CultureInfo.InvariantCulture),
			runtime ?? ""
		});
		ProtectChatSessionRowSensitiveValues(row);
		return row;
	}

	private ChatSessionDiagnosticsSnapshot MutateChatSessionDiagnostics(string sessionId, string ownerKey, Action<object[]> mutate)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : sessionId.Trim());
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			throw new InvalidOperationException("Session id is required.");
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				object[] row = NormalizeChatSessionRow(table.Rows[i]);
				table.Rows[i] = row;
				if (string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
				{
					if (!ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7)))
					{
						throw new InvalidOperationException("Session not found.");
					}
					mutate?.Invoke(row);
					ProtectChatSessionRowSensitiveValues(row);
					table.Rows[i] = row;
					SaveChatSessionDataAndInvalidateCaches();
					return BuildChatSessionDiagnosticsSnapshot(row);
				}
			}
		}
		throw new InvalidOperationException("Session not found.");
	}

	private ChatSessionDiagnosticsSnapshot BuildChatSessionDiagnosticsSnapshot(object[] row)
	{
		row = NormalizeChatSessionRow(row);
		return new ChatSessionDiagnosticsSnapshot
		{
			Id = GetRowValue(row, 0),
			Title = GetRowValue(row, 1),
			CreatedUtc = GetRowValue(row, 2),
			UpdatedUtc = GetRowValue(row, 3),
			Model = GetRowValue(row, 4),
			Runtime = GetRowValue(row, 18),
			OwnerKey = GetRowValue(row, 7),
			MessageCount = CountJsonArrayItems(GetChatSessionPrivateValue(row, 5, "messages", "[]")),
			FileCount = CountJsonArrayItems(GetChatSessionPrivateValue(row, 6, "files", "[]")),
			TitleLocked = ParseStoredBool(GetRowValue(row, 11), fallback: false),
			SavedUtc = GetRowValue(row, 12),
			Locked = ParseStoredBool(GetRowValue(row, 13), fallback: false),
			LockedUtc = GetRowValue(row, 14),
			ClonedFromSessionId = GetRowValue(row, 15),
			PromptTokenCount = ParseStoredLong(GetRowValue(row, 16), 0L),
			PromptTokenBudget = ParseStoredLong(GetRowValue(row, 17), 8192L)
		};
	}

	private ChatSessionCompatibilityPayload BuildChatSessionCompatibilityPayload(string ownerKey, string sessionId, string model = null, string runtime = null, long promptTokenCount = -1L, long promptTokenBudget = 0L)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		sessionId = (string.IsNullOrWhiteSpace(sessionId) ? "" : SanitizeFileName(sessionId.Trim()));
		if (!string.IsNullOrWhiteSpace(sessionId))
		{
			List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
			lock (_chatSessionLock)
			{
				Table table = GetChatSessionsTable();
				foreach (object[] sourceRow in table.Rows)
				{
					object[] row = NormalizeChatSessionRow(sourceRow);
					if (!string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal) || !OwnerKeyListContains(ownerKeys, GetRowValue(row, 7)))
					{
						continue;
					}
					return BuildChatSessionCompatibilityPayload(row, model, runtime, promptTokenCount, promptTokenBudget);
				}
			}
		}
		long budget = NormalizePromptTokenBudget((promptTokenBudget > 0) ? promptTokenBudget : 8192);
		long count = Math.Max(0L, promptTokenCount);
		string effectiveRuntime = (string.IsNullOrWhiteSpace(runtime) ? InferChatSessionRuntime(model) : runtime.Trim());
		return new ChatSessionCompatibilityPayload
		{
			id = sessionId,
			sessionId = sessionId,
			ownerKey = ownerKey,
			model = (model ?? ""),
			runtime = effectiveRuntime,
			state = "new",
			promptTokenCount = count,
			promptTokenBudget = budget,
			promptTokenPercent = CalculatePromptTokenPercent(count, budget),
			capabilities = BuildChatSessionCompatibilityCapabilities(locked: false)
		};
	}

	private ChatSessionCompatibilityPayload BuildChatSessionCompatibilityPayload(object[] row, string fallbackModel = null, string fallbackRuntime = null, long promptTokenCountOverride = -1L, long promptTokenBudgetOverride = 0L, int? messageCountOverride = null, int? fileCountOverride = null, int? commentCountOverride = null)
	{
		row = NormalizeChatSessionRow(row);
		bool locked = ParseStoredBool(GetRowValue(row, 13), fallback: false);
		string savedUtc = GetRowValue(row, 12);
		long budget = NormalizePromptTokenBudget((promptTokenBudgetOverride > 0) ? promptTokenBudgetOverride : ParseStoredLong(GetRowValue(row, 17), 8192L));
		long count = ((promptTokenCountOverride >= 0) ? promptTokenCountOverride : ParseStoredLong(GetRowValue(row, 16), 0L));
		string model = FirstNonEmpty(GetRowValue(row, 4), fallbackModel);
		string runtime = FirstNonEmpty(GetRowValue(row, 18), fallbackRuntime, InferChatSessionRuntime(model));
		return new ChatSessionCompatibilityPayload
		{
			id = GetRowValue(row, 0),
			sessionId = GetRowValue(row, 0),
			ownerKey = GetRowValue(row, 7),
			title = GetRowValue(row, 1),
			createdUtc = GetRowValue(row, 2),
			updatedUtc = GetRowValue(row, 3),
			model = (model ?? ""),
			runtime = (runtime ?? ""),
			state = (locked ? "locked" : (string.IsNullOrWhiteSpace(savedUtc) ? "draft" : "saved")),
			titleLocked = ParseStoredBool(GetRowValue(row, 11), fallback: false),
			locked = locked,
			lockedUtc = GetRowValue(row, 14),
			savedUtc = savedUtc,
			clonedFromSessionId = GetRowValue(row, 15),
			shareEnabled = ParseStoredBool(GetRowValue(row, 10), fallback: false),
			messageCount = messageCountOverride ?? CountJsonArrayItems(GetChatSessionPrivateValue(row, 5, "messages", "[]")),
			fileCount = fileCountOverride ?? CountJsonArrayItems(GetChatSessionPrivateValue(row, 6, "files", "[]")),
			commentCount = commentCountOverride ?? CountChatSessionComments(GetRowValue(row, 0)),
			promptTokenCount = count,
			promptTokenBudget = budget,
			promptTokenPercent = CalculatePromptTokenPercent(count, budget),
			capabilities = BuildChatSessionCompatibilityCapabilities(locked)
		};
	}

	private ChatSessionCompatibilityCapabilities BuildChatSessionCompatibilityCapabilities(bool locked)
	{
		return new ChatSessionCompatibilityCapabilities
		{
			canSave = true,
			canRename = true,
			canClone = true,
			canLock = !locked,
			canUnlock = locked,
			canModify = !locked,
			canDelete = !locked
		};
	}

	private static int CalculatePromptTokenPercent(long promptTokenCount, long promptTokenBudget)
	{
		if (promptTokenBudget <= 0 || promptTokenCount <= 0)
		{
			return 0;
		}
		double percent = (double)promptTokenCount / (double)promptTokenBudget * 100.0;
		return Math.Max(0, Math.Min(100, (int)Math.Round(percent)));
	}

	private object BuildChatSessionManagementCompatibilityPayload(string ownerKey = null, string sessionId = null, string runtime = null)
	{
		int storedCount = 0;
		int lockedCount = 0;
		long promptTokenCount = 0L;
		long promptTokenBudget = 0L;
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				storedCount++;
				if (ParseStoredBool(GetRowValue(row, 13), fallback: false))
				{
					lockedCount++;
				}
				promptTokenCount += Math.Max(0L, ParseStoredLong(GetRowValue(row, 16), 0L));
				promptTokenBudget += Math.Max(0L, ParseStoredLong(GetRowValue(row, 17), 8192L));
			}
		}
		return new
		{
			schema = "lmvsproxy.chat-session.compat.v1",
			source = "SocketJack-MagicMasterList",
			storedSessionCount = storedCount,
			lockedSessionCount = lockedCount,
			promptTokenCount = promptTokenCount,
			promptTokenBudget = promptTokenBudget,
			promptTokenPercent = CalculatePromptTokenPercent(promptTokenCount, promptTokenBudget),
			supportedActions = new string[8] { "save", "checkpoint", "rename", "lock", "unlock", "clone", "delete", "delete-bulk" },
			api = new
			{
				list = "/api/chat-sessions",
				get = "/api/chat-session?id={sessionId}",
				save = "/api/chat-session",
				deleteBulk = "/api/chat-sessions/delete",
				rename = "/api/chat-session-rename",
				action = "/api/chat-session-action",
				active = "/api/chat-active-sessions"
			},
			session = BuildChatSessionCompatibilityPayload(ownerKey, sessionId, ChatModel, runtime, -1L, 0L)
		};
	}

	private void RefreshChatSessionPromptMetrics(object[] row)
	{
		if (row != null && row.Length >= 19)
		{
			row[16] = EstimateChatSessionPromptTokens(GetChatSessionPrivateValue(row, 5, "messages", "[]"), GetChatSessionPrivateValue(row, 8, "draft", "")).ToString(CultureInfo.InvariantCulture);
			row[17] = NormalizePromptTokenBudget(ParseStoredLong(GetRowValue(row, 17), 8192L)).ToString(CultureInfo.InvariantCulture);
			if (string.IsNullOrWhiteSpace(GetRowValue(row, 18)))
			{
				row[18] = InferChatSessionRuntime(GetRowValue(row, 4));
			}
		}
	}

	private string InferChatSessionRuntime(string model)
	{
		string normalized = (model ?? "").Trim();
		if (string.IsNullOrWhiteSpace(normalized))
		{
			return "";
		}
		string lower = normalized.ToLowerInvariant();
		if (lower.Contains("llmruntime"))
		{
			return "LlmRuntime";
		}
		if (lower.Contains("magic"))
		{
			return "SockJackDml";
		}
		if (lower.Contains("lm-studio") || lower.Contains("lm studio"))
		{
			return "LM Studio";
		}
		return normalized;
	}

	private object[] NormalizeChatSessionRow(object[] row)
	{
		object[] normalized = new object[19];
		if (row != null)
