			normalized[4] = "";
		}
		if (string.IsNullOrWhiteSpace(normalized[5]?.ToString()))
		{
			normalized[5] = "[]";
		}
		if (string.IsNullOrWhiteSpace(normalized[6]?.ToString()))
		{
			normalized[6] = "[]";
		}
		if (string.IsNullOrWhiteSpace(normalized[7]?.ToString()))
		{
			normalized[7] = "legacy";
		}
		if (normalized[8] == null)
		{
			normalized[8] = "";
		}
		if (normalized[9] == null)
		{
			normalized[9] = "";
		}
		if (string.IsNullOrWhiteSpace(normalized[10]?.ToString()))
		{
			normalized[10] = "false";
		}
		if (string.IsNullOrWhiteSpace(normalized[11]?.ToString()))
		{
			normalized[11] = "false";
		}
		if (normalized[12] == null)
		{
			normalized[12] = "";
		}
		if (string.IsNullOrWhiteSpace(normalized[13]?.ToString()))
		{
			normalized[13] = "false";
		}
		if (normalized[14] == null)
		{
			normalized[14] = "";
		}
		if (normalized[15] == null)
		{
			normalized[15] = "";
		}
		if (string.IsNullOrWhiteSpace(normalized[16]?.ToString()))
		{
			normalized[16] = EstimateChatSessionPromptTokens(GetChatSessionPrivateValue(normalized, 5, "messages", "[]"), GetChatSessionPrivateValue(normalized, 8, "draft", "")).ToString(CultureInfo.InvariantCulture);
		}
		else
		{
			normalized[16] = Math.Max(0L, ParseStoredLong(normalized[16]?.ToString(), 0L)).ToString(CultureInfo.InvariantCulture);
		}
		if (string.IsNullOrWhiteSpace(normalized[17]?.ToString()))
		{
			normalized[17] = 8192.ToString(CultureInfo.InvariantCulture);
		}
		else
		{
			normalized[17] = NormalizePromptTokenBudget(ParseStoredLong(normalized[17]?.ToString(), 8192L)).ToString(CultureInfo.InvariantCulture);
		}
		if (string.IsNullOrWhiteSpace(normalized[18]?.ToString()))
		{
			normalized[18] = InferChatSessionRuntime(GetRowValue(normalized, 4));
		}
		return normalized;
	}

	private void ProtectChatSessionRowSensitiveValues(object[] row)
	{
		if (row == null || row.Length < ChatSessionColumnCount)
		{
			return;
		}
		string ownerKey = NormalizeChatFilesystemOwnerKey(GetRowValue(row, 7));
		row[5] = ProtectChatSessionPrivateValue(ownerKey, GetRowValue(row, 5), "messages", "[]", normalizeJsonArray: true);
		row[6] = ProtectChatSessionPrivateValue(ownerKey, GetRowValue(row, 6), "files", "[]", normalizeJsonArray: true);
		row[8] = ProtectChatSessionPrivateValue(ownerKey, GetRowValue(row, 8), "draft", "", normalizeJsonArray: false);
	}

	private object[] DecryptChatSessionRowForOwner(object[] row, string ownerKey = null)
	{
		object[] normalized = NormalizeChatSessionRow(row);
		object[] clone = (object[])normalized.Clone();
		string effectiveOwnerKey = NormalizeChatFilesystemOwnerKey(string.IsNullOrWhiteSpace(ownerKey) ? GetRowValue(clone, 7) : ownerKey);
		clone[5] = GetChatSessionPrivateValue(clone, 5, "messages", "[]", effectiveOwnerKey);
		clone[6] = GetChatSessionPrivateValue(clone, 6, "files", "[]", effectiveOwnerKey);
		clone[8] = GetChatSessionPrivateValue(clone, 8, "draft", "", effectiveOwnerKey);
		return clone;
	}

	private string GetChatSessionPrivateValue(object[] row, int index, string purpose, string fallback, string ownerKey = null)
	{
		if (row == null || index < 0 || index >= row.Length)
		{
			return fallback ?? "";
		}
		string value = GetRowValue(row, index);
		if (!IsProtectedChatSessionPrivateValue(value))
		{
			return string.IsNullOrWhiteSpace(value) ? (fallback ?? "") : value;
		}
		string rowOwnerKey = NormalizeChatFilesystemOwnerKey(string.IsNullOrWhiteSpace(ownerKey) ? GetRowValue(row, 7) : ownerKey);
		if (TryUnprotectChatSessionPrivateValue(rowOwnerKey, value, purpose, out var decrypted))
		{
			return decrypted;
		}
		return fallback ?? "";
	}

	private bool CanReadChatSessionPrivateValues(object[] row, string ownerKey = null)
	{
		row = NormalizeChatSessionRow(row);
		string value = GetRowValue(row, 5);
		if (!IsProtectedChatSessionPrivateValue(value))
		{
			return true;
		}
		string rowOwnerKey = NormalizeChatFilesystemOwnerKey(string.IsNullOrWhiteSpace(ownerKey) ? GetRowValue(row, 7) : ownerKey);
		return TryUnprotectChatSessionPrivateValue(rowOwnerKey, value, "messages", out var _);
	}

