	private bool IsProtectedChatSessionPrivateValue(string value)
	{
		return !string.IsNullOrWhiteSpace(value) && (value.StartsWith(ChatPrivatePayloadPrefix, StringComparison.Ordinal) || value.StartsWith(ChatPrivatePayloadPrefixV2, StringComparison.Ordinal));
	}

	private string ProtectChatSessionPrivateValue(string ownerKey, string value, string purpose, string fallback, bool normalizeJsonArray)
	{
		if (IsProtectedChatSessionPrivateValue(value))
		{
			return value;
		}
		string plain = value ?? fallback ?? "";
		if (normalizeJsonArray)
		{
			plain = NormalizeJsonArrayRawText(plain);
		}
		string secret = GetChatOwnerEncryptionSecretForWrite(ownerKey);
		if (string.IsNullOrWhiteSpace(secret))
		{
			return plain;
		}
		return EncryptChatSessionPrivateValue(ownerKey, plain, purpose, secret);
	}

	private string EncryptChatSessionPrivateValue(string ownerKey, string plainText, string purpose, string secret)
	{
		byte[] salt = GenerateRandomBytes(16);
		byte[] nonce = GenerateRandomBytes(12);
		byte[] plainBytes = Encoding.UTF8.GetBytes(plainText ?? "");
		byte[] cipherBytes = new byte[plainBytes.Length];
		byte[] tag = new byte[16];
		byte[] key = DeriveChatPrivatePayloadKey(secret, ownerKey, purpose, salt, ChatPrivatePayloadKeyIterationsV2);
		byte[] aad = Encoding.UTF8.GetBytes(NormalizeChatFilesystemOwnerKey(ownerKey) + "|" + (purpose ?? ""));
		try
		{
			using AesGcm aes = new AesGcm(key);
			aes.Encrypt(nonce, plainBytes, cipherBytes, tag, aad);
		}
		finally
		{
			Array.Clear(key, 0, key.Length);
		}
		byte[] payload = new byte[salt.Length + nonce.Length + tag.Length + cipherBytes.Length];
		Buffer.BlockCopy(salt, 0, payload, 0, salt.Length);
		Buffer.BlockCopy(nonce, 0, payload, salt.Length, nonce.Length);
		Buffer.BlockCopy(tag, 0, payload, salt.Length + nonce.Length, tag.Length);
		Buffer.BlockCopy(cipherBytes, 0, payload, salt.Length + nonce.Length + tag.Length, cipherBytes.Length);
		int arrayCount = (purpose == "messages" || purpose == "files") ? CountJsonArrayItems(plainText) : -1;
		return ChatPrivatePayloadPrefixV2 + (purpose ?? "") + ":" + ChatPrivatePayloadKeyIterationsV2.ToString(CultureInfo.InvariantCulture) + ":" + arrayCount.ToString(CultureInfo.InvariantCulture) + ":" + Convert.ToBase64String(payload);
	}

	private bool TryUnprotectChatSessionPrivateValue(string ownerKey, string protectedValue, string purpose, out string plainText)
	{
		plainText = "";
		if (!IsProtectedChatSessionPrivateValue(protectedValue))
		{
			plainText = protectedValue ?? "";
			return true;
		}
		string cacheKey = BuildChatPrivatePayloadCacheKey(ownerKey, purpose, protectedValue);
		if (TryGetCachedChatPrivatePayload(cacheKey, out plainText))
		{
			return true;
		}
		bool version2 = protectedValue.StartsWith(ChatPrivatePayloadPrefixV2, StringComparison.Ordinal);
		string storedPurpose;
		string encoded;
		int iterations = ChatPrivatePayloadKeyIterationsV1;
		if (version2)
		{
			string payloadText2 = protectedValue.Substring(ChatPrivatePayloadPrefixV2.Length);
			int first = payloadText2.IndexOf(':');
			if (first <= 0)
			{
				return false;
			}
			int second = payloadText2.IndexOf(':', first + 1);
			if (second <= first)
			{
				return false;
			}
			int third = payloadText2.IndexOf(':', second + 1);
			if (third <= second)
			{
				return false;
			}
			storedPurpose = payloadText2.Substring(0, first);
			if (!int.TryParse(payloadText2.Substring(first + 1, second - first - 1), NumberStyles.Integer, CultureInfo.InvariantCulture, out iterations))
			{
				return false;
			}
			iterations = Math.Max(1000, Math.Min(ChatPrivatePayloadKeyIterationsV1, iterations));
			encoded = payloadText2.Substring(third + 1);
		}
		else
		{
			string payloadText = protectedValue.Substring(ChatPrivatePayloadPrefix.Length);
			int separator = payloadText.IndexOf(':');
			if (separator <= 0)
			{
				return false;
			}
			storedPurpose = payloadText.Substring(0, separator);
			encoded = payloadText.Substring(separator + 1);
		}
		if (!string.Equals(storedPurpose, purpose, StringComparison.Ordinal))
		{
			return false;
		}
		byte[] payload;
		try
		{
			payload = Convert.FromBase64String(encoded);
		}
		catch
		{
			return false;
		}
		if (payload.Length < 44)
		{
			return false;
		}
		byte[] salt = new byte[16];
		byte[] nonce = new byte[12];
		byte[] tag = new byte[16];
		byte[] cipherBytes = new byte[payload.Length - 44];
		Buffer.BlockCopy(payload, 0, salt, 0, salt.Length);
		Buffer.BlockCopy(payload, salt.Length, nonce, 0, nonce.Length);
		Buffer.BlockCopy(payload, salt.Length + nonce.Length, tag, 0, tag.Length);
		Buffer.BlockCopy(payload, salt.Length + nonce.Length + tag.Length, cipherBytes, 0, cipherBytes.Length);
		byte[] aad = Encoding.UTF8.GetBytes(NormalizeChatFilesystemOwnerKey(ownerKey) + "|" + storedPurpose);
		foreach (string secret in GetChatOwnerEncryptionSecretCandidates(ownerKey))
		{
			if (string.IsNullOrWhiteSpace(secret))
			{
				continue;
			}
			byte[] key = DeriveChatPrivatePayloadKey(secret, ownerKey, storedPurpose, salt, iterations);
			byte[] plainBytes = new byte[cipherBytes.Length];
			try
			{
				using AesGcm aes = new AesGcm(key);
				aes.Decrypt(nonce, cipherBytes, tag, plainBytes, aad);
				plainText = Encoding.UTF8.GetString(plainBytes);
				SetCachedChatPrivatePayload(cacheKey, plainText);
				return true;
			}
			catch (CryptographicException)
			{
			}
			finally
			{
				Array.Clear(key, 0, key.Length);
				Array.Clear(plainBytes, 0, plainBytes.Length);
			}
		}
		return false;
	}

	private byte[] DeriveChatPrivatePayloadKey(string secret, string ownerKey, string purpose, byte[] salt, int iterations = ChatPrivatePayloadKeyIterationsV1)
	{
		string material = (secret ?? "") + "\n" + NormalizeChatFilesystemOwnerKey(ownerKey) + "\n" + (purpose ?? "");
		using Rfc2898DeriveBytes derive = new Rfc2898DeriveBytes(material, salt ?? Array.Empty<byte>(), Math.Max(1000, iterations), HashAlgorithmName.SHA256);
		return derive.GetBytes(32);
	}

	private string BuildChatPrivatePayloadCacheKey(string ownerKey, string purpose, string protectedValue)
	{
		string normalizedOwner = NormalizeChatFilesystemOwnerKey(ownerKey);
		string value = protectedValue ?? "";
		return normalizedOwner + "|" + (purpose ?? "") + "|" + value.Length.ToString(CultureInfo.InvariantCulture) + "|" + ComputeSha256Hex(value);
	}

	private bool TryGetCachedChatPrivatePayload(string cacheKey, out string plainText)
	{
		plainText = "";
		if (string.IsNullOrWhiteSpace(cacheKey))
		{
			return false;
		}
		lock (_chatPrivatePayloadCacheLock)
		{
			if (_chatPrivatePayloadCache.TryGetValue(cacheKey, out var entry) && entry != null)
			{
				plainText = entry.Text ?? "";
				return true;
			}
		}
		return false;
	}

	private void SetCachedChatPrivatePayload(string cacheKey, string plainText)
	{
		if (string.IsNullOrWhiteSpace(cacheKey))
		{
			return;
		}
		lock (_chatPrivatePayloadCacheLock)
		{
			if (_chatPrivatePayloadCache.Count >= ChatPrivatePayloadCacheMaxEntries)
			{
				foreach (string key in _chatPrivatePayloadCache.OrderBy((KeyValuePair<string, ChatPrivatePayloadCacheEntry> pair) => pair.Value?.CreatedUtc ?? DateTimeOffset.MinValue).Take(Math.Max(1, ChatPrivatePayloadCacheMaxEntries / 4)).Select((KeyValuePair<string, ChatPrivatePayloadCacheEntry> pair) => pair.Key).ToList())
				{
					_chatPrivatePayloadCache.Remove(key);
				}
			}
			_chatPrivatePayloadCache[cacheKey] = new ChatPrivatePayloadCacheEntry
			{
				Text = plainText ?? "",
				CreatedUtc = DateTimeOffset.UtcNow
			};
		}
	}

	private IReadOnlyList<string> GetChatOwnerEncryptionSecretCandidates(string ownerKey)
	{
		List<string> candidates = new List<string>();
		string remembered = GetRememberedChatOwnerEncryptionSecret(ownerKey);
		if (!string.IsNullOrWhiteSpace(remembered))
		{
			candidates.Add(remembered);
		}
		string fallback = GetChatOwnerEncryptionFallbackSecret(ownerKey);
		if (!string.IsNullOrWhiteSpace(fallback) && !candidates.Contains(fallback, StringComparer.Ordinal))
		{
			candidates.Add(fallback);
		}
		return candidates;
	}

	private string GetChatOwnerEncryptionSecretForWrite(string ownerKey)
	{
		string remembered = GetRememberedChatOwnerEncryptionSecret(ownerKey);
		return string.IsNullOrWhiteSpace(remembered) ? "" : remembered;
	}

	private string GetChatOwnerEncryptionFallbackSecret(string ownerKey)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			ownerKey = "legacy";
		}
		lock (_socketJackBearerTokenLock)
		{
			if (!_chatOwnerEphemeralEncryptionSecrets.TryGetValue(ownerKey, out var secret) || string.IsNullOrWhiteSpace(secret))
			{
				secret = Convert.ToBase64String(GenerateRandomBytes(32));
				_chatOwnerEphemeralEncryptionSecrets[ownerKey] = secret;
			}
			return secret;
		}
	}

