	private static int CountJsonArrayItems(string json)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "[]" : json);
			return (document.RootElement.ValueKind == JsonValueKind.Array) ? document.RootElement.GetArrayLength() : 0;
		}
		catch
		{
			return 0;
		}
	}

	private string GenerateChatShareKey()
	{
		byte[] bytes = new byte[24];
		RandomNumberGenerator.Fill(bytes);
		return Convert.ToBase64String(bytes).TrimEnd('=').Replace('+', '-')
			.Replace('/', '_');
	}

	private string BuildChatSessionShareUrl(HttpRequest request, JsonElement root, string shareKey)
	{
		shareKey = (shareKey ?? "").Trim();
		string publicBaseUrl = FirstNonEmpty(ExtractStringProperty(root, "publicBaseUrl"), ExtractStringProperty(root, "baseUrl"), ExtractStringProperty(root, "origin"), GetRequestOrigin(request));
		string publicPath = FirstNonEmpty(ExtractStringProperty(root, "publicPath"), ExtractStringProperty(root, "path"), request?.Path ?? "");
		string shellProxyPrefix = FirstNonEmpty(ExtractStringProperty(root, "shellProxyPrefix"), ExtractStringProperty(root, "proxyPath"), ExtractProxyPrefix(publicPath), ExtractProxyPrefix(request?.Path ?? ""));
		string serverName = FirstNonEmpty(ExtractStringProperty(root, "serverName"), ExtractStringProperty(root, "server"), ExtractProxyServerName(shellProxyPrefix), ExtractProxyServerName(publicPath));
		string path;
		if ((root.TryGetProperty("shellProxied", out var shellProxiedElement) && ReadJsonBool(shellProxiedElement, fallback: false)) || (root.TryGetProperty("proxied", out var proxiedElement) && ReadJsonBool(proxiedElement, fallback: false)) || !string.IsNullOrWhiteSpace(shellProxyPrefix) || !string.IsNullOrWhiteSpace(serverName))
		{
			string proxyBaseUrl = FirstNonEmpty(ExtractStringProperty(root, "proxyBaseUrl"), ExtractStringProperty(root, "socketJackBaseUrl"), HostLooksLikeSocketJack(publicBaseUrl) ? publicBaseUrl : "", "http://socketjack.com");
			string prefix = ((!string.IsNullOrWhiteSpace(shellProxyPrefix)) ? NormalizeShareUrlPath(shellProxyPrefix) : ("/proxy/" + Uri.EscapeDataString(string.IsNullOrWhiteSpace(serverName) ? "Server" : serverName.Trim())));
			path = prefix.TrimEnd('/') + "/Session";
			return AppendHashKeyToUrl(proxyBaseUrl, path, shareKey);
		}
		path = "/Session";
		return AppendHashKeyToUrl(publicBaseUrl, path, shareKey);
	}

	private string AppendHashKeyToUrl(string baseUrl, string path, string shareKey)
	{
		baseUrl = (string.IsNullOrWhiteSpace(baseUrl) ? ("http://localhost:" + _chatServerPort.ToString(CultureInfo.InvariantCulture)) : baseUrl.Trim());
		path = NormalizeShareUrlPath(path);
		UriBuilder builder = new UriBuilder(baseUrl.TrimEnd('/') + path)
		{
			Query = "hashKey=" + Uri.EscapeDataString(shareKey ?? "")
		};
		return builder.Uri.ToString();
	}

	private static string NormalizeShareUrlPath(string path)
	{
		path = (path ?? "").Trim();
		if (string.IsNullOrWhiteSpace(path))
		{
			return "/";
		}
		if (!path.StartsWith("/", StringComparison.Ordinal))
		{
			path = "/" + path;
		}
		return path;
	}

	private static string FirstNonEmpty(params string[] values)
	{
		string[] array = values ?? Array.Empty<string>();
		foreach (string value in array)
		{
			if (!string.IsNullOrWhiteSpace(value))
			{
				return value.Trim();
			}
		}
		return "";
	}

	private static string ExtractProxyPrefix(string path)
	{
		path = (path ?? "").Trim();
		if (string.IsNullOrWhiteSpace(path))
		{
			return "";
		}
		int proxy = path.IndexOf("/proxy/", StringComparison.OrdinalIgnoreCase);
		if (proxy < 0)
		{
			return "";
		}
		string tail = path.Substring(proxy).TrimEnd('/');
		string[] parts = tail.Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries);
		return (parts.Length >= 2 && parts[0].Equals("proxy", StringComparison.OrdinalIgnoreCase)) ? ("/proxy/" + Uri.EscapeDataString(Uri.UnescapeDataString(parts[1]))) : "";
	}

	private static string ExtractProxyServerName(string path)
	{
		string prefix = ExtractProxyPrefix(path);
		if (string.IsNullOrWhiteSpace(prefix))
		{
			return "";
		}
		string[] parts = prefix.Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries);
		return (parts.Length >= 2) ? Uri.UnescapeDataString(parts[1]) : "";
	}

	private static bool HostLooksLikeSocketJack(string baseUrl)
	{
		if (!Uri.TryCreate(baseUrl, UriKind.Absolute, out Uri uri))
		{
			return false;
		}
		return uri.Host.IndexOf("socketjack", StringComparison.OrdinalIgnoreCase) >= 0;
	}

	private static string GetRequestOrigin(HttpRequest request)
	{
		string host = (request?.Host ?? "").Trim();
		if (string.IsNullOrWhiteSpace(host))
		{
			return "";
		}
		string proto = "";
		if (request.Headers != null)
		{
			request.Headers.TryGetValue("X-Forwarded-Proto", out proto);
			if (string.IsNullOrWhiteSpace(proto))
			{
				request.Headers.TryGetValue("X-Forwarded-Scheme", out proto);
			}
		}
		proto = (string.IsNullOrWhiteSpace(proto) ? "http" : proto.Split(',')[0].Trim());
		if (!proto.Equals("http", StringComparison.OrdinalIgnoreCase) && !proto.Equals("https", StringComparison.OrdinalIgnoreCase))
		{
			proto = "http";
		}
		return proto + "://" + host;
	}

	private string ExtractChatUiShareKey(string requestBody)
	{
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return "";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			return (ExtractStringProperty(document.RootElement, "hashKey") ?? ExtractStringProperty(document.RootElement, "shareKey") ?? ExtractStringProperty(document.RootElement, "key") ?? "").Trim();
		}
		catch
		{
			return "";
		}
	}

	private bool TryResolveSharedChatRequest(string requestBody, out string ownerKey, out string sessionId, out string error)
	{
		ownerKey = "";
		sessionId = "";
		error = "";
		string shareKey = ExtractChatUiShareKey(requestBody);
		if (string.IsNullOrWhiteSpace(shareKey))
		{
			return false;
		}
		string rawSessionId = ExtractChatUiSessionId(requestBody);
		string requestedSessionId = (string.IsNullOrWhiteSpace(rawSessionId) ? "" : EnsureChatUiSessionId(rawSessionId));
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (!ParseStoredBool(GetRowValue(row, 10), fallback: false) || !string.Equals(GetRowValue(row, 9), shareKey, StringComparison.Ordinal))
				{
					continue;
				}
				string rowSessionId = GetRowValue(row, 0);
				if (!string.IsNullOrWhiteSpace(requestedSessionId) && !string.Equals(rowSessionId, requestedSessionId, StringComparison.Ordinal))
				{
					error = "Share key does not match this session.";
					return false;
				}
				sessionId = rowSessionId;
				ownerKey = GetRowValue(row, 7);
				return !string.IsNullOrWhiteSpace(ownerKey) && !string.IsNullOrWhiteSpace(sessionId);
			}
		}
		error = "Shared session not found or no longer public.";
		return false;
	}

	private bool TryResolveSharedSessionByKey(string shareKey, out string ownerKey, out string sessionId)
	{
		ownerKey = "";
		sessionId = "";
		shareKey = (shareKey ?? "").Trim();
		if (string.IsNullOrWhiteSpace(shareKey))
		{
			return false;
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (!ParseStoredBool(GetRowValue(row, 10), fallback: false) || !string.Equals(GetRowValue(row, 9), shareKey, StringComparison.Ordinal))
				{
					continue;
				}
				sessionId = GetRowValue(row, 0);
				ownerKey = GetRowValue(row, 7);
				return !string.IsNullOrWhiteSpace(ownerKey) && !string.IsNullOrWhiteSpace(sessionId);
			}
		}
		return false;
	}

	private string DisplayIpFromOwnerKey(string ownerKey)
	{
		ownerKey = (ownerKey ?? "").Trim();
		return ownerKey.StartsWith("ip:", StringComparison.OrdinalIgnoreCase) ? ownerKey.Substring(3) : "";
	}

	private string GetSharedPromptParticipantKey(NetworkConnection connection, HttpRequest request)
	{
		string ip = ExtractClientIp(connection, request);
		if (string.IsNullOrWhiteSpace(ip))
		{
			ip = "unknown";
		}
		return "ip:" + ip.Trim().ToLowerInvariant();
	}

	private bool TryAuthorizeSharedChatParticipant(NetworkConnection connection, HttpRequest request, out string participantKey, out string error)
	{
		participantKey = GetSharedPromptParticipantKey(connection, request);
		error = "";
		if (!TryAuthenticateWebAuthRequest(request, out var principal, out var _) || principal == null || string.IsNullOrWhiteSpace(principal.UserName))
		{
			error = "Sign in with a non-public SocketJack.com account to join this shared session.";
			return false;
		}
		if (principal.IsPublicAccount)
		{
			error = "Public SocketJack.com accounts can view this session but cannot send prompts.";
			return false;
		}
		ChatPermissionState participantPermissions = GetChatPermissions(participantKey);
		string restriction = BuildChatRestrictionMessage(participantPermissions);
		if (!string.IsNullOrWhiteSpace(restriction))
		{
			error = restriction;
			return false;
		}
		return true;
	}

	private ChatPermissionState BuildPublicSharedChatPermissions(ChatPermissionState source)
	{
		source = source ?? new ChatPermissionState();
		return new ChatPermissionState
		{
			internetSearch = false,
			vsCopilotTools = false,
			fileDownloads = false,
			ftpServer = false,
			sqlAdmin = false,
			terminalCommands = false,
			terminalForeverApproved = false,
			agentAccess = false,
			fileUploads = false,
			imageUploads = false,
			mutedUntilUtc = source.mutedUntilUtc,
			bannedUntilUtc = source.bannedUntilUtc,
			muteUntilEnabled = source.muteUntilEnabled,
			banUntilEnabled = source.banUntilEnabled,
			updatedUtc = source.updatedUtc
		};
	}

	private string AppendPublicSharedChatMessagesJson(string existingJson, JsonElement incomingMessages, out int appendedCount)
	{
		appendedCount = 0;
		using JsonDocument existingDocument = JsonDocument.Parse(string.IsNullOrWhiteSpace(existingJson) ? "[]" : existingJson);
		using MemoryStream stream = new MemoryStream();
		using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
		writer.WriteStartArray();
		if (existingDocument.RootElement.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement item in existingDocument.RootElement.EnumerateArray())
			{
				item.WriteTo(writer);
			}
		}
		int accepted = 0;
		foreach (JsonElement message in incomingMessages.EnumerateArray())
		{
			if (accepted >= 4)
			{
				break;
			}
			if (WritePublicSharedChatMessage(writer, message))
			{
				appendedCount++;
				accepted++;
			}
		}
		writer.WriteEndArray();
		writer.Flush();
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private bool WritePublicSharedChatMessage(Utf8JsonWriter writer, JsonElement message)
	{
		if (message.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		string role = (ExtractStringProperty(message, "role") ?? "").Trim().ToLowerInvariant();
		if (role != "user" && role != "assistant")
		{
			return false;
		}
		string content = ExtractStringProperty(message, "content") ?? "";
		string reasoning = ((role == "assistant") ? (ExtractStringProperty(message, "reasoning") ?? "") : "");
		content = TruncatePublicSharedChatText(content, 24000);
		reasoning = TruncatePublicSharedChatText(reasoning, 24000);
		if (string.IsNullOrWhiteSpace(content) && string.IsNullOrWhiteSpace(reasoning))
		{
			return false;
		}
		writer.WriteStartObject();
		writer.WriteString("role", role);
		writer.WriteString("content", content);
		if (role == "assistant" && !string.IsNullOrWhiteSpace(reasoning))
		{
			writer.WriteString("reasoning", reasoning);
		}
		writer.WriteEndObject();
		return true;
	}

	private string TruncatePublicSharedChatText(string text, int maxLength)
	{
		text = text ?? "";
		if (text.Length <= maxLength)
		{
			return text;
		}
		return text.Substring(0, maxLength);
	}

	private bool CanAccessChatSessionComments(string ownerKey, string sessionId, string shareKey, out bool ownerAccess, out bool sharedAccess)
	{
		ownerAccess = false;
		sharedAccess = false;
		sessionId = SanitizeFileName((sessionId ?? "").Trim());
		shareKey = (shareKey ?? "").Trim();
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return false;
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (!string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
				{
					continue;
				}
				ownerAccess = ChatOwnerKeysMatch(ownerKey, GetRowValue(row, 7));
				sharedAccess = ParseStoredBool(GetRowValue(row, 10), fallback: false) && !string.IsNullOrWhiteSpace(shareKey) && string.Equals(GetRowValue(row, 9), shareKey, StringComparison.Ordinal);
				return ownerAccess | sharedAccess;
			}
		}
		return false;
	}

	private string GetChatSessionOwnerForComments(string sessionId)
	{
		sessionId = SanitizeFileName((sessionId ?? "").Trim());
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionRow(sourceRow);
				if (string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
				{
					return GetRowValue(row, 7);
				}
			}
		}
		return "";
	}

	private int CountChatSessionComments(string sessionId)
	{
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return 0;
		}
		int count = 0;
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionCommentsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionCommentRow(sourceRow);
				if (string.Equals(GetRowValue(row, 1), sessionId, StringComparison.Ordinal))
				{
					count++;
				}
			}
		}
		return count;
	}

	private List<ChatSessionComment> GetChatSessionComments(string sessionId)
	{
		List<ChatSessionComment> comments = new List<ChatSessionComment>();
		if (string.IsNullOrWhiteSpace(sessionId))
		{
			return comments;
		}
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionCommentsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatSessionCommentRow(sourceRow);
				if (string.Equals(GetRowValue(row, 1), sessionId, StringComparison.Ordinal))
				{
					comments.Add(ChatSessionCommentFromRow(row));
				}
			}
		}
		comments.Sort((ChatSessionComment a, ChatSessionComment b) => string.CompareOrdinal(a.createdUtc, b.createdUtc));
		return comments;
	}

	private ChatSessionComment ChatSessionCommentFromRow(object[] row)
	{
		row = NormalizeChatSessionCommentRow(row);
		return new ChatSessionComment
		{
			id = GetRowValue(row, 0),
			sessionId = GetRowValue(row, 1),
			ownerKey = GetRowValue(row, 2),
			authorKey = GetRowValue(row, 3),
			authorName = GetRowValue(row, 4),
			body = GetRowValue(row, 5),
			createdUtc = GetRowValue(row, 6)
		};
	}

	private object[] ChatSessionCommentToRow(ChatSessionComment comment)
	{
		comment = comment ?? new ChatSessionComment();
		return NormalizeChatSessionCommentRow(new object[7]
		{
			comment.id ?? "",
			comment.sessionId ?? "",
			comment.ownerKey ?? "",
			comment.authorKey ?? "",
			comment.authorName ?? "",
			comment.body ?? "",
			comment.createdUtc ?? ""
		});
	}

	private string ShortenCommentAuthor(string ownerKey)
	{
		string text = (ownerKey ?? "").Trim();
		if (string.IsNullOrWhiteSpace(text))
		{
			return "Guest";
		}
		if (text.StartsWith("ip:", StringComparison.OrdinalIgnoreCase))
		{
			return "Guest " + text.Substring(3);
		}
		if (text.Length <= 42)
		{
			return text;
		}
		return text.Substring(0, 38) + "...";
	}

	private string HandleChatMemoriesGetRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			bool includeDeleted = string.Equals(GetQueryParameter(request, "includeDeleted"), "true", StringComparison.OrdinalIgnoreCase);
			List<ChatMemoryRecord> memories = GetChatMemories(ownerKey, includeDeleted);
			return JsonSerializer.Serialize(new
			{
				ok = true,
				ownerKey = ownerKey,
				count = memories.Count,
				memories = memories
			});
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Memory load failed: " + ex.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex.Message);
		}
	}

	private string HandleChatMemoriesMutationRequest(NetworkConnection connection, HttpRequest request)
	{
		try
		{
			string ownerKey = GetChatSessionOwnerKey(connection, request);
			using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(request?.Body) ? "{}" : request.Body);
			JsonElement root = document.RootElement;
			string action = (ExtractStringProperty(root, "action") ?? "add").Trim().ToLowerInvariant();
			string id = ExtractStringProperty(root, "id") ?? ExtractStringProperty(root, "memoryId") ?? "";
			string text = ExtractStringProperty(root, "text") ?? ExtractStringProperty(root, "memory") ?? "";
			string sourceSessionId = EnsureOptionalChatUiSessionId(ExtractStringProperty(root, "sessionId"));
			if (action == "add" || action == "save" || action == "create")
			{
				if (!TrySaveChatMemory(ownerKey, text, sourceSessionId, "explicit", out var memory, out var saveError))
				{
					return BuildJsonError(request, 400, "Bad Request", saveError);
				}
				return JsonSerializer.Serialize(new
				{
					ok = true,
					action = "add",
					ownerKey = ownerKey,
					memory = memory,
					memories = GetChatMemories(ownerKey)
				});
			}
			if (action == "delete" || action == "remove" || action == "forget")
			{
				int deleted = SoftDeleteChatMemories(ownerKey, id, text, clearAll: false);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					action = "delete",
					ownerKey = ownerKey,
					deleted = deleted,
					memories = GetChatMemories(ownerKey)
				});
			}
			if (action == "clear" || action == "delete-all" || action == "forget-all")
			{
				int deleted = SoftDeleteChatMemories(ownerKey, "", "", clearAll: true);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					action = "clear",
					ownerKey = ownerKey,
					deleted = deleted,
					memories = GetChatMemories(ownerKey)
				});
			}
			return BuildJsonError(request, 400, "Bad Request", "Unknown memory action.");
		}
		catch (JsonException ex)
		{
			return BuildJsonError(request, 400, "Bad Request", "Invalid memory JSON: " + ex.Message);
		}
		catch (Exception ex2)
		{
			LogMessage("[Chat UI] Memory update failed: " + ex2.Message);
			return BuildJsonError(request, 500, "Internal Server Error", ex2.Message);
		}
	}

	private void ProcessExplicitChatMemoryCommands(string ownerKey, string sessionId, string requestBody)
	{
		try
		{
			string userText = ExtractLatestChatUiUserText(requestBody);
			if (string.IsNullOrWhiteSpace(userText))
			{
				return;
			}
			string forgetText = ExtractExplicitMemoryForgetText(userText);
			if (!string.IsNullOrWhiteSpace(forgetText))
			{
				SoftDeleteChatMemories(ownerKey, "", forgetText, clearAll: false);
			}
			foreach (string memoryText in ExtractExplicitMemorySaveTexts(userText))
			{
				TrySaveChatMemory(ownerKey, memoryText, sessionId, "explicit", out var _, out var _);
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Chat UI] Memory command processing failed: " + ex.Message);
		}
	}

	private string BuildChatMemorySystemHint(string ownerKey)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			return "";
		}
		List<ChatMemoryRecord> memories = GetChatMemories(ownerKey)
			.Where((ChatMemoryRecord memory) => memory != null && string.IsNullOrWhiteSpace(memory.deletedUtc))
			.OrderByDescending((ChatMemoryRecord memory) => memory.updatedUtc ?? "")
			.Take(24)
			.ToList();
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("[JackLLM saved memory]");
		sb.AppendLine("JackLLM has application-managed explicit memory for this user. Use saved memories only as continuity context; the current user message wins if it conflicts. If the current user explicitly asks you to remember, save, forget, or make a mental note, acknowledge the memory action naturally and do not claim that JackLLM cannot store memories.");
		if (memories.Count == 0)
		{
			sb.AppendLine("No saved memories are currently stored for this user.");
			return sb.ToString().TrimEnd();
		}
		sb.AppendLine("Saved memories:");
		int index = 1;
		foreach (ChatMemoryRecord memory in memories)
		{
			string text = NormalizeChatMemoryText(memory.text, 320);
			if (string.IsNullOrWhiteSpace(text))
			{
				continue;
			}
			sb.Append("- ").Append(index.ToString(CultureInfo.InvariantCulture)).Append(". ")
				.AppendLine(text.Replace("\r", "").Replace("\n", " "));
			index++;
		}
		return TruncateChatUiSystemContextText(sb.ToString().TrimEnd(), 6000);
	}

	private List<ChatMemoryRecord> GetChatMemories(string ownerKey, bool includeDeleted = false)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
		List<ChatMemoryRecord> memories = new List<ChatMemoryRecord>();
		lock (_chatSessionLock)
		{
			Table table = GetChatMemoriesTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeChatMemoryRow(sourceRow);
				if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 1)))
				{
					continue;
				}
				if (!includeDeleted && !string.IsNullOrWhiteSpace(GetRowValue(row, 6)))
				{
					continue;
				}
				memories.Add(ChatMemoryFromRow(DecryptChatMemoryRowForOwner(row, ownerKey)));
			}
		}
		memories.Sort((ChatMemoryRecord a, ChatMemoryRecord b) => string.CompareOrdinal(b?.updatedUtc ?? "", a?.updatedUtc ?? ""));
		return memories;
	}

	private bool TrySaveChatMemory(string ownerKey, string text, string sourceSessionId, string category, out ChatMemoryRecord memory, out string error)
	{
		memory = null;
		error = "";
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		text = NormalizeChatMemoryText(text, 1000);
		sourceSessionId = EnsureOptionalChatUiSessionId(sourceSessionId);
		category = NormalizeChatMemoryCategory(category);
		if (string.IsNullOrWhiteSpace(text))
		{
			error = "Memory text is required.";
			return false;
		}
		string now = DateTimeOffset.UtcNow.ToString("O");
		string comparable = NormalizeChatMemoryComparable(text);
		List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
		lock (_chatSessionLock)
		{
			Table table = GetChatMemoriesTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				object[] row = NormalizeChatMemoryRow(table.Rows[i]);
				object[] readable = DecryptChatMemoryRowForOwner(row, ownerKey);
				if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 1)))
				{
					table.Rows[i] = row;
					continue;
				}
				if (string.Equals(NormalizeChatMemoryComparable(GetRowValue(readable, 2)), comparable, StringComparison.Ordinal))
				{
					readable[1] = ownerKey;
					readable[2] = text;
					readable[3] = sourceSessionId;
					readable[5] = now;
					readable[6] = "";
					readable[7] = category;
					ProtectChatMemoryRowSensitiveValues(readable);
					table.Rows[i] = readable;
					SaveChatSessionDataAndInvalidateCaches();
					memory = ChatMemoryFromRow(DecryptChatMemoryRowForOwner(readable, ownerKey));
					return true;
				}
				table.Rows[i] = row;
			}
			object[] next = NormalizeChatMemoryRow(new object[ChatMemoryColumnCount]
			{
				"mem_" + Guid.NewGuid().ToString("N"),
				ownerKey,
				text,
				sourceSessionId,
				now,
				now,
				"",
				category
			});
			ProtectChatMemoryRowSensitiveValues(next);
			table.Rows.Add(next);
			SaveChatSessionDataAndInvalidateCaches();
			memory = ChatMemoryFromRow(DecryptChatMemoryRowForOwner(next, ownerKey));
			return true;
		}
	}

	private int SoftDeleteChatMemories(string ownerKey, string id, string text, bool clearAll)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		id = (id ?? "").Trim();
		text = NormalizeChatMemoryText(text, 1000);
		string comparableText = NormalizeChatMemoryComparable(text);
		string now = DateTimeOffset.UtcNow.ToString("O");
		List<string> ownerKeys = GetEquivalentFilesystemOwnerKeys(ownerKey);
		int deleted = 0;
		lock (_chatSessionLock)
		{
			Table table = GetChatMemoriesTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				object[] row = NormalizeChatMemoryRow(table.Rows[i]);
				if (!OwnerKeyListContains(ownerKeys, GetRowValue(row, 1)) || !string.IsNullOrWhiteSpace(GetRowValue(row, 6)))
				{
					table.Rows[i] = row;
					continue;
				}
				object[] readable = DecryptChatMemoryRowForOwner(row, ownerKey);
				bool matches = clearAll ||
					(!string.IsNullOrWhiteSpace(id) && string.Equals(GetRowValue(row, 0), id, StringComparison.Ordinal)) ||
					(!string.IsNullOrWhiteSpace(comparableText) && NormalizeChatMemoryComparable(GetRowValue(readable, 2)).Contains(comparableText));
				if (!matches)
				{
					table.Rows[i] = row;
					continue;
				}
				row[5] = now;
				row[6] = now;
				table.Rows[i] = row;
				deleted++;
			}
			if (deleted > 0)
			{
				SaveChatSessionDataAndInvalidateCaches();
			}
		}
		return deleted;
	}

	private ChatMemoryRecord ChatMemoryFromRow(object[] row)
	{
		row = NormalizeChatMemoryRow(row);
		return new ChatMemoryRecord
		{
			id = GetRowValue(row, 0),
			ownerKey = GetRowValue(row, 1),
			text = GetRowValue(row, 2),
			sourceSessionId = GetRowValue(row, 3),
			createdUtc = GetRowValue(row, 4),
			updatedUtc = GetRowValue(row, 5),
			deletedUtc = GetRowValue(row, 6),
			category = GetRowValue(row, 7)
		};
	}

	private string ExtractLatestChatUiUserText(string requestBody)
	{
		try
		{
			using JsonDocument document = ParseChatUiRequestBodyJson(requestBody);
			JsonElement root = document.RootElement;
			if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty("messages", out var messages) && messages.ValueKind == JsonValueKind.Array)
			{
				int count = messages.GetArrayLength();
				for (int i = count - 1; i >= 0; i--)
				{
					JsonElement message = messages[i];
					string role = ExtractStringProperty(message, "role") ?? "";
					if (role.Equals("user", StringComparison.OrdinalIgnoreCase))
					{
						string text = ExtractChatUiMessageContentText(message);
						if (!string.IsNullOrWhiteSpace(text))
						{
							return text;
						}
					}
				}
			}
			return ExtractStringProperty(root, "message") ?? ExtractStringProperty(root, "prompt") ?? "";
		}
		catch
		{
			return "";
		}
	}

	private List<string> ExtractExplicitMemorySaveTexts(string text)
	{
		List<string> memories = new List<string>();
		text = NormalizeChatMemoryCommandText(text);
		if (string.IsNullOrWhiteSpace(text))
		{
			return memories;
		}
		string[] patterns = new string[5]
		{
			@"\b(?:please\s+)?remember\s+(?:that\s+|this\s*:?\s*)?(?<memory>[\s\S]+)$",
			@"\b(?:save|store)\s+(?:this\s+)?(?:memory|note)?\s*(?:that\s+|:)?\s*(?<memory>[\s\S]+)$",
			@"\b(?:make|take)\s+(?:a\s+)?mental\s+note\s+(?:that\s+|of\s+|:)?\s*(?<memory>[\s\S]+)$",
			@"\bmental\s+note\s*:?\s*(?<memory>[\s\S]+)$",
			@"\bnote\s+to\s+self\s*:?\s*(?<memory>[\s\S]+)$"
		};
		foreach (string pattern in patterns)
		{
			Match match = Regex.Match(text, pattern, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
			if (!match.Success)
			{
				continue;
			}
			string memory = TrimChatMemoryCommandPayload(match.Groups["memory"].Value);
			if (!string.IsNullOrWhiteSpace(memory) && !memories.Any((string existing) => string.Equals(NormalizeChatMemoryComparable(existing), NormalizeChatMemoryComparable(memory), StringComparison.Ordinal)))
			{
				memories.Add(memory);
			}
		}
		return memories;
	}

	private string ExtractExplicitMemoryForgetText(string text)
	{
		text = NormalizeChatMemoryCommandText(text);
		if (string.IsNullOrWhiteSpace(text))
		{
			return "";
		}
		string[] patterns = new string[3]
		{
			@"\bforget\s+(?:that\s+|about\s+)?(?<memory>[\s\S]+)$",
			@"\bdelete\s+(?:the\s+)?memory\s+(?:that\s+|about\s+)?(?<memory>[\s\S]+)$",
			@"\bremove\s+(?:the\s+)?memory\s+(?:that\s+|about\s+)?(?<memory>[\s\S]+)$"
		};
		foreach (string pattern in patterns)
		{
			Match match = Regex.Match(text, pattern, RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
			if (match.Success)
			{
				return TrimChatMemoryCommandPayload(match.Groups["memory"].Value);
			}
		}
		return "";
	}

	private static string NormalizeChatMemoryText(string text, int maxLength)
	{
		text = (text ?? "").Replace("\r\n", "\n").Replace('\r', '\n').Trim();
		if (string.IsNullOrWhiteSpace(text))
		{
			return "";
		}
		text = Regex.Replace(text, "[ \\t]+", " ");
		text = Regex.Replace(text, "\\n{3,}", "\n\n").Trim();
		if (text.Length > maxLength)
		{
			text = text.Substring(0, Math.Max(0, maxLength)).TrimEnd();
		}
		return text;
	}

	private static string NormalizeChatMemoryComparable(string text)
	{
		return Regex.Replace((text ?? "").Trim().ToLowerInvariant(), "\\s+", " ");
	}

	private static string NormalizeChatMemoryCategory(string category)
	{
		category = Regex.Replace((category ?? "").Trim().ToLowerInvariant(), "[^a-z0-9_-]+", "-").Trim('-');
		if (string.IsNullOrWhiteSpace(category))
		{
			return "explicit";
		}
		return category.Length > 80 ? category.Substring(0, 80) : category;
	}

	private static string NormalizeChatMemoryCommandText(string text)
	{
		text = (text ?? "").Replace("\r\n", "\n").Replace('\r', '\n').Trim();
		return Regex.Replace(text, "[ \\t]+", " ");
	}

	private static string TrimChatMemoryCommandPayload(string text)
	{
		text = NormalizeChatMemoryText(text, 1000).Trim().Trim('"', '\'', ' ', '\t', '\r', '\n');
		text = Regex.Replace(text, @"^(?:that|this)\s+", "", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant).Trim();
		text = Regex.Replace(text, @"\s+(?:please|thanks|thank you)\.?$", "", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant).Trim();
		text = text.TrimEnd('?', ' ', '\t', '\r', '\n');
		return NormalizeChatMemoryText(text, 1000);
	}

	private bool TryGetChatCommentIdentity(NetworkConnection connection, HttpRequest request, out string authorKey, out string displayName, out string error)
	{
		authorKey = "";
		displayName = "";
		error = "";
		if (!TryAuthenticateWebAuthRequest(request, out var principal, out var _) || principal == null || string.IsNullOrWhiteSpace(principal.UserName))
		{
			error = "Sign in with a SocketJack.com account to comment. Public viewers can read comments only.";
			return false;
		}
		if (principal.IsPublicAccount)
		{
			error = "Public SocketJack.com accounts can view this session but cannot comment.";
			return false;
		}
		displayName = principal.UserName.Trim();
		if (displayName.Length > 80)
		{
			displayName = displayName.Substring(0, 80);
		}
		authorKey = "webauth:" + principal.UserName.Trim().ToLowerInvariant();
		RememberSocketJackBearerToken(authorKey, principal.AccessToken);
		if (StoreLocalWebAuthAccounts)
		{
			GetOrCreateWebAuthTokenAccount(principal.UserName, connection, request);
			LinkWebAuthUserToIp(principal.UserName, ExtractClientIp(connection, request) ?? "");
		}
		return true;
	}

