			int copy = Math.Min(row.Length, normalized.Length);
			for (int i = 0; i < copy; i++)
			{
				if (row[i] != null)
				{
					normalized[i] = row[i];
				}
			}
		}
		if (string.IsNullOrWhiteSpace(normalized[0]?.ToString()))
		{
			normalized[0] = "lease_" + Guid.NewGuid().ToString("N");
		}
		normalized[1] = NormalizeCostOwnerKey(normalized[1]?.ToString());
		if (normalized[2] == null)
		{
			normalized[2] = "";
		}
		for (int j = 3; j <= 10; j++)
		{
			if (normalized[j] == null)
			{
				normalized[j] = "";
			}
		}
		normalized[11] = NormalizeMarketplaceLeaseStatus(normalized[11]?.ToString());
		normalized[12] = NormalizeMarketplaceLeasePaymentStatus(normalized[12]?.ToString(), ParseStoredBool(normalized[13]?.ToString(), fallback: false));
		normalized[13] = (ParseStoredBool(normalized[13]?.ToString(), fallback: false) ? "true" : "false");
		if (normalized[14] == null)
		{
			normalized[14] = "";
		}
		if (normalized[15] == null)
		{
			normalized[15] = "";
		}
		normalized[16] = Math.Max(0.0, ParseStoredDouble(normalized[16]?.ToString(), 0.0)).ToString("0.########", CultureInfo.InvariantCulture);
		normalized[17] = Math.Max(0L, ParseStoredLong(normalized[17]?.ToString(), 0L)).ToString(CultureInfo.InvariantCulture);
		normalized[18] = Math.Max(1L, ParseStoredLong(normalized[18]?.ToString(), 60L)).ToString(CultureInfo.InvariantCulture);
		for (int k = 19; k <= 23; k++)
		{
			if (normalized[k] == null)
			{
				normalized[k] = "";
			}
		}
		if (string.IsNullOrWhiteSpace(normalized[24]?.ToString()))
		{
			normalized[24] = now;
		}
		if (string.IsNullOrWhiteSpace(normalized[25]?.ToString()))
		{
			normalized[25] = normalized[24];
		}
		normalized[26] = (string.IsNullOrWhiteSpace(normalized[26]?.ToString()) ? "unknown" : normalized[26]?.ToString().Trim());
		normalized[27] = NormalizeJsonObjectRawText(normalized[27]?.ToString());
		normalized[28] = NormalizeJsonObjectRawText(normalized[28]?.ToString());
		return normalized;
	}

