	private void LinkWebAuthUserToIp(string username, string clientIp)
	{
		if (!TryNormalizeWebAuthUserName(username, out var normalizedUserName, out var _) || string.IsNullOrWhiteSpace(clientIp))
		{
			return;
		}
		clientIp = NormalizeClientIp(clientIp);
		lock (_chatSessionLock)
		{
			Table table = GetWebAuthIpLinksTable();
			string now = DateTimeOffset.UtcNow.ToString("O");
			for (int i = 0; i < table.Rows.Count; i++)
			{
				object[] row = NormalizeWebAuthIpLinkRow(table.Rows[i]);
				if (string.Equals(GetRowValue(row, 0), normalizedUserName, StringComparison.OrdinalIgnoreCase) && string.Equals(GetRowValue(row, 1), clientIp, StringComparison.OrdinalIgnoreCase))
				{
					row[2] = now;
					table.Rows[i] = row;
					SaveChatSessionDataAndInvalidateCaches();
					return;
				}
			}
			table.Rows.Add(new object[3] { normalizedUserName, clientIp, now });
			SaveChatSessionDataAndInvalidateCaches();
		}
	}

