	private TrustAbuseSummarySnapshot BuildTrustAbuseSummary(string ownerKey, string serverId, string serverName, string externalIp)
	{
		ownerKey = NormalizeTrustOwnerKey(ownerKey, "");
		serverId = (serverId ?? "").Trim();
		serverName = (serverName ?? "").Trim();
		externalIp = NormalizeTrustEndpoint(externalIp);
		TrustAbuseSummarySnapshot summary = new TrustAbuseSummarySnapshot
		{
			ReputationScore = 100,
			UpdatedUtc = DateTimeOffset.UtcNow.ToString("O")
		};
		DateTimeOffset staleCutoffUtc = DateTimeOffset.UtcNow.AddDays(-7.0);
		DateTimeOffset lastCaseUtc = default(DateTimeOffset);
		DateTimeOffset lastInterventionUtc = default(DateTimeOffset);
		lock (_chatSessionLock)
		{
			Table table = GetTrustAbuseCasesTable();
			foreach (object[] sourceRow in table.Rows)
			{
				TrustAbuseCaseRecord record = TrustAbuseCaseRecordFromRow(sourceRow);
				if (!TrustCaseMatches(record, ownerKey, serverId, serverName, externalIp))
				{
					continue;
				}
				summary.TotalCases++;
				bool open = IsOpenTrustStatus(record.status);
				if (open)
				{
					summary.OpenCases++;
					string severity = NormalizeTrustSeverity(record.severity);
					if (severity == "critical")
					{
						summary.CriticalOpenCases++;
					}
					else if (severity == "high")
					{
						summary.HighOpenCases++;
					}
					if (TryParseStoredDateTimeOffset(record.createdUtc, out var createdUtc) && createdUtc < staleCutoffUtc)
					{
						summary.StaleOpenCases++;
					}
				}
				if (TryParseStoredDateTimeOffset(record.createdUtc, out var caseCreatedUtc) && caseCreatedUtc > lastCaseUtc)
				{
					lastCaseUtc = caseCreatedUtc;
				}
				if (!string.IsNullOrWhiteSpace(record.intervention) && TryParseStoredDateTimeOffset(record.updatedUtc, out var interventionUtc) && interventionUtc > lastInterventionUtc)
				{
					lastInterventionUtc = interventionUtc;
				}
				switch (NormalizeTrustCategory(record.category))
				{
				case "dispute":
					summary.DisputeCount++;
					break;
				case "host_verification":
					summary.HostVerificationCount++;
					break;
				case "renter_identity":
					summary.RenterIdentityCount++;
					break;
				case "content_abuse":
					summary.ContentAbuseCount++;
					break;
				case "command_abuse":
					summary.CommandAbuseCount++;
					break;
				}
				summary.ReputationScore += record.reputationDelta;
				string intervention = NormalizeTrustIntervention(record.intervention);
				if (intervention == "verify_host" || record.status.Equals("verified", StringComparison.OrdinalIgnoreCase))
				{
					summary.HostVerified = true;
				}
				if (intervention == "verify_renter" || record.status.Equals("identity_verified", StringComparison.OrdinalIgnoreCase))
				{
					summary.RenterIdentityVerified = true;
				}
				if (!string.Equals(intervention, "note", StringComparison.OrdinalIgnoreCase) && open)
				{
					summary.OpenInterventionCases++;
				}
				if (intervention == "block_commands" && open)
				{
					summary.CommandsBlocked = true;
				}
				if (intervention == "suspend_host" && open)
				{
					summary.HostSuspended = true;
				}
			}
		}
		summary.ReputationScore = Math.Max(0, Math.Min(100, summary.ReputationScore));
		summary.ReputationTier = BuildTrustReputationTier(summary.ReputationScore, summary.OpenCases, summary.HostSuspended);
		summary.RiskScore = CalculateTrustRiskScore(summary);
		summary.RiskTier = BuildTrustRiskTier(summary.RiskScore, summary.HostSuspended);
		summary.NeedsAdminIntervention = summary.CriticalOpenCases > 0 || summary.HighOpenCases > 0 || summary.StaleOpenCases > 0 || summary.HostSuspended || summary.CommandsBlocked;
		summary.LastCaseUtc = ((lastCaseUtc == default(DateTimeOffset)) ? "" : lastCaseUtc.ToString("O"));
		summary.LastInterventionUtc = ((lastInterventionUtc == default(DateTimeOffset)) ? "" : lastInterventionUtc.ToString("O"));
		summary.HostVerificationStatus = (summary.HostSuspended ? "suspended" : (summary.HostVerified ? "verified" : ((summary.HostVerificationCount > 0) ? "reviewing" : "unverified")));
		summary.RenterIdentityStatus = (summary.RenterIdentityVerified ? "verified" : ((summary.RenterIdentityCount > 0) ? "reviewing" : "unknown"));
		return summary;
	}

	private bool TrustCaseMatches(TrustAbuseCaseRecord record, string ownerKey, string serverId, string serverName, string externalIp)
	{
		if (record == null)
		{
			return false;
		}
		if (string.IsNullOrWhiteSpace(ownerKey) && string.IsNullOrWhiteSpace(serverId) && string.IsNullOrWhiteSpace(serverName) && string.IsNullOrWhiteSpace(externalIp))
		{
			return true;
		}
		string recordOwner = NormalizeTrustOwnerKey(record.ownerKey, record.userName);
		if (!string.IsNullOrWhiteSpace(ownerKey) && string.Equals(recordOwner, ownerKey, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		if (!string.IsNullOrWhiteSpace(serverId) && string.Equals((record.serverId ?? "").Trim(), serverId, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		if (!string.IsNullOrWhiteSpace(serverName) && string.Equals((record.serverName ?? "").Trim(), serverName, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		if (!string.IsNullOrWhiteSpace(externalIp) && string.Equals(NormalizeTrustEndpoint(record.externalIp), externalIp, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		return false;
	}

	private string BuildTrustReputationTier(int score, int openCases, bool suspended)
	{
		if (suspended || score < 30)
		{
			return "Blocked";
		}
		if (score < 55 || openCases >= 3)
		{
			return "At Risk";
		}
		if (score < 80 || openCases > 0)
		{
			return "Review";
		}
		if (score >= 95)
		{
			return "Excellent";
		}
		return "Good";
	}

	private int CalculateTrustRiskScore(TrustAbuseSummarySnapshot summary)
	{
		summary = summary ?? new TrustAbuseSummarySnapshot();
		if (summary.HostSuspended)
		{
			return 100;
		}
		int risk = 0;
		risk += Math.Min(35, summary.OpenCases * 7);
		risk += Math.Min(30, summary.HighOpenCases * 10 + summary.CriticalOpenCases * 15);
		risk += Math.Min(12, summary.StaleOpenCases * 4);
		risk += Math.Max(0, 100 - summary.ReputationScore) / 3;
		if (summary.CommandsBlocked)
		{
			risk += 18;
		}
		if (!summary.HostVerified && summary.HostVerificationCount == 0)
		{
			risk += 6;
		}
		return Math.Max(0, Math.Min(100, risk));
	}

	private static string BuildTrustRiskTier(int riskScore, bool suspended)
	{
		if (suspended || riskScore >= 85)
		{
			return "Blocked";
		}
		if (riskScore >= 60)
		{
			return "High";
		}
		if (riskScore >= 30)
		{
			return "Watch";
		}
		return "Low";
	}

	private TrustAbuseCaseSnapshot ReadTrustAbuseCaseSnapshot(JsonElement root, NetworkConnection connection, HttpRequest request, WebAuthPrincipal principal)
	{
		string userName = ExtractStringProperty(root, "userName") ?? ExtractStringProperty(root, "username") ?? ExtractStringProperty(root, "ownerUserName") ?? "";
		string ownerKey = ExtractStringProperty(root, "ownerKey") ?? "";
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			ownerKey = NormalizeTrustOwnerKey("", userName);
		}
		if (string.IsNullOrWhiteSpace(userName))
		{
			userName = NormalizeTrustUserName("", ownerKey);
		}
		string reporter = principal?.UserName ?? "";
		string reporterOwner = (string.IsNullOrWhiteSpace(reporter) ? GetChatSessionOwnerKey(connection, request) : ("webauth:" + reporter.Trim().ToLowerInvariant()));
		return new TrustAbuseCaseSnapshot
		{
			Category = (ExtractStringProperty(root, "category") ?? ExtractStringProperty(root, "type") ?? "dispute"),
			Severity = (ExtractStringProperty(root, "severity") ?? "medium"),
			Status = (ExtractStringProperty(root, "status") ?? "open"),
			SubjectType = (ExtractStringProperty(root, "subjectType") ?? ""),
			SubjectId = (ExtractStringProperty(root, "subjectId") ?? ""),
			OwnerKey = ownerKey,
			UserName = userName,
			ServerId = (ExtractStringProperty(root, "serverId") ?? ""),
			ServerName = (ExtractStringProperty(root, "serverName") ?? ExtractStringProperty(root, "title") ?? ""),
			ExternalIp = (ExtractStringProperty(root, "externalIp") ?? ExtractStringProperty(root, "ip") ?? ExtractStringProperty(root, "connectHost") ?? ""),
			ReporterOwnerKey = (ExtractStringProperty(root, "reporterOwnerKey") ?? reporterOwner),
			ReporterUserName = (ExtractStringProperty(root, "reporterUserName") ?? reporter),
			Summary = (ExtractStringProperty(root, "summary") ?? ""),
			Detail = (ExtractStringProperty(root, "detail") ?? ExtractStringProperty(root, "description") ?? ""),
			EvidenceJson = ExtractEvidenceJson(root),
			Command = (ExtractStringProperty(root, "command") ?? ""),
			Path = (ExtractStringProperty(root, "path") ?? ExtractStringProperty(root, "filePath") ?? ""),
			ReputationDelta = ReadTrustReputationDelta(root)
		};
	}

	private string ExtractEvidenceJson(JsonElement root)
	{
		if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty("evidence", out var evidence) && evidence.ValueKind != JsonValueKind.Undefined && evidence.ValueKind != JsonValueKind.Null)
		{
			return evidence.GetRawText();
		}
		return ExtractStringProperty(root, "evidenceJson") ?? "";
	}

	private int ReadTrustReputationDelta(JsonElement root)
	{
		if (root.ValueKind != JsonValueKind.Object)
		{
			return 0;
		}
		if (root.TryGetProperty("reputationDelta", out var delta))
		{
			return ReadJsonInt(delta, 0);
		}
		if (root.TryGetProperty("delta", out var shortDelta))
		{
			return ReadJsonInt(shortDelta, 0);
		}
		return 0;
	}

	private string NormalizeTrustCategory(string category)
	{
		switch (NormalizeTrustToken(category))
		{
		case "host":
		case "hostverify":
		case "hostverification":
		case "verification":
			return "host_verification";
		case "identity":
		case "renter":
		case "renteridentity":
			return "renter_identity";
		case "content":
		case "contentabuse":
			return "content_abuse";
		case "command":
		case "commandabuse":
		case "terminal":
			return "command_abuse";
		case "reputation":
			return "reputation";
		default:
			return "dispute";
		}
	}

	private string NormalizeTrustSeverity(string severity)
	{
		string value = NormalizeTrustToken(severity);
		switch (value)
		{
		default:
			if (!(value == "low"))
			{
				return "medium";
			}
			goto case "critical";
		case "critical":
		case "high":
		case "medium":
			return value;
		}
	}

	private string NormalizeTrustStatus(string status, string fallback)
	{
		string value = NormalizeTrustToken(status);
		switch (value)
		{
		case "verified":
			return "verified";
		case "identityverified":
			return "identity_verified";
		default:
			if (!(value == "suspended"))
			{
				return string.IsNullOrWhiteSpace(fallback) ? "open" : fallback;
			}
			goto case "closed";
		case "closed":
		case "resolved":
		case "dismissed":
		case "open":
		case "pending":
		case "investigating":
			return value;
		}
	}

	private string NormalizeTrustIntervention(string intervention)
	{
		string value = NormalizeTrustToken(intervention);
		switch (value)
		{
		case "verifyhost":
		case "hostverified":
			return "verify_host";
		case "verifyrenter":
		case "identityverified":
			return "verify_renter";
		case "requesthostverification":
			return "request_host_verification";
		case "suspendhost":
			return "suspend_host";
		case "muterenter":
		case "mute":
			return "mute_renter";
		case "banrenter":
		case "ban":
			return "ban_renter";
		case "blockcommands":
		case "terminalblock":
			return "block_commands";
		case "dismiss":
		case "dismissed":
			return "dismiss";
		case "resolve":
		case "resolved":
		case "close":
		case "closed":
			return "resolve";
		default:
			return string.IsNullOrWhiteSpace(value) ? "note" : value;
		}
	}

	private string StatusForTrustIntervention(string intervention, string currentStatus)
	{
		intervention = NormalizeTrustIntervention(intervention);
		switch (intervention)
		{
		case "verify_host":
			return "verified";
		case "verify_renter":
			return "identity_verified";
		case "dismiss":
			return "dismissed";
		case "resolve":
			return "resolved";
		default:
			if (!(intervention == "ban_renter"))
			{
				return NormalizeTrustStatus(currentStatus, "open");
			}
			goto case "suspend_host";
		case "suspend_host":
		case "block_commands":
		case "mute_renter":
			return "investigating";
		}
	}

	private bool IsOpenTrustStatus(string status)
	{
		string value = NormalizeTrustStatus(status, "open");
		int result;
		switch (value)
		{
		default:
			result = ((value == "suspended") ? 1 : 0);
			break;
		case "open":
		case "pending":
		case "investigating":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private string NormalizeTrustOwnerKey(string ownerKey, string userName)
	{
		string value = (ownerKey ?? "").Trim();
		if (!string.IsNullOrWhiteSpace(value))
		{
			return NormalizeChatFilesystemOwnerKey(value);
		}
		userName = (userName ?? "").Trim();
		return string.IsNullOrWhiteSpace(userName) ? "" : ("webauth:" + userName.ToLowerInvariant());
	}

	private string NormalizeTrustUserName(string userName, string ownerKey)
	{
		userName = (userName ?? "").Trim();
		if (!string.IsNullOrWhiteSpace(userName))
		{
			return userName;
		}
		ownerKey = (ownerKey ?? "").Trim();
		if (ownerKey.StartsWith("webauth:", StringComparison.OrdinalIgnoreCase))
		{
			return ownerKey.Substring("webauth:".Length).Trim();
		}
		return "";
	}

	private string NormalizeTrustEndpoint(string value)
	{
		value = (value ?? "").Trim();
		if (Uri.TryCreate(value, UriKind.Absolute, out Uri uri) && !string.IsNullOrWhiteSpace(uri.Host))
		{
			return uri.Host.Trim().ToLowerInvariant();
		}
		return value.ToLowerInvariant();
	}

	private string NormalizeTrustToken(string value)
	{
		value = (value ?? "").Trim().ToLowerInvariant();
		StringBuilder builder = new StringBuilder(value.Length);
		string text = value;
		foreach (char c in text)
		{
			if (char.IsLetterOrDigit(c))
			{
				builder.Append(c);
			}
		}
		return builder.ToString();
	}

	private int CalculateDefaultTrustReputationDelta(TrustAbuseCaseRecord record)
	{
		string category = NormalizeTrustCategory(record?.category);
		string severity = NormalizeTrustSeverity(record?.severity);
		string intervention = NormalizeTrustIntervention(record?.intervention);
		if (intervention == "verify_host" || intervention == "verify_renter")
		{
			return 5;
		}
		if (category == "host_verification" || category == "renter_identity")
		{
			return 0;
		}
		int delta = category switch
		{
			"reputation" => -5, 
			"dispute" => -10, 
			"content_abuse" => -12, 
			"command_abuse" => -16, 
			_ => -8, 
		};
		switch (severity)
		{
		case "critical":
			delta -= 16;
			break;
		case "high":
			delta -= 8;
			break;
		case "low":
			delta += 4;
			break;
		}
		return delta;
	}

	private string BuildTrustSubjectLabel(TrustAbuseCaseRecord record)
	{
		if (record == null)
		{
			return "unknown subject";
		}
		if (!string.IsNullOrWhiteSpace(record.userName))
		{
			return record.userName;
		}
		if (!string.IsNullOrWhiteSpace(record.ownerKey))
		{
			return record.ownerKey;
		}
		if (!string.IsNullOrWhiteSpace(record.serverName))
		{
			return record.serverName;
		}
		if (!string.IsNullOrWhiteSpace(record.serverId))
		{
			return record.serverId;
		}
		if (!string.IsNullOrWhiteSpace(record.externalIp))
		{
			return record.externalIp;
		}
		return "unknown subject";
	}

	private void ApplyTrustAbuseRuntimeIntervention(TrustAbuseCaseRecord record)
	{
		if (record == null)
		{
			return;
		}
		string ownerKey = NormalizeTrustOwnerKey(record.ownerKey, record.userName);
		if (!string.IsNullOrWhiteSpace(ownerKey))
		{
			switch (NormalizeTrustIntervention(record.intervention))
			{
			case "mute_renter":
				RestrictChatClient(ownerKey, "mute", null);
				break;
			case "ban_renter":
				RestrictChatClient(ownerKey, "ban", null);
				break;
			case "block_commands":
			{
				ChatPermissionState permissions = GetChatPermissions(ownerKey);
				permissions.terminalCommands = false;
				permissions.terminalForeverApproved = false;
				SaveChatPermissions(ownerKey, permissions);
				ApplyRuntimeChatPermissions(GetChatPermissions());
				break;
			}
			}
		}
	}

