	private bool TryDetectHighRiskTerminalCommand(string command, out string reason)
	{
		reason = "";
		string normalized = (" " + (command ?? "").Trim().ToLowerInvariant() + " ").Replace("\r", " ").Replace("\n", " ");
		if (string.IsNullOrWhiteSpace(normalized))
		{
			return false;
		}
		if (normalized.Contains(" remove-item ", StringComparison.Ordinal) && normalized.Contains(" -recurse", StringComparison.Ordinal) && (normalized.Contains(" c:\\", StringComparison.Ordinal) || normalized.Contains(" $env:userprofile", StringComparison.Ordinal)))
		{
			reason = "recursive Remove-Item against a broad Windows root";
		}
		else if (normalized.Contains(" del ", StringComparison.Ordinal) && normalized.Contains(" /s", StringComparison.Ordinal) && normalized.Contains(" c:\\", StringComparison.Ordinal))
		{
			reason = "recursive delete against a broad Windows root";
		}
		else if (normalized.Contains(" format ", StringComparison.Ordinal) || normalized.Contains(" clear-disk ", StringComparison.Ordinal) || normalized.Contains(" diskpart ", StringComparison.Ordinal))
		{
			reason = "disk formatting or partition management command";
		}
		else if ((normalized.Contains(" invoke-webrequest ", StringComparison.Ordinal) || normalized.Contains(" iwr ", StringComparison.Ordinal) || normalized.Contains(" curl ", StringComparison.Ordinal)) && (normalized.Contains(" iex", StringComparison.Ordinal) || normalized.Contains(" invoke-expression", StringComparison.Ordinal)))
		{
			reason = "download-and-execute command chain";
		}
		else if (normalized.Contains(" set-mppreference ", StringComparison.Ordinal) && normalized.Contains(" disablerealtimemonitoring", StringComparison.Ordinal))
		{
			reason = "attempt to disable Windows Defender real-time monitoring";
		}
		else if (normalized.Contains(" net user ", StringComparison.Ordinal) && (normalized.Contains(" /add", StringComparison.Ordinal) || normalized.Contains(" /delete", StringComparison.Ordinal)))
		{
			reason = "local account mutation command";
		}
		return !string.IsNullOrWhiteSpace(reason);
	}

