	private WebAuthUserDiagnosticsSnapshot WebAuthUserDiagnosticsSnapshotFromRecord(WebAuthRecord record)
	{
		record = record ?? new WebAuthRecord();
		long tokenLimit = Math.Max(0L, record.tokenLimit);
		long tokensUsed = Math.Max(0L, record.tokensUsed);
		bool unlimited = tokenLimit <= 0;
		string ownerKey = (string.IsNullOrWhiteSpace(record.userName) ? "" : ("webauth:" + record.userName.Trim().ToLowerInvariant()));
		ChatPermissionState permissions = (string.IsNullOrWhiteSpace(ownerKey) ? new ChatPermissionState() : GetChatPermissions(ownerKey));
		return new WebAuthUserDiagnosticsSnapshot
		{
			UserName = (record.userName ?? ""),
			OwnerKey = ownerKey,
			Enabled = record.enabled,
			IsAdministrator = record.isAdministrator,
			LastClientIp = (record.lastClientIp ?? ""),
			CreatedUtc = (record.createdUtc ?? ""),
			UpdatedUtc = (record.updatedUtc ?? ""),
			LastLoginUtc = (record.lastLoginUtc ?? ""),
			TokenLimit = tokenLimit,
			TokensUsed = tokensUsed,
			TokensRemaining = (unlimited ? 0 : Math.Max(0L, tokenLimit - tokensUsed)),
			Unlimited = unlimited,
			MutedUntilUtc = (permissions.mutedUntilUtc ?? ""),
			BannedUntilUtc = (permissions.bannedUntilUtc ?? ""),
			MuteUntilEnabled = permissions.muteUntilEnabled,
			BanUntilEnabled = permissions.banUntilEnabled,
			IsMuted = IsChatMuted(permissions),
			IsBanned = IsChatBanned(permissions)
		};
	}

	private ChatUsageDiagnosticsSnapshot BuildChatUsageDiagnosticsSnapshot(ChatUsageSnapshot usage)
	{
		usage = usage ?? BuildAnonymousChatUsageSnapshot();
		double multiplier = ((usage.electricityMultiplier <= 0.0) ? 1.0 : usage.electricityMultiplier);
		double cpuBillableSeconds = usage.cpuComputeSecondsUsed / (double)Math.Max(1, Environment.ProcessorCount);
		double ioGbpsSeconds = NormalizeCostNumber((double)Math.Max(0L, usage.ioBytesProcessed) * 8.0 / 1000000000.0);
		double gpuKwh = CalculateUsageKwh(usage.gpuTdpWatts, usage.gpuSecondsUsed, multiplier);
		double cpuKwh = CalculateUsageKwh(usage.cpuTdpWatts, cpuBillableSeconds, multiplier);
		double ramKwh = CalculateUsageKwh(usage.ramWattsPerGb, usage.ramGbSecondsUsed, multiplier);
		double systemKwh = CalculateUsageKwh(usage.systemWatts, usage.systemSecondsUsed, multiplier);
		double ioKwh = CalculateUsageKwh(usage.ioWattsPerGbps, ioGbpsSeconds, multiplier);
		return new ChatUsageDiagnosticsSnapshot
		{
			OwnerKey = (usage.ownerKey ?? ""),
			UserName = (usage.username ?? ""),
			Authenticated = usage.authenticated,
			Unlimited = usage.unlimited,
			TokensRequired = usage.tokensRequired,
			TokensUsed = Math.Max(0L, usage.tokensUsed),
			TokenLimit = Math.Max(0L, usage.tokenLimit),
			TokensRemaining = Math.Max(0L, usage.tokensRemaining),
			GpuSecondsUsed = NormalizeCostNumber(usage.gpuSecondsUsed),
			CpuComputeSecondsUsed = NormalizeCostNumber(usage.cpuComputeSecondsUsed),
			RamGbSecondsUsed = NormalizeCostNumber(usage.ramGbSecondsUsed),
			SystemSecondsUsed = NormalizeCostNumber(usage.systemSecondsUsed),
			IoBytesProcessed = Math.Max(0L, usage.ioBytesProcessed),
			GpuKw = NormalizeCostNumber(Math.Max(0.0, usage.gpuTdpWatts) / 1000.0),
			CpuKw = NormalizeCostNumber(Math.Max(0.0, usage.cpuTdpWatts) / 1000.0),
			GpuKwh = gpuKwh,
			CpuKwh = cpuKwh,
			RamKwh = ramKwh,
			SystemKwh = systemKwh,
			IoKwh = ioKwh,
			TotalKwh = NormalizeCostNumber(gpuKwh + cpuKwh + ramKwh + systemKwh + ioKwh),
			TokenCostUsd = usage.tokenCostUsd,
			ElectricityCostUsd = usage.electricityCostUsd,
			GpuElectricityCostUsd = usage.gpuElectricityCostUsd,
			CpuElectricityCostUsd = usage.cpuElectricityCostUsd,
			RamElectricityCostUsd = usage.ramElectricityCostUsd,
			SystemElectricityCostUsd = usage.systemElectricityCostUsd,
			IoElectricityCostUsd = usage.ioElectricityCostUsd,
			ServiceTaxCostUsd = usage.serviceTaxCostUsd,
			StorageCostUsd = usage.storageCostUsd,
			TotalCostUsd = usage.totalCostUsd,
			TokenUsdPerToken = usage.tokenUsdPerToken,
			ElectricityCentsPerKwh = usage.electricityCentsPerKwh,
			ElectricityMultiplier = usage.electricityMultiplier,
			GpuTdpWatts = usage.gpuTdpWatts,
			CpuTdpWatts = usage.cpuTdpWatts,
			RamWattsPerGb = usage.ramWattsPerGb,
			SystemWatts = usage.systemWatts,
			IoWattsPerGbps = usage.ioWattsPerGbps,
			RamGbEstimated = usage.ramGbEstimated,
			StorageBytesUsed = usage.storageBytesUsed,
			StorageLimitBytes = usage.storageLimitBytes,
			StorageBytesRemaining = usage.storageBytesRemaining,
			StorageUnlimited = usage.storageUnlimited,
			CurrentSessionStorageBytes = usage.currentSessionStorageBytes,
			CurrentSessionId = (usage.currentSessionId ?? ""),
			StorageType = (usage.storageType ?? ""),
			CostSettingsTable = (usage.costSettingsTable ?? "")
		};
	}

	private double CalculateUsageKwh(double watts, double seconds, double multiplier)
	{
		watts = Math.Max(0.0, watts);
		seconds = Math.Max(0.0, seconds);
		multiplier = ((multiplier <= 0.0) ? 1.0 : multiplier);
		return NormalizeCostNumber(watts * seconds * multiplier / 3600000.0);
	}

	private string GetServerUsageDisplayName(string ownerKey)
	{
		ownerKey = (ownerKey ?? "").Trim();
		string username = GetUserNameFromOwnerKey(ownerKey);
		if (!string.IsNullOrWhiteSpace(username))
		{
			return username;
		}
		string ip = DisplayIpFromOwnerKey(ownerKey);
		if (!string.IsNullOrWhiteSpace(ip))
		{
			return IsLoopbackClientIp(ip) ? "Localhost" : ("IP " + ip);
		}
		return string.IsNullOrWhiteSpace(ownerKey) ? "Unknown user" : ownerKey;
	}

	private string GetServerUsageUserType(string ownerKey)
	{
		ownerKey = (ownerKey ?? "").Trim();
		if (ownerKey.StartsWith("webauth:", StringComparison.OrdinalIgnoreCase))
		{
			return "webauth";
		}
		if (ownerKey.StartsWith("ip:", StringComparison.OrdinalIgnoreCase))
		{
			return IsAdminOwnerKey(ownerKey) ? "local" : "ip";
		}
		return string.IsNullOrWhiteSpace(ownerKey) ? "unknown" : "owner";
	}

	private static bool IsLaterIsoUtc(string candidateUtc, string currentUtc)
	{
		if (string.IsNullOrWhiteSpace(candidateUtc))
		{
			return false;
		}
		if (string.IsNullOrWhiteSpace(currentUtc))
		{
			return true;
		}
		if (DateTimeOffset.TryParse(candidateUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out var candidate) && DateTimeOffset.TryParse(currentUtc, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out var current))
		{
			return candidate.ToUniversalTime() > current.ToUniversalTime();
		}
		return string.CompareOrdinal(candidateUtc, currentUtc) > 0;
	}

	private WebAuthRegistrationRequestRecord SaveWebAuthRegistrationRequest(string username, string password, string clientIp)
	{
		byte[] salt = GenerateRandomBytes(16);
		string now = DateTimeOffset.UtcNow.ToString("O");
		string passwordSalt = Convert.ToBase64String(salt);
		string passwordHash = HashWebAuthPassword(password, salt);
		clientIp = (string.IsNullOrWhiteSpace(clientIp) ? "" : NormalizeClientIp(clientIp));
		lock (_chatSessionLock)
		{
			Table table = GetWebAuthRegistrationRequestsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				WebAuthRegistrationRequestRecord existing = WebAuthRegistrationRequestRecordFromRow(table.Rows[i]);
				if (existing.status.Equals("pending", StringComparison.OrdinalIgnoreCase) && string.Equals(existing.userName, username, StringComparison.OrdinalIgnoreCase))
				{
					existing.passwordSalt = passwordSalt;
					existing.passwordHash = passwordHash;
					existing.clientIp = clientIp;
					existing.requestedUtc = now;
					existing.note = "Updated pending request.";
					table.Rows[i] = WebAuthRegistrationRequestRecordToRow(existing);
					SaveChatSessionDataAndInvalidateCaches();
					return existing;
				}
			}
			WebAuthRegistrationRequestRecord record = new WebAuthRegistrationRequestRecord
			{
				id = "regreq_" + Guid.NewGuid().ToString("N"),
				userName = username,
				passwordSalt = passwordSalt,
				passwordHash = passwordHash,
				clientIp = clientIp,
				status = "pending",
				requestedUtc = now,
				decidedUtc = "",
				decidedBy = "",
				note = ""
			};
			table.Rows.Add(WebAuthRegistrationRequestRecordToRow(record));
			SaveChatSessionDataAndInvalidateCaches();
			return record;
		}
	}

	private WebAuthRegistrationRequestRecord DecideWebAuthRegistrationRequest(string requestId, bool approved, string decidedBy, string note)
	{
		if (string.IsNullOrWhiteSpace(requestId))
		{
			throw new InvalidOperationException("Registration request id is required.");
		}
		lock (_chatSessionLock)
		{
			Table requestTable = GetWebAuthRegistrationRequestsTable();
			for (int i = 0; i < requestTable.Rows.Count; i++)
			{
				WebAuthRegistrationRequestRecord request = WebAuthRegistrationRequestRecordFromRow(requestTable.Rows[i]);
				if (!string.Equals(request.id, requestId, StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				if (!request.status.Equals("pending", StringComparison.OrdinalIgnoreCase))
				{
					throw new InvalidOperationException("Registration request has already been decided.");
				}
				if (approved)
				{
					if (GetWebAuthRecord(request.userName) != null)
					{
						throw new InvalidOperationException("A WebAuth user with that name already exists.");
					}
					string now = DateTimeOffset.UtcNow.ToString("O");
					WebAuthRecord user = new WebAuthRecord
					{
						userName = request.userName,
						passwordSalt = request.passwordSalt,
						passwordHash = request.passwordHash,
						createdUtc = now,
						updatedUtc = now,
						lastLoginUtc = "",
						tokenHash = "",
						tokenExpiresUtc = "",
						enabled = true,
						lastClientIp = request.clientIp,
						tokenLimit = 0L,
						tokensUsed = 0L
					};
					SaveWebAuthRecord(user, overwrite: false);
					LinkWebAuthUserToIp(user.userName, request.clientIp);
				}
				request.status = (approved ? "approved" : "denied");
				request.decidedUtc = DateTimeOffset.UtcNow.ToString("O");
				request.decidedBy = (string.IsNullOrWhiteSpace(decidedBy) ? "admin" : decidedBy);
				request.note = note ?? "";
				requestTable.Rows[i] = WebAuthRegistrationRequestRecordToRow(request);
				SaveChatSessionDataAndInvalidateCaches();
				return request;
			}
		}
		throw new InvalidOperationException("Registration request was not found or is no longer pending.");
	}

	private TokenRateRequestRecord FindPendingTokenRateRequestForOwner(string ownerKey)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		if (string.IsNullOrWhiteSpace(ownerKey))
		{
			return null;
		}
		lock (_chatSessionLock)
		{
			Table table = GetTokenRateRequestsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				TokenRateRequestRecord record = TokenRateRequestRecordFromRow(sourceRow);
				if (record.status.Equals("pending", StringComparison.OrdinalIgnoreCase) && string.Equals(record.ownerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
				{
					return record;
				}
			}
		}
		return null;
	}

	private TokenRateRequestRecord SaveTokenRateRequest(string username, string ownerKey, string clientIp, long requestedTokenRate, long advertisedTokenRate, long minTokenRate, long maxTokenRate)
	{
		string now = DateTimeOffset.UtcNow.ToString("O");
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		lock (_chatSessionLock)
		{
			Table table = GetTokenRateRequestsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				TokenRateRequestRecord existing = TokenRateRequestRecordFromRow(table.Rows[i]);
				if (existing.status.Equals("pending", StringComparison.OrdinalIgnoreCase) && string.Equals(existing.ownerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
				{
					existing.userName = username ?? existing.userName;
					existing.clientIp = clientIp ?? existing.clientIp;
					existing.requestedTokenRate = Math.Max(0L, requestedTokenRate);
					existing.advertisedTokenRate = Math.Max(0L, advertisedTokenRate);
					existing.minTokenRate = Math.Max(0L, minTokenRate);
					existing.maxTokenRate = Math.Max(existing.minTokenRate, maxTokenRate);
					existing.requestedUtc = now;
					existing.note = "Updated pending request.";
					table.Rows[i] = TokenRateRequestRecordToRow(existing);
					RecordFinanceTokenOperation(ownerKey, "token_rate_request", requestedTokenRate, 0.0, 0.0, 0.0, 0.0, "Updated pending token-rate request.");
					SaveChatSessionDataAndInvalidateCaches();
					return existing;
				}
			}
			TokenRateRequestRecord record = new TokenRateRequestRecord
			{
				id = "tokrate_" + Guid.NewGuid().ToString("N"),
				userName = (username ?? ""),
				ownerKey = ownerKey,
				clientIp = (clientIp ?? ""),
				requestedTokenRate = Math.Max(0L, requestedTokenRate),
				advertisedTokenRate = Math.Max(0L, advertisedTokenRate),
				minTokenRate = Math.Max(0L, minTokenRate),
				maxTokenRate = Math.Max(Math.Max(0L, minTokenRate), maxTokenRate),
				status = "pending",
				requestedUtc = now,
				decidedUtc = "",
				decidedBy = "",
				note = ""
			};
			table.Rows.Add(TokenRateRequestRecordToRow(record));
			RecordFinanceTokenOperation(ownerKey, "token_rate_request", requestedTokenRate, 0.0, 0.0, 0.0, 0.0, "Created token-rate request.");
			SaveChatSessionDataAndInvalidateCaches();
			return record;
		}
	}

	private TokenRateRequestRecord DecideTokenRateRequest(string requestId, bool approved, string decidedBy, string note)
	{
		if (string.IsNullOrWhiteSpace(requestId))
		{
			throw new InvalidOperationException("Token-rate request id is required.");
		}
		lock (_chatSessionLock)
		{
			Table requestTable = GetTokenRateRequestsTable();
			for (int i = 0; i < requestTable.Rows.Count; i++)
			{
				TokenRateRequestRecord request = TokenRateRequestRecordFromRow(requestTable.Rows[i]);
				if (!string.Equals(request.id, requestId, StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				if (!request.status.Equals("pending", StringComparison.OrdinalIgnoreCase))
				{
					throw new InvalidOperationException("Token-rate request has already been decided.");
				}
				if (approved && StoreLocalWebAuthAccounts)
				{
					WebAuthRecord user = GetWebAuthRecord(request.userName);
					if (user == null)
					{
						throw new InvalidOperationException("WebAuth user was not found for this token-rate request.");
					}
					user.tokenLimit = Math.Max(0L, request.requestedTokenRate);
					user.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
					UpsertWebAuthRecord(user);
				}
				request.status = (approved ? "approved" : "denied");
				request.decidedUtc = DateTimeOffset.UtcNow.ToString("O");
				request.decidedBy = (string.IsNullOrWhiteSpace(decidedBy) ? "admin" : decidedBy.Trim());
				request.note = note ?? "";
				requestTable.Rows[i] = TokenRateRequestRecordToRow(request);
				RecordFinanceTokenOperation(request.ownerKey, approved ? "token_rate_approved" : "token_rate_denied", request.requestedTokenRate, 0.0, 0.0, 0.0, 0.0, request.note);
				SaveChatSessionDataAndInvalidateCaches();
				return request;
			}
		}
		throw new InvalidOperationException("Token-rate request was not found or is no longer pending.");
	}

	private FinanceIdentity GetFinanceIdentity(NetworkConnection connection, HttpRequest request)
	{
		FinanceIdentity identity = new FinanceIdentity();
		identity.IsAdmin = IsDatabaseAdministrator(connection, request);
		if (TryAuthenticateWebAuthRequest(request, out var principal, out var _) && principal != null && !string.IsNullOrWhiteSpace(principal.UserName))
		{
			identity.Authenticated = true;
			identity.UserName = principal.UserName.Trim();
			identity.OwnerKey = "webauth:" + identity.UserName.ToLowerInvariant();
			identity.AuthType = principal.AuthType ?? "";
			return identity;
		}
		identity.OwnerKey = GetChatSessionOwnerKey(connection, request);
		identity.UserName = (IsAdminOwnerKey(identity.OwnerKey) ? "localhost" : GetUserNameFromOwnerKey(identity.OwnerKey));
		if (string.IsNullOrWhiteSpace(identity.UserName))
		{
			identity.UserName = "Guest";
		}
		identity.AuthType = (identity.IsAdmin ? "LocalAdmin" : "");
		return identity;
	}

	private FinancePeriod ReadFinancePeriod(HttpRequest request)
	{
		string period = (GetQueryParameter(request, "period") ?? "30d").Trim().ToLowerInvariant();
		DateTimeOffset end = DateTimeOffset.UtcNow;
		DateTimeOffset start;
		switch (period)
		{
		case "7d":
			start = end.AddDays(-7.0);
			break;
		case "90d":
			start = end.AddDays(-90.0);
			break;
		case "ytd":
			start = new DateTimeOffset(end.Year, 1, 1, 0, 0, 0, TimeSpan.Zero);
			break;
		default:
			if (!(period == "1y"))
			{
				if (period == "all")
				{
					start = DateTimeOffset.MinValue;
					break;
				}
				period = "30d";
				start = end.AddDays(-30.0);
				break;
			}
			goto case "12m";
		case "12m":
			start = end.AddYears(-1);
			break;
		}
		string startQuery = GetQueryParameter(request, "startUtc") ?? GetQueryParameter(request, "from");
		string endQuery = GetQueryParameter(request, "endUtc") ?? GetQueryParameter(request, "to");
		if (!string.IsNullOrWhiteSpace(startQuery) && DateTimeOffset.TryParse(startQuery, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out var parsedStart))
		{
			start = parsedStart.ToUniversalTime();
		}
		if (!string.IsNullOrWhiteSpace(endQuery) && DateTimeOffset.TryParse(endQuery, CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out var parsedEnd))
		{
			end = parsedEnd.ToUniversalTime();
		}
		if (end < start)
		{
			DateTimeOffset temp = start;
			start = end;
			end = temp;
		}
		return new FinancePeriod
		{
			Key = period,
			StartUtc = start,
			EndUtc = end
		};
	}

	private FinanceAccountProfile GetOrCreateFinanceAccountProfile(string ownerKey, string username)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		string now = DateTimeOffset.UtcNow.ToString("O");
		lock (_chatSessionLock)
		{
			Table table = GetFinanceProfilesTable();
			foreach (object[] sourceRow in table.Rows)
			{
				FinanceAccountProfile profile = FinanceAccountProfileFromRow(sourceRow);
				if (string.Equals(profile.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase))
				{
					return profile;
				}
			}
			FinanceAccountProfile created = new FinanceAccountProfile
			{
				OwnerKey = ownerKey,
				UserName = (username ?? GetUserNameFromOwnerKey(ownerKey)),
				TaxCountry = "US",
				CreatedUtc = now,
				UpdatedUtc = now
			};
			table.Rows.Add(FinanceAccountProfileToRow(created));
			SaveChatSessionDataAndInvalidateCaches();
			return created;
		}
	}

	private void UpsertFinanceAccountProfile(FinanceAccountProfile profile)
	{
		if (profile == null)
		{
			return;
		}
		profile.OwnerKey = NormalizeCostOwnerKey(profile.OwnerKey);
		lock (_chatSessionLock)
		{
			Table table = GetFinanceProfilesTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				FinanceAccountProfile existing = FinanceAccountProfileFromRow(table.Rows[i]);
				if (string.Equals(existing.OwnerKey, profile.OwnerKey, StringComparison.OrdinalIgnoreCase))
				{
					table.Rows[i] = FinanceAccountProfileToRow(profile);
					SaveChatSessionDataAndInvalidateCaches();
					return;
				}
			}
			table.Rows.Add(FinanceAccountProfileToRow(profile));
			SaveChatSessionDataAndInvalidateCaches();
		}
	}

	private FinanceDashboard BuildFinanceDashboard(FinanceIdentity identity, FinancePeriod period, string sort, bool descending)
	{
		List<FinancePaymentRecord> payments = ListFinancePayments(identity, period);
		List<FinancePayoutRecord> payouts = ListFinancePayouts(identity, period);
		List<FinanceTokenOperationRecord> operations = ListFinanceTokenOperations(identity, period);
		FinanceMoneySummary summary = SummarizeFinanceOperations(operations);
		double pendingNet = payouts.Where((FinancePayoutRecord p) => IsPendingFinancePayoutStatus(p.Status)).Sum((FinancePayoutRecord p) => (p.PayoutAmountUsd > 0.0) ? p.PayoutAmountUsd : p.NetUsd);
		double paidNet = payouts.Where((FinancePayoutRecord p) => IsPaidFinancePayoutStatus(p.Status)).Sum((FinancePayoutRecord p) => (p.PayoutAmountUsd > 0.0) ? p.PayoutAmountUsd : p.NetUsd);
		double cancelledNet = payouts.Where((FinancePayoutRecord p) => IsTerminalFailedFinancePayoutStatus(p.Status)).Sum((FinancePayoutRecord p) => (p.PayoutAmountUsd > 0.0) ? p.PayoutAmountUsd : p.NetUsd);
		double paidCheckout = (double)payments.Where((FinancePaymentRecord p) => p.Status.Equals("paid", StringComparison.OrdinalIgnoreCase)).Sum((FinancePaymentRecord p) => p.AmountCents) / 100.0;
		double pendingCheckout = (double)payments.Where((FinancePaymentRecord p) => p.Status.Equals("created", StringComparison.OrdinalIgnoreCase) || p.Status.Equals("pending", StringComparison.OrdinalIgnoreCase)).Sum((FinancePaymentRecord p) => p.AmountCents) / 100.0;
		double disputedCheckout = (double)payments.Where((FinancePaymentRecord p) => p.Status.Equals("disputed", StringComparison.OrdinalIgnoreCase) || p.Status.Equals("refunded", StringComparison.OrdinalIgnoreCase)).Sum((FinancePaymentRecord p) => p.AmountCents) / 100.0;
		IEnumerable<FinancePayoutRecord> ordered = payouts;
		ordered = ((sort == "amount") ? (descending ? payouts.OrderByDescending((FinancePayoutRecord p) => p.NetUsd) : payouts.OrderBy((FinancePayoutRecord p) => p.NetUsd)) : ((!(sort == "status")) ? (descending ? payouts.OrderByDescending((FinancePayoutRecord p) => p.RequestedUtc) : payouts.OrderBy((FinancePayoutRecord p) => p.RequestedUtc)) : (descending ? payouts.OrderByDescending((FinancePayoutRecord p) => p.Status) : payouts.OrderBy((FinancePayoutRecord p) => p.Status))));
		List<object> list = new List<object>();
		list.Add(new
		{
			id = "profit",
			title = "Profit margin",
			slices = BuildPieSlices(new FinancePiePart[3]
			{
				new FinancePiePart("Net payout", Math.Max(0.0, summary.NetUsd)),
				new FinancePiePart("SocketJack fee", Math.Max(0.0, summary.SocketJackFeeUsd)),
				new FinancePiePart("Energy and service cost", Math.Max(0.0, summary.ElectricityCostUsd + summary.ServiceTaxCostUsd))
			})
		});
		list.Add(new
		{
			id = "costs",
			title = "Billing cost mix",
			slices = BuildPieSlices(new FinancePiePart[3]
			{
				new FinancePiePart("Token revenue", summary.TokenCostUsd),
				new FinancePiePart("Electricity", summary.ElectricityCostUsd),
				new FinancePiePart("Service fee", summary.ServiceTaxCostUsd)
			})
		});
		list.Add(new
		{
			id = "payoutStatus",
			title = "Payout status",
			slices = BuildPieSlices(new FinancePiePart[3]
			{
				new FinancePiePart("Pending", pendingNet),
				new FinancePiePart("Paid", paidNet),
				new FinancePiePart("Cancelled", cancelledNet)
			})
		});
		list.Add(new
		{
			id = "paymentStatus",
			title = "Payment status",
			slices = BuildPieSlices(new FinancePiePart[3]
			{
				new FinancePiePart("Paid checkout", paidCheckout),
				new FinancePiePart("Pending checkout", pendingCheckout),
				new FinancePiePart("Refunded or disputed", disputedCheckout)
			})
		});
		list.Add(new
		{
			id = "tokenOps",
			title = "Token operations",
			slices = BuildPieSlices((from o in operations
				group o by o.Operation ?? "usage_charge" into g
				select new FinancePiePart(g.Key, ((IEnumerable<FinanceTokenOperationRecord>)g).Sum((Func<FinanceTokenOperationRecord, double>)((FinanceTokenOperationRecord o) => o.TokensDelta)))).ToArray())
		});
		list.Add(new
		{
			id = "serviceBilling",
			title = "Service billing",
			slices = BuildPieSlices(new FinancePiePart[4]
			{
				new FinancePiePart("GPU/compute", summary.ElectricityCostUsd),
				new FinancePiePart("Chat tokens", summary.TokenCostUsd),
				new FinancePiePart("Storage estimate", GetChatUsageSnapshot(identity.OwnerKey).storageCostUsd),
				new FinancePiePart("Platform fee", summary.SocketJackFeeUsd)
			})
		});
		List<object> charts = list;
		return new FinanceDashboard
		{
			Summary = summary,
			Payments = payments.OrderByDescending((FinancePaymentRecord p) => p.CreatedUtc).Take(200).Select(FinancePaymentToPayload)
				.ToList(),
			Payouts = ordered.Select(FinancePayoutToPayload).ToList(),
			TokenOperations = operations.OrderByDescending((FinanceTokenOperationRecord o) => o.CreatedUtc).Take(120).Select(FinanceTokenOperationToPayload)
				.ToList(),
			UsageLedger = ListFinanceUsageLedgerPayloads(identity, period, 120),
			TopEarners = BuildTopEarners(operations),
			TopExploitedServers = BuildTopExploitedServers(operations),
			Charts = charts
		};
	}

	private List<FinancePaymentRecord> ListFinancePayments(FinanceIdentity identity, FinancePeriod period)
