	private List<object> ListFinanceUsageLedgerPayloads(FinanceIdentity identity, FinancePeriod period, int take)
	{
		take = Math.Max(1, Math.Min(500, take));
		List<object[]> rows = new List<object[]>();
		lock (_chatSessionLock)
		{
			Table table = GetFinanceUsageLedgerTable();
			foreach (object[] sourceRow in table.Rows)
			{
				object[] row = NormalizeFinanceUsageLedgerRow(sourceRow);
				if ((identity == null || identity.IsAdmin || string.Equals(GetRowValue(row, 2), identity.OwnerKey, StringComparison.OrdinalIgnoreCase)) && IsFinanceDateInPeriod(GetRowValue(row, 22), period))
				{
					rows.Add(row);
				}
			}
		}
		return (from row2 in rows.OrderByDescending((object[] row2) => GetRowValue(row2, 22)).Take(take)
			select new
			{
				id = GetRowValue(row2, 0),
				operationId = GetRowValue(row2, 1),
				ownerKey = GetRowValue(row2, 2),
				username = GetRowValue(row2, 3),
				leaseId = GetRowValue(row2, 4),
				serverId = GetRowValue(row2, 5),
				sessionId = GetRowValue(row2, 6),
				category = GetRowValue(row2, 7),
				tokens = ParseStoredLong(GetRowValue(row2, 8), 0L),
				wallSeconds = ParseStoredDouble(GetRowValue(row2, 9), 0.0),
				gpuSeconds = ParseStoredDouble(GetRowValue(row2, 10), 0.0),
				cpuComputeSeconds = ParseStoredDouble(GetRowValue(row2, 11), 0.0),
				ramGbSeconds = ParseStoredDouble(GetRowValue(row2, 12), 0.0),
				ioBytes = ParseStoredLong(GetRowValue(row2, 13), 0L),
				storageBytes = ParseStoredLong(GetRowValue(row2, 14), 0L),
				bandwidthBytes = ParseStoredLong(GetRowValue(row2, 15), 0L),
				terminalSeconds = ParseStoredDouble(GetRowValue(row2, 16), 0.0),
				screenMinutes = ParseStoredDouble(GetRowValue(row2, 17), 0.0),
				grossUsd = ParseStoredDouble(GetRowValue(row2, 18), 0.0),
				platformFeeUsd = ParseStoredDouble(GetRowValue(row2, 19), 0.0),
				hostNetUsd = ParseStoredDouble(GetRowValue(row2, 20), 0.0),
				status = GetRowValue(row2, 21),
				createdUtc = GetRowValue(row2, 22),
				metadata = DeserializeJsonElement(GetRowValue(row2, 23), "{}")
			}).Cast<object>().ToList();
	}

	private FinancePaymentRecord UpsertFinancePayment(FinancePaymentRecord record)
	{
		if (record == null)
		{
			throw new ArgumentNullException("record");
		}
		record.Id = (string.IsNullOrWhiteSpace(record.Id) ? ("pay_" + Guid.NewGuid().ToString("N")) : record.Id.Trim());
		record.OwnerKey = NormalizeCostOwnerKey(record.OwnerKey);
		if (string.IsNullOrWhiteSpace(record.UserName))
		{
			record.UserName = GetUserNameFromOwnerKey(record.OwnerKey);
		}
		string now = DateTimeOffset.UtcNow.ToString("O");
		if (string.IsNullOrWhiteSpace(record.CreatedUtc))
		{
			record.CreatedUtc = now;
		}
		record.UpdatedUtc = now;
		lock (_chatSessionLock)
		{
			Table table = GetFinancePaymentsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				FinancePaymentRecord existing = FinancePaymentFromRow(table.Rows[i]);
				bool sameId = string.Equals(existing.Id, record.Id, StringComparison.OrdinalIgnoreCase);
				bool sameCheckout = !string.IsNullOrWhiteSpace(record.StripeCheckoutSessionId) && string.Equals(existing.StripeCheckoutSessionId, record.StripeCheckoutSessionId, StringComparison.OrdinalIgnoreCase);
				if (sameId || sameCheckout)
				{
					if (string.IsNullOrWhiteSpace(record.CreatedUtc))
					{
						record.CreatedUtc = existing.CreatedUtc;
					}
					table.Rows[i] = FinancePaymentToRow(record);
					SaveChatSessionDataAndInvalidateCaches();
					return record;
				}
			}
			table.Rows.Add(FinancePaymentToRow(record));
			SaveChatSessionDataAndInvalidateCaches();
		}
		return record;
	}

