	private List<object> BuildFinancePaymentProductPayloads()
	{
		return (from product in GetFinanceTokenProducts()
			select new
			{
				productId = product.ProductId,
				priceId = product.PriceId,
				name = product.Name,
				description = product.Description,
				currency = (string.IsNullOrWhiteSpace(product.Currency) ? "usd" : product.Currency.ToLowerInvariant()),
				tokenAmount = product.TokenAmount,
				amountCents = product.UnitAmountCents,
				amountUsd = NormalizeCostNumber((double)product.UnitAmountCents / 100.0),
				enabled = (product.Enabled && product.TokenAmount > 0 && product.UnitAmountCents > 0)
			}).Cast<object>().ToList();
	}

	private JackLLMPaymentTokenProductConfig ResolveFinanceTokenProduct(string productId, long tokenAmount)
	{
		List<JackLLMPaymentTokenProductConfig> products = GetFinanceTokenProducts();
		string key = (productId ?? "").Trim();
		if (!string.IsNullOrWhiteSpace(key))
		{
			JackLLMPaymentTokenProductConfig match = products.FirstOrDefault((JackLLMPaymentTokenProductConfig product) => string.Equals(product.ProductId, key, StringComparison.OrdinalIgnoreCase) || string.Equals(product.PriceId, key, StringComparison.OrdinalIgnoreCase) || string.Equals(product.Name, key, StringComparison.OrdinalIgnoreCase));
			if (match != null)
			{
				return match;
			}
		}
		if (tokenAmount > 0)
		{
			JackLLMPaymentTokenProductConfig match2 = products.FirstOrDefault((JackLLMPaymentTokenProductConfig product) => product.TokenAmount == tokenAmount);
			if (match2 != null)
			{
				return match2;
			}
		}
		return products.FirstOrDefault((JackLLMPaymentTokenProductConfig product) => product.Enabled && product.TokenAmount > 0 && product.UnitAmountCents > 0);
	}

	private List<JackLLMPaymentTokenProductConfig> GetFinanceTokenProducts()
	{
		IEnumerable<JackLLMPaymentTokenProductConfig> products = PaymentProcessor?.GetTokenProducts() ?? Enumerable.Empty<JackLLMPaymentTokenProductConfig>();
		List<JackLLMPaymentTokenProductConfig> normalized = new List<JackLLMPaymentTokenProductConfig>();
		foreach (JackLLMPaymentTokenProductConfig product in products)
		{
			if (product != null)
			{
				string productId = (product.ProductId ?? "").Trim();
				string priceId = (product.PriceId ?? "").Trim();
				string name = (product.Name ?? "").Trim();
				if (productId.Length != 0 || priceId.Length != 0 || name.Length != 0)
				{
					normalized.Add(new JackLLMPaymentTokenProductConfig
					{
						ProductId = productId,
						PriceId = priceId,
						Name = name,
						Description = (product.Description ?? "").Trim(),
						Currency = (string.IsNullOrWhiteSpace(product.Currency) ? "usd" : product.Currency.Trim().ToLowerInvariant()),
						TokenAmount = Math.Max(0L, product.TokenAmount),
						UnitAmountCents = Math.Max(0L, product.UnitAmountCents),
						Enabled = product.Enabled
					});
				}
			}
		}
		return normalized;
	}

	private IJackLLMPaymentProcessor RequirePaymentProcessor(string capability)
	{
		IJackLLMPaymentProcessor processor = PaymentProcessor;
		if (processor == null)
		{
			throw new InvalidOperationException("SocketJack.Stripe payment support is not configured for " + (string.IsNullOrWhiteSpace(capability) ? "this payment operation" : capability) + ".");
		}
		return processor;
	}

	private JackLLMPaymentProcessorStatus GetPaymentProcessorStatus()
	{
		try
		{
			return PaymentProcessor?.GetStatus() ?? new JackLLMPaymentProcessorStatus();
		}
		catch (Exception ex)
		{
			LogMessage("[Finance] Payment processor status failed: " + ex.Message);
			return new JackLLMPaymentProcessorStatus();
		}
	}

	private string GetFinancePublicBaseUrl()
	{
		string publicUrl = (ChatServerUrl ?? "").Trim();
		if (!string.IsNullOrWhiteSpace(publicUrl))
		{
			return publicUrl.TrimEnd('/');
		}
		return "http://localhost:" + _chatServerPort.ToString(CultureInfo.InvariantCulture);
	}

	private string EnsureCheckoutSessionSuccessUrl(string successUrl)
	{
		successUrl = (successUrl ?? "").Trim();
		if (successUrl.IndexOf("{CHECKOUT_SESSION_ID}", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			return successUrl;
		}
		string separator = (successUrl.Contains("?") ? "&" : "?");
		return successUrl + separator + "session_id={CHECKOUT_SESSION_ID}";
	}

	private FinancePaymentRecord ApplyStripeCheckoutSessionToPayment(JackLLMPaymentCheckoutSessionResult session, string note)
	{
		if (session == null || string.IsNullOrWhiteSpace(session.Id))
		{
			throw new InvalidOperationException("A Stripe Checkout Session result is required.");
		}
		Dictionary<string, string> metadata = new Dictionary<string, string>(session.Metadata ?? new Dictionary<string, string>(), StringComparer.Ordinal);
		FinancePaymentRecord payment = FindFinancePaymentByCheckoutSessionId(session.Id);
		if (payment == null && metadata.TryGetValue("socketjack_payment_id", out var metadataPaymentId))
		{
			payment = FindFinancePaymentById(metadataPaymentId);
		}
		if (payment == null)
		{
			payment = CreateFinancePaymentFromStripeSession(session, metadata);
		}
		bool alreadyPaid = string.Equals(payment.Status, "paid", StringComparison.OrdinalIgnoreCase);
		payment.StripeCheckoutSessionId = session.Id;
		payment.StripePaymentIntentId = (string.IsNullOrWhiteSpace(session.PaymentIntentId) ? payment.StripePaymentIntentId : session.PaymentIntentId);
		payment.StripeCustomerId = (string.IsNullOrWhiteSpace(session.CustomerId) ? payment.StripeCustomerId : session.CustomerId);
		payment.Currency = (string.IsNullOrWhiteSpace(session.Currency) ? payment.Currency : session.Currency.ToLowerInvariant());
		payment.AmountCents = ((session.AmountTotal.HasValue && session.AmountTotal.Value > 0) ? session.AmountTotal.Value : payment.AmountCents);
		payment.CheckoutUrl = (string.IsNullOrWhiteSpace(session.Url) ? payment.CheckoutUrl : session.Url);
		payment.MetadataJson = WriteFinancePaymentMetadata(MergeFinancePaymentMetadata(ReadFinancePaymentMetadata(payment.MetadataJson), metadata));
		payment.Status = GetFinancePaymentStatusFromCheckoutSession(session);
		if (payment.Status == "paid" && string.IsNullOrWhiteSpace(payment.PaidUtc))
		{
			payment.PaidUtc = DateTimeOffset.UtcNow.ToString("O");
		}
		if (!string.IsNullOrWhiteSpace(note))
		{
			payment.Note = AppendFinancePaymentNote(payment.Note, note);
		}
		if (payment.Status == "paid" && !alreadyPaid)
		{
			ApplyPaidFinancePaymentSideEffects(payment);
		}
		return UpsertFinancePayment(payment);
	}

	private FinancePaymentRecord CreateFinancePaymentFromStripeSession(JackLLMPaymentCheckoutSessionResult session, IDictionary<string, string> metadata)
	{
		metadata = metadata ?? new Dictionary<string, string>(StringComparer.Ordinal);
		string kind = ReadFinanceMetadata(metadata, "socketjack_payment_kind", ReadFinanceMetadata(metadata, "kind", "token_purchase"));
		if (kind.StartsWith("socketjack.", StringComparison.OrdinalIgnoreCase))
		{
			kind = kind.Substring("socketjack.".Length);
		}
		string ownerKey = ReadFinanceMetadata(metadata, "socketjack_owner_key", "");
		string userName = ReadFinanceMetadata(metadata, "socketjack_user_name", GetUserNameFromOwnerKey(ownerKey));
		string now = DateTimeOffset.UtcNow.ToString("O");
		return new FinancePaymentRecord
		{
			Id = ReadFinanceMetadata(metadata, "socketjack_payment_id", "pay_" + Guid.NewGuid().ToString("N")),
			Kind = (string.IsNullOrWhiteSpace(kind) ? "token_purchase" : kind.Trim().ToLowerInvariant()),
			Status = "pending",
			OwnerKey = NormalizeCostOwnerKey(ownerKey),
			UserName = userName,
			ServerId = ReadFinanceMetadata(metadata, "socketjack_server_id", ""),
			ServerName = ReadFinanceMetadata(metadata, "socketjack_server_name", ""),
			SessionId = ReadFinanceMetadata(metadata, "socketjack_session_id", ""),
			LeaseId = ReadFinanceMetadata(metadata, "socketjack_lease_id", ""),
			StripeCheckoutSessionId = session.Id,
			StripePaymentIntentId = session.PaymentIntentId,
			StripeCustomerId = session.CustomerId,
			Currency = (string.IsNullOrWhiteSpace(session.Currency) ? "usd" : session.Currency.ToLowerInvariant()),
			AmountCents = session.AmountTotal.GetValueOrDefault(),
			SocketJackFeeCents = ParseFinanceMetadataLong(metadata, "socketjack_fee_cents", 0L),
			HostAmountCents = ParseFinanceMetadataLong(metadata, "socketjack_host_amount_cents", 0L),
			TokenAmount = ParseFinanceMetadataLong(metadata, "socketjack_tokens", 0L),
			LeaseMinutes = ParseFinanceMetadataLong(metadata, "socketjack_lease_minutes", 0L),
			CreatedUtc = now,
			UpdatedUtc = now,
			MetadataJson = WriteFinancePaymentMetadata(metadata)
		};
	}

	private Dictionary<string, string> MergeFinancePaymentMetadata(IDictionary<string, string> existing, IDictionary<string, string> incoming)
	{
		Dictionary<string, string> merged = new Dictionary<string, string>(existing ?? new Dictionary<string, string>(), StringComparer.Ordinal);
		if (incoming != null)
		{
			foreach (KeyValuePair<string, string> pair in incoming)
			{
				if (!string.IsNullOrWhiteSpace(pair.Key))
				{
					merged[pair.Key] = pair.Value ?? "";
				}
			}
		}
		return merged;
	}

	private string GetFinancePaymentStatusFromCheckoutSession(JackLLMPaymentCheckoutSessionResult session)
	{
		string paymentStatus = (session.PaymentStatus ?? "").Trim().ToLowerInvariant();
		string checkoutStatus = (session.Status ?? "").Trim().ToLowerInvariant();
		if (paymentStatus == "paid" || checkoutStatus == "complete")
		{
			return "paid";
		}
		if (checkoutStatus == "expired")
		{
			return "expired";
		}
		if (paymentStatus == "unpaid" || checkoutStatus == "open")
		{
			return "pending";
		}
		if (paymentStatus == "no_payment_required")
		{
			return "paid";
		}
		return "pending";
	}

	private void ApplyPaidFinancePaymentSideEffects(FinancePaymentRecord payment)
	{
		if (payment != null)
		{
			if (string.Equals(payment.Kind, "token_purchase", StringComparison.OrdinalIgnoreCase) || string.Equals(payment.Kind, "tokens", StringComparison.OrdinalIgnoreCase))
			{
				bool credited = CreditLocalWebAuthTokens(payment.OwnerKey, payment.UserName, payment.TokenAmount);
				payment.Note = AppendFinancePaymentNote(payment.Note, credited ? "Credited local WebAuth token balance." : "Payment marked paid; SocketJack.com or an external account service must credit tokens for non-local accounts.");
			}
			else if (string.Equals(payment.Kind, "server_lease", StringComparison.OrdinalIgnoreCase) || string.Equals(payment.Kind, "marketplace_lease", StringComparison.OrdinalIgnoreCase))
			{
				ActivateMarketplaceLeaseForPayment(payment);
				RecordPaidLeaseFinanceOperation(payment);
			}
		}
	}

	private bool CreditLocalWebAuthTokens(string ownerKey, string username, long tokens)
	{
		tokens = Math.Max(0L, tokens);
		if (tokens <= 0 || !StoreLocalWebAuthAccounts)
		{
			return false;
		}
		username = (string.IsNullOrWhiteSpace(username) ? GetUserNameFromOwnerKey(ownerKey) : username.Trim());
		if (!TryNormalizeWebAuthUserName(username, out var normalizedUserName, out var _))
		{
			return false;
		}
		lock (_chatSessionLock)
		{
			Table table = GetWebAuthTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				WebAuthRecord record = WebAuthRecordFromRow(table.Rows[i]);
				if (string.Equals(record.userName, normalizedUserName, StringComparison.OrdinalIgnoreCase))
				{
					record.tokenLimit = ((record.tokenLimit > long.MaxValue - tokens) ? long.MaxValue : (record.tokenLimit + tokens));
					record.updatedUtc = DateTimeOffset.UtcNow.ToString("O");
					table.Rows[i] = WebAuthRecordToRow(record);
					SaveChatSessionDataAndInvalidateCaches();
					return true;
				}
			}
			string now = DateTimeOffset.UtcNow.ToString("O");
			WebAuthRecord created = new WebAuthRecord
			{
				userName = normalizedUserName,
				createdUtc = now,
				updatedUtc = now,
				enabled = true,
				tokenLimit = tokens,
				tokensUsed = 0L
			};
			table.Rows.Add(WebAuthRecordToRow(created));
			SaveChatSessionDataAndInvalidateCaches();
			return true;
		}
	}

	private void RecordPaidLeaseFinanceOperation(FinancePaymentRecord payment)
	{
		if (payment == null || string.IsNullOrWhiteSpace(payment.OwnerKey))
		{
			return;
		}
		long tokenAmount = payment.TokenAmount;
		if (tokenAmount <= 0 && payment.LeaseMinutes > 0)
		{
			long tokensPerHour = Math.Max(1L, GetPricingTokensPerHour(GetChatCostSettings()));
			tokenAmount = Math.Max(1L, (long)Math.Ceiling((double)tokensPerHour * ((double)payment.LeaseMinutes / 60.0)));
		}
		if (tokenAmount <= 0)
		{
			tokenAmount = 1L;
		}
		double grossUsd = NormalizeCostNumber((double)payment.AmountCents / 100.0);
		lock (_chatSessionLock)
		{
			RecordFinanceTokenOperation(payment.OwnerKey, "lease_payment", tokenAmount, grossUsd, 0.0, 0.0, grossUsd, "Paid marketplace lease " + payment.Id, string.IsNullOrWhiteSpace(payment.LeaseId) ? payment.StripeCheckoutSessionId : payment.LeaseId);
			SaveChatSessionDataAndInvalidateCaches();
		}
	}

	private void ActivateMarketplaceLeaseForPayment(FinancePaymentRecord payment)
	{
		if (payment == null || string.IsNullOrWhiteSpace(payment.LeaseId))
		{
			return;
		}
		MarketplaceLeaseRecord lease = FindMarketplaceLeaseById(payment.LeaseId);
		if (lease != null)
		{
			DateTimeOffset now = DateTimeOffset.UtcNow;
			lease.PaymentId = payment.Id ?? "";
			lease.CheckoutSessionId = payment.StripeCheckoutSessionId ?? "";
			lease.PaymentStatus = "paid";
			lease.Status = "active";
			lease.LeaseRequired = true;
			lease.QuoteUsd = ((payment.AmountCents > 0) ? NormalizeCostNumber((double)payment.AmountCents / 100.0) : lease.QuoteUsd);
			lease.LeaseMinutes = ((payment.LeaseMinutes > 0) ? payment.LeaseMinutes : Math.Max(1L, lease.LeaseMinutes));
			if (string.IsNullOrWhiteSpace(lease.StartedUtc))
			{
				lease.StartedUtc = now.ToString("O");
			}
			lease.RenewedUtc = now.ToString("O");
			lease.ExpiresUtc = now.AddMinutes(Math.Max(1L, lease.LeaseMinutes)).ToString("O");
			UpsertMarketplaceLease(lease);
			LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
			if (!string.IsNullOrWhiteSpace(selection.LeaseId) && string.Equals(selection.LeaseId, lease.Id, StringComparison.OrdinalIgnoreCase))
			{
				ConfigureRemoteModelServerSelection(BuildRemoteModelSelectionFromMarketplaceLease(lease));
			}
		}
	}

	private FinancePaymentRecord ApplyVerifiedStripeWebhookPayload(string json, string verifiedEventType)
	{
		using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(json) ? "{}" : json);
		JsonElement root = document.RootElement;
		string eventType = (string.IsNullOrWhiteSpace(verifiedEventType) ? (ExtractStringProperty(root, "type") ?? "") : verifiedEventType);
		if (!root.TryGetProperty("data", out var data) || data.ValueKind != JsonValueKind.Object || !data.TryGetProperty("object", out var stripeObject) || stripeObject.ValueKind != JsonValueKind.Object)
		{
			return null;
		}
		string objectType = ExtractStringProperty(stripeObject, "object") ?? "";
		if (string.Equals(objectType, "payout", StringComparison.OrdinalIgnoreCase) || string.Equals(objectType, "transfer", StringComparison.OrdinalIgnoreCase) || string.Equals(objectType, "balance_transaction", StringComparison.OrdinalIgnoreCase) || string.Equals(objectType, "application_fee", StringComparison.OrdinalIgnoreCase))
		{
			ReconcileFinancePayoutFromStripeWebhook(stripeObject, eventType, objectType);
			return null;
		}
		if (string.Equals(objectType, "checkout.session", StringComparison.OrdinalIgnoreCase))
		{
			JackLLMPaymentCheckoutSessionResult session = BuildCheckoutSessionResultFromWebhookObject(stripeObject);
			FinancePaymentRecord payment = ApplyStripeCheckoutSessionToPayment(session, "Stripe webhook " + eventType + ".");
			if (eventType.IndexOf("failed", StringComparison.OrdinalIgnoreCase) >= 0)
			{
				payment = MarkFinancePaymentStatus(payment, "failed", "Stripe webhook reported async payment failure.");
			}
			else if (eventType.IndexOf("expired", StringComparison.OrdinalIgnoreCase) >= 0)
			{
				payment = MarkFinancePaymentStatus(payment, "expired", "Stripe webhook reported checkout expiration.");
			}
			return payment;
		}
		string paymentIntentId = ExtractStripeObjectId(stripeObject, "payment_intent");
		string chargeId = ExtractStripeObjectId(stripeObject, "charge");
		if (string.IsNullOrWhiteSpace(chargeId))
		{
			chargeId = ExtractStringProperty(stripeObject, "id") ?? "";
		}
		FinancePaymentRecord matched = FindFinancePaymentByStripeObject("", paymentIntentId, chargeId);
		if (matched == null)
		{
			return null;
		}
		if (eventType.IndexOf("refund", StringComparison.OrdinalIgnoreCase) >= 0 || eventType.IndexOf("refunded", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			return MarkFinancePaymentStatus(matched, "refunded", "Stripe webhook reported refund.");
		}
		if (eventType.IndexOf("dispute", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			return MarkFinancePaymentStatus(matched, "disputed", "Stripe webhook reported dispute.");
		}
		return matched;
	}

	private JackLLMPaymentCheckoutSessionResult BuildCheckoutSessionResultFromWebhookObject(JsonElement stripeObject)
	{
		JackLLMPaymentCheckoutSessionResult result = new JackLLMPaymentCheckoutSessionResult
		{
			Id = (ExtractStringProperty(stripeObject, "id") ?? ""),
			Status = (ExtractStringProperty(stripeObject, "status") ?? ""),
			PaymentStatus = (ExtractStringProperty(stripeObject, "payment_status") ?? ""),
			PaymentIntentId = ExtractStripeObjectId(stripeObject, "payment_intent"),
			CustomerId = ExtractStripeObjectId(stripeObject, "customer"),
			ClientReferenceId = (ExtractStringProperty(stripeObject, "client_reference_id") ?? ""),
			Currency = (ExtractStringProperty(stripeObject, "currency") ?? "")
		};
		if (stripeObject.TryGetProperty("amount_total", out var amountTotal))
		{
			result.AmountTotal = Math.Max(0L, ReadJsonLong(amountTotal, 0L));
		}
		if (stripeObject.TryGetProperty("url", out var urlElement) && urlElement.ValueKind == JsonValueKind.String)
		{
			result.Url = urlElement.GetString() ?? "";
		}
		if (stripeObject.TryGetProperty("metadata", out var metadata) && metadata.ValueKind == JsonValueKind.Object)
		{
			foreach (JsonProperty property in metadata.EnumerateObject())
			{
				result.Metadata[property.Name] = ((property.Value.ValueKind == JsonValueKind.String) ? (property.Value.GetString() ?? "") : property.Value.ToString());
			}
		}
		return result;
	}

	private string ExtractStripeObjectId(JsonElement stripeObject, string propertyName)
	{
		if (!stripeObject.TryGetProperty(propertyName, out var value))
		{
			return "";
		}
		if (value.ValueKind == JsonValueKind.String)
		{
			return value.GetString() ?? "";
		}
		if (value.ValueKind == JsonValueKind.Object)
		{
			return ExtractStringProperty(value, "id") ?? "";
		}
		return "";
	}

	private FinancePaymentRecord MarkFinancePaymentStatus(FinancePaymentRecord payment, string status, string note)
	{
		if (payment == null)
		{
			return null;
		}
		string now = DateTimeOffset.UtcNow.ToString("O");
		payment.Status = status;
		if (status == "refunded")
		{
			payment.RefundedUtc = now;
		}
		else if (status == "disputed")
		{
			payment.DisputedUtc = now;
		}
		if (!string.IsNullOrWhiteSpace(note))
		{
			payment.Note = AppendFinancePaymentNote(payment.Note, note);
		}
		return UpsertFinancePayment(payment);
	}

	private string ReadFinanceMetadata(IDictionary<string, string> metadata, string key, string fallback)
	{
		string value;
		return (metadata != null && metadata.TryGetValue(key, out value) && !string.IsNullOrWhiteSpace(value)) ? value : fallback;
	}

	private long ParseFinanceMetadataLong(IDictionary<string, string> metadata, string key, long fallback)
	{
		string value = ReadFinanceMetadata(metadata, key, "");
		long parsed;
		return long.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed) ? Math.Max(0L, parsed) : fallback;
	}

	private string AppendFinancePaymentNote(string existing, string note)
	{
		existing = existing ?? "";
		note = note ?? "";
		if (string.IsNullOrWhiteSpace(note))
		{
			return existing;
		}
		if (string.IsNullOrWhiteSpace(existing))
		{
			return note.Trim();
		}
		if (existing.IndexOf(note, StringComparison.OrdinalIgnoreCase) >= 0)
		{
			return existing;
		}
		return existing.TrimEnd() + " " + note.Trim();
	}

	private FinancePayoutRecord CreateFinancePayout(string ownerKey, string username, FinancePeriod period, string note, string method, string destinationId, string schedule)
	{
		FinanceIdentity scopedIdentity = new FinanceIdentity
		{
			OwnerKey = NormalizeCostOwnerKey(ownerKey),
			UserName = (username ?? GetUserNameFromOwnerKey(ownerKey)),
			IsAdmin = false
		};
		FinanceMoneySummary summary = SummarizeFinanceOperations(ListFinanceTokenOperations(scopedIdentity, period));
		if (summary.NetUsd <= 0.0)
		{
			throw new InvalidOperationException("There is no payable SocketJack balance in this period.");
		}
		string payoutMethod = NormalizeFinancePayoutMethod(method);
		string payoutSchedule = ((!string.IsNullOrWhiteSpace(schedule)) ? schedule.Trim().ToLowerInvariant() : ((payoutMethod == "weekly") ? "weekly" : "manual"));
		FinancePayoutRecord duplicate = FindFinancePayoutForPeriod(scopedIdentity.OwnerKey, period, payoutMethod, payoutSchedule);
		if (duplicate != null)
		{
			return duplicate;
		}
		FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(scopedIdentity.OwnerKey, scopedIdentity.UserName);
		destinationId = (string.IsNullOrWhiteSpace(destinationId) ? profile.InstantPayoutDestinationId : destinationId.Trim());
		double instantFee = ((payoutMethod == "instant") ? 1.0 : 0.0);
		double instantFeeTax = ((payoutMethod == "instant") ? NormalizeCostNumber(instantFee * GetFinanceInstantPayoutFeeTaxRate(profile)) : 0.0);
		double payoutAmount = NormalizeCostNumber(Math.Max(0.0, summary.NetUsd - instantFee - instantFeeTax));
		if (payoutAmount <= 0.0)
		{
			throw new InvalidOperationException("The payout amount must be positive after payout fees and taxes.");
		}
		string now = DateTimeOffset.UtcNow.ToString("O");
		Dictionary<string, string> metadata = new Dictionary<string, string>(StringComparer.Ordinal)
		{
			["payout_method"] = payoutMethod,
			["payout_schedule"] = payoutSchedule,
			["instant_fee_usd"] = instantFee.ToString("0.########", CultureInfo.InvariantCulture),
			["instant_fee_tax_usd"] = instantFeeTax.ToString("0.########", CultureInfo.InvariantCulture),
			["destination_id"] = destinationId ?? ""
		};
		FinancePayoutRecord record = new FinancePayoutRecord
		{
			Id = "payout_" + Guid.NewGuid().ToString("N"),
			OwnerKey = scopedIdentity.OwnerKey,
			UserName = scopedIdentity.UserName,
			Status = "requested",
			Currency = "usd",
			GrossUsd = summary.GrossUsd,
			SocketJackFeeUsd = summary.SocketJackFeeUsd,
			NetUsd = summary.NetUsd,
			Tokens = summary.Tokens,
			PeriodStartUtc = period.StartUtc.ToString("O"),
			PeriodEndUtc = period.EndUtc.ToString("O"),
			RequestedUtc = now,
			PaidUtc = "",
			StripeTransferId = "",
			Method = payoutMethod,
			Schedule = payoutSchedule,
			DestinationType = ((payoutMethod == "instant") ? "debit_card" : "bank_account"),
			InstantFeeUsd = instantFee,
			InstantFeeTaxUsd = instantFeeTax,
			PayoutAmountUsd = payoutAmount,
			StripePayoutId = "",
			StripeConnectedAccountId = (profile.StripeConnectedAccountId ?? ""),
			AvailableOnUtc = ((payoutMethod == "instant") ? now : ""),
			MetadataJson = WriteFinancePaymentMetadata(metadata),
			Note = (note ?? "")
		};
		lock (_chatSessionLock)
		{
			GetFinancePayoutsTable().Rows.Add(FinancePayoutToRow(record));
			SaveChatSessionDataAndInvalidateCaches();
		}
		return record;
	}

	private FinancePayoutRecord FindFinancePayoutForPeriod(string ownerKey, FinancePeriod period, string method, string schedule)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		method = NormalizeFinancePayoutMethod(method);
		schedule = (string.IsNullOrWhiteSpace(schedule) ? "manual" : schedule.Trim().ToLowerInvariant());
		string start = ((period == null) ? "" : period.StartUtc.ToString("O"));
		string end = ((period == null) ? "" : period.EndUtc.ToString("O"));
		lock (_chatSessionLock)
		{
			Table table = GetFinancePayoutsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				FinancePayoutRecord record = FinancePayoutFromRow(sourceRow);
				if (!string.Equals(record.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) || !string.Equals(record.Method, method, StringComparison.OrdinalIgnoreCase) || !string.Equals(record.Schedule, schedule, StringComparison.OrdinalIgnoreCase) || !string.Equals(record.PeriodStartUtc, start, StringComparison.OrdinalIgnoreCase) || !string.Equals(record.PeriodEndUtc, end, StringComparison.OrdinalIgnoreCase) || IsTerminalFailedFinancePayoutStatus(record.Status))
				{
					continue;
				}
				return record;
			}
		}
		return null;
	}

	private FinancePayoutRecord FindFinancePayoutById(string payoutId)
	{
		if (string.IsNullOrWhiteSpace(payoutId))
		{
			return null;
		}
		lock (_chatSessionLock)
		{
			Table table = GetFinancePayoutsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				FinancePayoutRecord record = FinancePayoutFromRow(sourceRow);
				if (string.Equals(record.Id, payoutId, StringComparison.OrdinalIgnoreCase))
				{
					return record;
				}
			}
		}
		return null;
	}

	private FinancePayoutRecord FindFinancePayoutByStripeIds(string transferId, string payoutId)
	{
		transferId = (transferId ?? "").Trim();
		payoutId = (payoutId ?? "").Trim();
		if (string.IsNullOrWhiteSpace(transferId) && string.IsNullOrWhiteSpace(payoutId))
		{
			return null;
		}
		lock (_chatSessionLock)
		{
			Table table = GetFinancePayoutsTable();
			foreach (object[] sourceRow in table.Rows)
			{
				FinancePayoutRecord record = FinancePayoutFromRow(sourceRow);
				if (!string.IsNullOrWhiteSpace(transferId) && string.Equals(record.StripeTransferId, transferId, StringComparison.OrdinalIgnoreCase))
				{
					return record;
				}
				if (!string.IsNullOrWhiteSpace(payoutId) && string.Equals(record.StripePayoutId, payoutId, StringComparison.OrdinalIgnoreCase))
				{
					return record;
				}
			}
		}
		return null;
	}

	private FinancePayoutRecord ReconcileFinancePayoutFromStripeWebhook(JsonElement stripeObject, string eventType, string objectType)
	{
		string id = ExtractStringProperty(stripeObject, "id") ?? "";
		string status = ExtractStringProperty(stripeObject, "status") ?? "";
		string failure = ExtractStringProperty(stripeObject, "failure_message") ?? ExtractStringProperty(stripeObject, "failure_code") ?? "";
		string transferId = (string.Equals(objectType, "transfer", StringComparison.OrdinalIgnoreCase) ? id : ExtractStripeObjectId(stripeObject, "transfer"));
		string payoutId = (string.Equals(objectType, "payout", StringComparison.OrdinalIgnoreCase) ? id : ExtractStripeObjectId(stripeObject, "payout"));
		FinancePayoutRecord record = FindFinancePayoutByStripeIds(transferId, payoutId);
		if (record == null)
		{
			return null;
		}
		string normalizedStatus = NormalizeStripePayoutStatus(status, eventType, objectType);
		if (!string.IsNullOrWhiteSpace(normalizedStatus))
		{
			record.Status = normalizedStatus;
		}
		if (string.Equals(record.Status, "paid", StringComparison.OrdinalIgnoreCase) && string.IsNullOrWhiteSpace(record.PaidUtc))
		{
			record.PaidUtc = DateTimeOffset.UtcNow.ToString("O");
		}
		if (!string.IsNullOrWhiteSpace(transferId))
		{
			record.StripeTransferId = transferId;
		}
		if (!string.IsNullOrWhiteSpace(payoutId))
		{
			record.StripePayoutId = payoutId;
		}
		Dictionary<string, string> metadata = ReadFinancePaymentMetadata(record.MetadataJson);
		metadata["lastStripeEventType"] = eventType ?? "";
		metadata["lastStripeObjectType"] = objectType ?? "";
		metadata["lastStripeStatus"] = status ?? "";
		metadata["lastReconciledUtc"] = DateTimeOffset.UtcNow.ToString("O");
		record.MetadataJson = WriteFinancePaymentMetadata(metadata);
		record.Note = AppendFinancePaymentNote(record.Note, string.IsNullOrWhiteSpace(failure) ? ("Stripe payout reconciliation: " + (eventType ?? objectType ?? "event") + ".") : ("Stripe payout reconciliation failed: " + failure));
		RecordObservabilityEvent("payments", "payout reconciled", record.Status, record.Id, record.OwnerKey, "/api/payments/stripe-webhook", 0L);
		return UpsertFinancePayout(record);
	}

	private static string NormalizeStripePayoutStatus(string status, string eventType, string objectType)
	{
		string value = (status ?? "").Trim().ToLowerInvariant();
		string type = (eventType ?? "").Trim().ToLowerInvariant();
		if (type.Contains("failed") || value == "failed" || value == "canceled" || value == "cancelled")
		{
			return "failed";
		}
		if (type.Contains("paid") || value == "paid")
		{
			return "paid";
		}
		if (type.Contains("created") || value == "pending" || value == "in_transit")
		{
			return "processing";
		}
		if (type.Contains("updated") && value == "paid")
		{
			return "paid";
		}
		if (string.Equals(objectType, "transfer", StringComparison.OrdinalIgnoreCase) && (type.Contains("created") || string.IsNullOrWhiteSpace(value)))
		{
			return "transferred";
		}
		return "";
	}

	private FinancePayoutRecord UpsertFinancePayout(FinancePayoutRecord record)
	{
		if (record == null)
		{
			throw new ArgumentNullException("record");
		}
		record.Id = (string.IsNullOrWhiteSpace(record.Id) ? ("payout_" + Guid.NewGuid().ToString("N")) : record.Id.Trim());
		record.OwnerKey = NormalizeCostOwnerKey(record.OwnerKey);
		record.UserName = (string.IsNullOrWhiteSpace(record.UserName) ? GetUserNameFromOwnerKey(record.OwnerKey) : record.UserName);
		record.Status = (IsKnownFinancePayoutStatus(record.Status) ? record.Status.Trim().ToLowerInvariant() : "requested");
		record.Method = NormalizeFinancePayoutMethod(record.Method);
		record.Schedule = (string.IsNullOrWhiteSpace(record.Schedule) ? "manual" : record.Schedule.Trim().ToLowerInvariant());
		record.PayoutAmountUsd = ((record.PayoutAmountUsd > 0.0) ? NormalizeCostNumber(record.PayoutAmountUsd) : NormalizeCostNumber(Math.Max(0.0, record.NetUsd - record.InstantFeeUsd - record.InstantFeeTaxUsd)));
		lock (_chatSessionLock)
		{
			Table table = GetFinancePayoutsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				FinancePayoutRecord existing = FinancePayoutFromRow(table.Rows[i]);
				if (string.Equals(existing.Id, record.Id, StringComparison.OrdinalIgnoreCase))
				{
					table.Rows[i] = FinancePayoutToRow(record);
					SaveChatSessionDataAndInvalidateCaches();
					return record;
				}
			}
			table.Rows.Add(FinancePayoutToRow(record));
			SaveChatSessionDataAndInvalidateCaches();
		}
		return record;
	}

	private FinancePayoutRecord UpdateFinancePayoutStatus(string payoutId, string status, string note)
	{
		if (string.IsNullOrWhiteSpace(payoutId))
		{
			throw new InvalidOperationException("Payout id is required.");
		}
		status = (IsKnownFinancePayoutStatus(status) ? status.Trim().ToLowerInvariant() : "requested");
		lock (_chatSessionLock)
		{
			Table table = GetFinancePayoutsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				FinancePayoutRecord record = FinancePayoutFromRow(table.Rows[i]);
				if (string.Equals(record.Id, payoutId, StringComparison.OrdinalIgnoreCase))
				{
					record.Status = status;
					if (IsPaidFinancePayoutStatus(status))
					{
						record.PaidUtc = DateTimeOffset.UtcNow.ToString("O");
					}
					if (!string.IsNullOrWhiteSpace(note))
					{
						record.Note = AppendFinancePaymentNote(record.Note, note);
					}
					table.Rows[i] = FinancePayoutToRow(record);
					SaveChatSessionDataAndInvalidateCaches();
					return record;
				}
			}
		}
		throw new InvalidOperationException("Payout was not found.");
	}

	private FinancePayoutRecord TrySettleFinancePayoutWithPaymentProcessor(FinancePayoutRecord record, FinanceAccountProfile profile, string note)
	{
		if (record == null)
		{
			return null;
		}
		try
		{
			return SettleFinancePayoutWithPaymentProcessor(record, profile, note);
		}
		catch (Exception ex)
		{
			record.Status = ((!string.IsNullOrWhiteSpace(record.StripeTransferId)) ? "transferred" : (string.Equals(record.Status, "requested", StringComparison.OrdinalIgnoreCase) ? "requested" : "failed"));
			record.Note = AppendFinancePaymentNote(record.Note, "Payment payout settlement pending: " + ex.Message);
			return UpsertFinancePayout(record);
		}
	}

	private FinancePayoutRecord SettleFinancePayoutWithPaymentProcessor(FinancePayoutRecord record, FinanceAccountProfile profile, string note)
	{
		if (record == null)
		{
			throw new ArgumentNullException("record");
		}
		profile = profile ?? GetOrCreateFinanceAccountProfile(record.OwnerKey, record.UserName);
		string connectedAccountId = (profile.StripeConnectedAccountId ?? record.StripeConnectedAccountId ?? "").Trim();
		if (string.IsNullOrWhiteSpace(connectedAccountId))
		{
			record.Note = AppendFinancePaymentNote(record.Note, "Payout is recorded locally; connect a Stripe payout account to settle funds.");
			return UpsertFinancePayout(record);
		}
		IJackLLMPaymentProcessor paymentProcessor = PaymentProcessor;
		JackLLMPaymentProcessorStatus paymentStatus = GetPaymentProcessorStatus();
		if (paymentProcessor == null || !paymentStatus.PayoutsConfigured)
		{
			record.Note = AppendFinancePaymentNote(record.Note, "Payout is recorded locally; payment processor payouts are not configured.");
			return UpsertFinancePayout(record);
		}
		long transferAmountCents = UsdToMinorUnits((record.PayoutAmountUsd > 0.0) ? record.PayoutAmountUsd : record.NetUsd);
		if (transferAmountCents <= 0)
		{
			throw new InvalidOperationException("Payout transfer amount must be positive.");
		}
		JackLLMConnectedTransferRequest transferRequest = new JackLLMConnectedTransferRequest
		{
			ConnectedAccountId = connectedAccountId,
			PayoutRequestId = record.Id,
			Currency = (string.IsNullOrWhiteSpace(record.Currency) ? "usd" : record.Currency),
			Amount = transferAmountCents,
			GrossAmount = UsdToMinorUnits(record.GrossUsd),
			SocketJackFeeAmount = UsdToMinorUnits(record.SocketJackFeeUsd + record.InstantFeeUsd + record.InstantFeeTaxUsd),
			IdempotencyKey = "transfer_" + record.Id,
			TransferGroup = "socketjack_payout_" + record.Id
		};
		transferRequest.Metadata["socketjack_owner_key"] = record.OwnerKey ?? "";
		transferRequest.Metadata["socketjack_user_name"] = record.UserName ?? "";
		transferRequest.Metadata["socketjack_payout_method"] = NormalizeFinancePayoutMethod(record.Method);
		transferRequest.Metadata["socketjack_instant_fee_usd"] = record.InstantFeeUsd.ToString("0.########", CultureInfo.InvariantCulture);
		transferRequest.Metadata["socketjack_instant_fee_tax_usd"] = record.InstantFeeTaxUsd.ToString("0.########", CultureInfo.InvariantCulture);
		JackLLMConnectedTransferResult transfer = paymentProcessor.CreateConnectedAccountTransferAsync(transferRequest).GetAwaiter().GetResult();
		record.StripeTransferId = transfer.TransferId;
		record.StripeConnectedAccountId = connectedAccountId;
		string payoutMethod = NormalizeFinancePayoutMethod(record.Method);
		if (payoutMethod == "instant")
		{
			Dictionary<string, string> metadata = ReadFinancePaymentMetadata(record.MetadataJson);
			metadata.TryGetValue("destination_id", out var destinationId);
			JackLLMConnectedPayoutRequest payoutRequest = new JackLLMConnectedPayoutRequest
			{
				ConnectedAccountId = connectedAccountId,
				PayoutRequestId = record.Id,
				Currency = record.Currency,
				Amount = transferAmountCents,
				Method = "instant",
				Destination = (destinationId ?? ""),
				IdempotencyKey = "instant_payout_" + record.Id,
				StatementDescriptor = "SOCKETJACK"
			};
			payoutRequest.Metadata["socketjack_owner_key"] = record.OwnerKey ?? "";
			payoutRequest.Metadata["socketjack_payout_method"] = "instant";
			payoutRequest.Metadata["socketjack_instant_fee_usd"] = record.InstantFeeUsd.ToString("0.########", CultureInfo.InvariantCulture);
			payoutRequest.Metadata["socketjack_instant_fee_tax_usd"] = record.InstantFeeTaxUsd.ToString("0.########", CultureInfo.InvariantCulture);
			JackLLMConnectedPayoutResult payout = paymentProcessor.CreateConnectedAccountPayoutAsync(payoutRequest).GetAwaiter().GetResult();
			record.StripePayoutId = payout.PayoutId;
			record.AvailableOnUtc = payout.ArrivalDateUtc;
			record.Status = (string.Equals(payout.Status, "paid", StringComparison.OrdinalIgnoreCase) ? "paid" : "processing");
			if (record.Status == "paid")
			{
				record.PaidUtc = DateTimeOffset.UtcNow.ToString("O");
			}
		}
		else
		{
			if (payoutMethod == "weekly")
			{
				ConfigureFinanceWeeklyPayoutSchedule(profile, profile.PayoutDay, "Configured weekly direct deposit for payout " + record.Id + ".");
			}
			record.Status = ((payoutMethod == "weekly") ? "scheduled" : "transferred");
			record.AvailableOnUtc = (string.IsNullOrWhiteSpace(record.AvailableOnUtc) ? EstimateFinanceDirectDepositArrivalUtc().ToString("O") : record.AvailableOnUtc);
		}
		record.Note = AppendFinancePaymentNote(record.Note, string.IsNullOrWhiteSpace(note) ? "Payment transfer created." : note);
		return UpsertFinancePayout(record);
	}

	private FinanceAccountProfile ConfigureFinanceWeeklyPayoutSchedule(FinanceAccountProfile profile, string weeklyDay, string note)
	{
		if (profile == null)
		{
			return null;
		}
		profile.PayoutSchedule = "weekly";
		profile.PayoutDay = NormalizeFinanceWeeklyPayoutDay(weeklyDay ?? profile.PayoutDay);
		profile.PayoutMethod = "weekly";
		profile.UpdatedUtc = DateTimeOffset.UtcNow.ToString("O");
		IJackLLMPaymentProcessor paymentProcessor = PaymentProcessor;
		JackLLMPaymentProcessorStatus paymentStatus = GetPaymentProcessorStatus();
		if (!string.IsNullOrWhiteSpace(profile.StripeConnectedAccountId) && paymentProcessor != null && paymentStatus.PayoutsConfigured)
		{
			try
			{
				paymentProcessor.ConfigureWeeklyPayoutScheduleAsync(new JackLLMPayoutScheduleRequest
				{
					ConnectedAccountId = profile.StripeConnectedAccountId,
					WeeklyPayoutDay = profile.PayoutDay,
					IdempotencyKey = "weekly_schedule_" + NormalizeCostOwnerKey(profile.OwnerKey)
				}).GetAwaiter().GetResult();
			}
			catch (Exception ex)
			{
				LogMessage("[Finance] Weekly payment payout schedule update failed: " + ex.Message);
			}
		}
		UpsertFinanceAccountProfile(profile);
		return profile;
	}

	private List<FinancePayoutRecord> CreateWeeklyFinancePayouts(FinanceIdentity identity, string weeklyDay, string note)
	{
		List<FinancePayoutRecord> records = new List<FinancePayoutRecord>();
		FinancePeriod weeklyPeriod = BuildFinanceWeeklyPayoutPeriod(weeklyDay);
		FinanceIdentity adminIdentity = new FinanceIdentity
		{
			IsAdmin = true,
			OwnerKey = (identity?.OwnerKey ?? ""),
			UserName = (identity?.UserName ?? "admin")
		};
		foreach (IGrouping<string, FinanceTokenOperationRecord> group in (from operation in ListFinanceTokenOperations(adminIdentity, weeklyPeriod)
			where !string.IsNullOrWhiteSpace(operation.OwnerKey)
			select operation).GroupBy<FinanceTokenOperationRecord, string>((FinanceTokenOperationRecord operation) => operation.OwnerKey, StringComparer.OrdinalIgnoreCase))
		{
			FinanceMoneySummary summary = SummarizeFinanceOperations(group);
			if (!(summary.NetUsd <= 0.0))
			{
				string ownerKey = NormalizeCostOwnerKey(group.Key);
				string userName = group.Select((FinanceTokenOperationRecord operation) => operation.UserName).FirstOrDefault((string value) => !string.IsNullOrWhiteSpace(value)) ?? GetUserNameFromOwnerKey(ownerKey);
				FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(ownerKey, userName);
				try
				{
					FinancePayoutRecord record = CreateFinancePayout(ownerKey, userName, weeklyPeriod, note, "weekly", "", "weekly");
					record = TrySettleFinancePayoutWithPaymentProcessor(record, profile, note);
					profile.LastWeeklyPayoutUtc = DateTimeOffset.UtcNow.ToString("O");
					UpsertFinanceAccountProfile(profile);
					records.Add(record);
				}
				catch (Exception ex)
				{
					LogMessage("[Finance] Weekly payout skipped for " + ownerKey + ": " + ex.Message);
				}
			}
		}
		return records;
	}

	private FinancePeriod BuildFinanceWeeklyPayoutPeriod(string weeklyDay)
	{
		DayOfWeek payoutDay = ParseFinanceWeeklyPayoutDay(weeklyDay);
		DateTimeOffset now = DateTimeOffset.UtcNow;
		DateTimeOffset end = new DateTimeOffset(now.UtcDateTime.Date, TimeSpan.Zero);
		while (end.DayOfWeek != payoutDay || end > now)
		{
			end = end.AddDays(-1.0);
		}
		DateTimeOffset start = end.AddDays(-7.0);
		return new FinancePeriod
		{
			Key = "weekly",
			StartUtc = start,
			EndUtc = end.AddTicks(-1L)
		};
	}

	private object BuildFinanceWeeklyPayoutPreview(FinanceIdentity identity, FinanceAccountProfile profile)
	{
		FinancePeriod weeklyPeriod = BuildFinanceWeeklyPayoutPeriod(profile?.PayoutDay);
		FinanceMoneySummary summary = SummarizeFinanceOperations(ListFinanceTokenOperations(identity, weeklyPeriod));
		double instantFeeTax = NormalizeCostNumber(1.0 * GetFinanceInstantPayoutFeeTaxRate(profile));
		return new
		{
			period = new
			{
				startUtc = weeklyPeriod.StartUtc.ToString("O"),
				endUtc = weeklyPeriod.EndUtc.ToString("O"),
				key = weeklyPeriod.Key
			},
			grossUsd = summary.GrossUsd,
			netUsd = summary.NetUsd,
			tokens = summary.Tokens,
			weeklyDirectDepositUsd = summary.NetUsd,
			instantFeeUsd = 1.0,
			instantFeeTaxUsd = instantFeeTax,
			instantPayoutUsd = NormalizeCostNumber(Math.Max(0.0, summary.NetUsd - 1.0 - instantFeeTax))
		};
	}

	private object BuildFinancePayoutPolicyPayload(FinanceAccountProfile profile)
	{
		profile = profile ?? new FinanceAccountProfile();
		double taxRate = GetFinanceInstantPayoutFeeTaxRate(profile);
		return new
		{
			weeklyEnabled = true,
			weeklyPayoutDay = NormalizeFinanceWeeklyPayoutDay(profile.PayoutDay),
			defaultMethod = NormalizeFinancePayoutMethod(profile.PayoutMethod),
			directDepositEnabled = true,
			instantEnabled = true,
			instantFeeUsd = 1.0,
			instantFeeTaxRate = taxRate,
			instantFeeTaxUsd = NormalizeCostNumber(1.0 * taxRate),
			instantDestinationConfigured = !string.IsNullOrWhiteSpace(profile.InstantPayoutDestinationId),
			stripeConnectedAccountConfigured = !string.IsNullOrWhiteSpace(profile.StripeConnectedAccountId)
		};
	}

	private object BuildFinancePayoutReconciliationPayload(FinanceIdentity identity, FinancePeriod period)
	{
		List<FinancePayoutRecord> payouts = ListFinancePayouts(identity ?? new FinanceIdentity
		{
			IsAdmin = true
		}, period);
		int missingStripeIds = 0;
		int processing = 0;
		int failed = 0;
		int paid = 0;
		int transferred = 0;
		string latest = "";
		foreach (FinancePayoutRecord payout in payouts)
		{
			string status = (payout.Status ?? "").Trim().ToLowerInvariant();
			if (string.IsNullOrWhiteSpace(payout.StripeTransferId) && string.IsNullOrWhiteSpace(payout.StripePayoutId))
			{
				switch (status)
				{
				default:
					if (!(status == "paid"))
					{
						break;
					}
					goto case "processing";
				case "processing":
				case "scheduled":
				case "transferred":
					missingStripeIds++;
					break;
				}
			}
			if (status == "processing" || status == "scheduled")
			{
				processing++;
			}
			if (status == "failed")
			{
				failed++;
			}
			if (status == "paid")
			{
				paid++;
			}
			if (status == "transferred")
			{
				transferred++;
			}
			if (string.CompareOrdinal(payout.RequestedUtc ?? "", latest) > 0)
			{
				latest = payout.RequestedUtc ?? "";
			}
		}
		int score = Math.Max(0, Math.Min(100, 100 - failed * 12 - missingStripeIds * 8 - processing * 2));
		return new
		{
			webhookEvents = new string[7] { "payout.created", "payout.updated", "payout.paid", "payout.failed", "transfer.created", "transfer.updated", "transfer.reversed" },
			total = payouts.Count,
			processing = processing,
			transferred = transferred,
			paid = paid,
			failed = failed,
			missingStripeIds = missingStripeIds,
			latestRequestedUtc = latest,
			reconciliationScore = score,
			reconciliationTier = ((score >= 90) ? "Healthy" : ((score >= 75) ? "Watch" : ((score >= 55) ? "Needs Review" : "Blocked")))
		};
	}

	private bool IsKnownFinancePayoutStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant();
		int result;
		switch (status)
		{
		default:
			result = ((status == "failed") ? 1 : 0);
			break;
		case "requested":
		case "processing":
		case "scheduled":
		case "transferred":
		case "paid":
		case "cancelled":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private bool IsPendingFinancePayoutStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant();
		return status == "requested" || status == "processing" || status == "scheduled";
	}

	private bool IsPaidFinancePayoutStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant();
		return status == "paid" || status == "transferred";
	}

	private bool IsTerminalFailedFinancePayoutStatus(string status)
	{
		status = (status ?? "").Trim().ToLowerInvariant();
		return status == "cancelled" || status == "failed";
	}

	private string NormalizeFinancePayoutMethod(string method)
	{
		method = (method ?? "").Trim().ToLowerInvariant().Replace("-", "_");
		if (method == "instant" || method == "instant_pay" || method == "instant_payout")
		{
			return "instant";
		}
		if (method == "weekly" || method == "weekly_direct_deposit")
		{
			return "weekly";
		}
		return "direct_deposit";
	}

	private string NormalizeFinancePayoutSchedule(string schedule)
	{
		schedule = (schedule ?? "").Trim().ToLowerInvariant().Replace("-", "_");
		if (schedule == "manual" || schedule == "daily" || schedule == "monthly")
		{
			return schedule;
		}
		return "weekly";
	}

	private string NormalizeFinanceWeeklyPayoutDay(string day)
	{
		switch ((day ?? "").Trim().ToLowerInvariant())
		{
		case "monday":
		case "tuesday":
		case "wednesday":
		case "thursday":
		case "friday":
			return day.Trim().ToLowerInvariant();
		default:
			return "friday";
		}
	}

	private DayOfWeek ParseFinanceWeeklyPayoutDay(string day)
	{
		return NormalizeFinanceWeeklyPayoutDay(day) switch
		{
			"monday" => DayOfWeek.Monday, 
			"tuesday" => DayOfWeek.Tuesday, 
			"wednesday" => DayOfWeek.Wednesday, 
			"thursday" => DayOfWeek.Thursday, 
			_ => DayOfWeek.Friday, 
		};
	}

	private double GetFinanceInstantPayoutFeeTaxRate(FinanceAccountProfile profile)
	{
		if (profile == null || !string.Equals(profile.TaxCountry, "US", StringComparison.OrdinalIgnoreCase))
		{
			return 0.0;
		}
		return GetEffectiveServiceTaxRate(GetChatCostSettings());
	}

	private long UsdToMinorUnits(double amountUsd)
	{
		return (long)Math.Round(Math.Max(0.0, NormalizeCostNumber(amountUsd)) * 100.0, MidpointRounding.AwayFromZero);
	}

	private DateTimeOffset EstimateFinanceDirectDepositArrivalUtc()
	{
		DateTimeOffset value = DateTimeOffset.UtcNow;
		int businessDays = 0;
		while (businessDays < 2)
		{
			value = value.AddDays(1.0);
			if (value.DayOfWeek != DayOfWeek.Saturday && value.DayOfWeek != DayOfWeek.Sunday)
			{
				businessDays++;
			}
		}
		return value;
	}

	private void RecordFinanceTokenOperation(string ownerKey, string operation, long tokensDelta, double tokenCostUsd, double electricityCostUsd, double serviceTaxCostUsd, double totalCostUsd, string note = "", string sessionId = "", ChatResourceUsageDelta resourceDelta = null, double gpuElectricityCostUsd = 0.0, double cpuElectricityCostUsd = 0.0, double ramElectricityCostUsd = 0.0, double systemElectricityCostUsd = 0.0, double ioElectricityCostUsd = 0.0)
	{
		ownerKey = NormalizeCostOwnerKey(ownerKey);
		if (!string.IsNullOrWhiteSpace(ownerKey))
		{
			LmVsProxyServerProfile profile = GetServerBrowserProfile();
			resourceDelta = resourceDelta ?? new ChatResourceUsageDelta();
			long safeTokens = Math.Max(0L, tokensDelta);
			FinanceTokenOperationRecord record = new FinanceTokenOperationRecord
			{
				Id = "tokop_" + Guid.NewGuid().ToString("N"),
				OwnerKey = ownerKey,
				UserName = GetUserNameFromOwnerKey(ownerKey),
				Operation = (string.IsNullOrWhiteSpace(operation) ? "usage_charge" : operation),
				TokensDelta = safeTokens,
				TokenCostUsd = NormalizeCostNumber(tokenCostUsd),
				ElectricityCostUsd = NormalizeCostNumber(electricityCostUsd),
				ServiceTaxCostUsd = NormalizeCostNumber(serviceTaxCostUsd),
				TotalCostUsd = NormalizeCostNumber(totalCostUsd),
				CreatedUtc = DateTimeOffset.UtcNow.ToString("O"),
				ServerId = (profile.ServerId ?? ""),
				SessionId = (sessionId ?? ""),
				Note = (note ?? ""),
				GpuSecondsDelta = NormalizeCostNumber(resourceDelta.gpuSeconds),
				CpuComputeSecondsDelta = NormalizeCostNumber(resourceDelta.cpuComputeSeconds),
				RamGbSecondsDelta = NormalizeCostNumber(resourceDelta.ramGbSeconds),
				SystemSecondsDelta = NormalizeCostNumber(resourceDelta.systemSeconds),
				IoBytesDelta = Math.Max(0L, resourceDelta.ioBytes),
				GpuElectricityCostUsd = NormalizeCostNumber(gpuElectricityCostUsd),
				CpuElectricityCostUsd = NormalizeCostNumber(cpuElectricityCostUsd),
				RamElectricityCostUsd = NormalizeCostNumber(ramElectricityCostUsd),
				SystemElectricityCostUsd = NormalizeCostNumber(systemElectricityCostUsd),
				IoElectricityCostUsd = NormalizeCostNumber(ioElectricityCostUsd),
				GpuSecondsPerToken = ((safeTokens <= 0) ? 0.0 : NormalizeCostNumber(resourceDelta.gpuSeconds / (double)safeTokens)),
				CpuComputeSecondsPerToken = ((safeTokens <= 0) ? 0.0 : NormalizeCostNumber(resourceDelta.cpuComputeSeconds / (double)safeTokens))
			};
			GetFinanceTokenOperationsTable().Rows.Add(FinanceTokenOperationToRow(record));
			RecordFinanceUsageLedger(record);
		}
	}

	private void RecordFinanceUsageLedger(FinanceTokenOperationRecord record)
	{
		if (record != null && !string.IsNullOrWhiteSpace(record.OwnerKey))
		{
			MarketplaceLeaseRecord lease = FindActiveMarketplaceLease(record.OwnerKey);
			double wallSeconds = Math.Max(record.GpuSecondsDelta, Math.Max(record.CpuComputeSecondsDelta, record.SystemSecondsDelta));
			double platformFee = NormalizeCostNumber(record.TotalCostUsd * 0.015);
			double hostNet = NormalizeCostNumber(Math.Max(0.0, record.TotalCostUsd - platformFee));
			string metadataJson = JsonSerializer.Serialize(new
			{
				TokenCostUsd = record.TokenCostUsd,
				ElectricityCostUsd = record.ElectricityCostUsd,
				ServiceTaxCostUsd = record.ServiceTaxCostUsd,
				GpuElectricityCostUsd = record.GpuElectricityCostUsd,
				CpuElectricityCostUsd = record.CpuElectricityCostUsd,
				RamElectricityCostUsd = record.RamElectricityCostUsd,
				SystemElectricityCostUsd = record.SystemElectricityCostUsd,
				IoElectricityCostUsd = record.IoElectricityCostUsd,
				GpuSecondsPerToken = record.GpuSecondsPerToken,
				CpuComputeSecondsPerToken = record.CpuComputeSecondsPerToken,
				leaseStatus = ((lease == null) ? "none" : GetEffectiveMarketplaceLeaseStatus(lease))
			});
			object[] row = NormalizeFinanceUsageLedgerRow(new object[24]
			{
				"ledger_" + Guid.NewGuid().ToString("N"),
				record.Id ?? "",
				record.OwnerKey ?? "",
				record.UserName ?? "",
				lease?.Id ?? "",
				record.ServerId ?? "",
				record.SessionId ?? "",
				record.Operation ?? "usage_charge",
				Math.Max(0L, record.TokensDelta).ToString(CultureInfo.InvariantCulture),
				wallSeconds.ToString("0.######", CultureInfo.InvariantCulture),
				record.GpuSecondsDelta.ToString("0.######", CultureInfo.InvariantCulture),
				record.CpuComputeSecondsDelta.ToString("0.######", CultureInfo.InvariantCulture),
				record.RamGbSecondsDelta.ToString("0.######", CultureInfo.InvariantCulture),
				Math.Max(0L, record.IoBytesDelta).ToString(CultureInfo.InvariantCulture),
				"0",
				Math.Max(0L, record.IoBytesDelta).ToString(CultureInfo.InvariantCulture),
				"0",
				"0",
				record.TotalCostUsd.ToString("0.########", CultureInfo.InvariantCulture),
				platformFee.ToString("0.########", CultureInfo.InvariantCulture),
				hostNet.ToString("0.########", CultureInfo.InvariantCulture),
				"recorded",
				string.IsNullOrWhiteSpace(record.CreatedUtc) ? DateTimeOffset.UtcNow.ToString("O") : record.CreatedUtc,
				metadataJson
			});
			GetFinanceUsageLedgerTable().Rows.Add(row);
		}
	}

	private void SaveHardwareAttestationPayload(string ownerKey, string payloadJson)
	{
		payloadJson = NormalizeJsonObjectRawText(payloadJson);
		string serverId = "";
		string fingerprint = "";
		string signature = "";
		string signatureTrust = "";
		try
		{
			using JsonDocument document = JsonDocument.Parse(payloadJson);
			JsonElement root = document.RootElement;
			fingerprint = ExtractStringProperty(root, "fingerprint") ?? "";
			signature = ExtractStringProperty(root, "signature") ?? "";
			signatureTrust = ExtractStringProperty(root, "signatureTrust") ?? "";
			if (TryGetMasterJsonProperty(root, "claims", out var claims))
			{
				serverId = ExtractStringProperty(claims, "serverId") ?? "";
			}
		}
		catch
		{
		}
		object[] row = NormalizeHardwareAttestationRow(new object[8]
		{
			"attest_" + Guid.NewGuid().ToString("N"),
			NormalizeCostOwnerKey(ownerKey),
			serverId,
			fingerprint,
			signature,
			signatureTrust,
			DateTimeOffset.UtcNow.ToString("O"),
			payloadJson
		});
		lock (_chatSessionLock)
		{
			Table table = GetHardwareAttestationsTable();
			table.Rows.Add(row);
			while (table.Rows.Count > 250)
			{
				table.Rows.RemoveAt(0);
			}
			SaveChatSessionDataAndInvalidateCaches();
		}
	}

	private List<object> ListRecentHardwareAttestationPayloads(int take)
	{
		take = Math.Max(1, Math.Min(100, take));
		List<object> results = new List<object>();
		lock (_chatSessionLock)
		{
			Table table = GetHardwareAttestationsTable();
			int i = table.Rows.Count - 1;
			while (i >= 0 && results.Count < take)
			{
				object[] row = NormalizeHardwareAttestationRow(table.Rows[i]);
				results.Add(new
				{
					id = GetRowValue(row, 0),
					ownerKey = GetRowValue(row, 1),
					serverId = GetRowValue(row, 2),
					fingerprint = GetRowValue(row, 3),
					signatureTrust = GetRowValue(row, 5),
					createdUtc = GetRowValue(row, 6),
					payload = DeserializeJsonElement(GetRowValue(row, 7), "{}")
				});
				i--;
			}
		}
		return results;
	}

	private FinanceMoneySummary SummarizeFinanceOperations(IEnumerable<FinanceTokenOperationRecord> operations)
	{
		FinanceMoneySummary summary = new FinanceMoneySummary();
		if (operations != null)
		{
			foreach (FinanceTokenOperationRecord operation in operations)
			{
				summary.Tokens += Math.Max(0L, operation.TokensDelta);
				summary.TokenCostUsd = NormalizeCostNumber(summary.TokenCostUsd + operation.TokenCostUsd);
				summary.ElectricityCostUsd = NormalizeCostNumber(summary.ElectricityCostUsd + operation.ElectricityCostUsd);
				summary.ServiceTaxCostUsd = NormalizeCostNumber(summary.ServiceTaxCostUsd + operation.ServiceTaxCostUsd);
				summary.TotalCostUsd = NormalizeCostNumber(summary.TotalCostUsd + operation.TotalCostUsd);
			}
		}
		summary.GrossUsd = summary.TokenCostUsd;
		summary.SocketJackFeeUsd = NormalizeCostNumber(summary.GrossUsd * 0.015);
		summary.NetUsd = NormalizeCostNumber(Math.Max(0.0, summary.GrossUsd - summary.SocketJackFeeUsd - summary.ElectricityCostUsd));
		summary.ProfitMargin = ((summary.GrossUsd <= 0.0) ? 0.0 : NormalizeCostNumber(summary.NetUsd / summary.GrossUsd));
		return summary;
	}

	private object BuildFinanceTax1099Payload(string ownerKey, FinancePeriod period)
	{
		FinanceIdentity identity = new FinanceIdentity
		{
			OwnerKey = ownerKey,
			UserName = GetUserNameFromOwnerKey(ownerKey)
		};
		FinanceMoneySummary summary = SummarizeFinanceOperations(ListFinanceTokenOperations(identity, period));
		FinanceAccountProfile profile = GetOrCreateFinanceAccountProfile(ownerKey, identity.UserName);
		bool unitedStatesOnly = string.Equals(profile.TaxCountry, "US", StringComparison.OrdinalIgnoreCase);
		return new
		{
			available = unitedStatesOnly,
			country = profile.TaxCountry,
			printable = unitedStatesOnly,
			form = "1099-NEC service earnings summary",
			taxpayerName = profile.TaxpayerName,
			taxIdentifierMasked = profile.TaxIdentifierMasked,
			earningsUsd = summary.NetUsd,
			grossUsd = summary.GrossUsd,
			periodStartUtc = period.StartUtc.ToString("O"),
			periodEndUtc = period.EndUtc.ToString("O"),
			note = (unitedStatesOnly ? "Printable United States other-income summary." : "1099 summaries are only available for United States tax profiles.")
		};
	}

	private bool IsFinanceDateInPeriod(string value, FinancePeriod period)
	{
		if (period == null)
		{
			return true;
		}
		if (!DateTimeOffset.TryParse(value ?? "", CultureInfo.InvariantCulture, DateTimeStyles.AssumeUniversal, out var date))
		{
			return true;
		}
		date = date.ToUniversalTime();
		return date >= period.StartUtc && date <= period.EndUtc;
	}

	private IEnumerable<object> BuildPieSlices(IEnumerable<FinancePiePart> parts)
	{
		List<FinancePiePart> clean = (parts ?? Enumerable.Empty<FinancePiePart>()).Where((FinancePiePart p) => p != null && p.Value > 0.0).ToList();
		double total = clean.Sum((FinancePiePart p) => p.Value);
		if (total <= 0.0)
		{
			clean = new List<FinancePiePart>
			{
				new FinancePiePart("No data", 1.0)
			};
		}
		total = clean.Sum((FinancePiePart p) => p.Value);
		return clean.Select((FinancePiePart p, int i) => new
		{
			label = p.Label,
			value = NormalizeCostNumber(p.Value),
			percent = NormalizeCostNumber(p.Value / total),
			color = FinanceChartColor(i)
		}).ToList();
	}

	private IEnumerable<object> BuildTopEarners(IEnumerable<FinanceTokenOperationRecord> operations)
	{
		return (from x in (operations ?? Enumerable.Empty<FinanceTokenOperationRecord>()).GroupBy<FinanceTokenOperationRecord, string>((FinanceTokenOperationRecord o) => string.IsNullOrWhiteSpace(o.UserName) ? o.OwnerKey : o.UserName, StringComparer.OrdinalIgnoreCase).Select(delegate(IGrouping<string, FinanceTokenOperationRecord> g)
			{
				FinanceMoneySummary financeMoneySummary = SummarizeFinanceOperations(g);
				return new
				{
					username = g.Key,
					tokens = financeMoneySummary.Tokens,
					grossUsd = financeMoneySummary.GrossUsd,
					netUsd = financeMoneySummary.NetUsd
				};
			})
			orderby x.netUsd descending
			select x).Take(8).ToList();
	}

	private IEnumerable<object> BuildTopExploitedServers(IEnumerable<FinanceTokenOperationRecord> operations)
	{
		LmVsProxyServerProfile profile = GetServerBrowserProfile();
		return (from x in (operations ?? Enumerable.Empty<FinanceTokenOperationRecord>()).GroupBy<FinanceTokenOperationRecord, string>((FinanceTokenOperationRecord o) => string.IsNullOrWhiteSpace(o.ServerId) ? (profile.ServerId ?? "local") : o.ServerId, StringComparer.OrdinalIgnoreCase).Select(delegate(IGrouping<string, FinanceTokenOperationRecord> g)
			{
				FinanceMoneySummary financeMoneySummary = SummarizeFinanceOperations(g);
				double num = CalculateExploitRating(financeMoneySummary);
				return new
				{
					serverId = g.Key,
					serverName = profile.ServerName,
					rating = num,
					color = ExploitRatingColor(num),
					tokens = financeMoneySummary.Tokens,
					netUsd = financeMoneySummary.NetUsd,
					reason = ((num >= 7.0) ? "High utilization with thin margin" : ((num >= 4.0) ? "Watch utilization and margin" : "Healthy margin"))
				};
			})
			orderby x.rating descending
			select x).Take(8).ToList();
	}

	private double CalculateExploitRating(FinanceMoneySummary summary)
	{
		if (summary == null || summary.GrossUsd <= 0.0)
		{
			return 0.0;
		}
		double costPressure = Math.Min(1.0, (summary.ElectricityCostUsd + summary.ServiceTaxCostUsd + summary.SocketJackFeeUsd) / summary.GrossUsd);
		double tokenPressure = Math.Min(1.0, (double)summary.Tokens / 100000.0);
		return NormalizeCostNumber(Math.Max(0.0, Math.Min(10.0, costPressure * 7.0 + tokenPressure * 3.0)));
	}

	private string ExploitRatingColor(double rating)
	{
		rating = Math.Max(0.0, Math.Min(10.0, rating));
		double r;
		double g;
		if (rating <= 5.0)
		{
			r = 34.0 + 215.0 * (rating / 5.0);
			g = 197.0 + -82.0 * (rating / 5.0);
		}
		else
		{
			r = 249.0 + -10.0 * ((rating - 5.0) / 5.0);
			g = 115.0 + -47.0 * ((rating - 5.0) / 5.0);
		}
		return "rgb(" + ((int)Math.Round(r)).ToString(CultureInfo.InvariantCulture) + "," + ((int)Math.Round(g)).ToString(CultureInfo.InvariantCulture) + ",68)";
	}

	private string FinanceChartColor(int index)
	{
		string[] colors = new string[8] { "#22c55e", "#f97316", "#ef4444", "#38bdf8", "#a78bfa", "#facc15", "#14b8a6", "#fb7185" };
		return colors[Math.Abs(index) % colors.Length];
	}

	private string MaskTaxIdentifier(string value)
	{
		string digits = new string((value ?? "").Where(char.IsDigit).ToArray());
		if (digits.Length <= 4)
		{
			return string.IsNullOrWhiteSpace(digits) ? "" : ("****" + digits);
		}
		return "****" + digits.Substring(digits.Length - 4);
	}

