	private Dictionary<string, string> ReadFinancePaymentMetadata(string metadataJson)
	{
		try
		{
			Dictionary<string, string> values = JsonSerializer.Deserialize<Dictionary<string, string>>(string.IsNullOrWhiteSpace(metadataJson) ? "{}" : metadataJson);
			return (values == null) ? new Dictionary<string, string>(StringComparer.Ordinal) : new Dictionary<string, string>(values, StringComparer.Ordinal);
		}
		catch
		{
			return new Dictionary<string, string>(StringComparer.Ordinal);
		}
	}

	private string WriteFinancePaymentMetadata(IDictionary<string, string> metadata)
	{
		return JsonSerializer.Serialize((metadata == null) ? new Dictionary<string, string>(StringComparer.Ordinal) : new Dictionary<string, string>(metadata, StringComparer.Ordinal));
	}

