				bool flag2 = flag;
				if (flag2)
				{
					flag2 = await TryHandleChatUiDirectAgentDownloadAsync(output, request?.Body, streamOwnerKey, sessionId, sharedParticipantKey, promptSessionId, usageMeter, emitToolCall).ConfigureAwait(continueOnCapturedContext: false);
