				{
					WriteChatUiProgressWithUsage(output, streamOwnerKey, usageMeter, progress, "runtime_preflight", status, 0L, 0L);
				}, requestBody: request?.Body, cancellationToken: cancellationToken).ConfigureAwait(continueOnCapturedContext: false));
				if ((agentMode && permissions.agentAccess) || browserMode || (terminalMode && permissions.terminalCommands))
				{
					string toolRequestJson = BuildChatUiCompletionRequestJson(request?.Body, streamResponses: false, permissions, promptUserName, streamOwnerKey, includeMemories: !sharedChat);
					toolRequestJson = AddProxyResearchTools(toolRequestJson, permissions, agentMode, agentMode || terminalMode, agentMode || browserMode, streamOwnerKey);
					promptSessionId = promptSessionId ?? BeginActivePromptSession(agentMode ? "Web UI Agent" : (browserMode ? "Web UI Browser Skill" : "Web UI Terminal"), streamOwnerKey, toolRequestJson, sessionId, sharedParticipantKey);
					string agentStatus = imageRequest
						? ("Processing image in " + selectedRuntimeDisplayName + "...")
						: (agentMode
							? ("Running agent prompt on " + selectedRuntimeDisplayName + "...")
							: (browserMode
								? ("Running Browser Skill prompt on " + selectedRuntimeDisplayName + "...")
								: ("Running terminal prompt on " + selectedRuntimeDisplayName + "...")));
					WriteChatUiProgressWithUsage(output, streamOwnerKey, usageMeter, null, "prompt_processing", agentStatus, 0L, 0L);
					StringBuilder liveContent = new StringBuilder();
					StringBuilder liveReasoning = new StringBuilder();
					ChatUiCompletion completion = NormalizeChatUiCompletionForDisplay(await AwaitChatUiOperationWithProgressAsync(ExecuteChatUiCompletionWithProxyToolsAsync(emitLiveReasoning: delegate(string reasoning)
					{
						if (string.IsNullOrEmpty(reasoning))
						{
							return true;
						}
						liveReasoning.Append(reasoning);
						return WriteChatUiDeltaWithUsage(output, streamOwnerKey, "", reasoning, "", usageMeter, cancellationToken, promptSessionId);
					}, emitLiveContent: delegate(string text2)
					{
						if (string.IsNullOrEmpty(text2))
						{
							return true;
						}
						liveContent.Append(text2);
						return WriteChatUiDeltaWithUsage(output, streamOwnerKey, text2, "", "", usageMeter, cancellationToken, promptSessionId);
					}, lmRequestJson: toolRequestJson, ownerKey: streamOwnerKey, sessionId: sessionId, cancellationToken: cancellationToken, consumeSteering: () => ConsumeActiveChatStreamSteering(activeStreamCancellation), emitToolCall: emitToolCall), output, promptSessionId, "prompt_processing", agentStatus, cancellationToken, streamOwnerKey, usageMeter), toolRequestJson);
					completion = await ContinueChatUiCompletionForLateSteeringAsync(completion, toolRequestJson, activeStreamCancellation, streamOwnerKey, sessionId, cancellationToken, delegate(string reasoning)
					{
						if (string.IsNullOrEmpty(reasoning))
						{
							return true;
						}
						liveReasoning.Append(reasoning);
						return WriteChatUiDeltaWithUsage(output, streamOwnerKey, "", reasoning, "", usageMeter, cancellationToken, promptSessionId);
					}, delegate(string text2)
					{
						if (string.IsNullOrEmpty(text2))
						{
							return true;
						}
						liveContent.Append(text2);
						return WriteChatUiDeltaWithUsage(output, streamOwnerKey, text2, "", "", usageMeter, cancellationToken, promptSessionId);
					}, emitToolCall).ConfigureAwait(continueOnCapturedContext: false);
					if (!HasChatUiCompletionOutput(completion))
					{
