	private bool RuntimeModelMatchesMediaService(JsonElement model, string serviceId)
	{
		string normalizedService = (serviceId ?? "").Trim().ToLowerInvariant();
		if (string.IsNullOrWhiteSpace(normalizedService))
		{
			return false;
		}
		string runtimeService = FirstNonEmpty(ExtractStringProperty(model, "chat_service"), ExtractStringProperty(model, "chatService"), ExtractStringProperty(model, "service"));
		if (string.Equals(runtimeService, normalizedService, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		string mediaKind = normalizedService.Replace("_generation", "");
		string type = ExtractStringProperty(model, "type") ?? "";
		if (string.Equals(type, mediaKind, StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		if (TryGetJsonProperty(model, out var capabilities, "capabilities") && capabilities.ValueKind == JsonValueKind.Object)
		{
			if (string.Equals(mediaKind, "image", StringComparison.OrdinalIgnoreCase) && (ReadJsonBoolProperty(capabilities, "image_generation", fallback: false) || ReadJsonBoolProperty(capabilities, "imageGeneration", fallback: false)))
			{
				return true;
			}
			if (string.Equals(mediaKind, "audio", StringComparison.OrdinalIgnoreCase) && (ReadJsonBoolProperty(capabilities, "audio_generation", fallback: false) || ReadJsonBoolProperty(capabilities, "audioGeneration", fallback: false)))
			{
				return true;
			}
			if (string.Equals(mediaKind, "video", StringComparison.OrdinalIgnoreCase) && (ReadJsonBoolProperty(capabilities, "video_generation", fallback: false) || ReadJsonBoolProperty(capabilities, "videoGeneration", fallback: false)))
			{
				return true;
			}
		}
		if (model.TryGetProperty("tags", out var tags) && tags.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement tag in tags.EnumerateArray())
			{
				string tagText = tag.ValueKind == JsonValueKind.String ? (tag.GetString() ?? "") : "";
				if (string.Equals(tagText, mediaKind, StringComparison.OrdinalIgnoreCase) ||
					tagText.EndsWith("-to-" + mediaKind, StringComparison.OrdinalIgnoreCase) ||
					tagText.EndsWith("_to_" + mediaKind, StringComparison.OrdinalIgnoreCase) ||
					tagText.StartsWith(mediaKind + "-to-", StringComparison.OrdinalIgnoreCase) ||
					tagText.StartsWith(mediaKind + "_to_", StringComparison.OrdinalIgnoreCase))
				{
					return true;
				}
			}
		}
		return false;
	}

	private bool RuntimeModelHasLoadedInstances(JsonElement model)
	{
		if (TryGetJsonProperty(model, out var loaded, "loaded_instances", "loadedInstances", "loaded_models", "loadedModels"))
		{
			if (loaded.ValueKind == JsonValueKind.Array)
			{
				return loaded.GetArrayLength() > 0;
			}
			if (loaded.ValueKind == JsonValueKind.Object)
			{
				return true;
			}
			if (loaded.ValueKind == JsonValueKind.True)
			{
				return true;
			}
			if (loaded.ValueKind == JsonValueKind.String)
			{
				return !string.IsNullOrWhiteSpace(loaded.GetString());
			}
		}
		if (TryGetJsonProperty(model, out var loadedCount, "loaded_instance_count", "loadedInstanceCount", "loaded_count", "loadedCount"))
		{
			if (loadedCount.ValueKind == JsonValueKind.Number && loadedCount.TryGetInt32(out var count))
			{
				return count > 0;
			}
			if (loadedCount.ValueKind == JsonValueKind.String && int.TryParse(loadedCount.GetString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out count))
			{
				return count > 0;
			}
		}
		if (TryGetJsonProperty(model, out var loadedFlag, "loaded", "is_loaded", "isLoaded", "active", "ready", "available"))
		{
			return ReadJsonBool(loadedFlag, fallback: false);
		}
		return false;
	}

	private string ExtractRuntimeModelId(JsonElement model)
	{
		return FirstNonEmpty(ExtractStringProperty(model, "key"), ExtractStringProperty(model, "id"), ExtractStringProperty(model, "name"), ExtractStringProperty(model, "model"), ExtractStringProperty(model, "display_name"), ExtractStringProperty(model, "displayName"));
	}

	private bool RuntimeModelIdMatches(string modelId, string requestedModel)
	{
		modelId = (modelId ?? "").Trim();
		requestedModel = (requestedModel ?? "").Trim();
		if (string.IsNullOrWhiteSpace(modelId) || string.IsNullOrWhiteSpace(requestedModel))
		{
			return false;
		}
		if (string.Equals(modelId, requestedModel, StringComparison.OrdinalIgnoreCase) || string.Equals(Path.GetFileName(modelId), Path.GetFileName(requestedModel), StringComparison.OrdinalIgnoreCase) || string.Equals(Path.GetFileNameWithoutExtension(modelId), Path.GetFileNameWithoutExtension(requestedModel), StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		return ModelIdentifierMatches(BuildModelIdentifierCandidates(requestedModel), modelId);
	}

	private bool TryGetJsonProperty(JsonElement element, out JsonElement value, params string[] propertyNames)
	{
		if (element.ValueKind == JsonValueKind.Object)
		{
			foreach (string propertyName in propertyNames)
			{
				if (!string.IsNullOrWhiteSpace(propertyName) && element.TryGetProperty(propertyName, out value))
				{
					return true;
				}
			}
		}
		value = default(JsonElement);
		return false;
	}

	private bool ReadJsonBoolProperty(JsonElement element, string propertyName, bool fallback)
	{
		JsonElement value;
		return (element.ValueKind == JsonValueKind.Object && element.TryGetProperty(propertyName, out value)) ? ReadJsonBool(value, fallback) : fallback;
	}

