			tokenCostUsd = tokenCostUsd,
			electricityCostUsd = electricityCostUsd,
			gpuElectricityCostUsd = gpuElectricityCostUsd,
			cpuElectricityCostUsd = cpuElectricityCostUsd,
			ramElectricityCostUsd = ramElectricityCostUsd,
