		}
		LogStreamDiagnostic(streamId, "adapter", diagnosticStartedUtc, "upstream read completed; upstreamLines=" + upstreamLines + "; dataFrames=" + dataFrames + "; passthroughFrames=" + passthroughFrames + "; suppressedFrames=" + suppressedFrames + "; contentFrames=" + contentFrames + "; reasoningFrames=" + reasoningFrames + "; parseRepairFrames=" + parseRepairFrames + "; nativeToolCalls=" + sawNativeToolCalls + "; qwenToolCalls=" + sawQwenToolCalls + "; looseToolCalls=" + sawLooseToolCalls);
		if (reasoningBuffer.Length > 0)
