			reasoningBuffer.Clear();
		}
		if (sawNativeToolCalls && nativeBuilders.Count > 0)
		{
			List<ToolCallData> toolCalls = BuildToolCallsFromBuilders(nativeBuilders, requestBody);
			if (toolCalls.Count > 0)
