			RedirectMissingCodebehindLoopToCreateFile(toolCallsLoose, requestBody);
			RedirectSearchLoopToCreateFile(toolCallsLoose, requestBody);
			GuardVagueGetFileTargets(toolCallsLoose, requestBody);
			GuardRepeatedGetFileLoop(toolCallsLoose, requestBody);
			GuardCreateFileForExistingTarget(toolCallsLoose, requestBody);
			GuardBlankReplaceStringCalls(toolCallsLoose, requestBody);
			GuardUnsafeCreateFileTargets(toolCallsLoose, requestBody);
