				LogToolCalls("live loose proxy tools", toolCallsLoose);
				LogStreamDiagnostic(streamId, "proxy-tools", diagnosticStartedUtc, "executing proxy-owned loose tool calls; count=" + toolCallsLoose.Count);
				await ForwardProxyToolResultAsync(toolCallsLoose, model, clientStream, writeLock, CancellationToken.None);
				passthroughFrames++;
				wroteDone = true;
			}
		}
		if (!wroteDone && !sawNativeToolCalls && !sawQwenToolCalls && !sawLooseToolCalls)
		{
			List<ToolCallData> looseToolCalls = ExtractLooseProxyToolCalls(assistantVisibleText.ToString());
			if (looseToolCalls.Count > 0)
			{
				HashSet<string> availableTools = GetAvailableToolNames(requestBody);
				RemapSuppressedToolCalls(looseToolCalls, availableTools, requestBody);
				TranslateUnsupportedBatchReplaceToolCalls(looseToolCalls, requestBody);
				RedirectMissingCodebehindLoopToCreateFile(looseToolCalls, requestBody);
				RedirectSearchLoopToCreateFile(looseToolCalls, requestBody);
