			GuardVagueGetFileTargets(toolCalls3, requestBody);
			GuardRepeatedGetFileLoop(toolCalls3, requestBody);
			LogToolCalls("text intent rescue", toolCalls3);
			LogStreamDiagnostic(streamId, "text-intent", diagnosticStartedUtc, "converted plain assistant read/check intent into tool call; count=" + toolCalls3.Count);
			await WriteClientTextAsync(BuildToolCallSseResponse(toolCalls3, model), "text-intent-tool-response");
			passthroughFrames++;
			wroteDone = true;
		}
		if (!wroteDone)
		{
			await WriteClientFrameAsync("data: [DONE]", "done");
			passthroughFrames++;
