		}
		else
		{
			LogStreamDiagnostic(streamId, "done", diagnosticStartedUtc, "stream already completed by tool continuation/response; no extra [DONE] written.");
		}
		LogStreamDiagnostic(streamId, "adapter-summary", diagnosticStartedUtc, "finished adapter; upstreamLines=" + upstreamLines + "; dataFrames=" + dataFrames + "; passthroughFrames=" + passthroughFrames + "; suppressedFrames=" + suppressedFrames + "; contentFrames=" + contentFrames + "; downstreamWrites=" + downstreamWrites + "; downstreamBytes=" + downstreamBytes + "; wroteDone=" + wroteDone);
		async Task WriteClientFrameAsync(string frameLine, string kind)
		{
			await WriteClientTextAsync(frameLine + "\n\n", kind);
		}
		async Task WriteClientTextAsync(string text2, string kind)
		{
			int byteCount = Encoding.UTF8.GetByteCount(text2 ?? "");
			await WriteRawSseTextLockedAsync(clientStream, writeLock, text2);
			downstreamWrites++;
			downstreamBytes += byteCount;
			if (downstreamWrites <= 6 || downstreamWrites % 50 == 0)
			{
				LogStreamDiagnostic(streamId, "downstream", diagnosticStartedUtc, "wrote client frame #" + downstreamWrites + "; kind=" + (string.IsNullOrWhiteSpace(kind) ? "unknown" : kind) + "; bytes=" + byteCount + "; totalBytes=" + downstreamBytes + "; preview=" + TruncateForLog(text2, 220));
			}
		}
	}

	private void AppendVisibleAssistantTextFromPayload(string payload, StringBuilder assistantVisibleText)
	{
		if (string.IsNullOrWhiteSpace(payload) || assistantVisibleText == null)
		{
			return;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(payload);
			if (!document.RootElement.TryGetProperty("choices", out var choices) || choices.ValueKind != JsonValueKind.Array)
			{
				return;
			}
			foreach (JsonElement item in choices.EnumerateArray())
			{
				if (item.TryGetProperty("delta", out var delta) && delta.ValueKind == JsonValueKind.Object && delta.TryGetProperty("content", out var contentElement) && contentElement.ValueKind == JsonValueKind.String)
				{
					assistantVisibleText.Append(contentElement.GetString() ?? "");
				}
			}
		}
		catch
		{
		}
	}

	private bool TryBuildToolCallFromPlainTextIntent(string assistantText, string requestBody, out ToolCallData toolCall)
	{
		toolCall = null;
		if (string.IsNullOrWhiteSpace(assistantText) || string.IsNullOrWhiteSpace(requestBody) || !IsToolAdvertised(requestBody, "get_file") || IsToolChoiceNone(requestBody))
		{
			return false;
		}
		string normalizedText = assistantText.Replace("\r", "\n");
		string lower = normalizedText.ToLowerInvariant();
		if (!lower.Contains("let me read", StringComparison.Ordinal) && !lower.Contains("i'll read", StringComparison.Ordinal) && !lower.Contains("i will read", StringComparison.Ordinal) && !lower.Contains("read the", StringComparison.Ordinal) && !lower.Contains("reading the", StringComparison.Ordinal) && !lower.Contains("check the", StringComparison.Ordinal) && !lower.Contains("open the", StringComparison.Ordinal) && !lower.Contains("get the current content", StringComparison.Ordinal) && !lower.Contains("get current content", StringComparison.Ordinal) && !lower.Contains("understand the structure", StringComparison.Ordinal))
		{
			return false;
		}
		if (!TryExtractFilePathFromPlainTextIntent(normalizedText, requestBody, out var filename))
		{
			return false;
		}
		filename = NormalizeToolPathForVsArgument(filename);
		if (string.IsNullOrWhiteSpace(filename) || !HasUsableFileNameStem(filename))
		{
			return false;
		}
		toolCall = new ToolCallData
		{
			Id = "call_" + Guid.NewGuid().ToString("N").Substring(0, 16),
			Name = "get_file",
			ArgumentsJson = "{\"filename\":\"" + EscapeJson(filename) + "\",\"startLine\":1,\"endLine\":400,\"includeLineNumbers\":true}",
			ArgumentsWereMalformed = false
		};
		LogMessage("[Text Intent Rescue] Converted text-only read/check intent to get_file for " + filename + ".");
		return true;
	}

	private bool TryExtractFilePathFromPlainTextIntent(string assistantText, string requestBody, out string filename)
	{
		filename = null;
		if (string.IsNullOrWhiteSpace(assistantText))
		{
			return false;
		}
		MatchCollection matches = Regex.Matches(assistantText, "(?ix)(?<path>(?:[A-Za-z0-9_. \\-]+[\\\\/]){0,8}[A-Za-z0-9_. \\-]+\\.(?:xaml\\.vb|xaml|vb|cs|csproj|vbproj|json|xml|config|resx|txt|md))");
		for (int i = matches.Count - 1; i >= 0; i--)
		{
			string candidate = CleanPlainTextFilePathCandidate(matches[i].Groups["path"].Value);
			if (!string.IsNullOrWhiteSpace(candidate) && HasUsableFileNameStem(candidate))
			{
				filename = ResolvePlainTextIntentPathForVs(candidate, requestBody);
				if (!string.IsNullOrWhiteSpace(filename))
				{
					return true;
				}
			}
		}
		return false;
	}

	private string CleanPlainTextFilePathCandidate(string value)
	{
		return CleanToolFilePathArgument(value);
	}

	private string CleanToolFilePathArgument(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return null;
		}
		string cleaned = NormalizeLoosePathEscapes(value).Trim().Trim('"', '\'', '`', ',', '.', ':', ';', ')', ']', '}', ' ');
		cleaned = StripLeadingPathNoiseWords(cleaned);
		if (!cleaned.Contains("/", StringComparison.Ordinal) && !cleaned.Contains("\\", StringComparison.Ordinal) && cleaned.Contains(" ", StringComparison.Ordinal))
		{
			string[] parts = cleaned.Split(new char[1] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
			if (parts.Length > 1 && LooksLikeToolIntentNoiseWord(parts[0]) && LooksLikeFileName(parts[^1]))
			{
				cleaned = parts[^1];
			}
		}
		return CanonicalizeDuplicateFileExtensions(cleaned);
	}

	private string StripLeadingPathNoiseWords(string value)
	{
		string cleaned = value;
		bool changed;
		do
		{
			changed = false;
			string[] noiseWords = new string[22]
			{
				"the", "file", "read", "reading", "check", "checking", "open", "opening", "get", "getting",
				"update", "updating", "edit", "editing", "modify", "modifying", "create", "creating", "current", "content",
				"for", "of"
			};
			string[] array = noiseWords;
			foreach (string word in array)
			{
				string prefix = word + " ";
				if (cleaned.StartsWith(prefix, StringComparison.OrdinalIgnoreCase))
				{
					cleaned = cleaned.Substring(prefix.Length).Trim();
					changed = true;
				}
			}
		}
		while (changed);
		return cleaned;
	}

	private bool LooksLikeToolIntentNoiseWord(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return false;
		}
		string lower = value.Trim().Trim(':', '-', '.', ',').ToLowerInvariant();
		return lower.Equals("the", StringComparison.Ordinal) || lower.Equals("file", StringComparison.Ordinal) || lower.Equals("read", StringComparison.Ordinal) || lower.Equals("check", StringComparison.Ordinal) || lower.Equals("open", StringComparison.Ordinal) || lower.Equals("get", StringComparison.Ordinal) || lower.Equals("update", StringComparison.Ordinal) || lower.Equals("edit", StringComparison.Ordinal) || lower.Equals("modify", StringComparison.Ordinal) || lower.Equals("create", StringComparison.Ordinal);
	}

	private string ResolvePlainTextIntentPathForVs(string candidate, string requestBody)
	{
		candidate = NormalizeToolPathForVsArgument(candidate);
		if (string.IsNullOrWhiteSpace(candidate))
		{
			return null;
		}
		if (TryResolveLocalFilePath(candidate, out var resolvedFullPath))
		{
			string relative = TryGetSolutionRelativePath(resolvedFullPath);
			return string.IsNullOrWhiteSpace(relative) ? NormalizeToolPathForVsArgument(candidate) : NormalizeToolPathForVsArgument(relative);
		}
		if (candidate.Contains("/", StringComparison.Ordinal) || candidate.Contains("\\", StringComparison.Ordinal))
		{
			return candidate;
		}
		string prefix = InferProjectDirectoryPrefixFromRequest(requestBody);
		return string.IsNullOrWhiteSpace(prefix) ? candidate : NormalizeToolPathForVsArgument(prefix.TrimEnd('/', '\\') + "/" + candidate);
	}

	private string TryGetSolutionRelativePath(string fullPath)
	{
		if (string.IsNullOrWhiteSpace(fullPath))
		{
			return null;
		}
		try
		{
			string normalizedFullPath = Path.GetFullPath(fullPath);
			for (DirectoryInfo directory = new FileInfo(normalizedFullPath).Directory; directory != null; directory = directory.Parent)
			{
				if (Directory.GetFiles(directory.FullName, "*.sln", SearchOption.TopDirectoryOnly).Length != 0)
				{
					return Path.GetRelativePath(directory.FullName, normalizedFullPath);
				}
			}
		}
		catch
		{
		}
		return null;
	}

	private string InferProjectDirectoryPrefixFromRequest(string requestBody)
	{
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return null;
		}
		Match match = Regex.Match(requestBody, "\"(?:projectPath|filename|filePath)\"\\s*:\\s*\"(?<path>[^\"]+[\\\\/][^\"]+\\.(?:vbproj|csproj|xaml|vb|cs))\"", RegexOptions.IgnoreCase);
		if (!match.Success)
		{
			return null;
		}
		string path = NormalizeToolPathForVsArgument(match.Groups["path"].Value);
		int slash = path.IndexOf('/');
		if (slash <= 0)
		{
			return null;
		}
		return path.Substring(0, slash);
	}

	private void AccumulateNativeToolCallDeltas(Dictionary<int, ToolCallBuilder> builders, JsonElement nativeToolCalls)
	{
		foreach (JsonElement toolCall in nativeToolCalls.EnumerateArray())
		{
			JsonElement indexElement;
			int parsedIndex;
			int index = ((toolCall.TryGetProperty("index", out indexElement) && indexElement.ValueKind == JsonValueKind.Number && indexElement.TryGetInt32(out parsedIndex)) ? parsedIndex : builders.Count);
			if (!builders.TryGetValue(index, out var builder))
			{
				builder = (builders[index] = new ToolCallBuilder());
			}
			if (toolCall.TryGetProperty("id", out var idElement) && idElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(idElement.GetString()))
			{
				builder.Id = idElement.GetString();
			}
			if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
			{
				if (function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(nameElement.GetString()))
				{
					builder.Name = nameElement.GetString();
				}
				if (function.TryGetProperty("arguments", out var argumentsElement))
				{
					builder.Arguments.Append((argumentsElement.ValueKind == JsonValueKind.String) ? argumentsElement.GetString() : argumentsElement.ToString());
				}
			}
		}
	}

	private List<ToolCallData> BuildToolCallsFromBuilders(Dictionary<int, ToolCallBuilder> builders, string requestBody)
	{
		List<ToolCallData> toolCalls = new List<ToolCallData>();
		foreach (KeyValuePair<int, ToolCallBuilder> builder2 in builders)
		{
			ToolCallBuilder builder = builder2.Value;
			if (builder != null && !string.IsNullOrWhiteSpace(builder.Name))
			{
				string rawArguments = builder.Arguments.ToString();
				if (string.IsNullOrWhiteSpace(rawArguments))
				{
					rawArguments = "{}";
				}
				bool argumentsWereMalformed = !IsValidJsonObject(rawArguments);
				string repairedArguments = RepairKnownToolArguments(builder.Name, rawArguments);
				toolCalls.Add(new ToolCallData
				{
					Id = builder.Id,
					Name = builder.Name,
					ArgumentsJson = repairedArguments,
					ArgumentsWereMalformed = argumentsWereMalformed
				});
			}
		}
		HashSet<string> availableTools = GetAvailableToolNames(requestBody);
		RemapSuppressedToolCalls(toolCalls, availableTools, requestBody);
		TranslateUnsupportedBatchReplaceToolCalls(toolCalls, requestBody);
		GuardMalformedEditToolCalls(toolCalls, requestBody);
		RedirectMissingCodebehindLoopToCreateFile(toolCalls, requestBody);
		RedirectSearchLoopToCreateFile(toolCalls, requestBody);
		GuardVagueGetFileTargets(toolCalls, requestBody);
		GuardRepeatedGetFileLoop(toolCalls, requestBody);
		GuardCreateFileForExistingTarget(toolCalls, requestBody);
		GuardBlankReplaceStringCalls(toolCalls, requestBody);
		GuardNoOpReplaceStringCalls(toolCalls);
		GuardUnsafeCreateFileTargets(toolCalls, requestBody);
		if (availableTools.Count > 0)
		{
			toolCalls.RemoveAll((ToolCallData toolCall) => toolCall == null || string.IsNullOrWhiteSpace(toolCall.Name) || !availableTools.Contains(toolCall.Name));
		}
		return toolCalls;
	}

	private void AddToolCallsToBuilders(Dictionary<int, ToolCallBuilder> builders, IEnumerable<ToolCallData> toolCalls)
	{
		if (builders == null || toolCalls == null)
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || string.IsNullOrWhiteSpace(toolCall.Name))
			{
				continue;
			}
			string argumentsJson = string.IsNullOrWhiteSpace(toolCall.ArgumentsJson) ? "{}" : toolCall.ArgumentsJson;
			ToolCallBuilder builder = new ToolCallBuilder
			{
				Id = string.IsNullOrWhiteSpace(toolCall.Id) ? ("call_" + Guid.NewGuid().ToString("N")) : toolCall.Id,
				Name = toolCall.Name
			};
			builder.Arguments.Append(RepairKnownToolArguments(toolCall.Name, argumentsJson));
			builders[builders.Count] = builder;
		}
	}

	private string InterceptQwenToolCallContent(string content, StringBuilder qwenToolText, ref bool sawQwenToolCalls)
	{
		if (string.IsNullOrEmpty(content))
		{
			return content;
		}
		if (sawQwenToolCalls)
		{
			qwenToolText.Append(content);
			return "";
		}
		int toolStart = FindQwenToolCallOpenTag(content, 0, out var _, out var _);
		if (toolStart < 0)
		{
			return content;
		}
		sawQwenToolCalls = true;
		qwenToolText.Append(content.Substring(toolStart));
		return content.Substring(0, toolStart);
	}

	private bool ContainsQwenToolCallOpenTag(string content)
	{
		return FindQwenToolCallOpenTag(content, 0, out var _, out var _) >= 0;
	}

	private int FindQwenToolCallOpenTag(string content, int searchStart, out int openTagEnd, out string openTag)
	{
		openTagEnd = -1;
		openTag = "";
		if (string.IsNullOrEmpty(content) || searchStart >= content.Length)
		{
			return -1;
		}
		int safeStart = Math.Max(0, searchStart);
		Match match = Regex.Match(content.Substring(safeStart), "<\\s*tool_call\\b[^>]*>", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		if (!match.Success)
		{
			return -1;
		}
		openTag = match.Value;
		int index = safeStart + match.Index;
		openTagEnd = index + match.Length;
		return index;
	}

	private bool QwenToolCallTextReady(string text)
	{
		if (string.IsNullOrWhiteSpace(text) || text.IndexOf("</tool_call>", StringComparison.OrdinalIgnoreCase) < 0)
		{
			return false;
		}
		return ExtractQwenToolCalls(text).Count > 0;
	}

	private string InterceptLooseToolCallContent(string content, StringBuilder looseToolText, ref bool sawLooseToolCalls)
	{
		if (string.IsNullOrEmpty(content))
		{
			return content;
		}
		if (sawLooseToolCalls)
		{
			looseToolText.Append(content);
			return "";
		}
		int toolStart = FindLooseToolCallStart(content);
		if (toolStart < 0)
		{
			return content;
		}
		sawLooseToolCalls = true;
		looseToolText.Append(content.Substring(toolStart));
		return content.Substring(0, toolStart);
	}

	private int FindLooseToolCallStart(string content)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return -1;
		}
		for (int i = 0; i < content.Length; i++)
		{
			if (content[i] != '{')
			{
				continue;
			}
			string candidate = content.Substring(i, Math.Min(content.Length - i, 900));
			if (LooksLikeLooseToolCallStart(candidate))
			{
				return i;
			}
		}
		return -1;
	}

	private bool LooksLikeLooseToolCallStart(string candidate)
	{
		if (string.IsNullOrWhiteSpace(candidate))
		{
			return false;
		}
		string lower = candidate.ToLowerInvariant();
		return lower.Contains("\"tool_call\"", StringComparison.Ordinal) ||
		       lower.Contains("\"tool_calls\"", StringComparison.Ordinal) ||
		       (lower.Contains("\"name\"", StringComparison.Ordinal) && lower.Contains("\"arguments\"", StringComparison.Ordinal));
	}

	private bool LooseToolCallTextReady(string text, string requestBody)
	{
		if (string.IsNullOrWhiteSpace(text))
		{
			return false;
		}
		int start = FindLooseToolCallStart(text);
		if (start >= 0)
		{
			int end = FindMatchingJsonObjectEnd(text, start);
			if (end > start)
			{
				List<ToolCallData> complete = ExtractLooseProxyToolCalls(text.Substring(start, end - start + 1));
				if (complete.Count > 0)
				{
					return true;
				}
			}
		}
		if (text.Length >= 2000)
		{
			ToolCallData rescued = TryRescueTruncatedQwenToolCall(text);
			if (rescued != null)
			{
				return true;
			}
		}
		return false;
	}

	private void NormalizeProxyToolCallsForRequest(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		HashSet<string> availableTools = GetAvailableToolNames(requestBody);
		RemapSuppressedToolCalls(toolCalls, availableTools, requestBody);
		TranslateUnsupportedBatchReplaceToolCalls(toolCalls, requestBody);
		GuardMalformedEditToolCalls(toolCalls, requestBody);
		RedirectMissingCodebehindLoopToCreateFile(toolCalls, requestBody);
		RedirectSearchLoopToCreateFile(toolCalls, requestBody);
		GuardVagueGetFileTargets(toolCalls, requestBody);
		GuardRepeatedGetFileLoop(toolCalls, requestBody);
		GuardCreateFileForExistingTarget(toolCalls, requestBody);
		GuardBlankReplaceStringCalls(toolCalls, requestBody);
		GuardNoOpReplaceStringCalls(toolCalls);
		GuardUnsafeCreateFileTargets(toolCalls, requestBody);
		GuardUnhelpfulInternetSearchQueries(toolCalls, requestBody);
		NormalizeTerminalToolCalls(toolCalls, availableTools);
		if (availableTools.Count > 0)
		{
			toolCalls.RemoveAll((ToolCallData toolCall) => toolCall == null || string.IsNullOrWhiteSpace(toolCall.Name) || !availableTools.Contains(toolCall.Name));
		}
	}

	private void GuardUnhelpfulInternetSearchQueries(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		string prompt = FirstNonEmpty(ExtractChatUiLastUserPromptText(requestBody), ExtractLastUserMessage(requestBody) ?? "");
		string fallbackQuery = ExtractExplicitInternetSearchQuery(prompt);
		if (!IsUsefulInternetSearchQueryCandidate(fallbackQuery))
		{
			fallbackQuery = DeriveInternetSearchQueryFromUserPrompt(prompt);
		}
		if (!IsUsefulInternetSearchQueryCandidate(fallbackQuery))
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !string.Equals(toolCall.Name, "internet_search", StringComparison.Ordinal))
			{
				continue;
			}
			string mode = FirstNonEmpty(ExtractJsonStringProperty(toolCall.ArgumentsJson, "mode"), ExtractJsonStringProperty(toolCall.ArgumentsJson, "action"), ExtractJsonStringProperty(toolCall.ArgumentsJson, "operation"));
			string url = FirstNonEmpty(ExtractJsonStringProperty(toolCall.ArgumentsJson, "url"), ExtractJsonStringProperty(toolCall.ArgumentsJson, "href"), ExtractJsonStringProperty(toolCall.ArgumentsJson, "sourceUrl"));
			if (string.Equals(mode, "read", StringComparison.OrdinalIgnoreCase) || !string.IsNullOrWhiteSpace(url))
			{
				continue;
			}
			string query = NormalizeInternetSearchQueryCandidate(FirstNonEmpty(ExtractJsonStringProperty(toolCall.ArgumentsJson, "query"), ExtractJsonStringProperty(toolCall.ArgumentsJson, "q"), ExtractJsonStringProperty(toolCall.ArgumentsJson, "search")));
			if (IsUsefulInternetSearchQueryCandidate(query) && query.IndexOf("SocketJack Auto", StringComparison.OrdinalIgnoreCase) < 0)
			{
				continue;
			}
			int take = Math.Max(1, Math.Min(12, ExtractIntFromToolArguments(toolCall.ArgumentsJson, "take", ExtractRequestedInternetSearchSourceCount(prompt, 8, 12))));
			toolCall.ArgumentsJson = "{\"action\":\"search\",\"query\":\"" + EscapeJson(fallbackQuery) + "\",\"take\":" + take.ToString(CultureInfo.InvariantCulture) + "}";
			LogMessage("[Chat UI] Rewrote unhelpful internet_search query \"" + TruncateForLog(query, 80) + "\" to \"" + TruncateForLog(fallbackQuery, 160) + "\".");
		}
	}

	private string FormatVisibleReasoningText(string text)
	{
		if (string.IsNullOrEmpty(text))
		{
			return "";
		}
		string formatted = text.Replace("\r\n", "\n").Replace('\r', '\n');
		formatted = Regex.Replace(formatted, "(?<=\\S)(?=\\d+\\.\\s)", "\n");
		formatted = Regex.Replace(formatted, "(?<=[A-Za-z])(?=\\d)", " ");
		formatted = Regex.Replace(formatted, "(?<=\\d)(?=[A-Za-z])", " ");
		formatted = Regex.Replace(formatted, "(?<=\\d)\\s*x\\s*(?=\\d)", "x", RegexOptions.IgnoreCase);
		formatted = Regex.Replace(formatted, "(?<=[.!?])(?=[A-Z])", " ");
		formatted = Regex.Replace(formatted, "(?<!\\n)(?<=:)(?=\\d+\\.)", "\n");
		formatted = Regex.Replace(formatted, "(?<!\\n)(?<=\\s)(?=\\d+\\.\\s)", "\n");
		formatted = Regex.Replace(formatted, "(?<=\\S)(?=Let me\\b)", "\n\n");
		formatted = Regex.Replace(formatted, "\\n{3,}", "\n\n");
		return formatted.Trim();
	}

	private string BuildSingleContentDeltaSse(string content, string model)
	{
		long created = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
		string completionId = "chatcmpl_" + Guid.NewGuid().ToString("N");
		return "data: {\"id\":\"" + completionId + "\",\"object\":\"chat.completion.chunk\",\"created\":" + created + ",\"model\":\"" + EscapeJson(model ?? "lm-studio") + "\",\"choices\":[{\"index\":0,\"delta\":{\"content\":\"" + EscapeJson(content ?? "") + "\"},\"finish_reason\":null}]}\n\n";
	}

	private string BuildVisibleToolCallSummary(List<ToolCallData> toolCalls)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return "";
		}
		StringBuilder sb = new StringBuilder();
		sb.Append("**Tool call");
		if (toolCalls.Count != 1)
		{
			sb.Append("s");
		}
		sb.Append("**\n\n");
		for (int i = 0; i < toolCalls.Count; i++)
		{
			ToolCallData toolCall = toolCalls[i];
			if (toolCall != null)
			{
				sb.Append(i + 1).Append(". `").Append(toolCall.Name ?? "<missing>")
					.Append("`");
				string arguments = PrettyPrintToolArguments(toolCall.ArgumentsJson);
				if (!string.IsNullOrWhiteSpace(arguments))
				{
					sb.Append("\n```json\n");
					sb.Append(arguments);
					sb.Append("\n```");
				}
				sb.Append("\n\n");
			}
		}
		return sb.ToString();
	}

	private string PrettyPrintToolArguments(string argumentsJson)
	{
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			return "{}";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			if (LooksLikeLargeEditArguments(document.RootElement))
			{
				return SummarizeLargeEditArguments(document.RootElement);
			}
			JsonWriterOptions options = new JsonWriterOptions
			{
				Indented = true
			};
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream, options);
			document.RootElement.WriteTo(writer);
			writer.Flush();
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch
		{
			return TruncateForLog(argumentsJson, 1200);
		}
	}

	private bool LooksLikeLargeEditArguments(JsonElement root)
	{
		int total = 0;
		string[] array = new string[3] { "oldString", "newString", "content" };
		foreach (string propertyName in array)
		{
			if (root.TryGetProperty(propertyName, out var property) && property.ValueKind == JsonValueKind.String && property.GetString() != null)
			{
				total += property.GetString().Length;
			}
		}
		return total > 1200;
	}

	private string SummarizeLargeEditArguments(JsonElement root)
	{
		Dictionary<string, object> summary = new Dictionary<string, object>();
		foreach (JsonProperty property in root.EnumerateObject())
		{
			if ((property.NameEquals("oldString") || property.NameEquals("newString") || property.NameEquals("content")) && property.Value.ValueKind == JsonValueKind.String)
			{
				string value = property.Value.GetString() ?? "";
				summary[property.Name] = "<redacted " + value.Length + " chars>";
			}
			else if (property.Value.ValueKind == JsonValueKind.String)
			{
				summary[property.Name] = property.Value.GetString();
			}
			else if (property.Value.ValueKind == JsonValueKind.Number)
			{
				summary[property.Name] = property.Value.GetRawText();
			}
			else if (property.Value.ValueKind == JsonValueKind.True || property.Value.ValueKind == JsonValueKind.False)
			{
				summary[property.Name] = property.Value.GetBoolean();
			}
			else
			{
				summary[property.Name] = "<complex value>";
			}
		}
		JsonSerializerOptions options = new JsonSerializerOptions
		{
			WriteIndented = true
		};
		return JsonSerializer.Serialize(summary, options);
	}

	private async Task WriteRawSseFrameAsync(Stream stream, string frameLine)
	{
		await WriteRawSseTextAsync(stream, frameLine + "\n\n");
	}

	private async Task WriteRawSseTextAsync(Stream stream, string text)
	{
		byte[] bytes = Encoding.UTF8.GetBytes(text ?? "");
		await stream.WriteAsync(bytes, 0, bytes.Length);
		await stream.FlushAsync();
	}

	private async Task WriteRawSseTextLockedAsync(Stream stream, SemaphoreSlim writeLock, string text)
	{
		if (writeLock == null)
		{
			await WriteRawSseTextAsync(stream, text);
			return;
		}
		await writeLock.WaitAsync();
		try
		{
			await WriteRawSseTextAsync(stream, text);
		}
		finally
		{
			writeLock.Release();
		}
	}

	private bool IsClientDisconnectedException(Exception ex)
	{
		while (ex != null)
		{
			if (ex is HttpListenerException listenerException && (listenerException.ErrorCode == 64 || listenerException.ErrorCode == 995 || listenerException.ErrorCode == 1229))
			{
				return true;
			}
			if (ex is ObjectDisposedException)
			{
				return true;
			}
			if (ex is IOException)
			{
				return true;
			}
			ex = ex.InnerException;
		}
		return false;
	}

	private async Task WriteResponsesSseErrorAsync(Stream stream, string errorMessage)
	{
		LogMessage("[Responses Bridge] Sending SSE error: " + errorMessage);
		string responseId = "resp_" + Guid.NewGuid().ToString("N");
		long created = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
		string data = "{\"type\":\"response.failed\",\"response\":{\"id\":\"" + responseId + "\",\"object\":\"response\",\"created_at\":" + created + ",\"status\":\"failed\",\"error\":{\"message\":\"" + EscapeJson(errorMessage) + "\",\"type\":\"proxy_error\"}}}";
		byte[] bytes = Encoding.UTF8.GetBytes("event: response.failed\ndata: " + data + "\n\ndata: [DONE]\n\n");
		await stream.WriteAsync(bytes, 0, bytes.Length);
		await stream.FlushAsync();
	}

	private string ScrubDeadEndProjectContextMessage(string text)
	{
		if (string.IsNullOrEmpty(text))
		{
			return text;
		}
		if (!text.Contains("I have enough project context now. I will stop reading the project and continue from the existing file context."))
		{
			return text;
		}
		return text.Replace("I have enough project context now. I will stop reading the project and continue from the existing file context.", "Continue by using exact file tools or editing from the current Visual Studio context; do not repeat get_projects_in_solution.");
	}

	private string EscapeInvalidJsonStringControlCharacters(string json, out int escapedCount)
	{
		escapedCount = 0;
		if (string.IsNullOrEmpty(json))
		{
			return json;
		}
		StringBuilder sb = null;
		bool inString = false;
		bool escaped = false;
		for (int i = 0; i < json.Length; i++)
		{
			char ch = json[i];
			string replacement = null;
			if (inString && !escaped && ch < ' ')
			{
				switch (ch)
				{
				case '\b':
					replacement = "\\b";
					break;
				case '\t':
					replacement = "\\t";
					break;
				case '\n':
					replacement = "\\n";
					break;
				case '\f':
					replacement = "\\f";
					break;
				case '\r':
					replacement = "\\r";
					break;
				default:
				{
					int num = ch;
					replacement = "\\u" + num.ToString("x4");
					break;
				}
				}
			}
			if (replacement != null)
			{
				if (sb == null)
				{
					sb = new StringBuilder(json.Length + 16);
					sb.Append(json, 0, i);
				}
				sb.Append(replacement);
				escapedCount++;
				escaped = false;
				continue;
			}
			sb?.Append(ch);
			if (escaped)
			{
				escaped = false;
			}
			else if (ch == '\\' && inString)
			{
				escaped = true;
			}
			else if (ch == '"')
			{
				inString = !inString;
			}
		}
		return (sb == null) ? json : sb.ToString();
	}

	private async Task<string> ReadUpstreamBodyWithKeepAliveAsync(HttpContent content, Stream clientStream)
	{
		Task<string> readTask = content.ReadAsStringAsync();
		while (!readTask.IsCompleted)
		{
			await Task.Delay(VsKeepAliveInterval);
			await WriteSseCommentAsync(clientStream, "proxy keepalive");
			await WriteSseCommentAsync(clientStream, "proxy keepalive; phase=reading_upstream_response; progress=99%");
		}
		return await readTask;
	}

	private string AdaptNativeOpenAiToolCallStream(string upstreamBody, string requestBody)
	{
		if (string.IsNullOrWhiteSpace(upstreamBody) || ContainsQwenToolCallOpenTag(upstreamBody))
		{
			return upstreamBody;
		}
		Dictionary<int, ToolCallBuilder> builders = new Dictionary<int, ToolCallBuilder>();
		string model = ExtractJsonStringProperty(requestBody, "model");
		if (string.IsNullOrWhiteSpace(model))
		{
			model = "lm-studio";
		}
		try
		{
			using StringReader reader = new StringReader(upstreamBody);
			string line;
			while ((line = reader.ReadLine()) != null)
			{
				line = line.Trim();
				if (!line.StartsWith("data:", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				string data = DecodeChatUiSseFieldValue(line, 5);
				if (data.Trim().Length == 0 || data.Trim().Equals("[DONE]", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				int escapedControlCharacters;
				string safeData = EscapeInvalidJsonStringControlCharacters(data, out escapedControlCharacters);
				if (escapedControlCharacters > 0)
				{
					LogMessage($"[JSON Repair] Escaped {escapedControlCharacters} raw control character(s) in native streaming chunk.");
				}
				using JsonDocument document = JsonDocument.Parse(safeData);
				if (document.RootElement.TryGetProperty("model", out var modelElement) && modelElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(modelElement.GetString()))
				{
					model = modelElement.GetString();
				}
				if (!document.RootElement.TryGetProperty("choices", out var choices) || choices.ValueKind != JsonValueKind.Array || choices.GetArrayLength() == 0 || !choices[0].TryGetProperty("delta", out var delta) || delta.ValueKind != JsonValueKind.Object || !delta.TryGetProperty("tool_calls", out var nativeToolCalls) || nativeToolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement toolCall in nativeToolCalls.EnumerateArray())
				{
					JsonElement indexElement;
					int parsedIndex;
					int index = ((toolCall.TryGetProperty("index", out indexElement) && indexElement.ValueKind == JsonValueKind.Number && indexElement.TryGetInt32(out parsedIndex)) ? parsedIndex : builders.Count);
					if (!builders.TryGetValue(index, out var builder))
					{
						builder = (builders[index] = new ToolCallBuilder());
					}
					if (toolCall.TryGetProperty("id", out var idElement) && idElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(idElement.GetString()))
					{
						builder.Id = idElement.GetString();
					}
					if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
					{
						if (function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(nameElement.GetString()))
						{
							builder.Name = nameElement.GetString();
						}
						if (function.TryGetProperty("arguments", out var argumentsElement))
						{
							string argumentsChunk = ((argumentsElement.ValueKind == JsonValueKind.String) ? argumentsElement.GetString() : argumentsElement.GetRawText());
							builder.Arguments.Append(argumentsChunk);
						}
					}
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Native Tool Calls] Error parsing streaming tool calls: " + ex.Message);
			return upstreamBody;
		}
		if (builders.Count == 0)
		{
			return upstreamBody;
		}
		List<ToolCallData> toolCalls = new List<ToolCallData>();
		foreach (KeyValuePair<int, ToolCallBuilder> item in builders)
		{
			ToolCallBuilder builder2 = item.Value;
			if (builder2 != null && !string.IsNullOrWhiteSpace(builder2.Name))
			{
				string rawArguments = builder2.Arguments.ToString();
				if (string.IsNullOrWhiteSpace(rawArguments))
				{
					rawArguments = "{}";
				}
				bool argumentsWereMalformed = !IsValidJsonObject(rawArguments);
				string repairedArguments = RepairKnownToolArguments(builder2.Name, rawArguments);
				if (!string.Equals(rawArguments, repairedArguments, StringComparison.Ordinal))
				{
					LogMessage("[Native Tool Args Repair] " + builder2.Name + ": " + TruncateForLog(rawArguments, 300) + " -> " + TruncateForLog(repairedArguments, 300));
				}
				toolCalls.Add(new ToolCallData
				{
					Id = builder2.Id,
					Name = builder2.Name,
					ArgumentsJson = repairedArguments,
					ArgumentsWereMalformed = argumentsWereMalformed
				});
			}
		}
		if (toolCalls.Count == 0)
		{
			return upstreamBody;
		}
		HashSet<string> availableTools = GetAvailableToolNames(requestBody);
		RemapSuppressedToolCalls(toolCalls, availableTools, requestBody);
		TranslateUnsupportedBatchReplaceToolCalls(toolCalls, requestBody);
		GuardMalformedEditToolCalls(toolCalls, requestBody);
		RedirectMissingCodebehindLoopToCreateFile(toolCalls, requestBody);
		RedirectSearchLoopToCreateFile(toolCalls, requestBody);
		GuardVagueGetFileTargets(toolCalls, requestBody);
		GuardRepeatedGetFileLoop(toolCalls, requestBody);
		GuardCreateFileForExistingTarget(toolCalls, requestBody);
		GuardBlankReplaceStringCalls(toolCalls, requestBody);
		GuardNoOpReplaceStringCalls(toolCalls);
		GuardUnsafeCreateFileTargets(toolCalls, requestBody);
		if (availableTools.Count > 0)
		{
			List<string> droppedTools = new List<string>();
			foreach (ToolCallData toolCall2 in toolCalls)
			{
				if (toolCall2 == null || string.IsNullOrWhiteSpace(toolCall2.Name))
				{
					droppedTools.Add("<missing>");
				}
				else if (!availableTools.Contains(toolCall2.Name))
				{
					droppedTools.Add(toolCall2.Name);
				}
			}
			toolCalls.RemoveAll((ToolCallData toolCallData) => toolCallData == null || string.IsNullOrWhiteSpace(toolCallData.Name) || !availableTools.Contains(toolCallData.Name));
			if (droppedTools.Count > 0)
			{
				LogMessage("[Tool Calls] Dropped unavailable native tool call(s): " + string.Join(", ", droppedTools));
			}
		}
		LogToolCalls("native repaired", toolCalls);
		return BuildToolCallSseResponse(toolCalls, model);
	}

	private string AdaptQwenToolCallStream(string upstreamBody, string requestBody)
	{
		if (string.IsNullOrEmpty(upstreamBody) || !ContainsQwenToolCallOpenTag(upstreamBody))
		{
			return upstreamBody;
		}
		string content = ExtractStreamedAssistantContent(upstreamBody);
		if (string.IsNullOrWhiteSpace(content) || !ContainsQwenToolCallOpenTag(content))
		{
			return upstreamBody;
		}
		List<ToolCallData> toolCalls = ExtractQwenToolCalls(content);
		if (toolCalls.Count == 0)
		{
			return upstreamBody;
		}
		string model = ExtractJsonStringProperty(requestBody, "model");
		if (string.IsNullOrWhiteSpace(model))
		{
			model = "lm-studio";
		}
		if (IsToolChoiceNone(requestBody))
		{
			return BuildTextOnlySseResponse(SanitizeAssistantText(StripQwenToolCalls(content, requestBody)), model);
		}
		HashSet<string> availableTools = GetAvailableToolNames(requestBody);
		if (availableTools.Count > 0)
		{
			LogMessage("[Tool Calls] Available tools: " + TruncateForLog(string.Join(", ", availableTools), 900));
		}
		LogToolCalls("parsed", toolCalls);
		RemapSuppressedToolCalls(toolCalls, availableTools, requestBody);
		TranslateUnsupportedBatchReplaceToolCalls(toolCalls, requestBody);
		RedirectMissingCodebehindLoopToCreateFile(toolCalls, requestBody);
		RedirectSearchLoopToCreateFile(toolCalls, requestBody);
		GuardVagueGetFileTargets(toolCalls, requestBody);
		GuardRepeatedGetFileLoop(toolCalls, requestBody);
		GuardCreateFileForExistingTarget(toolCalls, requestBody);
		GuardBlankReplaceStringCalls(toolCalls, requestBody);
		GuardUnsafeCreateFileTargets(toolCalls, requestBody);
		LogToolCalls("after remap", toolCalls);
		if (availableTools.Count > 0)
		{
			List<string> droppedTools = new List<string>();
			foreach (ToolCallData toolCall in toolCalls)
			{
				if (toolCall == null || string.IsNullOrWhiteSpace(toolCall.Name))
				{
					droppedTools.Add("<missing>");
				}
				else if (!availableTools.Contains(toolCall.Name))
				{
					droppedTools.Add(toolCall.Name);
				}
			}
			toolCalls.RemoveAll((ToolCallData toolCallData) => toolCallData == null || string.IsNullOrWhiteSpace(toolCallData.Name) || !availableTools.Contains(toolCallData.Name));
			if (droppedTools.Count > 0)
			{
				LogMessage("[Tool Calls] Dropped unavailable tool call(s): " + string.Join(", ", droppedTools));
			}
		}
		LogToolCalls("after availability filter", toolCalls);
		if (toolCalls.Count == 0)
		{
			LogMessage("[Tool Calls] No executable tool calls after adaptation; returning text-only response.");
			return BuildTextOnlySseResponse(SanitizeAssistantText(StripQwenToolCalls(content, requestBody)), model);
		}
		return BuildToolCallSseResponse(toolCalls, model);
	}

	private string AdaptTextOnlyRepairContinuation(string upstreamBody, string requestBody)
	{
		if (string.IsNullOrWhiteSpace(upstreamBody) || upstreamBody.Contains("\"tool_calls\"", StringComparison.OrdinalIgnoreCase) || IsToolChoiceNone(requestBody) || !IsToolAdvertised(requestBody, "get_file"))
		{
			return upstreamBody;
		}
		if (!HasUnfixedBuildOrErrorFailure(requestBody, out var errorFile) || string.IsNullOrWhiteSpace(errorFile))
		{
			return upstreamBody;
		}
		if (CountToolCallsAfterLatestBuildFailure(requestBody, "get_file", errorFile) >= 2)
		{
			return upstreamBody;
		}
		string content = ExtractStreamedAssistantContent(upstreamBody);
		if (string.IsNullOrWhiteSpace(content))
		{
			return upstreamBody;
		}
		string model = ExtractJsonStringProperty(requestBody, "model");
		if (string.IsNullOrWhiteSpace(model))
		{
			model = "lm-studio";
		}
		List<ToolCallData> toolCalls = new List<ToolCallData>
		{
			new ToolCallData
			{
				Name = "get_file",
				ArgumentsJson = "{\"filename\":\"" + EscapeJson(errorFile) + "\",\"startLine\":1,\"endLine\":120,\"includeLineNumbers\":true}"
			}
		};
		LogMessage("[Build Error Continuation] Replaced text-only response after build/get_errors failure with get_file for " + errorFile + ".");
		return BuildToolCallSseResponse(toolCalls, model);
	}

	private bool ContainsProxyOwnedToolCall(List<ToolCallData> toolCalls)
	{
		if (toolCalls == null)
		{
			return false;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall != null && IsProxyOwnedResearchTool(toolCall.Name))
			{
				return true;
			}
		}
		return false;
	}

	private bool IsProxyOwnedResearchTool(string toolName)
	{
		return toolName != null && (toolName.Equals("internet_search", StringComparison.Ordinal) || toolName.Equals("download_file", StringComparison.Ordinal) || toolName.Equals("nuget_search", StringComparison.Ordinal) || toolName.Equals("nuget_package_info", StringComparison.Ordinal) || toolName.Equals("github_code_search", StringComparison.Ordinal) || IsProxyOwnedCoordinationTool(toolName) || IsProxyOwnedWorkstationModelTool(toolName) || IsProxyOwnedSockJackDmlTool(toolName) || IsProxyOwnedGitTool(toolName) || IsProxyOwnedTerminalTool(toolName) || IsProxyOwnedBrowserTool(toolName) || IsProxyOwnedVsTool(toolName) || IsLlmRuntimeToolName(toolName));
	}

