	private async Task ForwardProxyToolResultAsync(List<ToolCallData> toolCalls, string model, Stream clientStream, SemaphoreSlim writeLock, CancellationToken cancellationToken)
	{
		if (toolCalls == null)
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !IsProxyOwnedResearchTool(toolCall.Name))
			{
				continue;
			}
			string toolCallId = (string.IsNullOrWhiteSpace(toolCall.Id) ? ("call_proxy_" + Guid.NewGuid().ToString("N").Substring(0, 16)) : toolCall.Id);
			string toolOutputText = await ExecuteProxyResearchToolAsync(toolCall.Name, toolCall.ArgumentsJson);
			if (writeLock == null)
			{
				await _upstreamAdapter.HandleToolResultAsync(toolCallId, toolCall.Name, toolOutputText, clientStream, cancellationToken);
			}
			else
			{
				await writeLock.WaitAsync(cancellationToken);
				try
				{
					await _upstreamAdapter.HandleToolResultAsync(toolCallId, toolCall.Name, toolOutputText, clientStream, cancellationToken);
				}
				finally
				{
					writeLock.Release();
				}
			}
			LogMessage("[Proxy Research] Forwarded normalized tool result for " + toolCall.Name + "; id=" + toolCallId);
			return;
		}
	}

	private async Task<string> ExecuteProxyToolsAndContinueAsync(string requestBody, List<ToolCallData> toolCalls, string model)
	{
		try
		{
			string continuationRequest = await BuildProxyToolContinuationRequestAsync(requestBody, toolCalls);
			if (string.IsNullOrWhiteSpace(continuationRequest))
			{
				return BuildTextOnlySseResponse("Proxy research tools did not produce a continuation request.", model);
			}
			using HttpResponseMessage response = await ForwardChatCompletionBodyToLmStudioAsync(continuationRequest);
			string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync()) : "");
			string responseBody = text;
			if (!response.IsSuccessStatusCode)
			{
				LogMessage("[Proxy Research] Continuation request failed: " + (int)response.StatusCode + " " + response.ReasonPhrase + " " + TruncateForLog(responseBody, 1000));
				return BuildTextOnlySseResponse("Proxy research succeeded, but LM Studio continuation failed: " + (response.ReasonPhrase ?? "unknown error") + "\n\n" + TruncateForLog(responseBody, 2000), model);
			}
			ChatUiCompletion completion = ExtractChatUiCompletionFromChatCompletion(responseBody);
			string content = completion.Content;
			if (!string.IsNullOrWhiteSpace(completion.Reasoning))
			{
				content = "**Thinking**\n\n" + FormatVisibleReasoningText(completion.Reasoning) + "\n\n" + content;
			}
			if (string.IsNullOrWhiteSpace(content))
			{
				content = ExtractStreamedAssistantContent(responseBody);
			}
			return BuildTextOnlySseResponse(string.IsNullOrWhiteSpace(content) ? "(empty continuation after proxy research)" : content, model);
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			LogMessage("[Proxy Research] Error executing proxy research tools: " + ex2);
			return BuildTextOnlySseResponse("Proxy research tool failed: " + ex2.Message, model);
		}
	}

	private ProxyCoordinationToolResult BuildProxyCoordinationToolResult(string toolName, string argumentsJson, string requestBody)
	{
		string goal = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "goal"), ExtractChatUiLastUserPromptText(requestBody), ExtractLastUserMessage(requestBody) ?? "the user request");
		string status = NormalizeProxyCoordinationStatus(toolName, ExtractJsonStringProperty(argumentsJson, "status"));
		int progressPercent = ExtractProgressPercentFromJsonText(argumentsJson);
		if (progressPercent < 0)
		{
			progressPercent = EstimateProxyCoordinationProgressPercent(requestBody, status);
		}
		if (toolName.Equals(GoalCheckpointToolName, StringComparison.Ordinal))
		{
			return BuildGoalCheckpointToolResult(argumentsJson, goal, status, progressPercent);
		}
		if (toolName.Equals(ContinueWithToolsToolName, StringComparison.Ordinal))
		{
			return BuildContinueWithToolsToolResult(argumentsJson, requestBody, goal, status, progressPercent);
		}
		return new ProxyCoordinationToolResult
		{
			Result = toolName + " failed: Unknown coordination tool.",
			SystemInstruction = "[JackLLM coordination] The previous coordination tool name was unknown. Continue using the available real tools or provide a clean blocker if none are viable.",
			ProgressPercent = progressPercent
		};
	}

	private ProxyCoordinationToolResult BuildGoalCheckpointToolResult(string argumentsJson, string goal, string status, int progressPercent)
	{
		string successCriteria = ExtractJsonStringProperty(argumentsJson, "successCriteria") ?? "";
		string completed = ExtractJsonStringProperty(argumentsJson, "completed") ?? "";
		string remaining = ExtractJsonStringProperty(argumentsJson, "remaining") ?? "";
		string blockedReason = ExtractJsonStringProperty(argumentsJson, "blockedReason") ?? "";
		string notes = ExtractJsonStringProperty(argumentsJson, "notes") ?? "";
		bool blocked = status.Equals("blocked", StringComparison.Ordinal);
		bool readyFinal = status.Equals("ready_final", StringComparison.Ordinal);
		string result = JsonSerializer.Serialize(new
		{
			ok = true,
			coordination = true,
			tool = GoalCheckpointToolName,
			status,
			progressPercent,
			goal,
			successCriteria,
			completed,
			remaining,
			blockedReason,
			notes
		});
		string instruction = readyFinal
			? "[JackLLM goal checkpoint] The model marked the goal ready for final answer. Produce a clean final answer now using the gathered context. Do not expose checkpoint JSON, internal progress notes, or tool transcripts."
			: (blocked
				? "[JackLLM goal checkpoint] The model marked the goal blocked. Produce a brief user-facing blocker explanation and the best next user action. Do not expose checkpoint JSON, internal progress notes, or tool transcripts."
				: "[JackLLM goal checkpoint] Goal progress recorded at " + progressPercent.ToString(CultureInfo.InvariantCulture) + "%. Continue the same user request. If more external action, source material, files, browser work, shell output, or generated media is needed, call a real available tool next or use continue_with_tools to name the needed real tools.");
		return new ProxyCoordinationToolResult
		{
			Result = result,
			SystemInstruction = instruction,
			ForceFinalAnswer = readyFinal || blocked,
			ProgressPercent = progressPercent
		};
	}

	private ProxyCoordinationToolResult BuildContinueWithToolsToolResult(string argumentsJson, string requestBody, string goal, string status, int progressPercent)
	{
		string nextStep = ExtractJsonStringProperty(argumentsJson, "nextStep") ?? "";
		string successCriteria = ExtractJsonStringProperty(argumentsJson, "successCriteria") ?? "";
		string evidenceNeeded = ExtractJsonStringProperty(argumentsJson, "evidenceNeeded") ?? "";
		string reason = ExtractJsonStringProperty(argumentsJson, "reason") ?? "";
		string blockedReason = ExtractJsonStringProperty(argumentsJson, "blockedReason") ?? "";
		List<string> requestedTools = ExtractStringArrayToolArgument(argumentsJson, "requiredTools");
		List<string> availableRealTools = GetAvailableRealProxyToolNames(requestBody);
		List<string> validTools = ResolveRequestedRealProxyTools(requestedTools, availableRealTools, out var invalidTools);
		bool blocked = status.Equals("blocked", StringComparison.Ordinal);
		bool readyFinal = status.Equals("ready_final", StringComparison.Ordinal);
		bool needsTools = status.Equals("needs_tools", StringComparison.Ordinal);
		if (needsTools && validTools.Count == 0)
		{
			string result2 = ContinueWithToolsToolName + " failed: requiredTools must name at least one currently advertised non-coordination tool. Available real tools: " + (availableRealTools.Count == 0 ? "none" : string.Join(", ", availableRealTools)) + ". Requested: " + (requestedTools.Count == 0 ? "none" : string.Join(", ", requestedTools)) + ".";
			return new ProxyCoordinationToolResult
			{
				Result = result2,
				SystemInstruction = "[JackLLM tool continuation] The previous continue_with_tools call did not name an available real tool. Retry with one or more available real tools, or set status=blocked if no viable tool path remains. Available real tools: " + (availableRealTools.Count == 0 ? "none" : string.Join(", ", availableRealTools)) + ".",
				ProgressPercent = progressPercent
			};
		}
		string result = JsonSerializer.Serialize(new
		{
			ok = invalidTools.Count == 0,
			coordination = true,
			tool = ContinueWithToolsToolName,
			status,
			progressPercent,
			goal,
			requiredTools = validTools,
			invalidTools,
			nextStep,
			successCriteria,
			evidenceNeeded,
			reason,
			blockedReason
		});
		string instruction;
		if (readyFinal)
		{
			instruction = "[JackLLM tool continuation] The model marked the requested goal ready for final answer at " + progressPercent.ToString(CultureInfo.InvariantCulture) + "%. Produce a clean final answer now from the gathered context. Do not call more tools, and do not expose coordination JSON or tool transcripts.";
		}
		else if (blocked)
		{
			instruction = "[JackLLM tool continuation] The model marked the requested goal blocked at " + progressPercent.ToString(CultureInfo.InvariantCulture) + "%. Produce a brief user-facing blocker explanation and the best next user action. Do not expose coordination JSON or tool transcripts. Blocker: " + TruncateForLog(blockedReason, 700);
		}
		else
		{
			instruction = "[JackLLM tool continuation] Continue the same user request. Do not answer yet. Next, call one of these available real tools: " + string.Join(", ", validTools) + ". Prefer the first listed tool unless the latest context makes another listed tool clearly better. Do not call goal_checkpoint or continue_with_tools again until after at least one real tool result, unless the task becomes blocked or ready for final answer. Progress: " + progressPercent.ToString(CultureInfo.InvariantCulture) + "%. Goal: " + TruncateForLog(goal, 700) + ". Next step: " + TruncateForLog(nextStep, 700) + (string.IsNullOrWhiteSpace(successCriteria) ? "" : ". Success criteria: " + TruncateForLog(successCriteria, 700)) + (invalidTools.Count == 0 ? "" : ". Ignored unavailable requested tools: " + string.Join(", ", invalidTools));
		}
		return new ProxyCoordinationToolResult
		{
			Result = result,
			SystemInstruction = instruction,
			ForceFinalAnswer = readyFinal || blocked,
			ProgressPercent = progressPercent
		};
	}

	private string NormalizeProxyCoordinationStatus(string toolName, string status)
	{
		string value = (status ?? "").Trim().ToLowerInvariant().Replace('-', '_').Replace(' ', '_');
		if (toolName.Equals(GoalCheckpointToolName, StringComparison.Ordinal))
		{
			return value switch
			{
				"started" => "started",
				"in_progress" => "in_progress",
				"ready_final" => "ready_final",
				"ready" => "ready_final",
				"final" => "ready_final",
				"blocked" => "blocked",
				_ => "in_progress",
			};
		}
		return value switch
		{
			"ready_final" => "ready_final",
			"ready" => "ready_final",
			"final" => "ready_final",
			"blocked" => "blocked",
			_ => "needs_tools",
		};
	}

	private int EstimateProxyCoordinationProgressPercent(string requestBody, string status)
	{
		if (status.Equals("ready_final", StringComparison.Ordinal))
		{
			return 96;
		}
		if (status.Equals("blocked", StringComparison.Ordinal))
		{
			return 80;
		}
		int realResults = ExtractLatestProxyToolResultText(requestBody, 36).Count(result => !Regex.IsMatch(result ?? "", "^(?:goal_checkpoint|continue_with_tools)\\s+result\\s*:", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant));
		if (status.Equals("started", StringComparison.Ordinal))
		{
			return realResults == 0 ? 8 : Math.Min(88, 18 + realResults * 12);
		}
		return Math.Min(92, Math.Max(18, 24 + realResults * 12));
	}

	private List<string> GetAvailableRealProxyToolNames(string requestBody)
	{
		return GetAvailableToolNames(requestBody)
			.Where(IsRealProxyOwnedResearchTool)
			.OrderBy(name => name, StringComparer.Ordinal)
			.ToList();
	}

	private List<string> ResolveRequestedRealProxyTools(List<string> requestedTools, List<string> availableRealTools, out List<string> invalidTools)
	{
		invalidTools = new List<string>();
		List<string> resolved = new List<string>();
		Dictionary<string, string> availableLookup = availableRealTools.ToDictionary(name => name, name => name, StringComparer.OrdinalIgnoreCase);
		foreach (string rawTool in requestedTools ?? new List<string>())
		{
			string requested = (rawTool ?? "").Trim();
			if (string.IsNullOrWhiteSpace(requested))
			{
				continue;
			}
			if (availableLookup.TryGetValue(requested, out var actual) && !resolved.Contains(actual, StringComparer.Ordinal))
			{
				resolved.Add(actual);
			}
			else if (!invalidTools.Contains(requested, StringComparer.OrdinalIgnoreCase))
			{
				invalidTools.Add(requested);
			}
		}
		return resolved;
	}

	private List<string> ExtractStringArrayToolArgument(string argumentsJson, string propertyName)
	{
		List<string> values = new List<string>();
		if (string.IsNullOrWhiteSpace(argumentsJson) || string.IsNullOrWhiteSpace(propertyName))
		{
			return values;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			if (!document.RootElement.TryGetProperty(propertyName, out var value))
			{
				return values;
			}
			if (value.ValueKind == JsonValueKind.Array)
			{
				foreach (JsonElement item in value.EnumerateArray())
				{
					string text = item.ValueKind == JsonValueKind.String ? item.GetString() : item.ToString();
					if (!string.IsNullOrWhiteSpace(text))
					{
						values.Add(text.Trim());
					}
				}
			}
			else if (value.ValueKind == JsonValueKind.String)
			{
				values.AddRange(value.GetString().Split(new char[3] { ',', ';', '\n' }, StringSplitOptions.RemoveEmptyEntries).Select(item => item.Trim()).Where(item => item.Length > 0));
			}
		}
		catch
		{
		}
		return values.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
	}

	private async Task<string> BuildProxyToolContinuationRequestAsync(string requestBody, List<ToolCallData> toolCalls, bool keepProxyTools = false, string ownerKey = null, string sessionId = null, Action<ChatUiToolCallStreamEvent> emitToolCall = null)
	{
		List<ProxyToolExecutionResult> proxyResults = new List<ProxyToolExecutionResult>();
		List<ToolCallData> passthroughToolCalls = new List<ToolCallData>();
		List<string> coordinationInstructions = new List<string>();
		bool forceFinalAnswerFromCoordination = false;
		sessionId = EnsureChatUiSessionId(sessionId);
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null)
			{
				continue;
			}
			if (IsProxyOwnedResearchTool(toolCall.Name))
			{
				string toolCallId = FirstNonEmpty(toolCall.Id, "call_proxy_" + Guid.NewGuid().ToString("N").Substring(0, 16));
				DateTimeOffset startedUtc = DateTimeOffset.UtcNow;
				string toolKind = ClassifyChatUiToolKind(toolCall.Name);
				string label = BuildChatUiToolDisplayLabel(toolCall.Name, toolCall.ArgumentsJson);
				ProxyCoordinationToolResult coordinationResult = IsProxyOwnedCoordinationTool(toolCall.Name) ? BuildProxyCoordinationToolResult(toolCall.Name, toolCall.ArgumentsJson, requestBody) : null;
				ChatUiToolCallStreamEvent startedEvent = BuildChatUiToolCallStreamEvent(toolCallId, toolCall.Name, toolKind, "started", label, BuildChatUiToolSummary(toolCall.Name, toolCall.ArgumentsJson, "started"), toolCall.ArgumentsJson, null, startedUtc);
				if (coordinationResult != null && coordinationResult.ProgressPercent >= 0)
				{
					startedEvent.ProgressPercent = coordinationResult.ProgressPercent;
				}
				EmitChatUiToolCallEvent(emitToolCall, startedEvent);
				string result;
				ChatFileUndoScope undoScope = null;
				try
				{
					if (coordinationResult != null)
					{
						result = coordinationResult.Result ?? "";
						if (!string.IsNullOrWhiteSpace(coordinationResult.SystemInstruction))
						{
							coordinationInstructions.Add(coordinationResult.SystemInstruction);
						}
						forceFinalAnswerFromCoordination = forceFinalAnswerFromCoordination || coordinationResult.ForceFinalAnswer;
					}
					else if (IsProxyOwnedMutatingVsTool(toolCall.Name))
					{
						undoScope = BeginChatFileUndoScope(ownerKey, sessionId, toolCall.Name);
						result = await ExecuteProxyResearchToolAsync(toolCall.Name, toolCall.ArgumentsJson, ownerKey, sessionId);
					}
					else
					{
						result = await ExecuteProxyResearchToolAsync(toolCall.Name, toolCall.ArgumentsJson, ownerKey, sessionId);
					}
				}
				catch (Exception ex)
				{
					Exception ex2 = ex;
					EmitChatUiToolCallEvent(emitToolCall, BuildChatUiToolCallStreamEvent(completedUtc: DateTimeOffset.UtcNow, id: toolCallId, name: toolCall.Name, kind: toolKind, status: "failed", label: label, summary: BuildChatUiToolSummary(toolCall.Name, toolCall.ArgumentsJson, "failed", null, ex2.Message), argumentsJson: toolCall.ArgumentsJson, result: null, startedUtc: startedUtc, error: ex2.Message));
					throw;
				}
				finally
				{
					undoScope?.Dispose();
				}
				bool failed = ToolResultIndicatesFailure(result);
				ChatFileUndoTransaction undoTransaction = failed ? null : StoreChatFileUndoTransaction(undoScope?.Transaction);
				ChatUiToolCallStreamEvent completedEvent = BuildChatUiToolCallStreamEvent(completedUtc: DateTimeOffset.UtcNow, id: toolCallId, name: toolCall.Name, kind: toolKind, status: failed ? "failed" : "completed", label: label, summary: BuildChatUiToolSummary(toolCall.Name, toolCall.ArgumentsJson, failed ? "failed" : "completed", result), argumentsJson: toolCall.ArgumentsJson, result: result, startedUtc: startedUtc, error: failed ? ExtractFirstToolResultLine(result) : "");
				if (coordinationResult != null && coordinationResult.ProgressPercent >= 0)
				{
					completedEvent.ProgressPercent = coordinationResult.ProgressPercent;
				}
				AttachChatFileUndoToToolEvent(completedEvent, undoTransaction);
				EmitChatUiToolCallEvent(emitToolCall, completedEvent);
				proxyResults.Add(new ProxyToolExecutionResult
				{
					Id = toolCallId,
					Name = toolCall.Name,
					ArgumentsJson = (string.IsNullOrWhiteSpace(toolCall.ArgumentsJson) ? "{}" : toolCall.ArgumentsJson),
					Result = CompactProxyToolResultForModel(toolCall.Name, result)
				});
			}
			else
			{
				passthroughToolCalls.Add(toolCall);
			}
		}
		if (proxyResults.Count == 0)
		{
			return null;
		}
		using JsonDocument document = JsonDocument.Parse(requestBody);
		using MemoryStream stream = new MemoryStream();
		using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
		bool requiredFileWriteStillUnmet = RequestRequiresUnmetProxyFileWrite(requestBody) &&
			!proxyResults.Any(result => string.Equals(result.Name, "vs_write_file", StringComparison.Ordinal) && IsSuccessfulProxyFileWriteResultText(result.Result));
		writer.WriteStartObject();
		bool wroteMessages = false;
		bool wroteStream = false;
		bool wroteToolChoice = false;
		foreach (JsonProperty property in document.RootElement.EnumerateObject())
		{
			if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
			{
				wroteMessages = true;
				writer.WritePropertyName("messages");
				writer.WriteStartArray();
				foreach (JsonElement item in property.Value.EnumerateArray())
				{
					item.WriteTo(writer);
				}
				WriteProxyResearchAssistantAndToolMessages(writer, proxyResults);
				writer.WriteEndArray();
			}
			else if (property.NameEquals("tools") && property.Value.ValueKind == JsonValueKind.Array)
			{
				writer.WritePropertyName("tools");
				writer.WriteStartArray();
				foreach (JsonElement tool in property.Value.EnumerateArray())
				{
					string name = ExtractToolSchemaName(tool);
					if (keepProxyTools || !IsProxyOwnedResearchTool(name))
					{
						tool.WriteTo(writer);
					}
				}
				writer.WriteEndArray();
			}
			else if (property.NameEquals("stream"))
			{
				writer.WriteBoolean("stream", value: false);
				wroteStream = true;
			}
			else if (property.NameEquals("tool_choice"))
			{
				writer.WriteString("tool_choice", requiredFileWriteStillUnmet ? "required" : "auto");
				wroteToolChoice = true;
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteMessages)
		{
			writer.WritePropertyName("messages");
			writer.WriteStartArray();
			WriteProxyResearchAssistantAndToolMessages(writer, proxyResults);
			writer.WriteEndArray();
		}
		if (!wroteStream)
		{
			writer.WriteBoolean("stream", value: false);
		}
		if (!wroteToolChoice)
		{
			writer.WriteString("tool_choice", requiredFileWriteStillUnmet ? "required" : "auto");
		}
		writer.WriteEndObject();
		writer.Flush();
		string continuationRequest = Encoding.UTF8.GetString(stream.ToArray());
		if (requiredFileWriteStillUnmet && CountTextOccurrences(continuationRequest, "[LmVsProxy required file write]") < 4)
		{
			string prompt = ExtractRequiredProxyFileWritePrompt(continuationRequest);
			string target = ExtractLikelyRequestedFileTarget(prompt);
			string targetText = string.IsNullOrWhiteSpace(target) ? "the requested output file" : target;
			continuationRequest = AppendSystemMessage(continuationRequest, "[LmVsProxy required file write] A successful vs_write_file result is still required for " + targetText + ". The next acceptable completion must call vs_write_file with the completed file content, or continue inspecting only if absolutely necessary and then call vs_write_file before any final text. Do not emit the requested done marker or claim success until vs_write_file completes.");
		}
		foreach (string instruction in coordinationInstructions.Where(instruction => !string.IsNullOrWhiteSpace(instruction)))
		{
			continuationRequest = AppendSystemMessage(continuationRequest, instruction);
		}
		if (forceFinalAnswerFromCoordination)
		{
			continuationRequest = BuildProxyToolFinalAnswerRequest(continuationRequest);
		}
		return continuationRequest;
	}

	private void WriteProxyResearchAssistantAndToolMessages(Utf8JsonWriter writer, List<ProxyToolExecutionResult> proxyResults)
	{
		writer.WriteStartObject();
		writer.WriteString("role", "assistant");
		writer.WritePropertyName("tool_calls");
		writer.WriteStartArray();
		foreach (ProxyToolExecutionResult result in proxyResults)
		{
			writer.WriteStartObject();
			writer.WriteString("id", result.Id);
			writer.WriteString("type", "function");
			writer.WritePropertyName("function");
			writer.WriteStartObject();
			writer.WriteString("name", result.Name);
			writer.WriteString("arguments", result.ArgumentsJson ?? "{}");
			writer.WriteEndObject();
			writer.WriteEndObject();
		}
		writer.WriteEndArray();
		writer.WriteEndObject();
		foreach (ProxyToolExecutionResult result2 in proxyResults)
		{
			writer.WriteStartObject();
			writer.WriteString("role", "tool");
			writer.WriteString("tool_call_id", result2.Id);
			writer.WriteString("content", result2.Result ?? "");
			writer.WriteEndObject();
		}
		string digest = BuildProxyToolResultDigestForModel(proxyResults, 4800);
		if (!string.IsNullOrWhiteSpace(digest))
		{
			WriteChatUiSystemMessage(writer, "[LmVsProxy tool result digest] The completed tool calls above are summarized here for the next reasoning step. Use this digest as context instead of exposing raw tool JSON, HTML, XML, terminal transcripts, or tool-call markup. If the user asked for URLs, list the URLs with readable labels. If the user asked for examples, source material, scraped details, or page contents and the digest only has search-result URLs, choose the most relevant URL(s) yourself and continue with internet_search action=read, browser_read_page, or download_file followed by read_file when those tools are still available before producing the final answer.\n\n" + digest);
		}
	}

	private string ExtractToolSchemaName(JsonElement tool)
	{
		if (tool.ValueKind != JsonValueKind.Object)
		{
			return null;
		}
		if (tool.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
		{
			return ExtractStringProperty(function, "name");
		}
		return ExtractStringProperty(tool, "name");
	}

	private bool HasLlmRuntimeToolSchemas()
	{
		RefreshLlmRuntimeToolSchemaCache(force: false);
		lock (_llmRuntimeToolCacheLock)
		{
			return _llmRuntimeToolSchemas.Count > 0;
		}
	}

	private bool IsLlmRuntimeToolName(string toolName)
	{
		if (string.IsNullOrWhiteSpace(toolName))
		{
			return false;
		}
		RefreshLlmRuntimeToolSchemaCache(force: false);
		lock (_llmRuntimeToolCacheLock)
		{
			return _llmRuntimeToolNames.Contains(toolName);
		}
	}

	private List<string> GetLlmRuntimeToolNamesSnapshot()
	{
		RefreshLlmRuntimeToolSchemaCache(force: false);
		lock (_llmRuntimeToolCacheLock)
		{
			return _llmRuntimeToolNames.OrderBy<string, string>((string name) => name, StringComparer.Ordinal).ToList();
		}
	}

	private void WriteLlmRuntimeToolSchemas(Utf8JsonWriter writer)
	{
		RefreshLlmRuntimeToolSchemaCache(force: false);
		List<JsonElement> schemas;
		lock (_llmRuntimeToolCacheLock)
		{
			schemas = _llmRuntimeToolSchemas.Select((JsonElement schema) => schema.Clone()).ToList();
		}
		foreach (JsonElement item in schemas)
		{
			item.WriteTo(writer);
		}
	}

	private void RefreshLlmRuntimeToolSchemaCache(bool force)
	{
		lock (_llmRuntimeToolCacheLock)
		{
			if (!force && DateTimeOffset.UtcNow - _llmRuntimeToolCacheUtc < TimeSpan.FromSeconds(15.0))
			{
				return;
			}
		}
		List<JsonElement> schemas = new List<JsonElement>();
		HashSet<string> names = new HashSet<string>(StringComparer.Ordinal);
		try
		{
			string url = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/tools/openai";
			using CancellationTokenSource cts = new CancellationTokenSource(TimeSpan.FromSeconds(2.0));
			using HttpResponseMessage response = _httpClient.GetAsync(url, cts.Token).GetAwaiter().GetResult();
			if (response.IsSuccessStatusCode)
			{
				string body = ((response.Content == null) ? "" : response.Content.ReadAsStringAsync().GetAwaiter().GetResult());
				using JsonDocument document = JsonDocument.Parse(string.IsNullOrWhiteSpace(body) ? "{}" : body);
				if (document.RootElement.TryGetProperty("tools", out var tools) && tools.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement tool in tools.EnumerateArray())
					{
						string name = ExtractToolSchemaName(tool);
						if (!string.IsNullOrWhiteSpace(name) && !IsProxyOwnedSockJackDmlTool(name))
						{
							schemas.Add(tool.Clone());
							names.Add(name);
						}
					}
				}
			}
		}
		catch
		{
			schemas.Clear();
			names.Clear();
		}
		lock (_llmRuntimeToolCacheLock)
		{
			_llmRuntimeToolSchemas = schemas;
			_llmRuntimeToolNames = names;
			_llmRuntimeToolCacheUtc = DateTimeOffset.UtcNow;
		}
	}

	private string CompactProxyToolResultForModel(string toolName, string result)
	{
		if (string.IsNullOrWhiteSpace(result) || !IsProxyOwnedBrowserTool(toolName))
		{
			return result ?? "";
		}
		string normalized = result.Replace("\r\n", "\n").Replace('\r', '\n');
		if (normalized.Length <= 5500)
		{
			return result;
		}
		string header = SectionBefore(normalized, "\n[Visible text]");
		string visible = SectionBetween(normalized, "\n[Visible text]", "\n[Links]");
		string links = SectionBetween(normalized, "\n[Links]", "\n[HTML excerpt]");
		string html = SectionAfter(normalized, "\n[HTML excerpt]");
		StringBuilder sb = new StringBuilder();
		if (!string.IsNullOrWhiteSpace(header))
		{
			sb.AppendLine(header.Trim());
		}
		sb.AppendLine();
		sb.AppendLine("[Visible text]");
		sb.AppendLine(TruncateForLog((visible ?? "").Trim(), 2400));
		sb.AppendLine();
		sb.AppendLine("[Links]");
		int keptLinks = 0;
		string[] array = (links ?? "").Split(new char[1] { '\n' }, StringSplitOptions.RemoveEmptyEntries);
		foreach (string line in array)
		{
			if (keptLinks >= 10)
			{
				break;
			}
			sb.AppendLine(line.Trim());
			keptLinks++;
		}
		if (keptLinks == 0)
		{
			sb.AppendLine("No links found.");
		}
		sb.AppendLine();
		sb.AppendLine("[HTML excerpt]");
		sb.AppendLine(TruncateForLog((html ?? "").Trim(), 800));
		sb.AppendLine();
		sb.AppendLine("[LmVsProxy note] Browser Skill result was compacted before sending it back to the model to avoid LlmRuntime context overflow. Use browser_find_text or browser_read_page with a narrow URL/query if more detail is required.");
		return sb.ToString().TrimEnd();
	}

	private static string SectionBefore(string value, string marker)
	{
		if (string.IsNullOrEmpty(value))
		{
			return "";
		}
		int index = value.IndexOf(marker, StringComparison.Ordinal);
		return (index < 0) ? value : value.Substring(0, index);
	}

	private static string SectionBetween(string value, string startMarker, string endMarker)
	{
		if (string.IsNullOrEmpty(value))
		{
			return "";
		}
		int start = value.IndexOf(startMarker, StringComparison.Ordinal);
		if (start < 0)
		{
			return "";
		}
		start += startMarker.Length;
		int end = value.IndexOf(endMarker, start, StringComparison.Ordinal);
		return (end < 0) ? value.Substring(start) : value.Substring(start, end - start);
	}

	private static string SectionAfter(string value, string marker)
	{
		if (string.IsNullOrEmpty(value))
		{
			return "";
		}
		int index = value.IndexOf(marker, StringComparison.Ordinal);
		return (index < 0) ? "" : value.Substring(index + marker.Length);
	}

	private async Task<string> ExecuteLlmRuntimeToolAsync(string toolName, string argumentsJson, string ownerKey, string sessionId, ChatPermissionState permissions)
	{
		try
		{
			string url = BuildLocalModelRuntimeBaseUrl().TrimEnd('/') + "/api/v1/tools/calls";
			string projectPath = ResolveLlmRuntimeToolProjectPath(ownerKey, sessionId);
			string requestOwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
			bool approved = IsLlmRuntimeToolPreapproved(requestOwnerKey, toolName, permissions);
			ChatSessionCompatibilityPayload sessionCompatibility = BuildChatSessionCompatibilityPayload(requestOwnerKey, sessionId, ChatModel, "LlmRuntime", -1L, 0L);
			string payload = BuildLlmRuntimeToolCallPayload(toolName, argumentsJson, projectPath, approved, sessionCompatibility);
			string body = await PostLlmRuntimeToolCallAsync(url, payload).ConfigureAwait(continueOnCapturedContext: false);
			if (approved || !LlmRuntimeToolResponseRequiresApproval(body))
			{
				return MaterializeLlmRuntimeToolArtifactsInSession(toolName, body, ownerKey, sessionId);
			}
			TerminalPermissionDecision decision = await QueueTerminalPermissionRequestAsync(requestOwnerKey, new TerminalCommandRequest
			{
				Command = BuildLlmRuntimeToolApprovalCommand(toolName),
				Shell = "llmruntime",
				WorkingDirectory = (projectPath ?? ""),
				Summary = "Approve LlmRuntime proprietary tool: " + toolName,
				TimeoutMs = 120000
			}, CancellationToken.None).ConfigureAwait(continueOnCapturedContext: false);
			if (!decision.Approved)
			{
				return toolName + " blocked: " + (string.IsNullOrWhiteSpace(decision.Reason) ? "LlmRuntime tool call was not approved." : decision.Reason);
			}
			payload = BuildLlmRuntimeToolCallPayload(toolName, argumentsJson, projectPath, approved: true, sessionCompatibility);
			return MaterializeLlmRuntimeToolArtifactsInSession(toolName, await PostLlmRuntimeToolCallAsync(url, payload).ConfigureAwait(continueOnCapturedContext: false), ownerKey, sessionId);
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			return "LlmRuntime tool bridge failed: " + ex2.Message;
		}
	}

	private string MaterializeLlmRuntimeToolArtifactsInSession(string toolName, string body, string ownerKey, string sessionId)
	{
		string mediaKind;
		return TryGetLlmRuntimeMediaToolKind(toolName, out mediaKind) ? MaterializeChatUiMediaGenerationArtifactsInSession(body, ownerKey, sessionId, mediaKind) : body;
	}

	private static bool TryGetLlmRuntimeMediaToolKind(string toolName, out string mediaKind)
	{
		mediaKind = "";
		string normalized = (toolName ?? "").Trim().Replace('.', '_').Replace('-', '_')
			.ToLowerInvariant();
		if (normalized.Equals("jackonnx_image_generate", StringComparison.OrdinalIgnoreCase) || normalized.Equals("jackonnx_image.generate", StringComparison.OrdinalIgnoreCase))
		{
			mediaKind = "image";
			return true;
		}
		if (normalized.Equals("jackonnx_audio_generate", StringComparison.OrdinalIgnoreCase) ||
			normalized.Equals("jackonnx_audio.generate", StringComparison.OrdinalIgnoreCase) ||
			normalized.Equals("jackonnx_audio_speech", StringComparison.OrdinalIgnoreCase) ||
			normalized.Equals("jackonnx_audio.speech", StringComparison.OrdinalIgnoreCase))
		{
			mediaKind = "audio";
			return true;
		}
		if (normalized.Equals("jackonnx_video_generate", StringComparison.OrdinalIgnoreCase) || normalized.Equals("jackonnx_video.generate", StringComparison.OrdinalIgnoreCase))
		{
			mediaKind = "video";
			return true;
		}
		return false;
	}

	private async Task<string> PostLlmRuntimeToolCallAsync(string url, string payload)
	{
		using StringContent content = new StringContent(payload, Encoding.UTF8, "application/json");
		using CancellationTokenSource cts = new CancellationTokenSource(TimeSpan.FromSeconds(30.0));
		using HttpResponseMessage response = await _httpClient.PostAsync(url, content, cts.Token).ConfigureAwait(continueOnCapturedContext: false);
		string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false)) : "");
		string body = text;
		if (!response.IsSuccessStatusCode)
		{
			return "LlmRuntime tool bridge failed: " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + response.ReasonPhrase + "\n" + body;
		}
		return body;
	}

	private bool IsLlmRuntimeToolPreapproved(string ownerKey, string toolName, ChatPermissionState permissions)
	{
		if (permissions != null && permissions.terminalForeverApproved)
		{
			return true;
		}
		bool savedApproved;
		return TryGetTerminalPermissionRuleDecision(ownerKey, BuildLlmRuntimeToolApprovalCommand(toolName), out savedApproved) && savedApproved;
	}

	private static string BuildLlmRuntimeToolApprovalCommand(string toolName)
	{
		return "llmruntime:" + (toolName ?? "").Trim();
	}

	private static bool LlmRuntimeToolResponseRequiresApproval(string body)
	{
		if (string.IsNullOrWhiteSpace(body))
		{
			return false;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(body);
			if (!document.RootElement.TryGetProperty("results", out var results) || results.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			foreach (JsonElement result in results.EnumerateArray())
			{
				if (result.TryGetProperty("approvalRequired", out var approvalRequired) && approvalRequired.ValueKind == JsonValueKind.True)
				{
					return true;
				}
				string error = ExtractStringProperty(result, "error") ?? "";
				if (error.IndexOf("requires approval", StringComparison.OrdinalIgnoreCase) >= 0)
				{
					return true;
				}
			}
		}
		catch
		{
			return body.IndexOf("requires approval", StringComparison.OrdinalIgnoreCase) >= 0;
		}
		return false;
	}

	private string BuildLlmRuntimeToolCallPayload(string toolName, string argumentsJson, string projectPath, bool approved, ChatSessionCompatibilityPayload sessionCompatibility = null)
	{
		JsonDocument argumentsDocument = null;
		try
		{
			argumentsDocument = JsonDocument.Parse(string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson);
		}
		catch
		{
			argumentsDocument = JsonDocument.Parse("{}");
		}
		try
		{
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			writer.WriteStartObject();
			writer.WriteBoolean("approved", approved);
			writer.WriteString("project_path", projectPath ?? "");
			if (sessionCompatibility != null)
			{
				writer.WritePropertyName("session");
				JsonSerializer.Serialize(writer, sessionCompatibility);
				writer.WritePropertyName("metadata");
				writer.WriteStartObject();
				writer.WritePropertyName("lmvsproxy");
				JsonSerializer.Serialize(writer, sessionCompatibility);
				writer.WriteEndObject();
			}
			writer.WritePropertyName("tool_calls");
			writer.WriteStartArray();
			writer.WriteStartObject();
			writer.WriteString("id", "call_lrt_" + Guid.NewGuid().ToString("N").Substring(0, 16));
			writer.WriteString("name", toolName ?? "");
			writer.WritePropertyName("arguments");
			argumentsDocument.RootElement.WriteTo(writer);
			writer.WriteEndObject();
			writer.WriteEndArray();
			writer.WriteEndObject();
			writer.Flush();
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		finally
		{
			argumentsDocument.Dispose();
		}
	}

	private string BuildLlmRuntimeToolCallPayload(string toolName, string argumentsJson, string projectPath)
	{
		return BuildLlmRuntimeToolCallPayload(toolName, argumentsJson, projectPath, approved: false);
	}

	private string ResolveLlmRuntimeToolProjectPath(string ownerKey, string sessionId)
	{
		try
		{
			foreach (string root in GetChatAgentAllowedRoots(ownerKey, sessionId))
			{
				if (!string.IsNullOrWhiteSpace(root) && Directory.Exists(root))
				{
					return root;
				}
			}
		}
		catch
		{
		}
		try
		{
			foreach (string sessionRoot in GetChatAgentSessionRoots(EnsureChatUiSessionId(sessionId), ensureExists: true))
			{
				if (!string.IsNullOrWhiteSpace(sessionRoot) && Directory.Exists(sessionRoot))
				{
					return sessionRoot;
				}
			}
		}
		catch
		{
		}
		return "";
	}

	private bool IsGitCliAvailable(bool force = false)
	{
		lock (_gitServiceAvailabilityLock)
		{
			if (!force && DateTimeOffset.UtcNow - _gitServiceAvailabilityCheckedUtc < TimeSpan.FromSeconds(60.0))
			{
				return _gitServiceAvailable;
			}
		}
		bool available = false;
		string version = "";
		try
		{
			GitCommandResult result = _gitService.ExecuteAsync(new GitCommandRequest
			{
				Operation = "dependency_check",
				WorkingDirectory = Environment.CurrentDirectory,
				TimeoutMs = 5000
			}, CancellationToken.None).GetAwaiter().GetResult();
			available = result != null && result.Ok && result.GitAvailable;
			version = ((result == null) ? "" : (result.Output ?? "").Trim());
		}
		catch (Exception ex)
		{
			available = false;
			version = ex.Message;
		}
		lock (_gitServiceAvailabilityLock)
		{
			if (_gitServiceAvailable != available)
			{
				LogMessage("[Git Service] Auto-detect " + (available ? "enabled" : "disabled") + (string.IsNullOrWhiteSpace(version) ? "" : (": " + version)));
			}
			_gitServiceAvailable = available;
			_gitServiceVersion = version ?? "";
			_gitServiceAvailabilityCheckedUtc = DateTimeOffset.UtcNow;
			return _gitServiceAvailable;
		}
	}

	private async Task<string> ExecuteBrowserSkillToolAsync(string toolName, string argumentsJson, string ownerKey, string sessionId)
	{
		string normalized = (toolName ?? "").Trim().ToLowerInvariant();
		if (normalized.Equals("browser_open", StringComparison.Ordinal))
		{
			return await ExecuteBrowserSkillOpenAsync(argumentsJson, ownerKey, sessionId).ConfigureAwait(continueOnCapturedContext: false);
		}
		if (normalized.Equals("browser_read_page", StringComparison.Ordinal))
		{
			return await ExecuteBrowserSkillReadPageAsync(argumentsJson, ownerKey, sessionId).ConfigureAwait(continueOnCapturedContext: false);
		}
		if (normalized.Equals("browser_click_link", StringComparison.Ordinal))
		{
			return await ExecuteBrowserSkillClickLinkAsync(argumentsJson, ownerKey, sessionId).ConfigureAwait(continueOnCapturedContext: false);
		}
		if (normalized.Equals("browser_click", StringComparison.Ordinal))
		{
			return ExecuteBrowserSkillDomAction("browser_click", argumentsJson, ownerKey, sessionId);
		}
		if (normalized.Equals("browser_type", StringComparison.Ordinal))
		{
			return ExecuteBrowserSkillDomAction("browser_type", argumentsJson, ownerKey, sessionId);
		}
		if (normalized.Equals("browser_select", StringComparison.Ordinal))
		{
			return ExecuteBrowserSkillDomAction("browser_select", argumentsJson, ownerKey, sessionId);
		}
		if (normalized.Equals("browser_press", StringComparison.Ordinal))
		{
			return ExecuteBrowserSkillDomAction("browser_press", argumentsJson, ownerKey, sessionId);
		}
		if (normalized.Equals("browser_find_text", StringComparison.Ordinal))
		{
			return ExecuteBrowserSkillFindText(argumentsJson, ownerKey, sessionId);
		}
		return toolName + " failed: unsupported Browser Skill tool.";
	}

	private string BrowserSkillStateKey(string ownerKey, string sessionId)
	{
		return (string.IsNullOrWhiteSpace(ownerKey) ? "global" : ownerKey.Trim().ToLowerInvariant()) + "|" + EnsureChatUiSessionId(sessionId);
	}

	private ChatBrowserClientSession GetOrCreateChatBrowserClientSession(string ownerKey, string sessionId)
	{
		string normalizedOwner = string.IsNullOrWhiteSpace(ownerKey) ? "global" : ownerKey.Trim().ToLowerInvariant();
		string normalizedSession = EnsureChatUiSessionId(sessionId);
		string key = normalizedOwner + "|" + normalizedSession;
		lock (_chatBrowserClientSessionsLock)
		{
			if (!_chatBrowserClientSessions.TryGetValue(key, out var session) || session == null)
			{
				session = new ChatBrowserClientSession(key, _promptTimeout);
				_chatBrowserClientSessions[key] = session;
			}
			session.LastUsedUtc = DateTimeOffset.UtcNow;
			return session;
		}
	}

	private ChatBrowserClientSession CreateTransientChatBrowserClientSession()
	{
		return new ChatBrowserClientSession("transient_" + Guid.NewGuid().ToString("N"), _promptTimeout);
	}

	private static string BuildBrowserClientSandboxLabel(string ownerKey, string sessionId)
	{
		string owner = string.IsNullOrWhiteSpace(ownerKey) ? "global" : ownerKey.Trim().ToLowerInvariant();
		string session = string.IsNullOrWhiteSpace(sessionId) ? "transient" : sessionId.Trim();
		return owner + "|" + session;
	}

	private void DisposeChatBrowserClientSessions()
	{
		List<ChatBrowserClientSession> sessions;
		lock (_chatBrowserClientSessionsLock)
		{
			sessions = _chatBrowserClientSessions.Values.ToList();
			_chatBrowserClientSessions.Clear();
		}
		foreach (ChatBrowserClientSession session in sessions)
		{
			try
			{
				session.Dispose();
			}
			catch
			{
			}
		}
	}

	private bool TryParseBrowserSkillArguments(string argumentsJson, out JsonDocument document, out string error)
	{
		document = null;
		error = "";
		try
		{
			document = JsonDocument.Parse(string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson);
			if (document.RootElement.ValueKind != JsonValueKind.Object)
			{
				error = "Browser Skill tool arguments must be a JSON object.";
				document.Dispose();
				document = null;
				return false;
			}
			return true;
		}
		catch (Exception ex)
		{
			error = "Browser Skill tool arguments were not valid JSON: " + ex.Message;
			return false;
		}
	}

	private string BrowserSkillArgumentString(JsonElement root, string name)
	{
		return (root.ValueKind == JsonValueKind.Object) ? (ExtractStringProperty(root, name) ?? "") : "";
	}

	private string SanitizeBrowserSkillUrlArgument(string value)
	{
		string raw = WebUtility.HtmlDecode(value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(raw))
		{
			return "";
		}
		int firstHttp = FirstBrowserSkillHttpUrlIndex(raw);
		if (firstHttp > 0)
		{
			raw = raw.Substring(firstHttp).TrimStart();
		}
		const string metadataLabels = "(?:query|text|selector|href|url|take|index|value|key|label|action|mode)";
		RegexOptions options = RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant;
		raw = Regex.Replace(raw, @"(?:\\r)?\\n\s*" + metadataLabels + @"\s*:.*$", "", options);
		raw = Regex.Replace(raw, @"(?:%5c%5cr|%5cr)?(?:%5c%5cn|%5cn)\s*" + metadataLabels + @"\s*:.*$", "", options);
		raw = Regex.Replace(raw, @"(?:%0d)?%0a\s*" + metadataLabels + @"\s*:.*$", "", options);
		int newlineIndex = raw.IndexOfAny(new[] { '\r', '\n' });
		if (newlineIndex >= 0)
		{
			raw = raw.Substring(0, newlineIndex);
		}
		Match absoluteUrl = Regex.Match(raw, "https?://[^\\s<>\"']+", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		if (absoluteUrl.Success)
		{
			raw = absoluteUrl.Value;
		}
		raw = raw.Trim().Trim('"', '\'', '`');
		raw = Regex.Replace(raw, @"[)\].,;]+$", "", RegexOptions.CultureInvariant);
		return raw.Trim();
	}

	private static int FirstBrowserSkillHttpUrlIndex(string value)
	{
		if (string.IsNullOrEmpty(value))
		{
			return -1;
		}
		int http = value.IndexOf("http://", StringComparison.OrdinalIgnoreCase);
		int https = value.IndexOf("https://", StringComparison.OrdinalIgnoreCase);
		if (http < 0)
		{
			return https;
		}
		if (https < 0)
		{
			return http;
		}
		return Math.Min(http, https);
	}

	private int BrowserSkillArgumentInt(JsonElement root, string name, int fallback)
	{
		if (root.ValueKind != JsonValueKind.Object || !root.TryGetProperty(name, out var value))
		{
			return fallback;
		}
		if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out var number))
		{
			return number;
		}
		if (value.ValueKind == JsonValueKind.String && int.TryParse(value.GetString(), NumberStyles.Integer, CultureInfo.InvariantCulture, out number))
		{
			return number;
		}
		return fallback;
	}

	private bool TryResolveBrowserSkillUri(string value, ChatBrowserSkillPageState state, out Uri uri, out string error)
	{
		uri = null;
		error = "";
		string raw = (value ?? "").Trim();
		if (string.IsNullOrWhiteSpace(raw))
		{
			error = "URL is required.";
			return false;
		}
		Uri baseUri = null;
		if (state != null && Uri.TryCreate(state.Url, UriKind.Absolute, out Uri parsedBase))
		{
			baseUri = parsedBase;
		}
		raw = SanitizeBrowserSkillUrlArgument(raw);
		if (string.IsNullOrWhiteSpace(raw))
		{
			error = "URL is required.";
			return false;
		}
		if (!Uri.TryCreate(raw, UriKind.Absolute, out uri) && (baseUri == null || !Uri.TryCreate(baseUri, raw, out uri)))
		{
			error = "Could not resolve URL: " + raw;
			return false;
		}
		if (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps)
		{
			error = "Only HTTP and HTTPS URLs can be opened by Browser Skill.";
			return false;
		}
		return true;
	}

	private static Uri TryCreateBrowserSkillReferer(ChatBrowserSkillPageState state)
	{
		if (state != null && Uri.TryCreate(state.Url, UriKind.Absolute, out Uri referer) && (referer.Scheme == Uri.UriSchemeHttp || referer.Scheme == Uri.UriSchemeHttps))
		{
			return referer;
		}
		return null;
	}

	private async Task<string> ExecuteBrowserSkillOpenAsync(string argumentsJson, string ownerKey, string sessionId)
	{
		if (!TryParseBrowserSkillArguments(argumentsJson, out var document, out var error))
		{
			return "browser_open failed: " + error;
		}
		using (document)
		{
			string key = BrowserSkillStateKey(ownerKey, sessionId);
			_chatBrowserSkillPages.TryGetValue(key, out var state);
			string url = BrowserSkillArgumentString(document.RootElement, "url");
			if (!TryResolveBrowserSkillUri(url, state, out var uri, out error))
			{
				return "browser_open failed: " + error;
			}
			ChatBrowserSkillPageState page = await FetchBrowserSkillPageAsync(uri, ownerKey, sessionId, null).ConfigureAwait(continueOnCapturedContext: false);
			_chatBrowserSkillPages[key] = page;
			return BuildBrowserSkillPageResult("browser_open", page, BrowserSkillArgumentInt(document.RootElement, "take", 40));
		}
	}

	private async Task<string> ExecuteBrowserSkillReadPageAsync(string argumentsJson, string ownerKey, string sessionId)
	{
		if (!TryParseBrowserSkillArguments(argumentsJson, out var document, out var error))
		{
			return "browser_read_page failed: " + error;
		}
		using (document)
		{
			string key = BrowserSkillStateKey(ownerKey, sessionId);
			_chatBrowserSkillPages.TryGetValue(key, out var state);
			string url = BrowserSkillArgumentString(document.RootElement, "url");
			int take = BrowserSkillArgumentInt(document.RootElement, "take", 40);
			if (!string.IsNullOrWhiteSpace(url))
			{
				if (!TryResolveBrowserSkillUri(url, state, out var uri, out error))
				{
					return "browser_read_page failed: " + error;
				}
				state = await FetchBrowserSkillPageAsync(uri, ownerKey, sessionId, TryCreateBrowserSkillReferer(state)).ConfigureAwait(continueOnCapturedContext: false);
				_chatBrowserSkillPages[key] = state;
			}
			if (state == null)
			{
				return "browser_read_page failed: no Browser Skill page is loaded yet. Call browser_open with a URL first.";
			}
			return BuildBrowserSkillPageResult("browser_read_page", state, take);
		}
	}

	private async Task<string> ExecuteBrowserSkillClickLinkAsync(string argumentsJson, string ownerKey, string sessionId)
	{
		if (!TryParseBrowserSkillArguments(argumentsJson, out var document, out var error))
		{
			return "browser_click_link failed: " + error;
		}
		using (document)
		{
			string key = BrowserSkillStateKey(ownerKey, sessionId);
			if (!_chatBrowserSkillPages.TryGetValue(key, out var state) || state == null)
			{
				return "browser_click_link failed: no Browser Skill page is loaded yet. Call browser_open first.";
			}
			int index = BrowserSkillArgumentInt(document.RootElement, "index", 0);
			string text = BrowserSkillArgumentString(document.RootElement, "text");
			ChatBrowserSkillLink link = null;
			if (index > 0)
			{
				link = state.Links.FirstOrDefault((ChatBrowserSkillLink item) => item != null && item.Index == index);
			}
			if (link == null && !string.IsNullOrWhiteSpace(text))
			{
				string needle = NormalizeBrowserSkillText(text);
				link = state.Links.FirstOrDefault((ChatBrowserSkillLink item) => item != null && NormalizeBrowserSkillText(item.Text).IndexOf(needle, StringComparison.OrdinalIgnoreCase) >= 0);
			}
			if (link == null)
			{
				return "browser_click_link failed: no matching link was found. Use browser_read_page to inspect current link indexes/text.";
			}
			if (!TryResolveBrowserSkillUri(link.Href, state, out var uri, out error))
			{
				return "browser_click_link failed: " + error;
			}
			ChatBrowserSkillPageState page = await FetchBrowserSkillPageAsync(uri, ownerKey, sessionId, TryCreateBrowserSkillReferer(state)).ConfigureAwait(continueOnCapturedContext: false);
			_chatBrowserSkillPages[key] = page;
			return "clickedLink: " + link.Index.ToString(CultureInfo.InvariantCulture) + " " + link.Text + Environment.NewLine + BuildBrowserSkillPageResult("browser_click_link", page, BrowserSkillArgumentInt(document.RootElement, "take", 40));
		}
	}

	private string ExecuteBrowserSkillFindText(string argumentsJson, string ownerKey, string sessionId)
	{
		if (!TryParseBrowserSkillArguments(argumentsJson, out var document, out var error))
		{
			return "browser_find_text failed: " + error;
		}
		using (document)
		{
			string key = BrowserSkillStateKey(ownerKey, sessionId);
			if (!_chatBrowserSkillPages.TryGetValue(key, out var state) || state == null)
			{
				return "browser_find_text failed: no Browser Skill page is loaded yet. Call browser_open first.";
			}
			string query = BrowserSkillArgumentString(document.RootElement, "query");
			if (string.IsNullOrWhiteSpace(query))
			{
				return "browser_find_text failed: query is required.";
			}
			int take = Math.Max(1, Math.Min(30, BrowserSkillArgumentInt(document.RootElement, "take", 8)));
			string haystack = FirstNonEmpty(state.Text, HtmlToBrowserSkillText(state.Html));
			string lowerHaystack = haystack.ToLowerInvariant();
			string lowerNeedle = query.Trim().ToLowerInvariant();
			List<string> matches = new List<string>();
			int index = 0;
			while (matches.Count < take && index >= 0 && index < lowerHaystack.Length)
			{
				index = lowerHaystack.IndexOf(lowerNeedle, index, StringComparison.Ordinal);
				if (index < 0)
				{
					break;
				}
				int start = Math.Max(0, index - 180);
				int length = Math.Min(haystack.Length - start, lowerNeedle.Length + 360);
				matches.Add("match " + (matches.Count + 1).ToString(CultureInfo.InvariantCulture) + ": " + haystack.Substring(start, length).Trim());
				index += Math.Max(1, lowerNeedle.Length);
			}
			return "browser_find_text" + Environment.NewLine + "url: " + state.Url + Environment.NewLine + "query: " + query + Environment.NewLine + ((matches.Count == 0) ? "No matches found." : string.Join(Environment.NewLine + Environment.NewLine, matches));
		}
	}

	private string ExecuteBrowserSkillDomAction(string toolName, string argumentsJson, string ownerKey, string sessionId)
	{
		if (!TryParseBrowserSkillArguments(argumentsJson, out var document, out var error))
		{
			return toolName + " failed: " + error;
		}
		using (document)
		{
			string key = BrowserSkillStateKey(ownerKey, sessionId);
			_chatBrowserSkillPages.TryGetValue(key, out var state);
			string selector = BrowserSkillArgumentString(document.RootElement, "selector");
			string text = BrowserSkillArgumentString(document.RootElement, "text");
			string value = BrowserSkillArgumentString(document.RootElement, "value");
			string query = BrowserSkillArgumentString(document.RootElement, "query");
			string keyName = BrowserSkillArgumentString(document.RootElement, "key");
			int index = BrowserSkillArgumentInt(document.RootElement, "index", 0);
			string target = FirstNonEmpty(selector, index > 0 ? ("control #" + index.ToString(CultureInfo.InvariantCulture)) : "", text, value, query, keyName, "current focus");
			StringBuilder sb = new StringBuilder();
			sb.AppendLine("[Browser Skill " + toolName + "]");
			sb.AppendLine("action: " + toolName);
			if (state != null)
			{
				sb.AppendLine("url: " + state.Url);
				sb.AppendLine("title: " + (string.IsNullOrWhiteSpace(state.Title) ? "(untitled)" : state.Title));
			}
			else
			{
				sb.AppendLine("url: (none)");
			}
			sb.AppendLine("target: " + target);
			if (!string.IsNullOrWhiteSpace(value))
				sb.AppendLine("value: " + value);
			if (!string.IsNullOrWhiteSpace(keyName))
				sb.AppendLine("key: " + keyName);
			sb.AppendLine("The visible Web Chat browser mirrors this DOM action when the page allows same-origin proxy access. Request BROWSER_SKILL_OBSERVE next if updated page text, form state, or a screenshot is needed.");
			return sb.ToString().TrimEnd();
		}
	}

	private void AddBrowserLikeHeaders(HttpRequestMessage request, Uri uri, Uri referer = null)
	{
		if (request == null)
		{
			return;
		}
		request.Headers.TryAddWithoutValidation("User-Agent", BrowserLikeUserAgent);
		request.Headers.TryAddWithoutValidation("Accept", BrowserLikeAccept);
		request.Headers.TryAddWithoutValidation("Accept-Language", "en-US,en;q=0.9");
		request.Headers.TryAddWithoutValidation("Cache-Control", "no-cache");
		request.Headers.TryAddWithoutValidation("Pragma", "no-cache");
		request.Headers.TryAddWithoutValidation("Upgrade-Insecure-Requests", "1");
		request.Headers.TryAddWithoutValidation("Sec-CH-UA", "\"Chromium\";v=\"125\", \"Google Chrome\";v=\"125\", \"Not.A/Brand\";v=\"24\"");
		request.Headers.TryAddWithoutValidation("Sec-CH-UA-Mobile", "?0");
		request.Headers.TryAddWithoutValidation("Sec-CH-UA-Platform", "\"Windows\"");
		request.Headers.TryAddWithoutValidation("Sec-Fetch-Dest", "document");
		request.Headers.TryAddWithoutValidation("Sec-Fetch-Mode", "navigate");
		request.Headers.TryAddWithoutValidation("Sec-Fetch-Site", referer == null || uri == null || string.Equals(referer.Host, uri.Host, StringComparison.OrdinalIgnoreCase) ? "same-origin" : "cross-site");
		request.Headers.TryAddWithoutValidation("Sec-Fetch-User", "?1");
		if (referer != null)
		{
			request.Headers.TryAddWithoutValidation("Referer", referer.AbsoluteUri);
		}
	}

	private async Task<ChatBrowserSkillPageState> FetchBrowserSkillPageAsync(Uri uri, string ownerKey, string sessionId, Uri referer)
	{
		using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, uri);
		AddBrowserLikeHeaders(request, uri, referer);
		ChatBrowserClientSession browserSession = GetOrCreateChatBrowserClientSession(ownerKey, sessionId);
		using HttpResponseMessage response = await browserSession.ReadClient.SendAsync(request).ConfigureAwait(continueOnCapturedContext: false);
		string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false)) : "");
		string html = text;
		string finalUrl = ((response.RequestMessage != null && response.RequestMessage.RequestUri != null) ? response.RequestMessage.RequestUri.ToString() : uri.ToString());
		ChatBrowserSkillPageState state = new ChatBrowserSkillPageState
		{
			Url = finalUrl,
			Title = ExtractBrowserSkillTitle(html),
			Html = TruncateForLog(html ?? "", 160000),
			Text = TruncateForLog(HtmlToBrowserSkillText(html), 50000),
			FetchedUtc = DateTimeOffset.UtcNow
		};
		state.Links = ExtractBrowserSkillLinks(state.Html, state.Url, 120);
		state.Controls = ExtractBrowserSkillControls(state.Html, 80);
		if (!response.IsSuccessStatusCode)
		{
			state.Text = "HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + response.ReasonPhrase + Environment.NewLine + state.Text;
		}
		return state;
	}

	private string BuildBrowserSkillPageResult(string action, ChatBrowserSkillPageState page, int take)
	{
		take = Math.Max(1, Math.Min(40, (take <= 0) ? 20 : take));
		List<ChatBrowserSkillLink> links = page.Links ?? new List<ChatBrowserSkillLink>();
		List<ChatBrowserSkillControl> controls = page.Controls ?? new List<ChatBrowserSkillControl>();
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("[Browser Skill " + action + "]");
		sb.AppendLine("url: " + page.Url);
		sb.AppendLine("title: " + (string.IsNullOrWhiteSpace(page.Title) ? "(untitled)" : page.Title));
		sb.AppendLine("fetchedUtc: " + page.FetchedUtc.ToString("O"));
		sb.AppendLine();
		sb.AppendLine("[Visible text]");
		sb.AppendLine(TruncateForLog(page.Text ?? "", 6000));
		sb.AppendLine();
		sb.AppendLine("[Links]");
		foreach (ChatBrowserSkillLink link in links.Take(take))
		{
			sb.AppendLine(link.Index.ToString(CultureInfo.InvariantCulture) + ". " + FirstNonEmpty(link.Text, "(untitled link)") + " - " + link.Href);
		}
		if (links.Count == 0)
		{
			sb.AppendLine("No links found.");
		}
		sb.AppendLine();
		sb.AppendLine("[Controls]");
		foreach (ChatBrowserSkillControl control in controls.Take(take))
		{
			sb.AppendLine(control.Index.ToString(CultureInfo.InvariantCulture) + ". " + FirstNonEmpty(control.Label, control.Name, control.Id, control.Type, control.Tag, "control") + " - " + control.Tag + (string.IsNullOrWhiteSpace(control.Type) ? "" : (" type=" + control.Type)));
		}
		if (controls.Count == 0)
		{
			sb.AppendLine("No controls found.");
		}
		sb.AppendLine();
		sb.AppendLine("[HTML excerpt]");
		sb.AppendLine(TruncateForLog(page.Html ?? "", 4500));
		return sb.ToString().TrimEnd();
	}

	private string ExtractBrowserSkillTitle(string html)
	{
		if (string.IsNullOrWhiteSpace(html))
		{
			return "";
		}
		Match match = Regex.Match(html, "<title[^>]*>(?<title>.*?)</title>", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		return match.Success ? NormalizeBrowserSkillText(WebUtility.HtmlDecode(match.Groups["title"].Value)) : "";
	}

	private string HtmlToBrowserSkillText(string html)
	{
		if (string.IsNullOrWhiteSpace(html))
		{
			return "";
		}
		string text = Regex.Replace(html, "<script\\b[^<]*(?:(?!</script>)<[^<]*)*</script>", " ", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		text = Regex.Replace(text, "<style\\b[^<]*(?:(?!</style>)<[^<]*)*</style>", " ", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant);
		text = Regex.Replace(text, "<[^>]+>", " ", RegexOptions.CultureInvariant);
		return NormalizeBrowserSkillText(WebUtility.HtmlDecode(text));
	}

	private string NormalizeBrowserSkillText(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return "";
		}
		return Regex.Replace(value, "\\s+", " ", RegexOptions.CultureInvariant).Trim();
	}

	private List<ChatBrowserSkillLink> ExtractBrowserSkillLinks(string html, string baseUrl, int take)
	{
		List<ChatBrowserSkillLink> links = new List<ChatBrowserSkillLink>();
		if (string.IsNullOrWhiteSpace(html))
		{
			return links;
		}
		Uri baseUri = null;
		Uri.TryCreate(baseUrl, UriKind.Absolute, out baseUri);
		foreach (Match match in Regex.Matches(html, "<a\\b(?<attrs>[^>]*)>(?<text>.*?)</a>", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant))
		{
			if (links.Count >= take)
			{
				break;
			}
			string attrs = match.Groups["attrs"].Value;
			Match hrefMatch = Regex.Match(attrs, "href\\s*=\\s*(?:\"(?<href>[^\"]*)\"|'(?<href>[^']*)'|(?<href>[^\\s>]+))", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
			if (!hrefMatch.Success)
			{
				continue;
			}
			string href = WebUtility.HtmlDecode(hrefMatch.Groups["href"].Value ?? "").Trim();
			if (!string.IsNullOrWhiteSpace(href) && !href.StartsWith("javascript:", StringComparison.OrdinalIgnoreCase) && !href.StartsWith("mailto:", StringComparison.OrdinalIgnoreCase))
			{
				if (baseUri != null && Uri.TryCreate(baseUri, href, out Uri resolved))
				{
					href = resolved.ToString();
				}
				string text = NormalizeBrowserSkillText(HtmlToBrowserSkillText(match.Groups["text"].Value));
				if (string.IsNullOrWhiteSpace(text))
				{
					text = href;
				}
				if (!links.Any((ChatBrowserSkillLink existing) => string.Equals(existing.Href, href, StringComparison.OrdinalIgnoreCase) && string.Equals(existing.Text, text, StringComparison.OrdinalIgnoreCase)))
				{
					links.Add(new ChatBrowserSkillLink
					{
						Index = links.Count + 1,
						Text = TruncateForLog(text, 180),
						Href = href
					});
				}
			}
		}
		return links;
	}

	private List<ChatBrowserSkillControl> ExtractBrowserSkillControls(string html, int take)
	{
		List<ChatBrowserSkillControl> controls = new List<ChatBrowserSkillControl>();
		if (string.IsNullOrWhiteSpace(html))
		{
			return controls;
		}
		foreach (Match match in Regex.Matches(html, "<(?<tag>button|input|textarea|select)\\b(?<attrs>[^>]*)>(?<text>.*?)</\\s*\\k<tag>\\s*>|<(?<single>input)\\b(?<singleAttrs>[^>]*)/?\\s*>", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant))
		{
			if (controls.Count >= take)
			{
				break;
			}
			string tag = FirstNonEmpty(match.Groups["tag"].Value, match.Groups["single"].Value).ToLowerInvariant();
			string attrs = FirstNonEmpty(match.Groups["attrs"].Value, match.Groups["singleAttrs"].Value);
			string type = FirstNonEmpty(ExtractBrowserSkillAttribute(attrs, "type"), tag);
			string id = ExtractBrowserSkillAttribute(attrs, "id");
			string name = ExtractBrowserSkillAttribute(attrs, "name");
			string label = FirstNonEmpty(
				ExtractBrowserSkillAttribute(attrs, "aria-label"),
				ExtractBrowserSkillAttribute(attrs, "placeholder"),
				ExtractBrowserSkillAttribute(attrs, "value"),
				NormalizeBrowserSkillText(HtmlToBrowserSkillText(match.Groups["text"].Value)),
				name,
				id,
				type);
			controls.Add(new ChatBrowserSkillControl
			{
				Index = controls.Count + 1,
				Tag = tag,
				Type = TruncateForLog(type, 80),
				Label = TruncateForLog(label, 180),
				Name = TruncateForLog(name, 120),
				Id = TruncateForLog(id, 120)
			});
		}
		return controls;
	}

	private string ExtractBrowserSkillAttribute(string attrs, string name)
	{
		if (string.IsNullOrWhiteSpace(attrs) || string.IsNullOrWhiteSpace(name))
		{
			return "";
		}
		Match match = Regex.Match(attrs, "\\b" + Regex.Escape(name) + "\\s*=\\s*(?:\"(?<value>[^\"]*)\"|'(?<value>[^']*)'|(?<value>[^\\s>]+))", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		return match.Success ? NormalizeBrowserSkillText(WebUtility.HtmlDecode(match.Groups["value"].Value ?? "")) : "";
	}

	private async Task<string> ExecuteProxyResearchToolAsync(string toolName, string argumentsJson, string ownerKey = null, string sessionId = null)
	{
		if (IsProxyOwnedCoordinationTool(toolName))
		{
			return BuildProxyCoordinationToolResult(toolName, argumentsJson, "").Result;
		}
		ChatPermissionState permissions = (string.IsNullOrWhiteSpace(ownerKey) ? GetChatPermissions() : GetChatPermissions(ownerKey));
		if (IsProxyOwnedSockJackDmlTool(toolName))
		{
			if (permissions == null || !permissions.agentAccess)
			{
				return toolName + " blocked: Agent access is required for SockJackDml workflow tools.";
			}
			return await ExecuteSockJackDmlToolAsync(toolName, argumentsJson, ownerKey, sessionId).ConfigureAwait(continueOnCapturedContext: false);
		}
		if (IsProxyOwnedGitTool(toolName))
		{
			if (permissions == null || !permissions.agentAccess)
			{
				return toolName + " blocked: Agent access is required for Git tools.";
			}
			if (!IsGitCliAvailable())
			{
				return toolName + " blocked: Git CLI was not detected. Install Git or make sure git is on PATH.";
			}
			return await ExecuteGitToolAsync(toolName, argumentsJson, ownerKey, sessionId, permissions);
		}
		if (IsProxyOwnedTerminalTool(toolName))
		{
			if (permissions == null || !permissions.terminalCommands)
			{
				return toolName + " blocked: Terminal Commands permission is disabled.";
			}
			return await ExecuteTerminalCommandToolAsync(toolName, argumentsJson, ownerKey);
		}
		if (IsProxyOwnedBrowserTool(toolName))
		{
			if (permissions == null || !permissions.agentAccess)
			{
				return toolName + " blocked: Agent access is required for Browser Skill tools.";
			}
			return await ExecuteBrowserSkillToolAsync(toolName, argumentsJson, ownerKey, sessionId).ConfigureAwait(continueOnCapturedContext: false);
		}
		if (IsProxyOwnedWorkstationModelTool(toolName))
		{
			if (permissions == null || !permissions.agentAccess)
			{
				return toolName + " blocked: Agent access is required for Workstation model runtime tools.";
			}
			return await ExecuteWorkstationModelToolAsync(toolName, argumentsJson).ConfigureAwait(continueOnCapturedContext: false);
		}
		if (IsProxyOwnedVsTool(toolName))
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return toolName + " blocked: VS Copilot Tools permission is disabled.";
			}
			return ExecuteProxyVsTool(toolName, argumentsJson, ownerKey, sessionId);
		}
		if (IsLlmRuntimeToolName(toolName))
		{
			if (permissions == null || !permissions.agentAccess || !permissions.vsCopilotTools)
			{
				return toolName + " blocked: Agent access and VS Copilot Tools permission are required for LlmRuntime proprietary tools.";
			}
			return await ExecuteLlmRuntimeToolAsync(toolName, argumentsJson, ownerKey, sessionId, permissions);
		}
		if (toolName.Equals("download_file", StringComparison.Ordinal))
		{
			if (permissions == null || !permissions.fileDownloads)
			{
				LogMessage("[Chat Storage] download_file blocked: File Downloads permission is disabled.");
				return "download_file blocked: File Downloads permission is disabled.";
			}
			return await ExecuteDownloadFileAsync(argumentsJson, ownerKey, sessionId);
		}
		if (permissions == null || !permissions.internetSearch)
		{
			LogMessage("[Internet Search] " + toolName + " blocked: Internet Search permission is disabled.");
			return toolName + " blocked: Internet Search permission is disabled.";
		}
		if (toolName.Equals("internet_search", StringComparison.Ordinal))
		{
			LogProxyResearchToolStart(toolName, argumentsJson);
			string result = await ExecuteInternetSearchAsync(argumentsJson, ownerKey, sessionId);
			LogProxyResearchToolCompleted(toolName, result);
			return result;
		}
		if (toolName.Equals("nuget_search", StringComparison.Ordinal))
		{
			LogProxyResearchToolStart(toolName, argumentsJson);
			string result2 = await ExecuteNuGetSearchAsync(argumentsJson);
			LogProxyResearchToolCompleted(toolName, result2);
			return result2;
		}
		if (toolName.Equals("nuget_package_info", StringComparison.Ordinal))
		{
			LogProxyResearchToolStart(toolName, argumentsJson);
			string result3 = await ExecuteNuGetPackageInfoAsync(argumentsJson);
			LogProxyResearchToolCompleted(toolName, result3);
			return result3;
		}
		if (toolName.Equals("github_code_search", StringComparison.Ordinal))
		{
			LogProxyResearchToolStart(toolName, argumentsJson);
			string result4 = await ExecuteGitHubCodeSearchAsync(argumentsJson);
			LogProxyResearchToolCompleted(toolName, result4);
			return result4;
		}
		return "Unknown proxy research tool: " + toolName;
	}

	private async Task<string> ExecuteWorkstationModelToolAsync(string toolName, string argumentsJson)
	{
		string name = (toolName ?? "").Trim().ToLowerInvariant();
		if (name.Equals("workstation_list_models", StringComparison.Ordinal))
		{
			return ExecuteWorkstationListModelsTool(argumentsJson);
		}
		if (name.Equals("workstation_run_model", StringComparison.Ordinal))
		{
			return await ExecuteWorkstationRunModelToolAsync(argumentsJson).ConfigureAwait(continueOnCapturedContext: false);
		}
		return "Unknown Workstation model tool: " + toolName;
	}

	private string ExecuteWorkstationListModelsTool(string argumentsJson)
	{
		int take = Math.Max(1, Math.Min(200, ExtractIntFromToolArguments(string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson, "take", 80)));
		bool includeAll = false;
		try
		{
			using JsonDocument arguments = JsonDocument.Parse(string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson);
			includeAll = ReadJsonBoolProperty(arguments.RootElement, "includeAll", false) || ReadJsonBoolProperty(arguments.RootElement, "include_all", false);
		}
		catch
		{
		}
		string responseBody = ForwardLocalModelRuntimeRequest("GET", "/api/v1/models", "", CancellationToken.None);
		return CompactWorkstationModelListToolResult(responseBody, take, includeAll);
	}

	private string CompactWorkstationModelListToolResult(string responseBody, int take, bool includeAll)
	{
		if (string.IsNullOrWhiteSpace(responseBody))
		{
			return "workstation_list_models failed: Workstation model runtime returned an empty response.";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(responseBody);
			JsonElement root = document.RootElement;
			if (root.ValueKind == JsonValueKind.Object && root.TryGetProperty("error", out var error) && (!root.TryGetProperty("models", out var errorModels) || errorModels.ValueKind != JsonValueKind.Array || errorModels.GetArrayLength() == 0))
			{
				return "workstation_list_models failed: " + ReadModelRuntimeErrorMessage(error);
			}
			if (root.ValueKind != JsonValueKind.Object || !root.TryGetProperty("models", out var models) || models.ValueKind != JsonValueKind.Array)
			{
				return TruncateForLog(responseBody, 24000);
			}
			using MemoryStream stream = new MemoryStream();
			using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
			{
				writer.WriteStartObject();
				writer.WriteBoolean("ok", value: true);
				writer.WriteString("runtime", GetLocalModelRuntimeDisplayName());
				writer.WriteBoolean("web_chat_model_load_api_enabled", WebChatModelLoadApiEnabled);
				if (root.TryGetProperty("warning", out var warning) && warning.ValueKind == JsonValueKind.String)
				{
					writer.WriteString("warning", warning.GetString());
				}
				writer.WritePropertyName("models");
				writer.WriteStartArray();
				int written = 0;
				int skipped = 0;
				foreach (JsonElement model in models.EnumerateArray())
				{
					if (model.ValueKind != JsonValueKind.Object)
					{
						continue;
					}
					string id = ExtractRuntimeModelId(model);
					if (string.IsNullOrWhiteSpace(id))
					{
						continue;
					}
					bool enabled = ReadWorkstationModelBool(model, false, "web_chat_model_enabled", "webChatModelEnabled", "enabled", "isEnabled");
					bool dynamicLoadEnabled = ReadWorkstationModelBool(model, false, "web_chat_dynamic_load_enabled", "webChatDynamicLoadEnabled", "dynamicLoadEnabled", "web_chat_dynamic_load");
					bool loaded = RuntimeModelHasLoadedInstances(model) || ReadWorkstationModelBool(model, false, "isLoaded", "loaded", "ready", "active");
					bool chatCompletion = ReadWorkstationModelCapabilityBool(model, true, "chat_completion", "chatCompletion");
					if (!includeAll && (!chatCompletion || (!enabled && !dynamicLoadEnabled && !loaded)))
					{
						skipped++;
						continue;
					}
					if (written >= take)
					{
						skipped++;
						continue;
					}
					writer.WriteStartObject();
					writer.WriteString("id", id);
					writer.WriteString("name", FirstNonEmpty(ReadWorkstationModelString(model, "display_name", "displayName", "name"), id));
					writer.WriteString("type", FirstNonEmpty(ReadWorkstationModelString(model, "type", "model_type", "modelType"), "llm"));
					string service = ReadWorkstationModelString(model, "service", "chat_service", "chatService");
					if (!string.IsNullOrWhiteSpace(service))
					{
						writer.WriteString("service", service);
					}
					writer.WriteBoolean("isLoaded", loaded);
					writer.WriteBoolean("enabled", enabled);
					writer.WriteBoolean("dynamicLoadEnabled", dynamicLoadEnabled);
					writer.WriteBoolean("chatCompletion", chatCompletion);
					string description = ReadWorkstationModelString(model, "description");
					if (!string.IsNullOrWhiteSpace(description))
					{
						writer.WriteString("description", TruncateForLog(description, 240));
					}
					writer.WriteEndObject();
					written++;
				}
				writer.WriteEndArray();
				writer.WriteNumber("returned", written);
				writer.WriteNumber("skipped", skipped);
				writer.WriteBoolean("includeAll", includeAll);
				writer.WriteString("note", "Use workstation_run_model with an enabled chat-capable model id. Loading is allowed only for enabled Web Chat dynamic-load models unless the global Workstation model-load API is enabled.");
				writer.WriteEndObject();
			}
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch
		{
			return TruncateForLog(responseBody, 24000);
		}
	}

	private string ReadWorkstationModelString(JsonElement model, params string[] names)
	{
		foreach (string name in names ?? Array.Empty<string>())
		{
			string value = ReadJsonString(GetPropertyOrNull(model, name));
			if (!string.IsNullOrWhiteSpace(value))
			{
				return value;
			}
		}
		return "";
	}

	private bool ReadWorkstationModelBool(JsonElement model, bool fallback, params string[] names)
	{
		foreach (string name in names ?? Array.Empty<string>())
		{
			JsonElement? value = GetPropertyOrNull(model, name);
			if (value.HasValue)
			{
				return ReadJsonBool(value.Value, fallback);
			}
		}
		return fallback;
	}

	private bool ReadWorkstationModelCapabilityBool(JsonElement model, bool fallback, params string[] names)
	{
		if (model.ValueKind == JsonValueKind.Object && model.TryGetProperty("capabilities", out var capabilities) && capabilities.ValueKind == JsonValueKind.Object)
		{
			foreach (string name in names ?? Array.Empty<string>())
			{
				JsonElement? value = GetPropertyOrNull(capabilities, name);
				if (value.HasValue)
				{
					return ReadJsonBool(value.Value, fallback);
				}
			}
		}
		return ReadWorkstationModelBool(model, fallback, names);
	}

	private async Task<string> ExecuteWorkstationRunModelToolAsync(string argumentsJson)
	{
		try
		{
			string body = string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson;
			using JsonDocument document = JsonDocument.Parse(body);
			JsonElement root = document.RootElement;
			string model = FirstNonEmpty(ExtractStringProperty(root, "model"), ExtractStringProperty(root, "modelId"), ExtractStringProperty(root, "model_id"), ExtractStringProperty(root, "id"));
			string prompt = FirstNonEmpty(ExtractStringProperty(root, "prompt"), ExtractStringProperty(root, "message"), ExtractStringProperty(root, "input"), ExtractStringProperty(root, "text"));
			string systemPrompt = FirstNonEmpty(ExtractStringProperty(root, "systemPrompt"), ExtractStringProperty(root, "system_prompt"), ExtractStringProperty(root, "instructions"));
			if (string.IsNullOrWhiteSpace(model) || string.IsNullOrWhiteSpace(prompt))
			{
				return "workstation_run_model error: model and prompt are required.";
			}
			model = model.Trim();
			prompt = prompt.Trim();
			int maxTokens = Math.Max(64, Math.Min(8192, ExtractIntFromToolArguments(body, "maxTokens", ExtractIntFromToolArguments(body, "max_tokens", 2048))));
			double? temperature = ClampWorkstationRunModelNumber(ExtractJsonDoubleProperty(root, "temperature"), 0.0, 2.0);
			double? topP = ClampWorkstationRunModelNumber(ExtractJsonDoubleProperty(root, "topP") ?? ExtractJsonDoubleProperty(root, "top_p"), 0.0, 1.0);
			if (!CanForwardWebChatModelLoad(JsonSerializer.Serialize(new { model }), out var blockedModel, out var blockedReason))
			{
				return "workstation_run_model blocked: " + blockedReason;
			}
			bool loadedNow = false;
			bool loadedBefore = false;
			using (IDisposable modelUse = BeginWebChatRuntimeModelUse(model))
			{
				await EnsureLmStudioForPromptAsync().ConfigureAwait(continueOnCapturedContext: false);
				if (IsEffectiveLocalRuntimeLlmRuntime())
				{
					loadedBefore = await IsWebChatRuntimeModelLoadedAsync(model, CancellationToken.None).ConfigureAwait(continueOnCapturedContext: false);
					if (!loadedBefore)
					{
						await LoadWebChatRuntimeModelAsync(model, CancellationToken.None).ConfigureAwait(continueOnCapturedContext: false);
						loadedNow = true;
					}
				}
				string requestBody = BuildWorkstationRunModelChatCompletionRequestBody(model, prompt, systemPrompt, maxTokens, temperature, topP);
				string url = CombineOpenAiUpstreamUrl(BuildLocalModelRuntimeBaseUrl(), "/v1/chat/completions");
				LogMessage("[Workstation Model Tool] Running delegated model '" + model + "' via " + GetLocalModelRuntimeDisplayName() + ".");
				using CancellationTokenSource timeout = new CancellationTokenSource(TimeSpan.FromMinutes(5.0));
				using StringContent content = new StringContent(requestBody, Encoding.UTF8, "application/json");
				using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Post, url);
				request.Content = content;
				using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseContentRead, timeout.Token).ConfigureAwait(continueOnCapturedContext: false);
				string responseBody = response.Content == null ? "" : await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false);
				if (!response.IsSuccessStatusCode)
				{
					return "workstation_run_model failed: " + GetLocalModelRuntimeDisplayName() + " returned HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + TruncateForLog(responseBody, 1000);
				}
				if (ResponseBodyContainsJsonError(responseBody))
				{
					return "workstation_run_model failed: " + TruncateForLog(responseBody, 1000);
				}
				ChatUiCompletion completion = ExtractChatUiCompletionFromChatCompletion(responseBody);
				completion.Raw = responseBody;
				NoteWebChatRuntimeModelUsed(model);
				return JsonSerializer.Serialize(new
				{
					ok = true,
					service = "workstation_model",
					runtime = GetLocalModelRuntimeDisplayName(),
					model,
					loadedBefore,
					loadedNow,
					maxTokens,
					content = TruncateForLog(completion.Content ?? "", 16000),
					reasoning = TruncateForLog(completion.Reasoning ?? "", 8000),
					finishReason = completion.FinishReason ?? "",
					rawResponse = string.IsNullOrWhiteSpace(completion.Content) && string.IsNullOrWhiteSpace(completion.Reasoning) ? TruncateForLog(responseBody, 4000) : ""
				});
			}
		}
		catch (JsonException ex)
		{
			return "workstation_run_model error: invalid arguments JSON: " + ex.Message;
		}
		catch (Exception ex)
		{
			return "workstation_run_model failed: " + ex.Message;
		}
	}

	private string BuildWorkstationRunModelChatCompletionRequestBody(string model, string prompt, string systemPrompt, int maxTokens, double? temperature, double? topP)
	{
		using MemoryStream stream = new MemoryStream();
		using (Utf8JsonWriter writer = new Utf8JsonWriter(stream))
		{
			writer.WriteStartObject();
			writer.WriteString("model", model ?? "");
			writer.WriteBoolean("stream", value: false);
			writer.WriteNumber("max_tokens", Math.Max(64, Math.Min(8192, maxTokens)));
			if (temperature.HasValue)
			{
				writer.WriteNumber("temperature", temperature.Value);
			}
			if (topP.HasValue)
			{
				writer.WriteNumber("top_p", topP.Value);
			}
			writer.WritePropertyName("messages");
			writer.WriteStartArray();
			if (!string.IsNullOrWhiteSpace(systemPrompt))
			{
				writer.WriteStartObject();
				writer.WriteString("role", "system");
				writer.WriteString("content", systemPrompt.Trim());
				writer.WriteEndObject();
			}
			writer.WriteStartObject();
			writer.WriteString("role", "user");
			writer.WriteString("content", prompt ?? "");
			writer.WriteEndObject();
			writer.WriteEndArray();
			writer.WriteEndObject();
		}
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private double? ClampWorkstationRunModelNumber(double? value, double min, double max)
	{
		if (!value.HasValue || double.IsNaN(value.Value) || double.IsInfinity(value.Value))
		{
			return null;
		}
		return Math.Max(min, Math.Min(max, value.Value));
	}

	private void LogProxyResearchToolStart(string toolName, string argumentsJson)
	{
		string query = ExtractJsonStringProperty(argumentsJson, "query");
		string packageId = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "packageId"), ExtractJsonStringProperty(argumentsJson, "id"));
		string label = FirstNonEmpty(query, packageId);
		LogMessage("[Internet Search] " + (string.IsNullOrWhiteSpace(toolName) ? "research tool" : toolName) + (string.IsNullOrWhiteSpace(label) ? "" : (" started for \"" + TruncateForLog(label, 120) + "\"")) + ".");
	}

	private void LogProxyResearchToolCompleted(string toolName, string result)
	{
		bool failed = !string.IsNullOrWhiteSpace(result) && result.IndexOf(" error:", StringComparison.OrdinalIgnoreCase) >= 0;
		LogMessage("[Internet Search] " + (string.IsNullOrWhiteSpace(toolName) ? "research tool" : toolName) + (failed ? " returned an error" : " completed") + "; resultLength=" + (result ?? "").Length.ToString(CultureInfo.InvariantCulture) + ".");
	}

	private async Task<string> ExecuteSockJackDmlToolAsync(string toolName, string argumentsJson, string ownerKey, string sessionId)
	{
		try
		{
			ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
			sessionId = EnsureChatUiSessionId(sessionId);
			ChatPermissionState permissions = GetChatPermissions(ownerKey);
			if (permissions == null || !permissions.agentAccess)
			{
				return toolName + " blocked: Agent access is required for SockJackDml workflow tools.";
			}
			string name = (toolName ?? "").Trim().ToLowerInvariant();
			string body = (string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson);
			switch (name)
			{
			case "sockjackdml_plan_create":
			{
				MagicPlanCreateRequest request5 = _sockJackDmlWorkflows.ReadPlanCreateRequest(body);
				MagicPlanCreateResult result5 = _sockJackDmlWorkflows.CreateOrUpdatePlan(ownerKey, sessionId, request5);
				result5.SessionCompatibility = BuildChatSessionCompatibilityPayload(ownerKey, sessionId, ChatModel, "SockJackDml", -1L, 0L);
				RecordObservabilityEvent("sockjack-dml", "plan " + (result5.NeedsInput ? "needs-input" : "ready"), result5.Status, result5.FeatureName, ownerKey, "sockjackdml_plan_create", 0L);
				return _sockJackDmlWorkflows.Serialize(result5);
			}
			case "sockjackdml_progress_document_create":
			{
				MagicProgressDocumentRequest request2 = _sockJackDmlWorkflows.ReadProgressDocumentRequest(body);
				MagicProgressDocumentResult result2 = _sockJackDmlWorkflows.CreateOrUpdateProgress(ownerKey, sessionId, request2);
				ApplyMagicProgressDocumentWrite(result2, ownerKey, sessionId, permissions);
				result2.SessionCompatibility = BuildChatSessionCompatibilityPayload(ownerKey, sessionId, ChatModel, "SockJackDml", -1L, 0L);
				RecordObservabilityEvent("sockjack-dml", "progress document", result2.DocumentWritten ? "written" : "state-only", result2.ProgressFileName, ownerKey, "sockjackdml_progress_document_create", 0L);
				return _sockJackDmlWorkflows.Serialize(result2);
			}
			case "sockjackdml_plan_execute":
			{
				MagicPlanExecutionRequest request7 = _sockJackDmlWorkflows.ReadPlanExecutionRequest(body);
				MagicPlanExecutionResult result7 = await _sockJackDmlWorkflows.ExecutePlanAsync(ownerKey, sessionId, request7, (MagicPlanExecutionAction action) => ExecuteMagicPlanActionAsync(action, ownerKey, sessionId, permissions)).ConfigureAwait(continueOnCapturedContext: false);
				ApplyMagicProgressDocumentWrite(result7.Progress, ownerKey, sessionId, permissions);
				result7.SessionCompatibility = BuildChatSessionCompatibilityPayload(ownerKey, sessionId, ChatModel, "SockJackDml", -1L, 0L);
				if (result7.Progress != null)
				{
					result7.Progress.SessionCompatibility = result7.SessionCompatibility;
				}
				RecordObservabilityEvent("sockjack-dml", "plan execution", result7.Status, result7.PlanId, ownerKey, "sockjackdml_plan_execute", 0L);
				return _sockJackDmlWorkflows.Serialize(result7);
			}
			case "sockjackdml_workflow_status":
			{
				MagicWorkflowStatusRequest request4 = _sockJackDmlWorkflows.ReadWorkflowStatusRequest(body);
				MagicWorkflowStatusResult result4 = _sockJackDmlWorkflows.GetWorkflowStatus(ownerKey, sessionId, request4);
				RecordObservabilityEvent("sockjack-dml", "workflow status", result4.LatestStatus, result4.NextAction, ownerKey, "sockjackdml_workflow_status", 0L);
				return _sockJackDmlWorkflows.Serialize(result4);
			}
			case "sockjackdml_progress_document_find":
			{
				MagicProgressFindRequest request6 = _sockJackDmlWorkflows.ReadProgressFindRequest(body);
				MagicProgressFindResult result6 = _sockJackDmlWorkflows.FindProgressDocument(ownerKey, sessionId, request6);
				RecordObservabilityEvent("sockjack-dml", "progress find", result6.Ok ? "found" : "missing", result6.ProgressFileName, ownerKey, "sockjackdml_progress_document_find", 0L);
				return _sockJackDmlWorkflows.Serialize(result6);
			}
			case "sockjackdml_execution_control":
			{
				MagicExecutionControlRequest request3 = _sockJackDmlWorkflows.ReadExecutionControlRequest(body);
				MagicExecutionControlResult result3 = _sockJackDmlWorkflows.ControlExecution(ownerKey, sessionId, request3);
				RecordObservabilityEvent("sockjack-dml", "execution control", result3.Status, result3.ExecutionId, ownerKey, "sockjackdml_execution_control", 0L);
				return _sockJackDmlWorkflows.Serialize(result3);
			}
			case "sockjackdml_evidence_link":
			{
				MagicEvidenceLinkRequest request = _sockJackDmlWorkflows.ReadEvidenceLinkRequest(body);
				MagicEvidencePacket packet = null;
				if (string.IsNullOrWhiteSpace(request.EvidencePacketId) && string.IsNullOrWhiteSpace(request.PacketId))
				{
					packet = _sockJackDml.CreateEvidencePacket(ownerKey, "", FirstNonEmpty(request.Title, "SockJackDml workflow evidence"), FirstNonEmpty(request.Summary, "Workflow evidence linked from execution state."), FirstNonEmpty(request.SourceKind, "workflow"), request.SourceRef, FirstNonEmpty(request.ContentType, "text/markdown"), FirstNonEmpty(request.Classification, "private"), new List<string>());
					request.EvidencePacketId = packet.Id;
				}
				MagicEvidenceLinkResult result = _sockJackDmlWorkflows.LinkEvidence(ownerKey, sessionId, request);
				RecordObservabilityEvent("sockjack-dml", "evidence link", result.Created ? "created" : "updated", request.EvidencePacketId, ownerKey, "sockjackdml_evidence_link", 0L);
				return _sockJackDmlWorkflows.Serialize(new
				{
					ok = result.Ok,
					ownerKey = ownerKey,
					sessionId = sessionId,
					created = result.Created,
					error = result.Error,
					packet = packet,
					link = result.Link,
					updatedUtc = result.UpdatedUtc,
					storagePath = result.StoragePath
				});
			}
			default:
				return "Unknown SockJackDml workflow tool: " + toolName;
			}
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			LogMessage("[SockJackDml Tools] " + toolName + " failed: " + ex2);
			return toolName + " failed: " + ex2.Message;
		}
	}

	private void ApplyMagicProgressDocumentWrite(MagicProgressDocumentResult result, string ownerKey, string sessionId, ChatPermissionState permissions)
	{
		if (result != null)
		{
			string targetPath = (result.ProgressPath = ResolveMagicProgressDocumentPath(result, ownerKey, sessionId));
			_sockJackDmlWorkflows.UpdateProgressDocumentPath(ownerKey, result.ProgressId, targetPath);
			if (string.IsNullOrWhiteSpace(result.Markdown))
			{
				result.DocumentWritten = false;
				result.DocumentWriteResult = "progress document not written: rendered markdown was empty.";
			}
			else if (permissions == null || !permissions.vsCopilotTools)
			{
				result.DocumentWritten = false;
				result.DocumentWriteResult = "progress document state was saved, but markdown file writing is blocked because VS Copilot Tools permission is disabled.";
			}
			else
			{
				string writeArguments = JsonSerializer.Serialize(new
				{
					path = targetPath,
					content = result.Markdown,
					overwrite = true
				});
				string writeResult = (result.DocumentWriteResult = ExecuteVsWriteFile(writeArguments, ownerKey, sessionId));
				result.DocumentWritten = !string.IsNullOrWhiteSpace(writeResult) && writeResult.StartsWith("vs_write_file wrote ", StringComparison.OrdinalIgnoreCase);
			}
		}
	}

	private string ResolveMagicProgressDocumentPath(MagicProgressDocumentResult result, string ownerKey, string sessionId)
	{
		if (result == null)
		{
			return "";
		}
		string requestedPath = FirstNonEmpty(result.ProgressPath);
		if (!string.IsNullOrWhiteSpace(requestedPath))
		{
			return requestedPath;
		}
		string fileName = (string.IsNullOrWhiteSpace(result.ProgressFileName) ? SockJackDmlWorkflowService.SanitizeProgressFileName(result.ProjectOrSessionName, result.FeatureName) : result.ProgressFileName);
		foreach (string sessionRoot in GetChatAgentSessionRoots(sessionId, ensureExists: true))
		{
			if (!string.IsNullOrWhiteSpace(sessionRoot))
			{
				return Path.Combine(sessionRoot, fileName);
			}
		}
		foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(ownerKey))
		{
			if (entry != null && entry.exists && !string.IsNullOrWhiteSpace(entry.path) && Directory.Exists(entry.path))
			{
				return Path.Combine(entry.path, fileName);
			}
		}
		return fileName;
	}

	private async Task<MagicPlanActionResult> ExecuteMagicPlanActionAsync(MagicPlanExecutionAction action, string ownerKey, string sessionId, ChatPermissionState permissions)
	{
		action = action ?? new MagicPlanExecutionAction();
		string type = FirstNonEmpty(action.Type, action.Kind, action.ToolName).Trim().ToLowerInvariant();
		string summary = FirstNonEmpty(action.Summary, action.Description, type);
		if (string.IsNullOrWhiteSpace(type) || type == "progress" || type == "note")
		{
			string output = "Progress-only action acknowledged.";
			return BuildMagicActionResult(action, summary, "completed", output);
		}
		if (type == "write_file" || type == "create_file" || type == "vs_write_file")
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return BuildMagicActionResult(action, summary, "blocked", "VS Copilot Tools permission is disabled.");
			}
			string output = ExecuteVsWriteFile(FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				path = action.Path,
				content = action.Content,
				overwrite = action.Overwrite
			})), ownerKey, sessionId);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		if (type == "replace_in_file" || type == "edit_file" || type == "vs_replace_in_file")
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return BuildMagicActionResult(action, summary, "blocked", "VS Copilot Tools permission is disabled.");
			}
			string output = ExecuteVsReplaceInFile(FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				path = action.Path,
				oldString = action.OldString,
				newString = action.NewString,
				replaceAll = action.ReplaceAll
			})), ownerKey, sessionId);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		if (type == "copy_file" || type == "vs_copy_file")
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return BuildMagicActionResult(action, summary, "blocked", "VS Copilot Tools permission is disabled.");
			}
			string output = ExecuteProxyVsTool("vs_copy_file", FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				path = action.Path,
				newPath = action.NewPath,
				overwrite = action.Overwrite
			})), ownerKey, sessionId);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		if (type == "rename_file" || type == "move_file" || type == "vs_rename_file")
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return BuildMagicActionResult(action, summary, "blocked", "VS Copilot Tools permission is disabled.");
			}
			string output = ExecuteProxyVsTool("vs_rename_file", FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				path = action.Path,
				newPath = action.NewPath,
				newName = action.NewName,
				overwrite = action.Overwrite
			})), ownerKey, sessionId);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		if (type == "delete_file" || type == "vs_delete_file")
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return BuildMagicActionResult(action, summary, "blocked", "VS Copilot Tools permission is disabled.");
			}
			string output = ExecuteProxyVsTool("vs_delete_file", FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				path = action.Path
			})), ownerKey, sessionId);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		if (IsProxyOwnedVsTool(type))
		{
			if (permissions == null || !permissions.vsCopilotTools)
			{
				return BuildMagicActionResult(action, summary, "blocked", "VS Copilot Tools permission is disabled.");
			}
			string output = ExecuteProxyVsTool(type, FirstNonEmpty(action.ArgumentsJson, "{}"), ownerKey, sessionId);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		if (type == "git" || IsProxyOwnedGitTool(type))
		{
			if (permissions == null || !permissions.agentAccess)
			{
				return BuildMagicActionResult(action, summary, "blocked", "Agent access is required for Git tools.");
			}
			if (!IsGitCliAvailable())
			{
				return BuildMagicActionResult(action, summary, "blocked", "Git CLI was not detected.");
			}
			string gitTool = (IsProxyOwnedGitTool(type) ? type : FirstNonEmpty(action.ToolName, string.IsNullOrWhiteSpace(action.Operation) ? "git_status" : ("git_" + action.Operation.Trim().ToLowerInvariant().Replace("-", "_"))));
			string output = await ExecuteGitToolAsync(gitTool, FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				workingDirectory = action.WorkingDirectory,
				path = action.Path,
				timeoutMs = action.TimeoutMs
			})), ownerKey, sessionId, permissions).ConfigureAwait(continueOnCapturedContext: false);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		int num;
		switch (type)
		{
		default:
			num = ((type == "run_command_in_terminal") ? 1 : 0);
			break;
		case "terminal":
		case "command":
		case "shell":
			num = 1;
			break;
		}
		if (num != 0)
		{
			if (permissions == null || !permissions.terminalCommands)
			{
				return BuildMagicActionResult(action, summary, "blocked", "Terminal Commands permission is disabled.");
			}
			string output = await ExecuteTerminalCommandToolAsync("run_command_in_terminal", FirstNonEmpty(action.ArgumentsJson, JsonSerializer.Serialize(new
			{
				command = action.Command,
				summary = summary,
				workingDirectory = action.WorkingDirectory,
				shell = action.Shell,
				timeoutMs = action.TimeoutMs
			})), ownerKey).ConfigureAwait(continueOnCapturedContext: false);
			return BuildMagicActionResult(action, summary, ClassifyMagicToolOutput(output), output);
		}
		return BuildMagicActionResult(action, summary, "blocked", "Unsupported SockJackDml execution action type: " + type);
	}

	private static MagicPlanActionResult BuildMagicActionResult(MagicPlanExecutionAction action, string summary, string status, string output)
	{
		MagicPlanActionResult magicPlanActionResult = new MagicPlanActionResult();
		magicPlanActionResult.ActionId = FirstNonEmpty((action == null) ? "" : action.Id, (action == null) ? "" : action.StepId);
		magicPlanActionResult.Type = FirstNonEmpty((action == null) ? "" : action.Type, (action == null) ? "" : action.Kind, (action == null) ? "" : action.ToolName);
		magicPlanActionResult.Summary = summary ?? "";
		magicPlanActionResult.Status = (string.IsNullOrWhiteSpace(status) ? "failed" : status);
		magicPlanActionResult.Output = output ?? "";
		magicPlanActionResult.CompletedUtc = DateTimeOffset.UtcNow.ToString("O");
		return magicPlanActionResult;
	}

	private static string ClassifyMagicToolOutput(string output)
	{
		string text = (output ?? "").Trim();
		if (text.Length == 0)
		{
			return "failed";
		}
		if (text.IndexOf(" blocked:", StringComparison.OrdinalIgnoreCase) >= 0 || text.StartsWith("blocked:", StringComparison.OrdinalIgnoreCase))
		{
			return "blocked";
		}
		if (text.IndexOf(" error:", StringComparison.OrdinalIgnoreCase) >= 0 || text.StartsWith("error:", StringComparison.OrdinalIgnoreCase) || text.StartsWith("failed:", StringComparison.OrdinalIgnoreCase) || text.IndexOf(" failed:", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			return "failed";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(text);
			if (document.RootElement.ValueKind == JsonValueKind.Object)
			{
				if (document.RootElement.TryGetProperty("ok", out var ok) && ok.ValueKind == JsonValueKind.False)
				{
					return "failed";
				}
				if (document.RootElement.TryGetProperty("exitCode", out var exitCode) && exitCode.ValueKind == JsonValueKind.Number && exitCode.TryGetInt32(out var code) && code != 0)
				{
					return "failed";
				}
			}
		}
		catch
		{
		}
		return "completed";
	}

	private async Task<string> ExecuteGitToolAsync(string toolName, string argumentsJson, string ownerKey, string sessionId, ChatPermissionState permissions)
	{
		try
		{
			if (!TryBuildGitCommandRequest(toolName, argumentsJson, ownerKey, sessionId, out var gitRequest, out var requestError))
			{
				return toolName + " error: " + requestError;
			}
			if (_gitService.IsMutating(gitRequest))
			{
				string requestOwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
				TerminalPermissionDecision decision = await QueueTerminalPermissionRequestAsync(requestOwnerKey, new TerminalCommandRequest
				{
					Command = _gitService.BuildApprovalCommand(gitRequest),
					Shell = "git",
					WorkingDirectory = gitRequest.WorkingDirectory,
					Summary = "Approve Git tool: " + toolName,
					TimeoutMs = ((gitRequest.TimeoutMs <= 0) ? 120000 : gitRequest.TimeoutMs)
				}, CancellationToken.None).ConfigureAwait(continueOnCapturedContext: false);
				if (!decision.Approved)
				{
					return toolName + " blocked: " + (string.IsNullOrWhiteSpace(decision.Reason) ? "Git operation was not approved." : decision.Reason);
				}
			}
			GitCommandResult result = await _gitService.ExecuteAsync(gitRequest, CancellationToken.None).ConfigureAwait(continueOnCapturedContext: false);
			LogMessage("[Git Service] " + toolName + " for " + NormalizeChatFilesystemOwnerKey(ownerKey) + " command=" + result.Command + " exit=" + result.ExitCode.ToString(CultureInfo.InvariantCulture) + " repo=" + result.RepositoryRoot);
			return JsonSerializer.Serialize(new
			{
				ok = result.Ok,
				service = "git",
				operation = result.Operation,
				command = result.Command,
				workingDirectory = result.WorkingDirectory,
				repositoryRoot = result.RepositoryRoot,
				exitCode = result.ExitCode,
				timedOut = result.TimedOut,
				canceled = result.Canceled,
				gitAvailable = result.GitAvailable,
				destructiveBlocked = result.DestructiveBlocked,
				durationMs = result.DurationMs,
				stdout = (result.Output ?? ""),
				stderr = (result.Error ?? "")
			}, new JsonSerializerOptions
			{
				WriteIndented = true
			});
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			LogMessage("[Git Service] " + toolName + " failed: " + ex2);
			return toolName + " failed: " + ex2.Message;
		}
	}

	private bool TryBuildGitCommandRequest(string toolName, string argumentsJson, string ownerKey, string sessionId, out GitCommandRequest request, out string error)
	{
		request = null;
		error = null;
		string operation = NormalizeGitToolOperation(toolName);
		string requestedWorkingDirectory = ExtractJsonStringProperty(argumentsJson, "workingDirectory") ?? ExtractJsonStringProperty(argumentsJson, "cwd") ?? ExtractJsonStringProperty(argumentsJson, "repositoryRoot") ?? ExtractJsonStringProperty(argumentsJson, "repoRoot");
		if (!TryResolveGitWorkingDirectory(requestedWorkingDirectory, ownerKey, sessionId, out var workingDirectory, out error))
		{
			return false;
		}
		List<string> allowedRoots = (from root in GetChatAgentAllowedRoots(ownerKey, sessionId)
			where !string.IsNullOrWhiteSpace(root) && Directory.Exists(root)
			select root).Select(delegate(string root)
		{
			try
			{
				return Path.GetFullPath(root);
			}
			catch
			{
				return root;
			}
		}).Distinct<string>(StringComparer.OrdinalIgnoreCase).ToList();
		request = new GitCommandRequest
		{
			Operation = operation,
			WorkingDirectory = workingDirectory,
			AllowedRoots = allowedRoots,
			PathSpecs = ExtractGitPathSpecs(argumentsJson),
			Path = (ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "file") ?? ExtractJsonStringProperty(argumentsJson, "filePath") ?? ""),
			Query = (ExtractJsonStringProperty(argumentsJson, "query") ?? ExtractJsonStringProperty(argumentsJson, "pattern") ?? ExtractJsonStringProperty(argumentsJson, "search") ?? ""),
			Ref = (ExtractJsonStringProperty(argumentsJson, "ref") ?? ExtractJsonStringProperty(argumentsJson, "revision") ?? ExtractJsonStringProperty(argumentsJson, "commit") ?? ExtractJsonStringProperty(argumentsJson, "sha") ?? ""),
			Branch = (ExtractJsonStringProperty(argumentsJson, "branch") ?? ExtractJsonStringProperty(argumentsJson, "branchName") ?? ExtractJsonStringProperty(argumentsJson, "name") ?? ""),
			Message = (ExtractJsonStringProperty(argumentsJson, "message") ?? ExtractJsonStringProperty(argumentsJson, "commitMessage") ?? ""),
			Remote = (ExtractJsonStringProperty(argumentsJson, "remote") ?? ""),
			Staged = ExtractBoolFromToolArguments(argumentsJson, "staged", ExtractBoolFromToolArguments(argumentsJson, "cached", fallback: false)),
			Stat = ExtractBoolFromToolArguments(argumentsJson, "stat", fallback: false),
			IncludePatch = ExtractBoolFromToolArguments(argumentsJson, "includePatch", fallback: false),
			IncludeUntracked = ExtractBoolFromToolArguments(argumentsJson, "includeUntracked", fallback: true),
			Checkout = ExtractBoolFromToolArguments(argumentsJson, "checkout", fallback: true),
			SetUpstream = ExtractBoolFromToolArguments(argumentsJson, "setUpstream", fallback: false),
			StartLine = ExtractIntFromToolArguments(argumentsJson, "startLine", 0),
			EndLine = ExtractIntFromToolArguments(argumentsJson, "endLine", 0),
			Take = ExtractIntFromToolArguments(argumentsJson, "take", ExtractIntFromToolArguments(argumentsJson, "count", 20)),
			TimeoutMs = ExtractIntFromToolArguments(argumentsJson, "timeoutMs", 120000)
		};
		return true;
	}

	private string NormalizeGitToolOperation(string toolName)
	{
		string name = (toolName ?? "").Trim().ToLowerInvariant();
		if (name.StartsWith("git_", StringComparison.Ordinal))
		{
			name = name.Substring(4);
		}
		if (string.IsNullOrWhiteSpace(name))
		{
			return "status";
		}
		return name.Replace("-", "_");
	}

	private bool TryResolveGitWorkingDirectory(string requestedWorkingDirectory, string ownerKey, string sessionId, out string workingDirectory, out string error)
	{
		workingDirectory = null;
		error = null;
		if (!string.IsNullOrWhiteSpace(requestedWorkingDirectory))
		{
			return TryResolveChatAgentDirectoryPath(requestedWorkingDirectory, ownerKey, sessionId, out workingDirectory, out error);
		}
		foreach (string root in GetChatAgentAllowedRoots(ownerKey, sessionId))
		{
			if (string.IsNullOrWhiteSpace(root) || !Directory.Exists(root))
			{
				continue;
			}
			try
			{
				string fullRoot = Path.GetFullPath(root);
				if (Directory.Exists(Path.Combine(fullRoot, ".git")))
				{
					workingDirectory = fullRoot;
					return true;
				}
			}
			catch
			{
			}
		}
		foreach (string root2 in GetChatAgentAllowedRoots(ownerKey, sessionId))
		{
			if (!string.IsNullOrWhiteSpace(root2) && Directory.Exists(root2))
			{
				try
				{
					workingDirectory = Path.GetFullPath(root2);
					return true;
				}
				catch
				{
				}
			}
		}
		error = "no authorized session or accessible filesystem root is available for Git.";
		return false;
	}

	private List<string> ExtractGitPathSpecs(string argumentsJson)
	{
		List<string> paths = new List<string>();
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			return paths;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			AddGitPathSpecsFromElement(document.RootElement, "paths", paths);
			AddGitPathSpecsFromElement(document.RootElement, "pathSpecs", paths);
			AddGitPathSpecsFromElement(document.RootElement, "files", paths);
			AddGitPathSpecsFromElement(document.RootElement, "filePaths", paths);
			string single = ExtractStringProperty(document.RootElement, "path") ?? ExtractStringProperty(document.RootElement, "file") ?? ExtractStringProperty(document.RootElement, "filePath");
			if (!string.IsNullOrWhiteSpace(single))
			{
				paths.Add(single);
			}
		}
		catch
		{
			string single2 = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "file") ?? ExtractJsonStringProperty(argumentsJson, "filePath");
			if (!string.IsNullOrWhiteSpace(single2))
			{
				paths.Add(single2);
			}
		}
		return paths.Where((string path) => !string.IsNullOrWhiteSpace(path)).Distinct<string>(StringComparer.OrdinalIgnoreCase).ToList();
	}

	private void AddGitPathSpecsFromElement(JsonElement root, string propertyName, List<string> paths)
	{
		if (paths == null || root.ValueKind != JsonValueKind.Object || !root.TryGetProperty(propertyName, out var element))
		{
			return;
		}
		if (element.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement item in element.EnumerateArray())
			{
				if (item.ValueKind == JsonValueKind.String)
				{
					string value = item.GetString();
					if (!string.IsNullOrWhiteSpace(value))
					{
						paths.Add(value);
					}
				}
			}
			return;
		}
		if (element.ValueKind == JsonValueKind.String)
		{
			string value2 = element.GetString();
			if (!string.IsNullOrWhiteSpace(value2))
			{
				paths.Add(value2);
			}
		}
	}

	private async Task<string> ExecuteTerminalCommandToolAsync(string toolName, string argumentsJson, string ownerKey)
	{
		try
		{
			TerminalCommandRequest commandRequest = BuildTerminalCommandRequest(toolName, argumentsJson);
			if (string.IsNullOrWhiteSpace(commandRequest.Command))
			{
				return "run_command_in_terminal error: command is required.";
			}
			string requestOwnerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
			TerminalPermissionDecision decision = await QueueTerminalPermissionRequestAsync(requestOwnerKey, commandRequest, CancellationToken.None);
			if (!decision.Approved)
			{
				return "run_command_in_terminal blocked: " + (string.IsNullOrWhiteSpace(decision.Reason) ? "command was not approved." : decision.Reason);
			}
			TerminalCommandResult result = await _terminalService.ExecuteAsync(commandRequest, CancellationToken.None);
			bool ok = result.ExitCode == 0 && !result.TimedOut && !result.Canceled;
			LogMessage("[Terminal Service] Ran command for " + requestOwnerKey + ": " + commandRequest.Command + " (exit " + result.ExitCode.ToString(CultureInfo.InvariantCulture) + ").");
			return JsonSerializer.Serialize(new
			{
				ok = ok,
				service = "terminal",
				command = result.Command,
				shell = result.Shell,
				workingDirectory = result.WorkingDirectory,
				exitCode = result.ExitCode,
				timedOut = result.TimedOut,
				canceled = result.Canceled,
				durationMs = result.DurationMs,
				stdout = (result.Output ?? ""),
				stderr = (result.Error ?? "")
			}, new JsonSerializerOptions
			{
				WriteIndented = true
			});
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			LogMessage("[Terminal Service] " + toolName + " failed: " + ex2);
			return "run_command_in_terminal failed: " + ex2.Message;
		}
	}

	private TerminalCommandRequest BuildTerminalCommandRequest(string toolName, string argumentsJson)
	{
		string command = ExtractJsonStringProperty(argumentsJson, "command") ?? ExtractJsonStringProperty(argumentsJson, "script") ?? ExtractJsonStringProperty(argumentsJson, "subcommand") ?? ExtractJsonStringProperty(argumentsJson, "input") ?? ExtractJsonStringProperty(argumentsJson, "args") ?? ExtractJsonStringProperty(argumentsJson, "arguments") ?? "";
		if (!IsRunCommandTerminalToolName(toolName))
		{
			command = BuildDirectTerminalCommand(toolName, command, argumentsJson);
		}
		string workingDirectory = ExtractJsonStringProperty(argumentsJson, "workingDirectory") ?? ExtractJsonStringProperty(argumentsJson, "cwd") ?? "";
		return new TerminalCommandRequest
		{
			Command = NormalizeTerminalCommand(RepairDecodedWindowsPathEscapesInText(command)),
			Summary = (ExtractJsonStringProperty(argumentsJson, "summary") ?? ExtractJsonStringProperty(argumentsJson, "reason") ?? ""),
			WorkingDirectory = NormalizeLoosePathEscapes(workingDirectory),
			Shell = (ExtractJsonStringProperty(argumentsJson, "shell") ?? InferTerminalShell(toolName)),
			TimeoutMs = ExtractIntFromToolArguments(argumentsJson, "timeoutMs", 120000)
		};
	}

	private bool IsRunCommandTerminalToolName(string toolName)
	{
		if (string.IsNullOrWhiteSpace(toolName))
		{
			return false;
		}
		string name = toolName.Trim().ToLowerInvariant();
		int result;
		switch (name)
		{
		default:
			result = ((name == "command") ? 1 : 0);
			break;
		case "run_command_in_terminal":
		case "terminal_command":
		case "shell":
		case "powershell":
		case "pwsh":
		case "cmd":
			result = 1;
			break;
		}
		return (byte)result != 0;
	}

	private string BuildDirectTerminalCommand(string toolName, string command, string argumentsJson)
	{
		string executable = (toolName ?? "").Trim();
		if (string.IsNullOrWhiteSpace(executable))
		{
			return command ?? "";
		}
		string fixedArguments = GetDirectTerminalFixedArguments(executable);
		if (!string.IsNullOrWhiteSpace(fixedArguments))
		{
			executable = "dotnet";
		}
		command = (command ?? "").Trim();
		if (command.StartsWith(executable + " ", StringComparison.OrdinalIgnoreCase) || command.Equals(executable, StringComparison.OrdinalIgnoreCase))
		{
			return command;
		}
		if (!string.IsNullOrWhiteSpace(fixedArguments) && (command.StartsWith(fixedArguments + " ", StringComparison.OrdinalIgnoreCase) || command.Equals(fixedArguments, StringComparison.OrdinalIgnoreCase)))
		{
			return executable + " " + command;
		}
		if (string.IsNullOrWhiteSpace(command))
		{
			string joinedArgs = ExtractJsonStringArrayAsCommandText(argumentsJson, "args");
			if (string.IsNullOrWhiteSpace(joinedArgs))
			{
				joinedArgs = ExtractJsonStringArrayAsCommandText(argumentsJson, "arguments");
			}
			command = joinedArgs;
		}
		string prefix = (string.IsNullOrWhiteSpace(fixedArguments) ? executable : (executable + " " + fixedArguments));
		return string.IsNullOrWhiteSpace(command) ? prefix : (prefix + " " + command);
	}

	private string GetDirectTerminalFixedArguments(string toolName)
	{
		switch ((toolName ?? "").Trim().ToLowerInvariant())
		{
		case "dotnet_build":
		case "dotnet-build":
			return "build";
		case "dotnet_test":
		case "dotnet-test":
			return "test";
		case "dotnet_restore":
		case "dotnet-restore":
			return "restore";
		case "dotnet_run":
		case "dotnet-run":
			return "run";
		case "dotnet_publish":
		case "dotnet-publish":
			return "publish";
		case "dotnet_pack":
		case "dotnet-pack":
			return "pack";
		case "dotnet_clean":
		case "dotnet-clean":
			return "clean";
		case "dotnet_format":
		case "dotnet-format":
			return "format";
		default:
			return "";
		}
	}

	private string ExtractJsonStringArrayAsCommandText(string argumentsJson, string propertyName)
	{
		if (string.IsNullOrWhiteSpace(argumentsJson) || string.IsNullOrWhiteSpace(propertyName))
		{
			return "";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			if (!document.RootElement.TryGetProperty(propertyName, out var value) || value.ValueKind != JsonValueKind.Array)
			{
				return "";
			}
			List<string> parts = new List<string>();
			foreach (JsonElement item in value.EnumerateArray())
			{
				if (item.ValueKind == JsonValueKind.String)
				{
					parts.Add(item.GetString() ?? "");
				}
				else
				{
					parts.Add(item.ToString());
				}
			}
			return string.Join(" ", parts).Trim();
		}
		catch
		{
			return "";
		}
	}

	private string InferTerminalShell(string toolName)
	{
		if (string.IsNullOrWhiteSpace(toolName))
		{
			return "powershell";
		}
		string name = toolName.Trim().ToLowerInvariant();
		if (name == "cmd")
		{
			return "cmd";
		}
		if (name == "pwsh")
		{
			return "pwsh";
		}
		return "powershell";
	}

	private string ExecuteProxyVsTool(string toolName, string argumentsJson, string ownerKey, string sessionId)
	{
		try
		{
			if (toolName.Equals("read_file", StringComparison.Ordinal) || toolName.Equals("vs_read_file", StringComparison.Ordinal))
			{
				return ExecuteVsReadFile(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_write_file", StringComparison.Ordinal))
			{
				return ExecuteVsWriteFile(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_replace_in_file", StringComparison.Ordinal))
			{
				return ExecuteVsReplaceInFile(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_copy_file", StringComparison.Ordinal))
			{
				return ExecuteVsCopyFile(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_rename_file", StringComparison.Ordinal))
			{
				return ExecuteVsRenameFile(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_delete_file", StringComparison.Ordinal))
			{
				return ExecuteVsDeleteFile(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_search_files", StringComparison.Ordinal))
			{
				return ExecuteVsSearchFiles(argumentsJson, ownerKey, sessionId);
			}
			if (toolName.Equals("vs_list_files", StringComparison.Ordinal))
			{
				return ExecuteVsListFiles(argumentsJson, ownerKey, sessionId);
			}
			return "Unknown VS agent tool: " + toolName;
		}
		catch (Exception ex)
		{
			LogMessage("[VS Agent Tool] " + toolName + " failed: " + ex);
			return toolName + " failed: " + ex.Message;
		}
	}

	private void WriteChatAgentTextFile(string fullPath, string content, string ownerKey, string sessionId, string kind)
	{
		if (IsJackLlmSessionManagedPath(fullPath))
		{
			WriteChatSessionFileBytesToSandbox(sessionId, ownerKey, fullPath, Encoding.UTF8.GetBytes(content ?? ""), kind, out var _);
			return;
		}
		File.WriteAllText(fullPath, content ?? "", Encoding.UTF8);
	}

	private bool ExistingTextFileMatchesContent(string fullPath, string content, string ownerKey, string sessionId)
	{
		try
		{
			if (IsJackLlmSessionManagedPath(fullPath) && TryReadChatSessionSandboxTextFile(sessionId, ownerKey, fullPath, out var sandboxText))
			{
				return string.Equals(sandboxText, content ?? "", StringComparison.Ordinal);
			}
			return File.Exists(fullPath) && string.Equals(File.ReadAllText(fullPath), content ?? "", StringComparison.Ordinal);
		}
		catch
		{
			return false;
		}
	}

	private bool IsGeneratedChatSessionFile(string sessionId, string ownerKey, string fullPath)
	{
		if (string.IsNullOrWhiteSpace(sessionId) || string.IsNullOrWhiteSpace(fullPath) || !IsPathInsideRoot(fullPath, _chatSessionFilesRoot))
		{
			return false;
		}
		string normalizedPath;
		try
		{
			normalizedPath = Path.GetFullPath(fullPath);
		}
		catch
		{
			return false;
		}
		string normalizedOwner = NormalizeChatFilesystemOwnerKey(ownerKey);
		lock (_chatSessionLock)
		{
			Table table = GetChatSessionsTable();
			for (int i = 0; i < table.Rows.Count; i++)
			{
				object[] row = NormalizeChatSessionRow(table.Rows[i]);
				if (!string.Equals(GetRowValue(row, 0), sessionId, StringComparison.Ordinal))
				{
					continue;
				}
				if (!string.IsNullOrWhiteSpace(normalizedOwner) && !ChatOwnerKeysMatch(normalizedOwner, GetRowValue(row, 7)))
				{
					continue;
				}
				List<ChatSessionFile> files = new List<ChatSessionFile>();
				AddChatSessionFilesFromJson(files, new HashSet<string>(StringComparer.OrdinalIgnoreCase), GetChatSessionPrivateValue(row, 6, "files", "[]", normalizedOwner));
				foreach (ChatSessionFile file in files)
				{
					if (file == null || string.IsNullOrWhiteSpace(file.path) || !PathsEqual(file.path, normalizedPath))
					{
						continue;
					}
					string id = file.id ?? "";
					return id.StartsWith("generated_", StringComparison.OrdinalIgnoreCase) || id.StartsWith("generated-media_", StringComparison.OrdinalIgnoreCase);
				}
			}
		}
		return false;
	}

	private string ExecuteVsReadFile(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "filename") ?? ExtractJsonStringProperty(argumentsJson, "filePath");
		path = MaterializeRemoteSessionFilePathForTool("vs_read_file", path, ownerKey, sessionId);
		if (!TryResolveChatAgentFilePath(path, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullPath, out var error))
		{
			return "vs_read_file error: " + error;
		}
		int startLine = ExtractIntFromToolArguments(argumentsJson, "startLine", 1);
		int endLine = ExtractIntFromToolArguments(argumentsJson, "endLine", startLine + 240);
		bool includeLineNumbers = ExtractBoolFromToolArguments(argumentsJson, "includeLineNumbers", fallback: true);
		if (startLine < 1)
		{
			startLine = 1;
		}
		if (endLine < startLine)
		{
			endLine = startLine;
		}
		string fileText;
		string displayPath = FormatChatAgentPathForOutput(fullPath, sessionId);
		if (IsJackLlmSessionManagedPath(fullPath))
		{
			if (!TryReadChatSessionSandboxTextFile(sessionId, ownerKey, fullPath, out fileText))
			{
				return "vs_read_file error: sandbox file does not exist: " + displayPath;
			}
		}
		else
		{
			fileText = File.ReadAllText(fullPath);
		}
		string[] lines = fileText.Replace("\r\n", "\n").Replace('\r', '\n').Split('\n');
		if (lines.Length == 0)
		{
			return "```" + GetMarkdownLanguageForPath(fullPath) + " " + displayPath + " (0 lines total)\n```";
		}
		if (endLine > lines.Length)
		{
			endLine = lines.Length;
		}
		StringBuilder sb = new StringBuilder();
		sb.Append("```").Append(GetMarkdownLanguageForPath(fullPath)).Append(" ")
			.Append(displayPath)
			.Append(" (Lines ")
			.Append(startLine.ToString())
			.Append("-")
			.Append(endLine.ToString())
			.Append(" of ")
			.Append(lines.Length.ToString())
			.Append(" total.)\n");
		for (int lineNumber = startLine; lineNumber <= endLine; lineNumber++)
		{
			if (includeLineNumbers)
			{
				sb.Append(lineNumber.ToString()).Append(": ");
			}
			sb.Append(lines[lineNumber - 1]).Append("\n");
		}
		sb.Append("```");
		return sb.ToString();
	}

	private string ExecuteVsWriteFile(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "filePath") ?? ExtractJsonStringProperty(argumentsJson, "filename");
		string content = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "content") ?? "");
		bool overwrite = ExtractBoolFromToolArguments(argumentsJson, "overwrite", fallback: false);
		path = MaterializeRemoteSessionFilePathForTool("vs_write_file", path, ownerKey, sessionId);
		if (!TryResolveChatAgentFilePath(path, ownerKey, sessionId, mustExist: false, sessionOnly: false, out var fullPath, out var error))
		{
			return "vs_write_file error: " + error;
		}
		bool managedSessionPath = IsJackLlmSessionManagedPath(fullPath);
		bool fileExists = managedSessionPath ? ChatSessionSandboxFileExists(sessionId, ownerKey, fullPath) : File.Exists(fullPath);
		bool refreshedGeneratedFile = false;
		if (fileExists && !overwrite)
		{
			if (ExistingTextFileMatchesContent(fullPath, content, ownerKey, sessionId))
			{
				RegisterChatSessionFileIfTracked(sessionId, ownerKey, fullPath, "generated");
				return "vs_write_file skipped write because identical content already exists at " + FormatChatAgentPathForOutput(fullPath, sessionId) + ".";
			}
			if (IsGeneratedChatSessionFile(EnsureChatUiSessionId(sessionId), ownerKey, fullPath))
			{
				overwrite = true;
				refreshedGeneratedFile = true;
			}
			else
			{
				return "vs_write_file blocked: file already exists. Re-run with overwrite=true after reading the file if overwrite is intended: " + FormatChatAgentPathForOutput(fullPath, sessionId);
			}
		}
		long existingBytes = 0L;
		try
		{
			if (managedSessionPath && TryGetChatSessionSandboxFileEntry(sessionId, ownerKey, fullPath, out var existingEntry))
			{
				existingBytes = Math.Max(0L, existingEntry.Length);
			}
			else
			{
				existingBytes = (File.Exists(fullPath) ? Math.Max(0L, new FileInfo(fullPath).Length) : 0);
			}
		}
		catch
		{
		}
		long nextBytes = Encoding.UTF8.GetByteCount(content ?? "");
		if (IsPathInsideRoot(fullPath, _chatSessionFilesRoot) && !EnsureChatStorageCanAdd(ownerKey, sessionId, Math.Max(0L, nextBytes - existingBytes), out var _, out var storageError))
		{
			return "vs_write_file blocked: " + storageError;
		}
		string directory = Path.GetDirectoryName(fullPath);
		if (!managedSessionPath && !string.IsNullOrWhiteSpace(directory))
		{
			Directory.CreateDirectory(directory);
		}
		if (!managedSessionPath)
		{
			CaptureChatFileUndoBeforeChange(fullPath, File.Exists(fullPath) ? "modified" : "created");
		}
		WriteChatAgentTextFile(fullPath, content ?? "", ownerKey, sessionId, "generated-file");
		RegisterChatSessionFileIfTracked(sessionId, ownerKey, fullPath, "generated");
		return "vs_write_file wrote " + (content ?? "").Length + " chars to " + FormatChatAgentPathForOutput(fullPath, sessionId) + (refreshedGeneratedFile ? " (refreshed existing generated session file)." : ".");
	}

	private string ExecuteVsReplaceInFile(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "filePath") ?? ExtractJsonStringProperty(argumentsJson, "filename");
		string oldString = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "oldString") ?? "");
		string newString = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "newString") ?? "");
		bool replaceAll = ExtractBoolFromToolArguments(argumentsJson, "replaceAll", fallback: false);
		if (string.IsNullOrEmpty(oldString))
		{
			return "vs_replace_in_file error: oldString is required.";
		}
		path = MaterializeRemoteSessionFilePathForTool("vs_replace_in_file", path, ownerKey, sessionId);
		if (!TryResolveChatAgentFilePath(path, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullPath, out var error))
		{
			return "vs_replace_in_file error: " + error;
		}
		string existing;
		bool managedReplacePath = IsJackLlmSessionManagedPath(fullPath);
		if (managedReplacePath)
		{
			if (!TryReadChatSessionSandboxTextFile(sessionId, ownerKey, fullPath, out existing))
			{
				return "vs_replace_in_file error: sandbox file does not exist: " + FormatChatAgentPathForOutput(fullPath, sessionId);
			}
		}
		else
		{
			existing = File.ReadAllText(fullPath);
		}
		if (!existing.Contains(oldString))
		{
			string normalizedExisting = existing.Replace("\r\n", "\n").Replace('\r', '\n');
			string normalizedOld = oldString.Replace("\r\n", "\n").Replace('\r', '\n');
			if (!normalizedExisting.Contains(normalizedOld))
			{
				return "vs_replace_in_file found no exact match in " + FormatChatAgentPathForOutput(fullPath, sessionId) + ". Read the relevant lines and retry with exact text.";
			}
			oldString = (existing.Contains(oldString.Replace("\n", "\r\n")) ? oldString.Replace("\n", "\r\n") : oldString);
		}
		int replacements = ((!replaceAll) ? 1 : CountOccurrences(existing, oldString));
		string updated = (replaceAll ? existing.Replace(oldString, newString) : ReplaceFirst(existing, oldString, newString));
		if (string.Equals(existing, updated, StringComparison.Ordinal))
		{
			return "vs_replace_in_file made no changes to " + FormatChatAgentPathForOutput(fullPath, sessionId) + ".";
		}
		long existingBytes = 0L;
		try
		{
			if (managedReplacePath && TryGetChatSessionSandboxFileEntry(sessionId, ownerKey, fullPath, out var existingEntry))
			{
				existingBytes = Math.Max(0L, existingEntry.Length);
			}
			else
			{
				existingBytes = (File.Exists(fullPath) ? Math.Max(0L, new FileInfo(fullPath).Length) : Encoding.UTF8.GetByteCount(existing ?? ""));
			}
		}
		catch
		{
		}
		long nextBytes = Encoding.UTF8.GetByteCount(updated ?? "");
		if (IsPathInsideRoot(fullPath, _chatSessionFilesRoot) && !EnsureChatStorageCanAdd(ownerKey, sessionId, Math.Max(0L, nextBytes - existingBytes), out var _, out var storageError))
		{
			return "vs_replace_in_file blocked: " + storageError;
		}
		if (!managedReplacePath)
		{
			CaptureChatFileUndoBeforeChange(fullPath, "modified");
		}
		WriteChatAgentTextFile(fullPath, updated, ownerKey, sessionId, "generated-file-replace");
		RegisterChatSessionFileIfTracked(sessionId, ownerKey, fullPath, "generated");
		return "vs_replace_in_file applied " + replacements + " replacement(s) to " + FormatChatAgentPathForOutput(fullPath, sessionId) + ".";
	}

	private string ExecuteVsRenameFile(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "oldPath") ?? ExtractJsonStringProperty(argumentsJson, "sourcePath") ?? ExtractJsonStringProperty(argumentsJson, "filePath") ?? ExtractJsonStringProperty(argumentsJson, "filename");
		string newPath = ExtractJsonStringProperty(argumentsJson, "newPath") ?? ExtractJsonStringProperty(argumentsJson, "destinationPath") ?? ExtractJsonStringProperty(argumentsJson, "targetPath");
		string newName = ExtractJsonStringProperty(argumentsJson, "newName") ?? ExtractJsonStringProperty(argumentsJson, "name");
		bool overwrite = ExtractBoolFromToolArguments(argumentsJson, "overwrite", fallback: false);
		path = MaterializeRemoteSessionFilePathForTool("vs_rename_file", path, ownerKey, sessionId);
		if (!TryResolveChatAgentFilePath(path, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var sourceFullPath, out var sourceError))
		{
			return "vs_rename_file error: " + sourceError;
		}
		if (string.IsNullOrWhiteSpace(newPath) && !string.IsNullOrWhiteSpace(newName))
		{
			newPath = Path.Combine(Path.GetDirectoryName(sourceFullPath) ?? "", newName.Trim().Trim('"', '\'', ',', ' '));
		}
		if (string.IsNullOrWhiteSpace(newPath))
		{
			return "vs_rename_file error: newPath or newName is required.";
		}
		if (!TryResolveChatAgentFilePath(newPath, ownerKey, sessionId, mustExist: false, sessionOnly: false, out var targetFullPath, out var targetError))
		{
			return "vs_rename_file error: " + targetError;
		}
		if (PathsEqual(sourceFullPath, targetFullPath))
		{
			return "vs_rename_file made no changes because source and target are the same: " + FormatChatAgentPathForOutput(sourceFullPath, sessionId);
		}
		bool sourceManaged = IsJackLlmSessionManagedPath(sourceFullPath);
		bool targetManaged = IsJackLlmSessionManagedPath(targetFullPath);
		if (sourceManaged && !targetManaged)
		{
			return "vs_rename_file blocked: virtual session files cannot be moved to raw disk paths.";
		}
		long sourceBytes = GetChatAgentFileLength(sessionId, ownerKey, sourceFullPath);
		long targetExistingBytes = GetChatAgentFileLength(sessionId, ownerKey, targetFullPath);
		if (targetManaged && !sourceManaged && !EnsureChatStorageCanAdd(ownerKey, sessionId, Math.Max(0L, sourceBytes - targetExistingBytes), out var _, out var storageError))
		{
			return "vs_rename_file blocked: " + storageError;
		}
		bool targetExists = ChatAgentFileExists(sessionId, ownerKey, targetFullPath);
		if (targetExists)
		{
			if (!overwrite)
			{
				return "vs_rename_file blocked: target already exists. Re-run with overwrite=true if replacing it is intended: " + FormatChatAgentPathForOutput(targetFullPath, sessionId);
			}
		}
		CaptureChatFileUndoBeforeChange(sourceFullPath, "deleted");
		CaptureChatFileUndoBeforeChange(targetFullPath, targetExists ? "modified" : "created");
		if (sourceManaged || targetManaged)
		{
			byte[] bytes = sourceManaged
				? (TryReadChatSessionSandboxFileBytes(sessionId, ownerKey, sourceFullPath, out var sandboxBytes) ? sandboxBytes : Array.Empty<byte>())
				: File.ReadAllBytes(sourceFullPath);
			if (targetExists && targetManaged)
			{
				TryDeleteChatSessionSandboxFile(sessionId, ownerKey, targetFullPath);
			}
			WriteChatSessionFileBytesToSandbox(sessionId, ownerKey, targetFullPath, bytes, "generated-file-rename", out var _);
			if (sourceManaged)
			{
				TryDeleteChatSessionSandboxFile(sessionId, ownerKey, sourceFullPath);
			}
			else
			{
				File.Delete(sourceFullPath);
			}
		}
		else
		{
			if (targetExists)
			{
				File.Delete(targetFullPath);
			}
			string directory = Path.GetDirectoryName(targetFullPath);
			if (!string.IsNullOrWhiteSpace(directory))
			{
				Directory.CreateDirectory(directory);
			}
			File.Move(sourceFullPath, targetFullPath);
		}
		RegisterChatSessionFileIfTracked(sessionId, ownerKey, targetFullPath, "generated");
		return "vs_rename_file moved " + FormatChatAgentPathForOutput(sourceFullPath, sessionId) + " to " + FormatChatAgentPathForOutput(targetFullPath, sessionId) + ".";
	}

	private string ExecuteVsCopyFile(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "sourcePath") ?? ExtractJsonStringProperty(argumentsJson, "filePath") ?? ExtractJsonStringProperty(argumentsJson, "filename");
		string newPath = ExtractJsonStringProperty(argumentsJson, "newPath") ?? ExtractJsonStringProperty(argumentsJson, "destinationPath") ?? ExtractJsonStringProperty(argumentsJson, "targetPath");
		string newName = ExtractJsonStringProperty(argumentsJson, "newName") ?? ExtractJsonStringProperty(argumentsJson, "name");
		bool overwrite = ExtractBoolFromToolArguments(argumentsJson, "overwrite", fallback: false);
		path = MaterializeRemoteSessionFilePathForTool("vs_copy_file", path, ownerKey, sessionId);
		if (!TryResolveChatAgentFilePath(path, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var sourceFullPath, out var sourceError))
		{
			return "vs_copy_file error: " + sourceError;
		}
		if (string.IsNullOrWhiteSpace(newPath) && !string.IsNullOrWhiteSpace(newName))
		{
			newPath = Path.Combine(Path.GetDirectoryName(sourceFullPath) ?? "", newName.Trim().Trim('"', '\'', ',', ' '));
		}
		if (string.IsNullOrWhiteSpace(newPath))
		{
			return "vs_copy_file error: newPath or newName is required.";
		}
		if (!TryResolveChatAgentFilePath(newPath, ownerKey, sessionId, mustExist: false, sessionOnly: false, out var targetFullPath, out var targetError))
		{
			return "vs_copy_file error: " + targetError;
		}
		if (PathsEqual(sourceFullPath, targetFullPath))
		{
			return "vs_copy_file made no changes because source and target are the same: " + FormatChatAgentPathForOutput(sourceFullPath, sessionId);
		}
		bool sourceManaged = IsJackLlmSessionManagedPath(sourceFullPath);
		bool targetManaged = IsJackLlmSessionManagedPath(targetFullPath);
		if (sourceManaged && !targetManaged)
		{
			return "vs_copy_file blocked: virtual session files cannot be copied to raw disk paths.";
		}
		bool targetExists = ChatAgentFileExists(sessionId, ownerKey, targetFullPath);
		if (targetExists && !overwrite)
		{
			return "vs_copy_file blocked: target already exists. Re-run with overwrite=true if replacing it is intended: " + FormatChatAgentPathForOutput(targetFullPath, sessionId);
		}
		long sourceBytes = GetChatAgentFileLength(sessionId, ownerKey, sourceFullPath);
		long targetExistingBytes = GetChatAgentFileLength(sessionId, ownerKey, targetFullPath);
		if (targetManaged && !EnsureChatStorageCanAdd(ownerKey, sessionId, Math.Max(0L, sourceBytes - targetExistingBytes), out var _, out var storageError))
		{
			return "vs_copy_file blocked: " + storageError;
		}
		CaptureChatFileUndoBeforeChange(targetFullPath, targetExists ? "modified" : "created");
		if (targetManaged)
		{
			byte[] bytes = sourceManaged
				? (TryReadChatSessionSandboxFileBytes(sessionId, ownerKey, sourceFullPath, out var sandboxBytes) ? sandboxBytes : Array.Empty<byte>())
				: File.ReadAllBytes(sourceFullPath);
			WriteChatSessionFileBytesToSandbox(sessionId, ownerKey, targetFullPath, bytes, "generated-file-copy", out var _);
		}
		else
		{
			string directory = Path.GetDirectoryName(targetFullPath);
			if (!string.IsNullOrWhiteSpace(directory))
			{
				Directory.CreateDirectory(directory);
			}
			File.Copy(sourceFullPath, targetFullPath, overwrite);
		}
		RegisterChatSessionFileIfTracked(sessionId, ownerKey, targetFullPath, "generated");
		return "vs_copy_file copied " + FormatChatAgentPathForOutput(sourceFullPath, sessionId) + " to " + FormatChatAgentPathForOutput(targetFullPath, sessionId) + ".";
	}

	private string ExecuteVsDeleteFile(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path") ?? ExtractJsonStringProperty(argumentsJson, "filePath") ?? ExtractJsonStringProperty(argumentsJson, "filename");
		if (!TryResolveChatAgentFilePath(path, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullPath, out var error))
		{
			return "vs_delete_file error: " + error;
		}
		if (TryCreateChatSessionFileFromPath(fullPath, "deleted", out var deletedFile))
		{
			LogChatStorageFileEvent("deleted", ownerKey, sessionId, deletedFile);
		}
		CaptureChatFileUndoBeforeChange(fullPath, "deleted");
		if (IsJackLlmSessionManagedPath(fullPath))
		{
			TryDeleteChatSessionSandboxFile(sessionId, ownerKey, fullPath);
		}
		else
		{
			File.Delete(fullPath);
		}
		return "vs_delete_file deleted " + FormatChatAgentPathForOutput(fullPath, sessionId) + ".";
	}

	private string ExecuteVsSearchFiles(string argumentsJson, string ownerKey, string sessionId)
	{
		string query = ExtractJsonStringProperty(argumentsJson, "query") ?? ExtractJsonStringProperty(argumentsJson, "searchQuery") ?? "";
		string path = ExtractJsonStringProperty(argumentsJson, "path");
		int take = ExtractIntFromToolArguments(argumentsJson, "take", 30);
		take = Math.Max(1, Math.Min(100, take));
		if (string.IsNullOrWhiteSpace(query))
		{
			return "vs_search_files error: query is required.";
		}
		List<string> roots = ResolveChatAgentSearchRoots(path, ownerKey, sessionId);
		List<string> results = new List<string>();
		foreach (string root in roots)
		{
			SearchFilesInRoot(root, query, take, results, ownerKey, sessionId);
			if (results.Count >= take)
			{
				break;
			}
		}
		if (results.Count == 0)
		{
			return "vs_search_files found no results for: " + query;
		}
		return "vs_search_files results for \"" + query + "\":\n" + string.Join("\n", results);
	}

	private string ExecuteVsListFiles(string argumentsJson, string ownerKey, string sessionId)
	{
		string path = ExtractJsonStringProperty(argumentsJson, "path");
		bool recursive = ExtractBoolFromToolArguments(argumentsJson, "recursive", fallback: false);
		int take = ExtractIntFromToolArguments(argumentsJson, "take", 100);
		take = Math.Max(1, Math.Min(500, take));
		List<string> roots;
		if (string.IsNullOrWhiteSpace(path))
		{
			roots = GetChatAgentAllowedRoots(ownerKey, sessionId);
		}
		else
		{
			if (!TryResolveChatAgentDirectoryPath(path, ownerKey, sessionId, out var normalized, out var error))
			{
				return "vs_list_files error: " + error;
			}
			roots = new List<string> { normalized };
		}
		List<string> results = new List<string>();
		foreach (string root in roots)
		{
			ListFilesInRoot(root, recursive, take, results, ownerKey, sessionId);
			if (results.Count >= take)
			{
				break;
			}
		}
		if (results.Count == 0)
		{
			return "vs_list_files found no files.";
		}
		return "vs_list_files:\n" + string.Join("\n", results);
	}

	private string MaterializeRemoteSessionFilePathForTool(string toolName, string requestedPath, string ownerKey, string sessionId)
	{
		return MaterializeRemoteSessionFilePathForToolAsync(toolName, requestedPath, ownerKey, sessionId).GetAwaiter().GetResult();
	}

	private async Task<string> MaterializeRemoteSessionFilePathForToolAsync(string toolName, string requestedPath, string ownerKey, string sessionId)
	{
		if (!RemoteSessionFileCloningEnabled || string.IsNullOrWhiteSpace(requestedPath) || toolName.Equals("vs_delete_file", StringComparison.Ordinal))
		{
			return requestedPath;
		}
		if (!TryBuildRemoteSessionFileCloneRequest(toolName, requestedPath, ownerKey, sessionId, out var remoteUri, out var remotePath, out var localPath, out var fileName))
		{
			return requestedPath;
		}
		sessionId = EnsureChatUiSessionId(sessionId);
		string id = "remote_" + ComputeStableTextHash(remoteUri.AbsoluteUri + "|" + sessionId).Substring(0, 16);
		CancellationTokenSource cancellation = new CancellationTokenSource();
		RemoteSessionFileCloneRecord record;
		lock (_remoteSessionFileCloneLock)
		{
			if (!_remoteSessionFileClones.TryGetValue(id, out record))
			{
				record = new RemoteSessionFileCloneRecord
				{
					Id = id,
					StartedUtc = DateTimeOffset.UtcNow
				};
				_remoteSessionFileClones[id] = record;
			}
			if (_remoteSessionFileCloneCancellations.TryGetValue(id, out var existingCancellation))
			{
				try
				{
					existingCancellation.Cancel();
				}
				catch
				{
				}
				try
				{
					existingCancellation.Dispose();
				}
				catch
				{
				}
			}
			record.RemotePath = remotePath;
			record.RemoteUrl = remoteUri.AbsoluteUri;
			record.LocalPath = localPath;
			record.FileName = fileName;
			record.SessionId = sessionId ?? "";
			record.OwnerKey = ownerKey ?? "";
			record.Status = "Downloading";
			record.Bytes = 0L;
			record.Sha256 = "";
			record.Error = "";
			record.Canceled = false;
			record.ChangedLocally = false;
			record.UpdatedUtc = DateTimeOffset.UtcNow;
			_remoteSessionFileCloneCancellations[id] = cancellation;
		}
		NotifyRemoteSessionFileCloneChanged(record);
		try
		{
			byte[] clonedBytes = await DownloadRemoteSessionFileCloneAsync(remoteUri, ownerKey, sessionId, cancellation.Token, record);
			cancellation.Token.ThrowIfCancellationRequested();
			long total = clonedBytes.LongLength;
			string sandboxSessionId;
			SandboxFileEntry sandboxEntry = WriteChatSessionFileBytesToSandbox(sessionId, ownerKey, localPath, clonedBytes, "remote-session-clone", out sandboxSessionId);
			string hash = FirstNonEmpty(sandboxEntry.Sha256, ComputeBytesSha256(clonedBytes));
			DateTimeOffset lastWriteUtc = DateTimeOffset.UtcNow;
			lock (_remoteSessionFileCloneLock)
			{
				record.Status = "Complete";
				record.Bytes = total;
				record.Sha256 = hash;
				record.LastWriteUtc = lastWriteUtc;
				record.SandboxSessionId = sandboxSessionId;
				record.SandboxFileId = sandboxEntry.Id ?? "";
				record.SandboxPath = sandboxEntry.Path ?? "";
				record.UpdatedUtc = DateTimeOffset.UtcNow;
				record.Error = "";
				record.Canceled = false;
				_remoteSessionFileCloneCancellations.Remove(id);
			}
			ChatSessionFile clonedFile = new ChatSessionFile
			{
				id = "remoteclone_" + Guid.NewGuid().ToString("N"),
				name = fileName,
				type = GetChatFileDownloadMimeType(Path.GetExtension(fileName)),
				size = (int)((total > int.MaxValue) ? int.MaxValue : total),
				path = localPath,
				uploadedUtc = DateTimeOffset.UtcNow.ToString("O")
			};
			AttachSandboxMetadata(sessionId, ownerKey, clonedFile, sandboxEntry, sandboxSessionId);
			RegisterChatSessionFile(sessionId, ownerKey, clonedFile);
			NotifyRemoteSessionFileCloneChanged(record);
			LogMessage("[Copilot Duplicator Files] Cloned " + remotePath + " -> virtual session file " + localPath + " (" + total.ToString(CultureInfo.InvariantCulture) + " bytes).");
			return localPath;
		}
		catch (OperationCanceledException)
		{
			lock (_remoteSessionFileCloneLock)
			{
				record.Status = "Canceled";
				record.Canceled = true;
				record.Error = "Canceled by user.";
				record.UpdatedUtc = DateTimeOffset.UtcNow;
				_remoteSessionFileCloneCancellations.Remove(id);
			}
			NotifyRemoteSessionFileCloneChanged(record);
			throw new InvalidOperationException("remote session file clone canceled: " + remotePath);
		}
		catch (Exception ex2)
		{
			Exception ex3 = ex2;
			lock (_remoteSessionFileCloneLock)
			{
				record.Status = "Failed";
				record.Error = ex3.Message;
				record.UpdatedUtc = DateTimeOffset.UtcNow;
				_remoteSessionFileCloneCancellations.Remove(id);
			}
			NotifyRemoteSessionFileCloneChanged(record);
			throw new InvalidOperationException("remote session file clone failed for " + remotePath + ": " + ex3.Message);
		}
		finally
		{
			try
			{
				cancellation.Dispose();
			}
			catch
			{
			}
		}
	}

	private async Task<byte[]> DownloadRemoteSessionFileCloneAsync(Uri remoteUri, string ownerKey, string sessionId, CancellationToken cancellationToken, RemoteSessionFileCloneRecord record)
	{
		using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, remoteUri);
		request.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-CopilotDuplicator/1.0");
		request.Headers.TryAddWithoutValidation("Accept", "application/octet-stream, text/plain;q=0.9, */*;q=0.8");
		AddRemoteSelectionAuthorizationHeader(GetRemoteModelServerSelection(), request);
		using HttpResponseMessage response = await _httpClient.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, cancellationToken);
		if (!response.IsSuccessStatusCode)
		{
			throw new InvalidOperationException(((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + response.ReasonPhrase);
		}
		long? contentLength = response.Content?.Headers?.ContentLength;
		if (contentLength.HasValue && contentLength.Value > 104857600)
		{
			throw new InvalidOperationException("remote file is larger than the 100 MB clone limit.");
		}
		if (contentLength.HasValue && !EnsureChatStorageCanAdd(ownerKey, sessionId, contentLength.Value, out var snapshot, out var contentLengthStorageError))
		{
			throw new InvalidOperationException(contentLengthStorageError);
		}
		long total = 0L;
		byte[] buffer = new byte[81920];
		using MemoryStream output = new MemoryStream();
		using (Stream input = await response.Content.ReadAsStreamAsync())
		{
			while (true)
			{
				cancellationToken.ThrowIfCancellationRequested();
				int read = await input.ReadAsync(buffer, 0, buffer.Length, cancellationToken);
				if (read <= 0)
				{
					break;
				}
				total += read;
				if (total > 104857600)
				{
					throw new InvalidOperationException("remote file exceeded the 100 MB clone limit.");
				}
				if (!EnsureChatStorageCanAdd(ownerKey, sessionId, total, out snapshot, out var streamStorageError))
				{
					throw new InvalidOperationException(streamStorageError);
				}
				await output.WriteAsync(buffer, 0, read, cancellationToken);
				UpdateRemoteSessionFileCloneProgress(record, total);
				streamStorageError = null;
			}
		}
		return output.ToArray();
	}

	private bool TryBuildRemoteSessionFileCloneRequest(string toolName, string requestedPath, string ownerKey, string sessionId, out Uri remoteUri, out string remotePath, out string localPath, out string fileName)
	{
		remoteUri = null;
		remotePath = "";
		localPath = "";
		fileName = "";
		string cleaned = NormalizeLoosePathEscapes(requestedPath).Trim().Trim('"', '\'', ',', ' ');
		if (cleaned.Length == 0)
		{
			return false;
		}
		if (toolName.Equals("vs_write_file", StringComparison.Ordinal))
		{
			return false;
		}
		if (TryResolveAuthorizedExistingChatAgentFilePath(cleaned, ownerKey, sessionId, out var _))
		{
			return false;
		}
		LmVsProxyRemoteModelServerSelection selection = GetRemoteModelServerSelection();
		if (Uri.TryCreate(cleaned, UriKind.Absolute, out Uri directUri) && (directUri.Scheme == Uri.UriSchemeHttp || directUri.Scheme == Uri.UriSchemeHttps))
		{
			remoteUri = directUri;
			remotePath = cleaned;
			fileName = GetRemoteSessionFileName(cleaned, directUri);
			localPath = BuildRemoteSessionCloneLocalPath(selection, directUri, cleaned, sessionId, fileName);
			return true;
		}
		if (!selection.Enabled)
		{
			return false;
		}
		string endpoint = (string.IsNullOrWhiteSpace(selection.Endpoint) ? selection.OpenAiBaseUrl : selection.Endpoint);
		endpoint = LmVsProxyRemoteModelServerSelection.NormalizeOpenAiBaseUrl(endpoint);
		if (endpoint.Length == 0)
		{
			return false;
		}
		string downloadUrl = endpoint.TrimEnd('/') + "/api/chat-file-download?path=" + Uri.EscapeDataString(cleaned) + "&kind=session";
		if (!string.IsNullOrWhiteSpace(sessionId))
		{
			downloadUrl = downloadUrl + "&sessionId=" + Uri.EscapeDataString(sessionId);
		}
		if (!Uri.TryCreate(downloadUrl, UriKind.Absolute, out remoteUri))
		{
			return false;
		}
		remotePath = cleaned;
		fileName = GetRemoteSessionFileName(cleaned, null);
		localPath = BuildRemoteSessionCloneLocalPath(selection, remoteUri, cleaned, sessionId, fileName);
		return true;
	}

	private bool TryResolveAuthorizedExistingChatAgentFilePath(string requestedPath, string ownerKey, string sessionId, out string fullPath)
	{
		fullPath = null;
		try
		{
			string cleaned = NormalizeChatAgentRequestedPath(requestedPath);
			List<string> roots = GetChatAgentAllowedRoots(ownerKey, sessionId);
			if (Path.IsPathRooted(cleaned))
			{
				string candidate = Path.GetFullPath(cleaned);
				if ((File.Exists(candidate) || ChatSessionSandboxFileExists(sessionId, ownerKey, candidate)) && IsPathUnderAnyRoot(candidate, roots) && !IsFilesystemPathDenied(ownerKey, candidate))
				{
					fullPath = candidate;
					return true;
				}
				return false;
			}
			foreach (string root in roots)
			{
				string candidate2 = Path.GetFullPath(Path.Combine(root, cleaned));
				if ((File.Exists(candidate2) || ChatSessionSandboxFileExists(sessionId, ownerKey, candidate2)) && IsPathInsideRoot(candidate2, root))
				{
					fullPath = candidate2;
					return true;
				}
			}
		}
		catch
		{
		}
		return false;
	}

	private string BuildRemoteSessionCloneLocalPath(LmVsProxyRemoteModelServerSelection selection, Uri remoteUri, string remotePath, string sessionId, string fileName)
	{
		string sessionRoot = GetRemoteSessionCloneDirectory(sessionId);
		string relativePath = BuildRemoteSessionCloneRelativePath(remotePath, remoteUri, fileName);
		string candidate = Path.GetFullPath(Path.Combine(sessionRoot, relativePath));
		if (!IsPathInsideRoot(candidate, sessionRoot))
		{
			candidate = Path.Combine(sessionRoot, ComputeStableTextHash(remotePath + "|" + remoteUri.AbsoluteUri).Substring(0, 12), SanitizeFileName(fileName));
		}
		return candidate;
	}

	private string BuildRemoteSessionCloneRelativePath(string remotePath, Uri uri, string fileName)
	{
		string path = remotePath ?? "";
		if (uri != null)
		{
			string queryPath = ExtractSimpleQueryValue(uri.Query, "path");
			if (!string.IsNullOrWhiteSpace(queryPath))
			{
				path = queryPath;
			}
			else if (!string.IsNullOrWhiteSpace(uri.LocalPath))
			{
				path = uri.LocalPath;
			}
		}
		path = WebUtility.UrlDecode(NormalizeLoosePathEscapes(path)).Replace('/', Path.DirectorySeparatorChar).Trim()
			.Trim('"', '\'', ',', ' ');
		try
		{
			string root = Path.GetPathRoot(path);
			if (!string.IsNullOrWhiteSpace(root) && path.StartsWith(root, StringComparison.OrdinalIgnoreCase))
			{
				path = path.Substring(root.Length);
			}
		}
		catch
		{
		}
		path = path.TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
		List<string> parts = new List<string>();
		string[] array = path.Split(new char[2]
		{
			Path.DirectorySeparatorChar,
			Path.AltDirectorySeparatorChar
		}, StringSplitOptions.RemoveEmptyEntries);
		foreach (string part in array)
		{
			string cleanedPart = part.Trim();
			if (cleanedPart.Length != 0 && !(cleanedPart == ".") && !(cleanedPart == ".."))
			{
				parts.Add(SanitizeFileName(cleanedPart));
			}
		}
		if (parts.Count == 0)
		{
			parts.Add(SanitizeFileName(fileName));
		}
		else if (!string.Equals(parts[parts.Count - 1], SanitizeFileName(fileName), StringComparison.OrdinalIgnoreCase) && string.IsNullOrWhiteSpace(Path.GetExtension(parts[parts.Count - 1])))
		{
			parts.Add(SanitizeFileName(fileName));
		}
		return Path.Combine(parts.ToArray());
	}

	private string GetRemoteSessionFileName(string remotePath, Uri uri)
	{
		string path = remotePath ?? "";
		if (uri != null && !string.IsNullOrWhiteSpace(uri.LocalPath))
		{
			string queryPath = ExtractSimpleQueryValue(uri.Query, "path");
			path = (string.IsNullOrWhiteSpace(queryPath) ? uri.LocalPath : queryPath);
		}
		path = WebUtility.UrlDecode(path).TrimEnd('/', '\\');
		int slash = Math.Max(path.LastIndexOf('/'), path.LastIndexOf('\\'));
		string name = ((slash >= 0) ? path.Substring(slash + 1) : path);
		return SanitizeFileName(string.IsNullOrWhiteSpace(name) ? "remote-file.bin" : name);
	}

	private string ExtractSimpleQueryValue(string query, string name)
	{
		if (string.IsNullOrWhiteSpace(query) || string.IsNullOrWhiteSpace(name))
		{
			return "";
		}
		query = query.TrimStart('?');
		string[] array = query.Split('&');
		foreach (string part in array)
		{
			int equals = part.IndexOf('=');
			string key = ((equals >= 0) ? part.Substring(0, equals) : part);
			if (string.Equals(WebUtility.UrlDecode(key), name, StringComparison.OrdinalIgnoreCase))
			{
				string value = ((equals >= 0) ? part.Substring(equals + 1) : "");
				return WebUtility.UrlDecode(value.Replace("+", " "));
			}
		}
		return "";
	}

	private string ComputeStableTextHash(string value)
	{
		using SHA256 sha = SHA256.Create();
		byte[] bytes = Encoding.UTF8.GetBytes(value ?? "");
		byte[] hash = sha.ComputeHash(bytes);
		return BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
	}

	private string ComputeFileSha256(string path)
	{
		using SHA256 sha = SHA256.Create();
		using FileStream stream = File.Open(path, FileMode.Open, FileAccess.Read, FileShare.ReadWrite | FileShare.Delete);
		byte[] hash = sha.ComputeHash(stream);
		return BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
	}

	private string ComputeBytesSha256(byte[] bytes)
	{
		using SHA256 sha = SHA256.Create();
		byte[] hash = sha.ComputeHash(bytes ?? Array.Empty<byte>());
		return BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
	}

	private void UpdateRemoteSessionFileCloneProgress(RemoteSessionFileCloneRecord record, long bytes)
	{
		if (record == null)
		{
			return;
		}
		lock (_remoteSessionFileCloneLock)
		{
			if (record.Status != "Downloading")
			{
				return;
			}
			record.Bytes = bytes;
			record.UpdatedUtc = DateTimeOffset.UtcNow;
		}
		NotifyRemoteSessionFileCloneChanged(record);
	}

	private void NotifyRemoteSessionFileCloneChanged(RemoteSessionFileCloneRecord record)
	{
		if (record != null)
		{
			RemoteSessionFileCloneSnapshot snapshot = CloneRemoteSessionFileRecord(record);
			this.RemoteSessionFileCloneChanged?.Invoke(this, new RemoteSessionFileCloneChangedEventArgs(snapshot));
		}
	}

	private RemoteSessionFileCloneSnapshot CloneRemoteSessionFileRecord(RemoteSessionFileCloneRecord record)
	{
		if (record == null)
		{
			return new RemoteSessionFileCloneSnapshot();
		}
		return new RemoteSessionFileCloneSnapshot
		{
			Id = (record.Id ?? ""),
			RemotePath = (record.RemotePath ?? ""),
			RemoteUrl = (record.RemoteUrl ?? ""),
			LocalPath = (record.LocalPath ?? ""),
			FileName = (record.FileName ?? ""),
			SessionId = (record.SessionId ?? ""),
			OwnerKey = (record.OwnerKey ?? ""),
			SandboxSessionId = (record.SandboxSessionId ?? ""),
			SandboxFileId = (record.SandboxFileId ?? ""),
			SandboxPath = (record.SandboxPath ?? ""),
			Status = (record.Status ?? ""),
			Bytes = record.Bytes,
			Sha256 = (record.Sha256 ?? ""),
			LastWriteUtc = ((record.LastWriteUtc == default(DateTimeOffset)) ? "" : record.LastWriteUtc.ToString("O")),
			StartedUtc = ((record.StartedUtc == default(DateTimeOffset)) ? "" : record.StartedUtc.ToString("O")),
			UpdatedUtc = ((record.UpdatedUtc == default(DateTimeOffset)) ? "" : record.UpdatedUtc.ToString("O")),
			Error = (record.Error ?? ""),
			Canceled = record.Canceled,
			ChangedLocally = record.ChangedLocally
		};
	}

	private bool IsRemoteSessionCloneTerminal(string status)
	{
		return status != null && (status.Equals("Complete", StringComparison.OrdinalIgnoreCase) || status.Equals("Failed", StringComparison.OrdinalIgnoreCase) || status.Equals("Canceled", StringComparison.OrdinalIgnoreCase) || status.Equals("Changed Locally", StringComparison.OrdinalIgnoreCase) || status.Equals("Deleted Locally", StringComparison.OrdinalIgnoreCase) || status.Equals("Local", StringComparison.OrdinalIgnoreCase));
	}

	private void StartRemoteSessionFileCloneWatcher()
	{
		LogMessage("[Copilot Duplicator Files] Remote session clones are virtualized in SocketJack Sandbox memory; raw clone folder watching is disabled.");
	}

	private void StopRemoteSessionFileCloneWatcher()
	{
		try
		{
			if (_remoteSessionFileCloneWatcher != null)
			{
				_remoteSessionFileCloneWatcher.EnableRaisingEvents = false;
				_remoteSessionFileCloneWatcher.Dispose();
				_remoteSessionFileCloneWatcher = null;
			}
		}
		catch
		{
		}
	}

	private void HandleRemoteSessionFileCloneWatcherEvent(string path, bool deleted)
	{
		try
		{
			if (string.IsNullOrWhiteSpace(path))
			{
				return;
			}
			string fullPath = Path.GetFullPath(path);
			if (fullPath.EndsWith(".download", StringComparison.OrdinalIgnoreCase) || !IsPathInsideRoot(fullPath, _remoteSessionCloneRoot) || (!deleted && Directory.Exists(fullPath)))
			{
				return;
			}
			RemoteSessionFileCloneRecord record = null;
			lock (_remoteSessionFileCloneLock)
			{
				record = _remoteSessionFileClones.Values.FirstOrDefault((RemoteSessionFileCloneRecord item) => PathsEqual(item.LocalPath, fullPath));
			}
			if (record == null && !deleted && File.Exists(fullPath))
			{
				record = new RemoteSessionFileCloneRecord
				{
					Id = "local_" + ComputeStableTextHash(fullPath).Substring(0, 16),
					RemotePath = "",
					RemoteUrl = "",
					LocalPath = fullPath,
					FileName = Path.GetFileName(fullPath),
					SessionId = GetRemoteSessionCloneSessionIdFromPath(fullPath),
					OwnerKey = "",
					StartedUtc = DateTimeOffset.UtcNow
				};
				lock (_remoteSessionFileCloneLock)
				{
					_remoteSessionFileClones[record.Id] = record;
				}
			}
			if (record == null)
			{
				return;
			}
			string changedSandboxSessionId = "";
			string changedSandboxFileId = "";
			string changedSandboxPath = "";
			if (!deleted && File.Exists(fullPath))
			{
				try
				{
					string sandboxSessionId = (string.IsNullOrWhiteSpace(record.SessionId) ? GetRemoteSessionCloneSessionIdFromPath(fullPath) : record.SessionId);
					if (!string.IsNullOrWhiteSpace(sandboxSessionId))
					{
						SandboxFileEntry sandboxEntry = ImportChatSessionFileToSandbox(sandboxSessionId, record.OwnerKey, fullPath, "remote-session-local-change", out changedSandboxSessionId);
						changedSandboxFileId = sandboxEntry.Id ?? "";
						changedSandboxPath = sandboxEntry.Path ?? "";
					}
				}
				catch (Exception ex)
				{
					LogMessage("[SocketJack Sandbox] Could not refresh remote session clone sandbox entry for " + fullPath + ": " + ex.Message);
				}
			}
			lock (_remoteSessionFileCloneLock)
			{
				if (deleted || !File.Exists(fullPath))
				{
					record.Status = "Deleted Locally";
					record.Bytes = 0L;
					record.Sha256 = "";
					record.ChangedLocally = true;
				}
				else
				{
					FileInfo info = new FileInfo(fullPath);
					bool keepCurrentStatus = record.Status == "Downloading" || (record.Status == "Complete" && DateTimeOffset.UtcNow - record.UpdatedUtc < TimeSpan.FromSeconds(3.0));
					record.Status = (keepCurrentStatus ? record.Status : "Changed Locally");
					record.Bytes = info.Length;
					record.Sha256 = ComputeFileSha256(fullPath);
					record.LastWriteUtc = new DateTimeOffset(info.LastWriteTimeUtc, TimeSpan.Zero);
					record.ChangedLocally = !keepCurrentStatus;
					if (!string.IsNullOrWhiteSpace(changedSandboxSessionId))
					{
						record.SandboxSessionId = changedSandboxSessionId;
						record.SandboxFileId = changedSandboxFileId;
						record.SandboxPath = changedSandboxPath;
					}
				}
				record.UpdatedUtc = DateTimeOffset.UtcNow;
				record.Error = "";
			}
			NotifyRemoteSessionFileCloneChanged(record);
		}
		catch
		{
		}
	}

	private string ReplaceFirst(string text, string oldValue, string newValue)
	{
		int index = (text ?? "").IndexOf(oldValue ?? "", StringComparison.Ordinal);
		if (index < 0)
		{
			return text;
		}
		return text.Substring(0, index) + newValue + text.Substring(index + oldValue.Length);
	}

	private string NormalizeChatAgentRequestedPath(string requestedPath)
	{
		string cleaned = NormalizeLoosePathEscapes(requestedPath).Replace('/', Path.DirectorySeparatorChar).Trim().Trim('"', '\'', ',', ' ');
		if (IsRootedWithoutVolume(cleaned))
		{
			cleaned = cleaned.TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
		}
		return cleaned;
	}

	private bool IsRootedWithoutVolume(string path)
	{
		if (string.IsNullOrWhiteSpace(path) || !Path.IsPathRooted(path))
		{
			return false;
		}
		try
		{
			string root = Path.GetPathRoot(path);
			return string.Equals(root, Path.DirectorySeparatorChar.ToString(), StringComparison.Ordinal) || string.Equals(root, Path.AltDirectorySeparatorChar.ToString(), StringComparison.Ordinal);
		}
		catch
		{
			return false;
		}
	}

	private bool TryResolveChatAgentFilePath(string requestedPath, string ownerKey, string sessionId, bool mustExist, bool sessionOnly, out string fullPath, out string error)
	{
		fullPath = null;
		error = null;
		if (string.IsNullOrWhiteSpace(requestedPath))
		{
			error = "path is required.";
			return false;
		}
		string rawCleaned = NormalizeLoosePathEscapes(requestedPath).Replace('/', Path.DirectorySeparatorChar).Trim().Trim('"', '\'', ',', ' ');
		string cleaned = NormalizeChatAgentRequestedPath(requestedPath);
		List<string> roots = GetChatAgentAllowedRoots(ownerKey, sessionId);
		if (!mustExist || sessionOnly)
		{
			foreach (string sessionRoot in GetChatAgentSessionRoots(sessionId, !mustExist))
			{
				AddAllowedRoot(roots, sessionRoot, requireExists: false);
			}
		}
		if (roots.Count == 0)
		{
			error = (sessionOnly ? "current session files are unavailable; refusing to write outside the session." : "no authorized session or filesystem roots are available.");
			return false;
		}
		try
		{
			if (Path.IsPathRooted(rawCleaned))
			{
				string hostCandidate = Path.GetFullPath(rawCleaned);
				if (IsFilesystemPathDenied(ownerKey, hostCandidate))
				{
					error = "path is denied by saved filesystem permission rule: " + hostCandidate;
					return false;
				}
				if (IsPathUnderAnyRoot(hostCandidate, roots))
				{
					if (mustExist && !File.Exists(hostCandidate) && !ChatSessionSandboxFileExists(sessionId, ownerKey, hostCandidate))
					{
						error = "file does not exist: " + FormatChatAgentPathForOutput(hostCandidate, sessionId);
						return false;
					}
					fullPath = hostCandidate;
					return true;
				}
				if (!IsRootedWithoutVolume(rawCleaned))
				{
					QueueFilesystemPermissionRequest(ownerKey, requestedPath, hostCandidate, sessionOnly ? "write file" : "read/edit file", "outside authorized filesystem roots");
					error = (sessionOnly ? ("file write requires WPF approval because it is outside the current session and authorized filesystem directories: " + hostCandidate) : ("path is outside the current session and authorized filesystem directories: " + hostCandidate));
					return false;
				}
			}
			if (Path.IsPathRooted(cleaned))
			{
				string candidate = Path.GetFullPath(cleaned);
				if (IsFilesystemPathDenied(ownerKey, candidate))
				{
					error = "path is denied by saved filesystem permission rule: " + candidate;
					return false;
				}
				if (!IsPathUnderAnyRoot(candidate, roots))
				{
					QueueFilesystemPermissionRequest(ownerKey, requestedPath, candidate, sessionOnly ? "write file" : "read/edit file", "outside authorized filesystem roots");
					error = (sessionOnly ? ("file write requires WPF approval because it is outside the current session and authorized filesystem directories: " + candidate) : ("path is outside the current session and authorized filesystem directories: " + candidate));
					return false;
				}
				if (mustExist && !File.Exists(candidate) && !ChatSessionSandboxFileExists(sessionId, ownerKey, candidate))
				{
					error = "file does not exist: " + FormatChatAgentPathForOutput(candidate, sessionId);
					return false;
				}
				fullPath = candidate;
				return true;
			}
			if (sessionOnly)
			{
				string sessionRoot2 = roots[0];
				string candidate2 = Path.GetFullPath(Path.Combine(sessionRoot2, cleaned));
				if (!IsPathInsideRoot(candidate2, sessionRoot2))
				{
					error = "file writes must stay inside the current session files: " + requestedPath;
					return false;
				}
				if (mustExist && !File.Exists(candidate2) && !ChatSessionSandboxFileExists(sessionId, ownerKey, candidate2))
				{
					error = "file does not exist in current session: " + requestedPath;
					return false;
				}
				fullPath = candidate2;
				return true;
			}
			foreach (string root in roots)
			{
				string candidate3 = Path.GetFullPath(Path.Combine(root, cleaned));
				if (!IsPathInsideRoot(candidate3, root) || (mustExist && !File.Exists(candidate3) && !ChatSessionSandboxFileExists(sessionId, ownerKey, candidate3)))
				{
					continue;
				}
				fullPath = candidate3;
				return true;
			}
			if (mustExist)
			{
				string fileName = Path.GetFileName(cleaned);
				if (!string.IsNullOrWhiteSpace(fileName))
				{
					foreach (string root2 in roots)
					{
						foreach ((string sandboxFile, SandboxFileEntry _) in EnumerateChatSessionSandboxHostFiles(root2, ownerKey, sessionId, recursive: true))
						{
							if (string.Equals(Path.GetFileName(sandboxFile), fileName, StringComparison.OrdinalIgnoreCase) && IsPathInsideRoot(sandboxFile, root2))
							{
								fullPath = Path.GetFullPath(sandboxFile);
								return true;
							}
						}
						foreach (string candidate4 in SafeEnumerateFiles(root2, fileName, SearchOption.AllDirectories))
						{
							if (IsPathInsideRoot(candidate4, root2))
							{
								fullPath = Path.GetFullPath(candidate4);
								return true;
							}
						}
					}
				}
			}
		}
		catch (Exception ex)
		{
			error = ex.Message;
			return false;
		}
		error = (mustExist ? ("file could not be found: " + requestedPath) : ("could not resolve file path: " + requestedPath));
		return false;
	}

	private List<string> ResolveChatAgentSearchRoots(string requestedPath, string ownerKey, string sessionId)
	{
		List<string> roots = new List<string>();
		if (!string.IsNullOrWhiteSpace(requestedPath))
		{
			if (TryResolveChatAgentDirectoryPath(requestedPath, ownerKey, sessionId, out var normalized, out var _))
			{
				roots.Add(normalized);
			}
			return roots;
		}
		return GetChatAgentAllowedRoots(ownerKey, sessionId);
	}

	private bool TryResolveChatAgentDirectoryPath(string requestedPath, string ownerKey, string sessionId, out string fullPath, out string error)
	{
		fullPath = null;
		error = null;
		if (string.IsNullOrWhiteSpace(requestedPath))
		{
			error = "path is required.";
			return false;
		}
		string rawCleaned = NormalizeLoosePathEscapes(requestedPath).Replace('/', Path.DirectorySeparatorChar).Trim().Trim('"', '\'', ',', ' ');
		string cleaned = NormalizeChatAgentRequestedPath(requestedPath);
		List<string> roots = GetChatAgentAllowedRoots(ownerKey, sessionId);
		try
		{
			if (Path.IsPathRooted(rawCleaned))
			{
				string hostCandidate = Path.GetFullPath(rawCleaned);
				if (IsFilesystemPathDenied(ownerKey, hostCandidate))
				{
					error = "directory is denied by saved filesystem permission rule: " + hostCandidate;
					return false;
				}
				if ((Directory.Exists(hostCandidate) || IsJackLlmSessionManagedPath(hostCandidate)) && IsPathUnderAnyRoot(hostCandidate, roots))
				{
					fullPath = hostCandidate;
					return true;
				}
				if (!IsRootedWithoutVolume(rawCleaned))
				{
					QueueFilesystemPermissionRequest(ownerKey, requestedPath, hostCandidate, "list/search directory", "outside authorized filesystem roots");
					error = "directory could not be found or is outside the authorized roots: " + requestedPath;
					return false;
				}
			}
			if (Path.IsPathRooted(cleaned))
			{
				string candidate = Path.GetFullPath(cleaned);
				if (IsFilesystemPathDenied(ownerKey, candidate))
				{
					error = "directory is denied by saved filesystem permission rule: " + candidate;
					return false;
				}
				if ((Directory.Exists(candidate) || IsJackLlmSessionManagedPath(candidate)) && IsPathUnderAnyRoot(candidate, roots))
				{
					fullPath = candidate;
					return true;
				}
				QueueFilesystemPermissionRequest(ownerKey, requestedPath, candidate, "list/search directory", "outside authorized filesystem roots");
			}
			else
			{
				foreach (string root in roots)
				{
					string candidate2 = Path.GetFullPath(Path.Combine(root, cleaned));
					if ((Directory.Exists(candidate2) || IsJackLlmSessionManagedPath(candidate2)) && IsPathInsideRoot(candidate2, root))
					{
						fullPath = candidate2;
						return true;
					}
				}
			}
		}
		catch (Exception ex)
		{
			error = ex.Message;
			return false;
		}
		error = "directory could not be found or is outside the authorized roots: " + requestedPath;
		return false;
	}

	private List<string> GetChatAgentAllowedRoots(string ownerKey, string sessionId = null)
	{
		List<string> roots = new List<string>();
		foreach (string sessionRoot in GetChatAgentSessionRoots(sessionId, ensureExists: false))
		{
			AddAllowedRoot(roots, sessionRoot, requireExists: false);
		}
		if (!string.IsNullOrWhiteSpace(sessionId))
		{
			AddAllowedRoot(roots, GetRemoteSessionCloneDirectory(sessionId), requireExists: false);
		}
		if (!string.IsNullOrWhiteSpace(ownerKey))
		{
			foreach (ChatFilesystemAccessEntry entry in GetChatFilesystemAccess(ownerKey))
			{
				if (entry != null && entry.exists)
				{
					AddAllowedRoot(roots, entry.path);
				}
			}
			foreach (string root in GetTemporaryFilesystemAccess(ownerKey))
			{
				AddAllowedRoot(roots, root);
			}
		}
		return roots;
	}

	private List<string> GetActiveSolutionRoots()
	{
		List<string> roots = new List<string>();
		try
		{
			AddNearestSolutionRoot(roots, Directory.GetCurrentDirectory());
		}
		catch
		{
		}
		try
		{
			AddNearestSolutionRoot(roots, AppDomain.CurrentDomain.BaseDirectory);
		}
		catch
		{
		}
		return roots;
	}

	private void AddNearestSolutionRoot(List<string> roots, string startDirectory)
	{
		if (roots == null || string.IsNullOrWhiteSpace(startDirectory))
		{
			return;
		}
		DirectoryInfo directory;
		try
		{
			string full = Path.GetFullPath(startDirectory);
			if (File.Exists(full))
			{
				full = Path.GetDirectoryName(full);
			}
			if (string.IsNullOrWhiteSpace(full) || !Directory.Exists(full))
			{
				return;
			}
			directory = new DirectoryInfo(full);
		}
		catch
		{
			return;
		}
		while (directory != null)
		{
			try
			{
				if (Directory.GetFiles(directory.FullName, "*.sln", SearchOption.TopDirectoryOnly).Length != 0)
				{
					AddAllowedRoot(roots, directory.FullName);
					break;
				}
			}
			catch
			{
			}
			directory = directory.Parent;
		}
	}

	private bool IsFilesystemPathDenied(string ownerKey, string fullPath)
	{
		foreach (string deniedRoot in GetChatFilesystemDeniedDirectories(ownerKey))
		{
			if (IsPathInsideRoot(fullPath, deniedRoot))
			{
				return true;
			}
		}
		return false;
	}

	private void QueueFilesystemPermissionRequest(string ownerKey, string requestedPath, string fullPath, string operation, string reason)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		string directory = ResolvePermissionDirectory(fullPath);
		if (string.IsNullOrWhiteSpace(directory))
		{
			return;
		}
		if (IsFilesystemRootDirectory(directory))
		{
			LogMessage("[Filesystem Permission] Refusing root-level permission request for " + ownerKey + ": " + fullPath);
			return;
		}
		if (IsFilesystemPathDenied(ownerKey, fullPath))
		{
			LogMessage("[Filesystem Permission] Denied by saved rule for " + ownerKey + ": " + fullPath);
			return;
		}
		FilesystemPermissionRequestSnapshot snapshot = null;
		lock (_filesystemPermissionLock)
		{
			foreach (FilesystemPermissionRequestSnapshot existing in _pendingFilesystemPermissionRequests.Values)
			{
				if (string.Equals(existing.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) && PathsEqual(existing.DirectoryPath, directory))
				{
					snapshot = existing;
					break;
				}
			}
			if (snapshot == null)
			{
				snapshot = new FilesystemPermissionRequestSnapshot
				{
					Id = "fsperm_" + Guid.NewGuid().ToString("N"),
					OwnerKey = ownerKey,
					ClientIp = (ExtractIpFromOwnerKey(ownerKey) ?? ownerKey),
					RequestedPath = (requestedPath ?? ""),
					FullPath = (fullPath ?? ""),
					DirectoryPath = directory,
					Operation = (operation ?? "file access"),
					Reason = (reason ?? ""),
					CreatedUtc = DateTimeOffset.UtcNow.ToString("O")
				};
				_pendingFilesystemPermissionRequests[snapshot.Id] = snapshot;
			}
		}
		LogMessage("[Filesystem Permission] Permission required for " + ownerKey + " to " + snapshot.Operation + ": " + snapshot.FullPath + " (directory: " + snapshot.DirectoryPath + ").");
		RecordObservabilityEvent("security", "filesystem permission", "pending", snapshot.Operation + ": " + snapshot.DirectoryPath, ownerKey, "filesystem", 0L);
		this.FilesystemPermissionRequested?.Invoke(this, new FilesystemPermissionRequestEventArgs(snapshot));
	}

	private string ResolvePermissionDirectory(string fullPath)
	{
		if (string.IsNullOrWhiteSpace(fullPath))
		{
			return null;
		}
		try
		{
			string normalized = Path.GetFullPath(fullPath);
			if (Directory.Exists(normalized))
			{
				return normalized.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
			}
			string directory = Path.GetDirectoryName(normalized);
			return string.IsNullOrWhiteSpace(directory) ? null : directory.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
		}
		catch
		{
			return null;
		}
	}

	private FilesystemPermissionRequestSnapshot FindPendingFilesystemPermissionRequest(string requestId)
	{
		if (string.IsNullOrWhiteSpace(requestId))
		{
			return null;
		}
		lock (_filesystemPermissionLock)
		{
			FilesystemPermissionRequestSnapshot request;
			return _pendingFilesystemPermissionRequests.TryGetValue(requestId, out request) ? request : null;
		}
	}

	private void RemovePendingFilesystemPermissionRequest(string requestId)
	{
		if (string.IsNullOrWhiteSpace(requestId))
		{
			return;
		}
		lock (_filesystemPermissionLock)
		{
			_pendingFilesystemPermissionRequests.Remove(requestId);
		}
	}

	private async Task<TerminalPermissionDecision> QueueTerminalPermissionRequestAsync(string ownerKey, TerminalCommandRequest commandRequest, CancellationToken cancellationToken)
	{
		ownerKey = NormalizeChatFilesystemOwnerKey(ownerKey);
		string command = NormalizeTerminalCommand(commandRequest?.Command);
		if (string.IsNullOrWhiteSpace(command))
		{
			return new TerminalPermissionDecision(approved: false, always: false, forever: false, "Terminal command is empty.");
		}
		if (IsTerminalCommandBlockedByTrust(ownerKey, command, out var trustReason))
		{
			return new TerminalPermissionDecision(approved: false, always: false, forever: false, trustReason);
		}
		ChatPermissionState permissions = GetChatPermissions(ownerKey);
		if (permissions == null || !permissions.terminalCommands)
		{
			return new TerminalPermissionDecision(approved: false, always: false, forever: false, "Terminal Commands permission is disabled for this client.");
		}
		if (permissions.terminalForeverApproved)
		{
			return new TerminalPermissionDecision(approved: true, always: false, forever: true, "Terminal commands are forever approved for this client.");
		}
		if (TryGetTerminalPermissionRuleDecision(ownerKey, command, out var savedApproved))
		{
			return new TerminalPermissionDecision(savedApproved, always: true, forever: false, savedApproved ? "Approved by saved terminal command rule." : "Denied by saved terminal command rule.");
		}
		string commandHash = ComputeTerminalCommandHash(command);
		PendingTerminalPermissionRequest pending;
		lock (_terminalPermissionLock)
		{
			pending = _pendingTerminalPermissionRequests.Values.FirstOrDefault((PendingTerminalPermissionRequest existing) => existing != null && string.Equals(existing.Request.OwnerKey, ownerKey, StringComparison.OrdinalIgnoreCase) && string.Equals(ComputeTerminalCommandHash(existing.Request.Command), commandHash, StringComparison.OrdinalIgnoreCase));
			if (pending == null)
			{
				TerminalPermissionRequestSnapshot snapshot = new TerminalPermissionRequestSnapshot
				{
					Id = "termperm_" + Guid.NewGuid().ToString("N"),
					OwnerKey = ownerKey,
					ClientIp = (ExtractIpFromOwnerKey(ownerKey) ?? ownerKey),
					Command = command,
					Shell = (string.IsNullOrWhiteSpace(commandRequest?.Shell) ? "powershell" : commandRequest.Shell.Trim()),
					WorkingDirectory = (commandRequest?.WorkingDirectory ?? ""),
					Summary = (commandRequest?.Summary ?? ""),
					CreatedUtc = DateTimeOffset.UtcNow.ToString("O")
				};
				pending = new PendingTerminalPermissionRequest(snapshot);
				_pendingTerminalPermissionRequests[snapshot.Id] = pending;
			}
		}
		LogMessage("[Terminal Permission] Approval required for " + ownerKey + ": " + command);
		RecordObservabilityEvent("security", "terminal permission", "pending", pending.Request.Summary, ownerKey, "terminal", 0L);
		this.TerminalPermissionRequested?.Invoke(this, new TerminalPermissionRequestEventArgs(pending.Request));
		if (await Task.WhenAny(pending.Completion.Task, Task.Delay(TimeSpan.FromMinutes(10.0), cancellationToken)).ConfigureAwait(continueOnCapturedContext: false) == pending.Completion.Task)
		{
			return await pending.Completion.Task.ConfigureAwait(continueOnCapturedContext: false);
		}
		if (cancellationToken.IsCancellationRequested)
		{
			RemovePendingTerminalPermissionRequest(pending.Request.Id);
			pending.Completion.TrySetResult(new TerminalPermissionDecision(approved: false, always: false, forever: false, "Terminal command was cancelled before approval."));
			return new TerminalPermissionDecision(approved: false, always: false, forever: false, "Terminal command was cancelled before approval.");
		}
		RemovePendingTerminalPermissionRequest(pending.Request.Id);
		pending.Completion.TrySetResult(new TerminalPermissionDecision(approved: false, always: false, forever: false, "Terminal command approval timed out."));
		LogMessage("[Terminal Permission] Approval timed out for " + ownerKey + ": " + command);
		return new TerminalPermissionDecision(approved: false, always: false, forever: false, "Terminal command approval timed out.");
	}

	private PendingTerminalPermissionRequest FindPendingTerminalPermissionRequest(string requestId)
	{
		if (string.IsNullOrWhiteSpace(requestId))
		{
			return null;
		}
		lock (_terminalPermissionLock)
		{
			PendingTerminalPermissionRequest request;
			return _pendingTerminalPermissionRequests.TryGetValue(requestId, out request) ? request : null;
		}
	}

	private void RemovePendingTerminalPermissionRequest(string requestId)
	{
		if (string.IsNullOrWhiteSpace(requestId))
		{
			return;
		}
		lock (_terminalPermissionLock)
		{
			_pendingTerminalPermissionRequests.Remove(requestId);
		}
	}

	private List<string> GetChatAgentSessionRoots(string sessionId, bool ensureExists)
	{
		List<string> roots = new List<string>();
		string sessionRoot = GetChatSessionFilesDirectory(sessionId);
		if (string.IsNullOrWhiteSpace(sessionRoot))
		{
			return roots;
		}
		AddAllowedRoot(roots, sessionRoot, requireExists: false);
		return roots;
	}

	private void AddAllowedRoot(List<string> roots, string path)
	{
		AddAllowedRoot(roots, path, requireExists: true);
	}

	private void AddAllowedRoot(List<string> roots, string path, bool requireExists)
	{
		if (roots == null || string.IsNullOrWhiteSpace(path) || (requireExists && !Directory.Exists(path)))
		{
			return;
		}
		string normalized = Path.GetFullPath(path);
		if (IsFilesystemRootDirectory(normalized))
		{
			return;
		}
		string full = normalized.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
		foreach (string existing in roots)
		{
			if (PathsEqual(existing, full))
			{
				return;
			}
		}
		roots.Add(full);
	}

	private bool IsPathUnderAnyRoot(string fullPath, List<string> roots)
	{
		foreach (string root in roots)
		{
			if (IsPathInsideRoot(fullPath, root))
			{
				return true;
			}
		}
		return false;
	}

	private bool IsPathInsideRoot(string fullPath, string root)
	{
		if (string.IsNullOrWhiteSpace(fullPath) || string.IsNullOrWhiteSpace(root))
		{
			return false;
		}
		string normalizedPath = Path.GetFullPath(fullPath).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
		string normalizedRoot = Path.GetFullPath(root).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
		return normalizedPath.Equals(normalizedRoot, StringComparison.OrdinalIgnoreCase) || normalizedPath.StartsWith(normalizedRoot + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase) || normalizedPath.StartsWith(normalizedRoot + Path.AltDirectorySeparatorChar, StringComparison.OrdinalIgnoreCase);
	}

	private IEnumerable<string> SafeEnumerateFiles(string root, string pattern, SearchOption option)
	{
		if (string.IsNullOrWhiteSpace(root) || !Directory.Exists(root))
		{
			return new string[0];
		}
		return SafeEnumerateFilesCore(root, pattern, option);
	}

	private IEnumerable<string> SafeEnumerateFilesCore(string root, string pattern, SearchOption option)
	{
		Stack<string> pending = new Stack<string>();
		pending.Push(root);
		while (pending.Count > 0)
		{
			string directory = pending.Pop();
			string[] files;
			try
			{
				files = Directory.GetFiles(directory, pattern);
			}
			catch
			{
				files = new string[0];
			}
			for (int i = 0; i < files.Length; i++)
			{
				yield return files[i];
			}
			if (option == SearchOption.AllDirectories)
			{
				string[] children;
				try
				{
					children = Directory.GetDirectories(directory);
				}
				catch
				{
					children = new string[0];
				}
				for (int j = 0; j < children.Length; j++)
				{
					pending.Push(children[j]);
				}
			}
		}
	}

	private IEnumerable<(string FullPath, SandboxFileEntry Entry)> EnumerateChatSessionSandboxHostFiles(string root, string ownerKey, string sessionId, bool recursive)
	{
		List<(string FullPath, SandboxFileEntry Entry)> files = new List<(string FullPath, SandboxFileEntry Entry)>();
		if (string.IsNullOrWhiteSpace(root) || string.IsNullOrWhiteSpace(sessionId) || !IsJackLlmSessionManagedPath(root))
		{
			return files;
		}
		try
		{
			string normalizedRoot = Path.GetFullPath(root).TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
			HydrateChatSessionSandboxFilesFromSessionMetadata(sessionId, ownerKey, normalizedRoot);
			SandboxSession sandbox = GetOrCreateChatSessionSandbox(sessionId, ownerKey);
			foreach (SandboxFileEntry entry in sandbox.FileSystem.EnumerateFiles("/", "*", true))
			{
				if (!TryMapChatSessionSandboxEntryToHostPath(sessionId, entry, out var fullPath))
				{
					continue;
				}
				if (!IsPathInsideRoot(fullPath, normalizedRoot))
				{
					continue;
				}
				string relative = SafeRelativePath(normalizedRoot, fullPath);
				if (!recursive && (relative.Contains("/", StringComparison.Ordinal) || relative.Contains("\\", StringComparison.Ordinal)))
				{
					continue;
				}
				files.Add((fullPath, entry));
			}
		}
		catch
		{
		}
		return files;
	}

	private bool TryMapChatSessionSandboxEntryToHostPath(string sessionId, SandboxFileEntry entry, out string fullPath)
	{
		fullPath = "";
		if (entry == null)
		{
			return false;
		}
		try
		{
			if (!string.IsNullOrWhiteSpace(entry.SourcePath) && Path.IsPathRooted(entry.SourcePath))
			{
				fullPath = Path.GetFullPath(entry.SourcePath);
				return IsJackLlmSessionManagedPath(fullPath);
			}
			string sandboxPath = (entry.Path ?? "").Replace('\\', '/');
			string root;
			string relative;
			if (sandboxPath.Equals("/session", StringComparison.OrdinalIgnoreCase) || sandboxPath.StartsWith("/session/", StringComparison.OrdinalIgnoreCase))
			{
				root = GetChatSessionFilesDirectory(sessionId);
				relative = sandboxPath.Length <= "/session/".Length ? "" : sandboxPath.Substring("/session/".Length);
			}
			else if (sandboxPath.Equals("/remote-session", StringComparison.OrdinalIgnoreCase) || sandboxPath.StartsWith("/remote-session/", StringComparison.OrdinalIgnoreCase))
			{
				root = GetRemoteSessionCloneDirectory(sessionId);
				relative = sandboxPath.Length <= "/remote-session/".Length ? "" : sandboxPath.Substring("/remote-session/".Length);
			}
			else
			{
				return false;
			}
			if (string.IsNullOrWhiteSpace(root))
			{
				return false;
			}
			fullPath = Path.GetFullPath(Path.Combine(root, relative.Replace('/', Path.DirectorySeparatorChar)));
			return IsJackLlmSessionManagedPath(fullPath);
		}
		catch
		{
			fullPath = "";
			return false;
		}
	}

	private void SearchFilesInRoot(string root, string query, int take, List<string> results, string ownerKey, string sessionId)
	{
		if (string.IsNullOrWhiteSpace(root) || results == null)
		{
			return;
		}
		List<(string FullPath, SandboxFileEntry Entry)> sandboxFiles = EnumerateChatSessionSandboxHostFiles(root, ownerKey, sessionId, recursive: true).ToList();
		if (!Directory.Exists(root) && sandboxFiles.Count == 0)
		{
			return;
		}
		query = query ?? "";
		if (string.IsNullOrWhiteSpace(query))
		{
			return;
		}
		if (!SafeAhoCorasickSearchIndex.TryCreate(new string[1] { query }, out var searchIndex, out var searchIndexError) && !string.IsNullOrWhiteSpace(searchIndexError))
		{
			LogMessage("[Search Index] Aho-Corasick unavailable; using ordinal search. " + searchIndexError);
		}
		int inspected = 0;
		foreach ((string file, SandboxFileEntry entry) in sandboxFiles)
		{
			if (results.Count >= take || inspected++ > 5000)
			{
				break;
			}
			if (ShouldFilterGeneratedOrBuildOutputPath(file, root))
			{
				continue;
			}
			string relative = SafeRelativePath(root, file);
			string displayRelative = FormatChatAgentRelativePathForOutput(root, relative);
			if (SearchTextContainsQuery(relative, query, searchIndex))
			{
				results.Add(displayRelative + " [path]");
				continue;
			}
			if (!IsLikelyTextFile(file) || entry.Length > 1048576)
			{
				continue;
			}
			if (!TryReadChatSessionSandboxTextFile(sessionId, ownerKey, file, out var text))
			{
				continue;
			}
			string[] lines = text.Replace("\r\n", "\n").Replace('\r', '\n').Split('\n');
			for (int i = 0; i < lines.Length; i++)
			{
				if (SearchTextContainsQuery(lines[i], query, searchIndex))
				{
					results.Add(displayRelative + ":" + (i + 1).ToString(CultureInfo.InvariantCulture) + ": " + TruncateForLog(lines[i].Trim(), 220));
					break;
				}
			}
		}
		foreach (string file in SafeEnumerateFiles(root, "*", SearchOption.AllDirectories))
		{
			if (results.Count >= take || inspected++ > 5000)
			{
				break;
			}
			if (ShouldFilterGeneratedOrBuildOutputPath(file, root))
			{
				continue;
			}
			string relative = SafeRelativePath(root, file);
			string displayRelative = FormatChatAgentRelativePathForOutput(root, relative);
			if (SearchTextContainsQuery(relative, query, searchIndex))
			{
				results.Add(displayRelative + " [path]");
			}
			else
			{
				if (!IsLikelyTextFile(file))
				{
					continue;
				}
				try
				{
					FileInfo info = new FileInfo(file);
					if (info.Length > 1048576)
					{
						continue;
					}
					int lineNumber = 0;
					foreach (string line in File.ReadLines(file))
					{
						lineNumber++;
						if (SearchTextContainsQuery(line, query, searchIndex))
						{
							results.Add(displayRelative + ":" + lineNumber + ": " + TruncateForLog(line.Trim(), 220));
							break;
						}
					}
				}
				catch
				{
				}
			}
		}
	}

	private bool SearchTextContainsQuery(string text, string query, SafeAhoCorasickSearchIndex searchIndex)
	{
		if (string.IsNullOrEmpty(text) || string.IsNullOrWhiteSpace(query))
		{
			return false;
		}
		if (searchIndex != null && searchIndex.Contains(text))
		{
			return true;
		}
		return text.IndexOf(query, StringComparison.OrdinalIgnoreCase) >= 0;
	}

	private void ListFilesInRoot(string root, bool recursive, int take, List<string> results, string ownerKey, string sessionId)
	{
		if (string.IsNullOrWhiteSpace(root) || results == null)
		{
			return;
		}
		List<(string FullPath, SandboxFileEntry Entry)> sandboxFiles = EnumerateChatSessionSandboxHostFiles(root, ownerKey, sessionId, recursive: true).ToList();
		if (!Directory.Exists(root) && sandboxFiles.Count == 0)
		{
			return;
		}
		HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
		foreach ((string file, SandboxFileEntry _) in sandboxFiles)
		{
			if (results.Count >= take)
			{
				return;
			}
			string relative = SafeRelativePath(root, file);
			string displayRelative = FormatChatAgentRelativePathForOutput(root, relative);
			string normalizedRelative = relative.Replace('\\', '/');
			string[] parts = normalizedRelative.Split(new char[1] { '/' }, StringSplitOptions.RemoveEmptyEntries);
			if (parts.Length > 1)
			{
				int maxDepth = recursive ? parts.Length - 1 : 1;
				for (int depth = 1; depth <= maxDepth && results.Count < take; depth++)
				{
					string directory = string.Join("/", parts.Take(depth)) + "\\";
					if (seen.Add(directory) && !ShouldFilterGeneratedOrBuildOutputPath(Path.Combine(root, directory.TrimEnd('\\')), root))
					{
						results.Add(FormatChatAgentRelativePathForOutput(root, directory));
					}
				}
			}
			if ((recursive || parts.Length <= 1) && seen.Add(relative) && !ShouldFilterGeneratedOrBuildOutputPath(file, root))
			{
				results.Add(displayRelative);
			}
		}
		SearchOption option = (recursive ? SearchOption.AllDirectories : SearchOption.TopDirectoryOnly);
		try
		{
			foreach (string directory in Directory.EnumerateDirectories(root, "*", option))
			{
				if (results.Count >= take)
				{
					return;
				}
				if (!ShouldFilterGeneratedOrBuildOutputPath(directory, root))
				{
					string relative = SafeRelativePath(root, directory) + "\\";
					if (seen.Add(relative))
					{
						results.Add(FormatChatAgentRelativePathForOutput(root, relative));
					}
				}
			}
		}
		catch
		{
		}
		foreach (string file in SafeEnumerateFiles(root, "*", option))
		{
			if (results.Count >= take)
			{
				break;
			}
			if (!ShouldFilterGeneratedOrBuildOutputPath(file, root))
			{
				string relative = SafeRelativePath(root, file);
				if (seen.Add(relative))
				{
					results.Add(FormatChatAgentRelativePathForOutput(root, relative));
				}
			}
		}
	}

	private string FormatChatAgentRelativePathForOutput(string root, string relativePath)
	{
		return IsJackLlmSessionManagedPath(root) ? BuildChatSessionVirtualPath(relativePath) : (relativePath ?? "");
	}

	private string SafeRelativePath(string root, string path)
	{
		try
		{
			return Path.GetRelativePath(root, path).Replace(Path.DirectorySeparatorChar, '/');
		}
		catch
		{
			return path;
		}
	}

	private bool IsLikelyTextFile(string path)
	{
		switch (Path.GetExtension(path ?? "").ToLowerInvariant())
		{
		case ".cs":
		case ".vb":
		case ".xaml":
		case ".xml":
		case ".json":
		case ".txt":
		case ".md":
		case ".html":
		case ".htm":
		case ".css":
		case ".js":
		case ".ts":
		case ".csproj":
		case ".vbproj":
		case ".sln":
		case ".config":
		case ".props":
		case ".targets":
		case ".yml":
		case ".yaml":
		case ".resx":
			return true;
		default:
			return false;
		}
	}

	private async Task<string> ExecuteInternetSearchAsync(string argumentsJson, string ownerKey, string sessionId)
	{
		string query = NormalizeInternetSearchQueryCandidate(ExtractJsonStringProperty(argumentsJson, "query"));
		string url = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "url"), ExtractJsonStringProperty(argumentsJson, "href"), ExtractJsonStringProperty(argumentsJson, "sourceUrl"));
		string mode = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "mode"), ExtractJsonStringProperty(argumentsJson, "action"), ExtractJsonStringProperty(argumentsJson, "operation"));
		int take = ExtractIntFromToolArguments(argumentsJson, "take", 6);
		take = Math.Max(1, Math.Min(12, take));
		if (string.Equals(mode, "read", StringComparison.OrdinalIgnoreCase) || (!string.IsNullOrWhiteSpace(url) && string.IsNullOrWhiteSpace(query)))
		{
			return await ExecuteInternetReadPageAsync(argumentsJson, ownerKey, sessionId);
		}
		if (string.IsNullOrWhiteSpace(query))
		{
			LogMessage("[Internet Search] Query rejected: query is required.");
			return "internet_search error: query is required for action=search. Use action=read with url to read a chosen page.";
		}
		try
		{
			return await ExecuteInternetSearchServiceCompatibleAsync(query, take);
		}
		catch (Exception ex)
		{
			LogMessage("[Internet Search] Primary search failed for \"" + TruncateForLog(query, 120) + "\": " + ex.Message + "; trying fallback.");
			try
			{
				string fallbackUrl = "https://html.duckduckgo.com/html/?q=" + Uri.EscapeDataString(query);
				return SummarizeDuckDuckGoHtmlSearch(await GetStringWithUserAgentAsync(fallbackUrl), query, take);
			}
			catch (Exception ex2)
			{
				Exception fallbackEx = ex2;
				LogMessage("[Internet Search] Fallback search failed for \"" + TruncateForLog(query, 120) + "\": " + fallbackEx.Message);
				return "internet_search error: " + ex.Message;
			}
		}
	}

	private async Task<string> ExecuteInternetReadPageAsync(string argumentsJson, string ownerKey, string sessionId)
	{
		string url = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "url"), ExtractJsonStringProperty(argumentsJson, "href"), ExtractJsonStringProperty(argumentsJson, "sourceUrl"));
		if (string.IsNullOrWhiteSpace(url))
		{
			return "internet_search read error: url is required.";
		}
		if (!Uri.TryCreate(url, UriKind.Absolute, out Uri uri) || (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps))
		{
			return "internet_search read error: only absolute http and https URLs can be read.";
		}
		if (IsChatBrowserProxyUrlBlocked(uri, out var blockedReason))
		{
			return "internet_search read blocked: " + blockedReason + "\nurl: " + uri.AbsoluteUri;
		}
		if (!TryValidateBrowserDestination(uri, BrowserPrivateNetworkAccessEnabled, out var destinationReason))
		{
			return "internet_search read blocked: " + destinationReason + "\nurl: " + uri.AbsoluteUri;
		}
		string selector = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "selector"), ExtractJsonStringProperty(argumentsJson, "cssSelector"), ExtractJsonStringProperty(argumentsJson, "element"));
		int take = Math.Max(1, Math.Min(120, ExtractIntFromToolArguments(argumentsJson, "take", 40)));
		int maxChars = Math.Max(1000, Math.Min(100000, ExtractIntFromToolArguments(argumentsJson, "maxChars", 20000)));
		bool includeHtml = ExtractBoolFromToolArguments(argumentsJson, "includeHtml", fallback: false);
		ChatBrowserClientSession browserSession = GetOrCreateChatBrowserClientSession(ownerKey, sessionId);
		using HttpResponseMessage response = await SendValidatedBrowserGetAsync(browserSession.ReadClient, uri, (request, target) => AddBrowserLikeHeaders(request, target, null)).ConfigureAwait(continueOnCapturedContext: false);
		byte[] bytes = response.Content == null ? Array.Empty<byte>() : await response.Content.ReadAsByteArrayAsync().ConfigureAwait(continueOnCapturedContext: false);
		string contentType = response.Content?.Headers?.ContentType?.ToString() ?? "";
		string charset = response.Content?.Headers?.ContentType?.CharSet;
		string body = DecodeChatBrowserProxyText(bytes, charset);
		Uri finalUri = response.RequestMessage?.RequestUri ?? uri;
		return BuildInternetReadPageResult(uri, finalUri, response, contentType, body, selector, take, maxChars, includeHtml, ownerKey, sessionId);
	}

	private async Task<HttpResponseMessage> SendValidatedBrowserGetAsync(System.Net.Http.HttpClient client, Uri initialUri, Action<HttpRequestMessage, Uri> configureRequest)
	{
		Uri currentUri = initialUri;
		for (int redirectCount = 0; redirectCount <= 5; redirectCount++)
		{
			if (IsChatBrowserProxyUrlBlocked(currentUri, out var blockedReason))
			{
				throw new InvalidOperationException(blockedReason);
			}
			if (!TryValidateBrowserDestination(currentUri, BrowserPrivateNetworkAccessEnabled, out var destinationReason))
			{
				throw new InvalidOperationException(destinationReason);
			}
			using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, currentUri);
			configureRequest?.Invoke(request, currentUri);
			HttpResponseMessage response = await client.SendAsync(request, HttpCompletionOption.ResponseHeadersRead).ConfigureAwait(continueOnCapturedContext: false);
			if (!IsChatBrowserProxyRedirect(response.StatusCode) || response.Headers.Location == null)
			{
				return response;
			}
			Uri redirectUri = ResolveChatBrowserProxyRedirectUri(currentUri, response.Headers.Location);
			response.Dispose();
			if (redirectUri == null)
			{
				throw new InvalidOperationException("The destination returned an invalid redirect URL.");
			}
			if (redirectCount == 5)
			{
				throw new InvalidOperationException("The destination exceeded the five-redirect limit.");
			}
			currentUri = redirectUri;
		}
		throw new InvalidOperationException("The destination exceeded the redirect limit.");
	}

	private string BuildInternetReadPageResult(Uri requestedUri, Uri finalUri, HttpResponseMessage response, string contentType, string body, string selector, int take, int maxChars, bool includeHtml, string ownerKey, string sessionId)
	{
		string html = body ?? "";
		string title = IsLikelyHtmlDocument(contentType, finalUri, html) ? ExtractBrowserSkillTitle(html) : "";
		string visibleText = IsLikelyHtmlDocument(contentType, finalUri, html) ? HtmlToBrowserSkillText(html) : NormalizeBrowserSkillText(html);
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("[SearchInternet service read]");
		sb.AppendLine("requestedUrl: " + (requestedUri?.AbsoluteUri ?? ""));
		sb.AppendLine("finalUrl: " + (finalUri?.AbsoluteUri ?? ""));
		sb.AppendLine("status: " + (response == null ? "unknown" : (((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + response.ReasonPhrase)));
		sb.AppendLine("contentType: " + (string.IsNullOrWhiteSpace(contentType) ? "(none)" : contentType));
		sb.AppendLine("fetchedUtc: " + DateTimeOffset.UtcNow.ToString("O"));
		sb.AppendLine("cookieSandbox: " + BuildBrowserClientSandboxLabel(ownerKey, EnsureChatUiSessionId(sessionId)));
		if (!string.IsNullOrWhiteSpace(title))
		{
			sb.AppendLine("title: " + title);
		}
		sb.AppendLine();
		sb.AppendLine("[Visible text]");
		sb.AppendLine(TruncateForLog(visibleText, maxChars));
		if (IsLikelyHtmlDocument(contentType, finalUri, html))
		{
			AppendInternetReadMetadata(sb, html, finalUri);
			AppendInternetReadHeadings(sb, html, take);
			AppendInternetReadLinks(sb, html, finalUri, take);
			AppendInternetReadControls(sb, html, take);
			AppendInternetReadTables(sb, html, take);
			AppendInternetReadLists(sb, html, take);
			AppendInternetReadSelectorMatches(sb, html, finalUri, selector, take);
			if (includeHtml)
			{
				sb.AppendLine();
				sb.AppendLine("[HTML excerpt]");
				sb.AppendLine(TruncateForLog(html, Math.Min(maxChars, 30000)));
			}
		}
		return sb.ToString().TrimEnd();
	}

	private bool IsLikelyHtmlDocument(string contentType, Uri uri, string body)
	{
		if (IsHtmlContentType(contentType))
		{
			return true;
		}
		string path = uri?.AbsolutePath ?? "";
		if (path.EndsWith(".html", StringComparison.OrdinalIgnoreCase) || path.EndsWith(".htm", StringComparison.OrdinalIgnoreCase))
		{
			return true;
		}
		return Regex.IsMatch(body ?? "", "<\\s*(?:!doctype\\s+html|html|head|body|title|table|form|input|textarea|ul|ol)\\b", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
	}

	private void AppendInternetReadMetadata(StringBuilder sb, string html, Uri finalUri)
	{
		List<string> rows = new List<string>();
		AddInternetReadMetaRow(rows, "description", ExtractMetaContent(html, "name", "description"));
		AddInternetReadMetaRow(rows, "og:title", ExtractMetaContent(html, "property", "og:title"));
		AddInternetReadMetaRow(rows, "og:description", ExtractMetaContent(html, "property", "og:description"));
		string canonical = ExtractLinkHref(html, "canonical", finalUri);
		AddInternetReadMetaRow(rows, "canonical", canonical);
		if (rows.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("[Metadata]");
		foreach (string row in rows)
		{
			sb.AppendLine(row);
		}
	}

	private void AddInternetReadMetaRow(List<string> rows, string label, string value)
	{
		if (rows != null && !string.IsNullOrWhiteSpace(value))
		{
			rows.Add(label + ": " + TruncateForLog(NormalizeBrowserSkillText(value), 500));
		}
	}

	private string ExtractMetaContent(string html, string attrName, string attrValue)
	{
		if (string.IsNullOrWhiteSpace(html) || string.IsNullOrWhiteSpace(attrName) || string.IsNullOrWhiteSpace(attrValue))
		{
			return "";
		}
		foreach (Match match in Regex.Matches(html, "<meta\\b(?<attrs>[^>]*)>", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant))
		{
			string attrs = match.Groups["attrs"].Value;
			if (string.Equals(ExtractHtmlAttribute(attrs, attrName), attrValue, StringComparison.OrdinalIgnoreCase))
			{
				return WebUtility.HtmlDecode(ExtractHtmlAttribute(attrs, "content") ?? "");
			}
		}
		return "";
	}

	private string ExtractLinkHref(string html, string rel, Uri baseUri)
	{
		foreach (Match match in Regex.Matches(html ?? "", "<link\\b(?<attrs>[^>]*)>", RegexOptions.IgnoreCase | RegexOptions.Singleline | RegexOptions.CultureInvariant))
		{
			string attrs = match.Groups["attrs"].Value;
			string relValue = ExtractHtmlAttribute(attrs, "rel") ?? "";
			if (!Regex.IsMatch(relValue, "(^|\\s)" + Regex.Escape(rel ?? "") + "(\\s|$)", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
			{
				continue;
			}
			string href = ExtractHtmlAttribute(attrs, "href") ?? "";
			if (baseUri != null && Uri.TryCreate(baseUri, href, out Uri resolved))
			{
				return resolved.AbsoluteUri;
			}
			return href;
		}
		return "";
	}

	private void AppendInternetReadHeadings(StringBuilder sb, string html, int take)
	{
		List<string> headings = new List<string>();
		foreach (Match match in Regex.Matches(html ?? "", "<h(?<level>[1-6])\\b[^>]*>(?<text>[\\s\\S]*?)</h\\k<level>>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
		{
			string text = NormalizeBrowserSkillText(HtmlToBrowserSkillText(match.Groups["text"].Value));
			if (!string.IsNullOrWhiteSpace(text))
			{
				headings.Add("h" + match.Groups["level"].Value + ": " + TruncateForLog(text, 240));
			}
			if (headings.Count >= take)
			{
				break;
			}
		}
		if (headings.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("[Headings]");
		foreach (string heading in headings)
		{
			sb.AppendLine(heading);
		}
	}

	private void AppendInternetReadLinks(StringBuilder sb, string html, Uri baseUri, int take)
	{
		List<ChatBrowserSkillLink> links = ExtractBrowserSkillLinks(html, baseUri?.AbsoluteUri ?? "", Math.Min(120, take));
		if (links.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("[Links]");
		foreach (ChatBrowserSkillLink link in links.Take(take))
		{
			sb.AppendLine(link.Index.ToString(CultureInfo.InvariantCulture) + ". " + FirstNonEmpty(link.Text, "(untitled link)") + " - " + link.Href);
		}
	}

	private void AppendInternetReadControls(StringBuilder sb, string html, int take)
	{
		List<string> controls = new List<string>();
		foreach (Match match in Regex.Matches(html ?? "", "<(?<tag>input)\\b(?<attrs>[^>]*)/?>|<(?<tag>textarea|select|button)\\b(?<attrs>[^>]*)>(?<inner>[\\s\\S]*?)</\\k<tag>>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
		{
			string tag = match.Groups["tag"].Value.ToLowerInvariant();
			string attrs = match.Groups["attrs"].Value;
			string type = FirstNonEmpty(ExtractHtmlAttribute(attrs, "type"), tag);
			string name = FirstNonEmpty(ExtractHtmlAttribute(attrs, "name"), ExtractHtmlAttribute(attrs, "id"), "");
			string label = FirstNonEmpty(ExtractHtmlAttribute(attrs, "aria-label"), ExtractHtmlAttribute(attrs, "placeholder"), ExtractHtmlAttribute(attrs, "title"), CleanSearchHtml(match.Groups["inner"].Value));
			string value = ExtractHtmlAttribute(attrs, "value") ?? "";
			bool sensitive = IsSensitiveFormField(type, name);
			StringBuilder row = new StringBuilder();
			row.Append((controls.Count + 1).ToString(CultureInfo.InvariantCulture)).Append(". ").Append(tag).Append(" type=").Append(type);
			if (!string.IsNullOrWhiteSpace(name))
			{
				row.Append(" name=").Append(name);
			}
			if (!string.IsNullOrWhiteSpace(label))
			{
				row.Append(" label=\"").Append(TruncateForLog(NormalizeBrowserSkillText(label), 180)).Append("\"");
			}
			if (!string.IsNullOrWhiteSpace(value) && !sensitive)
			{
				row.Append(" value=\"").Append(TruncateForLog(NormalizeBrowserSkillText(value), 120)).Append("\"");
			}
			else if (sensitive)
			{
				row.Append(" value=(redacted)");
			}
			controls.Add(row.ToString());
			if (controls.Count >= take)
			{
				break;
			}
		}
		if (controls.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("[Forms and controls]");
		foreach (string control in controls)
		{
			sb.AppendLine(control);
		}
	}

	private bool IsSensitiveFormField(string type, string name)
	{
		string value = ((type ?? "") + " " + (name ?? "")).ToLowerInvariant();
		return value.Contains("password") || value.Contains("token") || value.Contains("secret") || value.Contains("auth") || value.Contains("csrf") || value.Contains("session") || value.Contains("cookie") || value.Contains("key");
	}

	private void AppendInternetReadTables(StringBuilder sb, string html, int take)
	{
		List<string> tables = new List<string>();
		int tableIndex = 0;
		foreach (Match tableMatch in Regex.Matches(html ?? "", "<table\\b[^>]*>(?<body>[\\s\\S]*?)</table>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
		{
			tableIndex++;
			List<string> rows = new List<string>();
			foreach (Match rowMatch in Regex.Matches(tableMatch.Groups["body"].Value, "<tr\\b[^>]*>(?<row>[\\s\\S]*?)</tr>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
			{
				List<string> cells = new List<string>();
				foreach (Match cellMatch in Regex.Matches(rowMatch.Groups["row"].Value, "<t[hd]\\b[^>]*>(?<cell>[\\s\\S]*?)</t[hd]>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
				{
					string cell = NormalizeBrowserSkillText(HtmlToBrowserSkillText(cellMatch.Groups["cell"].Value));
					cells.Add(TruncateForLog(cell, 140));
					if (cells.Count >= 8)
					{
						break;
					}
				}
				if (cells.Count > 0)
				{
					rows.Add("| " + string.Join(" | ", cells.Select(EscapeMarkdownTableCell)) + " |");
				}
				if (rows.Count >= 20)
				{
					break;
				}
			}
			if (rows.Count > 0)
			{
				tables.Add("table " + tableIndex.ToString(CultureInfo.InvariantCulture) + ":\n" + string.Join(Environment.NewLine, rows));
			}
			if (tables.Count >= Math.Min(8, take))
			{
				break;
			}
		}
		if (tables.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("[Tables]");
		foreach (string table in tables)
		{
			sb.AppendLine(table);
		}
	}

	private static string EscapeMarkdownTableCell(string value)
	{
		return (value ?? "").Replace("|", "\\|");
	}

	private void AppendInternetReadLists(StringBuilder sb, string html, int take)
	{
		List<string> lists = new List<string>();
		int listIndex = 0;
		foreach (Match listMatch in Regex.Matches(html ?? "", "<(?<tag>ul|ol)\\b[^>]*>(?<body>[\\s\\S]*?)</\\k<tag>>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
		{
			listIndex++;
			List<string> items = new List<string>();
			foreach (Match itemMatch in Regex.Matches(listMatch.Groups["body"].Value, "<li\\b[^>]*>(?<item>[\\s\\S]*?)</li>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
			{
				string item = NormalizeBrowserSkillText(HtmlToBrowserSkillText(itemMatch.Groups["item"].Value));
				if (!string.IsNullOrWhiteSpace(item))
				{
					items.Add("- " + TruncateForLog(item, 240));
				}
				if (items.Count >= 20)
				{
					break;
				}
			}
			if (items.Count > 0)
			{
				lists.Add("list " + listIndex.ToString(CultureInfo.InvariantCulture) + ":\n" + string.Join(Environment.NewLine, items));
			}
			if (lists.Count >= Math.Min(8, take))
			{
				break;
			}
		}
		if (lists.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("[Lists]");
		foreach (string list in lists)
		{
			sb.AppendLine(list);
		}
	}

	private void AppendInternetReadSelectorMatches(StringBuilder sb, string html, Uri baseUri, string selector, int take)
	{
		if (string.IsNullOrWhiteSpace(selector))
		{
			return;
		}
		List<string> matches = FindSimpleHtmlSelectorMatches(html, selector, baseUri, Math.Min(40, take));
		sb.AppendLine();
		sb.AppendLine("[Selector matches: " + selector.Trim() + "]");
		if (matches.Count == 0)
		{
			sb.AppendLine("No matching elements found by the simple selector matcher.");
			return;
		}
		foreach (string match in matches)
		{
			sb.AppendLine(match);
		}
	}

	private List<string> FindSimpleHtmlSelectorMatches(string html, string selector, Uri baseUri, int take)
	{
		List<string> results = new List<string>();
		selector = (selector ?? "").Trim();
		if (string.IsNullOrWhiteSpace(html) || string.IsNullOrWhiteSpace(selector))
		{
			return results;
		}
		string tagFilter = "";
		string idFilter = "";
		string classFilter = "";
		if (selector.StartsWith("#", StringComparison.Ordinal))
		{
			idFilter = selector.Substring(1);
		}
		else if (selector.StartsWith(".", StringComparison.Ordinal))
		{
			classFilter = selector.Substring(1);
		}
		else
		{
			Match parsed = Regex.Match(selector, "^(?<tag>[a-zA-Z][\\w:-]*)(?:\\.(?<class>[\\w:-]+))?(?:#(?<id>[\\w:-]+))?$", RegexOptions.CultureInvariant);
			if (!parsed.Success)
			{
				return results;
			}
			tagFilter = parsed.Groups["tag"].Value;
			classFilter = parsed.Groups["class"].Value;
			idFilter = parsed.Groups["id"].Value;
		}
		foreach (Match match in Regex.Matches(html, "<(?<tag>[a-zA-Z][\\w:-]*)\\b(?<attrs>[^>]*)>(?<inner>[\\s\\S]*?)</\\k<tag>>|<(?<selftag>input|img|meta|link|br|hr)\\b(?<selfattrs>[^>]*)/?>", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
		{
			string tag = FirstNonEmpty(match.Groups["tag"].Value, match.Groups["selftag"].Value);
			string attrs = FirstNonEmpty(match.Groups["attrs"].Value, match.Groups["selfattrs"].Value);
			if (!string.IsNullOrWhiteSpace(tagFilter) && !string.Equals(tag, tagFilter, StringComparison.OrdinalIgnoreCase))
			{
				continue;
			}
			if (!string.IsNullOrWhiteSpace(idFilter) && !string.Equals(ExtractHtmlAttribute(attrs, "id") ?? "", idFilter, StringComparison.OrdinalIgnoreCase))
			{
				continue;
			}
			if (!string.IsNullOrWhiteSpace(classFilter) && !HtmlClassListContains(ExtractHtmlAttribute(attrs, "class"), classFilter))
			{
				continue;
			}
			string text = NormalizeBrowserSkillText(HtmlToBrowserSkillText(match.Groups["inner"].Value));
			string href = FirstNonEmpty(ExtractHtmlAttribute(attrs, "href"), ExtractHtmlAttribute(attrs, "src"), ExtractHtmlAttribute(attrs, "action"));
			if (!string.IsNullOrWhiteSpace(href) && baseUri != null && Uri.TryCreate(baseUri, href, out Uri resolved))
			{
				href = resolved.AbsoluteUri;
			}
			results.Add((results.Count + 1).ToString(CultureInfo.InvariantCulture) + ". <" + tag.ToLowerInvariant() + ">" + (string.IsNullOrWhiteSpace(text) ? "" : (" " + TruncateForLog(text, 300))) + (string.IsNullOrWhiteSpace(href) ? "" : (" - " + href)));
			if (results.Count >= take)
			{
				break;
			}
		}
		return results;
	}

	private bool HtmlClassListContains(string classValue, string className)
	{
		if (string.IsNullOrWhiteSpace(classValue) || string.IsNullOrWhiteSpace(className))
		{
			return false;
		}
		return Regex.IsMatch(classValue, "(^|\\s)" + Regex.Escape(className) + "(\\s|$)", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
	}

	private string ExtractHtmlAttribute(string attrs, string name)
	{
		if (string.IsNullOrWhiteSpace(attrs) || string.IsNullOrWhiteSpace(name))
		{
			return "";
		}
		Match match = Regex.Match(attrs, "(^|\\s)" + Regex.Escape(name) + "\\s*=\\s*(?:\"(?<v>[^\"]*)\"|'(?<v>[^']*)'|(?<v>[^\\s>]+))", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		return match.Success ? WebUtility.HtmlDecode(match.Groups["v"].Value ?? "") : "";
	}

	private async Task<string> ExecuteInternetSearchServiceCompatibleAsync(string query, int take)
	{
		int offset = 0;
		string url = "https://html.duckduckgo.com/html/?q=" + Uri.EscapeDataString(query) + "&s=" + offset + "&dc=" + (offset + 1);
		string summary = SummarizeDuckDuckGoHtmlSearch(await GetStringWithUserAgentAsync(url), query, take);
		if (!summary.Contains("No results parsed", StringComparison.OrdinalIgnoreCase))
		{
			return "[SearchInternet service]\n" + summary;
		}
		return "[SearchInternet service]\n" + await ExecuteBingRssSearchAsync(query, take);
	}

	private async Task<string> ExecuteBingRssSearchAsync(string query, int take)
	{
		string url = "https://www.bing.com/search?format=rss&q=" + Uri.EscapeDataString(query);
		string xml = await GetStringWithUserAgentAsync(url);
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("Internet search results for: " + query);
		sb.AppendLine("Cite web-backed claims with bracket citations like [1], [2], then include these source links at the bottom of the answer.");
		sb.AppendLine();
		List<(int Number, string Title, string Url)> sources = new List<(int, string, string)>();
		try
		{
			MatchCollection matches = Regex.Matches(xml ?? "", "<item>[\\s\\S]*?<title>(?<title>[\\s\\S]*?)</title>[\\s\\S]*?<link>(?<url>[\\s\\S]*?)</link>[\\s\\S]*?(?:<description>(?<snippet>[\\s\\S]*?)</description>)?[\\s\\S]*?</item>", RegexOptions.IgnoreCase);
			int count = 0;
			foreach (Match match in matches)
			{
				if (match.Success)
				{
					count++;
					string title = CleanSearchHtml(match.Groups["title"].Value);
					string resultUrl = WebUtility.HtmlDecode(match.Groups["url"].Value ?? "").Trim();
					sb.Append(count.ToString()).Append(". [").Append(count.ToString())
						.Append("] ")
						.AppendLine(title);
					sb.AppendLine("   URL: " + resultUrl);
					string snippet = CleanSearchHtml(match.Groups["snippet"].Value);
					if (!string.IsNullOrWhiteSpace(snippet))
					{
						sb.AppendLine("   " + TruncateForLog(snippet, 260));
					}
					if (!string.IsNullOrWhiteSpace(resultUrl))
					{
						sources.Add((count, title, resultUrl));
					}
					if (count >= take)
					{
						break;
					}
				}
			}
			if (count == 0)
			{
				sb.AppendLine("No results found.");
			}
			else
			{
				AppendCitationSources(sb, sources);
			}
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			sb.AppendLine("Bing RSS fallback parse failed: " + ex2.Message);
		}
		return sb.ToString();
	}

	private async Task<string> ExecuteDownloadFileAsync(string argumentsJson, string ownerKey, string sessionId)
	{
		string url = ExtractJsonStringProperty(argumentsJson, "url");
		string fileName = FirstNonEmpty(ExtractJsonStringProperty(argumentsJson, "fileName"), ExtractJsonStringProperty(argumentsJson, "filename"), ExtractJsonStringProperty(argumentsJson, "name"), ExtractJsonStringProperty(argumentsJson, "saveAs"));
		bool explicitFileName = !string.IsNullOrWhiteSpace(fileName);
		if (string.IsNullOrWhiteSpace(url))
		{
			LogMessage("[Chat Storage] download_file rejected: url is required.");
			return "download_file error: url is required.";
		}
		if (!Uri.TryCreate(url, UriKind.Absolute, out Uri uri) || (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps))
		{
			LogMessage("[Chat Storage] download_file rejected: only http and https URLs are allowed.");
			return "download_file error: only http and https URLs are allowed.";
		}
		if (!TryValidateBrowserDestination(uri, BrowserPrivateNetworkAccessEnabled, out var destinationReason))
		{
			return "download_file blocked: " + destinationReason + "\nNo file was saved.\nurl: " + uri.AbsoluteUri;
		}
		sessionId = EnsureChatUiSessionId(sessionId);
		string sessionRoot = GetChatSessionFilesDirectory(sessionId);
		string downloadsRoot = Path.Combine(sessionRoot, "Downloads");
		string downloadsDisplayPath = ToChatSessionVirtualPath(sessionId, downloadsRoot);
		string sourceLabel = TruncateForLog(uri.Host + uri.AbsolutePath, 180);
		LogMessage("[Chat Storage] download_file started for " + sourceLabel + " in session " + sessionId + ".");
		string requestedUrl = url;
		if (string.IsNullOrWhiteSpace(fileName))
		{
			fileName = Path.GetFileName(uri.LocalPath);
		}
		fileName = SanitizeFileName(string.IsNullOrWhiteSpace(fileName) ? "download.bin" : fileName);
		string targetPath = BuildDownloadTargetPath(downloadsRoot, fileName);
		string redirectedFrom = null;
		string readmeUrl = null;
		ChatBrowserClientSession browserSession = GetOrCreateChatBrowserClientSession(ownerKey, sessionId);
		HttpResponseMessage response = await SendValidatedBrowserGetAsync(browserSession.ReadClient, uri, (request, target) =>
		{
			request.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-LmVsProxy/1.0");
			request.Headers.TryAddWithoutValidation("Accept", BuildDownloadAcceptHeader());
		}).ConfigureAwait(continueOnCapturedContext: false);
		bool flag = !response.IsSuccessStatusCode && response.StatusCode == HttpStatusCode.NotFound;
		bool flag2 = flag;
		if (flag2)
		{
			string value;
			readmeUrl = (value = await TryResolveGitHubReadmeRawUrlAsync(uri));
			flag2 = !string.IsNullOrWhiteSpace(value);
		}
		if (flag2)
		{
			response.Dispose();
			redirectedFrom = url;
			url = readmeUrl;
			uri = new Uri(readmeUrl);
			if (!explicitFileName)
			{
				fileName = SanitizeFileName(Path.GetFileName(uri.LocalPath));
				if (string.IsNullOrWhiteSpace(fileName))
				{
					fileName = "README.md";
				}
				targetPath = BuildDownloadTargetPath(downloadsRoot, fileName);
			}
			response = await SendValidatedBrowserGetAsync(browserSession.ReadClient, uri, (request, target) =>
			{
				request.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-LmVsProxy/1.0");
				request.Headers.TryAddWithoutValidation("Accept", BuildDownloadAcceptHeader());
			}).ConfigureAwait(continueOnCapturedContext: false);
		}
		using (response)
		{
			if (!response.IsSuccessStatusCode)
			{
				LogMessage("[Chat Storage] download_file failed for " + sourceLabel + ": HTTP " + ((int)response.StatusCode).ToString(CultureInfo.InvariantCulture) + " " + response.ReasonPhrase + ".");
				return "download_file error: " + (int)response.StatusCode + " " + response.ReasonPhrase + "\nNo file was saved.\nurl: " + requestedUrl + "\ndownloadsFolder: " + downloadsDisplayPath;
			}
			long? contentLength = response.Content?.Headers?.ContentLength;
			if (contentLength.HasValue && contentLength.Value > 26214400)
			{
				LogMessage("[Chat Storage] download_file blocked for " + sourceLabel + ": content-length exceeded 25 MB.");
				return "download_file blocked: file is larger than the 25 MB limit.\nNo file was saved.\nurl: " + url + "\ndownloadsFolder: " + downloadsDisplayPath;
			}
			if (contentLength.HasValue && !EnsureChatStorageCanAdd(ownerKey, sessionId, contentLength.Value, out var snapshot, out var contentLengthStorageError))
			{
				LogMessage("[Chat Storage] download_file blocked for " + sourceLabel + ": " + contentLengthStorageError);
				return "download_file blocked: " + contentLengthStorageError + "\nNo file was saved.\nurl: " + url + "\ndownloadsFolder: " + downloadsDisplayPath;
			}
			string contentType = response.Content?.Headers?.ContentType?.ToString() ?? "application/octet-stream";
			if (!explicitFileName)
			{
				string inferredFileName = InferDownloadFileName(uri, response, fileName);
				if (!string.Equals(fileName, inferredFileName, StringComparison.OrdinalIgnoreCase))
				{
					fileName = inferredFileName;
					targetPath = BuildDownloadTargetPath(downloadsRoot, fileName);
				}
			}
			long total = 0L;
			byte[] buffer = new byte[81920];
			using MemoryStream output = new MemoryStream();
			using (Stream input = await response.Content.ReadAsStreamAsync())
			{
				while (true)
				{
					int read = await input.ReadAsync(buffer, 0, buffer.Length);
					if (read <= 0)
					{
						break;
					}
					total += read;
					if (total > 26214400)
					{
						LogMessage("[Chat Storage] download_file blocked for " + sourceLabel + ": streamed content exceeded 25 MB.");
						return "download_file blocked: file exceeded the 25 MB limit.\nNo file was saved.\nurl: " + url + "\ndownloadsFolder: " + downloadsDisplayPath;
					}
					if (!EnsureChatStorageCanAdd(ownerKey, sessionId, total, out snapshot, out var streamStorageError))
					{
						LogMessage("[Chat Storage] download_file blocked for " + sourceLabel + ": " + streamStorageError);
						return "download_file blocked: " + streamStorageError + "\nNo file was saved.\nurl: " + url + "\ndownloadsFolder: " + downloadsDisplayPath;
					}
					await output.WriteAsync(buffer, 0, read);
					streamStorageError = null;
				}
			}
			ChatSessionFile file = new ChatSessionFile
			{
				id = "download_" + Guid.NewGuid().ToString("N"),
				name = fileName,
				type = contentType,
				size = (int)((total > int.MaxValue) ? int.MaxValue : total),
				path = targetPath,
				uploadedUtc = DateTimeOffset.UtcNow.ToString("O")
			};
			try
			{
				string sandboxSessionId;
				SandboxFileEntry entry = WriteChatSessionFileBytesToSandbox(sessionId, ownerKey, targetPath, output.ToArray(), "downloaded-file", out sandboxSessionId);
				AttachSandboxMetadata(sessionId, ownerKey, file, entry, sandboxSessionId);
				RegisterChatSessionFile(sessionId, ownerKey, file);
			}
			catch (Exception ex)
			{
				LogMessage("[Chat Storage] download_file blocked for " + sourceLabel + ": SocketJack Sandbox refused the session file. " + ex.Message);
				return "download_file blocked: SocketJack Sandbox refused the session file: " + ex.Message + "\nNo file was saved.\nurl: " + url + "\ndownloadsFolder: " + downloadsDisplayPath;
			}
			LogMessage("[Chat Storage] download_file saved " + fileName + " (" + total.ToString(CultureInfo.InvariantCulture) + " bytes) in session " + sessionId + ".");
			string targetDisplayPath = ToChatSessionVirtualPath(sessionId, targetPath);
			return "Downloaded file to the current session Downloads folder." + (string.IsNullOrWhiteSpace(redirectedFrom) ? "" : ("\nrequestedUrl: " + redirectedFrom)) + "\nurl: " + url + "\nsessionId: " + sessionId + "\ndownloadsFolder: " + downloadsDisplayPath + "\npath: " + targetDisplayPath + "\nsavedPath: " + targetDisplayPath + "\nread_file arguments: {\"path\":\"" + EscapeJson(targetDisplayPath) + "\"}\nbytes: " + total + "\ncontent-type: " + contentType + (string.IsNullOrWhiteSpace(redirectedFrom) ? "" : "\nNote: the requested GitHub raw URL returned 404, so LmVsProxy resolved and downloaded the repository README instead.") + "\nNext step: call read_file with savedPath if you need to inspect the downloaded file. Do not call read_file on the original URL.";
		}
	}

	private string BuildDownloadTargetPath(string downloadsRoot, string fileName)
	{
		return Path.Combine(downloadsRoot, DateTime.UtcNow.ToString("yyyyMMddHHmmss") + "_" + Guid.NewGuid().ToString("N").Substring(0, 8) + "_" + SanitizeFileName(string.IsNullOrWhiteSpace(fileName) ? "download.bin" : fileName));
	}

	private string BuildDownloadAcceptHeader()
	{
		return "text/html,application/xhtml+xml,application/xml;q=0.9,text/plain;q=0.85,application/json;q=0.8,application/octet-stream;q=0.75,*/*;q=0.6";
	}

	private string InferDownloadFileName(Uri uri, HttpResponseMessage response, string fallbackFileName)
	{
		string contentDispositionName = FirstNonEmpty(response?.Content?.Headers?.ContentDisposition?.FileNameStar, response?.Content?.Headers?.ContentDisposition?.FileName);
		contentDispositionName = TrimContentDispositionFileName(contentDispositionName);
		if (!string.IsNullOrWhiteSpace(contentDispositionName))
		{
			return SanitizeFileName(contentDispositionName);
		}
		string urlFileName = Path.GetFileName(uri?.LocalPath ?? "") ?? "";
		bool fileNameCameFromHost = string.IsNullOrWhiteSpace(urlFileName);
		string fileName = (fileNameCameFromHost ? FirstNonEmpty(uri?.Host, fallbackFileName, "download") : urlFileName);
		string contentType = response?.Content?.Headers?.ContentType?.MediaType ?? response?.Content?.Headers?.ContentType?.ToString() ?? "";
		string extension = (fileNameCameFromHost ? "" : Path.GetExtension(fileName));
		if (IsHtmlContentType(contentType) && (string.IsNullOrWhiteSpace(extension) || extension.Equals(".bin", StringComparison.OrdinalIgnoreCase)))
		{
			fileName = (fileNameCameFromHost ? (fileName + ".html") : Path.ChangeExtension(fileName, ".html"));
		}
		else if (IsJsonContentType(contentType) && (string.IsNullOrWhiteSpace(extension) || extension.Equals(".bin", StringComparison.OrdinalIgnoreCase)))
		{
			fileName = (fileNameCameFromHost ? (fileName + ".json") : Path.ChangeExtension(fileName, ".json"));
		}
		else if (IsTextContentType(contentType) && (string.IsNullOrWhiteSpace(extension) || extension.Equals(".bin", StringComparison.OrdinalIgnoreCase)))
		{
			fileName = (fileNameCameFromHost ? (fileName + ".txt") : Path.ChangeExtension(fileName, ".txt"));
		}
		return SanitizeFileName(string.IsNullOrWhiteSpace(fileName) ? FirstNonEmpty(fallbackFileName, "download.bin") : fileName);
	}

	private static string TrimContentDispositionFileName(string fileName)
	{
		fileName = (fileName ?? "").Trim();
		if (fileName.Length >= 2 && fileName[0] == '"' && fileName[fileName.Length - 1] == '"')
		{
			fileName = fileName.Substring(1, fileName.Length - 2);
		}
		return fileName.Trim();
	}

	private static bool IsHtmlContentType(string contentType)
	{
		contentType = (contentType ?? "").Trim().ToLowerInvariant();
		return contentType.StartsWith("text/html", StringComparison.Ordinal) || contentType.StartsWith("application/xhtml+xml", StringComparison.Ordinal);
	}

	private static bool IsJsonContentType(string contentType)
	{
		contentType = (contentType ?? "").Trim().ToLowerInvariant();
		return contentType.StartsWith("application/json", StringComparison.Ordinal) || contentType.EndsWith("+json", StringComparison.Ordinal);
	}

	private static bool IsTextContentType(string contentType)
	{
		contentType = (contentType ?? "").Trim().ToLowerInvariant();
		return contentType.StartsWith("text/", StringComparison.Ordinal);
	}

	private async Task<string> TryResolveGitHubReadmeRawUrlAsync(Uri failedUri)
	{
		if (!TryExtractGitHubRepository(failedUri, out var owner, out var repo))
		{
			return null;
		}
		try
		{
			string apiUrl = "https://api.github.com/repos/" + Uri.EscapeDataString(owner) + "/" + Uri.EscapeDataString(repo) + "/readme";
			using JsonDocument document = JsonDocument.Parse(await GetStringWithUserAgentAsync(apiUrl));
			string path = ExtractStringProperty(document.RootElement, "path");
			string htmlUrl = ExtractStringProperty(document.RootElement, "html_url");
			string branch = ExtractGitHubBranchFromBlobUrl(htmlUrl);
			if (!string.IsNullOrWhiteSpace(path) && !string.IsNullOrWhiteSpace(branch))
			{
				return "https://raw.githubusercontent.com/" + owner + "/" + repo + "/refs/heads/" + Uri.EscapeDataString(branch) + "/" + path.Replace("\\", "/");
			}
			string downloadUrl = ExtractStringProperty(document.RootElement, "download_url");
			if (!string.IsNullOrWhiteSpace(downloadUrl) && Uri.TryCreate(downloadUrl, UriKind.Absolute, out Uri rawUri) && rawUri.Scheme == Uri.UriSchemeHttps)
			{
				return downloadUrl;
			}
		}
		catch (Exception ex)
		{
			LogMessage("[download_file] GitHub README fallback failed for " + failedUri?.ToString() + ": " + ex.Message);
		}
		return null;
	}

	private bool TryExtractGitHubRepository(Uri uri, out string owner, out string repo)
	{
		owner = null;
		repo = null;
		if (uri == null || string.IsNullOrWhiteSpace(uri.Host))
		{
			return false;
		}
		string[] segments = uri.AbsolutePath.Trim('/').Split('/');
		if (segments.Length < 2)
		{
			return false;
		}
		if (uri.Host.Equals("raw.githubusercontent.com", StringComparison.OrdinalIgnoreCase) || uri.Host.Equals("github.com", StringComparison.OrdinalIgnoreCase))
		{
			owner = segments[0];
			repo = segments[1];
			if (repo.EndsWith(".git", StringComparison.OrdinalIgnoreCase))
			{
				repo = repo.Substring(0, repo.Length - 4);
			}
			return !string.IsNullOrWhiteSpace(owner) && !string.IsNullOrWhiteSpace(repo);
		}
		return false;
	}

	private string ExtractGitHubBranchFromBlobUrl(string htmlUrl)
	{
		if (string.IsNullOrWhiteSpace(htmlUrl) || !Uri.TryCreate(htmlUrl, UriKind.Absolute, out Uri uri) || !uri.Host.Equals("github.com", StringComparison.OrdinalIgnoreCase))
		{
			return null;
		}
		string[] segments = uri.AbsolutePath.Trim('/').Split('/');
		if (segments.Length < 5 || !segments[2].Equals("blob", StringComparison.OrdinalIgnoreCase))
		{
			return null;
		}
		return segments[3];
	}

	private async Task<string> ExecuteNuGetSearchAsync(string argumentsJson)
	{
		string query = ExtractJsonStringProperty(argumentsJson, "query");
		int take = ExtractIntFromToolArguments(argumentsJson, "take", 10);
		take = Math.Max(1, Math.Min(25, take));
		if (string.IsNullOrWhiteSpace(query))
		{
			return "nuget_search error: query is required.";
		}
		string url = "https://azuresearch-usnc.nuget.org/query?q=" + Uri.EscapeDataString(query) + "&take=" + take + "&prerelease=true&semVerLevel=2.0.0";
		return SummarizeNuGetSearch(await GetStringWithUserAgentAsync(url), query);
	}

	private async Task<string> ExecuteNuGetPackageInfoAsync(string argumentsJson)
	{
		string packageId = ExtractJsonStringProperty(argumentsJson, "packageId") ?? ExtractJsonStringProperty(argumentsJson, "id");
		if (string.IsNullOrWhiteSpace(packageId))
		{
			return "nuget_package_info error: packageId is required.";
		}
		string searchUrl = "https://azuresearch-usnc.nuget.org/query?q=packageid:" + Uri.EscapeDataString(packageId) + "&take=1&prerelease=true&semVerLevel=2.0.0";
		string searchJson = await GetStringWithUserAgentAsync(searchUrl);
		string registrationUrl = "https://api.nuget.org/v3/registration5-semver1/" + Uri.EscapeDataString(packageId.ToLowerInvariant()) + "/index.json";
		string registrationSummary;
		try
		{
			registrationSummary = SummarizeNuGetRegistration(await GetStringWithUserAgentAsync(registrationUrl));
		}
		catch (Exception ex)
		{
			registrationSummary = "Registration metadata unavailable: " + ex.Message;
		}
		return SummarizeNuGetSearch(searchJson, "packageid:" + packageId) + "\n\n" + registrationSummary;
	}

	private async Task<string> ExecuteGitHubCodeSearchAsync(string argumentsJson)
	{
		string query = ExtractJsonStringProperty(argumentsJson, "query");
		string repo = ExtractJsonStringProperty(argumentsJson, "repo");
		string language = ExtractJsonStringProperty(argumentsJson, "language");
		int take = ExtractIntFromToolArguments(argumentsJson, "take", 8);
		take = Math.Max(1, Math.Min(20, take));
		if (string.IsNullOrWhiteSpace(query))
		{
			return "github_code_search error: query is required.";
		}
		StringBuilder fullQuery = new StringBuilder(query.Trim());
		if (!string.IsNullOrWhiteSpace(repo))
		{
			fullQuery.Append(" repo:").Append(repo.Trim());
		}
		if (!string.IsNullOrWhiteSpace(language))
		{
			fullQuery.Append(" language:").Append(language.Trim());
		}
		string url = "https://api.github.com/search/code?q=" + Uri.EscapeDataString(fullQuery.ToString()) + "&per_page=" + take;
		try
		{
			return await SummarizeGitHubCodeSearchAsync(await GetStringWithUserAgentAsync(url), fullQuery.ToString(), query.Trim(), take);
		}
		catch (Exception ex)
		{
			return "github_code_search error: " + ex.Message + "\nTip: GitHub code search can be rate-limited without authentication. Try using a repo-qualified query from NuGet package repository metadata.";
		}
	}

	private async Task<string> GetStringWithUserAgentAsync(string url)
	{
		using HttpRequestMessage request = new HttpRequestMessage(HttpMethod.Get, url);
		request.Headers.TryAddWithoutValidation("User-Agent", "SocketJack-LmVsProxy/1.0");
		request.Headers.TryAddWithoutValidation("Accept", "application/json, text/plain;q=0.9, */*;q=0.8");
		using HttpResponseMessage response = await _httpClient.SendAsync(request);
		string text = ((response.Content != null) ? (await response.Content.ReadAsStringAsync()) : "");
		string body = text;
		if (!response.IsSuccessStatusCode)
		{
			throw new InvalidOperationException((int)response.StatusCode + " " + response.ReasonPhrase + ": " + TruncateForLog(body, 800));
		}
		return body;
	}

	private string SummarizeDuckDuckGoHtmlSearch(string html, string query, int take)
	{
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("Internet search results for: " + query);
		sb.AppendLine("Cite web-backed claims with bracket citations like [1], [2], then include these source links at the bottom of the answer.");
		sb.AppendLine();
		if (string.IsNullOrWhiteSpace(html))
		{
			sb.AppendLine("No response body returned.");
			return sb.ToString();
		}
		try
		{
			List<(int, string, string)> sources = new List<(int, string, string)>();
			MatchCollection matches = Regex.Matches(html, "<a[^>]+class=\"result__a\"[^>]+href=\"(?<url>[^\"]+)\"[^>]*>(?<title>[\\s\\S]*?)</a>", RegexOptions.IgnoreCase);
			int count = 0;
			foreach (Match match in matches)
			{
				if (!match.Success)
				{
					continue;
				}
				count++;
				string title = CleanSearchHtml(match.Groups["title"].Value);
				string url = WebUtility.HtmlDecode(match.Groups["url"].Value ?? "");
				url = DecodeDuckDuckGoRedirect(url);
				if (string.IsNullOrWhiteSpace(title) && string.IsNullOrWhiteSpace(url))
				{
					count--;
					continue;
				}
				string displayTitle = (string.IsNullOrWhiteSpace(title) ? "(untitled)" : title);
				sb.Append(count.ToString()).Append(". [").Append(count.ToString())
					.Append("] ")
					.AppendLine(displayTitle);
				if (!string.IsNullOrWhiteSpace(url))
				{
					sb.AppendLine("   URL: " + url);
					sources.Add((count, displayTitle, url));
				}
				if (count < take)
				{
					continue;
				}
				break;
			}
			if (count == 0)
			{
				sb.AppendLine("No results parsed from the search response.");
			}
			else
			{
				AppendCitationSources(sb, sources);
			}
		}
		catch (Exception ex)
		{
			sb.AppendLine("Could not parse search response: " + ex.Message);
			sb.AppendLine(TruncateForLog(CleanSearchHtml(html), 2000));
		}
		return sb.ToString();
	}

	private void AppendCitationSources(StringBuilder sb, List<(int Number, string Title, string Url)> sources)
	{
		if (sb == null || sources == null || sources.Count == 0)
		{
			return;
		}
		sb.AppendLine();
		sb.AppendLine("Sources:");
		foreach (var source in NormalizeCitationSources(sources))
		{
			sb.Append("[").Append(source.Number.ToString(CultureInfo.InvariantCulture)).Append("] ")
				.Append(string.IsNullOrWhiteSpace(source.Title) ? ("Source " + source.Number.ToString(CultureInfo.InvariantCulture)) : source.Title)
				.Append(" - ")
				.AppendLine(source.Url);
		}
	}

	private string CleanSearchHtml(string html)
	{
		if (string.IsNullOrWhiteSpace(html))
		{
			return "";
		}
		string text = Regex.Replace(html, "<[^>]+>", " ");
		text = WebUtility.HtmlDecode(text);
		return Regex.Replace(text ?? "", "\\s+", " ").Trim();
	}

	private string DecodeDuckDuckGoRedirect(string url)
	{
		if (string.IsNullOrWhiteSpace(url))
		{
			return "";
		}
		url = WebUtility.HtmlDecode(url).Trim();
		try
		{
			int marker = url.IndexOf("uddg=", StringComparison.OrdinalIgnoreCase);
			if (marker >= 0)
			{
				string encoded = url.Substring(marker + 5);
				int amp = encoded.IndexOf('&');
				if (amp >= 0)
				{
					encoded = encoded.Substring(0, amp);
				}
				return Uri.UnescapeDataString(encoded);
			}
		}
		catch
		{
		}
		return url;
	}

	private string SummarizeNuGetSearch(string json, string query)
	{
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("NuGet search results for: " + query);
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			if (!document.RootElement.TryGetProperty("data", out var data) || data.ValueKind != JsonValueKind.Array || data.GetArrayLength() == 0)
			{
				sb.AppendLine("No packages found.");
				return sb.ToString();
			}
			int index = 0;
			foreach (JsonElement item in data.EnumerateArray())
			{
				index++;
				string id = ExtractStringProperty(item, "id") ?? "(unknown)";
				string version = ExtractStringProperty(item, "version") ?? "";
				string description = ExtractStringProperty(item, "description") ?? "";
				string projectUrl = ExtractStringProperty(item, "projectUrl") ?? "";
				string repositoryUrl = ExtractStringProperty(item, "repositoryUrl") ?? "";
				JsonElement downloadsElement;
				long d;
				long downloads = ((item.TryGetProperty("totalDownloads", out downloadsElement) && downloadsElement.TryGetInt64(out d)) ? d : 0);
				sb.Append(index.ToString()).Append(". ").Append(id);
				if (!string.IsNullOrWhiteSpace(version))
				{
					sb.Append(" ").Append(version);
				}
				if (downloads > 0)
				{
					sb.Append(" downloads=").Append(downloads.ToString());
				}
				sb.AppendLine();
				if (!string.IsNullOrWhiteSpace(description))
				{
					sb.AppendLine("   " + TruncateForLog(description, 260));
				}
				if (!string.IsNullOrWhiteSpace(projectUrl))
				{
					sb.AppendLine("   project: " + projectUrl);
				}
				if (!string.IsNullOrWhiteSpace(repositoryUrl))
				{
					sb.AppendLine("   repo: " + repositoryUrl);
				}
			}
		}
		catch (Exception ex)
		{
			sb.AppendLine("Could not parse NuGet response: " + ex.Message);
			sb.AppendLine(TruncateForLog(json, 2000));
		}
		return sb.ToString();
	}

	private string SummarizeNuGetRegistration(string json)
	{
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("NuGet registration metadata:");
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			if (document.RootElement.TryGetProperty("items", out var pages) && pages.ValueKind == JsonValueKind.Array)
			{
				int pageCount = pages.GetArrayLength();
				sb.AppendLine("version page count: " + pageCount);
				if (pageCount > 0)
				{
					JsonElement lastPage = pages[pageCount - 1];
					if (lastPage.TryGetProperty("upper", out var upper) && upper.ValueKind == JsonValueKind.String)
					{
						sb.AppendLine("latest listed version: " + upper.GetString());
					}
					if (lastPage.TryGetProperty("items", out var versions) && versions.ValueKind == JsonValueKind.Array)
					{
						AppendLatestRegistrationLeaf(sb, versions);
					}
				}
			}
		}
		catch (Exception ex)
		{
			sb.AppendLine("Could not parse registration metadata: " + ex.Message);
		}
		return sb.ToString();
	}

	private void AppendLatestRegistrationLeaf(StringBuilder sb, JsonElement versions)
	{
		if (versions.GetArrayLength() != 0 && versions[versions.GetArrayLength() - 1].TryGetProperty("catalogEntry", out var catalog) && catalog.ValueKind == JsonValueKind.Object)
		{
			string description = ExtractStringProperty(catalog, "description");
			string projectUrl = ExtractStringProperty(catalog, "projectUrl");
			if (!string.IsNullOrWhiteSpace(description))
			{
				sb.AppendLine("description: " + TruncateForLog(description, 300));
			}
			if (!string.IsNullOrWhiteSpace(projectUrl))
			{
				sb.AppendLine("project: " + projectUrl);
			}
		}
	}

	private async Task<string> SummarizeGitHubCodeSearchAsync(string json, string query, string snippetNeedle, int take)
	{
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("GitHub code search results for: " + query);
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			if (!document.RootElement.TryGetProperty("items", out var items) || items.ValueKind != JsonValueKind.Array || items.GetArrayLength() == 0)
			{
				sb.AppendLine("No code results found.");
				return sb.ToString();
			}
			int index = 0;
			foreach (JsonElement item in items.EnumerateArray())
			{
				index++;
				string name = ExtractStringProperty(item, "name") ?? "";
				string path = ExtractStringProperty(item, "path") ?? "";
				string htmlUrl = ExtractStringProperty(item, "html_url") ?? "";
				string apiUrl = ExtractStringProperty(item, "url") ?? "";
				string repoName = "";
				if (item.TryGetProperty("repository", out var repoElement) && repoElement.ValueKind == JsonValueKind.Object)
				{
					repoName = ExtractStringProperty(repoElement, "full_name") ?? "";
				}
				sb.Append(index.ToString()).Append(". ");
				if (!string.IsNullOrWhiteSpace(repoName))
				{
					sb.Append(repoName).Append(" ");
				}
				sb.Append(string.IsNullOrWhiteSpace(path) ? name : path).AppendLine();
				if (!string.IsNullOrWhiteSpace(htmlUrl))
				{
					sb.AppendLine("   " + htmlUrl);
				}
				if (index <= 5 && !string.IsNullOrWhiteSpace(apiUrl))
				{
					string snippet = await TryFetchGitHubCodeSnippetAsync(apiUrl, snippetNeedle);
					if (!string.IsNullOrWhiteSpace(snippet))
					{
						sb.AppendLine(snippet);
					}
				}
				repoElement = default(JsonElement);
			}
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			sb.AppendLine("Could not parse GitHub response: " + ex2.Message);
			sb.AppendLine(TruncateForLog(json, 2000));
		}
		return sb.ToString();
	}

	private async Task<string> TryFetchGitHubCodeSnippetAsync(string apiUrl, string needle)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(await GetStringWithUserAgentAsync(apiUrl));
			if (!document.RootElement.TryGetProperty("content", out var contentElement) || contentElement.ValueKind != JsonValueKind.String)
			{
				return null;
			}
			string encoded = contentElement.GetString() ?? "";
			encoded = encoded.Replace("\n", "").Replace("\r", "");
			byte[] bytes = Convert.FromBase64String(encoded);
			string source = Encoding.UTF8.GetString(bytes);
			return BuildSourceSnippet(source, needle);
		}
		catch (Exception ex)
		{
			Exception ex2 = ex;
			return "   snippet unavailable: " + ex2.Message;
		}
	}

	private string BuildSourceSnippet(string source, string needle)
	{
		if (string.IsNullOrWhiteSpace(source))
		{
			return null;
		}
		string[] lines = source.Replace("\r\n", "\n").Replace('\r', '\n').Split('\n');
		int matchLine = -1;
		string[] tokens = (needle ?? "").Split(new char[15]
		{
			' ', '.', ':', '"', '\'', '(', ')', '[', ']', '{',
			'}', '<', '>', ',', ';'
		}, StringSplitOptions.RemoveEmptyEntries);
		for (int i = 0; i < lines.Length; i++)
		{
			string[] array = tokens;
			foreach (string token in array)
			{
				if (token.Length >= 3 && lines[i].IndexOf(token, StringComparison.OrdinalIgnoreCase) >= 0)
				{
					matchLine = i;
					break;
				}
			}
			if (matchLine >= 0)
			{
				break;
			}
		}
		if (matchLine < 0)
		{
			matchLine = 0;
		}
		int start = Math.Max(0, matchLine - 2);
		int end = Math.Min(lines.Length - 1, matchLine + 5);
		StringBuilder sb = new StringBuilder();
		sb.AppendLine("   snippet:");
		for (int k = start; k <= end; k++)
		{
			string line = lines[k];
			if (line.Length > 220)
			{
				line = line.Substring(0, 220) + "...";
			}
			sb.Append("   ").Append((k + 1).ToString()).Append(": ")
				.AppendLine(line);
		}
		return sb.ToString().TrimEnd();
	}

	private string BuildToolCallSseResponse(List<ToolCallData> toolCalls, string model)
	{
		DebounceForwardedToolCalls(toolCalls);
		if (toolCalls == null || toolCalls.Count == 0)
		{
			LogMessage("[Tool Calls] No executable tool calls remained after LmVsProxy filtering/debounce.");
			return BuildTextOnlySseResponse("No executable tool call remained after LmVsProxy filtering.", model);
		}
		long created = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
		string completionId = "chatcmpl_" + Guid.NewGuid().ToString("N");
		StringBuilder sb = new StringBuilder();
		sb.Append("data: {\"id\":\"").Append(completionId).Append("\",\"object\":\"chat.completion.chunk\",\"created\":")
			.Append(created)
			.Append(",\"model\":\"")
			.Append(EscapeJson(model ?? "lm-studio"))
			.Append("\",\"choices\":[{\"index\":0,\"delta\":{\"role\":\"assistant\"},\"finish_reason\":null}]}\n\n");
		for (int i = 0; i < toolCalls.Count; i++)
		{
			ToolCallData toolCall = toolCalls[i];
			string toolCallId = (toolCall.Id = ((!string.IsNullOrWhiteSpace(toolCall.Id)) ? toolCall.Id : ("call_" + Guid.NewGuid().ToString("N").Substring(0, 16))));
			LogMessage("[Tool Calls] [sse response] index=" + i + " id=" + toolCallId + " name=" + (toolCall.Name ?? "<missing>") + " args=" + TruncateForLog(toolCall.ArgumentsJson, 300));
			sb.Append("data: {\"id\":\"").Append(completionId).Append("\",\"object\":\"chat.completion.chunk\",\"created\":")
				.Append(created)
				.Append(",\"model\":\"")
				.Append(EscapeJson(model ?? "lm-studio"))
				.Append("\",\"choices\":[{\"index\":0,\"delta\":{\"tool_calls\":[{\"index\":")
				.Append(i)
				.Append(",\"id\":\"")
				.Append(toolCallId)
				.Append("\",\"type\":\"function\",\"function\":{\"name\":\"")
				.Append(EscapeJson(toolCall.Name))
				.Append("\",\"arguments\":\"")
				.Append(EscapeJson(toolCall.ArgumentsJson))
				.Append("\"}}]},\"finish_reason\":null}]}\n\n");
		}
		sb.Append("data: {\"id\":\"").Append(completionId).Append("\",\"object\":\"chat.completion.chunk\",\"created\":")
			.Append(created)
			.Append(",\"model\":\"")
			.Append(EscapeJson(model ?? "lm-studio"))
			.Append("\",\"choices\":[{\"index\":0,\"delta\":{},\"finish_reason\":\"tool_calls\"}]}\n\n");
		sb.Append("data: [DONE]\n\n");
		return sb.ToString();
	}

	private string ConvertChatSseToResponsesSse(string chatSse, string chatRequestBody, string responseId = null, long? createdOverride = null, bool skipCreatedEvent = false)
	{
		string model = ExtractJsonStringProperty(chatRequestBody, "model");
		if (string.IsNullOrWhiteSpace(model))
		{
			model = "lm-studio";
		}
		if (string.IsNullOrWhiteSpace(responseId))
		{
			responseId = "resp_" + Guid.NewGuid().ToString("N");
		}
		long created = createdOverride ?? DateTimeOffset.UtcNow.ToUnixTimeSeconds();
		StringBuilder text = new StringBuilder();
		Dictionary<int, ToolCallBuilder> builders = new Dictionary<int, ToolCallBuilder>();
		using (StringReader reader = new StringReader(chatSse ?? ""))
		{
			string line;
			while ((line = reader.ReadLine()) != null)
			{
				line = line.Trim();
				if (!line.StartsWith("data:", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				string data = DecodeChatUiSseFieldValue(line, 5);
				if (data.Trim().Length == 0 || data.Trim().Equals("[DONE]", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				try
				{
					int escapedCount;
					string safeData = EscapeInvalidJsonStringControlCharacters(data, out escapedCount);
					using JsonDocument document = JsonDocument.Parse(safeData);
					if (!document.RootElement.TryGetProperty("choices", out var choices) || choices.ValueKind != JsonValueKind.Array || choices.GetArrayLength() == 0 || !choices[0].TryGetProperty("delta", out var delta) || delta.ValueKind != JsonValueKind.Object)
					{
						continue;
					}
					if (delta.TryGetProperty("content", out var contentElement) && contentElement.ValueKind == JsonValueKind.String)
					{
						text.Append(contentElement.GetString());
					}
					if (!delta.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
					{
						continue;
					}
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						JsonElement indexElement;
						int parsedIndex;
						int index = ((toolCall.TryGetProperty("index", out indexElement) && indexElement.ValueKind == JsonValueKind.Number && indexElement.TryGetInt32(out parsedIndex)) ? parsedIndex : builders.Count);
						if (!builders.TryGetValue(index, out var builder))
						{
							builder = (builders[index] = new ToolCallBuilder());
						}
						if (toolCall.TryGetProperty("id", out var idElement) && idElement.ValueKind == JsonValueKind.String)
						{
							builder.Id = idElement.GetString();
						}
						if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
						{
							if (function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
							{
								builder.Name = nameElement.GetString();
							}
							if (function.TryGetProperty("arguments", out var argumentsElement))
							{
								string chunk = ((argumentsElement.ValueKind == JsonValueKind.String) ? argumentsElement.GetString() : argumentsElement.GetRawText());
								builder.Arguments.Append(chunk);
							}
						}
					}
				}
				catch (Exception ex)
				{
					LogMessage("[Responses Bridge] Could not parse chat SSE frame: " + ex.Message);
				}
			}
		}
		if (builders.Count > 0)
		{
			return BuildResponsesToolCallSse(responseId, created, model, builders, skipCreatedEvent);
		}
		return BuildResponsesTextSse(responseId, created, model, text.ToString(), skipCreatedEvent);
	}

	private string BuildResponsesTextSse(string responseId, long created, string model, string content, bool skipCreatedEvent = false)
	{
		string itemId = "msg_" + Guid.NewGuid().ToString("N");
		string safeContent = EscapeJson(content ?? "");
		StringBuilder sb = new StringBuilder();
		if (!skipCreatedEvent)
		{
			sb.Append("event: response.created\n");
			sb.Append("data: {\"type\":\"response.created\",\"response\":{\"id\":\"").Append(responseId).Append("\",\"object\":\"response\",\"created_at\":")
				.Append(created)
				.Append(",\"status\":\"in_progress\",\"model\":\"")
				.Append(EscapeJson(model))
				.Append("\",\"output\":[]}}\n\n");
		}
		sb.Append("event: response.output_item.added\n");
		sb.Append("data: {\"type\":\"response.output_item.added\",\"output_index\":0,\"item\":{\"id\":\"").Append(itemId).Append("\",\"type\":\"message\",\"status\":\"in_progress\",\"role\":\"assistant\",\"content\":[]}}\n\n");
		sb.Append("event: response.content_part.added\n");
		sb.Append("data: {\"type\":\"response.content_part.added\",\"item_id\":\"").Append(itemId).Append("\",\"output_index\":0,\"content_index\":0,\"part\":{\"type\":\"output_text\",\"text\":\"\"}}\n\n");
		if (!string.IsNullOrEmpty(content))
		{
			sb.Append("event: response.output_text.delta\n");
			sb.Append("data: {\"type\":\"response.output_text.delta\",\"item_id\":\"").Append(itemId).Append("\",\"output_index\":0,\"content_index\":0,\"delta\":\"")
				.Append(safeContent)
				.Append("\"}\n\n");
		}
		sb.Append("event: response.output_text.done\n");
		sb.Append("data: {\"type\":\"response.output_text.done\",\"item_id\":\"").Append(itemId).Append("\",\"output_index\":0,\"content_index\":0,\"text\":\"")
			.Append(safeContent)
			.Append("\"}\n\n");
		sb.Append("event: response.content_part.done\n");
		sb.Append("data: {\"type\":\"response.content_part.done\",\"item_id\":\"").Append(itemId).Append("\",\"output_index\":0,\"content_index\":0,\"part\":{\"type\":\"output_text\",\"text\":\"")
			.Append(safeContent)
			.Append("\"}}\n\n");
		sb.Append("event: response.output_item.done\n");
		sb.Append("data: {\"type\":\"response.output_item.done\",\"output_index\":0,\"item\":{\"id\":\"").Append(itemId).Append("\",\"type\":\"message\",\"status\":\"completed\",\"role\":\"assistant\",\"content\":[{\"type\":\"output_text\",\"text\":\"")
			.Append(safeContent)
			.Append("\"}]}}\n\n");
		sb.Append("event: response.completed\n");
		sb.Append("data: {\"type\":\"response.completed\",\"response\":{\"id\":\"").Append(responseId).Append("\",\"object\":\"response\",\"created_at\":")
			.Append(created)
			.Append(",\"status\":\"completed\",\"model\":\"")
			.Append(EscapeJson(model))
			.Append("\",\"output\":[{\"id\":\"")
			.Append(itemId)
			.Append("\",\"type\":\"message\",\"status\":\"completed\",\"role\":\"assistant\",\"content\":[{\"type\":\"output_text\",\"text\":\"")
			.Append(safeContent)
			.Append("\"}]}]}}\n\n");
		sb.Append("data: [DONE]\n\n");
		return sb.ToString();
	}

	private void DebounceForwardedToolCalls(List<ToolCallData> toolCalls)
	{
		if (toolCalls != null && toolCalls.Count != 0 && _upstreamAdapter != null)
		{
			int removed = toolCalls.RemoveAll((ToolCallData toolCall) => toolCall == null || !_upstreamAdapter.ShouldForwardToolCall(toolCall.Id, toolCall.Name, toolCall.ArgumentsJson));
			if (removed > 0)
			{
				LogMessage("[UpstreamAdapter] Debounced " + removed + " duplicate tool call(s) before forwarding to Visual Studio.");
			}
		}
	}

	private string BuildResponsesToolCallSse(string responseId, long created, string model, Dictionary<int, ToolCallBuilder> builders, bool skipCreatedEvent = false)
	{
		StringBuilder sb = new StringBuilder();
		if (!skipCreatedEvent)
		{
			sb.Append("event: response.created\n");
			sb.Append("data: {\"type\":\"response.created\",\"response\":{\"id\":\"").Append(responseId).Append("\",\"object\":\"response\",\"created_at\":")
				.Append(created)
				.Append(",\"status\":\"in_progress\",\"model\":\"")
				.Append(EscapeJson(model))
				.Append("\",\"output\":[]}}\n\n");
		}
		int outputIndex = 0;
		foreach (KeyValuePair<int, ToolCallBuilder> builder2 in builders)
		{
			ToolCallBuilder builder = builder2.Value;
			if (builder != null && !string.IsNullOrWhiteSpace(builder.Name))
			{
				string itemId = "fc_" + Guid.NewGuid().ToString("N");
				string callId = (string.IsNullOrWhiteSpace(builder.Id) ? ("call_" + Guid.NewGuid().ToString("N").Substring(0, 16)) : builder.Id);
				string arguments = builder.Arguments.ToString();
				sb.Append("event: response.output_item.added\n");
				sb.Append("data: {\"type\":\"response.output_item.added\",\"output_index\":").Append(outputIndex).Append(",\"item\":{\"id\":\"")
					.Append(itemId)
					.Append("\",\"type\":\"function_call\",\"status\":\"in_progress\",\"call_id\":\"")
					.Append(EscapeJson(callId))
					.Append("\",\"name\":\"")
					.Append(EscapeJson(builder.Name))
					.Append("\",\"arguments\":\"\"}}\n\n");
				sb.Append("event: response.function_call_arguments.delta\n");
				sb.Append("data: {\"type\":\"response.function_call_arguments.delta\",\"item_id\":\"").Append(itemId).Append("\",\"output_index\":")
					.Append(outputIndex)
					.Append(",\"delta\":\"")
					.Append(EscapeJson(arguments))
					.Append("\"}\n\n");
				sb.Append("event: response.function_call_arguments.done\n");
				sb.Append("data: {\"type\":\"response.function_call_arguments.done\",\"item_id\":\"").Append(itemId).Append("\",\"output_index\":")
					.Append(outputIndex)
					.Append(",\"arguments\":\"")
					.Append(EscapeJson(arguments))
					.Append("\"}\n\n");
				sb.Append("event: response.output_item.done\n");
				sb.Append("data: {\"type\":\"response.output_item.done\",\"output_index\":").Append(outputIndex).Append(",\"item\":{\"id\":\"")
					.Append(itemId)
					.Append("\",\"type\":\"function_call\",\"status\":\"completed\",\"call_id\":\"")
					.Append(EscapeJson(callId))
					.Append("\",\"name\":\"")
					.Append(EscapeJson(builder.Name))
					.Append("\",\"arguments\":\"")
					.Append(EscapeJson(arguments))
					.Append("\"}}\n\n");
				outputIndex++;
			}
		}
		sb.Append("event: response.completed\n");
		sb.Append("data: {\"type\":\"response.completed\",\"response\":{\"id\":\"").Append(responseId).Append("\",\"object\":\"response\",\"created_at\":")
			.Append(created)
			.Append(",\"status\":\"completed\",\"model\":\"")
			.Append(EscapeJson(model))
			.Append("\",\"output\":[]}}\n\n");
		sb.Append("data: [DONE]\n\n");
		return sb.ToString();
	}

	private string ExtractStreamedAssistantContent(string upstreamBody)
	{
		StringBuilder sb = new StringBuilder();
		using (StringReader reader = new StringReader(upstreamBody))
		{
			string line;
			while ((line = reader.ReadLine()) != null)
			{
				line = line.Trim();
				if (!line.StartsWith("data:", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				string data = DecodeChatUiSseFieldValue(line, 5);
				if (data.Trim().Equals("[DONE]", StringComparison.OrdinalIgnoreCase) || data.Trim().Length == 0)
				{
					continue;
				}
				try
				{
					int escapedControlCharacters;
					string safeData = EscapeInvalidJsonStringControlCharacters(data, out escapedControlCharacters);
					if (escapedControlCharacters > 0)
					{
						LogMessage($"[JSON Repair] Escaped {escapedControlCharacters} raw control character(s) in assistant content chunk.");
					}
					using JsonDocument document = JsonDocument.Parse(safeData);
					if (document.RootElement.TryGetProperty("choices", out var choices) && choices.ValueKind == JsonValueKind.Array && choices.GetArrayLength() != 0)
					{
						JsonElement choice = choices[0];
						JsonElement message;
						JsonElement messageContent;
						if (choice.TryGetProperty("delta", out var delta) && delta.ValueKind == JsonValueKind.Object && delta.TryGetProperty("content", out var deltaContent) && deltaContent.ValueKind == JsonValueKind.String)
						{
							sb.Append(deltaContent.GetString());
						}
						else if (choice.TryGetProperty("message", out message) && message.ValueKind == JsonValueKind.Object && message.TryGetProperty("content", out messageContent) && messageContent.ValueKind == JsonValueKind.String)
						{
							sb.Append(messageContent.GetString());
						}
					}
				}
				catch
				{
				}
			}
		}
		return sb.ToString();
	}

	private List<ToolCallData> ExtractQwenToolCalls(string content)
	{
		List<ToolCallData> result = new List<ToolCallData>();
		int searchStart = 0;
		while (searchStart < content.Length)
		{
			int start = FindQwenToolCallOpenTag(content, searchStart, out var openTagEnd, out var openTag);
			if (start < 0)
			{
				break;
			}
			int bodyStart = openTagEnd;
			int end = content.IndexOf("</tool_call>", bodyStart, StringComparison.OrdinalIgnoreCase);
			if (end < 0)
			{
				string trailingBody = content.Substring(bodyStart);
				ToolCallData parsedTrailing = ParseQwenToolCallBlock(openTag, trailingBody);
				if (parsedTrailing != null)
				{
					result.Add(parsedTrailing);
					break;
				}
				ToolCallData rescued = TryRescueTruncatedQwenToolCall(trailingBody);
				if (rescued != null)
				{
					result.Add(rescued);
				}
				break;
			}
			string body = content.Substring(bodyStart, end - bodyStart).Trim();
			ToolCallData parsed = ParseQwenToolCallBlock(openTag, body);
			if (parsed != null)
			{
				result.Add(parsed);
			}
			searchStart = end + "</tool_call>".Length;
		}
		return result;
	}

	private ToolCallData ParseQwenToolCallBlock(string openTag, string body)
	{
		string cleanedBody = (body ?? "").Trim();
		ToolCallData parsed = ParseQwenToolCall(cleanedBody);
		string id = ExtractToolCallTagAttribute(openTag, "id") ?? "";
		string nameFromTag = NormalizeLooseToolName(ExtractToolCallTagAttribute(openTag, "name") ?? ExtractToolCallTagAttribute(openTag, "tool") ?? ExtractToolCallTagAttribute(openTag, "function"));
		if (parsed != null)
		{
			if (string.IsNullOrWhiteSpace(parsed.Id) && !string.IsNullOrWhiteSpace(id))
			{
				parsed.Id = id;
			}
			if (string.IsNullOrWhiteSpace(parsed.Name) && !string.IsNullOrWhiteSpace(nameFromTag))
			{
				parsed.Name = nameFromTag;
			}
			return parsed;
		}
		string name = nameFromTag;
		if (string.IsNullOrWhiteSpace(name))
		{
			return null;
		}
		string arguments = ExtractQwenParameterTagBody(cleanedBody);
		if (string.IsNullOrWhiteSpace(arguments))
		{
			arguments = ExtractFirstJsonObject(cleanedBody);
		}
		if (string.IsNullOrWhiteSpace(arguments))
		{
			arguments = cleanedBody;
		}
		string argumentsJson = IsValidJsonObject(arguments)
			? NormalizeLooseToolArgumentsJson(name, arguments, default(JsonElement))
			: BuildPseudoToolArguments(name, CleanPseudoToolTagBody(arguments));
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			argumentsJson = "{}";
		}
		return new ToolCallData
		{
			Id = string.IsNullOrWhiteSpace(id) ? ("call_" + Guid.NewGuid().ToString("N").Substring(0, 16)) : id,
			Name = name,
			ArgumentsJson = RepairKnownToolArguments(name, argumentsJson),
			ArgumentsWereMalformed = true
		};
	}

	private string ExtractToolCallTagAttribute(string openTag, string attributeName)
	{
		if (string.IsNullOrWhiteSpace(openTag) || string.IsNullOrWhiteSpace(attributeName))
		{
			return null;
		}
		Match match = Regex.Match(openTag, "\\b" + Regex.Escape(attributeName) + "\\s*=\\s*(?:\"(?<value>[^\"]*)\"|'(?<value>[^']*)'|(?<value>[^\\s>]+))", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
		if (!match.Success)
		{
			return null;
		}
		return WebUtility.HtmlDecode(match.Groups["value"].Value ?? "").Trim();
	}

	private string ExtractQwenParameterTagBody(string body)
	{
		if (string.IsNullOrWhiteSpace(body))
		{
			return "";
		}
		Match match = Regex.Match(body, "(?is)<\\s*(?:arguments?|parameters?)\\b[^>]*>(?<body>[\\s\\S]*?)(?:<\\s*/\\s*(?:arguments?|parameters?)\\s*>|$)", RegexOptions.CultureInvariant);
		return match.Success ? match.Groups["body"].Value.Trim() : "";
	}

	private string ExtractFirstJsonObject(string text)
	{
		if (string.IsNullOrWhiteSpace(text))
		{
			return "";
		}
		int start = text.IndexOf('{');
		while (start >= 0)
		{
			int end = FindMatchingJsonObjectEnd(text, start);
			if (end > start)
			{
				return text.Substring(start, end - start + 1);
			}
			start = text.IndexOf('{', start + 1);
		}
		return "";
	}

	private IEnumerable<string> ExtractAssistantToolCandidateTexts(JsonElement message)
	{
		if (message.ValueKind != JsonValueKind.Object)
		{
			yield break;
		}
		JsonElement contentElement;
		if (message.TryGetProperty("content", out contentElement))
		{
			string content = ExtractResponsesContentText(contentElement);
			if (!string.IsNullOrWhiteSpace(content))
			{
				yield return content;
			}
		}
		if (TryExtractReasoningText(message, out var reasoning) && !string.IsNullOrWhiteSpace(reasoning))
		{
			yield return reasoning;
		}
		string[] names = new string[11] { "reasoning_content", "reasoningContent", "thinking", "thinking_content", "thinkingContent", "analysis", "analysis_content", "thought", "thought_content", "tool_text", "toolText" };
		foreach (string name in names)
		{
			if (TryGetMasterJsonProperty(message, name, out var value) && TryExtractStructuredChatText(value, out var text) && !string.IsNullOrWhiteSpace(text))
			{
				yield return text;
			}
		}
	}

	private List<ToolCallData> ExtractLooseProxyToolCalls(string content)
	{
		List<ToolCallData> result = new List<ToolCallData>();
		if (string.IsNullOrWhiteSpace(content))
		{
			return result;
		}
		HashSet<string> seen = new HashSet<string>(StringComparer.Ordinal);
		foreach (ToolCallData qwenToolCall in ExtractQwenToolCalls(content))
		{
			if (qwenToolCall == null || string.IsNullOrWhiteSpace(qwenToolCall.Name) || !IsProxyOwnedResearchTool(qwenToolCall.Name))
			{
				continue;
			}
			string key = qwenToolCall.Name + "\n" + (qwenToolCall.ArgumentsJson ?? "");
			if (seen.Add(key))
			{
				result.Add(qwenToolCall);
			}
		}
		if (result.Count > 0)
		{
			return result;
		}
		TryParsePseudoToolTags(content, result, seen);
		if (result.Count > 0)
		{
			return result;
		}
		string lower = content.ToLowerInvariant();
		if (!lower.Contains("tool_call", StringComparison.Ordinal) && !lower.Contains("\"name\"", StringComparison.Ordinal) && !lower.Contains("\"arguments\"", StringComparison.Ordinal))
		{
			return result;
		}
		for (int i = 0; i < content.Length; i++)
		{
			if (content[i] != '{')
			{
				continue;
			}
			int end = FindMatchingJsonObjectEnd(content, i);
			if (end <= i)
			{
				continue;
			}
			string candidate = content.Substring(i, end - i + 1);
			string candidateLower = candidate.ToLowerInvariant();
			if ((candidateLower.Contains("\"tool_call\"", StringComparison.Ordinal) || candidateLower.Contains("\"tool_calls\"", StringComparison.Ordinal) || (candidateLower.Contains("\"name\"", StringComparison.Ordinal) && candidateLower.Contains("\"arguments\"", StringComparison.Ordinal))) && TryParseLooseToolCallCandidate(candidate, result, seen))
			{
				i = end;
			}
		}
		if (result.Count == 0)
		{
			TryParseLooseToolCallSnippet(content, result, seen);
		}
		return result;
	}

	private bool TryParseLooseToolCallCandidate(string json, List<ToolCallData> result, HashSet<string> seen)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			return TryParseLooseToolCallElement(document.RootElement, result, seen);
		}
		catch
		{
			return false;
		}
	}

	private bool TryParseLooseToolCallElement(JsonElement element, List<ToolCallData> result, HashSet<string> seen)
	{
		if (element.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		bool added = false;
		if (element.TryGetProperty("tool_call", out var toolCall) && toolCall.ValueKind == JsonValueKind.Object)
		{
			added |= TryAddLooseToolCall(toolCall, result, seen);
		}
		if (element.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
		{
			foreach (JsonElement item in toolCalls.EnumerateArray())
			{
				added |= TryAddLooseToolCall(item, result, seen);
			}
		}
		added |= TryAddLooseToolCall(element, result, seen);
		return added;
	}

	private bool TryAddLooseToolCall(JsonElement element, List<ToolCallData> result, HashSet<string> seen)
	{
		if (element.ValueKind != JsonValueKind.Object)
		{
			return false;
		}
		ToolCallData parsed = ParseOpenAiToolCall(element);
		if (parsed == null)
		{
			string id = ExtractStringProperty(element, "id") ?? "";
			string name = ExtractStringProperty(element, "name") ?? ExtractStringProperty(element, "tool") ?? ExtractStringProperty(element, "toolName") ?? ExtractStringProperty(element, "function");
			name = NormalizeLooseToolName(name);
			if (string.IsNullOrWhiteSpace(name))
			{
				return false;
			}
			string arguments = "{}";
			if (element.TryGetProperty("arguments", out var argumentsElement) || element.TryGetProperty("args", out argumentsElement) || element.TryGetProperty("parameters", out argumentsElement) || element.TryGetProperty("parameter", out argumentsElement))
			{
				arguments = argumentsElement.ValueKind == JsonValueKind.String ? (argumentsElement.GetString() ?? "{}") : argumentsElement.GetRawText();
			}
			arguments = NormalizeLooseToolArgumentsJson(name, arguments, element);
			parsed = new ToolCallData
			{
				Id = string.IsNullOrWhiteSpace(id) ? ("call_" + Guid.NewGuid().ToString("N").Substring(0, 16)) : id,
				Name = name,
				ArgumentsJson = RepairKnownToolArguments(name, arguments),
				ArgumentsWereMalformed = false
			};
		}
		else
		{
			parsed.Name = NormalizeLooseToolName(parsed.Name);
			parsed.ArgumentsJson = NormalizeLooseToolArgumentsJson(parsed.Name, parsed.ArgumentsJson, element);
			parsed.ArgumentsJson = RepairKnownToolArguments(parsed.Name, parsed.ArgumentsJson);
		}
		if (string.IsNullOrWhiteSpace(parsed.Name) || !IsProxyOwnedResearchTool(parsed.Name))
		{
			return false;
		}
		string key = parsed.Name + "\n" + (parsed.ArgumentsJson ?? "");
		if (!seen.Add(key))
		{
			return false;
		}
		result.Add(parsed);
		LogMessage("[Tool Call Rescue] Parsed loose assistant tool call as " + parsed.Name + ".");
		return true;
	}

	private void TryParsePseudoToolTags(string content, List<ToolCallData> result, HashSet<string> seen)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return;
		}
		foreach (Match match in Regex.Matches(content, "(?is)<\\s*(?<tag>search_query|internet_search|browser_open|browser_read_page|browser_click_link|browser_click|browser_type|browser_select|browser_press|browser_find_text)\\b[^>]*>(?<body>[\\s\\S]*?)(?:<\\s*/\\s*\\k<tag>\\s*>|<\\s*/\\s*>|<\\s*/\\s*|$)", RegexOptions.CultureInvariant))
		{
			string tag = match.Groups["tag"].Value;
			string body = CleanPseudoToolTagBody(match.Groups["body"].Value);
			if (string.IsNullOrWhiteSpace(tag) || string.IsNullOrWhiteSpace(body))
			{
				continue;
			}
			string toolName = tag.Equals("search_query", StringComparison.OrdinalIgnoreCase) ? "internet_search" : tag.Trim().ToLowerInvariant();
			string argumentsJson = BuildPseudoToolArguments(toolName, body);
			if (string.IsNullOrWhiteSpace(argumentsJson))
			{
				continue;
			}
			string key = toolName + "\n" + argumentsJson;
			if (!seen.Add(key))
			{
				continue;
			}
			result.Add(new ToolCallData
			{
				Id = "call_" + Guid.NewGuid().ToString("N").Substring(0, 16),
				Name = toolName,
				ArgumentsJson = RepairKnownToolArguments(toolName, argumentsJson),
				ArgumentsWereMalformed = true
			});
			LogMessage("[Tool Call Rescue] Parsed pseudo tool tag as " + toolName + ".");
		}
	}

	private string CleanPseudoToolTagBody(string body)
	{
		string cleaned = (body ?? "").Replace("\r\n", "\n").Replace('\r', '\n').Trim();
		cleaned = Regex.Replace(cleaned, "<\\s*/?\\s*$", "", RegexOptions.CultureInvariant).Trim();
		cleaned = cleaned.Trim('`').Trim();
		if ((cleaned.StartsWith("\"", StringComparison.Ordinal) && cleaned.EndsWith("\"", StringComparison.Ordinal)) ||
		    (cleaned.StartsWith("'", StringComparison.Ordinal) && cleaned.EndsWith("'", StringComparison.Ordinal)))
		{
			cleaned = cleaned.Substring(1, cleaned.Length - 2).Trim();
		}
		return Regex.Replace(cleaned, "\\s+", " ", RegexOptions.CultureInvariant).Trim();
	}

	private string BuildPseudoToolArguments(string toolName, string body)
	{
		if (string.IsNullOrWhiteSpace(toolName) || string.IsNullOrWhiteSpace(body))
		{
			return "";
		}
		if (IsValidJsonObject(body))
		{
			return NormalizeLooseToolArgumentsJson(toolName, body, default(JsonElement));
		}
		switch (toolName.Trim().ToLowerInvariant())
		{
		case "internet_search":
			if (body.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || body.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
			{
				return "{\"action\":\"read\",\"url\":\"" + EscapeJson(body) + "\",\"take\":40}";
			}
			string searchQuery = NormalizeInternetSearchQueryCandidate(body);
			return "{\"action\":\"search\",\"query\":\"" + EscapeJson(searchQuery) + "\",\"take\":" + ExtractRequestedInternetSearchSourceCount(body, 8, 12).ToString(CultureInfo.InvariantCulture) + "}";
		case "browser_open":
			return "{\"url\":\"" + EscapeJson(body) + "\",\"take\":40}";
		case "browser_read_page":
			if (body.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || body.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
			{
				return "{\"url\":\"" + EscapeJson(body) + "\",\"take\":40}";
			}
			return "{}";
		case "browser_click_link":
			if (int.TryParse(body, NumberStyles.Integer, CultureInfo.InvariantCulture, out var index) && index > 0)
			{
				return "{\"index\":" + index.ToString(CultureInfo.InvariantCulture) + "}";
			}
			return "{\"text\":\"" + EscapeJson(body) + "\",\"take\":40}";
		case "browser_click":
			if (int.TryParse(body, NumberStyles.Integer, CultureInfo.InvariantCulture, out var controlIndex) && controlIndex > 0)
			{
				return "{\"index\":" + controlIndex.ToString(CultureInfo.InvariantCulture) + "}";
			}
			return "{\"text\":\"" + EscapeJson(body) + "\"}";
		case "browser_type":
			return "{\"text\":\"" + EscapeJson(body) + "\"}";
		case "browser_select":
			return "{\"value\":\"" + EscapeJson(body) + "\"}";
		case "browser_press":
			return "{\"key\":\"" + EscapeJson(body) + "\"}";
		case "browser_find_text":
			return "{\"query\":\"" + EscapeJson(body) + "\"}";
		default:
			return "";
		}
	}

	private void TryParseLooseToolCallSnippet(string content, List<ToolCallData> result, HashSet<string> seen)
	{
		Match match = Regex.Match(content ?? "", "(?is)\"id\"\\s*:\\s*\"(?<id>[^\"]+)\".{0,600}?\"name\"\\s*:\\s*\"(?<name>[^\"]+)\".{0,600}?\"arguments\"\\s*:\\s*(?<args>\\{[\\s\\S]*?\\})");
		if (!match.Success)
		{
			match = Regex.Match(content ?? "", "(?is)\"name\"\\s*:\\s*\"(?<name>[^\"]+)\".{0,600}?\"arguments\"\\s*:\\s*(?<args>\\{[\\s\\S]*?\\})");
		}
		if (!match.Success)
		{
			return;
		}
		string name = NormalizeLooseToolName(match.Groups["name"].Value);
		if (string.IsNullOrWhiteSpace(name) || !IsProxyOwnedResearchTool(name))
		{
			return;
		}
		string args = match.Groups["args"].Value.Trim();
		if (!IsValidJsonObject(args))
		{
			args = "{}";
		}
		ToolCallData parsed = new ToolCallData
		{
			Id = match.Groups["id"].Success ? match.Groups["id"].Value : ("call_" + Guid.NewGuid().ToString("N").Substring(0, 16)),
			Name = name,
			ArgumentsJson = RepairKnownToolArguments(name, NormalizeLooseToolArgumentsJson(name, args, default(JsonElement))),
			ArgumentsWereMalformed = true
		};
		string key = parsed.Name + "\n" + (parsed.ArgumentsJson ?? "");
		if (seen.Add(key))
		{
			result.Add(parsed);
			LogMessage("[Tool Call Rescue] Parsed loose assistant tool-call snippet as " + parsed.Name + ".");
		}
	}

	private int FindMatchingJsonObjectEnd(string text, int start)
	{
		bool inString = false;
		bool escaped = false;
		int depth = 0;
		for (int i = start; i < text.Length; i++)
		{
			char ch = text[i];
			if (inString)
			{
				if (escaped)
				{
					escaped = false;
				}
				else if (ch == '\\')
				{
					escaped = true;
				}
				else if (ch == '"')
				{
					inString = false;
				}
				continue;
			}
			if (ch == '"')
			{
				inString = true;
			}
			else if (ch == '{')
			{
				depth++;
			}
			else if (ch == '}')
			{
				depth--;
				if (depth == 0)
				{
					return i;
				}
			}
		}
		return -1;
	}

	private string NormalizeLooseToolName(string name)
	{
		string normalized = (name ?? "").Trim();
		switch (normalized.ToLowerInvariant())
		{
		case "write_file":
		case "create_file":
			return "vs_write_file";
		case "replace_in_file":
		case "edit_file":
			return "vs_replace_in_file";
		case "copy_file":
			return "vs_copy_file";
		case "rename_file":
			return "vs_rename_file";
		case "delete_file":
		case "remove_file":
			return "vs_delete_file";
		case "search_files":
		case "file_search":
			return "vs_search_files";
		case "list_files":
			return "vs_list_files";
		default:
			return normalized;
		}
	}

	private string NormalizeLooseToolArgumentsJson(string toolName, string argumentsJson, JsonElement sourceElement)
	{
		if (string.IsNullOrWhiteSpace(argumentsJson) || !IsValidJsonObject(argumentsJson))
		{
			argumentsJson = "{}";
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			JsonElement root = document.RootElement;
			if (toolName.Equals("vs_write_file", StringComparison.Ordinal))
			{
				string path = ExtractStringProperty(root, "path") ?? ExtractStringProperty(root, "filePath") ?? ExtractStringProperty(root, "filename") ?? ExtractStringProperty(root, "file_path");
				string content = ExtractStringProperty(root, "content") ?? ExtractStringProperty(root, "text") ?? "";
				bool overwrite = ReadJsonBool(GetPropertyOrNull(root, "overwrite") ?? default(JsonElement), fallback: false);
				return "{\"path\":\"" + EscapeJson(path ?? "") + "\",\"content\":\"" + EscapeJson(content ?? "") + "\",\"overwrite\":" + (overwrite ? "true" : "false") + "}";
			}
			if (toolName.Equals("vs_read_file", StringComparison.Ordinal) || toolName.Equals("read_file", StringComparison.Ordinal))
			{
				string path = ExtractStringProperty(root, "path") ?? ExtractStringProperty(root, "filePath") ?? ExtractStringProperty(root, "filename") ?? ExtractStringProperty(root, "file_path");
				if (!string.IsNullOrWhiteSpace(path))
				{
					return "{\"path\":\"" + EscapeJson(path) + "\"}";
				}
			}
		}
		catch
		{
		}
		return argumentsJson;
	}

	private ToolCallData TryRescueTruncatedQwenToolCall(string rawToolJson)
	{
		if (string.IsNullOrWhiteSpace(rawToolJson))
		{
			return null;
		}
		string raw = rawToolJson.Trim();
		string toolName = ExtractJsonStringPropertyFromMalformedText(raw, "name");
		if (string.IsNullOrWhiteSpace(toolName))
		{
			return null;
		}
		if (toolName.Equals("run_command_in_terminal", StringComparison.Ordinal))
		{
			string partialCommand = ExtractJsonStringPropertyFromMalformedText(raw, "command");
			string message = "Write-Host \"LmVsProxy blocked a malformed run_command_in_terminal tool call because the model ended before valid JSON was complete.\"";
			if (!string.IsNullOrWhiteSpace(partialCommand))
			{
				message = message + " ; Write-Host \"Partial command: " + EscapePowerShellDoubleQuotedString(TruncateForLog(partialCommand, 300)) + "\"";
			}
			LogMessage("[Tool Call Rescue] Blocked truncated run_command_in_terminal tool call: " + TruncateForLog(EscapeControlCharsForLog(raw), 500));
			return new ToolCallData
			{
				Id = "call_" + Guid.NewGuid().ToString("N").Substring(0, 16),
				Name = "run_command_in_terminal",
				ArgumentsJson = "{\"command\":\"" + EscapeJson(message) + "\",\"summary\":\"Malformed terminal tool call blocked by proxy\",\"background\":false}",
				ArgumentsWereMalformed = true
			};
		}
		LogMessage("[Tool Call Rescue] Dropped truncated " + toolName + " tool call because its JSON was incomplete: " + TruncateForLog(EscapeControlCharsForLog(raw), 500));
		return null;
	}

	private string ExtractJsonStringPropertyFromMalformedText(string text, string propertyName)
	{
		if (string.IsNullOrWhiteSpace(text) || string.IsNullOrWhiteSpace(propertyName))
		{
			return null;
		}
		Match match = Regex.Match(text, "\"" + Regex.Escape(propertyName) + "\"\\s*:\\s*\"(?<value>(?:\\\\.|[^\"\\\\])*)", RegexOptions.IgnoreCase | RegexOptions.Singleline);
		if (!match.Success)
		{
			return null;
		}
		string value = match.Groups["value"].Value;
		try
		{
			return JsonSerializer.Deserialize<string>("\"" + value + "\"");
		}
		catch
		{
			return value.Replace("\\\"", "\"").Replace("\\\\", "\\");
		}
	}

	private string EscapePowerShellDoubleQuotedString(string value)
	{
		return (value ?? "").Replace("`", "``").Replace("\"", "`\"").Replace("$", "`$");
	}

	private void LogToolCalls(string stage, List<ToolCallData> toolCalls)
	{
		try
		{
			if (toolCalls == null || toolCalls.Count == 0)
			{
				LogMessage("[Tool Calls] [" + stage + "] none");
				return;
			}
			List<string> parts = new List<string>();
			foreach (ToolCallData toolCall in toolCalls)
			{
				if (toolCall != null)
				{
					string args = toolCall.ArgumentsJson ?? "";
					if (args.Length > 180)
					{
						args = args.Substring(0, 180) + "...";
					}
					parts.Add(toolCall.Name + "(" + args + ")");
				}
			}
			LogMessage("[Tool Calls] [" + stage + "] " + string.Join("; ", parts));
		}
		catch
		{
		}
	}

	private bool IsToolChoiceNone(string requestBody)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			JsonElement toolChoice;
			return document.RootElement.TryGetProperty("tool_choice", out toolChoice) && toolChoice.ValueKind == JsonValueKind.String && toolChoice.GetString().Equals("none", StringComparison.OrdinalIgnoreCase);
		}
		catch
		{
			return false;
		}
	}

	private HashSet<string> GetAvailableToolNames(string requestBody)
	{
		HashSet<string> result = new HashSet<string>(StringComparer.Ordinal);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("tools", out var tools) || tools.ValueKind != JsonValueKind.Array)
			{
				return result;
			}
			foreach (JsonElement item in tools.EnumerateArray())
			{
				if (item.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
				{
					string name = nameElement.GetString();
					if (!string.IsNullOrWhiteSpace(name) && !name.Equals("multi_replace_string_in_file", StringComparison.Ordinal))
					{
						result.Add(name);
					}
				}
			}
		}
		catch
		{
		}
		return result;
	}

	private void RemapSuppressedToolCalls(List<ToolCallData> toolCalls, HashSet<string> availableTools, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0 || availableTools == null || availableTools.Count == 0)
		{
			return;
		}
		int historicalProjectCalls = CountHistoricalToolCalls(requestBody, "get_projects_in_solution");
		string projectPath = ExtractProjectPathFromToolResult(ExtractFirstToolResultForTool(requestBody, "get_projects_in_solution"));
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall != null && !string.IsNullOrWhiteSpace(toolCall.Name) && toolCall.Name.Equals("get_projects_in_solution", StringComparison.Ordinal) && availableTools.Contains("get_files_in_project") && historicalProjectCalls >= 1 && !string.IsNullOrWhiteSpace(projectPath))
			{
				toolCall.Name = "get_files_in_project";
				toolCall.ArgumentsJson = "{\"projectPath\":\"" + EscapeJson(NormalizeToolPathForVsArgument(projectPath.Trim())) + "\"}";
				LogMessage("[Tool Loop Redirect] Rewrote repeated get_projects_in_solution to get_files_in_project for " + projectPath.Trim());
			}
		}
	}

	private void NormalizeTerminalToolCalls(List<ToolCallData> toolCalls, HashSet<string> availableTools)
	{
		if (toolCalls == null || toolCalls.Count == 0 || availableTools == null || !availableTools.Contains("run_command_in_terminal"))
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall != null && !string.IsNullOrWhiteSpace(toolCall.Name) && !toolCall.Name.Equals("run_command_in_terminal", StringComparison.Ordinal) && IsTerminalCommandToolName(toolCall.Name))
			{
				string oldName = toolCall.Name;
				string command = BuildTerminalCommandRequest(toolCall.Name, toolCall.ArgumentsJson).Command;
				toolCall.Name = "run_command_in_terminal";
				toolCall.ArgumentsJson = "{\"command\":\"" + EscapeJson(command) + "\",\"summary\":\"Run " + EscapeJson(oldName) + " from terminal service\",\"background\":false}";
				LogMessage("[Terminal Service] Rewrote " + oldName + " tool call to run_command_in_terminal.");
			}
		}
	}

	private void RedirectSearchLoopToCreateFile(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0 || string.IsNullOrWhiteSpace(requestBody) || !HasCreateFileGoal(requestBody) || !IsToolAdvertised(requestBody, "create_file"))
		{
			return;
		}
		string targetPath = InferMissingCreationTargetPath(requestBody);
		if (string.IsNullOrWhiteSpace(targetPath))
		{
			return;
		}
		if (!IsSafeCreateFileTarget(targetPath))
		{
			LogMessage("[Create File Redirect] Refusing unsafe create_file target: " + targetPath);
			return;
		}
		if (HasSuccessfulFileRead(requestBody, targetPath))
		{
			LogMessage("[Create File Redirect] Refusing to create existing file already read successfully: " + targetPath);
			return;
		}
		if (HasRepeatedCreateFileAttempts(requestBody, targetPath, 3))
		{
			LogMessage("[Create File Redirect] Refusing to repeat create_file for " + targetPath + " because it was already attempted repeatedly.");
			return;
		}
		int repeatedSearchCount = CountRepeatedSearchOrNavigationAttempts(requestBody, targetPath);
		if (repeatedSearchCount < 4)
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || string.IsNullOrWhiteSpace(toolCall.Name) || !IsSearchOrNavigationTool(toolCall.Name))
			{
				continue;
			}
			toolCall.Name = "create_file";
			toolCall.ArgumentsJson = BuildCreateFileArguments(targetPath, null);
			LogMessage("[Create File Redirect] Rewrote repeated " + repeatedSearchCount + " search/navigation attempt(s) to create_file for " + targetPath);
			break;
		}
	}

	private void RedirectMissingCodebehindLoopToCreateFile(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0 || string.IsNullOrWhiteSpace(requestBody) || !IsToolAdvertised(requestBody, "create_file") || !TryInferMissingCodebehindLoopTarget(requestBody, out var targetPath, out var signalCount))
		{
			return;
		}
		if (!IsSafeCreateFileTarget(targetPath))
		{
			LogMessage("[Codebehind Loop Redirect] Refusing unsafe code-behind target: " + targetPath);
			return;
		}
		if (HasSuccessfulFileRead(requestBody, targetPath))
		{
			LogMessage("[Codebehind Loop Redirect] Refusing to create existing file already read successfully: " + targetPath);
			return;
		}
		if (TryResolveLocalFilePath(targetPath, out var existingCodebehindPath))
		{
			LogMessage("[Codebehind Loop Redirect] Refusing to create existing local file: " + existingCodebehindPath);
			return;
		}
		if (HasRepeatedCreateFileAttempts(requestBody, targetPath, 3))
		{
			LogMessage("[Codebehind Loop Redirect] Refusing to repeat create_file for " + targetPath + " because it was already attempted repeatedly.");
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall != null && !string.IsNullOrWhiteSpace(toolCall.Name))
			{
				if (toolCall.Name.Equals("get_file", StringComparison.Ordinal))
				{
					LogMessage("[Codebehind Loop Redirect] Leaving get_file unchanged; reads should not be rewritten to create_file for " + targetPath);
				}
				else if (IsSearchOrNavigationTool(toolCall.Name) || toolCall.Name.Equals("get_errors", StringComparison.Ordinal))
				{
					string originalName = toolCall.Name;
					toolCall.Name = "create_file";
					toolCall.ArgumentsJson = BuildCreateFileArguments(targetPath, null);
					LogMessage("[Codebehind Loop Redirect] Rewrote " + originalName + " after " + signalCount + " missing-codebehind signal(s) to create_file for " + targetPath);
					break;
				}
			}
		}
	}

	private bool TryInferMissingCodebehindLoopTarget(string requestBody, out string targetPath, out int signalCount)
	{
		targetPath = null;
		signalCount = 0;
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return false;
		}
		string lower = requestBody.ToLowerInvariant();
		string candidate = ExtractLikelyCodebehindPathFromConversation(requestBody);
		if (string.IsNullOrWhiteSpace(candidate))
		{
			return false;
		}
		targetPath = NormalizeInferredCodebehindPath(candidate, requestBody);
		if (string.IsNullOrWhiteSpace(targetPath))
		{
			return false;
		}
		string fileName = targetPath.Replace('\\', '/');
		int slash = fileName.LastIndexOf('/');
		if (slash >= 0)
		{
			fileName = fileName.Substring(slash + 1);
		}
		string stem = fileName;
		int dot = stem.IndexOf('.');
		if (dot > 0)
		{
			stem = stem.Substring(0, dot);
		}
		int relatedToolCalls = CountHistoricalToolCalls(requestBody, "file_search") + CountHistoricalToolCalls(requestBody, "code_search") + CountHistoricalToolCalls(requestBody, "get_file") + CountHistoricalToolCalls(requestBody, "find_symbol") + CountHistoricalToolCalls(requestBody, "get_errors");
		bool codebehindTopic = lower.Contains(".xaml.vb") || (lower.Contains("codebehind") && lower.Contains(".xaml")) || (lower.Contains("code-behind") && lower.Contains(".xaml"));
		bool missingSignal = lower.Contains("no " + fileName.ToLowerInvariant()) || lower.Contains("no " + stem.ToLowerInvariant() + ".xaml.vb") || lower.Contains("missing") || lower.Contains("not found") || lower.Contains("doesn't exist") || lower.Contains("does not exist") || lower.Contains("no relevant matches") || lower.Contains("there's no") || lower.Contains("there is no");
		signalCount = 0;
		if (codebehindTopic)
		{
			signalCount++;
		}
		if (missingSignal)
		{
			signalCount++;
		}
		signalCount += Math.Min(relatedToolCalls, 4);
		return signalCount >= 3;
	}

	private string ExtractLikelyCodebehindPathFromConversation(string requestBody)
	{
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return null;
		}
		string latestXaml = null;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return null;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var roleElement) || roleElement.ValueKind != JsonValueKind.String || !roleElement.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (!item.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
					{
						continue;
					}
					JsonElement argumentsElement;
					string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
					foreach (string value in ExtractPathLikeToolArgumentValues(arguments))
					{
						string candidate = ExtractCodebehindCandidateFromPathValue(value);
						if (!string.IsNullOrWhiteSpace(candidate))
						{
							latestXaml = candidate;
						}
					}
				}
			}
		}
		catch
		{
		}
		if (!string.IsNullOrWhiteSpace(latestXaml))
		{
			return latestXaml;
		}
		return null;
	}

	private IEnumerable<string> ExtractPathLikeToolArgumentValues(string argumentsJson)
	{
		List<string> values = new List<string>();
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			return values;
		}
		JsonDocument document = null;
		try
		{
			document = JsonDocument.Parse(argumentsJson);
		}
		catch
		{
			string fallback = TryExtractLikelyFilePath(argumentsJson);
			if (!string.IsNullOrWhiteSpace(fallback))
			{
				values.Add(fallback);
			}
			return values;
		}
		using (document)
		{
			JsonElement root = document.RootElement;
			string[] array = new string[3] { "filename", "filePath", "projectPath" };
			foreach (string propertyName in array)
			{
				if (root.TryGetProperty(propertyName, out var property) && property.ValueKind == JsonValueKind.String)
				{
					values.Add(property.GetString());
				}
			}
			string[] array2 = new string[2] { "queries", "searchQueries" };
			foreach (string arrayName in array2)
			{
				if (!root.TryGetProperty(arrayName, out var array3) || array3.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in array3.EnumerateArray())
				{
					if (item.ValueKind == JsonValueKind.String)
					{
						values.Add(item.GetString());
					}
				}
			}
		}
		return values;
	}

	private string ExtractCodebehindCandidateFromPathValue(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return null;
		}
		string cleaned = NormalizeLoosePathEscapes(value).Trim().Trim('"', '\'', ',', '.', ' ');
		Match codebehindMatch = Regex.Match(cleaned, "^(?<path>(?:[A-Za-z0-9_. \\-]+[\\\\/]+)*[A-Za-z0-9_.\\-]+\\.xaml\\.vb)$", RegexOptions.IgnoreCase);
		if (codebehindMatch.Success)
		{
			return codebehindMatch.Groups["path"].Value;
		}
		Match xamlMatch = Regex.Match(cleaned, "^(?<path>(?:[A-Za-z0-9_. \\-]+[\\\\/]+)*[A-Za-z0-9_.\\-]+\\.xaml)$", RegexOptions.IgnoreCase);
		if (xamlMatch.Success)
		{
			return xamlMatch.Groups["path"].Value + ".vb";
		}
		return null;
	}

	private string NormalizeInferredCodebehindPath(string candidate, string requestBody)
	{
		if (string.IsNullOrWhiteSpace(candidate))
		{
			return null;
		}
		string normalized = NormalizeLoosePathEscapes(candidate).Replace("\\\\", "\\").Replace('/', '\\').Trim()
			.Trim('"', '\'', ',', '.', ' ');
		while (normalized.Contains("\\\\"))
		{
			normalized = normalized.Replace("\\\\", "\\");
		}
		if (!normalized.EndsWith(".xaml.vb", StringComparison.OrdinalIgnoreCase) || !HasUsableFileNameStem(normalized))
		{
			return null;
		}
		if (normalized.IndexOf('\\') >= 0)
		{
			return normalized;
		}
		string projectFolder = ExtractProjectFolderFromConversation(requestBody);
		if (string.IsNullOrWhiteSpace(projectFolder))
		{
			projectFolder = "Maf Scale";
		}
		return projectFolder.TrimEnd('\\', '/') + "\\" + normalized;
	}

	private string InferMissingCreationTargetPath(string requestBody)
	{
		string requested = ExtractCreationTargetFileName(requestBody);
		if (!string.IsNullOrWhiteSpace(requested))
		{
			requested = RepairPathControlCharacters(requested.Trim());
			if (requested.IndexOf('\\') >= 0 || requested.IndexOf('/') >= 0)
			{
				return requested;
			}
			string projectFolder = ExtractProjectFolderFromConversation(requestBody);
			if (string.IsNullOrWhiteSpace(projectFolder))
			{
				projectFolder = "Maf Scale";
			}
			return projectFolder.TrimEnd('\\', '/') + "\\" + requested;
		}
		string lastUserMessage = ExtractLastUserMessage(requestBody) ?? "";
		string lower = lastUserMessage.ToLowerInvariant();
		if (lower.Contains("fkkvs"))
		{
			string projectFolder2 = ExtractProjectFolderFromConversation(requestBody);
			if (string.IsNullOrWhiteSpace(projectFolder2))
			{
				projectFolder2 = "Maf Scale";
			}
			return projectFolder2.TrimEnd('\\', '/') + "\\fkkvs.xaml.vb";
		}
		return null;
	}

	private string ExtractCreationTargetFileName(string requestBody)
	{
		string result = null;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return null;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var roleElement) || roleElement.ValueKind != JsonValueKind.String || !roleElement.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (item.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
					{
						string name = ExtractStringProperty(function, "name") ?? "";
						JsonElement argumentsElement;
						string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
						string candidate = ExtractCreationTargetFromToolArguments(name, arguments);
						if (!string.IsNullOrWhiteSpace(candidate))
						{
							result = candidate;
						}
					}
				}
			}
		}
		catch
		{
		}
		return result;
	}

	private string ExtractCreationTargetFromToolArguments(string toolName, string argumentsJson)
	{
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			return null;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			JsonElement root = document.RootElement;
			if (toolName.Equals("create_file", StringComparison.Ordinal) && root.TryGetProperty("filePath", out var filePathElement) && filePathElement.ValueKind == JsonValueKind.String)
			{
				string filePath = filePathElement.GetString();
				return IsSafeCreateFileTarget(filePath) ? filePath : null;
			}
			if (toolName.Equals("file_search", StringComparison.Ordinal) && root.TryGetProperty("queries", out var queries) && queries.ValueKind == JsonValueKind.Array)
			{
				foreach (JsonElement query in queries.EnumerateArray())
				{
					if (query.ValueKind == JsonValueKind.String && LooksLikeNewTargetFileName(query.GetString()))
					{
						return query.GetString();
					}
				}
			}
			if (toolName.Equals("file_search", StringComparison.Ordinal) && root.TryGetProperty("searchQueries", out var searchQueries) && searchQueries.ValueKind == JsonValueKind.Array)
			{
				foreach (JsonElement query2 in searchQueries.EnumerateArray())
				{
					if (query2.ValueKind == JsonValueKind.String && LooksLikeNewTargetFileName(query2.GetString()))
					{
						return query2.GetString();
					}
				}
			}
		}
		catch
		{
		}
		return null;
	}

	private int CountRepeatedSearchOrNavigationAttempts(string requestBody, string targetPath)
	{
		int count = 0;
		string fileName = targetPath.Replace('\\', '/');
		int slash = fileName.LastIndexOf('/');
		if (slash >= 0)
		{
			fileName = fileName.Substring(slash + 1);
		}
		string stem = fileName;
		int dot = stem.IndexOf('.');
		if (dot > 0)
		{
			stem = stem.Substring(0, dot);
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return 0;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var roleElement) || roleElement.ValueKind != JsonValueKind.String || !roleElement.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (!item.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
					{
						continue;
					}
					string name = ExtractStringProperty(function, "name") ?? "";
					if (IsSearchOrNavigationTool(name))
					{
						JsonElement argumentsElement;
						string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
						string lower = arguments.ToLowerInvariant();
						if (lower.Contains(fileName.ToLowerInvariant()) || lower.Contains(stem.ToLowerInvariant()))
						{
							count++;
						}
					}
				}
			}
		}
		catch
		{
		}
		return count;
	}

	private bool IsSearchOrNavigationTool(string toolName)
	{
		return toolName.Equals("file_search", StringComparison.Ordinal) || toolName.Equals("code_search", StringComparison.Ordinal) || toolName.Equals("get_projects_in_solution", StringComparison.Ordinal) || toolName.Equals("get_files_in_project", StringComparison.Ordinal) || toolName.Equals("get_file", StringComparison.Ordinal) || toolName.Equals("find_symbol", StringComparison.Ordinal);
	}

	private bool LooksLikeFileName(string text)
	{
		if (string.IsNullOrWhiteSpace(text))
		{
			return false;
		}
		string lower = text.ToLowerInvariant();
		return lower.EndsWith(".xaml") || lower.EndsWith(".xaml.vb") || lower.EndsWith(".vb") || lower.EndsWith(".cs") || lower.EndsWith(".proj") || lower.Contains(".");
	}

	private bool LooksLikeNewTargetFileName(string text)
	{
		if (!LooksLikeFileName(text))
		{
			return false;
		}
		string lower = text.ToLowerInvariant();
		if (lower.Contains("application.xaml") || lower.Contains("mainwindow") || lower.Contains("injectortimes") || lower.Contains("maf.xaml") || !IsSafeCreateFileTarget(text))
		{
			return false;
		}
		return true;
	}

	private bool IsSafeCreateFileTarget(string filePath)
	{
		if (string.IsNullOrWhiteSpace(filePath))
		{
			return false;
		}
		string repaired = RepairPathControlCharacters(filePath).Trim().Trim('"', '\'', ',', ' ');
		if (!HasUsableFileNameStem(repaired))
		{
			return false;
		}
		string lower = repaired.Replace('\\', '/').ToLowerInvariant();
		if (lower.EndsWith(".sln", StringComparison.Ordinal) || lower.EndsWith(".proj", StringComparison.Ordinal) || lower.EndsWith(".vbproj", StringComparison.Ordinal) || lower.EndsWith(".csproj", StringComparison.Ordinal) || lower.EndsWith(".fsproj", StringComparison.Ordinal) || lower.EndsWith(".props", StringComparison.Ordinal) || lower.EndsWith(".targets", StringComparison.Ordinal))
		{
			return false;
		}
		if (lower.EndsWith("/app.xaml", StringComparison.Ordinal) || lower.EndsWith("/application.xaml", StringComparison.Ordinal) || lower.EndsWith("/application.xaml.vb", StringComparison.Ordinal) || lower.EndsWith("/maf.xaml", StringComparison.Ordinal) || lower.EndsWith("/maf.xaml.vb", StringComparison.Ordinal))
		{
			return false;
		}
		return lower.EndsWith(".xaml", StringComparison.Ordinal) || lower.EndsWith(".xaml.vb", StringComparison.Ordinal) || lower.EndsWith(".vb", StringComparison.Ordinal) || lower.EndsWith(".cs", StringComparison.Ordinal);
	}

	private bool HasUsableFileNameStem(string filePath)
	{
		if (string.IsNullOrWhiteSpace(filePath))
		{
			return false;
		}
		string normalized = RepairPathControlCharacters(filePath).Replace('/', '\\').Trim().Trim('"', '\'', ',', ' ');
		if (normalized.EndsWith("\\", StringComparison.Ordinal))
		{
			return false;
		}
		int slash = normalized.LastIndexOf('\\');
		string fileName = ((slash >= 0) ? normalized.Substring(slash + 1) : normalized);
		if (string.IsNullOrWhiteSpace(fileName) || fileName.StartsWith(".", StringComparison.Ordinal) || fileName.EndsWith(".", StringComparison.Ordinal))
		{
			return false;
		}
		int dot = fileName.IndexOf('.');
		return dot > 0;
	}

	private void TranslateUnsupportedBatchReplaceToolCalls(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		bool canReplace = !string.IsNullOrWhiteSpace(requestBody) && IsToolAdvertised(requestBody, "replace_string_in_file");
		List<ToolCallData> translated = new List<ToolCallData>(toolCalls.Count);
		int translatedCount = 0;
		int droppedCount = 0;
		foreach (ToolCallData toolCall in toolCalls)
		{
			List<ToolCallData> replacementCalls;
			if (toolCall == null || string.IsNullOrWhiteSpace(toolCall.Name) || !toolCall.Name.Equals("multi_replace_string_in_file", StringComparison.Ordinal))
			{
				translated.Add(toolCall);
			}
			else if (canReplace && TryTranslateBatchReplaceToSingleReplaceCalls(toolCall, out replacementCalls))
			{
				translated.AddRange(replacementCalls);
				translatedCount += replacementCalls.Count;
			}
			else
			{
				droppedCount++;
			}
		}
		if (translatedCount != 0 || droppedCount != 0)
		{
			toolCalls.Clear();
			toolCalls.AddRange(translated);
			if (translatedCount > 0)
			{
				LogMessage("[Tool Compatibility] Translated unsupported batch replace tool into " + translatedCount + " replace_string_in_file call(s).");
			}
			if (droppedCount > 0)
			{
				LogMessage("[Tool Compatibility] Dropped " + droppedCount + " unsupported batch replace tool call(s).");
			}
		}
	}

	private bool TryTranslateBatchReplaceToSingleReplaceCalls(ToolCallData source, out List<ToolCallData> replacementCalls)
	{
		replacementCalls = new List<ToolCallData>();
		if (source == null || string.IsNullOrWhiteSpace(source.ArgumentsJson))
		{
			return false;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(source.ArgumentsJson);
			if (!document.RootElement.TryGetProperty("replacements", out var replacements) || replacements.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			int index = 0;
			foreach (JsonElement replacement in replacements.EnumerateArray())
			{
				if (replacement.ValueKind == JsonValueKind.Object)
				{
					string filePath = ExtractJsonStringFromObject(replacement, "filePath") ?? ExtractJsonStringFromObject(replacement, "filename") ?? ExtractJsonStringFromObject(replacement, "path");
					string oldString = NormalizeGeneratedFileText(ExtractJsonStringFromObject(replacement, "oldString"));
					string newString = NormalizeGeneratedFileText(ExtractJsonStringFromObject(replacement, "newString"));
					if (!string.IsNullOrWhiteSpace(filePath))
					{
						filePath = NormalizeLoosePathEscapes(RepairPathControlCharacters(filePath) ?? filePath);
						replacementCalls.Add(new ToolCallData
						{
							Id = BuildDerivedToolCallId(source.Id, index),
							Name = "replace_string_in_file",
							ArgumentsJson = "{\"filePath\":\"" + EscapeJson(filePath) + "\",\"oldString\":\"" + EscapeJson(oldString ?? "") + "\",\"newString\":\"" + EscapeJson(newString ?? "") + "\"}",
							ArgumentsWereMalformed = false
						});
						index++;
					}
				}
			}
		}
		catch
		{
			return false;
		}
		return replacementCalls.Count > 0;
	}

	private string ExtractJsonStringFromObject(JsonElement element, string propertyName)
	{
		if (element.ValueKind != JsonValueKind.Object || string.IsNullOrWhiteSpace(propertyName) || !element.TryGetProperty(propertyName, out var value))
		{
			return null;
		}
		return (value.ValueKind == JsonValueKind.String) ? value.GetString() : value.ToString();
	}

	private string BuildDerivedToolCallId(string sourceId, int index)
	{
		string prefix = (string.IsNullOrWhiteSpace(sourceId) ? ("call_" + Guid.NewGuid().ToString("N").Substring(0, 12)) : sourceId);
		return prefix + "_replace_" + index.ToString(CultureInfo.InvariantCulture);
	}

	private void GuardMalformedEditToolCalls(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		bool canReadFile = !string.IsNullOrWhiteSpace(requestBody) && IsToolAdvertised(requestBody, "get_file");
		bool canSearchFile = !string.IsNullOrWhiteSpace(requestBody) && IsToolAdvertised(requestBody, "file_search");
		List<ToolCallData> suppressedToolCalls = new List<ToolCallData>();
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall != null && toolCall.ArgumentsWereMalformed && (toolCall.Name.Equals("replace_string_in_file", StringComparison.Ordinal) || toolCall.Name.Equals("create_file", StringComparison.Ordinal)))
			{
				string targetPath = (toolCall.Name.Equals("replace_string_in_file", StringComparison.Ordinal) ? ExtractFilePathFromReplaceStringArguments(toolCall.ArgumentsJson) : ExtractFilePathFromCreateFileArguments(toolCall.ArgumentsJson));
				targetPath = NormalizeLoosePathEscapes(targetPath ?? "");
				if (string.IsNullOrWhiteSpace(targetPath))
				{
					targetPath = TryExtractLikelyFilePath(toolCall.ArgumentsJson);
				}
				if (canReadFile && !string.IsNullOrWhiteSpace(targetPath) && HasUsableFileNameStem(targetPath))
				{
					string originalName = toolCall.Name;
					toolCall.Name = "get_file";
					toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(targetPath) + "\",\"startLine\":1,\"endLine\":400,\"includeLineNumbers\":true}";
					LogMessage("[Malformed Edit Guard] Rewrote malformed " + originalName + " to get_file for " + targetPath + ".");
				}
				else if (canSearchFile && !string.IsNullOrWhiteSpace(targetPath))
				{
					string originalName2 = toolCall.Name;
					toolCall.Name = "file_search";
					toolCall.ArgumentsJson = "{\"queries\":[\"" + EscapeJson(targetPath) + "\"],\"maxResults\":20}";
					LogMessage("[Malformed Edit Guard] Rewrote malformed " + originalName2 + " to file_search for " + targetPath + ".");
				}
				else
				{
					suppressedToolCalls.Add(toolCall);
					LogMessage("[Malformed Edit Guard] Suppressed malformed " + toolCall.Name + " because no safe read/search fallback was available.");
				}
			}
		}
		if (suppressedToolCalls.Count > 0)
		{
			toolCalls.RemoveAll((ToolCallData item) => suppressedToolCalls.Contains(item));
		}
	}

	private void GuardCreateFileForExistingTarget(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0 || string.IsNullOrWhiteSpace(requestBody) || !IsToolAdvertised(requestBody, "get_file"))
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !toolCall.Name.Equals("create_file", StringComparison.Ordinal))
			{
				continue;
			}
			string filePath = ExtractFilePathFromCreateFileArguments(toolCall.ArgumentsJson);
			if (string.IsNullOrWhiteSpace(filePath) || !HasUsableFileNameStem(filePath))
			{
				continue;
			}
			filePath = NormalizeLoosePathEscapes(filePath);
			if (HasEmptyOrSummaryOnlyGetFileResult(requestBody, filePath))
			{
				toolCall.Name = "get_file";
				toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(filePath) + "\",\"startLine\":1,\"endLine\":400,\"includeLineNumbers\":true}";
				LogMessage("[Get File Empty Guard] Rewrote create_file to get_file because previous get_file result had no substantive content: " + filePath);
			}
			else if (ConversationShowsFileAlreadyExists(requestBody, filePath))
			{
				string replacementContent = ExtractCreateFileContent(toolCall.ArgumentsJson);
				if (!string.IsNullOrWhiteSpace(replacementContent) && IsToolAdvertised(requestBody, "replace_string_in_file") && TryExtractLatestSuccessfulFileReadContent(requestBody, filePath, out var oldContent))
				{
					toolCall.Name = "replace_string_in_file";
					toolCall.ArgumentsJson = "{\"filePath\":\"" + EscapeJson(filePath) + "\",\"oldString\":\"" + EscapeJson(oldContent) + "\",\"newString\":\"" + EscapeJson(NormalizeGeneratedFileText(replacementContent) ?? "") + "\"}";
					LogMessage("[Create File Guard] Rewrote create_file to replace_string_in_file because the existing target was already read: " + filePath);
					RemoveRedundantGetFileCalls(toolCalls, filePath, toolCall);
				}
				else
				{
					toolCall.Name = "get_file";
					toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(filePath) + "\",\"startLine\":1,\"endLine\":200,\"includeLineNumbers\":true}";
					LogMessage("[Create File Guard] Rewrote create_file to get_file because history already shows the target exists: " + filePath);
				}
			}
		}
	}

	private void GuardBlankReplaceStringCalls(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		bool canReadFile = !string.IsNullOrWhiteSpace(requestBody) && IsToolAdvertised(requestBody, "get_file");
		bool canSearchFile = !string.IsNullOrWhiteSpace(requestBody) && IsToolAdvertised(requestBody, "file_search");
		List<ToolCallData> suppressedToolCalls = new List<ToolCallData>();
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !toolCall.Name.Equals("replace_string_in_file", StringComparison.Ordinal))
			{
				continue;
			}
			string filePath = ExtractFilePathFromReplaceStringArguments(toolCall.ArgumentsJson);
			filePath = NormalizeLoosePathEscapes(filePath ?? "");
			string oldString = NormalizeGeneratedFileText(ExtractJsonStringProperty(toolCall.ArgumentsJson, "oldString"));
			string newString = NormalizeGeneratedFileText(ExtractJsonStringProperty(toolCall.ArgumentsJson, "newString"));
			bool oldIsBlank = string.IsNullOrWhiteSpace(oldString);
			bool newIsBlank = string.IsNullOrWhiteSpace(newString);
			if (string.IsNullOrWhiteSpace(filePath) || !HasUsableFileNameStem(filePath))
			{
				if (canSearchFile)
				{
					string query = (string.IsNullOrWhiteSpace(filePath) ? "replace_string_in_file target" : filePath);
					toolCall.Name = "file_search";
					toolCall.ArgumentsJson = "{\"queries\":[\"" + EscapeJson(query) + "\"],\"maxResults\":20}";
					LogMessage("[Replace String Guard] Rewrote replace_string_in_file with unusable filePath to file_search.");
				}
				else
				{
					suppressedToolCalls.Add(toolCall);
					LogMessage("[Replace String Guard] Suppressed replace_string_in_file with unusable filePath.");
				}
			}
			else if (oldIsBlank)
			{
				if (!newIsBlank && !string.IsNullOrWhiteSpace(requestBody) && TryExtractLatestSuccessfulFileReadContent(requestBody, filePath, out var oldContent) && !string.IsNullOrWhiteSpace(oldContent))
				{
					toolCall.ArgumentsJson = "{\"filePath\":\"" + EscapeJson(filePath) + "\",\"oldString\":\"" + EscapeJson(oldContent) + "\",\"newString\":\"" + EscapeJson(newString ?? "") + "\"}";
					LogMessage("[Replace String Guard] Hydrated blank oldString from the latest successful get_file result for " + filePath + ".");
					RemoveRedundantGetFileCalls(toolCalls, filePath, toolCall);
				}
				else if (canReadFile)
				{
					toolCall.Name = "get_file";
					toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(filePath) + "\",\"startLine\":1,\"endLine\":400,\"includeLineNumbers\":true}";
					LogMessage("[Replace String Guard] Rewrote replace_string_in_file with blank oldString/newString context to get_file for " + filePath + ".");
				}
				else if (canSearchFile)
				{
					toolCall.Name = "file_search";
					toolCall.ArgumentsJson = "{\"queries\":[\"" + EscapeJson(filePath) + "\"],\"maxResults\":20}";
					LogMessage("[Replace String Guard] Rewrote replace_string_in_file with blank oldString to file_search for " + filePath + ".");
				}
				else
				{
					suppressedToolCalls.Add(toolCall);
					LogMessage("[Replace String Guard] Suppressed replace_string_in_file with blank oldString for " + filePath + " because no read/search fallback was advertised.");
				}
			}
		}
		if (suppressedToolCalls.Count > 0)
		{
			toolCalls.RemoveAll((ToolCallData item) => suppressedToolCalls.Contains(item));
		}
	}

	private void GuardNoOpReplaceStringCalls(List<ToolCallData> toolCalls)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		int removed = toolCalls.RemoveAll(delegate(ToolCallData toolCall)
		{
			if (toolCall == null || !toolCall.Name.Equals("replace_string_in_file", StringComparison.Ordinal))
			{
				return false;
			}
			string text = NormalizeGeneratedFileText(ExtractJsonStringProperty(toolCall.ArgumentsJson, "oldString"));
			string text2 = NormalizeGeneratedFileText(ExtractJsonStringProperty(toolCall.ArgumentsJson, "newString"));
			return text != null && text2 != null && string.Equals(text, text2, StringComparison.Ordinal);
		});
		if (removed > 0)
		{
			LogMessage("[Replace String Guard] Suppressed " + removed + " no-op replace_string_in_file call(s) where oldString equals newString.");
		}
	}

	private void RemoveRedundantGetFileCalls(List<ToolCallData> toolCalls, string filePath, ToolCallData keepToolCall)
	{
		if (toolCalls == null || string.IsNullOrWhiteSpace(filePath))
		{
			return;
		}
		string normalizedTarget = NormalizePathForCompare(filePath);
		string targetFileName = ExtractFileNameForCompare(filePath);
		int removed = toolCalls.RemoveAll(delegate(ToolCallData toolCall)
		{
			if (toolCall == null || toolCall == keepToolCall)
			{
				return false;
			}
			if (!toolCall.Name.Equals("get_file", StringComparison.Ordinal))
			{
				return false;
			}
			string text = ExtractFilenameFromGetFileArguments(toolCall.ArgumentsJson);
			if (string.IsNullOrWhiteSpace(text))
			{
				return false;
			}
			string text2 = NormalizePathForCompare(text);
			string text3 = ExtractFileNameForCompare(text);
			return text2.Equals(normalizedTarget, StringComparison.OrdinalIgnoreCase) || text3.Equals(targetFileName, StringComparison.OrdinalIgnoreCase);
		});
		if (removed > 0)
		{
			LogMessage("[Create File Guard] Dropped " + removed + " redundant get_file call(s) for " + filePath + " after edit rewrite.");
		}
	}

	private string ExtractCreateFileContent(string argumentsJson)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			JsonElement contentElement;
			return (document.RootElement.TryGetProperty("content", out contentElement) && contentElement.ValueKind == JsonValueKind.String) ? contentElement.GetString() : null;
		}
		catch
		{
			return null;
		}
	}

	private string ExtractFilePathFromReplaceStringArguments(string argumentsJson)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			if (document.RootElement.TryGetProperty("filePath", out var filePathElement) && filePathElement.ValueKind == JsonValueKind.String)
			{
				return filePathElement.GetString();
			}
			if (document.RootElement.TryGetProperty("filename", out var filenameElement) && filenameElement.ValueKind == JsonValueKind.String)
			{
				return filenameElement.GetString();
			}
		}
		catch
		{
			return TryExtractLikelyFilePath(argumentsJson);
		}
		return TryExtractLikelyFilePath(argumentsJson);
	}

	private bool TryExtractLatestSuccessfulFileReadContent(string requestBody, string targetPath, out string fileContent)
	{
		fileContent = null;
		string normalizedTarget = NormalizePathForCompare(targetPath);
		string targetFileName = ExtractFileNameForCompare(targetPath);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, string> getFileCalls = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement call in toolCalls.EnumerateArray())
					{
						if (!call.TryGetProperty("id", out var idElement) || idElement.ValueKind != JsonValueKind.String || !call.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
						{
							continue;
						}
						string name = ExtractStringProperty(function, "name") ?? "";
						if (name.Equals("get_file", StringComparison.Ordinal))
						{
							JsonElement argumentsElement;
							string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
							string assistantReadPath = ExtractFilenameFromGetFileArguments(arguments);
							if (!string.IsNullOrWhiteSpace(assistantReadPath))
							{
								getFileCalls[idElement.GetString()] = assistantReadPath;
							}
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (string.IsNullOrWhiteSpace(toolCallId) || !getFileCalls.TryGetValue(toolCallId, out var toolResultReadPath))
					{
						continue;
					}
					string normalizedFilename = NormalizePathForCompare(toolResultReadPath);
					string readFileName = ExtractFileNameForCompare(toolResultReadPath);
					if (!normalizedFilename.Equals(normalizedTarget, StringComparison.OrdinalIgnoreCase) && !readFileName.Equals(targetFileName, StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement contentElement;
					string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
					if (!LooksLikeToolError(content) && !LooksLikeFileSearchMiss(content))
					{
						string parsed = ExtractPlainFileContentFromToolResult(content);
						if (LooksLikeSubstantiveFileContent(parsed, targetPath))
						{
							fileContent = parsed;
						}
					}
				}
			}
		}
		catch
		{
		}
		return fileContent != null;
	}

	private bool HasEmptyOrSummaryOnlyGetFileResult(string requestBody, string targetPath)
	{
		if (string.IsNullOrWhiteSpace(requestBody) || string.IsNullOrWhiteSpace(targetPath))
		{
			return false;
		}
		string normalizedTarget = NormalizePathForCompare(targetPath);
		string targetFileName = ExtractFileNameForCompare(targetPath);
		bool sawMatchingRead = false;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, string> getFileCalls = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement call in toolCalls.EnumerateArray())
					{
						if (!call.TryGetProperty("id", out var idElement) || idElement.ValueKind != JsonValueKind.String || !call.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
						{
							continue;
						}
						string name = ExtractStringProperty(function, "name") ?? "";
						if (name.Equals("get_file", StringComparison.Ordinal))
						{
							JsonElement argumentsElement;
							string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
							string filename = ExtractFilenameFromGetFileArguments(arguments);
							if (!string.IsNullOrWhiteSpace(filename))
							{
								getFileCalls[idElement.GetString()] = filename;
							}
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (string.IsNullOrWhiteSpace(toolCallId) || !getFileCalls.TryGetValue(toolCallId, out var readPath))
					{
						continue;
					}
					string normalizedRead = NormalizePathForCompare(readPath);
					string readFileName = ExtractFileNameForCompare(readPath);
					if (!normalizedRead.Equals(normalizedTarget, StringComparison.OrdinalIgnoreCase) && !readFileName.Equals(targetFileName, StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement contentElement;
					string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
					if (!LooksLikeToolError(content) && !LooksLikeFileSearchMiss(content))
					{
						sawMatchingRead = true;
						string parsed = ExtractPlainFileContentFromToolResult(content);
						if (LooksLikeSubstantiveFileContent(parsed, targetPath))
						{
							return false;
						}
					}
				}
			}
		}
		catch
		{
		}
		return sawMatchingRead;
	}

	private string ExtractPlainFileContentFromToolResult(string content)
	{
		if (string.IsNullOrEmpty(content))
		{
			return "";
		}
		string text = content.Trim();
		if (text.StartsWith("```", StringComparison.Ordinal))
		{
			int firstLine = text.IndexOf('\n');
			int lastFence = text.LastIndexOf("```", StringComparison.Ordinal);
			if (firstLine >= 0 && lastFence > firstLine)
			{
				text = text.Substring(firstLine + 1, lastFence - firstLine - 1);
			}
		}
		text = NormalizeLineEndings(text).TrimEnd();
		string[] lines = text.Split(new string[1] { Environment.NewLine }, StringSplitOptions.None);
		StringBuilder sb = new StringBuilder();
		bool strippedAnyLineNumber = false;
		string[] array = lines;
		foreach (string line in array)
		{
			string outputLine = line;
			Match match = Regex.Match(line, "^\\s*\\d+:\\s?(?<text>.*)$");
			if (match.Success)
			{
				outputLine = match.Groups["text"].Value;
				strippedAnyLineNumber = true;
			}
			if (sb.Length > 0)
			{
				sb.Append(Environment.NewLine);
			}
			sb.Append(outputLine);
		}
		return strippedAnyLineNumber ? sb.ToString() : text;
	}

	private bool LooksLikeSubstantiveFileContent(string content, string targetPath)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return false;
		}
		string trimmed = content.Trim();
		string lower = trimmed.ToLowerInvariant();
		if (lower.StartsWith("read ", StringComparison.Ordinal) && lower.Contains("lines ") && trimmed.Length < 160)
		{
			return false;
		}
		string pathLower = (targetPath ?? "").ToLowerInvariant();
		if (pathLower.EndsWith(".xaml", StringComparison.Ordinal))
		{
			return trimmed.Contains("<") && trimmed.Contains(">");
		}
		if (pathLower.EndsWith(".vb", StringComparison.Ordinal))
		{
			return lower.Contains("class ") || lower.Contains("imports ") || lower.Contains("sub ") || lower.Contains("function ");
		}
		if (pathLower.EndsWith(".cs", StringComparison.Ordinal))
		{
			return lower.Contains("class ") || lower.Contains("namespace ") || lower.Contains("using ");
		}
		return trimmed.Length > 80;
	}

	private bool ConversationShowsFileAlreadyExists(string requestBody, string targetPath)
	{
		if (string.IsNullOrWhiteSpace(requestBody) || string.IsNullOrWhiteSpace(targetPath))
		{
			return false;
		}
		if (HasSuccessfulFileRead(requestBody, targetPath))
		{
			return true;
		}
		string normalizedTarget = NormalizePathForCompare(targetPath);
		string targetFileName = ExtractFileNameForCompare(targetPath);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, string> toolNamesById = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCallsElement) && toolCallsElement.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement call in toolCallsElement.EnumerateArray())
					{
						JsonElement idElement;
						string id = ((call.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						string name = "";
						if (call.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
						{
							name = nameElement.GetString();
						}
						if (!string.IsNullOrWhiteSpace(id) && !string.IsNullOrWhiteSpace(name))
						{
							toolNamesById[id] = name;
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (string.IsNullOrWhiteSpace(toolCallId) || !toolNamesById.TryGetValue(toolCallId, out var toolName) || (!toolName.Equals("file_search", StringComparison.Ordinal) && !toolName.Equals("get_files_in_project", StringComparison.Ordinal) && !toolName.Equals("code_search", StringComparison.Ordinal)))
					{
						continue;
					}
					JsonElement contentElement;
					string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
					if (!LooksLikeToolError(content) && !LooksLikeFileSearchMiss(content))
					{
						string normalizedContent = NormalizePathForCompare(content);
						if (normalizedContent.Contains(normalizedTarget) || (!string.IsNullOrWhiteSpace(targetFileName) && normalizedContent.Contains(targetFileName)))
						{
							return true;
						}
					}
				}
			}
		}
		catch
		{
		}
		return false;
	}

	private string ExtractFileNameForCompare(string path)
	{
		if (string.IsNullOrWhiteSpace(path))
		{
			return "";
		}
		string normalized = NormalizePathForCompare(path);
		int slash = normalized.LastIndexOf('\\');
		return (slash >= 0) ? normalized.Substring(slash + 1) : normalized;
	}

	private void GuardVagueGetFileTargets(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0 || string.IsNullOrWhiteSpace(requestBody))
		{
			return;
		}
		bool canSearch = IsToolAdvertised(requestBody, "file_search");
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !toolCall.Name.Equals("get_file", StringComparison.Ordinal))
			{
				continue;
			}
			string filename = ExtractFilenameFromGetFileArguments(toolCall.ArgumentsJson);
			if (LooksLikeVagueGetFileTarget(filename) || LooksLikeDefaultGetFileFallbackForActiveTopic(filename, requestBody))
			{
				string query = ExtractBestFileSearchToken(filename);
				if (string.IsNullOrWhiteSpace(query))
				{
					query = ExtractLikelyActiveFileTopic(requestBody);
				}
				if (string.IsNullOrWhiteSpace(query))
				{
					query = "MatrixControl";
				}
				if (TryResolveFilePathFromHistory(requestBody, query, out var resolvedPath))
				{
					toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(resolvedPath) + "\",\"startLine\":1,\"endLine\":240,\"includeLineNumbers\":true}";
					LogMessage("[Get File Guard] Resolved vague get_file target '" + filename + "' to " + resolvedPath);
				}
				else if (canSearch)
				{
					toolCall.Name = "file_search";
					string xamlQuery = (query.EndsWith(".xaml", StringComparison.OrdinalIgnoreCase) ? query : (query + ".xaml"));
					string vbQuery = (query.EndsWith(".xaml.vb", StringComparison.OrdinalIgnoreCase) ? query : (query + ".xaml.vb"));
					toolCall.ArgumentsJson = "{\"queries\":[\"" + EscapeJson(query) + "\",\"" + EscapeJson(xamlQuery) + "\",\"" + EscapeJson(vbQuery) + "\"],\"maxResults\":20}";
					LogMessage("[Get File Guard] Rewrote vague get_file target '" + filename + "' to file_search for " + query);
				}
			}
		}
	}

	private void GuardRepeatedGetFileLoop(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0 || string.IsNullOrWhiteSpace(requestBody))
		{
			return;
		}
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !toolCall.Name.Equals("get_file", StringComparison.Ordinal))
			{
				continue;
			}
			string filename = ExtractFilenameFromGetFileArguments(toolCall.ArgumentsJson);
			if (string.IsNullOrWhiteSpace(filename))
			{
				continue;
			}
			int startLine = ExtractIntFromToolArguments(toolCall.ArgumentsJson, "startLine", 1);
			int endLine = ExtractIntFromToolArguments(toolCall.ArgumentsJson, "endLine", 80);
			int successfulRepeats = CountSuccessfulGetFileReads(requestBody, filename, startLine, endLine);
			if (successfulRepeats >= 2)
			{
				string oldContent;
				if (endLine - startLine < 180)
				{
					int nextStart = Math.Max(1, endLine + 1);
					int nextEnd = nextStart + 199;
					toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(filename) + "\",\"startLine\":" + nextStart + ",\"endLine\":" + nextEnd + ",\"includeLineNumbers\":true}";
					LogMessage("[Get File Loop Guard] Expanded repeated get_file range for " + filename + " after " + successfulRepeats + " successful repeat(s).");
				}
				else if (IsToolAdvertised(requestBody, "replace_string_in_file") && LooksLikeEditRequest(requestBody) && TryExtractLatestSuccessfulFileReadContent(requestBody, filename, out oldContent) && !string.IsNullOrWhiteSpace(oldContent))
				{
					string newContent = SynthesizeEditPlaceholderContent(oldContent, filename, requestBody);
					toolCall.Name = "replace_string_in_file";
					toolCall.ArgumentsJson = "{\"filePath\":\"" + EscapeJson(filename) + "\",\"oldString\":\"" + EscapeJson(oldContent) + "\",\"newString\":\"" + EscapeJson(newContent) + "\"}";
					LogMessage("[Get File Loop Guard] Rewrote repeated broad get_file to replace_string_in_file for " + filename + ".");
				}
			}
		}
	}

	private int CountSuccessfulGetFileReads(string requestBody, string targetPath, int startLine, int endLine)
	{
		int count = 0;
		string normalizedTarget = NormalizePathForCompare(targetPath);
		string targetFileName = ExtractFileNameForCompare(targetPath);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return 0;
			}
			Dictionary<string, Tuple<string, int, int>> getFileCalls = new Dictionary<string, Tuple<string, int, int>>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCallsElement) && toolCallsElement.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement call in toolCallsElement.EnumerateArray())
					{
						if (!call.TryGetProperty("id", out var idElement) || idElement.ValueKind != JsonValueKind.String || !call.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
						{
							continue;
						}
						string name = ExtractStringProperty(function, "name") ?? "";
						if (name.Equals("get_file", StringComparison.Ordinal))
						{
							JsonElement argumentsElement;
							string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
							string filename = ExtractFilenameFromGetFileArguments(arguments);
							if (!string.IsNullOrWhiteSpace(filename))
							{
								int readStart = ExtractIntFromToolArguments(arguments, "startLine", 1);
								int readEnd = ExtractIntFromToolArguments(arguments, "endLine", 80);
								getFileCalls[idElement.GetString()] = Tuple.Create(filename, readStart, readEnd);
							}
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (string.IsNullOrWhiteSpace(toolCallId) || !getFileCalls.TryGetValue(toolCallId, out var read))
					{
						continue;
					}
					string normalizedRead = NormalizePathForCompare(read.Item1);
					string readFileName = ExtractFileNameForCompare(read.Item1);
					if ((normalizedRead.Equals(normalizedTarget, StringComparison.OrdinalIgnoreCase) || readFileName.Equals(targetFileName, StringComparison.OrdinalIgnoreCase)) && read.Item2 == startLine && read.Item3 == endLine)
					{
						JsonElement contentElement;
						string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
						string parsed = ExtractPlainFileContentFromToolResult(content);
						if (!LooksLikeToolError(content) && !LooksLikeFileSearchMiss(content) && LooksLikeSubstantiveFileContent(parsed, targetPath))
						{
							count++;
						}
					}
				}
			}
		}
		catch
		{
		}
		return count;
	}

	private int ExtractIntFromToolArguments(string argumentsJson, string propertyName, int fallback)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			int value;
			return TryGetIntProperty(document.RootElement, propertyName, out value) ? value : fallback;
		}
		catch
		{
			return fallback;
		}
	}

	private bool LooksLikeEditRequest(string requestBody)
	{
		string lastUser = ExtractLastUserMessage(requestBody) ?? "";
		string lower = lastUser.ToLowerInvariant();
		return lower.Contains("add ") || lower.Contains("update ") || lower.Contains("modify ") || lower.Contains("replace ") || lower.Contains("create ") || lower.Contains("implement ") || lower.Contains("enhance ") || lower.Contains("fix ") || lower.Contains("populate ");
	}

	private string SynthesizeEditPlaceholderContent(string oldContent, string filename, string requestBody)
	{
		return oldContent;
	}

	private bool LooksLikeVagueGetFileTarget(string filename)
	{
		if (string.IsNullOrWhiteSpace(filename))
		{
			return true;
		}
		string cleaned = NormalizeLoosePathEscapes(filename);
		if (!HasUsableFileNameStem(cleaned))
		{
			return true;
		}
		string lower = cleaned.ToLowerInvariant();
		return lower.Contains(" main project ") || lower.StartsWith("main project ", StringComparison.Ordinal) || lower.Contains(" current project ") || lower.Contains(" the project ") || lower.Contains(" file ");
	}

	private bool LooksLikeDefaultGetFileFallbackForActiveTopic(string filename, string requestBody)
	{
		if (string.IsNullOrWhiteSpace(filename) || string.IsNullOrWhiteSpace(requestBody))
		{
			return false;
		}
		string normalized = NormalizePathForCompare(filename);
		if (!normalized.EndsWith("toolselection.xaml", StringComparison.Ordinal))
		{
			return false;
		}
		string topic = ExtractLikelyActiveFileTopic(requestBody);
		return !string.IsNullOrWhiteSpace(topic) && !topic.Equals("ToolSelection", StringComparison.OrdinalIgnoreCase);
	}

	private string ExtractLikelyActiveFileTopic(string requestBody)
	{
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return null;
		}
		string lastUser = ExtractLastUserMessage(requestBody) ?? "";
		string combined = lastUser + "\n" + ExtractRecentAssistantText(requestBody, 4);
		MatchCollection matches = Regex.Matches(combined, "[A-Z][A-Za-z0-9_]*(?:Control|Window|Page|View|Dialog|\\.xaml(?:\\.vb)?)?");
		string best = null;
		foreach (Match match in matches)
		{
			string token = match.Value;
			if (!token.Equals("Thinking", StringComparison.Ordinal) && !token.Equals("Tool", StringComparison.Ordinal) && !token.Equals("Window", StringComparison.Ordinal) && !token.Equals("Application", StringComparison.Ordinal))
			{
				if (token.EndsWith(".xaml.vb", StringComparison.OrdinalIgnoreCase))
				{
					token = token.Substring(0, token.Length - ".xaml.vb".Length);
				}
				else if (token.EndsWith(".xaml", StringComparison.OrdinalIgnoreCase))
				{
					token = token.Substring(0, token.Length - ".xaml".Length);
				}
				if (best == null || token.Length > best.Length)
				{
					best = token;
				}
			}
		}
		return best;
	}

	private string ExtractRecentAssistantText(string requestBody, int maxMessages)
	{
		if (string.IsNullOrWhiteSpace(requestBody) || maxMessages <= 0)
		{
			return "";
		}
		List<string> parts = new List<string>();
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return "";
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("content", out var contentElement) && contentElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(contentElement.GetString()))
				{
					parts.Add(contentElement.GetString());
					if (parts.Count > maxMessages)
					{
						parts.RemoveAt(0);
					}
				}
			}
		}
		catch
		{
		}
		return string.Join("\n", parts);
	}

	private string ExtractBestFileSearchToken(string text)
	{
		if (string.IsNullOrWhiteSpace(text))
		{
			return null;
		}
		string cleaned = NormalizeLoosePathEscapes(text);
		MatchCollection matches = Regex.Matches(cleaned, "[A-Za-z_][A-Za-z0-9_]*(?:\\.xaml(?:\\.vb)?)?");
		string best = null;
		foreach (Match match in matches)
		{
			string token = match.Value;
			string lower = token.ToLowerInvariant();
			if (!lower.Equals("main", StringComparison.Ordinal) && !lower.Equals("project", StringComparison.Ordinal) && !lower.Equals("current", StringComparison.Ordinal) && !lower.Equals("file", StringComparison.Ordinal) && !lower.Equals("xaml", StringComparison.Ordinal) && !lower.Equals("vb", StringComparison.Ordinal) && (best == null || token.Length > best.Length))
			{
				best = token;
			}
		}
		return best;
	}

	private bool TryResolveFilePathFromHistory(string requestBody, string query, out string resolvedPath)
	{
		resolvedPath = null;
		if (string.IsNullOrWhiteSpace(requestBody) || string.IsNullOrWhiteSpace(query))
		{
			return false;
		}
		string token = NormalizePathForCompare(query);
		int dot = token.IndexOf('.');
		if (dot > 0)
		{
			token = token.Substring(0, dot);
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var roleElement) || roleElement.ValueKind != JsonValueKind.String || !roleElement.GetString().Equals("tool", StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				JsonElement contentElement;
				string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
				if (!LooksLikeToolError(content) && !LooksLikeFileSearchMiss(content))
				{
					string candidate = ExtractBestMatchingPathFromText(content, token);
					if (!string.IsNullOrWhiteSpace(candidate))
					{
						resolvedPath = candidate;
						return true;
					}
				}
			}
		}
		catch
		{
		}
		return false;
	}

	private string ExtractBestMatchingPathFromText(string text, string token)
	{
		if (string.IsNullOrWhiteSpace(text) || string.IsNullOrWhiteSpace(token))
		{
			return null;
		}
		MatchCollection matches = Regex.Matches(text, "(?<path>(?:[A-Za-z0-9_. \\-]+[\\\\/]+)*[A-Za-z0-9_.\\-]+\\.(?:xaml\\.vb|xaml|vb|cs))", RegexOptions.IgnoreCase);
		string fallback = null;
		foreach (Match match in matches)
		{
			string path = NormalizeLoosePathEscapes(match.Groups["path"].Value);
			if (!HasUsableFileNameStem(path))
			{
				continue;
			}
			string comparable = NormalizePathForCompare(path);
			if (comparable.Contains(token))
			{
				if (comparable.EndsWith(".xaml", StringComparison.Ordinal))
				{
					return path;
				}
				if (fallback == null)
				{
					fallback = path;
				}
			}
		}
		return fallback;
	}

	private void GuardUnsafeCreateFileTargets(List<ToolCallData> toolCalls, string requestBody)
	{
		if (toolCalls == null || toolCalls.Count == 0)
		{
			return;
		}
		bool canReadFile = IsToolAdvertised(requestBody, "get_file");
		foreach (ToolCallData toolCall in toolCalls)
		{
			if (toolCall == null || !toolCall.Name.Equals("create_file", StringComparison.Ordinal))
			{
				continue;
			}
			string filePath = ExtractFilePathFromCreateFileArguments(toolCall.ArgumentsJson);
			if (!IsSafeCreateFileTarget(filePath))
			{
				if (!canReadFile)
				{
					LogMessage("[Create File Guard] Unsafe create_file target has no safe read fallback: " + (filePath ?? "<missing>"));
					continue;
				}
				string fallbackPath = ((string.IsNullOrWhiteSpace(filePath) || !HasUsableFileNameStem(filePath)) ? "Maf Scale/ToolSelection.xaml" : NormalizeToolPathForVsArgument(filePath));
				toolCall.Name = "get_file";
				toolCall.ArgumentsJson = "{\"filename\":\"" + EscapeJson(fallbackPath) + "\",\"startLine\":1,\"endLine\":80,\"includeLineNumbers\":true}";
				LogMessage("[Create File Guard] Rewrote unsafe create_file target to get_file: " + fallbackPath);
			}
		}
	}

	private bool HasSuccessfulFileRead(string requestBody, string targetPath)
	{
		string normalizedTarget = NormalizePathForCompare(targetPath);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, string> getFileCalls = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						if (!toolCall.TryGetProperty("id", out var idElement) || idElement.ValueKind != JsonValueKind.String || !toolCall.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
						{
							continue;
						}
						string name = ExtractStringProperty(function, "name") ?? "";
						if (name.Equals("get_file", StringComparison.Ordinal))
						{
							JsonElement argumentsElement;
							string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
							string filename = ExtractFilenameFromGetFileArguments(arguments);
							if (!string.IsNullOrWhiteSpace(filename))
							{
								getFileCalls[idElement.GetString()] = filename;
							}
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (string.IsNullOrWhiteSpace(toolCallId) || !getFileCalls.TryGetValue(toolCallId, out var filename2))
					{
						continue;
					}
					string normalizedFilename = NormalizePathForCompare(filename2);
					string readFileName = ExtractFileNameForCompare(filename2);
					string targetFileName = ExtractFileNameForCompare(targetPath);
					if (normalizedFilename.Equals(normalizedTarget, StringComparison.OrdinalIgnoreCase) || readFileName.Equals(targetFileName, StringComparison.OrdinalIgnoreCase))
					{
						JsonElement contentElement;
						string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
						string parsed = ExtractPlainFileContentFromToolResult(content);
						if (!LooksLikeToolError(content) && !LooksLikeFileSearchMiss(content) && LooksLikeSubstantiveFileContent(parsed, targetPath))
						{
							return true;
						}
					}
				}
			}
		}
		catch
		{
		}
		return false;
	}

	private bool HasRepeatedCreateFileAttempts(string requestBody, string targetPath, int threshold)
	{
		int count = 0;
		string normalizedTarget = NormalizePathForCompare(targetPath);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var roleElement) || roleElement.ValueKind != JsonValueKind.String || !roleElement.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (!item.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
					{
						continue;
					}
					string name = ExtractStringProperty(function, "name") ?? "";
					if (!name.Equals("create_file", StringComparison.Ordinal))
					{
						continue;
					}
					JsonElement argumentsElement;
					string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
					string filePath = ExtractFilePathFromCreateFileArguments(arguments);
					if (!string.IsNullOrWhiteSpace(filePath) && NormalizePathForCompare(filePath).Equals(normalizedTarget, StringComparison.OrdinalIgnoreCase))
					{
						count++;
						if (count >= threshold)
						{
							return true;
						}
					}
				}
			}
		}
		catch
		{
		}
		return false;
	}

	private string ExtractFilenameFromGetFileArguments(string argumentsJson)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			JsonElement filenameElement;
			return (document.RootElement.TryGetProperty("filename", out filenameElement) && filenameElement.ValueKind == JsonValueKind.String) ? filenameElement.GetString() : null;
		}
		catch
		{
			return null;
		}
	}

	private string ExtractFilePathFromCreateFileArguments(string argumentsJson)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			JsonElement filePathElement;
			return (document.RootElement.TryGetProperty("filePath", out filePathElement) && filePathElement.ValueKind == JsonValueKind.String) ? filePathElement.GetString() : null;
		}
		catch
		{
			return TryExtractLikelyFilePath(argumentsJson);
		}
	}

	private string NormalizePathForCompare(string path)
	{
		return RepairPathControlCharacters(path ?? "").Replace('/', '\\').Trim().Trim('"', '\'', ',', ' ')
			.TrimEnd('\\')
			.ToLowerInvariant();
	}

	private string ExtractProjectFolderFromConversation(string requestBody)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return null;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var roleElement) || roleElement.ValueKind != JsonValueKind.String || !roleElement.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (item.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
					{
						JsonElement argumentsElement;
						string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
						Match match = Regex.Match(arguments, "(?<folder>[^\"\\\\]+)\\\\[^\"]+\\.(xaml|vb|cs|vbproj|csproj)", RegexOptions.IgnoreCase);
						if (match.Success)
						{
							return match.Groups["folder"].Value;
						}
					}
				}
			}
		}
		catch
		{
		}
		return null;
	}

	private string ExtractFirstToolResultForTool(string requestBody, string toolName)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return null;
			}
			Dictionary<string, string> toolCallIds = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						JsonElement idElement;
						string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						string name = "";
						if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
						{
							name = nameElement.GetString();
						}
						if (!string.IsNullOrEmpty(id) && name.Equals(toolName, StringComparison.Ordinal))
						{
							toolCallIds[id] = name;
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (!string.IsNullOrEmpty(toolCallId) && toolCallIds.ContainsKey(toolCallId))
					{
						JsonElement contentElement;
						string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
						if (!string.IsNullOrWhiteSpace(content))
						{
							return content.Trim();
						}
					}
				}
			}
		}
		catch
		{
		}
		return null;
	}

	private int CountHistoricalToolCalls(string requestBody, string toolName)
	{
		int count = 0;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return 0;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (!role.Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (item.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
