	}

	private string ExtractProjectPathFromToolResult(string content)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return null;
		}
		string[] lines = content.Replace("\r", "").Split('\n');
		string[] array = lines;
		foreach (string rawLine in array)
		{
			string line = rawLine.Trim().Trim('`');
			if (line.EndsWith(".vbproj", StringComparison.OrdinalIgnoreCase) || line.EndsWith(".csproj", StringComparison.OrdinalIgnoreCase) || line.EndsWith(".fsproj", StringComparison.OrdinalIgnoreCase))
			{
				return RepairPathControlCharacters(line);
			}
		}
		return null;
	}

	private string StripQwenToolCalls(string content, string requestBody)
	{
		if (string.IsNullOrEmpty(content))
		{
			return "";
		}
		StringBuilder sb = new StringBuilder();
		int searchStart = 0;
		while (searchStart < content.Length)
		{
			int start = FindQwenToolCallOpenTag(content, searchStart, out var _, out var _);
			if (start < 0)
			{
				sb.Append(content.Substring(searchStart));
				break;
			}
			sb.Append(content.Substring(searchStart, start - searchStart));
			int end = content.IndexOf("</tool_call>", start, StringComparison.OrdinalIgnoreCase);
			if (end < 0)
			{
				break;
			}
			searchStart = end + "</tool_call>".Length;
		}
		string stripped = StripPseudoToolTags(sb.ToString()).Trim();
		if (string.IsNullOrWhiteSpace(stripped))
		{
			if (!IsToolAdvertised(requestBody, "get_file") && !IsToolAdvertised(requestBody, "vs_read_file") && !IsToolAdvertised(requestBody, "create_file") && !IsToolAdvertised(requestBody, "replace_string_in_file"))
			{
				return "";
			}
			string userRequest = ExtractLastUserMessage(requestBody);
			stripped = (string.IsNullOrWhiteSpace(userRequest) ? "Continue from the current Visual Studio context. Do not read the project again." : ("Continue from the current Visual Studio context without reading the project again: " + userRequest));
		}
		return stripped;
	}

	private string StripPseudoToolTags(string content)
	{
		if (string.IsNullOrEmpty(content))
		{
			return "";
		}
		return Regex.Replace(content, "(?is)<\\s*(?:search_query|internet_search|browser_open|browser_read_page|browser_click_link|browser_click|browser_type|browser_select|browser_press|browser_find_text|arguments?|parameters?)\\b[^>]*>[\\s\\S]*?(?:<\\s*/\\s*(?:search_query|internet_search|browser_open|browser_read_page|browser_click_link|browser_click|browser_type|browser_select|browser_press|browser_find_text|arguments?|parameters?)\\s*>|<\\s*/\\s*>|<\\s*/\\s*|$)", "", RegexOptions.CultureInvariant);
	}

	private string SanitizeAssistantText(string content)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return content;
		}
		string withoutThinking = CleanAssistantVisibleContent(content).Trim();
		if (string.IsNullOrWhiteSpace(withoutThinking))
		{
			withoutThinking = content;
		}
		return CollapseRepeatedText(withoutThinking).Trim();
	}

	private string RemoveTaggedBlocks(string content, string tagName)
	{
		string openTag = "<" + tagName + ">";
		string closeTag = "</" + tagName + ">";
		StringBuilder sb = new StringBuilder();
		int searchStart = 0;
		while (searchStart < content.Length)
		{
			int start = content.IndexOf(openTag, searchStart, StringComparison.OrdinalIgnoreCase);
			if (start < 0)
			{
				sb.Append(content.Substring(searchStart));
				break;
			}
			sb.Append(content.Substring(searchStart, start - searchStart));
			int end = content.IndexOf(closeTag, start + openTag.Length, StringComparison.OrdinalIgnoreCase);
			if (end < 0)
			{
				break;
			}
			searchStart = end + closeTag.Length;
		}
		return sb.ToString();
	}

	private string CollapseRepeatedText(string content)
	{
		List<string> output = new List<string>();
		bool removedDuplicateLine = false;
		string previousNonBlankKey = "";
		string normalizedNewlines = content.Replace("\r\n", "\n").Replace('\r', '\n');
		string[] chunks = normalizedNewlines.Split(new char[1] { '\n' }, StringSplitOptions.None);
		string[] array = chunks;
		foreach (string chunk in array)
		{
			string trimmed = chunk.Trim();
			if (Regex.IsMatch(trimmed, "^</?final_answer\\b[^>]*>$", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant))
			{
				continue;
			}
			if (string.IsNullOrEmpty(trimmed))
			{
				if (output.Count > 0 && output[output.Count - 1].Length != 0)
				{
					output.Add("");
				}
				continue;
			}
			string key = NormalizeRepeatKey(trimmed);
			if (key.Length >= 24 && string.Equals(previousNonBlankKey, key, StringComparison.Ordinal))
			{
				removedDuplicateLine = true;
			}
			else
			{
				output.Add(chunk.TrimEnd());
			}
			previousNonBlankKey = key;
		}
		string collapsed = string.Join("\n", output).Trim();
		string repeatedSentence = "The build should be successful as no new files were added and existing files weren't modified.";
		int first = collapsed.IndexOf(repeatedSentence, StringComparison.Ordinal);
		if (first >= 0)
		{
			int second = collapsed.IndexOf(repeatedSentence, first + repeatedSentence.Length, StringComparison.Ordinal);
			if (second >= 0)
			{
				collapsed = collapsed.Substring(0, first + repeatedSentence.Length).Trim();
			}
		}
		int maxVisibleChars = removedDuplicateLine ? 12000 : 24000;
		if (collapsed.Length > maxVisibleChars)
		{
			collapsed = collapsed.Substring(0, maxVisibleChars).Trim() + "\n\n[" + (removedDuplicateLine ? "Response shortened by proxy after repeated output." : "Response shortened by proxy for display safety.") + "]";
		}
		return collapsed;
	}

	private string NormalizeRepeatKey(string text)
	{
		return text.Trim().ToLowerInvariant();
	}

	private string ExtractLastUserMessage(string requestBody)
	{
		string lastUserMessage = null;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return null;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (message.TryGetProperty("role", out var role) && role.ValueKind == JsonValueKind.String && role.GetString().Equals("user", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("content", out var content) && content.ValueKind == JsonValueKind.String)
				{
					lastUserMessage = content.GetString();
				}
			}
		}
		catch
		{
		}
		return lastUserMessage;
	}

	private string BuildTextOnlySseResponse(string content, string model)
	{
		long created = DateTimeOffset.UtcNow.ToUnixTimeSeconds();
		string completionId = "chatcmpl_" + Guid.NewGuid().ToString("N");
		string safeContent = EscapeJson(content ?? "");
		StringBuilder sb = new StringBuilder();
		sb.Append("data: {\"id\":\"").Append(completionId).Append("\",\"object\":\"chat.completion.chunk\",\"created\":")
			.Append(created)
			.Append(",\"model\":\"")
			.Append(EscapeJson(model ?? "lm-studio"))
			.Append("\",\"choices\":[{\"index\":0,\"delta\":{\"role\":\"assistant\"},\"finish_reason\":null}]}\n\n");
		sb.Append("data: {\"id\":\"").Append(completionId).Append("\",\"object\":\"chat.completion.chunk\",\"created\":")
			.Append(created)
			.Append(",\"model\":\"")
			.Append(EscapeJson(model ?? "lm-studio"))
			.Append("\",\"choices\":[{\"index\":0,\"delta\":{\"content\":\"")
			.Append(safeContent)
			.Append("\"},\"finish_reason\":null}]}\n\n");
		sb.Append("data: {\"id\":\"").Append(completionId).Append("\",\"object\":\"chat.completion.chunk\",\"created\":")
			.Append(created)
			.Append(",\"model\":\"")
			.Append(EscapeJson(model ?? "lm-studio"))
			.Append("\",\"choices\":[{\"index\":0,\"delta\":{},\"finish_reason\":\"stop\"}]}\n\n");
		sb.Append("data: [DONE]\n\n");
		return sb.ToString();
	}

	private ToolCallData ParseQwenToolCall(string json)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			JsonElement nameElement;
			string name = NormalizeLooseToolName((document.RootElement.TryGetProperty("name", out nameElement) && nameElement.ValueKind == JsonValueKind.String) ? nameElement.GetString() : "");
			string id = ExtractStringProperty(document.RootElement, "id") ?? "";
			string arguments = "{}";
			if (document.RootElement.TryGetProperty("arguments", out var argumentsElement) || document.RootElement.TryGetProperty("args", out argumentsElement) || document.RootElement.TryGetProperty("parameters", out argumentsElement) || document.RootElement.TryGetProperty("parameter", out argumentsElement))
			{
				arguments = ((argumentsElement.ValueKind == JsonValueKind.String) ? argumentsElement.GetString() : argumentsElement.GetRawText());
			}
			if (string.IsNullOrWhiteSpace(name))
			{
				return null;
			}
			string repairedArguments = RepairKnownToolArguments(name, arguments);
			if (!string.Equals(arguments ?? "{}", repairedArguments ?? "{}", StringComparison.Ordinal))
			{
				LogMessage("[Tool Args Repair] " + name + ": " + TruncateForLog(arguments, 300) + " -> " + TruncateForLog(repairedArguments, 300));
			}
			return new ToolCallData
			{
				Id = id,
				Name = name,
				ArgumentsJson = repairedArguments
			};
		}
		catch (Exception ex)
		{
			LogMessage("Error parsing Qwen tool call: " + ex.Message);
			return null;
		}
	}

	private bool IsValidJsonObject(string json)
	{
		if (string.IsNullOrWhiteSpace(json))
		{
			return false;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			return document.RootElement.ValueKind == JsonValueKind.Object;
		}
		catch
		{
			return false;
		}
	}

	private string RepairKnownToolArguments(string toolName, string argumentsJson)
	{
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			argumentsJson = "{}";
		}
		argumentsJson = RepairBareWindowsBackslashesInJsonStrings(toolName, argumentsJson);
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			if (toolName.Equals("code_search", StringComparison.Ordinal) && (!document.RootElement.TryGetProperty("searchQueries", out var searchQueries) || searchQueries.ValueKind != JsonValueKind.Array || searchQueries.GetArrayLength() == 0))
			{
				return "{\"searchQueries\":[\"fkkvs\",\"ToolSelection.xaml\",\"tool selection window\",\"new tool window\"]}";
			}
			if (toolName.Equals("file_search", StringComparison.Ordinal))
			{
				return RepairFileSearchArguments(document.RootElement);
			}
			if (toolName.Equals("get_files_in_project", StringComparison.Ordinal) && (!document.RootElement.TryGetProperty("projectPath", out var projectPath) || projectPath.ValueKind != JsonValueKind.String || string.IsNullOrWhiteSpace(projectPath.GetString())))
			{
				return "{\"projectPath\":\"Maf Scale/ME7Tools.vbproj\"}";
			}
			if (toolName.Equals("get_files_in_project", StringComparison.Ordinal))
			{
				string projectPathValue = ((document.RootElement.TryGetProperty("projectPath", out var projectPathElement) && projectPathElement.ValueKind == JsonValueKind.String) ? projectPathElement.GetString() : "Maf Scale/ME7Tools.vbproj");
				projectPathValue = NormalizeToolPathForVsArgument(projectPathValue);
				if (string.IsNullOrWhiteSpace(projectPathValue))
				{
					projectPathValue = "Maf Scale/ME7Tools.vbproj";
				}
				return "{\"projectPath\":\"" + EscapeJson(projectPathValue) + "\"}";
			}
			if (toolName.Equals("get_file", StringComparison.Ordinal))
			{
				string filename = ((document.RootElement.TryGetProperty("filename", out var filenameElement) && filenameElement.ValueKind == JsonValueKind.String) ? filenameElement.GetString() : "");
				JsonElement startLineElement;
				int parsedStartLine;
				int startLine = ((!document.RootElement.TryGetProperty("startLine", out startLineElement) || startLineElement.ValueKind != JsonValueKind.Number || !startLineElement.TryGetInt32(out parsedStartLine)) ? 1 : parsedStartLine);
				JsonElement endLineElement;
				int parsedEndLine;
				int endLine = ((document.RootElement.TryGetProperty("endLine", out endLineElement) && endLineElement.ValueKind == JsonValueKind.Number && endLineElement.TryGetInt32(out parsedEndLine)) ? parsedEndLine : 240);
				filename = NormalizeToolPathForVsArgument(CleanToolFilePathArgument(filename));
				if (string.IsNullOrWhiteSpace(filename))
				{
					filename = "Maf Scale/ToolSelection.xaml";
				}
				if (startLine <= 0)
				{
					startLine = 1;
				}
				if (endLine < startLine)
				{
					endLine = startLine + 239;
				}
				return "{\"filename\":\"" + EscapeJson(filename) + "\",\"startLine\":" + startLine + ",\"endLine\":" + endLine + ",\"includeLineNumbers\":true}";
			}
			if (toolName.Equals("run_command_in_terminal", StringComparison.Ordinal))
			{
				return RepairRunCommandInTerminalArguments(document.RootElement);
			}
			if (toolName.Equals("replace_string_in_file", StringComparison.Ordinal))
			{
				return RepairReplaceStringArguments(document.RootElement);
			}
			if (toolName.Equals("create_file", StringComparison.Ordinal))
			{
				return RepairCreateFileArguments(document.RootElement, argumentsJson);
			}
			if (toolName.Equals("update_plan_progress", StringComparison.Ordinal))
			{
				return RepairUpdatePlanProgressArguments(document.RootElement);
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Tool Args Repair] Could not parse " + toolName + " arguments: " + ex.Message + "; raw=" + TruncateForLog(argumentsJson, 300));
			if (toolName.Equals("code_search", StringComparison.Ordinal))
			{
				return "{\"searchQueries\":[\"fkkvs\",\"ToolSelection.xaml\",\"tool selection window\",\"new tool window\"]}";
			}
			if (toolName.Equals("file_search", StringComparison.Ordinal))
			{
				return "{\"queries\":[\"ToolSelection.xaml\",\"fkkvs\"],\"maxResults\":20}";
			}
			if (toolName.Equals("get_files_in_project", StringComparison.Ordinal))
			{
				return "{\"projectPath\":\"Maf Scale/ME7Tools.vbproj\"}";
			}
			if (toolName.Equals("get_file", StringComparison.Ordinal))
			{
				return "{\"filename\":\"Maf Scale/ToolSelection.xaml\",\"startLine\":1,\"endLine\":240,\"includeLineNumbers\":true}";
			}
			if (toolName.Equals("run_command_in_terminal", StringComparison.Ordinal))
			{
				return "{\"command\":\"Write-Host \\\"Command arguments were malformed and were blocked by LmVsProxy.\\\"\",\"summary\":\"Malformed command blocked by proxy\",\"background\":false}";
			}
			if (toolName.Equals("replace_string_in_file", StringComparison.Ordinal))
			{
				return "{\"filePath\":\"Maf Scale/ToolSelection.xaml\",\"oldString\":\"\",\"newString\":\"\"}";
			}
			if (toolName.Equals("create_file", StringComparison.Ordinal))
			{
				return BuildCreateFileArguments(TryExtractLikelyFilePath(argumentsJson), null);
			}
			if (toolName.Equals("update_plan_progress", StringComparison.Ordinal))
			{
				return "{\"stepId\":\"step-1\",\"status\":\"completed\",\"message\":\"Progress updated by LmVsProxy after malformed update_plan_progress arguments.\",\"autoAdvance\":true}";
			}
		}
		return string.IsNullOrWhiteSpace(argumentsJson) ? "{}" : argumentsJson;
	}

	private string RepairUpdatePlanProgressArguments(JsonElement arguments)
	{
		JsonElement stepIdElement;
		string stepId = ((arguments.TryGetProperty("stepId", out stepIdElement) && stepIdElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(stepIdElement.GetString())) ? stepIdElement.GetString() : "step-1");
		string status = ((arguments.TryGetProperty("status", out var statusElement) && statusElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(statusElement.GetString())) ? statusElement.GetString() : "completed");
		status = NormalizePlanProgressStatus(status);
		JsonElement messageElement;
		string message = ((arguments.TryGetProperty("message", out messageElement) && messageElement.ValueKind == JsonValueKind.String && !string.IsNullOrWhiteSpace(messageElement.GetString())) ? messageElement.GetString() : "Progress updated by LmVsProxy.");
		bool autoAdvance = true;
		if (arguments.TryGetProperty("autoAdvance", out var autoAdvanceElement))
		{
			bool parsedAutoAdvance;
			if (autoAdvanceElement.ValueKind == JsonValueKind.False)
			{
				autoAdvance = false;
			}
			else if (autoAdvanceElement.ValueKind == JsonValueKind.String && bool.TryParse(autoAdvanceElement.GetString(), out parsedAutoAdvance))
			{
				autoAdvance = parsedAutoAdvance;
			}
		}
		return "{\"stepId\":\"" + EscapeJson(stepId) + "\",\"status\":\"" + EscapeJson(status) + "\",\"message\":\"" + EscapeJson(message) + "\",\"autoAdvance\":" + (autoAdvance ? "true" : "false") + "}";
	}

	private string NormalizePlanProgressStatus(string status)
	{
		string normalized = (status ?? "").Trim().Replace("_", "-").ToLowerInvariant();
		switch (normalized)
		{
		case "pending":
		case "in-progress":
		case "completed":
		case "failed":
		case "skipped":
			return normalized;
		case "started":
		case "running":
			return "in-progress";
		case "complete":
		case "done":
		case "success":
			return "completed";
		default:
			return "completed";
		}
	}

	private string RepairCreateFileArguments(JsonElement arguments, string rawArgumentsJson)
	{
		JsonElement filePathElement;
		string filePath = ((arguments.TryGetProperty("filePath", out filePathElement) && filePathElement.ValueKind == JsonValueKind.String) ? filePathElement.GetString() : "");
		if (string.IsNullOrWhiteSpace(filePath))
		{
			filePath = TryExtractLikelyFilePath(rawArgumentsJson);
		}
		string content = ((arguments.TryGetProperty("content", out var contentElement) && contentElement.ValueKind == JsonValueKind.String) ? contentElement.GetString() : null);
		content = NormalizeGeneratedFileText(content);
		return BuildCreateFileArguments(filePath, content);
	}

	private string BuildCreateFileArguments(string filePath, string content)
	{
		filePath = NormalizeLoosePathEscapes(filePath);
		if (string.IsNullOrWhiteSpace(filePath))
		{
			filePath = "Maf Scale/fkkvs.xaml.vb";
		}
		filePath = filePath.Trim().Trim('"', '\'', ',', ' ');
		filePath = TrimDanglingSlashAfterFileExtension(filePath);
		if (filePath.EndsWith("\\", StringComparison.Ordinal) || filePath.EndsWith("/", StringComparison.Ordinal))
		{
			filePath += "fkkvs.xaml.vb";
		}
		if (!IsSafeCreateFileTarget(filePath))
		{
			LogMessage("[Tool Args Repair] create_file target is protected and will be guarded: " + filePath);
			return "{\"filePath\":\"" + EscapeJson(filePath) + "\",\"content\":\"" + EscapeJson(NormalizeGeneratedFileText(content) ?? "") + "\"}";
		}
		content = NormalizeGeneratedFileText(content);
		if (string.IsNullOrWhiteSpace(content))
		{
			content = BuildMinimalFileContent(filePath);
			LogMessage("[Tool Args Repair] create_file was missing content; generated minimal content for " + filePath);
		}
		return "{\"filePath\":\"" + EscapeJson(filePath) + "\",\"content\":\"" + EscapeJson(content) + "\"}";
	}

	private string RepairReplaceStringArguments(JsonElement arguments)
	{
		string filePath = ((arguments.TryGetProperty("filePath", out var filePathElement) && filePathElement.ValueKind == JsonValueKind.String) ? RepairPathControlCharacters(filePathElement.GetString()) : "");
		string oldString = ((arguments.TryGetProperty("oldString", out var oldStringElement) && oldStringElement.ValueKind == JsonValueKind.String) ? oldStringElement.GetString() : "");
		string newString = ((arguments.TryGetProperty("newString", out var newStringElement) && newStringElement.ValueKind == JsonValueKind.String) ? newStringElement.GetString() : "");
		filePath = NormalizeLoosePathEscapes(filePath);
		oldString = NormalizeGeneratedFileText(oldString);
		newString = NormalizeGeneratedFileText(newString);
		return "{\"filePath\":\"" + EscapeJson(filePath) + "\",\"oldString\":\"" + EscapeJson(oldString ?? "") + "\",\"newString\":\"" + EscapeJson(newString ?? "") + "\"}";
	}

	private string NormalizeGeneratedFileText(string text)
	{
		if (text == null)
		{
			return null;
		}
		string normalized = text.Replace("\\r\\n", "\n").Replace("\\n", "\n").Replace("\\r", "\n")
			.Replace("\\t", "\t");
		normalized = NormalizeLineEndings(normalized);
		normalized = CollapseDuplicatedGeneratedContent(normalized);
		if (!string.Equals(text, normalized, StringComparison.Ordinal))
		{
			LogMessage("[Tool Args Repair] Normalized generated file text escapes/duplicates.");
		}
		return normalized;
	}

	private string NormalizeLineEndings(string text)
	{
		if (text == null)
		{
			return null;
		}
		string lf = text.Replace("\r\n", "\n").Replace("\r", "\n");
		return lf.Replace("\n", Environment.NewLine);
	}

	private string CollapseDuplicatedGeneratedContent(string text)
	{
		if (string.IsNullOrWhiteSpace(text))
		{
			return text;
		}
		string lf = text.Replace("\r\n", "\n").Replace("\r", "\n");
		string trimmed = lf.Trim();
		int middle = trimmed.Length / 2;
		int start = Math.Max(1, middle - 20);
		int end = Math.Min(trimmed.Length - 1, middle + 20);
		for (int i = start; i <= end; i++)
		{
			if (trimmed[i - 1] == '\n' || trimmed[i] == '\n')
			{
				string first = trimmed.Substring(0, i).Trim();
				string second = trimmed.Substring(i).Trim();
				if (first.Length > 0 && first.Equals(second, StringComparison.Ordinal))
				{
					return NormalizeLineEndings(first) + Environment.NewLine;
				}
			}
		}
		return text;
	}

	private string TrimDanglingSlashAfterFileExtension(string filePath)
	{
		if (string.IsNullOrWhiteSpace(filePath) || (!filePath.EndsWith("\\", StringComparison.Ordinal) && !filePath.EndsWith("/", StringComparison.Ordinal)))
		{
			return filePath;
		}
		string withoutSlash = filePath.Substring(0, filePath.Length - 1);
		string extension = Path.GetExtension(withoutSlash);
		if (string.IsNullOrWhiteSpace(extension))
		{
			return filePath;
		}
		return withoutSlash;
	}

	private string BuildMinimalFileContent(string filePath)
	{
		string normalized = filePath ?? "";
		string fileName = normalized.Replace('\\', '/');
		int slash = fileName.LastIndexOf('/');
		if (slash >= 0)
		{
			fileName = fileName.Substring(slash + 1);
		}
		string className = fileName;
		int dot = className.IndexOf('.');
		if (dot > 0)
		{
			className = className.Substring(0, dot);
		}
		if (string.IsNullOrWhiteSpace(className) || className.StartsWith(".", StringComparison.Ordinal))
		{
			className = "fkkvs";
		}
		if (normalized.EndsWith(".xaml.vb", StringComparison.OrdinalIgnoreCase) || normalized.EndsWith(".vb", StringComparison.OrdinalIgnoreCase))
		{
			return "Public Class " + className + Environment.NewLine + "End Class" + Environment.NewLine;
		}
		if (normalized.EndsWith(".xaml", StringComparison.OrdinalIgnoreCase))
		{
			return "<Window x:Class=\"" + className + "\"" + Environment.NewLine + "        xmlns=\"http://schemas.microsoft.com/winfx/2006/xaml/presentation\"" + Environment.NewLine + "        xmlns:x=\"http://schemas.microsoft.com/winfx/2006/xaml\"" + Environment.NewLine + "        Title=\"" + className + "\" Height=\"400\" Width=\"800\">" + Environment.NewLine + "    <Grid />" + Environment.NewLine + "</Window>" + Environment.NewLine;
		}
		return "";
	}

	private string TryExtractLikelyFilePath(string rawArgumentsJson)
	{
		if (string.IsNullOrWhiteSpace(rawArgumentsJson))
		{
			return null;
		}
		Match match = Regex.Match(rawArgumentsJson, "\"filePath\"\\s*:\\s*\"(?<path>[^\"]+)", RegexOptions.IgnoreCase);
		if (!match.Success)
		{
			return null;
		}
		string path = NormalizeLoosePathEscapes(match.Groups["path"].Value);
		path = path.Trim().Trim('"', '\'', ',', ' ');
		return HasUsableFileNameStem(path) ? path : null;
	}

	private string NormalizeLoosePathEscapes(string value)
	{
		if (string.IsNullOrEmpty(value))
		{
			return value;
		}
		string repaired = RepairPathControlCharacters(value);
		repaired = repaired.Replace("\\\"", "\"").Replace("\\u0022", "\"").Replace("\\U0022", "\"")
			.Replace("u0022", "\"");
		return CanonicalizeDuplicateFileExtensions(repaired.Trim().Trim('"', '\'', ',', ' '));
	}

	private string NormalizeToolPathForVsArgument(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return value;
		}
		string repaired = NormalizeLoosePathEscapes(value).Trim().Trim('"', '\'', ',', ' ');
		return repaired.Replace('\\', '/');
	}

	private string CanonicalizeDuplicateFileExtensions(string path)
	{
		if (string.IsNullOrWhiteSpace(path))
		{
			return path;
		}
		string normalized = path;
		string previous;
		do
		{
			previous = normalized;
			normalized = Regex.Replace(normalized, "(?i)\\.xaml(?:\\.xaml)+\\.vb$", ".xaml.vb");
			normalized = Regex.Replace(normalized, "(?i)\\.xaml(?:\\.xaml)+$", ".xaml");
			normalized = Regex.Replace(normalized, "(?i)\\.vb(?:\\.vb)+$", ".vb");
			normalized = Regex.Replace(normalized, "(?i)\\.cs(?:\\.cs)+$", ".cs");
		}
		while (!string.Equals(previous, normalized, StringComparison.Ordinal));
		if (!string.Equals(path, normalized, StringComparison.Ordinal))
		{
			LogMessage("[Path Repair] Canonicalized duplicate extension path: " + path + " -> " + normalized);
		}
		return normalized;
	}

	private string RepairFileSearchArguments(JsonElement arguments)
	{
		List<string> queries = new List<string>();
		AddStringArrayOrStringProperty(arguments, "queries", queries);
		AddStringArrayOrStringProperty(arguments, "query", queries);
		AddStringArrayOrStringProperty(arguments, "searchQuery", queries);
		AddStringArrayOrStringProperty(arguments, "searchQueries", queries);
		AddStringArrayOrStringProperty(arguments, "file", queries);
		AddStringArrayOrStringProperty(arguments, "filename", queries);
		AddStringArrayOrStringProperty(arguments, "fileName", queries);
		AddStringArrayOrStringProperty(arguments, "path", queries);
		if (queries.Count == 0)
		{
			queries.Add("ToolSelection.xaml");
			queries.Add("fkkvs");
		}
		int maxResults = 20;
		if (!TryGetIntProperty(arguments, "maxResults", out maxResults) && !TryGetIntProperty(arguments, "max_results", out maxResults))
		{
			maxResults = 20;
		}
		if (maxResults <= 0)
		{
			maxResults = 20;
		}
		if (maxResults > 50)
		{
			maxResults = 50;
		}
		StringBuilder sb = new StringBuilder();
		sb.Append("{\"queries\":[");
		for (int i = 0; i < queries.Count; i++)
		{
			if (i > 0)
			{
				sb.Append(",");
			}
			sb.Append("\"").Append(EscapeJson(NormalizeFileSearchQuery(queries[i]))).Append("\"");
		}
		sb.Append("],\"maxResults\":").Append(maxResults.ToString()).Append("}");
		return sb.ToString();
	}

	private string NormalizeFileSearchQuery(string query)
	{
		if (string.IsNullOrWhiteSpace(query))
		{
			return query;
		}
		string trimmed = RepairPathControlCharacters(query.Trim());
		string lower = trimmed.ToLowerInvariant();
		switch (lower)
		{
		case "*.cpp":
			return ".cpp";
		case "*.c":
			return ".c";
		case "*.h":
			return ".h";
		case "*.hpp":
			return ".hpp";
		case "*.cs":
			return ".cs";
		case "*.vb":
			return ".vb";
		case "*.xaml":
			return ".xaml";
		default:
			if (lower.StartsWith("*.", StringComparison.Ordinal) && lower.Length > 2)
			{
				return trimmed.Substring(1);
			}
			if (lower.StartsWith("**/*.", StringComparison.Ordinal) && lower.Length > 5)
			{
				return trimmed.Substring(4);
			}
			return trimmed;
		}
	}

	private void AddStringArrayOrStringProperty(JsonElement arguments, string propertyName, List<string> values)
	{
		if (!arguments.TryGetProperty(propertyName, out var property))
		{
			return;
		}
		if (property.ValueKind == JsonValueKind.String)
		{
			AddDistinctNonEmpty(values, property.GetString());
		}
		else
		{
			if (property.ValueKind != JsonValueKind.Array)
			{
				return;
			}
			foreach (JsonElement item in property.EnumerateArray())
			{
				if (item.ValueKind == JsonValueKind.String)
				{
					AddDistinctNonEmpty(values, item.GetString());
				}
			}
		}
	}

	private void AddDistinctNonEmpty(List<string> values, string value)
	{
		if (values == null || string.IsNullOrWhiteSpace(value))
		{
			return;
		}
		string trimmed = RepairPathControlCharacters(value.Trim());
		foreach (string existing in values)
		{
			if (existing.Equals(trimmed, StringComparison.OrdinalIgnoreCase))
			{
				return;
			}
		}
		values.Add(trimmed);
	}

	private string RepairBareWindowsBackslashesInJsonStrings(string toolName, string argumentsJson)
	{
		if (string.IsNullOrEmpty(argumentsJson) || !argumentsJson.Contains("\\", StringComparison.Ordinal))
		{
			return argumentsJson;
		}
		StringBuilder sb = null;
		bool inString = false;
		for (int i = 0; i < argumentsJson.Length; i++)
		{
			char ch = argumentsJson[i];
			if (ch == '"' && !IsEscapedQuote(argumentsJson, i))
			{
				inString = !inString;
				sb?.Append(ch);
			}
			else if (inString && ch == '\\' && LooksLikeBareWindowsPathBackslash(argumentsJson, i))
			{
				if (sb == null)
				{
					sb = new StringBuilder(argumentsJson.Length + 8);
					sb.Append(argumentsJson, 0, i);
				}
				sb.Append("\\\\");
			}
			else
			{
				sb?.Append(ch);
			}
		}
		if (sb == null)
		{
			return argumentsJson;
		}
		string repaired = sb.ToString();
		LogMessage("[Tool Args Path Repair] " + (string.IsNullOrWhiteSpace(toolName) ? "<unknown>" : toolName) + ": " + TruncateForLog(argumentsJson, 300) + " -> " + TruncateForLog(repaired, 300));
		return repaired;
	}

	private bool IsEscapedQuote(string text, int quoteIndex)
	{
		int slashCount = 0;
		int i = quoteIndex - 1;
		while (i >= 0 && text[i] == '\\')
		{
			slashCount++;
			i--;
		}
		return slashCount % 2 == 1;
	}

	private bool LooksLikeBareWindowsPathBackslash(string text, int slashIndex)
	{
		if (string.IsNullOrEmpty(text) || slashIndex <= 0 || slashIndex >= text.Length - 1)
		{
			return false;
		}
		char previous = text[slashIndex - 1];
		char next = text[slashIndex + 1];
		if (previous == '\\' || next == '\\' || next == '"' || (next == 'u' && HasFourHexDigits(text, slashIndex + 2)))
		{
			return false;
		}
		string prefix = GetCurrentArgumentTokenPrefix(text, slashIndex);
		if (prefix.Length >= 2 && prefix[prefix.Length - 1] == ':' && IsAsciiLetter(prefix[prefix.Length - 2]))
		{
			return true;
		}
		return Regex.IsMatch(prefix, "(?i)(^|[\\s\"'`(=])(?:[A-Z]:[\\\\/]|\\\\\\\\)[^\\s\"'`|<>]*$");
	}

	private bool HasFourHexDigits(string text, int startIndex)
	{
		if (startIndex < 0 || startIndex + 4 > text.Length)
		{
			return false;
		}
		for (int i = startIndex; i < startIndex + 4; i++)
		{
			char ch = text[i];
			if ((ch < '0' || ch > '9') && (ch < 'a' || ch > 'f') && (ch < 'A' || ch > 'F'))
			{
				return false;
			}
		}
		return true;
	}

	private string GetCurrentArgumentTokenPrefix(string text, int index)
	{
		int start;
		for (start = index; start > 0; start--)
		{
			char ch = text[start - 1];
			if (char.IsWhiteSpace(ch) || ch == '"' || ch == '\'' || ch == '`' || ch == '|' || ch == '<' || ch == '>' || ch == '{' || ch == '[' || ch == ',')
			{
				break;
			}
		}
		return text.Substring(start, index - start);
	}

	private bool IsAsciiLetter(char ch)
	{
		return (ch >= 'A' && ch <= 'Z') || (ch >= 'a' && ch <= 'z');
	}

	private string RepairDecodedWindowsPathEscapesInText(string value)
	{
		if (string.IsNullOrEmpty(value))
		{
			return value;
		}
		StringBuilder sb = null;
		for (int i = 0; i < value.Length; i++)
		{
			char ch = value[i];
			string replacement = GetDecodedPathEscapeReplacement(ch);
			if (replacement != null && LooksLikeDecodedWindowsPathEscape(value, i))
			{
				if (sb == null)
				{
					sb = new StringBuilder(value.Length + 4);
					sb.Append(value, 0, i);
				}
				sb.Append(replacement);
			}
			else
			{
				sb?.Append(ch);
			}
		}
		if (sb == null)
		{
			return value;
		}
		string repaired = sb.ToString();
		LogMessage("[Command Path Repair] " + EscapeControlCharsForLog(value) + " -> " + EscapeControlCharsForLog(repaired));
		return repaired;
	}

	private bool LooksLikeDecodedWindowsPathEscape(string value, int index)
	{
		if (string.IsNullOrEmpty(value) || index <= 0 || index >= value.Length - 1 || char.IsWhiteSpace(value[index - 1]) || char.IsWhiteSpace(value[index + 1]))
		{
			return false;
		}
		string prefix = GetCurrentArgumentTokenPrefix(value, index);
		if (prefix.Length >= 2 && prefix[prefix.Length - 1] == ':' && IsAsciiLetter(prefix[prefix.Length - 2]))
		{
			return true;
		}
		return Regex.IsMatch(prefix, "(?i)(^|[\\s\"'`(=])(?:[A-Z]:[\\\\/]|\\\\\\\\)[^\\s\"'`|<>]*$");
	}

	private string GetDecodedPathEscapeReplacement(char ch)
	{
		return ch switch
		{
			'\f' => "\\f", 
			'\t' => "\\t", 
			'\n' => "\\n", 
			'\r' => "\\r", 
			'\b' => "\\b", 
			_ => null, 
		};
	}

	private string RepairPathControlCharacters(string value)
	{
		if (string.IsNullOrEmpty(value))
		{
			return value;
		}
		StringBuilder sb = null;
		for (int i = 0; i < value.Length; i++)
		{
			char ch = value[i];
			string replacement = GetDecodedPathEscapeReplacement(ch);
			if (replacement != null)
			{
				if (sb == null)
				{
					sb = new StringBuilder(value.Length + 4);
					sb.Append(value, 0, i);
				}
				sb.Append(replacement);
			}
			else
			{
				sb?.Append(ch);
			}
		}
		if (sb == null)
		{
			return value;
		}
		string repaired = sb.ToString();
		LogMessage("[Path Repair] " + EscapeControlCharsForLog(value) + " -> " + EscapeControlCharsForLog(repaired));
		return repaired;
	}

	private bool TryGetIntProperty(JsonElement arguments, string propertyName, out int value)
	{
		value = 0;
		if (!arguments.TryGetProperty(propertyName, out var property))
		{
			return false;
		}
		if (property.ValueKind == JsonValueKind.Number)
		{
			return property.TryGetInt32(out value);
		}
		if (property.ValueKind == JsonValueKind.String)
		{
			return int.TryParse(property.GetString(), out value);
		}
		return false;
	}

	private string RepairRunCommandInTerminalArguments(JsonElement arguments)
	{
		string command = ((arguments.TryGetProperty("command", out var commandElement) && commandElement.ValueKind == JsonValueKind.String) ? commandElement.GetString() : "");
		JsonElement summaryElement;
		string summary = ((arguments.TryGetProperty("summary", out summaryElement) && summaryElement.ValueKind == JsonValueKind.String) ? summaryElement.GetString() : "Run command");
		JsonElement backgroundElement;
		bool background = arguments.TryGetProperty("background", out backgroundElement) && backgroundElement.ValueKind == JsonValueKind.True;
		command = RepairPowerShellHereStrings(command);
		command = RepairDecodedWindowsPathEscapesInText(command);
		command = RepairUnixShellCommandForPowerShell(command);
		return "{\"command\":\"" + EscapeJson(command) + "\",\"summary\":\"" + EscapeJson(summary) + "\",\"background\":" + (background ? "true" : "false") + "}";
	}

	private string RepairUnixShellCommandForPowerShell(string command)
	{
		if (string.IsNullOrWhiteSpace(command))
		{
			return command;
		}
		string trimmed = command.Trim();
		string normalized = Regex.Replace(trimmed, "\\s+", " ");
		if (normalized.Equals("pwd && find . -type f 2>/dev/null | head -50", StringComparison.OrdinalIgnoreCase) || normalized.Equals("pwd && find . -type f | head -50", StringComparison.OrdinalIgnoreCase))
		{
			LogMessage("[Tool Args Repair] Rewrote Unix discovery command for PowerShell.");
			return "Get-Location; Get-ChildItem -Path . -Recurse -File -ErrorAction SilentlyContinue | Select-Object -First 50 -ExpandProperty FullName";
		}
		if (normalized.Equals("pwd", StringComparison.OrdinalIgnoreCase))
		{
			return "Get-Location";
		}
		Match findHead = Regex.Match(normalized, "^find\\s+\\.\\s+-type\\s+f(?:\\s+2>/dev/null)?\\s*\\|\\s*head\\s+-(?<count>\\d+)$", RegexOptions.IgnoreCase);
		if (findHead.Success)
		{
			string count = findHead.Groups["count"].Value;
			LogMessage("[Tool Args Repair] Rewrote Unix find/head command for PowerShell.");
			return "Get-ChildItem -Path . -Recurse -File -ErrorAction SilentlyContinue | Select-Object -First " + count + " -ExpandProperty FullName";
		}
		return command;
	}

	private string RepairPowerShellHereStrings(string command)
	{
		if (string.IsNullOrEmpty(command))
		{
			return command;
		}
		string repaired = command.Replace("@'\\n", "@'\n").Replace("@\"\\n", "@\"\n").Replace("\\n'@", "\n'@")
			.Replace("\\n\"@", "\n\"@");
		repaired = Regex.Replace(repaired, "@'(?=\\S)", "@'\n");
		repaired = Regex.Replace(repaired, "@\"(?=\\S)", "@\"\n");
		repaired = Regex.Replace(repaired, "(?<!\\n)'@", "\n'@");
		return Regex.Replace(repaired, "(?<!\\n)\"@", "\n\"@");
	}

	private string ExtractJsonStringProperty(string json, string propertyName)
	{
		if (string.IsNullOrWhiteSpace(json) || string.IsNullOrWhiteSpace(propertyName))
		{
			return null;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(json);
			JsonElement value;
			return (document.RootElement.TryGetProperty(propertyName, out value) && value.ValueKind == JsonValueKind.String) ? value.GetString() : null;
		}
		catch
		{
			return null;
		}
	}

	private string PrepareRequestBodyForLmStudio(HttpListenerRequest originalRequest, string requestBody)
	{
		if (originalRequest == null || originalRequest.Url?.AbsolutePath == null || string.IsNullOrWhiteSpace(requestBody))
		{
			return requestBody;
		}
		if (!originalRequest.Url.AbsolutePath.Equals("/v1/chat/completions", StringComparison.OrdinalIgnoreCase))
		{
			return requestBody;
		}
		string ownerKey = GetHttpPromptOwnerKey(originalRequest);
		string sessionId = ExtractChatUiSessionId(requestBody);
		requestBody = RepairConversationToolCallHistory(requestBody, ownerKey, sessionId);
		requestBody = AddChatSessionCompatibilityHintToOpenAiRequest(requestBody, ownerKey, sessionId, GetLocalModelRuntimeDisplayName());
		requestBody = AddCreateFileHintAfterRepeatedFileSearchMisses(requestBody);
		requestBody = AddMissingCodebehindCreationHint(requestBody);
		requestBody = AddToolSchemaRecoveryHints(requestBody);
		requestBody = AddBuildErrorRepairHint(requestBody);
		requestBody = AddProxyResearchTools(requestBody, GetChatPermissions(), includeVsTools: false, includeTerminalTools: false, includeBrowserTools: false, ownerKey);
		return requestBody;
	}

	private string AddChatSessionCompatibilityHintToOpenAiRequest(string requestBody, string ownerKey, string sessionId, string runtime)
	{
		if (string.IsNullOrWhiteSpace(requestBody) || string.IsNullOrWhiteSpace(sessionId) || requestBody.IndexOf("[LmVsProxy session metadata]", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			return requestBody;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			JsonElement root = document.RootElement;
			if (root.ValueKind != JsonValueKind.Object)
			{
				return requestBody;
			}
			string hint = BuildChatSessionCompatibilitySystemHint(root, ownerKey, runtime, sessionId);
			if (string.IsNullOrWhiteSpace(hint))
			{
				return requestBody;
			}
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			writer.WriteStartObject();
			bool wroteMessages = false;
			foreach (JsonProperty property in root.EnumerateObject())
			{
				if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
				{
					wroteMessages = true;
					writer.WritePropertyName("messages");
					writer.WriteStartArray();
					foreach (JsonElement item in property.Value.EnumerateArray())
					{
						item.WriteTo(writer);
					}
					writer.WriteStartObject();
					writer.WriteString("role", "system");
					writer.WriteString("content", hint);
					writer.WriteEndObject();
					writer.WriteEndArray();
				}
				else
				{
					property.WriteTo(writer);
				}
			}
			writer.WriteEndObject();
			writer.Flush();
			return wroteMessages ? Encoding.UTF8.GetString(stream.ToArray()) : requestBody;
		}
		catch
		{
			return requestBody;
		}
	}

	private string ApplyIncomingPermissionGates(HttpListenerRequest originalRequest, string requestBody)
	{
		try
		{
			if (originalRequest == null || originalRequest.Url?.AbsolutePath == null || string.IsNullOrWhiteSpace(requestBody))
			{
				return requestBody;
			}
			string path = originalRequest.Url.AbsolutePath;
			if (!path.Equals("/v1/chat/completions", StringComparison.OrdinalIgnoreCase) && !path.Equals("/v1/responses", StringComparison.OrdinalIgnoreCase))
			{
				return requestBody;
			}
			ChatPermissionState permissions = GetChatPermissions();
			if (permissions.vsCopilotTools)
			{
				return requestBody;
			}
			string stripped = StripToolSchemasFromRequest(requestBody, "[LmVsProxy permissions] VS Copilot tools are disabled by the SocketJack admin. Do not call tools in this turn; answer with normal text from the available conversation context.");
			LogMessage("[Permissions] VS Copilot tools disabled; removed incoming tool schemas for " + path + ".");
			return stripped;
		}
		catch (Exception ex)
		{
			LogMessage("[Permissions] Could not apply incoming permission gates: " + ex.Message);
			return requestBody;
		}
	}

	private string StripToolSchemasFromRequest(string requestBody, string systemHint)
	{
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return requestBody;
		}
		using JsonDocument document = JsonDocument.Parse(requestBody);
		using MemoryStream stream = new MemoryStream();
		using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
		JsonElement root = document.RootElement;
		if (root.ValueKind != JsonValueKind.Object)
		{
			return requestBody;
		}
		bool wroteMessages = false;
		bool wroteInstructions = false;
		writer.WriteStartObject();
		foreach (JsonProperty property in root.EnumerateObject())
		{
			if (property.NameEquals("tools") || property.NameEquals("tool_choice"))
			{
				continue;
			}
			if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
			{
				wroteMessages = true;
				writer.WritePropertyName("messages");
				writer.WriteStartArray();
				foreach (JsonElement item in property.Value.EnumerateArray())
				{
					item.WriteTo(writer);
				}
				writer.WriteStartObject();
				writer.WriteString("role", "system");
				writer.WriteString("content", systemHint ?? "");
				writer.WriteEndObject();
				writer.WriteEndArray();
			}
			else if (property.NameEquals("instructions") && property.Value.ValueKind == JsonValueKind.String)
			{
				wroteInstructions = true;
				writer.WriteString("instructions", property.Value.GetString() + "\n\n" + systemHint);
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteMessages && !wroteInstructions && !string.IsNullOrWhiteSpace(systemHint))
		{
			writer.WriteString("instructions", systemHint);
		}
		writer.WriteEndObject();
		writer.Flush();
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private string AddProxyResearchTools(string requestBody, ChatPermissionState permissions, bool includeVsTools = false, bool includeTerminalTools = false, bool includeBrowserTools = false, string ownerKey = null)
	{
		try
		{
			bool includeLlmRuntimeTools = includeVsTools && permissions != null && permissions.agentAccess && permissions.vsCopilotTools && HasLlmRuntimeToolSchemas();
			bool includeGitTools = includeVsTools && permissions != null && permissions.agentAccess && IsGitCliAvailable();
			bool includeSockJackDmlTools = includeVsTools && permissions != null && permissions.agentAccess;
			if (permissions == null || (!permissions.internetSearch && !permissions.fileDownloads && (!includeVsTools || !permissions.vsCopilotTools) && (!includeBrowserTools || !permissions.agentAccess) && !includeGitTools && !includeSockJackDmlTools && (!includeTerminalTools || !permissions.terminalCommands) && !includeLlmRuntimeTools))
			{
				return requestBody;
			}
			if (string.IsNullOrWhiteSpace(requestBody))
			{
				return requestBody;
			}
			bool requiresProxyFileWrite = includeVsTools && PromptRequestsProxyFileWrite(ExtractRequiredProxyFileWritePrompt(requestBody));
			if (includeVsTools && ShouldBypassAgentToolSchemasForDirectPrompt(requestBody) && !requiresProxyFileWrite)
			{
				LogMessage("[Proxy Research] Skipped Agent tool schemas for a direct prompt.");
				return RewriteDirectAgentPromptWithoutTools(requestBody);
			}
			bool alreadyHasProxyResearchTools = RequestAlreadyHasProxyResearchTools(requestBody);
			if (alreadyHasProxyResearchTools && IsToolAdvertised(requestBody, "vs_write_file"))
			{
				return requiresProxyFileWrite ? RewriteRequestToolChoiceRequired(requestBody) : requestBody;
			}
			if (alreadyHasProxyResearchTools && !requiresProxyFileWrite)
			{
				return requestBody;
			}
			if (IsToolChoiceNone(requestBody) && !requiresProxyFileWrite)
			{
				return requestBody;
			}
			bool compactFileToolsOnly = requiresProxyFileWrite;
			using JsonDocument document = JsonDocument.Parse(requestBody);
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			writer.WriteStartObject();
			bool wroteTools = false;
			bool wroteMessages = false;
			bool wroteToolChoice = false;
			bool wroteRequiredFileWriteMarker = false;
			string requiredFileWriteTarget = compactFileToolsOnly ? ExtractLikelyRequestedFileTarget(ExtractRequiredProxyFileWritePrompt(requestBody)) : "";
			foreach (JsonProperty property in document.RootElement.EnumerateObject())
			{
				if (property.NameEquals("tools") && property.Value.ValueKind == JsonValueKind.Array)
				{
					wroteTools = true;
					writer.WritePropertyName("tools");
					writer.WriteStartArray();
					foreach (JsonElement item in property.Value.EnumerateArray())
					{
						item.WriteTo(writer);
					}
					WriteProxyResearchToolSchemas(writer, permissions, includeVsTools, includeTerminalTools, includeBrowserTools, compactFileToolsOnly);
					writer.WriteEndArray();
				}
				else if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
				{
					wroteMessages = true;
					writer.WritePropertyName("messages");
					writer.WriteStartArray();
					foreach (JsonElement item2 in property.Value.EnumerateArray())
					{
						item2.WriteTo(writer);
					}
					writer.WriteStartObject();
					writer.WriteString("role", "system");
					writer.WriteString("content", BuildProxyResearchToolSystemPrompt(permissions, includeVsTools, includeTerminalTools, includeBrowserTools, ownerKey, compactFileToolsOnly));
					writer.WriteEndObject();
					writer.WriteEndArray();
				}
				else if (property.NameEquals("tool_choice"))
				{
					writer.WriteString("tool_choice", compactFileToolsOnly ? "required" : "auto");
					wroteToolChoice = true;
				}
				else if (property.NameEquals("lmvs_required_file_write") || property.NameEquals("lmvs_required_file_write_target"))
				{
					property.WriteTo(writer);
					wroteRequiredFileWriteMarker = true;
				}
				else
				{
					property.WriteTo(writer);
				}
			}
			if (!wroteTools)
			{
				writer.WritePropertyName("tools");
				writer.WriteStartArray();
				WriteProxyResearchToolSchemas(writer, permissions, includeVsTools, includeTerminalTools, includeBrowserTools, compactFileToolsOnly);
				writer.WriteEndArray();
			}
			if (!wroteMessages)
			{
				writer.WritePropertyName("messages");
				writer.WriteStartArray();
				writer.WriteStartObject();
				writer.WriteString("role", "system");
				writer.WriteString("content", BuildProxyResearchToolSystemPrompt(permissions, includeVsTools, includeTerminalTools, includeBrowserTools, ownerKey, compactFileToolsOnly));
				writer.WriteEndObject();
				writer.WriteEndArray();
			}
			if (!wroteToolChoice)
			{
				writer.WriteString("tool_choice", compactFileToolsOnly ? "required" : "auto");
			}
			if (compactFileToolsOnly && !wroteRequiredFileWriteMarker)
			{
				writer.WriteBoolean("lmvs_required_file_write", value: true);
				if (!string.IsNullOrWhiteSpace(requiredFileWriteTarget))
				{
					writer.WriteString("lmvs_required_file_write_target", requiredFileWriteTarget);
				}
			}
			writer.WriteEndObject();
			writer.Flush();
			LogMessage(compactFileToolsOnly ? "[Proxy Research] Added compact file-write tools to LM Studio request." : "[Proxy Research] Added permission-enabled research tools to LM Studio request.");
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (Exception ex)
		{
			LogMessage("[Proxy Research] Could not add research tools: " + ex.Message);
			return requestBody;
		}
	}

	private bool ShouldBypassAgentToolSchemasForDirectPrompt(string requestBody)
	{
		if (string.IsNullOrWhiteSpace(requestBody))
		{
			return false;
		}
		string prompt = ExtractChatUiLastUserPromptText(requestBody);
		if (string.IsNullOrWhiteSpace(prompt))
		{
			return false;
		}
		return !PromptLikelyNeedsProxyTools(prompt);
	}

	private string RewriteDirectAgentPromptWithoutTools(string requestBody)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			JsonElement root = document.RootElement;
			string prompt = ExtractChatUiLastUserPromptText(requestBody);
			string model = ExtractStringProperty(root, "model") ?? "";
			bool exactReply = PromptRequestsExactReply(prompt);
			bool addNoThink = DirectPromptShouldDisableThinking(model, prompt);
			int directMaxTokens = (exactReply ? 64 : 0);
			bool wroteMaxTokens = false;
			bool wroteToolChoice = false;
			writer.WriteStartObject();
			foreach (JsonProperty property in root.EnumerateObject())
			{
				if (!property.NameEquals("tools"))
				{
					if (property.NameEquals("tool_choice"))
					{
						writer.WriteString("tool_choice", "none");
						wroteToolChoice = true;
					}
					else if (directMaxTokens > 0 && (property.NameEquals("max_tokens") || property.NameEquals("max_completion_tokens") || property.NameEquals("max_output_tokens")))
					{
						writer.WriteNumber(property.Name, ReadBoundedDirectMaxTokens(property.Value, directMaxTokens));
						wroteMaxTokens = true;
					}
					else if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
					{
						writer.WritePropertyName("messages");
						WriteDirectAgentMessagesWithoutTools(writer, property.Value, addNoThink);
					}
					else
					{
						property.WriteTo(writer);
					}
				}
			}
			if (directMaxTokens > 0 && !wroteMaxTokens)
			{
				writer.WriteNumber("max_tokens", directMaxTokens);
			}
			if (!wroteToolChoice)
			{
				writer.WriteString("tool_choice", "none");
			}
			writer.WriteEndObject();
			writer.Flush();
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (Exception ex)
		{
			LogMessage("[Proxy Research] Could not rewrite direct Agent prompt without tools: " + ex.Message);
			return AppendSystemMessage(requestBody, "[LmVsProxy agent mode] This Agent turn is a direct conversational prompt and does not need tool calls. No tool schemas were attached for prompt safety. Answer the user directly and do not invent tool results.");
		}
	}

	private void WriteDirectAgentMessagesWithoutTools(Utf8JsonWriter writer, JsonElement messages, bool addNoThink)
	{
		List<JsonElement> messageList = (from message in messages.EnumerateArray()
			select message.Clone()).ToList();
		int lastUserIndex = -1;
		for (int i = messageList.Count - 1; i >= 0; i--)
		{
			string role = ExtractStringProperty(messageList[i], "role") ?? "";
			if (role.Equals("user", StringComparison.OrdinalIgnoreCase))
			{
				lastUserIndex = i;
				break;
			}
		}
		writer.WriteStartArray();
		writer.WriteStartObject();
		writer.WriteString("role", "system");
		writer.WriteString("content", "[LmVsProxy agent mode] This is a direct no-tool Agent turn. Answer the user immediately in final-answer form. Do not call tools, do not invent tool results, do not write a thought process, and do not emit <think>, <thinking>, <thought>, or <analysis> blocks.");
		writer.WriteEndObject();
		foreach (JsonElement message in messageList)
		{
			string role = ExtractStringProperty(message, "role") ?? "";
			if (!role.Equals("system", StringComparison.OrdinalIgnoreCase))
			{
				continue;
			}
			string content = ExtractChatUiMessageContentText(message);
			if (!string.IsNullOrWhiteSpace(content))
			{
				writer.WriteStartObject();
				writer.WriteString("role", "system");
				writer.WriteString("content", content);
				writer.WriteEndObject();
			}
		}
		for (int i2 = 0; i2 < messageList.Count; i2++)
		{
			string role2 = ExtractStringProperty(messageList[i2], "role") ?? "";
			if (!role2.Equals("system", StringComparison.OrdinalIgnoreCase) && !role2.Equals("tool", StringComparison.OrdinalIgnoreCase))
			{
				string content = ExtractStringProperty(messageList[i2], "content") ?? ExtractChatUiMessageContentText(messageList[i2]);
				if (!string.IsNullOrWhiteSpace(content))
				{
					writer.WriteStartObject();
					writer.WriteString("role", role2.Equals("assistant", StringComparison.OrdinalIgnoreCase) ? "assistant" : "user");
					writer.WriteString("content", (addNoThink && i2 == lastUserIndex) ? AddNoThinkDirective(content) : content);
					writer.WriteEndObject();
				}
			}
		}
		writer.WriteStartObject();
		writer.WriteString("role", "system");
		writer.WriteString("content", "[LmVsProxy agent mode] Begin the final answer now. If the user asked for a chart, table, list, or summary, output that artifact directly and then stop. Do not preface it with analysis.");
		writer.WriteEndObject();
		writer.WriteEndArray();
	}

	private void WriteMessageWithNoThinkDirective(Utf8JsonWriter writer, JsonElement message)
	{
		if (message.ValueKind != JsonValueKind.Object)
		{
			message.WriteTo(writer);
			return;
		}
		writer.WriteStartObject();
		bool wroteContent = false;
		foreach (JsonProperty property in message.EnumerateObject())
		{
			if (property.NameEquals("content") && property.Value.ValueKind == JsonValueKind.String)
			{
				writer.WriteString("content", AddNoThinkDirective(property.Value.GetString() ?? ""));
				wroteContent = true;
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteContent)
		{
			writer.WriteString("content", "");
		}
		writer.WriteEndObject();
	}

	private static string AddNoThinkDirective(string prompt)
	{
		return prompt ?? "";
	}

	private static bool DirectPromptShouldDisableThinking(string model, string prompt)
	{
		return false;
	}

	private static bool PromptRequestsExactReply(string prompt)
	{
		return Regex.IsMatch(prompt ?? "", "\\b(reply|respond|say|answer)\\s+(with\\s+)?exactly\\b", RegexOptions.IgnoreCase | RegexOptions.CultureInvariant);
	}

	private bool ShouldAdvertiseProxyCoordinationTools(ChatPermissionState permissions, bool includeVsTools = false, bool includeTerminalTools = false, bool includeBrowserTools = false)
	{
		if (permissions == null)
		{
			return false;
		}
		return permissions.internetSearch ||
			permissions.fileDownloads ||
			(includeBrowserTools && permissions.agentAccess) ||
			(includeVsTools && permissions.vsCopilotTools) ||
			(includeVsTools && permissions.agentAccess) ||
			(includeTerminalTools && permissions.terminalCommands);
	}

	private static int ReadBoundedDirectMaxTokens(JsonElement value, int cap)
	{
		int current = cap;
		if (value.ValueKind == JsonValueKind.Number && value.TryGetInt32(out var parsed) && parsed > 0)
		{
			current = parsed;
		}
		return Math.Max(1, Math.Min(current, cap));
	}

	private static bool PromptLikelyNeedsProxyTools(string prompt)
	{
		string text = (prompt ?? "").Trim().ToLowerInvariant();
		if (string.IsNullOrWhiteSpace(text))
		{
			return false;
		}
		if (Regex.IsMatch(text, "https?://|www\\.", RegexOptions.CultureInvariant))
		{
			return true;
		}
		if (Regex.IsMatch(text, "\\b(search|browse|internet|web|website|url|download|scrape|scraping|crawl|fetch|citation|source|current|latest|today|now|price|listing|listings)\\b", RegexOptions.CultureInvariant))
		{
			return true;
		}
		if (Regex.IsMatch(text, "\\b(file|folder|directory|path|repo|repository|solution|workspace|read|write|edit|modify|replace|rename|delete|list files|open file|save)\\b", RegexOptions.CultureInvariant))
		{
			return true;
		}
		if (Regex.IsMatch(text, "\\b(create|add|make|overwrite|save)\\b.{0,160}([a-z]:\\\\|/[^\\s]+|\\.[a-z0-9]{1,8}\\b)", RegexOptions.CultureInvariant))
		{
			return true;
		}
		if (Regex.IsMatch(text, "\\b(?:another|other|enabled|workstation|runtime|web\\s*chat)\\s+models?\\b|\\bmodels?\\b.{0,160}\\b(?:consult|compare|delegate|run|ask|signal|load|enabled|workstation|runtime|web\\s*chat)\\b|\\b(?:consult|compare|delegate|ask|signal|load|run)\\b.{0,160}\\b(?:another|other|enabled|workstation|runtime|web\\s*chat)\\s+models?\\b|\\b(?:ask|consult|delegate|compare\\s+with|run|load)\\b.{0,160}\\b(?:qwen|llama|mistral|gemma|phi|deepseek|gpt[-_ ]?oss|model)\\b", RegexOptions.CultureInvariant))
		{
			return true;
		}
		if (Regex.IsMatch(text, "\\b(run|execute|start|stop|restart|build|test)\\s+(a\\s+)?(command|script|terminal|powershell|shell|build|test|server|process|project|app)\\b", RegexOptions.CultureInvariant))
		{
			return true;
		}
		if (Regex.IsMatch(text, "\\b(git|commit|branch|diff|status|stage|push|pull|clone|merge|checkout)\\b", RegexOptions.CultureInvariant))
		{
			return true;
		}
		return false;
	}

	private string BuildProxyResearchToolSystemPrompt(ChatPermissionState permissions, bool includeVsTools = false, bool includeTerminalTools = false, bool includeBrowserTools = false, string ownerKey = null, bool compactFileToolsOnly = false)
	{
		List<string> tools = new List<string>();
		if (compactFileToolsOnly)
		{
			if (includeVsTools && permissions != null && permissions.vsCopilotTools)
			{
				tools.Add("read_file");
				tools.Add("vs_read_file");
				tools.Add("vs_write_file");
				tools.Add("vs_replace_in_file");
				tools.Add("vs_search_files");
				tools.Add("vs_list_files");
			}
			string compactRootText = (includeVsTools ? (" " + BuildAccessibleRootDirectorySystemHint(ownerKey)) : "");
