	private ProxyToolParameter[] GitCommonParameters()
	{
		return new ProxyToolParameter[2]
		{
			new ProxyToolParameter("workingDirectory", "string", "Optional authorized directory inside the target repository."),
			new ProxyToolParameter("timeoutMs", "integer", "Optional timeout in milliseconds. Default 120000, max 600000.")
		};
	}

	private ProxyToolParameter[] GitParameters(params ProxyToolParameter[] extra)
	{
		List<ProxyToolParameter> parameters = new List<ProxyToolParameter>(GitCommonParameters());
		if (extra != null)
		{
			parameters.AddRange(extra);
		}
		return parameters.ToArray();
	}

	private void WriteProxyResearchToolSchema(Utf8JsonWriter writer, string name, string description, string[] required, ProxyToolParameter[] parameters)
	{
		writer.WriteStartObject();
		writer.WriteString("type", "function");
		writer.WritePropertyName("function");
		writer.WriteStartObject();
		writer.WriteString("name", name);
		writer.WriteString("description", description);
		writer.WritePropertyName("parameters");
		writer.WriteStartObject();
		writer.WriteString("type", "object");
		writer.WritePropertyName("properties");
		writer.WriteStartObject();
		foreach (ProxyToolParameter parameter in parameters)
		{
			writer.WritePropertyName(parameter.Name);
			writer.WriteStartObject();
			writer.WriteString("type", parameter.Type);
			writer.WriteString("description", parameter.Description);
			if (string.Equals(parameter.Type, "array", StringComparison.OrdinalIgnoreCase))
			{
				writer.WritePropertyName("items");
				writer.WriteStartObject();
				writer.WriteString("type", "string");
				writer.WriteEndObject();
			}
			writer.WriteEndObject();
		}
		writer.WriteEndObject();
		writer.WritePropertyName("required");
		writer.WriteStartArray();
		foreach (string item in required)
		{
			writer.WriteStringValue(item);
		}
		writer.WriteEndArray();
		writer.WriteBoolean("additionalProperties", value: false);
		writer.WriteEndObject();
		writer.WriteEndObject();
		writer.WriteEndObject();
	}

	private string AddBuildErrorRepairHint(string requestBody)
	{
		try
		{
			if (!HasUnfixedBuildOrErrorFailure(requestBody, out var errorFile))
			{
				return requestBody;
			}
			if (requestBody.Contains("[LmVsProxy build error repair hint]"))
			{
				return requestBody;
			}
			string target = (string.IsNullOrWhiteSpace(errorFile) ? "the failing files" : errorFile);
			string hint = "[LmVsProxy build error repair hint] Visual Studio has returned build/get_errors failures and no edit tool has succeeded afterward. Do not end the response after describing the errors. Read the failing file if needed, then use replace_string_in_file to fix it. Do not run run_build again until after an edit. Current primary failing target: " + target + ".";
			string rewritten = AppendSystemMessage(requestBody, hint);
			if ((object)rewritten != requestBody)
			{
				LogMessage("[Build Error Hint] Added repair guidance for " + target + ".");
			}
			return rewritten;
		}
		catch (Exception ex)
		{
			LogMessage("[Build Error Hint] Error: " + ex.Message);
			return requestBody;
		}
	}

	private string AddToolSchemaRecoveryHints(string requestBody)
