	private string BuildToolSchemaRecoveryHint(string requestBody)
	{
		bool createFileMissingContent = false;
		bool updatePlanMissingAutoAdvance = false;
		using (JsonDocument document = JsonDocument.Parse(requestBody))
		{
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return null;
			}
			Dictionary<string, string> toolCallNames = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						JsonElement idElement;
						string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						string name = "";
						if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
						{
							name = nameElement.GetString();
						}
						if (!string.IsNullOrWhiteSpace(id) && !string.IsNullOrWhiteSpace(name))
						{
							toolCallNames[id] = name;
						}
					}
				}
				else if (role.Equals("tool", StringComparison.OrdinalIgnoreCase))
				{
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					string mappedName;
					string toolName = ((!string.IsNullOrWhiteSpace(toolCallId) && toolCallNames.TryGetValue(toolCallId, out mappedName)) ? mappedName : "");
					JsonElement contentElement;
					string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
					string lower = content.ToLowerInvariant();
					if (toolName.Equals("create_file", StringComparison.Ordinal) && lower.Contains("missing parameter content"))
					{
						createFileMissingContent = true;
					}
					if (toolName.Equals("update_plan_progress", StringComparison.Ordinal) && lower.Contains("missing parameter autoadvance"))
					{
						updatePlanMissingAutoAdvance = true;
					}
				}
			}
		}
		List<string> parts = new List<string>();
		if (createFileMissingContent)
		{
			parts.Add("For create_file, always provide both required fields: filePath and content. Do not call create_file with only filePath.");
		}
		if (updatePlanMissingAutoAdvance)
		{
			parts.Add("For update_plan_progress, always provide all required fields: stepId, status, message, and autoAdvance. Do not explain the schema error; retry the tool call with autoAdvance as a boolean.");
		}
		return (parts.Count == 0) ? null : string.Join(" ", parts);
	}

	private string AddCreateFileHintAfterRepeatedFileSearchMisses(string requestBody)
	{
		try
		{
			if (!HasCreateFileGoal(requestBody))
			{
				return requestBody;
			}
			if (!IsToolAdvertised(requestBody, "create_file"))
			{
				return requestBody;
			}
			int missCount = CountFileSearchMisses(requestBody);
			if (missCount < 5)
			{
				return requestBody;
			}
			if (requestBody.Contains("[LmVsProxy create_file hint]"))
			{
				return requestBody;
			}
			string hint = "[LmVsProxy create_file hint] file_search has failed to find the requested file " + missCount + " times. The user's request is a creation task. Do not keep searching for that missing file; call create_file with the intended path and content, then use edit/read/build tools as needed.";
			string rewritten = AppendSystemMessage(requestBody, hint);
			if ((object)rewritten != requestBody)
			{
				LogMessage("[Create File Hint] Added create_file guidance after " + missCount + " file_search miss(es).");
			}
			return rewritten;
		}
		catch (Exception ex)
		{
			LogMessage("[Create File Hint] Error: " + ex.Message);
			return requestBody;
		}
	}

	private string AddMissingCodebehindCreationHint(string requestBody)
	{
		try
		{
			if (!IsToolAdvertised(requestBody, "create_file"))
			{
				return requestBody;
			}
			if (!TryInferMissingCodebehindLoopTarget(requestBody, out var targetPath, out var signalCount))
			{
				return requestBody;
			}
			if (requestBody.Contains("[LmVsProxy missing codebehind hint]"))
			{
				return requestBody;
			}
			string hint = "[LmVsProxy missing codebehind hint] The conversation has already established that " + targetPath + " is the missing WPF XAML code-behind file. Do not keep searching, checking symbols, or checking errors for that missing code-behind. Call create_file for that path with a concrete VB Window class that matches the XAML x:Class name, then continue with build/error fixes if needed.";
			string rewritten = AppendSystemMessage(requestBody, hint);
			if ((object)rewritten != requestBody)
			{
				LogMessage("[Codebehind Hint] Added missing code-behind creation guidance after " + signalCount + " signal(s).");
			}
			return rewritten;
		}
		catch (Exception ex)
		{
			LogMessage("[Codebehind Hint] Error: " + ex.Message);
			return requestBody;
		}
	}

	private bool HasCreateFileGoal(string requestBody)
	{
		string lastUserMessage = ExtractLastUserMessage(requestBody);
		if (string.IsNullOrWhiteSpace(lastUserMessage))
		{
			return false;
		}
		string lower = lastUserMessage.ToLowerInvariant();
		return lower.Contains("create ") || lower.Contains("add ") || lower.Contains("make ") || lower.Contains("new file") || lower.Contains("new tool") || lower.Contains("scaffold");
	}

	private bool HasUnfixedBuildOrErrorFailure(string requestBody, out string errorFile)
	{
		errorFile = null;
		bool pendingFailure = false;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, string> toolCallNames = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						JsonElement idElement;
						string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						string name = "";
						if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
						{
							name = ExtractStringProperty(function, "name") ?? "";
						}
						if (!string.IsNullOrWhiteSpace(id) && !string.IsNullOrWhiteSpace(name))
						{
							toolCallNames[id] = name;
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					string mappedName;
					string toolName = ((!string.IsNullOrWhiteSpace(toolCallId) && toolCallNames.TryGetValue(toolCallId, out mappedName)) ? mappedName : "");
					JsonElement contentElement;
					string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
					if (IsBuildErrorTool(toolName) && LooksLikeBuildOrGetErrorsFailure(content))
					{
						pendingFailure = true;
						string extracted = ExtractFirstErrorFile(content);
						if (!string.IsNullOrWhiteSpace(extracted))
						{
							errorFile = extracted;
						}
					}
					else if (pendingFailure && IsEditTool(toolName) && !LooksLikeToolError(content))
					{
						pendingFailure = false;
						errorFile = null;
					}
				}
			}
		}
		catch
		{
		}
		return pendingFailure;
	}

	private int CountToolCallsAfterLatestBuildFailure(string requestBody, string toolName, string targetFile)
	{
		int count = 0;
		bool afterFailure = false;
		string normalizedTarget = NormalizePathForCompare(targetFile ?? "");
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return 0;
			}
			Dictionary<string, string> toolCallNames = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						if (!toolCall.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
						{
							continue;
						}
						JsonElement idElement;
						string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						string name = ExtractStringProperty(function, "name") ?? "";
						if (!string.IsNullOrWhiteSpace(id) && !string.IsNullOrWhiteSpace(name))
						{
							toolCallNames[id] = name;
						}
						if (afterFailure && name.Equals(toolName, StringComparison.Ordinal))
						{
							JsonElement argumentsElement;
							string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
							if (string.IsNullOrWhiteSpace(normalizedTarget) || NormalizePathForCompare(arguments).Contains(normalizedTarget))
							{
								count++;
							}
						}
					}
				}
				else if (role.Equals("tool", StringComparison.OrdinalIgnoreCase))
				{
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					string name2;
					string mappedName = ((!string.IsNullOrWhiteSpace(toolCallId) && toolCallNames.TryGetValue(toolCallId, out name2)) ? name2 : "");
					JsonElement contentElement;
					string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
					if (IsBuildErrorTool(mappedName) && LooksLikeBuildOrGetErrorsFailure(content))
					{
						afterFailure = true;
						count = 0;
					}
					else if (afterFailure && IsEditTool(mappedName) && !LooksLikeToolError(content))
					{
						afterFailure = false;
					}
				}
			}
		}
		catch
		{
		}
		return afterFailure ? count : 0;
	}

	private bool IsBuildErrorTool(string toolName)
	{
		return toolName.Equals("run_build", StringComparison.Ordinal) || toolName.Equals("get_errors", StringComparison.Ordinal);
	}

	private bool IsEditTool(string toolName)
	{
		return toolName.Equals("replace_string_in_file", StringComparison.Ordinal) || toolName.Equals("create_file", StringComparison.Ordinal) || toolName.Equals("remove_file", StringComparison.Ordinal) || toolName.Equals("run_command_in_terminal", StringComparison.Ordinal);
	}

	private bool LooksLikeBuildOrGetErrorsFailure(string content)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return false;
		}
		string lower = content.ToLowerInvariant();
		return lower.Contains("build failed") || lower.Contains("error in file:") || lower.Contains("produces this issue") || lower.Contains("xls0") || lower.Contains("bc3") || lower.Contains("data at the root level is invalid");
	}

	private string ExtractFirstErrorFile(string content)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return null;
		}
		Match match = Regex.Match(content, "Error in File:\\s*(?<file>[^\\r\\n]+)", RegexOptions.IgnoreCase);
		return match.Success ? RepairPathControlCharacters(match.Groups["file"].Value.Trim()) : null;
	}

	private int CountFileSearchMisses(string requestBody)
	{
		int misses = 0;
		using (JsonDocument document = JsonDocument.Parse(requestBody))
		{
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return 0;
			}
			Dictionary<string, string> toolCallNames = new Dictionary<string, string>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						JsonElement idElement;
						string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						string name = "";
						if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
						{
							name = nameElement.GetString();
						}
						if (!string.IsNullOrWhiteSpace(id) && name.Equals("file_search", StringComparison.Ordinal))
						{
							toolCallNames[id] = name;
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (!string.IsNullOrWhiteSpace(toolCallId) && toolCallNames.ContainsKey(toolCallId))
					{
						JsonElement contentElement;
						string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
						if (LooksLikeFileSearchMiss(content))
						{
							misses++;
						}
					}
				}
			}
		}
		return misses;
	}

	private bool LooksLikeFileSearchMiss(string content)
	{
		if (string.IsNullOrWhiteSpace(content))
		{
			return true;
		}
		string lower = content.ToLowerInvariant();
		return lower.Contains("no results") || lower.Contains("no files") || lower.Contains("not found") || lower.Contains("couldn't find") || lower.Contains("could not find") || lower.Contains("0 results") || lower.Trim().Equals("[]", StringComparison.Ordinal);
	}

	private bool IsToolAdvertised(string requestBody, string toolName)
	{
		return GetAvailableToolNames(requestBody).Contains(toolName);
	}

	private string RepairConversationToolCallHistory(string requestBody, string ownerKey = null, string sessionId = null)
	{
		try
		{
			bool changed = false;
			Dictionary<string, ToolCallHistoryEntry> toolCallHistory = new Dictionary<string, ToolCallHistoryEntry>(StringComparer.Ordinal);
			using JsonDocument document = JsonDocument.Parse(requestBody);
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			writer.WriteStartObject();
			foreach (JsonProperty property in document.RootElement.EnumerateObject())
			{
				if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
				{
					writer.WritePropertyName("messages");
					writer.WriteStartArray();
					foreach (JsonElement message in property.Value.EnumerateArray())
					{
						WriteMessageWithRepairedToolHistory(writer, message, toolCallHistory, ref changed, ownerKey, sessionId);
					}
					writer.WriteEndArray();
				}
				else
				{
					property.WriteTo(writer);
				}
			}
			writer.WriteEndObject();
			writer.Flush();
			if (!changed)
			{
				return requestBody;
			}
			LogMessage("[Tool History Repair] Repaired malformed tool-call history before forwarding request.");
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (Exception ex)
		{
			LogMessage("[Tool History Repair] Error: " + ex.Message);
			return requestBody;
		}
	}

	private void WriteMessageWithRepairedToolHistory(Utf8JsonWriter writer, JsonElement message, Dictionary<string, ToolCallHistoryEntry> toolCallHistory, ref bool changed, string ownerKey = null, string sessionId = null)
	{
		if (message.ValueKind != JsonValueKind.Object)
		{
			message.WriteTo(writer);
			return;
		}
		JsonElement roleElement;
		string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
		writer.WriteStartObject();
		foreach (JsonProperty property in message.EnumerateObject())
		{
			string repairedContent;
			if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && property.NameEquals("tool_calls") && property.Value.ValueKind == JsonValueKind.Array)
			{
				writer.WritePropertyName("tool_calls");
				writer.WriteStartArray();
				foreach (JsonElement toolCall in property.Value.EnumerateArray())
				{
					WriteToolCallWithRepairedArguments(writer, toolCall, toolCallHistory, ref changed);
				}
				writer.WriteEndArray();
			}
			else if (role.Equals("tool", StringComparison.OrdinalIgnoreCase) && property.NameEquals("content") && TryRepairToolHistoryResultContent(message, toolCallHistory, property.Value, ownerKey, sessionId, out repairedContent))
			{
				writer.WriteString("content", repairedContent);
				changed = true;
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		writer.WriteEndObject();
	}

	private void WriteToolCallWithRepairedArguments(Utf8JsonWriter writer, JsonElement toolCall, Dictionary<string, ToolCallHistoryEntry> toolCallHistory, ref bool changed)
	{
		if (toolCall.ValueKind != JsonValueKind.Object)
		{
			toolCall.WriteTo(writer);
			return;
		}
		JsonElement idElement;
		string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
		string toolName = "";
		if (toolCall.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
		{
			toolName = ExtractStringProperty(function, "name") ?? "";
		}
		string arguments = "{}";
		if (toolCall.TryGetProperty("function", out var originalFunction) && originalFunction.ValueKind == JsonValueKind.Object)
		{
			arguments = ExtractFunctionArguments(originalFunction);
		}
		string repairedArguments = (string.IsNullOrWhiteSpace(toolName) ? arguments : RepairKnownToolArguments(toolName, arguments));
		if (!string.IsNullOrWhiteSpace(id) && !string.IsNullOrWhiteSpace(toolName))
		{
			toolCallHistory[id] = new ToolCallHistoryEntry
			{
				Name = toolName,
				ArgumentsJson = repairedArguments
			};
		}
		writer.WriteStartObject();
		foreach (JsonProperty property in toolCall.EnumerateObject())
		{
			if (property.NameEquals("function") && property.Value.ValueKind == JsonValueKind.Object)
			{
				WriteFunctionWithRepairedArguments(writer, property.Value, toolName, repairedArguments, ref changed);
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		writer.WriteEndObject();
	}

	private string ExtractFunctionArguments(JsonElement function)
	{
		JsonElement argumentsElement;
		return (!function.TryGetProperty("arguments", out argumentsElement)) ? "{}" : ((argumentsElement.ValueKind == JsonValueKind.String) ? argumentsElement.GetString() : argumentsElement.ToString());
	}

	private void WriteFunctionWithRepairedArguments(Utf8JsonWriter writer, JsonElement function, string toolName, string repairedArguments, ref bool changed)
	{
		string arguments = ExtractFunctionArguments(function);
		bool wroteArguments = false;
		writer.WritePropertyName("function");
		writer.WriteStartObject();
		foreach (JsonProperty property in function.EnumerateObject())
		{
			if (property.NameEquals("arguments"))
			{
				writer.WriteString("arguments", repairedArguments ?? "{}");
				wroteArguments = true;
				if (!string.Equals(arguments ?? "{}", repairedArguments ?? "{}", StringComparison.Ordinal))
				{
					changed = true;
				}
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteArguments && !string.IsNullOrWhiteSpace(toolName))
		{
			writer.WriteString("arguments", repairedArguments ?? "{}");
			changed = true;
		}
		writer.WriteEndObject();
	}

	private bool TryRepairToolHistoryResultContent(JsonElement message, Dictionary<string, ToolCallHistoryEntry> toolCallHistory, JsonElement contentElement, string ownerKey, string sessionId, out string repairedContent)
	{
		repairedContent = null;
		JsonElement toolCallIdElement;
		string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
		if (string.IsNullOrWhiteSpace(toolCallId) || !toolCallHistory.TryGetValue(toolCallId, out var toolCall) || toolCall == null)
		{
			return false;
		}
		string content = contentElement.ToString();
		if (toolCall.Name.Equals("update_plan_progress", StringComparison.Ordinal) && content.IndexOf("missing parameter autoAdvance", StringComparison.OrdinalIgnoreCase) >= 0)
		{
			repairedContent = "update_plan_progress arguments were repaired by LmVsProxy. Retry update_plan_progress with stepId, status, message, and autoAdvance.";
			return true;
		}
		if (toolCall.Name.Equals("get_file", StringComparison.Ordinal) && ShouldHydrateGetFileResult(content, toolCall.ArgumentsJson) && TryReadLocalFileForGetFile(toolCall.ArgumentsJson, ownerKey, sessionId, out var localContent))
		{
			repairedContent = localContent;
			return true;
		}
		if (toolCall.Name.Equals("get_files_in_project", StringComparison.Ordinal) && ShouldHydrateGetFilesInProjectResult(content) && TryReadLocalProjectFilesForGetFilesInProject(toolCall.ArgumentsJson, ownerKey, sessionId, out var localProjectContent))
		{
			repairedContent = localProjectContent;
			return true;
		}
		if (toolCall.Name.Equals("replace_string_in_file", StringComparison.Ordinal) && ShouldApplyEditToolFallback(content) && TryExplainLocalReplaceStringInFileFailure(toolCall.ArgumentsJson, ownerKey, sessionId, out var replaceExplanation))
		{
			repairedContent = replaceExplanation;
			return true;
		}
		if (toolCall.Name.Equals("replace_string_in_file", StringComparison.Ordinal) && ShouldApplyEditToolFallback(content) && TryApplyLocalReplaceStringInFile(toolCall.ArgumentsJson, ownerKey, sessionId, out var replaceResult))
		{
			repairedContent = replaceResult;
			return true;
		}
		if (toolCall.Name.Equals("create_file", StringComparison.Ordinal) && ShouldApplyEditToolFallback(content) && TryApplyLocalCreateFile(toolCall.ArgumentsJson, ownerKey, sessionId, out var createResult))
		{
			repairedContent = createResult;
			return true;
		}
		return false;
	}

	private bool ShouldApplyEditToolFallback(string content)
	{
		string lower = (content ?? "").Trim().ToLowerInvariant();
		if (string.IsNullOrWhiteSpace(lower))
		{
			return true;
		}
		return LooksLikeToolError(content) || lower.Contains("no changes") || lower.Contains("0 changes") || lower.Contains("did not find a match") || lower.Contains("could not find a match") || lower.Contains("not applied") || lower.Contains("not changed") || lower.Contains("unchanged");
	}

	private bool ShouldHydrateGetFilesInProjectResult(string content)
	{
		string lower = (content ?? "").Trim().ToLowerInvariant();
		if (string.IsNullOrWhiteSpace(lower))
		{
			return true;
		}
		return LooksLikeToolError(content) || lower.Contains("couldn't run") || lower.Contains("could not run") || lower.Contains("couldn't find") || lower.Contains("could not find") || lower.Contains("invalid arguments") || lower.Contains("failed to execute") || lower.Contains("not in solution") || lower.Contains("project was not found");
	}

	private bool ShouldHydrateGetFileResult(string content, string getFileArgumentsJson)
	{
		string filename = ExtractFilenameFromGetFileArguments(getFileArgumentsJson);
		if (string.IsNullOrWhiteSpace(filename))
		{
			return false;
		}
		string parsed = ExtractPlainFileContentFromToolResult(content ?? "");
		if (LooksLikeSubstantiveFileContent(parsed, filename))
		{
			return false;
		}
		string lower = (content ?? "").Trim().ToLowerInvariant();
		return string.IsNullOrWhiteSpace(lower) || (lower.StartsWith("read ", StringComparison.Ordinal) && lower.Contains("lines ")) || lower.Contains("read " + ExtractFileNameForCompare(filename)) || lower.Contains("couldn't display") || lower.Contains("could not display") || lower.Contains("couldn't find") || lower.Contains("could not find") || lower.Contains("not found") || lower.Contains("query could not find") || lower.Contains("file is not found");
	}

	private bool TryReadLocalFileForGetFile(string argumentsJson, string ownerKey, string sessionId, out string content)
	{
		content = null;
		string filename = ExtractFilenameFromGetFileArguments(argumentsJson);
		if (string.IsNullOrWhiteSpace(filename))
		{
			return false;
		}
		filename = NormalizeLoosePathEscapes(filename);
		if (!TryResolveChatAgentFilePath(filename, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullPath, out var resolveError))
		{
			LogMessage("[Get File Local Fallback] Permission or resolution blocked for " + filename + ": " + resolveError);
			return false;
		}
		string displayPath = FormatChatAgentPathForOutput(fullPath, sessionId);
		int startLine = ExtractIntFromToolArguments(argumentsJson, "startLine", 1);
		int endLine = ExtractIntFromToolArguments(argumentsJson, "endLine", startLine + 239);
		bool includeLineNumbers = ExtractBoolFromToolArguments(argumentsJson, "includeLineNumbers", fallback: true);
		try
		{
			string[] lines = File.ReadAllLines(fullPath);
			if (lines.Length == 0)
			{
				content = "```" + GetMarkdownLanguageForPath(fullPath) + " " + displayPath + " (0 lines total)\n```";
				return true;
			}
			if (startLine < 1)
			{
				startLine = 1;
			}
			if (endLine < startLine)
			{
				endLine = startLine;
			}
			if (endLine > lines.Length)
			{
				endLine = lines.Length;
			}
			StringBuilder sb = new StringBuilder();
			sb.Append("```").Append(GetMarkdownLanguageForPath(fullPath)).Append(" ")
				.Append(displayPath)
				.Append(" (Lines ")
				.Append(startLine.ToString())
				.Append("-")
				.Append(endLine.ToString())
				.Append(" of ")
				.Append(lines.Length.ToString())
				.Append(" total. Local fallback by LmVsProxy.)\n");
			for (int lineNumber = startLine; lineNumber <= endLine; lineNumber++)
			{
				if (includeLineNumbers)
				{
					sb.Append(lineNumber.ToString()).Append(": ");
				}
				sb.Append(lines[lineNumber - 1]).Append("\n");
			}
			sb.Append("```");
			content = sb.ToString();
			LogMessage("[Get File Local Fallback] Hydrated get_file result for " + filename + " from " + fullPath);
			return true;
		}
		catch (Exception ex)
		{
			LogMessage("[Get File Local Fallback] Failed to read " + fullPath + ": " + ex.Message);
			return false;
		}
	}

	private bool TryReadLocalProjectFilesForGetFilesInProject(string argumentsJson, string ownerKey, string sessionId, out string content)
	{
		content = null;
		string projectPath = ExtractProjectPathFromGetFilesInProjectArguments(argumentsJson);
		if (string.IsNullOrWhiteSpace(projectPath))
		{
			projectPath = "Maf Scale\\ME7Tools.vbproj";
		}
		projectPath = NormalizeLoosePathEscapes(projectPath);
		if (!TryResolveChatAgentFilePath(projectPath, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullProjectPath, out var resolveError))
		{
			LogMessage("[Get Files Local Fallback] Permission or resolution blocked for " + projectPath + ": " + resolveError);
			return false;
		}
		string displayProjectPath = FormatChatAgentPathForOutput(fullProjectPath, sessionId);
		try
		{
			string projectDirectory = Path.GetDirectoryName(fullProjectPath);
			List<string> files = new List<string>();
			HashSet<string> seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
			foreach (string include in ExtractProjectIncludes(fullProjectPath))
			{
				string relative = NormalizeLoosePathEscapes(include).Replace('/', Path.DirectorySeparatorChar);
				string full = Path.GetFullPath(Path.Combine(projectDirectory, relative));
				if (File.Exists(full))
				{
					AddProjectFileResult(files, seen, projectDirectory, full);
				}
			}
			if (files.Count == 0)
			{
				string[] array = new string[7] { "*.vb", "*.xaml", "*.resx", "*.config", "*.settings", "*.xml", "*.json" };
				foreach (string pattern in array)
				{
					string[] files2 = Directory.GetFiles(projectDirectory, pattern, SearchOption.AllDirectories);
					foreach (string full2 in files2)
					{
						if (!IsGeneratedOrBuildOutputPath(full2))
						{
							AddProjectFileResult(files, seen, projectDirectory, full2);
						}
					}
				}
			}
			files.Sort(StringComparer.OrdinalIgnoreCase);
			StringBuilder sb = new StringBuilder();
			sb.AppendLine("Files in project " + displayProjectPath + " (Local fallback by LmVsProxy):");
			foreach (string file in files)
			{
				sb.AppendLine(file);
			}
			content = sb.ToString().TrimEnd();
			LogMessage("[Get Files Local Fallback] Hydrated get_files_in_project for " + projectPath + " from " + fullProjectPath + "; files=" + files.Count);
			return true;
		}
		catch (Exception ex)
		{
			LogMessage("[Get Files Local Fallback] Failed to list " + fullProjectPath + ": " + ex.Message);
			return false;
		}
	}

	private bool TryExplainLocalReplaceStringInFileFailure(string argumentsJson, string ownerKey, string sessionId, out string result)
	{
		result = null;
		string filePath = NormalizeLoosePathEscapes(ExtractFilePathFromReplaceStringArguments(argumentsJson));
		string oldString = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "oldString"));
		string newString = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "newString"));
		if (string.IsNullOrWhiteSpace(filePath) || oldString == null || newString == null)
		{
			return false;
		}
		if (string.Equals(oldString, newString, StringComparison.Ordinal))
		{
			string displayPath = filePath;
			if (TryResolveChatAgentFilePath(filePath, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var resolvedPath, out var _))
			{
				displayPath = FormatChatAgentPathForOutput(resolvedPath, sessionId);
			}
			result = "replace_string_in_file skipped by LmVsProxy because oldString and newString are identical for " + displayPath + ". Treat this as complete; do not retry the same edit.";
			LogMessage("[Local Edit Fallback] " + result);
			return true;
		}
		if (!TryResolveChatAgentFilePath(filePath, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullPath, out var resolveError))
		{
			LogMessage("[Local Edit Fallback] replace_string_in_file permission or resolution blocked for " + filePath + ": " + resolveError);
			return false;
		}
		string displayFilePath = FormatChatAgentPathForOutput(fullPath, sessionId);
		try
		{
			string existing = File.ReadAllText(fullPath);
			string normalizedExisting = existing.Replace("\r\n", "\n").Replace('\r', '\n');
			string normalizedOld = oldString.Replace("\r\n", "\n").Replace('\r', '\n');
			string normalizedNew = newString.Replace("\r\n", "\n").Replace('\r', '\n');
			if (!string.IsNullOrWhiteSpace(normalizedNew) && normalizedExisting.Contains(normalizedNew) && (string.IsNullOrWhiteSpace(normalizedOld) || !normalizedExisting.Contains(normalizedOld)))
			{
				result = "replace_string_in_file already appears applied in " + displayFilePath + " (oldString is absent and newString is present). Treat this as complete; do not retry the same edit.";
				LogMessage("[Local Edit Fallback] " + result + " fullPath=" + fullPath);
				return true;
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Local Edit Fallback] replace_string_in_file state check failed for " + fullPath + ": " + ex.Message);
		}
		return false;
	}

	private bool TryApplyLocalReplaceStringInFile(string argumentsJson, string ownerKey, string sessionId, out string result)
	{
		result = null;
		string filePath = NormalizeLoosePathEscapes(ExtractFilePathFromReplaceStringArguments(argumentsJson));
		string oldString = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "oldString"));
		string newString = NormalizeGeneratedFileText(ExtractJsonStringProperty(argumentsJson, "newString"));
		if (string.IsNullOrWhiteSpace(filePath) || oldString == null || newString == null || string.Equals(oldString, newString, StringComparison.Ordinal))
		{
			return false;
		}
		if (!TryResolveChatAgentFilePath(filePath, ownerKey, sessionId, mustExist: true, sessionOnly: false, out var fullPath, out var resolveError))
		{
			LogMessage("[Local Edit Fallback] replace_string_in_file permission or resolution blocked for " + filePath + ": " + resolveError);
			return false;
		}
		string displayFilePath = FormatChatAgentPathForOutput(fullPath, sessionId);
		try
		{
			bool managedSessionPath = IsJackLlmSessionManagedPath(fullPath);
			string existing;
			if (managedSessionPath)
			{
				if (!TryReadChatSessionSandboxTextFile(sessionId, ownerKey, fullPath, out existing))
				{
					return false;
				}
			}
			else
			{
				existing = File.ReadAllText(fullPath);
			}
			string replacementTarget = oldString;
			if (!existing.Contains(replacementTarget))
			{
				string normalizedExisting = existing.Replace("\r\n", "\n").Replace('\r', '\n');
				string normalizedOld = oldString.Replace("\r\n", "\n").Replace('\r', '\n');
				if (!normalizedExisting.Contains(normalizedOld))
				{
					string normalizedNew = newString.Replace("\r\n", "\n").Replace('\r', '\n');
					if (!string.IsNullOrWhiteSpace(normalizedNew) && normalizedExisting.Contains(normalizedNew))
					{
						result = "replace_string_in_file already appears applied locally by LmVsProxy to " + displayFilePath + ". oldString was absent and newString was present, so the retry was treated as complete.";
						LogMessage("[Local Edit Fallback] " + result + " fullPath=" + fullPath);
						return true;
					}
					LogMessage("[Local Edit Fallback] replace_string_in_file could not find oldString in " + fullPath);
					return false;
				}
				replacementTarget = (existing.Contains(oldString.Replace("\n", "\r\n")) ? oldString.Replace("\n", "\r\n") : oldString);
			}
			string updated = existing.Replace(replacementTarget, newString);
			if (string.Equals(existing, updated, StringComparison.Ordinal))
			{
				return false;
			}
			WriteChatAgentTextFile(fullPath, updated, ownerKey, sessionId, "local-edit-fallback-replace");
			result = "replace_string_in_file applied locally by LmVsProxy to " + displayFilePath + ". Replaced " + CountOccurrences(existing, replacementTarget) + " occurrence(s).";
			LogMessage("[Local Edit Fallback] " + result + " fullPath=" + fullPath);
			return true;
		}
		catch (Exception ex)
		{
			LogMessage("[Local Edit Fallback] replace_string_in_file failed for " + fullPath + ": " + ex.Message);
			return false;
		}
	}

	private bool TryApplyLocalCreateFile(string argumentsJson, string ownerKey, string sessionId, out string result)
	{
		result = null;
		string filePath = NormalizeLoosePathEscapes(ExtractFilePathFromCreateFileArguments(argumentsJson));
		string content = NormalizeGeneratedFileText(ExtractCreateFileContent(argumentsJson));
		if (string.IsNullOrWhiteSpace(filePath) || !IsSafeCreateFileTarget(filePath))
		{
			return false;
		}
		if (string.IsNullOrWhiteSpace(content))
		{
			content = BuildMinimalFileContent(filePath);
		}
		try
		{
			if (!TryResolveChatAgentFilePath(filePath, ownerKey, sessionId, mustExist: false, sessionOnly: false, out var fullPath, out var resolveError))
			{
				LogMessage("[Local Edit Fallback] create_file permission or resolution blocked for " + filePath + ": " + resolveError);
				return false;
			}
			bool managedSessionPath = IsJackLlmSessionManagedPath(fullPath);
			string displayPath = FormatChatAgentPathForOutput(fullPath, sessionId);
			if (!managedSessionPath)
			{
				Directory.CreateDirectory(Path.GetDirectoryName(fullPath));
			}
			if (ChatAgentFileExists(sessionId, ownerKey, fullPath))
			{
				result = "create_file local fallback skipped because file already exists: " + displayPath;
				LogMessage("[Local Edit Fallback] " + result);
				return true;
			}
			WriteChatAgentTextFile(fullPath, content, ownerKey, sessionId, "local-edit-fallback-create");
			result = "create_file applied locally by LmVsProxy: " + displayPath + " (" + content.Length + " chars).";
			LogMessage("[Local Edit Fallback] " + result + " fullPath=" + fullPath);
			return true;
		}
		catch (Exception ex)
		{
			LogMessage("[Local Edit Fallback] create_file failed for " + filePath + ": " + ex.Message);
			return false;
		}
	}

	private int CountOccurrences(string text, string value)
	{
		if (string.IsNullOrEmpty(text) || string.IsNullOrEmpty(value))
		{
			return 0;
		}
		int count = 0;
		int index = 0;
		while ((index = text.IndexOf(value, index, StringComparison.Ordinal)) >= 0)
		{
			count++;
			index += value.Length;
		}
		return count;
	}

	private string ExtractProjectPathFromGetFilesInProjectArguments(string argumentsJson)
	{
		string projectPath = ExtractJsonStringProperty(argumentsJson, "projectPath");
		if (!string.IsNullOrWhiteSpace(projectPath))
		{
			return projectPath;
		}
		if (string.IsNullOrWhiteSpace(argumentsJson))
		{
			return null;
		}
		Match match = Regex.Match(argumentsJson, "\"projectPath\"\\s*:\\s*\"(?<path>[^\"]+)\"", RegexOptions.IgnoreCase);
		return match.Success ? RepairPathControlCharacters(match.Groups["path"].Value) : null;
	}

	private List<string> ExtractProjectIncludes(string fullProjectPath)
	{
		List<string> includes = new List<string>();
		string text = File.ReadAllText(fullProjectPath);
		foreach (Match match in Regex.Matches(text, "\\b(?:Include|Update)\\s*=\\s*\"(?<path>[^\"]+)\"", RegexOptions.IgnoreCase))
		{
			string include = match.Groups["path"].Value;
			if (!string.IsNullOrWhiteSpace(include))
			{
				includes.Add(include);
			}
		}
		return includes;
	}

	private void AddProjectFileResult(List<string> files, HashSet<string> seen, string projectDirectory, string fullPath)
	{
		string relative = Path.GetRelativePath(projectDirectory, fullPath).Replace(Path.DirectorySeparatorChar, '\\');
		if (seen.Add(relative))
		{
			files.Add(relative);
		}
	}

	private bool IsGeneratedOrBuildOutputPath(string fullPath)
	{
		string normalized = fullPath.Replace('/', '\\').ToLowerInvariant();
		return normalized.Contains("\\bin\\") || normalized.Contains("\\obj\\") || normalized.Contains("\\.vs\\") || normalized.Contains("\\packages\\");
	}

	private bool ShouldFilterGeneratedOrBuildOutputPath(string fullPath, string root = null)
	{
		if (!string.IsNullOrWhiteSpace(_chatSessionFilesRoot))
		{
			try
			{
				if (IsPathInsideRoot(fullPath, _chatSessionFilesRoot) || (!string.IsNullOrWhiteSpace(root) && IsPathInsideRoot(root, _chatSessionFilesRoot)))
				{
					return false;
				}
			}
			catch
			{
			}
		}
		return IsGeneratedOrBuildOutputPath(fullPath);
	}

	private bool TryResolveLocalFilePath(string requestedPath, out string fullPath)
	{
		fullPath = null;
		if (string.IsNullOrWhiteSpace(requestedPath))
		{
			return false;
		}
		string cleaned = NormalizeLoosePathEscapes(requestedPath).Replace('/', Path.DirectorySeparatorChar).Trim().Trim('"', '\'', ',', ' ');
		if (Path.IsPathRooted(cleaned) && File.Exists(cleaned))
		{
			fullPath = Path.GetFullPath(cleaned);
			return true;
		}
		List<string> roots = new List<string>();
		AddCandidateRoot(roots, Directory.GetCurrentDirectory());
		AddCandidateRoot(roots, AppDomain.CurrentDomain.BaseDirectory);
		string userProfile = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
		if (!string.IsNullOrWhiteSpace(userProfile))
		{
			AddCandidateRoot(roots, Path.Combine(userProfile, "source", "repos"));
			AddCandidateRoot(roots, Path.Combine(userProfile, "Documents", "GitHub"));
			AddCandidateRoot(roots, Path.Combine(userProfile, "Documents"));
		}
		foreach (string root in roots)
		{
			string candidate = Path.Combine(root, cleaned);
			if (File.Exists(candidate))
			{
				fullPath = Path.GetFullPath(candidate);
				return true;
			}
			string rootLeaf = new DirectoryInfo(root).Name;
			if (string.IsNullOrWhiteSpace(rootLeaf) || !cleaned.StartsWith(rootLeaf + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase))
			{
				continue;
			}
			string parent = Directory.GetParent(root)?.FullName;
			if (!string.IsNullOrWhiteSpace(parent))
			{
				candidate = Path.Combine(parent, cleaned);
				if (File.Exists(candidate))
				{
					fullPath = Path.GetFullPath(candidate);
					return true;
				}
			}
		}
		string fileName = Path.GetFileName(cleaned);
		if (string.IsNullOrWhiteSpace(fileName))
		{
			return false;
		}
		string normalizedSuffix = NormalizePathForCompare(cleaned);
		foreach (string root2 in roots)
		{
			try
			{
				if (!Directory.Exists(root2))
				{
					continue;
				}
				foreach (string candidate2 in Directory.EnumerateFiles(root2, fileName, SearchOption.AllDirectories))
				{
					string comparable = NormalizePathForCompare(candidate2);
					if (comparable.EndsWith(normalizedSuffix, StringComparison.OrdinalIgnoreCase) || comparable.EndsWith("\\" + fileName.ToLowerInvariant(), StringComparison.OrdinalIgnoreCase))
					{
						fullPath = candidate2;
						return true;
					}
				}
			}
			catch
			{
			}
		}
		return false;
	}

	private void AddCandidateRoot(List<string> roots, string root)
	{
		if (string.IsNullOrWhiteSpace(root))
		{
			return;
		}
		try
		{
			string full = Path.GetFullPath(root);
			if (Directory.Exists(full) && !roots.Contains(full))
			{
				roots.Add(full);
			}
		}
		catch
		{
		}
	}

	private bool ExtractBoolFromToolArguments(string argumentsJson, string propertyName, bool fallback)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(argumentsJson);
			if (!document.RootElement.TryGetProperty(propertyName, out var property))
			{
				return fallback;
			}
			if (property.ValueKind == JsonValueKind.True)
			{
				return true;
			}
			if (property.ValueKind == JsonValueKind.False)
			{
				return false;
			}
			if (property.ValueKind == JsonValueKind.String && bool.TryParse(property.GetString(), out var parsed))
			{
				return parsed;
			}
		}
		catch
		{
		}
		return fallback;
	}

	private string GetMarkdownLanguageForPath(string path)
	{
		string lower = (path ?? "").ToLowerInvariant();
		if (lower.EndsWith(".xaml", StringComparison.Ordinal))
		{
			return "xml";
		}
		if (lower.EndsWith(".vb", StringComparison.Ordinal))
		{
			return "visualbasic";
		}
		if (lower.EndsWith(".cs", StringComparison.Ordinal))
		{
			return "csharp";
		}
		if (lower.EndsWith(".json", StringComparison.Ordinal))
		{
			return "json";
		}
		if (lower.EndsWith(".xml", StringComparison.Ordinal))
		{
			return "xml";
		}
		return "";
	}

	private string AppendSystemMessage(string requestBody, string content)
	{
		using JsonDocument document = JsonDocument.Parse(requestBody);
		using MemoryStream stream = new MemoryStream();
		using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
		writer.WriteStartObject();
		foreach (JsonProperty property in document.RootElement.EnumerateObject())
		{
			if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
			{
				writer.WritePropertyName("messages");
				writer.WriteStartArray();
				foreach (JsonElement item in property.Value.EnumerateArray())
				{
					item.WriteTo(writer);
				}
				writer.WriteStartObject();
				writer.WriteString("role", "system");
				writer.WriteString("content", content);
				writer.WriteEndObject();
				writer.WriteEndArray();
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		writer.WriteEndObject();
		writer.Flush();
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private string AppendSystemAndUserMessages(string requestBody, string systemContent, string userContent)
	{
		using JsonDocument document = JsonDocument.Parse(requestBody);
		using MemoryStream stream = new MemoryStream();
		using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
		bool wroteMessages = false;
		writer.WriteStartObject();
		foreach (JsonProperty property in document.RootElement.EnumerateObject())
		{
			if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
			{
				wroteMessages = true;
				writer.WritePropertyName("messages");
				writer.WriteStartArray();
				foreach (JsonElement item in property.Value.EnumerateArray())
				{
					item.WriteTo(writer);
				}
				WriteSystemAndUserMessages(writer, systemContent, userContent);
				writer.WriteEndArray();
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteMessages)
		{
			writer.WritePropertyName("messages");
			writer.WriteStartArray();
			WriteSystemAndUserMessages(writer, systemContent, userContent);
			writer.WriteEndArray();
		}
		writer.WriteEndObject();
		writer.Flush();
		return Encoding.UTF8.GetString(stream.ToArray());
	}

	private string AppendAssistantAndSystemMessage(string requestBody, string assistantContent, string systemContent)
	{
		using JsonDocument document = JsonDocument.Parse(requestBody);
		using MemoryStream stream = new MemoryStream();
		using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
		bool wroteMessages = false;
		writer.WriteStartObject();
		foreach (JsonProperty property in document.RootElement.EnumerateObject())
		{
			if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
			{
				wroteMessages = true;
				writer.WritePropertyName("messages");
				writer.WriteStartArray();
				foreach (JsonElement item in property.Value.EnumerateArray())
				{
					item.WriteTo(writer);
				}
				WriteAssistantAndSystemMessages(writer, assistantContent, systemContent);
				writer.WriteEndArray();
			}
			else
			{
				property.WriteTo(writer);
			}
		}
		if (!wroteMessages)
		{
			writer.WritePropertyName("messages");
			writer.WriteStartArray();
			WriteAssistantAndSystemMessages(writer, assistantContent, systemContent);
			writer.WriteEndArray();
		}
		writer.WriteEndObject();
		writer.Flush();
		string continuationRequest = Encoding.UTF8.GetString(stream.ToArray());
		return continuationRequest;
	}

	private static void WriteAssistantAndSystemMessages(Utf8JsonWriter writer, string assistantContent, string systemContent)
	{
		if (!string.IsNullOrWhiteSpace(assistantContent))
		{
			writer.WriteStartObject();
			writer.WriteString("role", "assistant");
			writer.WriteString("content", assistantContent);
			writer.WriteEndObject();
		}
		writer.WriteStartObject();
		writer.WriteString("role", "system");
		writer.WriteString("content", systemContent ?? "");
		writer.WriteEndObject();
	}

	private static void WriteSystemAndUserMessages(Utf8JsonWriter writer, string systemContent, string userContent)
	{
		writer.WriteStartObject();
		writer.WriteString("role", "system");
		writer.WriteString("content", systemContent ?? "");
		writer.WriteEndObject();
		writer.WriteStartObject();
		writer.WriteString("role", "user");
		writer.WriteString("content", userContent ?? "");
		writer.WriteEndObject();
	}

	private bool HasTooManyToolRounds(string requestBody, out int totalToolCalls)
	{
		totalToolCalls = 0;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (message.TryGetProperty("role", out var role) && role.ValueKind == JsonValueKind.String && role.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					totalToolCalls += toolCalls.GetArrayLength();
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Tool Rounds] Error counting: " + ex.Message);
			return false;
		}
		return totalToolCalls >= 20;
	}

	private HashSet<string> GetPreviouslyCalledToolNames(string requestBody)
	{
		HashSet<string> result = new HashSet<string>(StringComparer.Ordinal);
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return result;
			}
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var role) || role.ValueKind != JsonValueKind.String || !role.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (item.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
					{
						string name = nameElement.GetString();
						if (!string.IsNullOrWhiteSpace(name))
						{
							result.Add(name);
						}
					}
				}
			}
		}
		catch
		{
		}
		return result;
	}

	private bool IsSuppressibleVsTool(string toolName)
	{
		if (string.IsNullOrWhiteSpace(toolName))
		{
			return false;
		}
		return toolName.Equals("get_projects_in_solution", StringComparison.Ordinal) || toolName.Equals("code_search", StringComparison.Ordinal);
	}

	private void KeepOnlySuppressibleVsTools(HashSet<string> toolNames)
	{
		if (toolNames == null || toolNames.Count == 0)
		{
			return;
		}
		HashSet<string> allowed = new HashSet<string>(StringComparer.Ordinal);
		foreach (string toolName in toolNames)
		{
			if (IsSuppressibleVsTool(toolName))
			{
				allowed.Add(toolName);
			}
		}
		toolNames.Clear();
		foreach (string toolName2 in allowed)
		{
			toolNames.Add(toolName2);
		}
	}

	private bool TryGetToolsToSuppress(string requestBody, out HashSet<string> toolsToSuppress, out string reason)
	{
		toolsToSuppress = new HashSet<string>(StringComparer.Ordinal);
		reason = null;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, string> toolCallIds = new Dictionary<string, string>(StringComparer.Ordinal);
			Dictionary<string, int> toolCallCounts = new Dictionary<string, int>(StringComparer.Ordinal);
			Dictionary<string, int> emptyToolResultCounts = new Dictionary<string, int>(StringComparer.Ordinal);
			Dictionary<string, int> successfulToolResultCounts = new Dictionary<string, int>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				JsonElement roleElement;
				string role = ((message.TryGetProperty("role", out roleElement) && roleElement.ValueKind == JsonValueKind.String) ? roleElement.GetString() : "");
				if (role.Equals("assistant", StringComparison.OrdinalIgnoreCase) && message.TryGetProperty("tool_calls", out var toolCalls) && toolCalls.ValueKind == JsonValueKind.Array)
				{
					foreach (JsonElement toolCall in toolCalls.EnumerateArray())
					{
						JsonElement idElement;
						string id = ((toolCall.TryGetProperty("id", out idElement) && idElement.ValueKind == JsonValueKind.String) ? idElement.GetString() : "");
						if (!toolCall.TryGetProperty("function", out var function) || function.ValueKind != JsonValueKind.Object)
						{
							continue;
						}
						JsonElement nameElement;
						string name = ((function.TryGetProperty("name", out nameElement) && nameElement.ValueKind == JsonValueKind.String) ? nameElement.GetString() : "");
						if (!string.IsNullOrWhiteSpace(name))
						{
							if (!string.IsNullOrEmpty(id))
							{
								toolCallIds[id] = name;
							}
							toolCallCounts.TryGetValue(name, out var callCount);
							toolCallCounts[name] = callCount + 1;
						}
					}
				}
				else
				{
					if (!role.Equals("tool", StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
					JsonElement toolCallIdElement;
					string toolCallId = ((message.TryGetProperty("tool_call_id", out toolCallIdElement) && toolCallIdElement.ValueKind == JsonValueKind.String) ? toolCallIdElement.GetString() : "");
					if (!string.IsNullOrEmpty(toolCallId) && toolCallIds.TryGetValue(toolCallId, out var toolName))
					{
						JsonElement contentElement;
						string content = (message.TryGetProperty("content", out contentElement) ? contentElement.ToString() : "");
						if (string.IsNullOrWhiteSpace(content))
						{
							emptyToolResultCounts.TryGetValue(toolName, out var emptyCount);
							emptyToolResultCounts[toolName] = emptyCount + 1;
						}
						else
						{
							successfulToolResultCounts.TryGetValue(toolName, out var successCount);
							successfulToolResultCounts[toolName] = successCount + 1;
						}
					}
				}
			}
			foreach (KeyValuePair<string, int> kv in emptyToolResultCounts)
			{
				if (kv.Key.Equals("get_projects_in_solution", StringComparison.Ordinal) && kv.Value >= 1)
				{
					toolsToSuppress.Add(kv.Key);
				}
				else if (kv.Key.Equals("code_search", StringComparison.Ordinal) && kv.Value >= 3)
				{
					toolsToSuppress.Add(kv.Key);
				}
			}
			foreach (KeyValuePair<string, int> kv2 in toolCallCounts)
			{
				if (kv2.Key.Equals("get_projects_in_solution", StringComparison.Ordinal) && kv2.Value >= 2)
				{
					toolsToSuppress.Add(kv2.Key);
				}
				else if (kv2.Key.Equals("code_search", StringComparison.Ordinal) && kv2.Value >= 5)
				{
					toolsToSuppress.Add(kv2.Key);
				}
			}
			if (successfulToolResultCounts.ContainsKey("get_projects_in_solution"))
			{
				toolsToSuppress.Add("get_projects_in_solution");
			}
			KeepOnlySuppressibleVsTools(toolsToSuppress);
			if (toolsToSuppress.Count == 0)
			{
				return false;
			}
			reason = "Some Visual Studio tools already returned empty or repeated results and must not be called again this turn: " + string.Join(", ", toolsToSuppress) + ". Continue with the remaining tools. Exact file reads, file search, terminal commands, edits, and build verification are still available.";
			return true;
		}
		catch (Exception ex)
		{
			LogMessage("[Tool Detection] Error detecting failed tools: " + ex.Message);
			return false;
		}
	}

	private string RewriteChatCompletionWithSuppressedTools(string requestBody, HashSet<string> toolsToSuppress, string reason)
	{
		if (toolsToSuppress == null || toolsToSuppress.Count == 0)
		{
			return requestBody;
		}
		KeepOnlySuppressibleVsTools(toolsToSuppress);
		if (toolsToSuppress.Count == 0)
		{
			return requestBody;
		}
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			bool sawTools = false;
			bool anyToolsRemaining = false;
			bool wroteToolChoice = false;
			bool suppressedAnyTool = false;
			writer.WriteStartObject();
			foreach (JsonProperty property in document.RootElement.EnumerateObject())
			{
				if (property.NameEquals("tools") && property.Value.ValueKind == JsonValueKind.Array)
				{
					sawTools = true;
					writer.WritePropertyName("tools");
					writer.WriteStartArray();
					foreach (JsonElement tool in property.Value.EnumerateArray())
					{
						string name = "";
						if (tool.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object && function.TryGetProperty("name", out var nameElement) && nameElement.ValueKind == JsonValueKind.String)
						{
							name = nameElement.GetString();
						}
						if (!string.IsNullOrWhiteSpace(name) && toolsToSuppress.Contains(name))
						{
							suppressedAnyTool = true;
							continue;
						}
						tool.WriteTo(writer);
						anyToolsRemaining = true;
					}
					writer.WriteEndArray();
				}
				else if (property.NameEquals("tool_choice"))
				{
					if (sawTools && !anyToolsRemaining)
					{
						writer.WriteString("tool_choice", "auto");
					}
					else
					{
						property.WriteTo(writer);
					}
					wroteToolChoice = true;
				}
				else if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
				{
					writer.WritePropertyName("messages");
					writer.WriteStartArray();
					foreach (JsonElement item in property.Value.EnumerateArray())
					{
						item.WriteTo(writer);
					}
					writer.WriteStartObject();
					writer.WriteString("role", "system");
					writer.WriteString("content", reason);
					writer.WriteEndObject();
					writer.WriteEndArray();
				}
				else
				{
					property.WriteTo(writer);
				}
			}
			if (!wroteToolChoice && sawTools && !anyToolsRemaining)
			{
				writer.WriteString("tool_choice", "auto");
			}
			writer.WriteEndObject();
			writer.Flush();
			if (!suppressedAnyTool)
			{
				return requestBody;
			}
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (Exception ex)
		{
			LogMessage("[Tool Suppression] Error: " + ex.Message);
			return requestBody;
		}
	}

	private bool HasRepeatedToolCallLoop(string requestBody, out string repeatedToolName, out int repeatCount)
	{
		repeatedToolName = null;
		repeatCount = 0;
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			if (!document.RootElement.TryGetProperty("messages", out var messages) || messages.ValueKind != JsonValueKind.Array)
			{
				return false;
			}
			Dictionary<string, int> counts = new Dictionary<string, int>(StringComparer.Ordinal);
			foreach (JsonElement message in messages.EnumerateArray())
			{
				if (!message.TryGetProperty("role", out var role) || role.ValueKind != JsonValueKind.String || !role.GetString().Equals("assistant", StringComparison.OrdinalIgnoreCase) || !message.TryGetProperty("tool_calls", out var toolCalls) || toolCalls.ValueKind != JsonValueKind.Array)
				{
					continue;
				}
				foreach (JsonElement item in toolCalls.EnumerateArray())
				{
					if (item.TryGetProperty("function", out var function) && function.ValueKind == JsonValueKind.Object)
					{
						JsonElement nameElement;
						string name = ((function.TryGetProperty("name", out nameElement) && nameElement.ValueKind == JsonValueKind.String) ? nameElement.GetString() : "");
						JsonElement argumentsElement;
						string arguments = (function.TryGetProperty("arguments", out argumentsElement) ? argumentsElement.ToString() : "");
						string signature = name + "\n" + arguments;
						counts.TryGetValue(signature, out var currentCount);
						currentCount = (counts[signature] = currentCount + 1);
						if (currentCount > repeatCount)
						{
							repeatedToolName = name;
							repeatCount = currentCount;
						}
					}
				}
			}
		}
		catch (Exception ex)
		{
			LogMessage("[Tool Loop] Error detecting: " + ex.Message);
			return false;
		}
		if (repeatedToolName != null && repeatedToolName.Equals("get_projects_in_solution", StringComparison.Ordinal))
		{
			return repeatCount >= 3;
		}
		if (repeatedToolName != null && repeatedToolName.Equals("code_search", StringComparison.Ordinal))
		{
			return repeatCount >= 5;
		}
		return false;
	}

	private string RewriteChatCompletionWithoutTools(string requestBody, string repeatedToolName, int repeatCount)
	{
		try
		{
			using JsonDocument document = JsonDocument.Parse(requestBody);
			using MemoryStream stream = new MemoryStream();
			using Utf8JsonWriter writer = new Utf8JsonWriter(stream);
			bool wroteToolChoice = false;
			writer.WriteStartObject();
			foreach (JsonProperty property in document.RootElement.EnumerateObject())
			{
				if (property.NameEquals("tools"))
				{
					continue;
				}
				if (property.NameEquals("tool_choice"))
				{
					writer.WriteString("tool_choice", "none");
					wroteToolChoice = true;
				}
				else if (property.NameEquals("messages") && property.Value.ValueKind == JsonValueKind.Array)
				{
					writer.WritePropertyName("messages");
					writer.WriteStartArray();
					foreach (JsonElement item in property.Value.EnumerateArray())
					{
						item.WriteTo(writer);
					}
					writer.WriteStartObject();
					writer.WriteString("role", "system");
					writer.WriteString("content", "The same Visual Studio tool call has already been repeated (" + repeatedToolName + ", " + repeatCount + " times). Do not call tools again in this turn and do not emit <tool_call> tags. Produce normal assistant text only. Use the existing file, IDE, and tool-result context to provide the final answer or concise next edit step.");
					writer.WriteEndObject();
					writer.WriteEndArray();
				}
				else
				{
					property.WriteTo(writer);
				}
			}
			if (!wroteToolChoice)
			{
				writer.WriteString("tool_choice", "none");
			}
			writer.WriteEndObject();
			writer.Flush();
			return Encoding.UTF8.GetString(stream.ToArray());
		}
		catch (Exception ex)
		{
			LogMessage("[Tool Loop] Error rewriting request: " + ex.Message);
			return requestBody;
		}
	}

	private void CopyResponseHeaders(HttpResponseMessage source, HttpListenerResponse target)
	{
		if (source == null || target == null)
		{
			return;
		}
		if (source.Content?.Headers?.ContentType != null)
		{
			target.ContentType = source.Content.Headers.ContentType.ToString();
		}
		HttpContent content = source.Content;
		if (content != null && content.Headers?.ContentLength.HasValue == true)
		{
			target.ContentLength64 = source.Content.Headers.ContentLength.Value;
		}
		foreach (KeyValuePair<string, IEnumerable<string>> header in source.Headers)
		{
			if (header.Key != null && !IsRestrictedResponseHeader(header.Key))
			{
				target.Headers[header.Key] = string.Join(", ", header.Value);
			}
		}
		if (source.Content == null)
		{
			return;
		}
		foreach (KeyValuePair<string, IEnumerable<string>> header2 in source.Content.Headers)
		{
			if (header2.Key != null && !header2.Key.Equals("Content-Type", StringComparison.OrdinalIgnoreCase) && !header2.Key.Equals("Content-Length", StringComparison.OrdinalIgnoreCase) && !IsRestrictedResponseHeader(header2.Key))
			{
				target.Headers[header2.Key] = string.Join(", ", header2.Value);
			}
		}
	}

	private Stream PrepareCompressedProxyOutputStream(HttpListenerRequest request, HttpListenerResponse response, HttpResponseMessage source)
	{
		if (!ShouldCompressProxyResponse(request, source))
		{
			return response.OutputStream;
		}
		string encoding = SelectProxyCompressionEncoding(request.Headers["Accept-Encoding"]);
		if (string.IsNullOrWhiteSpace(encoding))
		{
			return response.OutputStream;
		}
		response.Headers["Content-Encoding"] = encoding;
		response.Headers["Vary"] = AppendHeaderToken(response.Headers["Vary"], "Accept-Encoding");
		response.Headers.Remove("Content-MD5");
		response.ContentLength64 = -1L;
		response.SendChunked = true;
		if (encoding.Equals("gzip", StringComparison.OrdinalIgnoreCase))
		{
			return new GZipStream(response.OutputStream, CompressionLevel.Fastest, leaveOpen: true);
		}
		return new DeflateStream(response.OutputStream, CompressionLevel.Fastest, leaveOpen: true);
	}

	private bool ShouldCompressProxyResponse(HttpListenerRequest request, HttpResponseMessage source)
	{
		if (request == null || source == null || source.Content == null)
		{
			return false;
		}
		if (!NetworkOptions.DefaultOptions.UseHttpCompression)
		{
			return false;
		}
		if (string.Equals(request.HttpMethod, "HEAD", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		if (source.StatusCode == HttpStatusCode.NoContent || source.StatusCode == HttpStatusCode.NotModified)
		{
			return false;
		}
		if (source.Content.Headers.ContentEncoding != null && source.Content.Headers.ContentEncoding.Count > 0)
		{
			return false;
		}
		if (source.Content.Headers.ContentLength.HasValue && source.Content.Headers.ContentLength.Value < NetworkOptions.DefaultOptions.HttpCompressionMinimumBytes)
		{
			return false;
		}
		string contentType = source.Content.Headers.ContentType?.MediaType ?? source.Content.Headers.ContentType?.ToString();
		return IsCompressibleProxyContentType(contentType);
	}

	private static string SelectProxyCompressionEncoding(string acceptEncoding)
	{
		if (HeaderContainsToken(acceptEncoding, "gzip"))
		{
			return "gzip";
		}
		if (HeaderContainsToken(acceptEncoding, "deflate"))
		{
			return "deflate";
		}
		return null;
	}

	private static bool IsCompressibleProxyContentType(string contentType)
	{
		if (string.IsNullOrWhiteSpace(contentType))
		{
			return false;
		}
		contentType = contentType.ToLowerInvariant();
		if (contentType.StartsWith("text/event-stream", StringComparison.OrdinalIgnoreCase))
		{
			return false;
		}
		return contentType.StartsWith("text/", StringComparison.OrdinalIgnoreCase) || contentType.Contains("json") || contentType.Contains("javascript") || contentType.Contains("xml") || contentType.Contains("svg") || contentType.Contains("wasm");
	}

	private static bool HeaderContainsToken(string headerValue, string token)
	{
		if (string.IsNullOrWhiteSpace(headerValue) || string.IsNullOrWhiteSpace(token))
		{
			return false;
		}
		string[] parts = headerValue.Split(',');
		string[] array = parts;
		foreach (string part in array)
		{
			string candidate = part.Split(';')[0].Trim();
			if (candidate.Equals(token, StringComparison.OrdinalIgnoreCase))
			{
				return true;
			}
		}
		return false;
	}

	private static string AppendHeaderToken(string headerValue, string token)
	{
		if (string.IsNullOrWhiteSpace(token))
		{
			return headerValue;
		}
		if (HeaderContainsToken(headerValue, token))
		{
			return headerValue;
		}
		if (string.IsNullOrWhiteSpace(headerValue))
		{
			return token;
		}
		return headerValue + ", " + token;
	}

	private bool IsRestrictedResponseHeader(string headerName)
	{
		if (string.IsNullOrWhiteSpace(headerName))
		{
			return true;
		}
		return WebHeaderCollection.IsRestricted(headerName);
	}

	private string ConvertLmResponseToVsFormat(string lmResponse)
	{
		try
		{
			Match choiceMatch = Regex.Match(lmResponse, "\"message\"\\s*:\\s*(\\{[^}]*\\})");
			if (choiceMatch.Success)
			{
				string message = choiceMatch.Groups[1].Value;
				if (message.Contains("\"function_call\""))
				{
					Match funcMatch = Regex.Match(message, "\"function_call\"\\s*:\\s*(\\{[^}]*\\})");
					if (funcMatch.Success)
					{
						string funcCall = funcMatch.Groups[1].Value;
						string toolId = "tool_" + Guid.NewGuid().ToString("N").Substring(0, 8);
						return "{ \"tool_calls\": [{ \"id\": \"" + toolId + "\", \"type\": \"function\", \"function\": " + funcCall + " }] }";
					}
				}
				Match contentMatch = Regex.Match(message, "\"content\"\\s*:\\s*\"([^\"]*)\"");
				if (contentMatch.Success)
				{
					string content = EscapeJson(contentMatch.Groups[1].Value);
					return "{ \"content\": \"" + content + "\", \"tool_calls\": null }";
				}
			}
			return "{ \"content\": \"No response from LM Studio\", \"tool_calls\": null }";
		}
		catch (Exception ex)
		{
			LogMessage("[Response Conversion] Error: " + ex.Message);
			return "{ \"error\": \"Failed to parse LM Studio response\", \"tool_calls\": null }";
		}
	}

	private string EscapeJson(string text)
	{
		if (text == null)
		{
			return "";
		}
		StringBuilder sb = new StringBuilder(text.Length + 16);
		foreach (char ch in text)
		{
			switch (ch)
			{
			case '\\':
				sb.Append("\\\\");
				continue;
			case '"':
				sb.Append("\\\"");
				continue;
			case '\b':
				sb.Append("\\b");
				continue;
			case '\f':
				sb.Append("\\f");
				continue;
			case '\n':
				sb.Append("\\n");
				continue;
			case '\r':
				sb.Append("\\r");
				continue;
			case '\t':
				sb.Append("\\t");
				continue;
			}
			if (ch < ' ')
			{
				StringBuilder stringBuilder = sb.Append("\\u");
				int num = ch;
				stringBuilder.Append(num.ToString("x4"));
			}
			else
			{
				sb.Append(ch);
			}
		}
		return sb.ToString();
	}

	private string TruncateForLog(string text, int maxChars)
	{
		if (string.IsNullOrEmpty(text))
		{
			return "";
		}
		if (maxChars <= 0 || text.Length <= maxChars)
		{
			return EscapeControlCharsForLog(text);
		}
		return EscapeControlCharsForLog(text.Substring(0, maxChars)) + "...";
	}

	private string EscapeControlCharsForLog(string text)
	{
		if (string.IsNullOrEmpty(text))
		{
			return "";
		}
		StringBuilder sb = new StringBuilder(text.Length);
		foreach (char ch in text)
		{
			switch (ch)
			{
			case '\b':
				sb.Append("\\b");
				continue;
			case '\f':
				sb.Append("\\f");
				continue;
			case '\n':
				sb.Append("\\n");
				continue;
			case '\r':
				sb.Append("\\r");
				continue;
			case '\t':
				sb.Append("\\t");
				continue;
			}
			if (ch < ' ')
			{
				StringBuilder stringBuilder = sb.Append("\\u");
				int num = ch;
				stringBuilder.Append(num.ToString("x4"));
			}
			else
			{
				sb.Append(ch);
			}
		}
		return sb.ToString();
	}

	public void Dispose()
	{
		if (!_isDisposed)
		{
			Stop();
			CancelAllRemoteSessionFileClones();
			CancelAllWebChatRuntimeModelIdleUnloads();
			StopRemoteSessionFileCloneWatcher();
			DisposeChatSessionSandboxes();
			DisposeChatBrowserClientSessions();
			_jackDirector?.Dispose();
			_httpListener = null;
			try
			{
				((IDisposable)_chatServer)?.Dispose();
			}
			catch
			{
			}
			_chatServer = null;
			_httpClient?.Dispose();
			_chatBrowserProxyHttpClient?.Dispose();
			_browserSkillHttpClient?.Dispose();
			_cts?.Dispose();
			_isDisposed = true;
			GC.SuppressFinalize(this);
		}
	}
}

